window.POMS_DATA = {"meta":{"name":"POMS 2025","sessionCount":451,"abstractCount":1628},"days":[{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May","count":117},{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May","count":150},{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May","count":145},{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May","count":39}],"tracks":[{"name":"Agriculture and Food Supply Chains","color":"oklch(0.64 0.12 0)","count":11},{"name":"Aviation, Transportation, and Logistics Management","color":"oklch(0.64 0.12 11)","count":13},{"name":"Behavioral Operations Management","color":"oklch(0.64 0.12 23)","count":17},{"name":"Data Science, Analytics and AI","color":"oklch(0.64 0.12 34)","count":13},{"name":"Digital Platforms, Innovations and Transformations","color":"oklch(0.64 0.12 45)","count":18},{"name":"Disruptive Technologies and Operations Management","color":"oklch(0.64 0.12 56)","count":12},{"name":"Empirical Research in Operations Management","color":"oklch(0.64 0.12 68)","count":18},{"name":"Energy and Natural Resource Management","color":"oklch(0.64 0.12 79)","count":10},{"name":"Generative AI and Societal Sustainable Operations","color":"oklch(0.64 0.12 90)","count":6},{"name":"Healthcare Analytics","color":"oklch(0.64 0.12 101)","count":21},{"name":"Healthcare Operations Management","color":"oklch(0.64 0.12 113)","count":20},{"name":"Honoring Retirees","color":"oklch(0.64 0.12 124)","count":3},{"name":"Humanitarian Operations and Crisis Management","color":"oklch(0.64 0.12 135)","count":23},{"name":"Industry Studies and Public Policy","color":"oklch(0.64 0.12 146)","count":4},{"name":"Information Systems and Operations Management","color":"oklch(0.64 0.12 158)","count":20},{"name":"Manufacturing Operations","color":"oklch(0.64 0.12 169)","count":9},{"name":"Operational Excellence","color":"oklch(0.64 0.12 180)","count":18},{"name":"Operations and Society","color":"oklch(0.64 0.12 191)","count":10},{"name":"POM and Community","color":"oklch(0.64 0.12 203)","count":20},{"name":"POM-Economics Interface","color":"oklch(0.64 0.12 214)","count":10},{"name":"POM-Finance Interface","color":"oklch(0.64 0.12 225)","count":7},{"name":"POM-Marketing Interface","color":"oklch(0.64 0.12 236)","count":19},{"name":"Practice Leaders","color":"oklch(0.64 0.12 248)","count":4},{"name":"Procurement and Supplier Management","color":"oklch(0.64 0.12 259)","count":9},{"name":"Product Innovation and Technology Management","color":"oklch(0.64 0.12 270)","count":17},{"name":"Retail Operations","color":"oklch(0.64 0.12 281)","count":14},{"name":"Revenue Management and Pricing","color":"oklch(0.64 0.12 293)","count":10},{"name":"Service Operations","color":"oklch(0.64 0.12 304)","count":19},{"name":"Supply Chain Management","color":"oklch(0.64 0.12 315)","count":34},{"name":"Supply Chain Risk Management","color":"oklch(0.64 0.12 326)","count":13},{"name":"Sustainable Operations Management","color":"oklch(0.64 0.12 338)","count":22},{"name":"Tutorials and Workshops in Research and Teaching","color":"oklch(0.64 0.12 349)","count":7}],"rooms":["AUBURN","BAKER","COURTLAND","DUNWOODY","EMBASSY A","EMBASSY B","EMBASSY C","EMBASSY D","EMBASSY E","EMBASSY F","EMBASSY G","EMBASSY H","FAIRLIE","GRAND HALL EAST A","GRAND HALL EAST B","GRAND HALL EAST C","GRAND HALL EAST D","GREENBRIAR","HARRIS","INMAN","KENNESAW","LENOX","Learning Center","MARIETTA","PIEDMONT","ROSWELL","SPRING","TECHWOOD","UNIVERSITY","VININGS"],"sessions":[{"id":"s26","title":"Integrating AI in Healthcare Operations: Challenges and Opportunities","track":"Healthcare Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"PIEDMONT","chairs":["Prof. Mehmet Eren Ahsen"],"abstracts":[{"id":"136-1978","title":"What People Think of Machines as Doctors: Unveiling the Value of Gen-AI for E-Health","content":"Framed within the context of patient-physician communication, we investigate how non-experts (typical patients) perceive LLM responses versus physician responses and explore behavioral factors influencing their perception. In a survey-based experiment, we compare non-experts’ (survey participants) evaluations of responses from physicians and ChatGPT to patient queries.","presenter":"Prof. Mehmet Ayvaci","authors":[{"name":"Ms. Dicle Ozdemir","aff":"Assistant Professor, Erasmus University Rotterdam"},{"name":"Prof. Mehmet Ayvaci","aff":"Associate Professor, The University of Texas at Dallas"},{"name":"Prof. Alejandro Zentner","aff":"Associate Professor, University of Texas Dallas"}],"order":1},{"id":"136-2000","title":"Information Disclosure and Acceptance of AI: A Field Study on Human-AI Interaction in Healthcare Gatekeeping","content":"This study investigates how information disclosure influences patient acceptance of AI recommendations in healthcare. Through field experiments, we show that higher algorithm accuracy or peer acceptance independently increases AI acceptance. When presented together, they exhibit complementary effects, yet peer acceptance has a dominant impact on patient decisions over algorithm accuracy.","presenter":"Prof. Shujing Sun","authors":[{"name":"Prof. Shujing Sun","aff":"Assistant Professor, University of Texas at Dallas"},{"name":"Prof. Lauren Lu","aff":"Professor, Dartmouth College"},{"name":"Prof. Feng (Susan) Lu","aff":"Professor, Purdue University"},{"name":"Prof. Wei Gu","aff":"Professor, University of Science and Technology Beijing"}],"order":2},{"id":"136-1641","title":"Improved Personalized Drug Dosing through Data Generation and Expert Feedback","content":"We address the challenge of data scarcity and variability in personalized dosing by proposing a framework that combines generative models with Bayesian optimization. Integrating synthetic data, expert feedback, and Bayesian optimization, our approach matches the performance of models trained on larger datasets, enhancing therapeutic efficacy while minimizing adverse drug effects.","presenter":"Mr. H. Satyam Verma","authors":[{"name":"Mr. H. Satyam Verma","aff":"Student, Carnegie Mellon University"},{"name":"Prof. Holly Wiberg","aff":"Assistant Professor, Carnegie Mellon University"},{"name":"Prof. Shixiang Zhu","aff":"Assistant Professor, Carnegie Mellon University"},{"name":"Prof. Sridhar Tayur","aff":"Professor, Carnegie Mellon University"}],"order":3},{"id":"136-1855","title":"Enhancing Fairness and Accuracy in Mammography Screening Using a Custom Ensemble","content":"As AI permeates industries like healthcare, balancing accuracy and fairness in decision-making is critical. We propose a linear ensemble model that combines diverse, potentially unfair algorithms to enhance fairness and performance. Empirical analysis using mammography screening data demonstrates improved discriminative ability and equity.","presenter":"Prof. Mehmet Eren Ahsen","authors":[{"name":"Prof. Mehmet Eren Ahsen","aff":"Assistant Professor, University of Illinois at Urbana Champaign"},{"name":"Prof. Mehmet Ayvaci","aff":"Associate Professor, The University of Texas at Dallas"}],"order":4}]},{"id":"s38","title":"Navigating Complexity: Crisis, Conflict, and Humanitarian Operations","track":"Humanitarian Operations and Crisis Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"GRAND HALL EAST B","chairs":["Dr. Telesilla Kotsi"],"abstracts":[{"id":"136-0549","title":"Framework agreements for relief items -- Current use, weaknesses, and the potential for incentive schemes","content":"Humanitarian organizations increasingly use framework agreements (FA) to increase local sourcing of relief items, responsiveness, and efficiency. However, FAs often provide a weak \"business case\" for suppliers to stock sufficient quantities. We examine how to design incentive schemes for FAs that balance local availability, costs, and equity.","presenter":"Dr. Harwin De Vries","authors":[{"name":"Dr. Harwin De Vries","aff":"Associate Professor, Rotterdam School of Management"},{"name":"Mr. Run Zhang","aff":"Student, Fudan University"},{"name":"Dr. Jelmer Pier Gaast","aff":"Associate Professor, Fudan University"}],"order":1},{"id":"136-0587","title":"Two sides of the same precarious coin: Addressing Conflict and Climate Crises through Mindanao’s Lens","content":"This case study explores the interplay between conflict and climate-induced displacement in Mindanao, uniquely illustrating complex crises. Using mixed methods, we combine disaster preparedness perceptions data with conflict-displacement dynamics simulation. This analysis reveals how local migration decision-making is shaped and offers integrated strategies to enhance community resilience and humanitarian responses.","presenter":"Ms. Patience Saungweme","authors":[{"name":"Ms. Patience Saungweme","aff":"Student, WHU - Otto Beisheim School of Management"},{"name":"Dr. Vincenzo Bollettino","aff":"Senior Lecturer, Harvard T.H. Chan School of Public Health"},{"name":"Prof. Stefan Spinler","aff":"Professor, WHU - Otto Beisheim School of Management"}],"order":2},{"id":"136-0834","title":"Assessing the Influence of Protracted Crisis and Conflict Towards Environmentally Sustainable Humanitarian Operations","content":"Conflict, climate change, and humanitarian operations interact within a vicious cycle that may exacerbate protracted crisis. However, it is unclear what role conflict and protracted crisis may play in influencing the environmental footprint of humanitarian operations. We examine this topic using Life Cycle Assessment and a case study approach.","presenter":"Prof. Maria Besiou","authors":[{"name":"Dr. Sarah Joseph","aff":"Post Doc/Researcher, Kühne Logistics University gGmbH"},{"name":"Prof. Maria Besiou","aff":"Professor, Kuehne Logistics University"},{"name":"Mr. Jonas Stumpf","aff":"Student, WU Vienna Univ of Economics and Business"}],"order":3},{"id":"136-1715","title":"Donor Influence on Humanitarian Resource Allocation: A Classification-Based Analysis in Conflict Settings","content":"This study examines how institutional donors—funding agencies without direct field engagement—and operational donors—organizations directly involved in field operations—impact resource allocation in humanitarian organizations. Using a robust classification method, we analyze donor-specific effects on program versus administrative costs, highlighting variations driven by donor type and operational contexts in conflict settings.","presenter":"Dr. Telesilla Kotsi","authors":[{"name":"Dr. Telesilla Kotsi","aff":"Assistant Professor, Fisher College of Business"},{"name":"Mr. Mohamed Megahed","aff":"Student, The Ohio State University"},{"name":"Prof. Maria Besiou","aff":"Professor, Kuehne Logistics University"},{"name":"Prof. Alfonso Pedraza-Martinez","aff":"Professor, Mendoza College of Business"}],"order":4}]},{"id":"s39","title":"Nonprofit Operations for Social Good","track":"Humanitarian Operations and Crisis Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY G","chairs":["Ms. Shikha Safaya"],"abstracts":[{"id":"136-1794","title":"The impact of managerial ties on the relationship between institutional voids and business performance","content":"Institutional voids challenge business performance in emerging markets. Building on international business literature, we examine how managerial ties—political, business, and NGO—moderate the relationship between institutional voids and performance. Using data from multiple African nations, we propose conditions under which firms benefit from specific ties, advancing understanding of institutional adaptations.","presenter":"Mr. Fakulie Alfred Jawara","authors":[{"name":"Mr. Fakulie Alfred Jawara","aff":"Student, Korea University"},{"name":"Prof. Hojung Shin","aff":"Professor, Korea University"}],"order":1},{"id":"136-0808","title":"Allocating Volunteers to Beneficiaries in a Non-Profit Organization","content":"We explore the tradeoffs between incorporating volunteer and beneficiary preferences in task assignments for a non-profit versus pooling them to alleviate supply-demand mismatch. We compare the performance outcomes of alternative policies and suggest ways by which non-profits can better align incentives of all stakeholders.","presenter":"Ms. Shikha Safaya","authors":[{"name":"Ms. Shikha Safaya","aff":"Student, Georgia Institute of Technology"},{"name":"Prof. Basak Kalkanci","aff":"Associate Professor, Georgia Institute of Technology"},{"name":"Dr. Ravi Subramanian","aff":"Professor, Georgia Tech"}],"order":2},{"id":"136-1528","title":"Inter-Organizational Networks among Food Banks: Impact on Food Aid Distribution and Resource Sharing","content":"This case study explores the interconnected effects of inter-organizational networks on small food banks’ ability to deliver diverse, high-quality food aid efficiently. By emphasizing collaboration and resource-sharing, the study underscores how networks improve service operations, service improvisation and impact food security, ultimately enhancing community satisfaction and service quality.","presenter":"Ms. Madison Edwards","authors":[{"name":"Ms. Madison Edwards","aff":"Student, Auburn University Harbert College of Bus"},{"name":"Dr. LaDonna Thornton","aff":"Assistant Professor, Auburn University Harbert College of Bus"}],"order":3},{"id":"136-1254","title":"Optimizing Incentives in Voucher-Based Subsidy Programs for Equitable Service Delivery","content":"This study examines voucher-based subsidy programs where mission-oriented agencies collaborate with profit-driven providers to serve low-income populations. Using an analytical framework, we identify optimal funding mechanisms that incentivize provider participation while addressing demand uncertainty and budget constraints. Our findings provide insights to enhance accessibility and equity in essential service delivery.","presenter":"Ms. Gulten Busra Karkili","authors":[{"name":"Ms. Gulten Busra Karkili","aff":"Student, University of Massachusetts Amherst"},{"name":"Dr. Senay Solak","aff":"Professor, University of Massachusetts Amherst"}],"order":4}]},{"id":"s46","title":"Supply Chain Disruption","track":"Supply Chain Risk Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY H","chairs":["Dr. William Haskell"],"abstracts":[{"id":"136-1720","title":"Fortifying Supply Chains: Unraveling Resilience Mechanisms Against Cyberattacks","content":"Cyberattacks increasingly threaten entire supply chain networks. This study seeks to uncover the causal mechanisms that enhance a firm’s resilience to cyberattacks using a novel dataset that integrates longitudinal survey data with secondary sources. Our findings offer valuable insights into strengthening supply chain resilience in a volatile digital landscape.","presenter":"Dr. Anto Verghese","authors":[{"name":"Dr. Anto Verghese","aff":"Assistant Professor, University of North Texas"},{"name":"Dr. Russell Torres","aff":"Assistant Professor, University of North Texas"}],"order":1},{"id":"136-1100","title":"Risk Management in Supplier Selection","content":"In this study, we develop a comprehensive framework to evaluate supplier risk within a supply chain context. Building on principles from insurance theory and the Bühlmann credibility model, we introduce a risk assessment index that integrates multiple macro and micro risk factors to quantitatively measure supplier risk.","presenter":"Dr. Zhixin Yang","authors":[{"name":"Dr. Zhixin Yang","aff":"Associate Professor, Ball State University"},{"name":"Dr. Qiannong Gu","aff":"Associate Professor, Ball State University"}],"order":2},{"id":"136-1917","title":"Managing Compound Risks in Supply Chains: A System Dynamics Approach to Network Reconfiguration","content":"This study investigates supply chain resilience under compound risks, defined as concurrent and sequential disruptions. A System Dynamics approach is adopted to simulate network reconfiguration and efficient resource allocation, addressing dynamic risks. The findings advance the understanding of resilience in interconnected supply networks and inform strategic decision-making under prolonged crises.","presenter":"Dr. Naoum Tsolakis","authors":[{"name":"Dr. Naoum Tsolakis","aff":"Associate Professor, University of Cambridge"}],"order":3},{"id":"136-1032","title":"Integrated Crop and Cargo War Risk Insurance: Application to Ukraine","content":"Conflicts and wars disrupt global agricultural supply chains, impacting food security. We develop a multicommodity trade model that incorporates exchange rates, production and transportation capacities, and commodity losses under wartime scenarios. We propose war risk insurance premiums with government subsidies, demonstrating their importance using examples from Russia’s war on Ukraine.","presenter":"Mr. Ismael Mohammad Pour","authors":[{"name":"Prof. Anna Nagurney","aff":"Professor, University of Massachusetts Amherst"},{"name":"Mr. Ismael Mohammad Pour","aff":"Student, University of Massachusetts Amherst"},{"name":"Prof. Borys Kormych","aff":"Professor, Odesa Law Academy"}],"order":4}]},{"id":"s62","title":"Digital Influence: Cybersecurity, Health, and Algorithmic Fairness","track":"Disruptive Technologies and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"KENNESAW","chairs":["Prof. Jong Youl Lee","Prof. Yeongin Kim"],"abstracts":[{"id":"136-0180","title":"Addressing Socio-Algorithmic Bias: A Framework for Fair and Efficient Algorithmic Decision-Making in Healthcare","content":"Algorithms using historical data can replicate and amplify existing flaws in social systems. For example, systemic disparities in access to healthcare can taint algorithmic predictions, leading to \"socio-algorithmic bias.\" We formulate a bias-aware algorithmic decision-making framework that factors the origins of socio-algorithmic bias in healthcare while considering fairness and efficiency","presenter":"Ms. Ozgur Aksoy","authors":[{"name":"Ms. Ozgur Aksoy","aff":"Student, The University of Texas at Dallas"},{"name":"Prof. Mehmet Ayvaci","aff":"Associate Professor, The University of Texas at Dallas"},{"name":"Prof. Asunur Cezar","aff":"Professor, Bogazici University"},{"name":"Prof. Srinivasan Raghunathan","aff":"Professor, The University of Texas at Dallas"}],"order":1},{"id":"136-0807","title":"Keep an Eye on Me: The Role of Fitness Tracking Group as a Social Pre-commitment","content":"This study explores how group-based fitness-tracking apps encourage sustained health behaviors. Using staggered DID, it finds that joining a group increases workout duration by 24.7%. This effect is explained by users’ pre-commitment strategies, which create psychological costs when they fail to conform to group norms.","presenter":"Mr. Donggyu (David) Min","authors":[{"name":"Ms. Gayoon Kim","aff":"Student, KAIST"},{"name":"Mr. Donggyu (David) Min","aff":"Student, KAIST"},{"name":"Prof. Yeongin Kim","aff":"Assistant Professor, Wake Forest University"},{"name":"Prof. Chul Ho Lee","aff":"Assistant Professor, KAIST"}],"order":2},{"id":"136-1892","title":"Microblogging Character Limit and Phishing Strategy","content":"We study the impact of character limit increase on attackers' phishing strategy on microblogging platforms. We find that increasing character limits reduces volume of phishing URLs. However, attackers adapt by crafting more subtle, complex phishing URLs, along with lengthier, negative, and loss-framed messages. Therefore, phishing threats persist in new forms.","presenter":"Prof. Jong Youl Lee","authors":[{"name":"Prof. Jong Youl Lee","aff":"Assistant Professor, Florida International University"},{"name":"Prof. Jennifer Zhang","aff":"Professor, University of Texas Arlington"},{"name":"Dr. H. Raghav Rao","aff":"Professor, University of Texas San Antonio"}],"order":3}]},{"id":"s66","title":"Empirical Research in Supply Chain Management","track":"Procurement and Supplier Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"LENOX","chairs":["Dr. Sining Song","Dr. Li Cheng"],"abstracts":[{"id":"136-0246","title":"Innovation and accumulation of knowledge spillovers in buyer-supplier relationships","content":"In this study, we focus on a buyer as a source of technological knowledge spillovers for a supplier, and examine factors that make a supplier accumulate technological knowledge spillovers from the buyer. We construct a panel data from multiple sources to verify the hypotheses.","presenter":"Dr. Shubhobrata Palit","authors":[{"name":"Dr. Shubhobrata Palit","aff":"Assistant Professor, Rochester Institute of Technology"},{"name":"Dr. Soumen Ghosh","aff":"Professor, Georgia Institute of Technology"},{"name":"Prof. Manpreet Hora","aff":"Professor, Georgia Institute of Technology"}],"order":1},{"id":"136-1573","title":"Buyer-Supplier Networks and Innovation: The Role of Technological Knowledge Spillovers","content":"In this study, using a panel data of supplier-buyer relationships and the patenting activities of the respective firms, we address the following research question: How does buyer innovation influence supplier innovation performance?","presenter":"Dr. Shubhobrata Palit","authors":[{"name":"Dr. Shubhobrata Palit","aff":"Assistant Professor, Rochester Institute of Technology"}],"order":2},{"id":"136-1866","title":"An Empirical Analysis of Generic Drug Manufacturing Location and Serious Adverse Events","content":"Generic drug manufacturing is increasingly shifting to emerging economies. This study, leveraging novel data, finds higher rates of serious adverse events for generics produced in emerging economies, particularly older drugs from India, compared to those from advanced economies. The findings highlight regulatory implications for ensuring drug quality.","presenter":"Prof. In Joon Noh","authors":[{"name":"Prof. In Joon Noh","aff":"Assistant Professor, Korea University"},{"name":"Dr. John Gray","aff":"Professor, Ohio State University"},{"name":"Prof. George Ball","aff":"Associate Professor, Kelley School of Business, Indiana Univ."},{"name":"Dr. Zachary Wright","aff":"Assistant Professor, Brigham Young University"},{"name":"Dr. Hyunwoo Park","aff":"Associate Professor, Seoul National University"}],"order":3},{"id":"136-1043","title":"Interplay between resolution tactics of a supplier-induced disruption: A configurational approach","content":"We examine the interplay between resolution tactics and individual purchasing managers' traits in two distinct disruption contexts. Using experimental data, our paper sheds light on the effectiveness of disruption resolution tactics used in tandem, considering various contingencies. Managerially, we provide guidance for suppliers to devise resolution portfolios in given contexts.","presenter":"Dr. Li Cheng","authors":[{"name":"Dr. Li Cheng","aff":"Assistant Professor, Michigan State University"},{"name":"Dr. Qiong Wang","aff":"Associate Professor, University of Oklahoma"},{"name":"Dr. Christopher Craighead","aff":"Professor, University of Tennessee Knoxville"},{"name":"Dr. Juan (Julie) Li","aff":"Professor, City University of Hong Kong"},{"name":"Dr. Matthew Jensen","aff":"Professor, University of Oklahoma"}],"order":8}]},{"id":"s88","title":"Behavior in the New World of Work","track":"Behavioral Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY D","chairs":["Ms. Clare Snyder","Prof. Samantha Keppler"],"abstracts":[{"id":"136-0176","title":"When Alarms Fall Silent: Human-Adaptive Maintenance Optimization","content":"Sensors that monitor equipment may predict a problem unnecessarily. If this happens more often, service engineers may ignore the warnings. We perform an experiment to test people’s reactions to warnings. Using our findings we improve the timing of warnings and perform a second experiment to confirm improved performance.","presenter":"Dr. Rob Basten","authors":[{"name":"Dr. Bas Van Oudenhoven","aff":"Post Doc/Researcher, University of Twente"},{"name":"Dr. Melvin Drent","aff":"Assistant Professor, Eindhoven University of Technology"},{"name":"Dr. Collin Drent","aff":"Assistant Professor, Eindhoven University of Technology"},{"name":"Dr. Rob Basten","aff":"Associate Professor, Eindhoven University of Technology"},{"name":"Dr. Philippe Van de Calseyde","aff":"Assistant Professor, Eindhoven University of Technology"}],"order":1},{"id":"136-0234","title":"Algorithm Reliance for Binary Classification: Implications for Accuracy and Fairness","content":"In this research we use laboratory experiments to answer the question: how effective will binary classification algorithms designed for fairness (i.e., equal opportunity) be when they are channeled through a human decision-maker? We find that human deviations from the algorithms' advice can undermine fair outcomes.","presenter":"Ms. Clare Snyder","authors":[{"name":"Ms. Clare Snyder","aff":"Student, University of Michigan - Ann Arbor"},{"name":"Prof. Samantha Keppler","aff":"Assistant Professor, University of Michigan Ann Arbor"},{"name":"Prof. Stephen Leider","aff":"Professor, University of Michigan Ann Arbor"}],"order":2},{"id":"136-0438","title":"AI Supervision in Call Center Operations: Experimental Evidence","content":"Artificial intelligence is being rapidly deployed to change the face of customer service operations. In this experimental study, we document efficiency-service tradeoffs when \"Conversational AI\" is used to reinforce service script protocols used by call center agents and we explore mechanisms that may explain our observations.","presenter":"Dr. Michelle Kinch","authors":[{"name":"Dr. Michelle Kinch","aff":"Assistant Professor, Dartmouth College"}],"order":3},{"id":"136-1729","title":"Privacy, Risk and Fatalism","content":"We demonstrate the importance of fatalism in privacy decisions, modeling it under different levels of pre-existing breach risk. Our experimental data supports the case of moderate fatalism: privacy sensitivity when pre-existing risks are low, but insensitivity to further data collection (i.e. additional risks) for high pre-existing risks.","presenter":"Ms. Cagla Ergul","authors":[{"name":"Ms. Cagla Ergul","aff":"Student, University of Michigan - Ann Arbor"},{"name":"Prof. Stephen Leider","aff":"Professor, University of Michigan Ann Arbor"},{"name":"Dr. Ruslan Momot","aff":"Assistant Professor, University of Michigan - Ann Arbor"}],"order":4}]},{"id":"s101","title":"Frontiers in Pricing and Market Design","track":"POM-Economics Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"TECHWOOD","chairs":["Prof. Michael Hamilton","Prof. Titing Cui"],"abstracts":[{"id":"136-0278","title":"Tight Tradeoffs for Two-Stage Bipartite Matching with Advice","content":"We study two-stage bipartite matching when the algorithm is given advice in the form of a first-stage suggested matching. We characterize the tight tradeoff between consistency (the performance of the algorithm relative to the advice), and robustness (the performance of the algorithm relative to the optimal solution in hindsight).","presenter":"Mr. Billy Jin","authors":[{"name":"Mr. Billy Jin","aff":"Student, University of Chicago"},{"name":"Mr. Will Ma","aff":"Assistant Professor, Columbia University"}],"order":1},{"id":"136-0380","title":"Subscription vs. Spot Pricing in On-Demand Economy","content":"We study subscription and spot pricing in on-demand economy. Unlike subscription, spot pricing empowers the platform owner to dynamically control congestion and extract more consumer surplus, complementing the process of incentivizing gig workers and segmenting heterogeneous consumers. A hybrid pricing model, though, can yield higher profit than pure spot pricing.","presenter":"Dr. Zhoupeng (Jack) Zhang","authors":[{"name":"Prof. Ming Hu","aff":"Professor, University of Toronto"},{"name":"Dr. Taojie Qin","aff":"Student, Southwestern University of Finance and Economics"},{"name":"Mr. Lu Wang","aff":"Assistant Professor, Shanghai University of Finance and Economics"},{"name":"Dr. Zhoupeng (Jack) Zhang","aff":"Assistant Professor, University at Buffalo, SUNY"}],"order":2},{"id":"136-0637","title":"Optimal Regulation Paradigm Design with Privacy Protection and R&amp;D Incentive","content":"Modern technologies enable vast data collection, sparking debates on privacy protection. We model optimal privacy regulation in two-phases Bayesian persuasion, where a regulator designs information revelation policies. By balancing consumer surplus, R&amp;D incentive, and additional regulations, we demonstrate that combining regulations maximizes social welfare and optimally safeguards privacy.","presenter":"Dr. Qian (Ken) ZHANG","authors":[{"name":"Dr. Qian (Ken) ZHANG","aff":"Assistant Professor, California State Polytech University Pomona"},{"name":"Ms. Luying Wang","aff":"Student, Tianjin Uinversity"}],"order":3},{"id":"136-1121","title":"Managing Trade-offs Between Revenue, Access, and Market Balance on Online Dating Platforms","content":"Online dating platforms frequently engage in price discrimination to maximize profit. These platforms also want the number of users on both sides of the market to be equal, ensuring access to the platform is valuable. This study explores the trade-offs between revenue, access, and market balance through segmented pricing.","presenter":"Prof. Michael Hamilton","authors":[{"name":"Prof. Titing Cui","aff":"Assistant Professor, University of Tulsa"},{"name":"Prof. Michael Hamilton","aff":"Assistant Professor, University of Pittsburgh"},{"name":"Ms. Qiqi Hao","aff":"Student, University of Pittsburgh"}],"order":4}]},{"id":"s112","title":"Empirical Service Operations on Equity and Fairness","track":"Empirical Research in Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY B","chairs":["Prof. Qiuping Yu"],"abstracts":[{"id":"136-0669","title":"Eliminate Gender Wage Gap in the Gig Economy: A Solution from a Customer Service Platform","content":"We study gender wage gaps in female-dominated, remote gig work at an online chat center with a gender-neutral pay algorithm. Men earn 2.4% more hourly due to faster work pace and chat concurrency, but the gap disappears after adjusting for experience, thanks to gender-neutral performance metrics.","presenter":"Ms. Xiao Ni","authors":[{"name":"Ms. Xiao Ni","aff":"Student, Fudan University"},{"name":"Prof. Qiuping Yu","aff":"Associate Professor, Georgetown University"},{"name":"Prof. Tianjun Feng","aff":"Professor, Fudan University"}],"order":2},{"id":"136-1010","title":"The Impact of Ridesharing Platforms on Healthcare Access","content":"We use a natural experiment in Austin to show that the presence of ridesharing has a negative impact on healthcare access for Medicare patients. We further show that this disproportionately affected providers with low-income and less healthy patients. Our mechanism investigation suggests that ridesharing platforms negatively impact other transportation methods.","presenter":"Mr. Nicholas Clyde","authors":[{"name":"Mr. Nicholas Clyde","aff":"Student, Washington University in St. Louis"},{"name":"Ms. Bing Bai","aff":"Assistant Professor, Mcgill University"},{"name":"Prof. Dennis Zhang","aff":"Associate Professor, Washington University in St. Louis"}],"order":3},{"id":"136-1395","title":"Reducing Gender Disparities in Online Labor Platforms: The Role of Performance Feedback and Task Exposure","content":"We examine the role of gender differences in self-evaluation in contributing to gender disparities in task selections and earnings in online labor platforms. Through an online experiment, we show combining performance feedback with early exposure to challenging tasks reduces such disparities, increasing women’s hourly earnings without adverse effects on men.","presenter":"Dr. Li Ding","authors":[{"name":"Dr. Li Ding","aff":"Assistant Professor, Nanyang Technological University"},{"name":"Prof. Basak Kalkanci","aff":"Associate Professor, Georgia Institute of Technology"}],"order":4}]},{"id":"s113","title":"Consumers and Platforms: Driving Transformations in Marketplaces","track":"Empirical Research in Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"INMAN","chairs":["Ms. Srishti Arora"],"abstracts":[{"id":"136-0432","title":"Consumers' Role in Circularity Execution: Evidence from Field Experiments","content":"Sustainability initiatives directed at circularity are a growing focus for businesses. We run a set of field experiments involving a take-back program at a world-leading consumer electronics company to understand, in practice, the collection yield and the retailer's ability to increase the yield through incentives.","presenter":"Prof. Dayton Steele","authors":[{"name":"Prof. Dayton Steele","aff":"Assistant Professor, University of Minnesota"},{"name":"Prof. Atalay Atasu","aff":"Professor, INSEAD"},{"name":"Prof. Saravanan Kesavan","aff":"Professor, University of North Carolina Chapel Hill"}],"order":1},{"id":"136-0476","title":"Democratization Effects of an Online Marketplace","content":"Online B2B marketplaces bring together sellers and buyers from geographically dispersed markets. Using a large-scale dataset containing 77MN buyer-seller transactions, we empirically investigate whether such integration of markets leads to concentration or democratization of market access. We find that marketplaces democratize access to markets irrespective of the physical geographic distance","presenter":"Mr. Rakesh Allu","authors":[{"name":"Mr. Rakesh Allu","aff":"Student, Cornell University"},{"name":"Prof. Li Chen","aff":"Associate Professor, Cornell University"},{"name":"Prof. Vishal Gaur","aff":"Professor, Cornell University"}],"order":2},{"id":"136-0479","title":"The impact of customer interactions on crowdfunding success","content":"We investigate the impact of discussion threads (a platform where project backers can interact with each other and project owner) on crowdfunding success using a data from a large crowdfunding platform. In addition, we perform sentiment analysis to establish that the content of discussions is an important driver for success","presenter":"Ms. Deepanshi Bhardwaj","authors":[{"name":"Mr. Philipp Cornelius","aff":"Assistant Professor, Rotterdam School of Management"},{"name":"Ms. Deepanshi Bhardwaj","aff":"Student, University College London"}],"order":3},{"id":"136-0586","title":"Design of Wait Time Intervals in Virtual Queues","content":"This paper examines the impact of displayed wait time intervals on customer abandonment in virtual queues. Through a field experiment with a ride-sharing platform, we analyze standard, LB-extended, and UB-extended intervals, uncovering mechanisms behind treatment effects and offering insights for firms to optimize wait time displays.","presenter":"Dr. Yiming ZHANG","authors":[{"name":"Dr. Yiming ZHANG","aff":"Assistant Professor, The Chinese Univ of Hong Kong, Shenzhen"},{"name":"Prof. Qiuping Yu","aff":"Associate Professor, Georgetown University"},{"name":"Prof. Yong-Pin Zhou","aff":"Professor, University of Washington"}],"order":4}]},{"id":"s115","title":"Emerging Topics in Energy and EV","track":"Sustainable Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"GRAND HALL EAST C","chairs":["Dr. Jason Nguyen"],"abstracts":[{"id":"136-0509","title":"Strategic Deployment of Electric Vehicle Charging Infrastructure in South Korea","content":"To align with the government’s goal of accelerating EV adoption in South Korea, this study addresses the problem of determining optimal capacities for EV chargers while adhering to regulatory guidelines for charging infrastructure. Furthermore, we examine the key drivers influencing investments in EV charging facilities and explore their implications.","presenter":"Dr. Na Rea Cho","authors":[{"name":"Dr. Na Rea Cho","aff":"Assistant Professor, Wichita State University"},{"name":"Dr. Jin Ah Yang","aff":"Researcher, Research Institute of Korea Land and Housing Corporation"}],"order":1},{"id":"136-1275","title":"The Impact of Political Affiliation on the Adoption of Green Technology","content":"The attitude towards green technology adoption such as Electric Vehicles and Renewable Energy is dependent on many factors. In this paper we examine the impact of cultural issues such as political affiliation on the adoption of electric vehicles by consumers.","presenter":"Ms. Yiru Lang","authors":[{"name":"Prof. Gal Raz","aff":"Associate Professor, Ivey Business School, Western University"},{"name":"Dr. Mesut Yavuz","aff":"Associate Professor, University of Alabama Tuscaloosa"},{"name":"Ms. Yiru Lang","aff":"Student, Ivey Business School"}],"order":2},{"id":"136-1427","title":"Circular Supply Chain for Electric Vehicle Batteries: Recycle or Refurbish?","content":"We study how implementation of extended producer responsibility legislation on EV batteries affects EV manufacturers' choice of circular economic strategies, including recycling the used batteries or repurposing for use in a secondary storage market.","presenter":"Mr. Vikash Kumar","authors":[{"name":"Mr. Vikash Kumar","aff":"Student, Ivey Business School"},{"name":"Dr. Jason Nguyen","aff":"Assistant Professor, Ivey Business School"}],"order":3}]},{"id":"s126","title":"Improving pharmaceutical supply chains","track":"Operational Excellence","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"BAKER","chairs":["Dr. Hanu Tyagi"],"abstracts":[{"id":"136-1411","title":"Generic Drug Transparency: Testing a Regulatory Policy Proposal","content":"Consumers of pharmaceuticals have little ability to determine country of origin or relative quality risk of their drugs. This opacity has been argued to be a key driver of the lack of resilience in the generic drug industry. Here, we study how the market would respond to such transparency.","presenter":"Dr. John Gray","authors":[{"name":"Dr. Sebastian Villa","aff":"Assistant Professor, University of Colorado Boulder"},{"name":"Dr. Gloria Urrea","aff":"Assistant Professor, University of Colorado Boulder"},{"name":"Prof. George Ball","aff":"Associate Professor, Kelley School of Business, Indiana Univ."},{"name":"Dr. John Gray","aff":"Professor, Ohio State University"}],"order":1},{"id":"136-1922","title":"Bridging the Gap Between Shortage and Surplus Outside the Traditional Pharmaceutical Procurement Channel","content":"Drug shortage and surplus represent inefficiencies in the pharmaceutical supply chain that could help alleviate one another. Using proprietary data from an e-commerce platform serving as an alternative, direct procurement channel for surplus drugs, we explore the platform's implications for providers (e.g., pharmacies, hospitals) and manufacturers during supply disruptions.","presenter":"Mr. Ji Won Moon","authors":[{"name":"Mr. Ji Won Moon","aff":"Student, Pennsylvania State University"},{"name":"Prof. Hui Zhao","aff":"Professor, Pennsylvania State University"},{"name":"Prof. Suvrat Dhanorkar","aff":"Associate Professor, Pennsylvania State University"}],"order":3},{"id":"136-0277","title":"When life gives you lemons: Spillovers between pharmaceutical recalls and shortages","content":"We investigate operational failures in the pharmaceutical industry and ask: How does a firm's recall experience impact shortages? Using recalls and shortages data for 319 firms from 2010 to 2019, we show the ambivalent impact of recall experience on shortage outcomes. We discuss implications for managerial practice and policymakers.","presenter":"Dr. Hanu Tyagi","authors":[{"name":"Dr. Hanu Tyagi","aff":"Assistant Professor, University of Illinois Urbana-Champaign"},{"name":"Prof. Junghee Lee","aff":"Assistant Professor, University of Notre Dame"},{"name":"Prof. Rachna Shah","aff":"Professor, University of Minnesota"}],"order":4}]},{"id":"s137","title":"Rethinking Sustainability: Smarter Strategies for a Greener Future","track":"Operations and Society","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"SPRING","chairs":["Dr. Lei Hua","Prof. Tim Kraft"],"abstracts":[{"id":"136-0242","title":"The Market Value of Social Responsibility Communications: A Cross-Cultural Behavioral Study","content":"With consumers' increasing expectation for transparency, companies need to understand how to effectively communicate information about their supply chain practices. Our study examines consumers' valuations of sustainability communication and the impact of different social responsibility topics and message formats on these valuations.","presenter":"Dr. Lei Hua","authors":[{"name":"Dr. Lei Hua","aff":"Assistant Professor, University of Texas At Tyler"},{"name":"Prof. Tim Kraft","aff":"Associate Professor, North Carolina State University"},{"name":"Prof. Doug Thomas","aff":"Professor, University of Virginia"},{"name":"Prof. Yanchong Zheng","aff":"Professor, Massachusetts Institute of Technology"}],"order":1},{"id":"136-0418","title":"How do customers respond to sustainability initiatives of a fashion retailer in the developing world?","content":"Social sustainability initiatives are communicated to customers through engaging visuals. We measure purchasing behaviors in collaboration with a fashion retailers in the developing world. This study aims to provide insights into which sustainability-focused initiatives customers trust and identify which activities and types of promotions or price levels benefit customer profiles.","presenter":"Dr. NESLIHAN OZLU","authors":[{"name":"Dr. NESLIHAN OZLU","aff":"Assistant Professor, College of Admin. Sciences and Economics"},{"name":"Prof. Basak Kalkanci","aff":"Associate Professor, Georgia Institute of Technology"}],"order":2},{"id":"136-1171","title":"Can Packaging Prevent Food Waste in Homes?","content":"This study investigates the impact of packaging features on consumer food waste. Employing surveys and a framed field experiment, it explores how resealability, transparency, and rigidity influence waste behavior, revealing significant effects on consumer food waste reduction, particularly through features enhancing food's perceived quality and extending its usable life.","presenter":"Dr. Monireh Mahmoudi","authors":[{"name":"Dr. Monireh Mahmoudi","aff":"Assistant Professor, Michigan State University"},{"name":"Dr. Chao Wu","aff":"Assistant Professor, Wayne State University"},{"name":"Prof. Stanley Lim","aff":"Assistant Professor, Michigan State University"}],"order":3},{"id":"136-1907","title":"Energy-Wise Desalination: Strategic Investments and Operations for a Sustainable Future","content":"Industrial desalination of seawater is an energy intensive process and if implemented irresponsibly can result in an energy and emissions crisis. We propose an operational strategy for the integrated planner using water and energy storage, which simultaneously determines the optimal desalination and battery operations to minimize energy cost and emissions.","presenter":"Mr. Angshuman Pal","authors":[{"name":"Mr. Angshuman Pal","aff":"Student, Kelley School of Business, Indiana Univ."},{"name":"Prof. Owen Wu","aff":"Associate Professor, Kelley School of Business, Indiana Univ."},{"name":"Prof. Rodney Parker","aff":"Professor, Kelley School of Business, Indiana Univ."}],"order":4}]},{"id":"s151","title":"Improving Decision-Making in Healthcare via Optimization and AI","track":"Healthcare Analytics","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"GRAND HALL EAST D","chairs":["Prof. Arkajyoti Roy"],"abstracts":[{"id":"136-0964","title":"Creating Precision Healthcare Interventions with Non-Stationary Bandits","content":"Mobile health interventions enable personalized treatments in areas like diabetes, mental health, and weight loss. These utilize non-stationary multi-armed bandit (MAB) models to balance learning and optimizing treatments under resource constraints. In this talk, we will discuss both theoretical analysis of these algorithms and explore case studies of their use.","presenter":"Prof. Yonatan Mintz","authors":[{"name":"Prof. Yonatan Mintz","aff":"Assistant Professor, University of Wisconsin-Madison"},{"name":"Mr. Qinyang He","aff":"Student, University of Wisconsin Madison"},{"name":"Dr. Katherine Adams","aff":"Post Doc/Researcher, University of Texas at San Antonio"}],"order":1},{"id":"136-1049","title":"Robust and Personalized Shift Scheduling of Anesthesiology Providers Under Uncertainty","content":"We study the problem of provider hiring and shift scheduling for an anesthesiology department that requires clinical coverage across multiple specialties. Our model incorporates uncertainty in case load, fairness considerations, vacation granting decisions, and provider preferences with respect to their shift assignments.","presenter":"Dr. Katherine Adams","authors":[{"name":"Dr. Katherine Adams","aff":"Post Doc/Researcher, University of Texas at San Antonio"},{"name":"Prof. Arkajyoti Roy","aff":"Assistant Professor, University of Texas at San Antonio"}],"order":2},{"id":"136-1524","title":"Simulation Optimization Approach for Appointment Scheduling in Multi-stage Multi-server Systems","content":"We study an appointment scheduling problem in multi-stage, multi-server systems, common in healthcare services. To model queue-like service flow in practice, a simulation optimization approach is adopted. We design a stochastic gradient descent algorithm using conditional Monte Carlo sampling to address the discontinuous sample path cost function.","presenter":"Ms. Can Zhao","authors":[{"name":"Ms. Can Zhao","aff":"Student, Zhejiang University"},{"name":"Dr. Zheng Zhang","aff":"Assistant Professor, Zhejiang University"},{"name":"Dr. Miao Bai","aff":"Assistant Professor, University of Connecticut"},{"name":"Mr. Xuan Liao","aff":"Student, Shanghai Jiao Tong University"}],"order":3},{"id":"136-1679","title":"Personalized and Interpretable Screening Policy for Diabetic Eye Disease","content":"Teleretinal imaging (TRI) is an emerging AI-based screening tool for diabetic retinopathy. We develop a partially-observable Markov decision process (POMDP) that uses patient-specific characteristics and determines personalized TRI-based screening policy. To promote clinical implementability we then convert the POMDP-driven policy into a more interpretable screening policy and analyze its cost-effectiveness.","presenter":"Mr. Soroush Akbarijokar","authors":[{"name":"Dr. Taewoo Lee","aff":"Associate Professor, Seoul National University"},{"name":"Dr. Poria Dorali","aff":"Post Doc/Researcher, The Medical University of South Carolina"},{"name":"Mr. Soroush Akbarijokar","aff":"Student, University of Pittsburgh"},{"name":"Dr. Christina Weng","aff":"Professor, Baylor College of Medicine"}],"order":4}]},{"id":"s177","title":"Improving Outcomes in Agriculture and Food Supply Chains","track":"Agriculture and Food Supply Chains","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"VININGS","chairs":["Dr. Wei Wei"],"abstracts":[{"id":"136-0065","title":"Dynamic Irrigation Management Under Temporal and Spatial Variability","content":"Agricultural productivity must improve significantly soon following increasing food demand. One way to improve productivity is irrigation. However, freshwater scarcity, increasing costs, and climate change necessitate sustainable and efficient methods for irrigation. We study dynamic irrigation\r\nmanagement under uncertainty considering temporal variability and spatial soil heterogeneity of the\r\nfield.","presenter":"Dr. Erkut Sonmez","authors":[{"name":"Dr. Erkut Sonmez","aff":"Associate Professor, University of Nebraska Lincoln"},{"name":"Prof. Baris Ata","aff":"Professor, University of Chicago"},{"name":"Dr. Derek Heeren","aff":"Associate Professor, University of Nebraska Lincoln"}],"order":1},{"id":"136-0136","title":"Strategic Sell-By Dates: Implications for Food Waste and Availability","content":"Grocery stores in the U.S. throw away 16 billion tons of food each year due to expiration. In this study, we develop a game-theoretic model to examine the strategic motivations behind a profit-maximizing manufacturer’s choice of sell-by dates and the corresponding implications for food waste and availability.","presenter":"Dr. Karthik Murali","authors":[{"name":"Dr. Karthik Murali","aff":"Associate Professor, Oregon State University"},{"name":"Prof. Nicholas Petruzzi","aff":"Professor, University of Wisconsin-Madison"},{"name":"Dr. Aditya Vedantam","aff":"Associate Professor, University of Buffalo"}],"order":2},{"id":"136-0362","title":"Retailing Strategies of Imperfect Produce and the Battle Against Food Waste","content":"This study investigates how a retailer should choose from three popular retailing strategies (discarding, bunching, and differentiating strategies) to deal with imperfect produce. Our result shows that each strategy can be optimal and increasing consumers' valuations can lead to food waste. This result is robust in many extensions.","presenter":"Mr. Haoran Yu","authors":[{"name":"Mr. Haoran Yu","aff":"Student, Syracuse University"},{"name":"Prof. Burak Kazaz","aff":"Professor, Whitman School of Management"},{"name":"Prof. Fasheng Xu","aff":"Assistant Professor, University of Connecticut"}],"order":3},{"id":"136-0580","title":"How Do Producers Fare with Fair Trade?","content":"The fair trade initiative was launched to ensure that farmers receive a fair price for their products and get protected from the volatility in the commodity market. We study a fair trade retailer who sources commodity agriculture products from small farmers and explore the benefit of participating farmers under fair-trade.","presenter":"Prof. Ying Zhang","authors":[{"name":"Prof. Ying Zhang","aff":"Assistant Professor, Santa Clara University"},{"name":"Prof. Yen-Ting Lin","aff":"Professor, University of San Diego"},{"name":"Dr. Adem Orsdemir","aff":"Assistant Professor, University of California Riverside"},{"name":"Dr. Heng Chen","aff":"Assistant Professor, University of Nebraska Lincoln"}],"order":4}]},{"id":"s187","title":"Economics of Retail Distribution Services","track":"Retail Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"FAIRLIE","chairs":["Dr. Jiachen Wei","Prof. Stanley Lim"],"abstracts":[{"id":"136-0142","title":"Only fast-food stores with a drive-through recovered post-pandemic; Stores without did not","content":"We empirically document a profound, permanent change in the US fast-food consumer demand after the COVID-19 pandemic. After a big pandemic slump, visits to drive-through stores almost recovered to pre-pandemic levels, but visits to non-drive-through stores stayed permanently suppressed. Our findings are robust to differences-in-differences regression, matching and placebo tests.","presenter":"Mr. Partha Mishra","authors":[{"name":"Mr. Partha Mishra","aff":"Student, Northwestern University Kellogg School o"},{"name":"Prof. Sunil Chopra","aff":"Professor, Kellogg School of Management"},{"name":"Prof. Yannis Stamatopoulos","aff":"Associate Professor, The University of Texas at Austin"}],"order":1},{"id":"136-0172","title":"Investigating the Impact of Personalized Dynamic Pricing on Consumer Online Shopping","content":"Armed with advanced information technology, more digital retailing platforms are implementing personalized dynamic pricing for their consumers. In this study, we investigate this impact from the consumer and store levels and provide managerial implications for platforms to better understand consumer online shopping behavior and enhance their financial performance.","presenter":"Dr. Xun Xu","authors":[{"name":"Dr. Baile Lu","aff":"Assistant Professor, National University of Defense Technolog"},{"name":"Prof. Weihua Zhou","aff":"Professor, Zhejiang University"},{"name":"Dr. Hongyan Dai","aff":"Professor, Central University of Finance And Economics"},{"name":"Dr. Xun Xu","aff":"Associate Professor, California State University Dominguez Hills"}],"order":2},{"id":"136-0786","title":"Impact of Multi-Channel Adoption on Customer Purchasing Behavior During Supply Chain Disruption","content":"We use transaction data from a grocery chain to examine how consumers use the online channel to fulfill needs in a multi-channel setting following the onset of the COVID-19 crisis. We use the empirical insights to develop models for the design of product assortments in the offline and online channels.","presenter":"Dr. Jiachen Wei","authors":[{"name":"Prof. Stanley Lim","aff":"Assistant Professor, Michigan State University"},{"name":"Prof. Elliot Rabinovich","aff":"Professor, Arizona State University Tempe"},{"name":"Dr. Timothy Richards","aff":"Professor, Arizona State University"},{"name":"Dr. Jiachen Wei","aff":"Post Doc/Researcher, Michigan State University"}],"order":3},{"id":"136-1707","title":"Estimating the Effects of Delivery Platforms on Small-Business Restaurants in California","content":"We empirically study the impact of online food delivery platforms on small-business restaurants in California. We collect unique panel data sets and use econometric and machine learning methods to research the implications of platform’s commission rates and listing menus of restaurants without\r\nexplicit contracts.","presenter":"Prof. Hailong Cui","authors":[{"name":"Prof. Hailong Cui","aff":"Assistant Professor, University of Minnesota"},{"name":"Mr. Rui Niu","aff":"Software Enginner, Microsoft"},{"name":"Prof. Kingshuk Sinha","aff":"Professor, University of Minnesota"},{"name":"Prof. Xin Tong","aff":"Associate Professor, University of Southern California"}],"order":4}]},{"id":"s188","title":"Service Operations on Platforms","track":"Service Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY C","chairs":["Prof. Guangwen Kong"],"abstracts":[{"id":"136-1325","title":"Service Systems with On-Demand and Reserved Servers","content":"We study a queueing system that employs both reserved and on-demand servers – the number of reserved servers is decided at the beginning while the number of on-demand servers is decided dynamically. The objective is to minimize the cost incurred in the hiring of servers and in the waiting.","presenter":"Dr. Zhichao Feng","authors":[{"name":"Dr. Zhichao Feng","aff":"Assistant Professor, Hong Kong Polytechnic Univ"},{"name":"Prof. Milind Dawande","aff":"Professor, The University of Texas at Dallas"},{"name":"Prof. Ganesh Janakiraman","aff":"Professor, The University of Texas at Dallas"},{"name":"Dr. Anyan Qi","aff":"Associate Professor, University of Texas Dallas"}],"order":1},{"id":"136-1740","title":"Rushed Justice: The Pros and Cons of Fast-Track Dispute Systems on Second-Hand Platforms","content":"The increase in transactions on second-hand platforms has led to a rise in disputes, highlighting the need for a more streamlined dispute resolution system. In this study, we investigate whether a fast-track dispute system enhances consumer welfare, and examine its impact on seller behavior and platform.","presenter":"Ms. Bingyue Hu","authors":[{"name":"Ms. Bingyue Hu","aff":"Student, Tianjin Uinversity"},{"name":"Dr. Wee Kiat Lee","aff":"Assistant Professor, Nanyang Technological University"}],"order":2},{"id":"136-1810","title":"Vertical Competition on a Common Platform","content":"This paper examines how competing vendors in a digital goods market craft products when they sell through a common platform and how the platform devises its provision and pricing of the common infrastructure.","presenter":"Dr. Rachel Chen","authors":[{"name":"Prof. Xiaojuan Puyang","aff":"Assistant Professor, Sichuan Normal University"},{"name":"Dr. Zheyin Gu","aff":"Associate Professor, University of Connecticut"},{"name":"Prof. Juan Li","aff":"Professor, Nanjing University"},{"name":"Dr. Rachel Chen","aff":"Professor, University of California Davis"}],"order":3},{"id":"136-1786","title":"Managing Capacity Reservation for Low-priority Strategic Customers","content":"We study a capacity reservation problem where low-priority customers may balk based on either static or dynamic queue information for service systems that operate a shared track and a dedicated track to serve two priority classes of customers. We derive under which conditions the capacity should be pooled (or not).","presenter":"Dr. Marco Bijvank","authors":[{"name":"Dr. Marco Bijvank","aff":"Associate Professor, University of Calgary"},{"name":"Mrs. Guanlian Xiao","aff":"Assistant Professor, Vrije Universiteit Amsterdam"}],"order":4}]},{"id":"s199","title":"Agrifood supply chains and food waste","track":"Supply Chain Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"GRAND HALL EAST A","chairs":["Dr. Yann Bouchery"],"abstracts":[{"id":"136-0869","title":"Does a markdown on older products reduce waste at home and at store?","content":"We study a profit maximizing store that decides on order quantity and optimal markdown. We show that a freshness-dependent markdown is likely to improve store’s profit via a large increase in old product sales and an increase in store’s order quantity. However, this practice is likely to increase total waste.","presenter":"Dr. Yann Bouchery","authors":[{"name":"Dr. Yann Bouchery","aff":"Associate Professor, Kedge Business School"},{"name":"Prof. Benjamin Legros","aff":"Professor, SKEMA"},{"name":"Prof. Mohamed Babai","aff":"Professor, Kedge Business School"}],"order":1},{"id":"136-0548","title":"Battling Food Loss and Empowering Growers with Ugly Veg: The Role of Whole-crop Contracts","content":"We examine the efficacy of whole-crop contracts in reducing food loss due to discarding fruit and vegetables not conforming to aesthetic requirements, i.e. ugly veg. We show that whole-crop contracts always bring the ugly veg to the market and enable the grower to profit under lower wholesale prices.","presenter":"Dr. Guven Demirel","authors":[{"name":"Prof. Behzad Hezarkhani","aff":"Associate Professor, University of Southampton"},{"name":"Dr. Yann Bouchery","aff":"Associate Professor, Kedge Business School"},{"name":"Dr. Guven Demirel","aff":"Reader, Queen Mary University of London"}],"order":2},{"id":"136-0752","title":"Channel Selection in Agricultural Supply Chains: Managing Yield Uncertainty, Aesthetic Requirements, and Producer Information","content":"Farmers face a complex decision when selecting sales channels, as uncertainties in crop yield and retailer-imposed requirements significantly influence their choices. We examine this decision-making process for a farmer considering three options: selling directly to consumers, supplying to a retailer, or pursuing both channels simultaneously.","presenter":"Prof. Sandra Transchel","authors":[{"name":"Prof. Sandra Transchel","aff":"Professor, Kuehne Logistics University"},{"name":"Ms. Mirjam Meijer","aff":"Assistant Professor, Kühne Logistics University"},{"name":"Ms. Nina Mayer","aff":"Student, Kuehne Logistics University"}],"order":3},{"id":"136-1038","title":"From deals to dumps: The effect of promotions on food waste in retail","content":"Analyzing 65,000 promotion events, we find that promotions double food waste, with short-life products experiencing up to a fivefold increase. Overstocking and cannibalization are key drivers, but optimized planning can reduce waste by 9%, highlighting the need for sustainable, data-driven strategies in grocery retail.","presenter":"Mr. Fabian Schaefer","authors":[{"name":"Mr. Fabian Schaefer","aff":"Post Doc/Researcher, Technical University of Munich"},{"name":"Mr. Konstantin Wink","aff":"Student, Technical University of Munich"},{"name":"Mr. Sebastian Goerg","aff":"Professor, Technical University of Munich"},{"name":"Prof. Alexander Hübner","aff":"Professor, Technical University of Munich"}],"order":4}]},{"id":"s206","title":"AI Innovations for Responsible Decision-Making and Social Impact","track":"Digital Platforms, Innovations and Transformations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"GREENBRIAR","chairs":["Dr. Milad Baghersad"],"abstracts":[{"id":"136-0390","title":"Enhancing Communication for Operational Insights: A Summarization Approach for Effective Decision-Making","content":"This study presents a summarization approach using a pointer-generator network to support business decision-making. By extracting keywords and emphasizing actionable insights, it enhances understanding of complex challenges. Grounded in Language-Action Perspective and Speech Act Theory, it enables effective communication, fostering informed decisions and strategic improvements in organizational operations.","presenter":"Dr. Sukhwa Hong","authors":[{"name":"Dr. Sukhwa Hong","aff":"Associate Professor, University of Hawaii"},{"name":"Dr. Hyeonjo Kim","aff":"Assistant Professor, Augsburg University"}],"order":2},{"id":"136-0554","title":"Towards responsible AI through clustered interpretability: Developing metrics and a framework with social good implications","content":"We introduce the novel notion of clustered interpretability, extending interpretability principles with new metrics for within-cluster and between-cluster interpretability. Our approach bridges global interpretability, which covers overall variable importance, and local interpretability, which focuses on individual decisions.","presenter":"Dr. Meysam Rabiee","authors":[{"name":"Dr. Matt Baucum","aff":"Assistant Professor, Colorado State University"},{"name":"Dr. Meysam Rabiee","aff":"Assistant Professor, University of Colorado Denver"}],"order":3},{"id":"136-1359","title":"An AI-driven Approach to Assess Sentiments and Interpret Context in a Critical Mineral Supply Chain","content":"This study proposes the Context Enhanced Supply Chain Sentiment and Summaries approach, leveraging long context LLMs to analyze sentiment shifts across supply chains. Using 5,168 news articles, findings highlight the importance of context for precise and interpretable sentiment analysis for supply chain decision making. Human evaluations validate the approach’s reliability.","presenter":"Ms. Wei Nie","authors":[{"name":"Prof. Nitin Joglekar","aff":"Associate Professor, Villanova University"},{"name":"Ms. Wei Nie","aff":"Student, University of Cambridge"},{"name":"Ms. Mariel Alem Fonseca","aff":"Student, Cambridge University"},{"name":"Dr. Naoum Tsolakis","aff":"Associate Professor, University of Cambridge"},{"name":"Dr. Mukesh Kumar","aff":"Associate Professor, University of Cambridge"}],"order":4}]},{"id":"s213","title":"Data-driven Research in Retail Innovations","track":"Supply Chain Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"AUBURN","chairs":["Ms. Bing Bai","Ms. Chenshan Hu"],"abstracts":[{"id":"136-0570","title":"Food Delivery Platform Expansion Strategies: A Structural Approach","content":"This study develops a two-sided structural model for food delivery platforms, capturing customer choices among platforms and restaurants alongside restaurants' platform participation decisions. Leveraging platform and restaurant-level data, we estimate demand patterns, competitive dynamics, and restaurants' strategic behaviors. Employing counterfactual simulations, we derive insights into platforms' geographic expansion strategies.","presenter":"Mr. Zhikun Lu","authors":[{"name":"Mr. Zhikun Lu","aff":"Student, Emory University"},{"name":"Dr. Wenchang Zhang","aff":"Assistant Professor, Kelley School of Business"},{"name":"Prof. Ruomeng Cui","aff":"Professor, Emory University"}],"order":1},{"id":"136-1485","title":"Increasing Parents' Engagement on Ed-Tech Platforms: Evidence from the Field","content":"In this study, we collaborate with one of India’s leading non-profits focused on catalyzing Early Childhood Education. We run a series of large-scale experiments to evaluate the impact of personalized behavioral nudging using WhatsApp messages. Results demonstrate the significant positive effect that data-driven techniques can have on parents’ engagement.","presenter":"Mr. Alex Okuno","authors":[{"name":"Mr. Alex Okuno","aff":"Student, New York University"},{"name":"Prof. Divya Singhvi","aff":"Assistant Professor, New York University"},{"name":"Prof. Somya Singhvi","aff":"Assistant Professor, University of Southern California"}],"order":2},{"id":"136-1627","title":"Balancing Profitability and Food Waste in Online Grocery: A General Fluid Analysis of Inventory-Adaptive Ranking","content":"Food waste is a major challenge for grocery retailers, eroding profit margins and increasing operating costs. Key drivers of waste at the retail level include damaged packaging and product expiration. This paper investigates how dynamic ranking can mitigate waste by adapting to both inventory dynamics and quality degradation.","presenter":"Ms. Alys Liang","authors":[{"name":"Ms. Alys Liang","aff":"Assistant Professor, McGill University"},{"name":"Prof. Sajjad Najafi","aff":"Assistant Professor, Hec Paris"},{"name":"Prof. Huanan Zhang","aff":"Assistant Professor, University of Colorado Boulder"}],"order":3}]},{"id":"s218","title":"Exploring Behavioral and Financial Drivers of Supply Chain Performance","track":"POM-Finance Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"UNIVERSITY","chairs":["Dr. Christopher Chen"],"abstracts":[{"id":"136-1047","title":"The Effect of Accounting Restatements on Supply Chain Partner Acquisitions","content":"Using theoretical and empirical analysis, we examine how accounting restatements affect a firm’s attractiveness as an acquisition target. While restatements deter general acquisitions, they increase supply chain partner acquisitions by aligning information sets of investors and supply chain partners and reducing the equilibrium market price of the target firm.","presenter":"Prof. Volodymyr Babich","authors":[{"name":"Prof. Volodymyr Babich","aff":"Professor, Georgetown University"},{"name":"Prof. Gilles Hilary","aff":"Professor, Georgetown University"},{"name":"Prof. Kai Wai Hui","aff":"Professor, University of Hong Kong"},{"name":"Prof. Gouman She","aff":"Assistant Professor, Hong Kong University"}],"order":1},{"id":"136-1176","title":"When Artificial Intelligence Meets Behavioral Operations Studies: A Framework with Large Language Models","content":"This study pioneers an LLM-based framework to simulate human decision-making in complex business scenarios, focusing on inventory management and forecasting from Management Science. By leveraging LLMs in a lab setting, we demonstrate their feasibility and validity as tools for behavioral experiments, reflecting real-world complexities and advancing decision and management practices.","presenter":"Prof. Jing Wu","authors":[{"name":"Mr. Xiaoran Ma","aff":"Student, Chinese Univ of Hong Kong"},{"name":"Prof. Andrew Wu","aff":"Assistant Professor, Ross School of Business"},{"name":"Prof. Jing Wu","aff":"Associate Professor, The Chinese University of Hong Kong"}],"order":2},{"id":"136-1281","title":"Value Destruction and Recovery from Supply Chain Disruptions","content":"We examine how multisourcing and supply chain relationship length affect resilience, using an LLM-based method to identify disruptions and a financial market-based approach to measure resilience. Our findings show that long-term supply chain relationships generally have a greater impact on resilience than multisourcing, with a few notable exceptions.","presenter":"Mr. Yue Tang","authors":[{"name":"Mr. Yue Tang","aff":"Student, Emory University"},{"name":"Prof. Nikolay Osadchiy","aff":"Associate Professor, Emory University"}],"order":3},{"id":"136-1693","title":"Optimization Model for Farmers’ Sales Decisions in Coffee Supply Chains To Achieve Equitable Income","content":"This research develops an optimization model for coffee farmers’ sales decisions, integrating quality investment, market selection, and storage strategies. The model offers insights to enhance decision-making, manage risk, and promote equitable income distribution, empowering producers to navigate market dynamics and achieve better outcomes in agricultural supply chains.","presenter":"Ms. Mariana Losada","authors":[{"name":"Ms. Mariana Losada","aff":"Student, Rensselaer Polytechnic Institute"},{"name":"Prof. Sebastian Souyris","aff":"Assistant Professor, Rensselaer Polytechnic Institute"},{"name":"Dr. Mert Hakan Hekimoglu","aff":"Associate Professor, Rensselaer Polytechnic Institute"}],"order":4}]},{"id":"s220","title":"Empirical Research in Supply Chain Management","track":"Supply Chain Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY A","chairs":["Dr. Brian Jacobs"],"abstracts":[{"id":"136-0259","title":"Stock Market Reactions to Social Sustainability Incidents: The Impact of Severity, Resilience, and Firm Orientation","content":"Incidents affecting factory workers' health, safety, and well-being occur at renowned manufacturing firms located in developed countries. We assess the stock market reaction to 299 international incidents and observe a significant mean abnormal return of -0.15%. Further, we demonstrate how firm characteristics on production and organizational levels influence the returns.","presenter":"Mr. Christian Wagner","authors":[{"name":"Mr. Christian Wagner","aff":"Student, ETH Zürich"},{"name":"Prof. Christoph Schmidt","aff":"Associate Professor, University of Bath"},{"name":"Dr. Maximilian Klöckner","aff":"Post Doc/Researcher, ETH Zurich"},{"name":"Prof. Stephan Wagner","aff":"Professor, ETH Zurich"}],"order":1},{"id":"136-0872","title":"Overcoming the Capacity Compression Effect – IoT-driven Smart Replenishment Strategies","content":"Our research examines how Internet-of-Things-enabled inventory information enhances ordering decisions in agricultural supply chains. A three-staged implementation of IoT-sensors, reveals a capacity compression effect that causes higher supply chain costs. Empirical results show limited improvements through IoT and Vendor-Managed-Inventory while counterfactual analyses demonstrate the theoretical benefits of inventory visibility, .","presenter":"Prof. Kai Hoberg","authors":[{"name":"Mr. Tim Schlaich","aff":"Student, Kuehne Logistics University"},{"name":"Prof. Yale Herer","aff":"Associate Professor, Technion Israel Institute of Technology"},{"name":"Prof. Kai Hoberg","aff":"Professor, Kühne Logistics University"}],"order":2},{"id":"136-0878","title":"Fast &amp; Frugal drift towards optimizing tires in trailer fleets using IoT and design echelons","content":"Suboptimal tire choice for fleets leads to inefficiencies throughout the supply chain. We use Design Science Research to solve this problem by creating a solution using IoT data and prescriptive analytics for data-driven technology management. The result is enhanced efficiency and reduced costs through optimized tire selection.","presenter":"Mr. Jens Dorniak","authors":[{"name":"Mr. Jens Dorniak","aff":"Student, Kühne Logistics University"},{"name":"Prof. Henrik Sternberg","aff":"Associate Professor, Iowa State University"},{"name":"Prof. Kai Hoberg","aff":"Professor, Kühne Logistics University"}],"order":3},{"id":"136-0185","title":"Effects of national security driven trade sanctions on shareholder value","content":"For national security reasons, the US enacted trade restrictions in 2022 on the sale of advanced semiconductors and manufacturing equipment to Chinese firms. We examine the stock market reaction to this event to estimate the financial impacts to affected firms in the US, China, and other countries.","presenter":"Dr. Brian Jacobs","authors":[{"name":"Dr. Brian Jacobs","aff":"Professor, Pepperdine University"},{"name":"Mr. Xiaoran Ma","aff":"Student, Chinese Univ of Hong Kong"},{"name":"Prof. Vinod Singhal","aff":"Professor, Georgia Institute of Technology"},{"name":"Prof. Jing Wu","aff":"Associate Professor, The Chinese University of Hong Kong"}],"order":4}]},{"id":"s288","title":"Sustainable supply chain management","track":"Supply Chain Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"HARRIS","chairs":["Prof. Stephen Gilbert","Dr. Haoying Sun"],"abstracts":[{"id":"136-0317","title":"Walled Garden or Cash Cow? Strategizing with Supporting Services","content":"Inspired by Tesla opening up its Supercharging network, we analyze a firm's dynamic decisions to open up its supporting service to a competitor. We find that the firm may indeed strategically open up the service when the market matures. We also discuss government policies regarding proprietary and open services.","presenter":"Dr. Mingliu Chen","authors":[{"name":"Ms. Yulin Hu","aff":"Student, Zhejiang University"},{"name":"Dr. Mingliu Chen","aff":"Assistant Professor, University of Texas Dallas"},{"name":"Prof. Bin Hu","aff":"Professor, Naveen Jindal School of Management"}],"order":1},{"id":"136-0402","title":"Control of Used Goods Markets and Sustainability","content":"Many products, including apparel, toys, furniture etc. have extended lifespans and maintain significant residual value, often exceeding consumers' preference to retain the product. We investigate the impact that control of used goods markets has upon pricing and quantity decisions as well as the implications for sustainability.","presenter":"Prof. Sreekumar Bhaskaran","authors":[{"name":"Prof. Stephen Gilbert","aff":"Professor, McCombs School of Business"},{"name":"Prof. Sreekumar Bhaskaran","aff":"Associate Professor, Southern Methodist University"}],"order":2},{"id":"136-0759","title":"Design of Subsidies for Environmentally Beneficial Products","content":"To combat climate change, governments offer subsidies for eco-friendly products like Electric Vehicles. Two subsidy structures emerge under a fixed budget: a high-value, short-term subsidy and a low-value, long-term subsidy. We explore the trade-offs between these structures and their impact on product adoption and environmental benefits.","presenter":"Dr. Haoying Sun","authors":[{"name":"Dr. Haoying Sun","aff":"Associate Professor, University of Kentucky"},{"name":"Prof. Stephen Gilbert","aff":"Professor, McCombs School of Business"}],"order":3}]},{"id":"s297","title":"AI, Information, and Dynamic Decision-Making","track":"POM-Marketing Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"DUNWOODY","chairs":["Prof. Yi Zhu","Mr. Weize Yin"],"abstracts":[{"id":"136-0385","title":"Sequential Search of Multi-Unit Demand Buyers","content":"I consider a model where buyers have multi-unit demand and sequentially search sellers to learn price and product match. In contrast to the unit-demand model of Wolinsky (1986), sellers' equilibrium profit can first increase and then decrease in search cost. Furthermore, buyers' equilibrium search intensity is inefficient low.","presenter":"Mr. Yue Li","authors":[{"name":"Mr. Yue Li","aff":"Assistant Professor, Shandong University"}],"order":1},{"id":"136-0776","title":"The Strategic Analysis and Implication of Data Trading","content":"This study examines the impacts of data trading on firms’ profits, consumer surplus, and social welfare. The data platform collects data from consumers by offering them privacy compensation to generate market-demand information, which is then sold to the manufacturer to support decision making.","presenter":"Ms. Xiaohan Zhou","authors":[{"name":"Ms. Xiaohan Zhou","aff":"Student, Fudan University"},{"name":"Prof. Lin Tian","aff":"Professor, Fudan University"},{"name":"Prof. Yi Zhu","aff":"Professor, University of Minnesota"}],"order":2},{"id":"136-2053","title":"New Venture Creation: A Drift Variance Diffusion Model","content":"We model the creation of a new venture with a diffusion control framework. The entrepreneur chooses costly controls, which determine the drift and the variance of the venture process. We characterize the optimal policy for the entrepreneur and provide managerial insights.","presenter":"Dr. Zhengli Wang","authors":[{"name":"Dr. Zhengli Wang","aff":"Assistant Professor, The University of Hong Kong"},{"name":"Prof. Stefanos Zenios","aff":"Professor, Stanford University"}],"order":3},{"id":"136-0655","title":"Less is More: Exploring the Impact of LLMs' Omission Mistake on Product Evaluation","content":"This study investigates the \"omission mistake,\" where a Large Language Model (LLM) overlooks part of the product attributes in a consumer’s prompt during product evaluations. Experiments confirm its occurrence and prompt dependence. Analytical modeling shows this mistake can sometimes benefit both the consumer and the seller.","presenter":"Mr. Weize Yin","authors":[{"name":"Mr. Weize Yin","aff":"Student, University of Minnesota"},{"name":"Prof. Yi Zhu","aff":"Professor, University of Minnesota"}],"order":4}]},{"id":"s317","title":"Pooling, Strategic Customers and Promotion","track":"Revenue Management and Pricing","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"MARIETTA","chairs":["Mr. Ronak Tiwari"],"abstracts":[{"id":"136-0081","title":"Impact of the \"Hidden City Ticketing'' under the Presence of Risk-Conscious Customers","content":"Hidden City Ticketing is a strategy where customers book flights with layovers at their intended destination, skipping the final leg. We analyze its impact on airline revenue, showing it can reduce revenue by half in the worst case or double it in the best case.","presenter":"Ms. Nanxi Zhang","authors":[{"name":"Mr. Jiacheng Guo","aff":"Student, Princeton U / The American U in Cairo"},{"name":"Mr. Bo Jiang","aff":"Professor, Shanghai University of Finance and Economics"},{"name":"Mr. Zikai Xiong","aff":"Student, MIT"},{"name":"Ms. Nanxi Zhang","aff":"Assistant Professor, Ivey Biusiness School, Western University"}],"order":1},{"id":"136-1320","title":"Promotion Optimization for Durable Goods","content":"The profitability of promotions is often a concern for retailers. Management scholars have episodically studied the problem of determining profit-optimal promotional prices for CPG and fast-fashion sectors, much less so - empirically. We utilize data from an online bike retailer and study promotional pricing in the less-discussed durable goods context.","presenter":"Mr. Ronak Tiwari","authors":[{"name":"Mr. Ronak Tiwari","aff":"Student, WHU - Otto Beisheim School of Management"},{"name":"Prof. Arnd Huchzermeier","aff":"Professor, WHU - Otto Beisheim School of Management"}],"order":2},{"id":"136-0031","title":"Network Revenue Management with Pooling","content":"We consider a novel variant of the network RM, where in addition to the partitioned limits, the firm keeps aside some capacity that is common to all the products. We propose solution methods to obtain the product-specific booking limits as well as the common shared capacity.","presenter":"Prof. Sumit Kunnumkal","authors":[{"name":"Mr. Asrar Ahmed","aff":"Student, Indian School of Business"},{"name":"Dr. Milind Sohoni","aff":"Professor, The State University of New York at Buffalo"},{"name":"Prof. Sumit Kunnumkal","aff":"Professor, Indian School of Business"}],"order":3}]},{"id":"s327","title":"Leveraging Platforms and Collaboration for Economic and Social Impact","track":"Product Innovation and Technology Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"COURTLAND","chairs":["Dr. Arunima Chhikara"],"abstracts":[{"id":"136-1433","title":"Delivery Service: A Food for Thought for Consumers","content":"Delivery platforms, e.g., DoorDash, Grubhub, and Uber Eats offer customers the convenience of delivery from a variety of merchants but often charge high fees in return, raising questions about their overall impact. This study uses a game-theoretic approach to investigate how these platforms influence merchant operations and customer welfare.","presenter":"Mr. Alireza Ghassemi","authors":[{"name":"Mr. Alireza Ghassemi","aff":"Student, University of Kansas"},{"name":"Prof. Soudipta Chakraborty","aff":"Assistant Professor, University of Kansas"},{"name":"Prof. Debrabata Dey","aff":"Professor, University of Kansas"}],"order":1},{"id":"136-1787","title":"Inter-Organizational Teams and Innovation Performance","content":"Inter-organizational teams can contribute to strategic alignment and shared risk-taking, improving resource utilization and operational efficiency. However, misaligned objectives and communication barriers may hinder team performance if not managed effectively. Our study underscores the potential and challenges of inter-organizational teams as drivers of sustained competitive advantage.","presenter":"Dr. Param Pal Singh Chhabra","authors":[{"name":"Dr. Param Pal Singh Chhabra","aff":"Assistant Professor, University of Alberta"},{"name":"Prof. Manpreet Hora","aff":"Professor, Georgia Institute of Technology"},{"name":"Dr. Karthik Ramachandran","aff":"Professor, Georgia Institute of Technology"}],"order":2},{"id":"136-1730","title":"Improving Skill Production with Peer-Induced Knowledge Diffusion in K-12 Schools","content":"We provide experimental evidence of the impact of peer-driven knowledge sharing on skill production in K-12 classrooms. We designed a technology platform that identifies individual students’ knowledge gaps and organizes team contests inside classrooms to induce knowledge sharing among team members.","presenter":"Dr. Anurag Garg","authors":[{"name":"Prof. Anuj Kumar","aff":"Associate Professor, University of Florida"},{"name":"Dr. Anurag Garg","aff":"Assistant Professor, University of Kansas"}],"order":3},{"id":"136-0931","title":"Technology-Driven Business Incubation: Examining the Role of Digital Platforms in Accelerating Startup Innovation","content":"The research highlights the transformative role of digital technologies in reshaping traditional business incubation models, enhancing startup support through AI, IoT, cloud computing, and big data analytics. These technologies reduce market entry barriers, optimize resource distribution, foster global networking, enabling startups to respond quickly to market demands and technological shifts.","presenter":"Prof. Rudra Prakash Pradhan","authors":[{"name":"Mr. Mohd Tabrej Alam","aff":"Student, IIT Kharagpur"},{"name":"Prof. Rudra Prakash Pradhan","aff":"Professor, Indian Institute of Technology Kharagpur"}],"order":4}]},{"id":"s331","title":"Panel: Bridging Academia and Practice: Role of POM and Community","track":"POM and Community","type":"Panel","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY F","chairs":["Prof. Chengcheng Zhai"],"abstracts":[{"id":"136-2120","title":"Panel: Bridging Academia and Practice: Role of DEI Research Centers","content":"A key goal of this panel is to have a conversation around ways to bridge academic research, pedagogy and practice, with an emphasis on the role of DEI research centers within business schools to accomplish this objective.","presenter":"Prof. Dwaipayan Roy","authors":[{"name":"Dr. Priyank Arora","aff":"Associate Professor, University of South Carolina"},{"name":"Prof. Dwaipayan Roy","aff":"Assistant Professor, University of Virginia"},{"name":"Prof. Chengcheng Zhai","aff":"Assistant Professor, Mendoza College of Business"}],"order":1}]},{"id":"s361","title":"Panel: AI for Social Good","track":"Information Systems and Operations Management","type":"Panel","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY E","chairs":["Dr. Anjana Susarla"],"abstracts":[{"id":"136-2113","title":"Panel: AI for Social Good","content":"Artificial intelligence (AI) is intertwined with almost every aspect of life. While AI has the power to advance progress, the use of AI also entails extensive social, economic and ethical implications. This panel will discuss AI safety, trust and ethics in domains ranging from mobility, education, and healthcare.","presenter":"Dr. Anjana Susarla","authors":[{"name":"Dr. Anjana Susarla","aff":"Professor, Michigan State University"},{"name":"Dr. Balaji Padmanabhan","aff":"Professor, University of South Florida"},{"name":"Prof. Heng Xu","aff":"Professor, University of Florida"},{"name":"Prof. Tinglong Dai","aff":"Professor, Johns Hopkins University"},{"name":"Prof. MS Krishnan","aff":"Professor, University of Michigan, Ann Arbor"}],"order":1}]},{"id":"s375","title":"Panel: AI for Sustainability","track":"Practice Leaders","type":"Panel","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"Learning Center","chairs":["Prof. Burak Kazaz","Prof. Scott Webster","Dr. Saurabh Bansal"],"abstracts":[{"id":"136-2133","title":"Panel: AI for Sustainability","content":"In this session, experts from industry will share their experiences and insights into how AI is transforming industry practices and shaping sustainability efforts in the agriculture, pharmaceutical, and transportation sectors.","presenter":"Prof. Burak Kazaz","authors":[{"name":"Prof. Burak Kazaz","aff":"Professor, Whitman School of Management"},{"name":"Ms. Jess Bolinger","aff":"Director of Strategy, Sustainability and Public Relations, Regrow Ag"},{"name":"Dr. Mabby Amouie","aff":"AVP Enterprise Data &amp; Analytics, Norfolk Southern"},{"name":"Mr. Ankit Kohli","aff":"AI Leader, ."}],"order":1}]},{"id":"s436","title":"Using AI &amp; Analytics for forecasting and prediction","track":"Data Science, Analytics and AI","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"ROSWELL","chairs":["Dr. Mona Jabbari"],"abstracts":[{"id":"136-0238","title":"Data-Driven Forecasting for Tourism Operations Management","content":"This study leverages multimodal data, including user-generated content from social media platforms, to design advanced models for predicting tourism demand. By integrating state-of-the-art forecasting methodologies, it uncovers complex patterns in tourism dynamics, offering actionable insights. These insights support optimized resource allocation and streamlined operations, ultimately improving management efficiency.","presenter":"Dr. Xin Li","authors":[{"name":"Dr. Xin Li","aff":"Associate Professor, University of Science and Technology Beijing"},{"name":"Prof. Xiangbin Yan","aff":"Professor, University of Science and Technology Beijing"}],"order":1},{"id":"136-0880","title":"Predicting Product Life Cycles: An Experiment from the Gaming Industry","content":"In this research, we focus on the improvement of the product life cycle prediction accuracy in the gaming industry. We include visual specifications of products to understand their influence on sales. We utilize time series clustering techniques to identify crucial features differentiating sales patterns among similar products.","presenter":"Mrs. Azadeh Arjmand","authors":[{"name":"Mrs. Azadeh Arjmand","aff":"Student, State University of New York at Buffalo"},{"name":"Dr. Milind Sohoni","aff":"Professor, The State University of New York at Buffalo"},{"name":"Dr. Aditya Vedantam","aff":"Associate Professor, University of Buffalo"},{"name":"Dr. Inki Sul","aff":"Assistant Professor, University at Buffalo"}],"order":2},{"id":"136-1881","title":"Incorporating Deep Learning into System Dynamics: Amortized Bayesian Inference for Scalable Likelihood-free Parameter Estimation","content":"We developed a framework to integrate Amortized Bayesian Inference methods, focusing on Neural Posterior Estimation, with complex system dynamics models. We show how neural networks can be trained and used to infer parameter estimates and their credible intervals. We also introduce metrics to evaluate the quality of inference systematically.","presenter":"Dr. Ali Akhavan","authors":[{"name":"Prof. Hazhir Rahmandad","aff":"Professor, Sloan School of Management"},{"name":"Dr. Ali Akhavan","aff":"Post Doc/Researcher, Massachusetts General Hospital and MIT"},{"name":"Prof. Mohammad Jalali","aff":"Associate Professor, Harvard University"}],"order":3},{"id":"136-1950","title":"Systematic Feature Evaluation with Global and Local Prediction Importance Techniques","content":"This paper presents Global and Local Prediction Importance, methods to assess feature importance by comparing model performance with and without specific features. These approaches provide unbiased estimates of each feature's contribution to prediction accuracy.","presenter":"Dr. Mona Jabbari","authors":[{"name":"Dr. Mona Jabbari","aff":"Assistant Professor, University of Colorado Colorado Springs"},{"name":"Dr. Meysam Rabiee","aff":"Assistant Professor, University of Colorado Denver"}],"order":4}]},{"id":"s0","title":"AI and Digital Platforms","track":"Information Systems and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY E","chairs":["Dr. Jinan Lin","Jiaqi Shi"],"abstracts":[{"id":"136-1125","title":"Foundation Models and AI Innovation: Evidence from the Hugging Face Platform","content":"Large-scale pre-trained models transform AI development, exhibiting new economies of scale. Our research investigates their impact on AI innovation and competition among developers, on Hugging Face platform. Results reveal experienced developers respond to Llama 3 with increased innovation rate, pursuing vertical and horizontal differentiation strategies through parameters, datasets, and datacard.","presenter":"Mr. David Wu","authors":[{"name":"Mr. David Wu","aff":"Student, University of Wisconsin-Madison"},{"name":"Dr. Jinan Lin","aff":"Professor, University of Wisconsin"},{"name":"Dr. Zhuoxin (Allen) Li","aff":"Associate Professor, University of Wisconsin-Madison"}],"order":1},{"id":"136-1251","title":"RIPPLE EFFECT OF PRICE CHANGES: EXPLORING THE IMPACT OF ADAPTIVE PRICING ON LONG-TERM CUSTOMER EXPENDITURES","content":"We explore the impact of adaptive pricing on customer behavior, revealing that frequent or significant price changes can reduce long-term customer expenditure by 2%, with spillover effects across product categories. Incorporating such customer responses into pricing strategies can boost per product revenue by 3.23%, on average.","presenter":"Dr. Inki Sul","authors":[{"name":"Prof. Ozalp Ozer","aff":"Professor, University of Texas Dallas"},{"name":"Dr. Inki Sul","aff":"Assistant Professor, University at Buffalo"},{"name":"Dr. Serdar Simsek","aff":"Associate Professor, University of Texas Dallas"}],"order":2},{"id":"136-1412","title":"Competing with GenAI: A Two-Period Game-Theoretic Model","content":"Two heterogeneous firms compete using AI in high- and low-margin markets over two periods. First-period AI usage influences second-period productivity gains, with spillover effects on the competitor. Depending on the spillover rate and initial lead in the high-margin market, these spillover effects can undermine the leading firm’s competitive advantage.","presenter":"Ms. Guoxing He","authors":[{"name":"Ms. Guoxing He","aff":"Student, The University of Hong Kong"},{"name":"Prof. Chunghan Kang","aff":"Assistant Professor, The University of Hong Kong"},{"name":"Prof. Feng Tian","aff":"Assistant Professor, The University of Hong Kong"}],"order":3},{"id":"136-1617","title":"Design and Development of a Diet Management AI Chatbot for Patients with Type 2 Diabetes","content":"This study presents Salutem, an AI chatbot for type 2 diabetes dietary management. Using a Design Science Research approach, it integrates cultural dietary preferences, personalized recommendations, digital nudges, and progress tracking. Salutem addresses existing solution gaps, improving user engagement, adherence, and usability through machine learning-driven personalization.","presenter":"Dr. Raj Sharman","authors":[{"name":"Dr. Pavan Mulgund","aff":"Assistant Professor, The University of Memphis"},{"name":"Dr. Raj Sharman","aff":"Professor, Suny At Buffalo"},{"name":"Dr. Yafang Li","aff":"Assistant Professor, The University of Memphis"}],"order":4}]},{"id":"s7","title":"Empirical OM Research on POM and Community","track":"POM and Community","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY F","chairs":["Dr. Li Cheng"],"abstracts":[{"id":"136-0437","title":"Doing Less Good: Pollution Reduction in Minority Communities, Evidence from Manufacturing Facilities in the US","content":"Past environmental justice literature has primarily focused on higher levels of toxic emissions in minority communities, doing more harm. This research builds on this to explore whether facilities in minority communities implement fewer pollution reduction activities, doing less good. The results indicate this is the case.","presenter":"Dr. Dustin Cole","authors":[{"name":"Dr. Dustin Cole","aff":"Assistant Professor, Auburn University"},{"name":"Prof. Suresh Muthulingam","aff":"Professor, Penn State University University Park"}],"order":1},{"id":"136-1449","title":"Collaborative Growth: How Minority-Owned Businesses Thrive with Retail Partnerships","content":"This paper examines the role of retailers' electronic logistics service quality (ELSQ) in enhancing perceptions of minority-owned business products. By exploring how ELSQ impacts customer purchase intentions the study highlights strategies for retailers to boost minority business success, fostering inclusivity and equity within modern supply chains","presenter":"Dr. Saif Mir","authors":[{"name":"Dr. Saif Mir","aff":"Assistant Professor, Lehigh University"},{"name":"Dr. Christian Hofer","aff":"Professor, University of Arkansas"},{"name":"Dr. Stephanie Thomas","aff":"Associate Professor, University of Arkansas - Fayetteville"}],"order":3},{"id":"136-0592","title":"DEI Rollback or Spike: DEI Performance and Operational Performance","content":"The true impact of DEI performance on operational performance remains a primary concern for many firms. We apply BERT and DiD techniques to examine this impact and relevant moderators. Drawing on the signaling theory perspective, we show this positive relationship is continuously stronger for more innovations and lower competitive networks.","presenter":"Mr. Shucheng MIAO","authors":[{"name":"Mr. Shucheng MIAO","aff":"Student, The Hong Kong Polytechnic University"}],"order":4}]},{"id":"s24","title":"Healthcare Payment Models","track":"Healthcare Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"PIEDMONT","chairs":["Dr. Zahra Mobini"],"abstracts":[{"id":"136-0117","title":"The role of physician integration in alternative payment models","content":"We study how horizontal and vertical integration of orthopaedic surgeons drives heterogeneity in hospital outcomes under the Comprehensive Joint Replacement alternative payment model. We find that hospitals with highly integrated physicians received increased payments from Medicare with no changes in complications or patient satisfaction.","presenter":"Dr. Christopher Chen","authors":[{"name":"Dr. Christopher Chen","aff":"Assistant Professor, Indiana University"},{"name":"Dr. Kraig Delana","aff":"Assistant Professor, IE BUSINESS SCHOOL"}],"order":1},{"id":"136-0480","title":"Impact of Copay Accumulator Ban: Evidence from National Healthcare Utilization Data on Drug Payments","content":"The recent federal copay accumulator ban, which undoes insurers' restrictions on brand drug manufacturers' copay assistance to patients, represents the latest development in a decade-long payment game. We investigate the ban's impact on (1) patient adherence, affordability, and access, (2) health equity, and (3) insurers' spending and potential long-term consequences.","presenter":"Mr. Ji Won Moon","authors":[{"name":"Mr. Ji Won Moon","aff":"Student, Pennsylvania State University"},{"name":"Prof. Hui Zhao","aff":"Professor, Pennsylvania State University"},{"name":"Prof. Feng (Susan) Lu","aff":"Professor, Purdue University"}],"order":2},{"id":"136-0504","title":"The \"Netflix Model\": A New Payment Model for Asymptomatic Disease Management","content":"Several state governments (e.g., Louisiana and Washington) recently entered into Netflix-style procurement contracts with pharmaceutical companies.\r\nWe analyze this novel subscription-based payment model from a mechanismdesign perspective, and characterize conditions under which such a\r\ncontract would benefit both pharma and payer, as well as improve the overall market efficiency.","presenter":"Dr. Zhaowei She","authors":[{"name":"Dr. Zhaowei She","aff":"Assistant Professor, Singapore Management University"},{"name":"Dr. Huaiyang Zhong","aff":"Assistant Professor, Virginia Tech"},{"name":"Dr. Yueran Zhuo","aff":"Assistant Professor, Mississippi State University"},{"name":"Prof. Turgay Ayer","aff":"Professor, Georgia Tech"},{"name":"Dr. Jagpreet Chhatwal","aff":"Associate Professor, Harvard University"}],"order":3},{"id":"136-0641","title":"Beyond the Budget: The Unseen Costs of Maryland’s Hospital Payment Reforms","content":"To rein in healthcare costs, Maryland implemented a global budget revenue (GBP) program for its hospitals, establishing yearly cost growth targets for all inpatient and outpatient services. Leveraging an extensive claims dataset for commercially insured individuals, our study empirically examines how GBR influences care delivery patterns within hospitals.","presenter":"Dr. Zahra Mobini","authors":[{"name":"Dr. Zahra Mobini","aff":"Assistant Professor, Georgia Institute of Technology"},{"name":"Mr. Austin Mccandlish","aff":"Student, Georgia Institute of Technology"},{"name":"Prof. Turgay Ayer","aff":"Professor, Georgia Tech"}],"order":4}]},{"id":"s40","title":"Disaster Response: Information, Optimization, and Evacuation Strategies","track":"Humanitarian Operations and Crisis Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY G","chairs":["Dr. Trilce Encarnacion"],"abstracts":[{"id":"136-1164","title":"Sheltering During the Storm: An Analysis of Shelter Choices via the Protective Action Decision Model","content":"Flash floods challenge disaster management due to their unpredictability and rapid onset. This study uses the Protective Action Decision-Making framework and Hybrid Discrete Choice modeling to examine individual behavioral responses, addressing gaps in risk communication. Findings support strategies to reduce preventable deaths, enhance disaster response, and strengthen community resilience.","presenter":"Ms. Paula Penagos","authors":[{"name":"Ms. Paula Penagos","aff":"Student, University of Missouri - Saint Louis, MO"},{"name":"Dr. Trilce Encarnacion","aff":"Assistant Professor, University of Missouri St Louis"}],"order":1},{"id":"136-1717","title":"Optimization of Truck and Drone Operations for Socially Optimal Disaster Relief Distribution","content":"The study develops a mixed-integer non-linear model comprising the routing, location, and allocation decisions for the distribution of relief supplies to survivors after a disaster using a hybrid fleet of drones and trucks. The formulation minimizes a social cost function comprising logistic and suffering costs for socially optimal disaster relief.","presenter":"Prof. Sofia Perez-Guzman","authors":[{"name":"Mr. Ricardo Modrego Eisman","aff":"Student, Georgia Institute of Technology"},{"name":"Prof. Sofia Perez-Guzman","aff":"Assistant Professor, Georgia Institute of Technology"},{"name":"Dr. Rosemarie Santa Gonzalez","aff":"Post Doc/Researcher, Georgia Institute of Technology"}],"order":2},{"id":"136-0511","title":"Rolling Horizon Two-Stage Stochastic Programming for Hurricane Relief Logistics","content":"We present a novel rolling horizon two-stage stochastic programming model for hurricane relief logistics, updated every six hours with new scenarios. By addressing progressive uncertainty and optimizing pre- and post-disaster operations, our approach enhances decision-making for humanitarian agencies like FEMA, improving disaster response efficiency and outcomes for affected communities.","presenter":"Prof. Ali Tolooie","authors":[{"name":"Prof. Ali Tolooie","aff":"Assistant Professor, Mercer University"},{"name":"Prof. Marzieh Soltanolkottabi","aff":"Assistant Professor, University of New Haven"}],"order":3},{"id":"136-1098","title":"The Impact of Psychic Distance on Donation Behavior During Sudden Onset Disasters","content":"Material convergence may be managed by understanding donor behavior: how people make donation decisions. Psychic Distance can be used to explain the dynamics between the donor and the beneficiaries, helping us understand donation behavior and choices.","presenter":"Prof. Nezih Altay","authors":[{"name":"Mr. Can Erzi","aff":"Student, Sabanci University"},{"name":"Dr. Raha Akhavan","aff":"Professor, Sabanci University"},{"name":"Prof. Nezih Altay","aff":"Professor, Depaul University"}],"order":4}]},{"id":"s43","title":"Information Systems Applications for Humanitarian Operations","track":"Humanitarian Operations and Crisis Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"GRAND HALL EAST B","chairs":["Ms. Marialena Bevilacqua"],"abstracts":[{"id":"136-0077","title":"Keeping the Human in Humanitarian: The Effects of Artificial Intelligence on Donations to Humanitarian Organizations","content":"The continued rise in the adoption of artificial intelligence among humanitarian organizations may prove beneficial to their operational performance. Yet, private donors' preferences for the technology’s use are unknown. Through online conjoint experiments, we investigate private donor preferences for humanitarian organizations with varying attributes, including AI involvement in decision-making.","presenter":"Ms. Marialena Bevilacqua","authors":[{"name":"Ms. Marialena Bevilacqua","aff":"Student, Mendoza College of Business"},{"name":"Mr. Cameron Kormylo","aff":"Student, University of Notre Dame"},{"name":"Prof. Alfonso Pedraza-Martinez","aff":"Professor, Mendoza College of Business"}],"order":1},{"id":"136-0463","title":"AI-Powered Philanthropy: Effects on Volunteer Productivity","content":"Nonprofit organizations are incorporating AI to enhance volunteer performance. Given that volunteers are motivated by generating impact and altruism, the effect of AI in the volunteering context is an open question. We answer this using data from an online volunteering platform that implemented an AI tool that complements volunteers’ work.","presenter":"Dr. Gloria Urrea","authors":[{"name":"Mr. Vinit Tipnis","aff":"Student, Indiana University Bloomington"},{"name":"Dr. Eunae Yoo","aff":"Assistant Professor, Indiana University Bloomington"},{"name":"Dr. Gloria Urrea","aff":"Assistant Professor, University of Colorado Boulder"},{"name":"Dr. Fei Gao","aff":"Associate Professor, Indiana University Bloomington"}],"order":2},{"id":"136-0551","title":"Authenticity in Action: Boosting Operational Transparency and Donations","content":"This study explores how humanitarian workers' authentic communication of operational transparency during crisis enhances information diffusion and donations. Analyzing tweets that convey operational transparency, the findings reveal that authentic communication with modest positive emotion boosts engagement. Using experiments, we are to validate these findings and explore their impact on donations.","presenter":"Prof. Lea Ruesch","authors":[{"name":"Prof. Lea Ruesch","aff":"Assistant Professor, IE BUSINESS SCHOOL"},{"name":"Dr. Emily Dickey","aff":"Assistant Professor, University of Tennessee"},{"name":"Prof. Maria Besiou","aff":"Professor, Kuehne Logistics University"},{"name":"Prof. Niels Van Quaquebeke","aff":"Professor, Kuehne Logistics University"},{"name":"Prof. Chrstian Tröster","aff":"Professor, Kühne Logistics Univesity"}],"order":3},{"id":"136-1015","title":"Social Media Strategies and Donations During Disasters","content":"We employ a VAR modeling approach to examine the relationship between Twitter activity and donation behavior. Our results establish two distinct mechanisms through which DROs' tweets drive donation activity. We also find that tweets eliciting positive empathy are particularly effective in encouraging donations.","presenter":"Dr. Changseung (Chang) Yoo","authors":[{"name":"Dr. Eunae Yoo","aff":"Assistant Professor, Indiana University Bloomington"},{"name":"Dr. Changseung (Chang) Yoo","aff":"Assistant Professor, Mcgill University"},{"name":"Prof. Lu (Lucy) Yan","aff":"Associate Professor, Indiana University Bloomington"},{"name":"Prof. Alfonso Pedraza-Martinez","aff":"Professor, Mendoza College of Business"}],"order":4}]},{"id":"s63","title":"Smart Strategies in AI, Retail, and On-Demand Platforms","track":"Disruptive Technologies and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"KENNESAW","chairs":["Dr. Chenglong Zhang"],"abstracts":[{"id":"136-0702","title":"Optimal Order Assignment Policy for a Hybrid Workforce On-Demand Delivery Platform","content":"We study an order assignment problem with heterogeneous orders in a hybrid workforce on-demand delivery platform. We develop an infinite horizon discrete-time event-based MDP model and propose an optimal state-dependent policy which is mainly determined by delivery fees of orders, wages of drivers, and order rejection penalty.","presenter":"Prof. Mingzheng Wang","authors":[{"name":"Prof. Mingzheng Wang","aff":"Professor, Zhejiang University"},{"name":"Dr. Haohan Li","aff":"Student, Zhejiang University"},{"name":"Prof. Yun Fong Lim","aff":"Professor, Singapore Management University"},{"name":"Prof. Hai Wang","aff":"Associate Professor, Singapore Management University"}],"order":2},{"id":"136-0749","title":"To Purchase or Develop? Strategies to Procure AI Service","content":"Nowadays, firms consider integrating AI services into their products. These product firms may purchase AI services from AI-specialized companies or develop by themselves. We study procurement strategies in this context characterized by development uncertainties, consumers' heterogeneous valuations of AI, and AI's interaction with products' other components.","presenter":"Dr. Chenglong Zhang","authors":[{"name":"Dr. Zhengrui Jiang","aff":"Professor, Chinese Univ of Hong Kong (Shenzhen)"},{"name":"Ms. Jiayin Liu","aff":"Student, Chinese Univ of Hong Kong (Shenzhen)"},{"name":"Dr. Chenglong Zhang","aff":"Assistant Professor, Chinese Univ of Hong Kong (Shenzhen)"}],"order":3},{"id":"136-0980","title":"Retailers' Inventory Information Disclosure on Platforms","content":"Grocery platforms such as Instacart offer customers a wide range of grocery stores to choose from. Groceries need to be delivered in short time and inventory availability is important. We analyze the optimal inventory disclosure decisions for retailers and the platform.","presenter":"Dr. Xuying Zhao","authors":[{"name":"Mr. Tolga Dizdarer","aff":"Assistant Professor, Boston College"},{"name":"Prof. Dmitry Mitrofanov","aff":"Assistant Professor, Boston College"},{"name":"Dr. Xuying Zhao","aff":"Associate Professor, Texas A&amp;M University College Station"}],"order":4}]},{"id":"s67","title":"Management of Supply Base and Network","track":"Procurement and Supplier Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"LENOX","chairs":["Prof. Seongkyoon Jeong"],"abstracts":[{"id":"136-1294","title":"Supply base complexity in times of crisis: Moderating the negative impact of the Russia-Ukraine war","content":"Our study reveals that automotive firms experience a negative market reaction following the war, which is propagated to their customers in other industries. It further reveals that supply base complexity has differential moderating effects during the crisis, depending on whether its structure is more horizontally focused or vertically oriented.","presenter":"Dr. Seongtae Kim","authors":[{"name":"Dr. Seongtae Kim","aff":"Assistant Professor, Aalto University"},{"name":"Dr. Nishat Choudhury","aff":"Post Doc/Researcher, Aalto University"},{"name":"Ms. Petriina Heikkinen","aff":"Student, Aalto University"}],"order":1},{"id":"136-1852","title":"Firm-Level Small-Worldliness: Exploring the Structural Characteristics and Performance Effects","content":"Small-world networks, characterized by clustered groups linked through occasional distant connections, are typically studied at the network level for their impact on innovation. This study examines individual-level structural properties that enhance small-worldliness effects in high-tech manufacturing networks, identifying different factors than those found at the network level.","presenter":"Dr. Hyunwoo Park","authors":[{"name":"Dr. Yusoon Kim","aff":"Associate Professor, Oregon State University"},{"name":"Dr. Hyunwoo Park","aff":"Associate Professor, Seoul National University"}],"order":2},{"id":"136-1838","title":"Assessing Spatial Matching Mechanisms with Supplier Regret in Digital Platforms","content":"This research develops a framework for spatial matching on ride-sharing platforms, examining how drivers’ regret influences relocation decisions. Combining location and pricing data with simulations, it evaluates system performance under various matching policies, offering insights to optimize welfare and profitability while incorporating behavioral factors into policy design.","presenter":"Prof. Brad Kyungmin Lee","authors":[{"name":"Prof. Brad Kyungmin Lee","aff":"Assistant Professor, Salisbury University"},{"name":"Prof. Nitin Joglekar","aff":"Associate Professor, Villanova University"}],"order":3},{"id":"136-0367","title":"Supply Base ESG Disclosures and Focal Firm Innovation","content":"The supply base is in the direct purview of a focal firm. Its performance can send signals to the market that can impact its buyer focal firm. Hence, we examine how supply base ESG disclosures effect a focal firm's innovation under boundary conditions.","presenter":"Mr. Nitin Jain","authors":[{"name":"Mr. Nitin Jain","aff":"Student, IIM Udaipur"},{"name":"Dr. Anirban Adhikary","aff":"Associate Professor, IIM Udaipur"},{"name":"Dr. Sreejith Kumar Krishnakumar","aff":"Assistant Professor, Indian Institute of Management Udaipur"}],"order":4}]},{"id":"s91","title":"Behavioral Insights into Workforce Scheduling","track":"Behavioral Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY D","chairs":["Prof. Ryan Buell","Ms. Paige Tsai"],"abstracts":[{"id":"136-0149","title":"To Each Their Own (Shifts): Incorporating Preferences into Shift Work Schedules","content":"We explore a potential organizational lever—incorporating heterogeneous preferences over shift design—to mitigate detrimental ramifications of shift work in the context of acute care bedside nurses. Using survey, administrative, and shift data, we investigate how individual choice over shift dimensions influences worker well-being and turnover.","presenter":"Ms. Harriet Jeon","authors":[{"name":"Ms. Harriet Jeon","aff":"Student, Wharton School, University of Pennsylvan"},{"name":"Dr. Song-Hee Kim","aff":"Associate Professor, Seoul National University"},{"name":"Prof. Hummy Song","aff":"Assistant Professor, The Wharton School"}],"order":1},{"id":"136-0220","title":"The Impact of Scheduling Fairness on Employee Turnover","content":"We explore drivers of job sustainability in the restaurant industry. We leverage field data from a large restaurant group to better understand the impact of shift unfairness on employee turnover and find that relative unfairness — as compared to one’s peers — is a strong predictor of employee attrition.","presenter":"Ms. Paige Tsai","authors":[{"name":"Ms. Paige Tsai","aff":"Student, Harvard Business School"},{"name":"Prof. Ryan Buell","aff":"Professor, Harvard Business School"}],"order":2},{"id":"136-0357","title":"Policing Staffing and Fairness: Evidence from Atlanta Police Department","content":"This study analyzes 4.7 million 911 records from Atlanta, revealing significant disparities in police response times, with longer delays in wealthier areas. Using causal inference, we show police staffing policies plays significant roles. We propose an optimization framework that reallocates resources, improving equity and efficiency without additional staffing.","presenter":"Mr. Jonathan Zhou","authors":[{"name":"Mr. Jonathan Zhou","aff":"Student, Georgia Tech"},{"name":"Dr. Qiuping Yu","aff":"Associate Professor, Georgetown University"},{"name":"Prof. Yao Xie","aff":"Professor, Georgia Tech"}],"order":3}]},{"id":"s105","title":"Digital Payments, Sanctions, and Financing Impact on Supply Chains","track":"POM-Economics Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"TECHWOOD","chairs":["Prof. Wenqiang Xiao","Mr. Chuanshuai Ru"],"abstracts":[{"id":"136-0083","title":"Examining the Role of Digital Voucher Payments in Supply Chain Finance","content":"With the rapid development of blockchain technology, many more participants in a supply chain adopt digital voucher payments. In this study, we focused on the role of digital voucher payment in supply chain finance to find its coordination role and financial function. Business insights are thus discussed.","presenter":"Dr. Xun Xu","authors":[{"name":"Dr. Yaobin Wu","aff":"Assistant Professor, Shanghai University"},{"name":"Prof. Xiangfeng Chen","aff":"Professor, Fudan University"},{"name":"Dr. Xun Xu","aff":"Associate Professor, California State University Dominguez Hills"},{"name":"Dr. Gangshu Cai","aff":"Professor, Santa Clara University"}],"order":1},{"id":"136-0662","title":"To Comply or Not to Comply: Understanding Neutral Country Supply Chain Responses to Russian Sanctions","content":"This study examines how neutral countries' firms adapted supply chains post-2022 Ukraine invasion under Western sanctions on Russia. It reveals that while sanctioning-country firms reduced exports, neutral domestic firms increased sanctioned exports, undermining sanctions. Multinationals show a mix of compliance and evasion. Financial sanctions influenced trade finance-intensive sectors.","presenter":"Prof. Jing Wu","authors":[{"name":"Prof. Haishi Li","aff":"Assistant Professor, University of Hongkong"},{"name":"Prof. Zhi Li","aff":"Student, The Chinese University of Hong Kong"},{"name":"Prof. Ziho Park","aff":"Assistant Professor, National Taiwan University"},{"name":"Prof. Jing Wu","aff":"Associate Professor, The Chinese University of Hong Kong"}],"order":2},{"id":"136-0683","title":"Buyback Contracts and Multi-Party Signaling in Supply Chain Financing","content":"We examine a novel financing scheme in which a supplier employs buyback contracts to facilitate external funding for the downstream reseller. Through a multi-party signaling framework, we uncover the informational, financial, and operational benefits of buyback contracts, emphasizing their effectiveness in mitigating information asymmetry within supply chain financing.","presenter":"Mr. Chuanshuai Ru","authors":[{"name":"Mr. Chuanshuai Ru","aff":"Student, Shanghai Jiao Tong University"},{"name":"Prof. Fangruo Chen","aff":"Professor, Shanghai Jiao Tong University"},{"name":"Prof. Guoming Lai","aff":"Associate Professor, University of Texas Austin"},{"name":"Prof. Wenqiang Xiao","aff":"Professor, New York University"}],"order":3},{"id":"136-1339","title":"Financing R&amp;D in Innovation Value Chains","content":"This work presents an analytical framework where a manufacturer supports supplier innovation through corporate venture capital (CVC), with the new market interacting with the supplier’s home market. We compare contracts with and without CVC financing to examine its impact on innovation within the supply chain.","presenter":"Dr. Jin YAO","authors":[{"name":"Dr. Jin YAO","aff":"Assistant Professor, Lingnan Univ"},{"name":"Prof. S. Alex Yang","aff":"Professor, London Business School"},{"name":"Dr. Liao Wang","aff":"Associate Professor, The University of Hong Kong"}],"order":4}]},{"id":"s125","title":"Workshop: Manufacturing Analytics System (MAS): What It Is And What It Brings","track":"Operational Excellence","type":"Workshop","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"BAKER","chairs":["Prof. Torbjørn Netland"],"abstracts":[{"id":"136-2123","title":"Workshop: Manufacturing Analytics System (MAS): What It Is And What It Brings1","content":"Manufacturing Analytics System (MAS) is a new category of industrial software that helps manufacturing companies put AI to purposeful use. In this session, we will present and demonstrate what MAS is, how it works, and how leading companies use MAS to gain tangible operational benefits. 1","presenter":"Prof. Torbjørn Netland","authors":[{"name":"Prof. Torbjørn Netland","aff":"Professor, ETH Zurich"}],"order":1},{"id":"136-2116","title":"Manufacturing Analytics System (MAS): What It Is And What It Brings","content":"Manufacturing Analytics System (MAS) is a new category of industrial software that helps manufacturing companies put AI to purposeful use. In this session, we will present and demonstrate what MAS is, how it works, and how leading companies use MAS to gain tangible operational benefits.","presenter":"Prof. Torbjørn Netland","authors":[{"name":"Prof. Torbjørn Netland","aff":"Professor, ETH Zurich"},{"name":"Mr. Julian Senoner","aff":"Student, Eth Zurich"}],"order":2}]},{"id":"s141","title":"Supply Chain Resilience and Sustainability","track":"Empirical Research in Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"INMAN","chairs":["Mr. Wenting Li"],"abstracts":[{"id":"136-0308","title":"Port Congestion and Resilience Effects on Supply Chains","content":"We examine US port congestion and resilience, focusing on the impact of external shocks, such as weather events, on supply chain flows. We examine these flows over time and across industries, aiming to inform policy on infrastructure investment to alleviate port congestion and improve resilience.","presenter":"Ms. Elham Zafarani","authors":[{"name":"Ms. Elham Zafarani","aff":"Student, Arizona State University"},{"name":"Prof. Elliot Rabinovich","aff":"Professor, Arizona State University Tempe"},{"name":"Prof. Scott Webster","aff":"Professor, Arizona State University Tempe"}],"order":1},{"id":"136-0692","title":"Optimizing Procurement Tactics: Navigating Unreliable Suppliers and Quantity Constraint","content":"In a volatile global supply chain, identifying optimal supplier selection and order allocation strategies is crucial, especially when faced with uncertainties and a predefined upper limit on supplier count. Our study introduces a multi-supplier framework with theoretical underpinnings, which enables the proposal of tractable algorithms.","presenter":"Ms. Ning Ma","authors":[{"name":"Ms. Ning Ma","aff":"Student, Arizona State University"},{"name":"Prof. Heng Zhang","aff":"Assistant Professor, Arizona State University"},{"name":"Prof. Yimin Wang","aff":"Associate Professor, Arizona State University"}],"order":2},{"id":"136-0751","title":"More or less: Net-zero target and supplier inventory levels","content":"Firms often claim environmental commitments, including net-zero targets, which can significantly influence the operational decisions of their suppliers. For example, suppliers may reduce inventory levels to mitigate the rising holding costs associated with the uncertainties of these net-zero targets. In this study, we focus on the supplier decision-making process.","presenter":"Dr. Jie Lian","authors":[{"name":"Dr. Jie Lian","aff":"Assistant Professor, University of Oklahoma"},{"name":"Prof. Yan Dong","aff":"Professor, University of South Carolina"},{"name":"Prof. Keith Skowronski","aff":"Associate Professor, University of South Carolina"}],"order":3},{"id":"136-0266","title":"Operational Violations of Organizations’ Espoused Values: How Ethical Weight Shapes Public Support","content":"Motivated by recent backlash against corporate value statements (e.g., those involving ESG and DEI), we use primary experimental data to examine how people react when a corporation’s operational actions violate the values it has publicly embraced. We find that the novel concept of a value’s “ethical weight” moderates this relationship.","presenter":"Mr. Angel Perez-Vila","authors":[{"name":"Mr. Angel Perez-Vila","aff":"Student, University of Cincinnati"},{"name":"Prof. Craig Froehle","aff":"Professor, University of Cincinnati"}],"order":4}]},{"id":"s142","title":"Emerging contexts in operations and supply chain management","track":"Empirical Research in Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY B","chairs":["Ms. Jasmina Holst"],"abstracts":[{"id":"136-0599","title":"Managing supplier sustainability in multi-tier supply chains: Productizing sustainability attributes","content":"Firms struggle with improving and proving supply chain sustainability due to limited visibility and monitoring-costs. An emerging approach is to source sustainability attributes separately from the core product, resulting in the productization of sustainability. This qualitative study explores the adoption of this approach and its implications for the buyer-supplier relationship.","presenter":"Mr. Ramón van Almsick","authors":[{"name":"Mr. Ramón van Almsick","aff":"Student, Kuehne Logistics University"},{"name":"Prof. Moritz Petersen","aff":"Associate Professor, Kuehne Logistics University"},{"name":"Prof. Maria Besiou","aff":"Professor, Kuehne Logistics University"}],"order":1},{"id":"136-0730","title":"Supply Chains under Attack: The Impact of Wars on Global Supply Chains","content":"This research defines the construct of war-related disruptions and explores its impact on supply chains. Drawing on unique case data collected at the onset of the Russia-Ukraine war in 2022, several constraints have been identified and modeled, revealing their impact on supply chains at local, regional, and global levels.","presenter":"Ms. Jasmina Holst","authors":[{"name":"Ms. Jasmina Holst","aff":"Post Doc/Researcher, ETH Zürich"},{"name":"Prof. Maria Besiou","aff":"Professor, Kuehne Logistics University"}],"order":2},{"id":"136-1123","title":"Supply Chain Emergence in Nascent Industries - A Study of the Plant-based Meat Sector","content":"This case study explores how six new ventures in the emerging plant-based meat industry shape and scale their supply chains. It highlights power asymmetry, ambidextrous tensions, and the multifaceted role of SCM as distinctive features of the entrepreneurial growth phase and identifies three scaling modes: vertical, horizontal and replication scaling","presenter":"Mr. Tim Schlaich","authors":[{"name":"Mr. Tim Schlaich","aff":"Student, Kuehne Logistics University"},{"name":"Dr. Benn Lawson","aff":"Professor, Oxford University"},{"name":"Prof. Kai Hoberg","aff":"Professor, Kühne Logistics University"}],"order":3},{"id":"136-1356","title":"The Impact of the Fear of Being Replaced by an Algorithm on Algorithm-Augmented Decision-Making","content":"In addition to various behavioral biases and contextual factors affecting Algorithm-augmented decision-making in operations, emotions play an important role. Using a lab experiment, we manipulate the fear of replacement by an Algorithm, the most reported emotion among those working with them, and show how it affects decision-making process and performance.","presenter":"Mr. Seyyed Iman Moosavi","authors":[{"name":"Mr. Seyyed Iman Moosavi","aff":"Student, Tilburg University"},{"name":"Prof. Jan Fransoo","aff":"Professor, Tilburg University"},{"name":"Prof. Prisca Brosi","aff":"Associate Professor, Kühne Logistics University"}],"order":4},{"id":"136-1986","title":"An Empirical Study on Operational Agility and Long-term Firm Performance","content":"Past survey-based cross-sectional studies have predominantly identified a positive linkage between agility and firm performance. This study reviews potential side effects of agility and evaluates long-term firm performance using financial data. The research informs practices by pinpointing the optimal level of agile actions.","presenter":"Dr. Zhezhu Wen","authors":[{"name":"Dr. Zhezhu Wen","aff":"Assistant Professor, California State University at Fresno"},{"name":"Ms. Pingping Tang","aff":"Student, Washington State University Pullman"}],"order":5}]},{"id":"s181","title":"Data-driven operational efficiency improvements in food supply chains","track":"Agriculture and Food Supply Chains","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"VININGS","chairs":["Prof. Maya Ganesh"],"abstracts":[{"id":"136-1027","title":"A Variational Inequality Trade Network Model in Prices and Quantities Under Commodity Losses","content":"This paper presents a variational inequality trade network model in price and quantity variables, addressing transportation losses due to perishability(Agriculture) or theft. It establishes equilibrium conditions and variational inequality formulation. The numerical examples yield insights into the impacts of commodity losses, increased congestion, and enhanced marketing on producers and consumers.","presenter":"Ms. Samirasadat Samadi","authors":[{"name":"Prof. Anna Nagurney","aff":"Professor, University of Massachusetts Amherst"},{"name":"Mr. Ismael Mohammad Pour","aff":"Student, University of Massachusetts Amherst"},{"name":"Ms. Samirasadat Samadi","aff":"Student, University of Massachusetts Amherst"}],"order":2},{"id":"136-1463","title":"Maximizing Small-Farm Revenues by Selecting Optimal Routing Based on Customer Purchase Price and Time Windows","content":"We analyze a milk logistics network problem with heterogeneous vehicles, small farms, depots and customers. Milk logistics challenges include pickup and milk-grade based co-mingling restrictions and short shelf-life. We propose a novel MILP formulation to determine optimal routing that maximizes farm revenues based on customers’ purchase price and time windows.","presenter":"Dr. Ashesh Kumar Sinha","authors":[{"name":"Dr. Ashesh Kumar Sinha","aff":"Assistant Professor, West Virginia University"},{"name":"Prof. John Saldanha","aff":"Professor, John Chambers College of Business &amp; Econ"}],"order":3},{"id":"136-1243","title":"Price Optimization and Food Waste in Secondary Markets: An Empirical Analysis","content":"In the context of the growing market for surplus food, we estimate a structural model of demand using hourly data from Too Good To Go and analyze store entry using an optimization framework. Our counterfactual analysis reveals that flexible pricing policies can both reduce food waste and enhance store revenue.","presenter":"Ms. Yizhuo Dong","authors":[{"name":"Ms. Yizhuo Dong","aff":"Student, UCLA Anderson School of Management"},{"name":"Prof. Auyon Siddiq","aff":"Assistant Professor, UCLA Anderson School of Management"},{"name":"Prof. Jingwei Zhang","aff":"Assistant Professor, Cornell University"}],"order":4},{"id":"136-0938","title":"Collaboration or Chaos? How Human-Tech Overrides Affect Order Fulfillment in Ghost Kitchens","content":"We examine coordination challenges in a prominent Indian cloud kitchen's operations. Cross-brand items, added to menus without the provider's knowledge, result in \"implicit multi-brand orders.\" These bypass systematic processing, relying on informal communication, disrupting coordination. This impacts fulfilment times, delaying explicitly identified multi-brand orders due to FIFO breaches and inefficiencies.","presenter":"Prof. Maya Ganesh","authors":[{"name":"Prof. Maya Ganesh","aff":"Assistant Professor, Indian Institute of Management Bangalore"},{"name":"Prof. Neha Sharma","aff":"Assistant Professor, Wharton School, University of Pennsylvan"},{"name":"Prof. Debjit Roy","aff":"Professor, Indian Institute of Management Ahmedabad"}],"order":5}]},{"id":"s183","title":"Digital Business Innovation","track":"Product Innovation and Technology Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"COURTLAND","chairs":["Dr. Maria Ibanez","Dr. Sebastian Villa"],"abstracts":[{"id":"136-0183","title":"Managerial Insight and “Optimal” Algorithms","content":"I introduce FIND, a method that integrates humans’ private information and algorithmic decision making to generate newsvendor order quantities. In eight experiments, FIND outperforms all other ordering regimes considered over a broad range of conditions. To model unstructured demand signals, four experiments convey signals non-quantitatively using images, colors, and tones.","presenter":"Dr. Blair Flicker","authors":[{"name":"Dr. Blair Flicker","aff":"Assistant Professor, University of South Carolina"}],"order":1},{"id":"136-0447","title":"The Influence of Market Changes and Donation Urgency on Cryptocurrency Donations","content":"Cryptocurrency donations are appealing to both donors and charities due to characteristics such as time efficiencies. However, cryptocurrencies are riskier assets compared to stocks and cash. We conduct an empirical exploration of cryptocurrency donations and a controlled online experiment to study novel sources of bias in decision-making around cryptocurrency donations.","presenter":"Dr. Sebastian Villa","authors":[{"name":"Dr. Sebastian Villa","aff":"Assistant Professor, University of Colorado Boulder"},{"name":"Dr. Gloria Urrea","aff":"Assistant Professor, University of Colorado Boulder"},{"name":"Dr. Eunae Yoo","aff":"Assistant Professor, Indiana University Bloomington"},{"name":"Prof. Gordon Burtch","aff":"Associate Professor, Boston University"}],"order":2},{"id":"136-1967","title":"How Online Reviews Content Affect Patients' Trust to Choose a Doctor","content":"Recent research suggests that more than two-thirds of people use online reviews to find a new doctor. However, the role review content plays when patients use online reviews to decide about a new doctor in unclear. This research aims to understand how a review's content impacts patients’ trust to choose.","presenter":"Dr. Sina Ansari","authors":[{"name":"Dr. Sina Ansari","aff":"Assistant Professor, Driehaus College of Business"},{"name":"Dr. Shabnam Azimi","aff":"Associate Professor, Loyola University of Chicago"}],"order":3},{"id":"136-0532","title":"Understanding User Behavior and Engagement in Mobile Apps","content":"This study investigates how external factors influence user behavior, and app performance in mobile applications. Leveraging large-scale daily user interaction data, we examine user retention, engagement, and revenue generation drivers. Our findings reveal that disruptions can impact user satisfaction, engagement patterns, and monetization outcomes.","presenter":"Mr. Alejandro Hernandez De la Lanza","authors":[{"name":"Mr. Alejandro Hernandez De la Lanza","aff":"Student, Kellogg School of Management"},{"name":"Dr. Maria Ibanez","aff":"Associate Professor, Kellogg School of Management"}],"order":4}]},{"id":"s185","title":"Platform Operations &amp; NPD","track":"Retail Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"FAIRLIE","chairs":["Prof. Aadhaar Chaturvedi"],"abstracts":[{"id":"136-0171","title":"Managing Sales via Livestream Commerce: Implications of Price Negotiation and Consumer Price Search","content":"Livestreaming has been increasingly used by farmers from remote rural areas to sell their agricultural products to consumers. In this paper, we study whether and under what circumstances selling through livestreaming can improve farmers' income compared to traditional approaches such as selling to wholesalers.","presenter":"Mr. Xi (Henry) Lin","authors":[{"name":"Mr. Xi (Henry) Lin","aff":"Student, University of California Irvine"},{"name":"Prof. Luyi Gui","aff":"Associate Professor, University of California Irvine"},{"name":"Prof. Yixin Lu","aff":"Associate Professor, George Washington University"}],"order":1},{"id":"136-0175","title":"Food-Delivery Platforms: A Near-Optimal Policy for Capacity Sizing, Order Batching, and Spatial Routing","content":"We study the one-time capacity sizing and real-time order-batching and driver-routing decisions for a stochastic, dynamic food-delivery system. We identify a near-optimal policy that ensures (a) a vanishing performance gap with respect to a clairvoyant optimal policy, and (b) a vanishing excess delay in delivery, in a meaningful asymptotic regime.","presenter":"Dr. Yang BO","authors":[{"name":"Dr. Yang BO","aff":"Assistant Professor, CUHK Business School"},{"name":"Prof. Milind Dawande","aff":"Professor, The University of Texas at Dallas"},{"name":"Prof. Ganesh Janakiraman","aff":"Professor, The University of Texas at Dallas"}],"order":2},{"id":"136-0195","title":"Impact of Cocreation Under Supply Chain Encroachment","content":"The increasing complexity of supply chains has led firms to redesign supply chains through co-creation with other supply chain members. Our research investigates how co-creation can add value under supplier encroachment environment, when the manufacturer establishes a direct sales channel (especially via an online platform).","presenter":"Dr. Piyal Sarkar","authors":[{"name":"Prof. Abhishek Roy","aff":"Assistant Professor, Temple University"},{"name":"Dr. Piyal Sarkar","aff":"Assistant Professor, Pennsylvania State University Harrisburg"},{"name":"Dr. Shubham Gupta","aff":"Assistant Professor, New Jersey Institute of Technology"}],"order":3},{"id":"136-0257","title":"Deploying Parallel Teams in Complex Product Development","content":"In product development, internal competition and reliance on external expertise are common practices. This study examines the optimal allocation of internally competing product development teams to external suppliers. Using game theory, we derive equilibrium outcomes and identify optimal decision-making strategies.","presenter":"Dr. Timofey Shalpegin","authors":[{"name":"Dr. Timofey Shalpegin","aff":"Associate Professor, MBSC"},{"name":"Prof. Svenja Sommer","aff":"Associate Professor, Hec Paris"},{"name":"Prof. Christian Van Delft","aff":"Associate Professor, Hec Paris"}],"order":4},{"id":"136-0678","title":"Improving E-Retailer Order Fulfillment: Packing Delivery Boxes Better","content":"E-retailers' profitability is affected by order fulfillment and shipping costs, which often increase due to carriers' dimensional pricing. This study examines how better box packing decisions can reduce these costs. We propose algorithms for optimal box sizing and selection, helping managers improve packaging operations and shipment cost estimation.","presenter":"Mr. Qilong Zhu","authors":[{"name":"Mr. Qilong Zhu","aff":"Student, Texas A&amp;M University"},{"name":"Prof. Gregory Heim","aff":"Professor, Texas A&amp;M University College Station"},{"name":"Prof. Chelliah Sriskandarajah","aff":"Professor, Texas A&amp;M University College Station"},{"name":"Dr. Yunxia Zhu","aff":"Associate Professor, University of Nebraska Lincoln"}],"order":5}]},{"id":"s207","title":"Healthcare operations","track":"Digital Platforms, Innovations and Transformations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"GREENBRIAR","chairs":["Dr. Mohammad Delasay"],"abstracts":[{"id":"136-1230","title":"Brick or Click: Managing Outpatient (Tele)visits with Strategic Behavior","content":"As telemedicine grows in outpatient care, providers must balance virtual (URL, or internet) and in-person (RL, or real-life) services. Whereas telemedicine offers convenience, it may require follow-up in-person visits, which could offset initial benefits. This study explores strategies to optimize outpatient care delivery with telemedicine.","presenter":"Prof. Nan Liu","authors":[{"name":"Prof. Nan Liu","aff":"Associate Professor, Boston College"},{"name":"Dr. Shan Wang","aff":"Assistant Professor, Sun Yat-sen University"},{"name":"Prof. Noa Zychlinski","aff":"Assistant Professor, Technion Israel Institute of Technology"}],"order":1},{"id":"136-1234","title":"Optimal Genetic Testing of Families","content":"We propose a Markov decision process framework for optimizing genetic testing by integrating Bayesian networks and cost-effectiveness analysis. Our model dynamically prioritizes family members for testing based on sequential results, improving cost-effectiveness over existing protocols. In addition, we show an approximate algorithm for scaling family testing to multiple conditions.","presenter":"Dr. Kanix Wang","authors":[{"name":"Dr. Kanix Wang","aff":"Assistant Professor, University of Cincinnati"},{"name":"Prof. Dan Adelman","aff":"Professor, Booth School of Business"}],"order":2},{"id":"136-1754","title":"Enhancing Patient Care Through Telemedicine: Linking Primary Care with Specialists","content":"We investigate how using telemedicine and e-consultation platforms to link primary care doctors with specialists can enhance patient care and coordination. We also examine how referral choices and resource allocation are affected by different payment methods.","presenter":"Dr. Mohammad Delasay","authors":[{"name":"Dr. Mohammad Delasay","aff":"Associate Professor, Stony Brook University"},{"name":"Prof. Saligrama Agnihothri","aff":"Professor, Binghamton University"},{"name":"Dr. ARVIND SAINATHAN","aff":"Associate Professor, NEOMA Business School"}],"order":3},{"id":"136-1957","title":"From Data to Action: A Process-Driven Framework for Emergency Department Queue Mining and Intervention Design","content":"A data-driven methodology integrates event-log-mining, process-mining, and queue-mining to improve emergency department operations. This approach addresses the challenges of mapping complex service interactions in healthcare service systems. Through systematic data exploration and analysis, the framework identifies KPI drivers to enable evidence-based operational interventions through queueing network analysis.","presenter":"Mrs. Shany Azaria","authors":[{"name":"Mrs. Shany Azaria","aff":"Post Doc/Researcher, University of Toronto"},{"name":"Prof. Opher Baron","aff":"Professor, University of Toronto"},{"name":"Prof. Dmitry Krass","aff":"Professor, Rotman School of Management"},{"name":"Dr. Arik Senderovich","aff":"Assistant Professor, York University"}],"order":4}]},{"id":"s214","title":"Managing food supply chains","track":"Supply Chain Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"GRAND HALL EAST A","chairs":["Prof. Eda Kemahlioglu-Ziya"],"abstracts":[{"id":"136-0139","title":"Achieving Resilience with Redundancy in Food Bank Operations","content":"Food banks are non-profit organizations that collect food from sources such as retailers, manufacturers, and farmers, and distribute to the needy population. In this study, we investigate the role of redundancy-building strategies in affecting a food bank’s level of resilience in food distribution in the case of a major disruption.","presenter":"Prof. Pelin Pekgun","authors":[{"name":"Ms. Yingru Han","aff":"Student, University of South Carolina"},{"name":"Dr. Luv Sharma","aff":"Associate Professor, University of South Carolina"},{"name":"Prof. Pelin Pekgun","aff":"Professor, Wake Forest University"},{"name":"Dr. Olga Perdikaki","aff":"Associate Professor, University of South Carolina"}],"order":1},{"id":"136-0629","title":"Innovator’s Edge in Supply Chain Transparency and Food Waste Reduction","content":"New digital technologies are transforming fresh produce retail, enabling real-time freshness tracking and information sharing with consumers. In a duopoly with freshness-sensitive demand, we explore whether an innovator gains a competitive advantage over a follower. In general, innovator’s edges do not always exist, but they grow when consumers value transparency.","presenter":"Mr. Chenghuai Li","authors":[{"name":"Prof. N. Bora Keskin","aff":"Associate Professor, Duke University Durham"},{"name":"Mr. Chenghuai Li","aff":"Student, Duke University"},{"name":"Prof. Jing-Sheng (Jeannette) Song","aff":"Professor, Duke University Durham"}],"order":2},{"id":"136-0911","title":"Coordinator or active participant? The food bank’s role in ad-hoc food rescue operations","content":"Motivated by our food bank partner, we compare a centralized approach, where the food bank coordinates and participates in food rescue, to a decentralized approach, where it acts solely as coordinator. We find that agency rescue and storage capacities strongly influence the preferred approach in ad-hoc food rescue operations.","presenter":"Dr. Irem Sengul Orgut","authors":[{"name":"Dr. Irem Sengul Orgut","aff":"Assistant Professor, University of Alabama"},{"name":"Ms. Shabnam Salehi","aff":"Student, The University of Alabama"},{"name":"Dr. Lauren Davis","aff":"Associate Professor, North Carolina A&amp;T State University"},{"name":"Dr. Emmett Lodree","aff":"Professor, University of Alabama Tuscaloosa"}],"order":3}]},{"id":"s221","title":"Retailing and Omni Channels","track":"Supply Chain Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY A","chairs":["Dr. Shuya Yin","Dr. Rachel Chen"],"abstracts":[{"id":"136-0405","title":"Anti-competitive Effects of a Dominant Retailer's Guaranteed Profit Margin and Low-Price Contracts","content":"In a guaranteed profit margin contract, the retailer expects a margin on a sale and the supplier must make up any difference. Recently, there has been debate on whether these contracts in conjunction with low-price guarantees are anti-competitive. We formulate and analyze a game-theoretic model to\r\nanswer this question.","presenter":"Prof. Haresh Gurnani","authors":[{"name":"Prof. Leela Nageswaran","aff":"Assistant Professor, University of Washington"},{"name":"Prof. Aditya Jain","aff":"Associate Professor, Baruch College"},{"name":"Prof. Haresh Gurnani","aff":"Professor, Stony Brook University"}],"order":1},{"id":"136-0990","title":"The Dynamics of Distribution to Financially Constrained Nanostores","content":"The financially constrained nanostores often place frequent orders of small sizes from regional distributors, who will then face a decision challenge: Frequent deliveries result in high distribution costs, while infrequent deliveries result in lost sales. We study this tradeoff and how the trade credit plays a role.","presenter":"Dr. Xin Geng","authors":[{"name":"Dr. Zheyu Jiang","aff":"Assistant Professor, Nanjing University"},{"name":"Dr. Harihara Natarajan","aff":"Professor, University of Miami"},{"name":"Prof. Nan Yang","aff":"Professor, University of Miami"},{"name":"Dr. Xin Geng","aff":"Assistant Professor, University of Miami"}],"order":2},{"id":"136-1138","title":"Bundling or Discounting? Field Experiment for Heterogenous Products","content":"In this paper, we compare two popular price promotion strategies - bundling and discounting - through a large scale field experiment for two different types of products - healthy and unhealthy. We show that discounting is better for increasing sales, but bundling is better in terms of revenue and profit.","presenter":"Prof. Saibal Ray","authors":[{"name":"Prof. Saibal Ray","aff":"Professor, Mcgill University"},{"name":"Ms. Nymisha Bandi","aff":"Student, Desautels Faculty of Management"},{"name":"Prof. Maxime Cohen","aff":"Professor, McGill University"}],"order":3},{"id":"136-0774","title":"A Theory of Blitzscaling start-up with the Venture Capitalist Method","content":"Blitzscaling describes aggressive expansion in demand and capacity commonly observed among expansion stage startups, trading monetary efficiency for growth. We provide an explanatory theory that analyze when and how blitzscaling occurs by studying a model of a startup funded by an exit-seeking venture capitalist (VC).","presenter":"Mr. Yishen Cai","authors":[{"name":"Mr. Yishen Cai","aff":"Student, Ph.D. Operation Management"},{"name":"Prof. Lingxiu Dong","aff":"Professor, Olin Business School, Washington Univers"},{"name":"Prof. Fasheng Xu","aff":"Assistant Professor, University of Connecticut"}],"order":4}]},{"id":"s227","title":"AI for Societal Decision Making","track":"Data Science, Analytics and AI","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"ROSWELL","chairs":["Mr. Jiannan Xu","Mr. Sung Hyun Kwon"],"abstracts":[{"id":"136-0287","title":"Language Model Based Assistance for Volunteers: Reuniting Families Impacted by Child Trafficking and Illegal Adoption","content":"Illegal adoptions from child trafficking and abandonment have caused numerous family separations. This study uses natural language processing and other machine learning models to analyze victim-provided clues from a social platform, aiming to improve matching and optimize volunteer-led search efforts, providing a framework for facilitating family reunification","presenter":"Mr. Huifeng Su","authors":[{"name":"Mr. Huifeng Su","aff":"Student, Yale School of Management"},{"name":"Prof. Lesley Meng","aff":"Assistant Professor, Yale School of Management"},{"name":"Prof. Edieal Pinker","aff":"Professor, Yale School of Management"}],"order":1},{"id":"136-0294","title":"Putting Yourself in Someone Else’s Shoes: Improving_x000B_Human Generated Labels with Empathy Priming","content":"Improving AI model performance involves enhancing the quality of training data. Our approach is encouraging labelers to adopt others' perspectives, which helps reduce bias and improve label quality, ultimately leading to more accurate and fair AI systems.","presenter":"Mr. Sung Hyun Kwon","authors":[{"name":"Mr. Sung Hyun Kwon","aff":"Student, University of Maryland"},{"name":"Dr. Jessica Clark","aff":"Assistant Professor, University of Maryland - College Park"},{"name":"Dr. Il-Horn Hann","aff":"Professor, University of Maryland"},{"name":"Prof. Jui Ramaprasad","aff":"Associate Professor, University of Maryland - College Park"}],"order":2},{"id":"136-1051","title":"AI Self-preferencing in Algorithmic Hiring: Empirical Evidence and Insights","content":"This project investigates AI self-preferencing in algorithmic hiring, where LLM evaluators favor AI-generated resumes over human-written ones. Through controlled resume correspondence experiments, we examine its impact on screening decisions and fairness, offering empirical insights into bias and its broader implications for AI-driven recruitment.","presenter":"Mr. Jiannan Xu","authors":[{"name":"Mr. Jiannan Xu","aff":"Student, University of Maryland - College Park"},{"name":"Ms. Jane Jiang","aff":"Assistant Professor, Ohio State University"},{"name":"Mr. Gujie Li","aff":"Student, University of Maryland - College Park"}],"order":3}]},{"id":"s257","title":"Turn Supply Chain Exposure into Business Opportunity","track":"POM-Marketing Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"DUNWOODY","chairs":["Dr. Gangshu Cai","Prof. Lizhi Xing"],"abstracts":[{"id":"136-1890","title":"Make Your Medication a Habit —Dynamic Incentives for Medication Adherence","content":"Poor medication adherence is a prevalent issue with serious consequences. We design dynamic\r\nincentives to foster medication habits through personalized penetration rewards, leveraging\r\nhabituation. Using data from a Chinese online pharmacy, we demonstrate this approach's\r\neffectiveness in improving adherence, providing valuable insights for scalable healthcare interventions and patient-centered CRM strategies.","presenter":"Prof. Dawei Jian","authors":[{"name":"Prof. Dawei Jian","aff":"Assistant Professor, University of Wisconsin-Milwaukee"},{"name":"Prof. Wei Zhang","aff":"Assistant Professor, Zhejiang University"}],"order":1},{"id":"136-0274","title":"Service Provision in Supply Chain under Consumer Risk Aversion","content":"Service is a core driver of business development, yet the supply chain service provision strategy under consumer risk aversion remains unexplored. Our study reveals that with symmetric service costs, downstream retailers prefer providing services independently and resist cost-sharing. Besides, the manufacuter and retailer prefer sharing when certain condition is met.","presenter":"Mr. Zhaotong Wang","authors":[{"name":"Mr. Zhaotong Wang","aff":"Student, Tsinghua University"},{"name":"Dr. Gangshu Cai","aff":"Professor, Santa Clara University"},{"name":"Mr. Tianhu Deng","aff":"Associate Professor, Tsinghua University"}],"order":2},{"id":"136-0262","title":"Network-Based Analytical Framework for Identifying and Quantifying the Risk Exposures in Global Supply Chains","content":"We first constructed the global production networks based on intermediate goods trade data and quantified the risk exposures in global supply chains from multiple perspectives. Then, we empirically analyzed the structural risks brought by the restructuring of the global value chain and the exogenous risks caused by China-U.S. trade friction.","presenter":"Prof. Lizhi Xing","authors":[{"name":"Prof. Lizhi Xing","aff":"Professor, Beijing University of Technology"},{"name":"Prof. Jun Guan","aff":"Professor, Beijing University of Technology"}],"order":3}]},{"id":"s269","title":"AI, Recommendation, and Crowdfunding","track":"POM-Marketing Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"HARRIS","chairs":["Dr. Evelyn Smith"],"abstracts":[{"id":"136-0292","title":"Strategic Conformity in Affiliate Marketing","content":"Affiliate marketing is a prevalent marketing model. Commonly, retailers compensate their affiliates per click/purchase. We show that by choosing its affiliate compensation model, a retailer can affect the equilibrium in the market for recommendations that have significant implications for consumer surplus, affiliates' revenues, aggregate welfare, and the retailer's profits.","presenter":"Mr. Xudong Zheng","authors":[{"name":"Prof. Itay Fainmesser","aff":"Associate Professor, Johns Hopkins Carey Business School"},{"name":"Mr. Xudong Zheng","aff":"Student, Johns Hopkins University"}],"order":1},{"id":"136-1097","title":"Targeted Promotions Based on Consumer Characteristics Extracted from a Retailer’s Online Community","content":"To boost shopping cart checkout rates, online retailers can offer targeted promotions like free shipping, discounts, and coupons. Using a machine learning algorithm, we analyze consumers' regulatory focus from their digital footprints and combine this with transactional data to show how retailers can leverage these insights to improve checkout rates.","presenter":"Dr. Haoying Sun","authors":[{"name":"Prof. Ji Wu","aff":"Professor, Sun Yat-Sen University"},{"name":"Dr. Haoying Sun","aff":"Associate Professor, University of Kentucky"},{"name":"Dr. Haipeng (Allan) Chen","aff":"Professor, University of Iowa"}],"order":2},{"id":"136-0045","title":"Crowdfunding Pricing with Network Externality","content":"We examine the interaction between network externality and crowdfunding pricing mechanisms. The results highlight non-monotonic effects of network externality on optimal pricing strategies and social welfare. We explain these findings from the perspective of information and provide managerial insights for managing crowdfunding projects with network externalities.","presenter":"Mr. Yi Wang","authors":[{"name":"Prof. Lin Feng","aff":"Associate Professor, Southwest Jiaotong University"},{"name":"Prof. Baojun Jiang","aff":"Professor, Washington University in St. Louis"},{"name":"Mr. Yi Wang","aff":"Student, Tianjin University"},{"name":"Prof. Jianxiong Zhang","aff":"Professor, Tianjin Uinversity"}],"order":3},{"id":"136-0986","title":"My Fair AI: Predictive Parity Policy Effects on AI Content Recommendation with Privacy Concerns","content":"Firms use AI to recommend content (news, videos). However, certain consumer groups systematically receive undesirable content because of AI bias. To rectify such inequalities, firms formulate AI fairness algorithmic policies such as Predictive Parity. We use a game theoretical model to analyze the direct and strategic effects of such policy.","presenter":"Dr. Evelyn Smith","authors":[{"name":"Dr. Evelyn Smith","aff":"Assistant Professor, University of Kentucky"},{"name":"Prof. Jeffrey Shulman","aff":"Associate Professor, University of Washington"},{"name":"Prof. Antino Kim","aff":"Associate Professor, Indiana University"}],"order":4}]},{"id":"s310","title":"Machine Learning in Pricing and Revenue Management","track":"Revenue Management and Pricing","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"MARIETTA","chairs":["Mr. Ruihao Zhu"],"abstracts":[{"id":"136-1492","title":"Can an LLM Chatbot Replace Human Workers and NLP Chatbots in Online Customer Service?","content":"In collaboration with a large online B2B marketplace, we investigate whether an LLM-powered chatbot can outperform and potentially replace its existing NLP chatbot in online customer service. Our results demonstrate that the LLM chatbot significantly outperforms the NLP chatbot across several metrics, delivering more detailed, accurate, and friendly answers.","presenter":"Mr. Bolin Song","authors":[{"name":"Prof. Vishal Gaur","aff":"Professor, Cornell University"},{"name":"Mr. Bolin Song","aff":"Post Doc/Researcher, Cornell University"},{"name":"Mr. Ruihao Zhu","aff":"Assistant Professor, Cornell University"}],"order":1},{"id":"136-1744","title":"A Stability Principle for Learning under Non-Stationarity","content":"We develop a versatile framework for statistical learning in non-stationary environments. In each time period, our approach applies a stability principle to select a look-back window that maximizes the utilization of historical data while keeping the cumulative bias within an acceptable range relative to the stochastic error.","presenter":"Prof. Kaizheng Wang","authors":[{"name":"Mr. Chengpiao Huang","aff":"Student, Columbia University"},{"name":"Prof. Kaizheng Wang","aff":"Assistant Professor, Columbia University"}],"order":2},{"id":"136-0444","title":"Learning-based dynamic pricing strategy with pay-per-chapter mode for online publisher with case study of COL","content":"We consider how to make dynamic pricing decision for COL at T time-points. We propose a learning-based dynamic pricing strategy that exploits newly information to maximize cumulative revenue for the publisher. We show that LDPS outperform several classical strategies, we also provide some management implications for the COL publisher.","presenter":"Mr. Lang Fang","authors":[{"name":"Mr. Lang Fang","aff":"Student, Dongbei University of Finance and Economics"},{"name":"Mr. Zhendong Pan","aff":"Associate Professor, Dongbei University of Finance and Economics"},{"name":"Prof. Jiafu Tang","aff":"Professor, Dongbei University of Finance and Economics"}],"order":3}]},{"id":"s324","title":"Circular Supply Chains for Low-Value Products","track":"Sustainable Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"GRAND HALL EAST C","chairs":["Prof. Sandra Transchel"],"abstracts":[{"id":"136-0462","title":"Rethinking remanufacuring for non-durable goods: An apparel remanufacturing model under extended producer responsibility legislation","content":"Remanufacturing is known to be a viable solution to decouple economic growth from resource usage but is limited in the AT industry. However, due to extended producer responsibility, it will inevitably become mainstream. This study finds that different remanufacturing options should be utilized depending on the firm’s market position.","presenter":"Dr. Zoe Schumm","authors":[{"name":"Dr. Zoe Schumm","aff":"Assistant Professor, Penn State University Erie"},{"name":"Dr. Meltem Denizel","aff":"Associate Professor, Iowa State University"}],"order":1},{"id":"136-0250","title":"The Impact and Implication of Bag Tax Policies on Sustainable Operations: A System Dynamics Approach","content":"This study investigates the impact of plastic bag tax policy on sustainable operations. By leveraging 71k historical dataset and Vensim modeling, we simulate the interactions and feedback loops to demonstrate and forecast policy impacts, providing evidence-based recommendations for tax structures and accompanying measures to maximize environmental and social benefits.","presenter":"Dr. Nesreen El-Rayes","authors":[{"name":"Dr. Nesreen El-Rayes","aff":"Assistant Professor, Georgia State University"},{"name":"Prof. Aichih Chang","aff":"Assistant Professor, New Jersey Institute of Technology"},{"name":"Dr. Jim Shi","aff":"Professor, New Jersey Inst of Technology"},{"name":"Ms. Fuqin Zhou","aff":"Student, New Jersey Institute of Technology"}],"order":2},{"id":"136-1372","title":"Endogenizing rebound effects in the life cycle assessment of circularity strategies: a focus on refurbishment","content":"Rebound effects from circularity strategies are often overlooked or assumed exogenously in life cycle assessment (LCA) studies, potentially leading to unreliable claims. We demonstrate how to complement LCA with economic modeling to quantify the rebound effects of a refurbishment strategy and examine the implications for two different product types.","presenter":"Dr. Antonio Cavallin Toscani","authors":[{"name":"Dr. Antonio Cavallin Toscani","aff":"Assistant Professor, Padova University"},{"name":"Prof. Vishal Agrawal","aff":"Professor, Georgetown University"},{"name":"Prof. Atalay Atasu","aff":"Professor, INSEAD"},{"name":"Prof. Luk Van Wassenhove","aff":"Professor, INSEAD"}],"order":4},{"id":"136-0756","title":"Evaluating Contracting Mechanisms for Closed-loop Supply chains of Reusable Packaging","content":"Effective reusable packaging systems require the coordination of various stakeholders. This study models a closed-loop supply chain of a wholesaler and multiple producers with different products investing in sorting capacity. Using a game-theoretical model, we analyze the effects of different contracts on the performance of the reusable packaging system.","presenter":"Prof. Sandra Transchel","authors":[{"name":"Prof. Sandra Transchel","aff":"Professor, Kuehne Logistics University"},{"name":"Prof. Andreas Gernert","aff":"Assistant Professor, Kuehne Logistics University"}],"order":5}]},{"id":"s329","title":"Empirical Platform Operations","track":"Service Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY C","chairs":["Prof. Vishal Gaur","Mr. Rakesh Allu"],"abstracts":[{"id":"136-1703","title":"Fulfilling the Promise: Delivery Performance and Consumer Repeat Purchase Behavior on a Grocery Platform","content":"Our analysis of over 1 million grocery orders in a leading grocery platform reveals late deliveries can significantly harm the revenue. Surprisingly, early deliveries do not benefit the platform across all types of orders. Customers who face consistent 15-minute late deliveries are 30% less likely to return to the platform.","presenter":"Prof. Hailong Cui","authors":[{"name":"Prof. Hailong Cui","aff":"Assistant Professor, University of Minnesota"},{"name":"Prof. Guo Li","aff":"Professor, Beijing Institute of Technology"},{"name":"Prof. Na Li","aff":"Assistant Professor, Nankai Univeristy"}],"order":1},{"id":"136-0037","title":"Conceptualizing the US News Media Supply Chain through a Supply Chain Flows Framework","content":"This research maps the evolving US news media supply chain using a contemporary supply chain flows framework, integrating a systematic literature review and empirical content analysis. It reveals a shift from a linear to decentralized, interactive models driven by digitalization and changing consumer behavior, highlighting challenges like misinformation and economic","presenter":"Mr. Derek Dubois","authors":[{"name":"Mr. Derek Dubois","aff":"Student, University of Rhode Island"},{"name":"Dr. Muhammad Hasan Ashraf","aff":"Assistant Professor, California State University Long Beach"},{"name":"Dr. Mehmet Yalcin","aff":"Assistant Professor, University of Rhode Island"}],"order":3},{"id":"136-0475","title":"User Engagement on an Online B2B Platform: How Does Quality of Rankings Matter?","content":"Online business-to-business platforms invest in R&amp;D to improve the quality of their ranked-recommendations. Using 21MN ranked transactions from a B2B platform, we develop methods to measure ranking quality, and to address endogeneity and censorship in such data. Our methods show that improving ranking quality increases usage and decreases browsing effort.","presenter":"Mr. Rakesh Allu","authors":[{"name":"Mr. Rakesh Allu","aff":"Student, Cornell University"},{"name":"Prof. Vishal Gaur","aff":"Professor, Cornell University"}],"order":4}]},{"id":"s355","title":"Panel: Shaping the Next Decade - Research Agendas for Operations &amp; Society","track":"Operations and Society","type":"Panel","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"SPRING","chairs":["Dr. Telesilla Kotsi"],"abstracts":[{"id":"136-2085","title":"Panel: Shaping the Next Decade - Research Agendas for Operations &amp; Society","content":"This panel brings together experts to discuss key research directions in operations management that address societal challenges. Topics include supply chains in developing countries, support services for vulnerable populations, and sustainable business practices. Panelists will explore how operations research can drive impact in climate change, poverty, and healthcare through collaboration","presenter":"Dr. Telesilla Kotsi","authors":[{"name":"Prof. Jan Fransoo","aff":"Professor, Tilburg University"},{"name":"Dr. Priyank Arora","aff":"Associate Professor, University of South Carolina"},{"name":"Prof. Vishal Agrawal","aff":"Professor, Georgetown University"},{"name":"Dr. Telesilla Kotsi","aff":"Assistant Professor, Fisher College of Business"}],"order":1}]},{"id":"s376","title":"Panel: AI for Operational Excellence and Change Management","track":"Practice Leaders","type":"Panel","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"Learning Center","chairs":["Dr. Dino Petrarolo","Dr. Andreea Popescu","Prof. Manpreet Hora"],"abstracts":[{"id":"136-2131","title":"Panel: AI for Operational Excellence and Change Management","content":"Discover how AI is shaping production and operations, enhancing efficiency, and driving smart change. This session features industry experts sharing real-world examples, best practices, and strategies for building agile, data-driven teams that can thrive in evolving environments.","presenter":"Prof. Manpreet Hora","authors":[{"name":"Prof. Manpreet Hora","aff":"Professor, Georgia Institute of Technology"},{"name":"Ms. Cheryl Lester","aff":"VP, Operational Fraud and Continuous Improvement, Shipt"},{"name":"Dr. Russell Allgor","aff":"Chief Supply Chain Scientist, Auger"},{"name":"Dr. Dayana Cope","aff":"General Manager, Decision Science, Delta Air Lines"},{"name":"Dr. Alan Barnard","aff":"CEO, Goldratt Research Labs"}],"order":1}]},{"id":"s382","title":"Risk Models and Metrics","track":"Supply Chain Risk Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY H","chairs":["Dr. William Haskell"],"abstracts":[{"id":"136-0315","title":"Measuring Supply Chain Resilience: A Perspective Inspired by Material Mechanics","content":"Inspired by material resilience, we propose a novel method to measure supply chain resilience. The new measure has three nice attributes that serve practical use: 1. Based on a network perspective; 2. As an intrinsic property of supply chain networks (SCNs); 3. Able to characterize the reactive adaptation of SCN.","presenter":"Mr. Jinzhi Li","authors":[{"name":"Mr. Jinzhi Li","aff":"Student, Fudan University"},{"name":"Prof. Jeff Hong","aff":"Professor, Fudan University"},{"name":"Dr. Jun Luo","aff":"Professor, Shanghai Jiao Tong University"}],"order":1},{"id":"136-1262","title":"Using sample entropy as the risk measure of a firm","content":"We use sample entropy to develop a risk measure to compare the irregularities of revenue and profit of a firm. While revenue entropy is determined externally, profit entropy is determined by external and internal factors. The proposed profit entropy is effective in assessing the risk of a complex system.","presenter":"Prof. Seokjin Kim","authors":[{"name":"Prof. Renato Guimaraes","aff":"Associate Professor, ICN Business School"},{"name":"Prof. Seokjin Kim","aff":"Associate Professor, Suffolk University"},{"name":"Prof. Mozart Menezes","aff":"Professor, NEOMA Business School"}],"order":2},{"id":"136-1763","title":"Onshoring / Offshoring: Managing Risk in a Dynamic Environment","content":"As the global climate changes politically, environmentally and economically, supply chains are at greater risk than ever. With consumers demanding quicker responses and lower costs, offshoring to only minimize production costs may no longer have the expected results. We examine the evaluation process behind these decisions.","presenter":"Dr. Tom Morgan","authors":[{"name":"Dr. Tom Morgan","aff":"Associate Professor, Central Connecticut State University"}],"order":3},{"id":"136-1912","title":"Physics of Decisions: An Innovative Framework for Managing Supply Chain Performance","content":"The Physics of Decisions offers a novel decision-support approach under uncertainty, treating risks and opportunities as forces affecting supply chain performance. Changes in the supply chain or its environment parameters shift KPIs, altering the system’s trajectory in multidimensional performance space, enabling insights into instability's impacts and informed decision-making.","presenter":"Prof. Frederick Benaben","authors":[{"name":"Prof. Frederick Benaben","aff":"Professor, IMT Mines Albi / Georgia Tech"},{"name":"Prof. Matthieu Lauras","aff":"Professor, IMT Mines Albi / Georgia Tech"},{"name":"Dr. Victor Romero","aff":"Assistant Professor, IMT Mines Albi"}],"order":4}]},{"id":"s424","title":"Managing and Mitigating Risk","track":"POM-Finance Interface","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"UNIVERSITY","chairs":["Dr. Sirong Luo"],"abstracts":[{"id":"136-1307","title":"Managing Extreme Risk: Innovative Financial and Operational Hedging Strategies for Resilient Supply Chains","content":"This paper examines the management of tail risk spillovers in supply chain finance, highlighting strategies to mitigate extreme risks. It explores financial tools like supply chain finance and operational hedging techniques such as supplier diversification and inventory buffers. The study offers insights into enhancing supply chain resilience during disruptions.","presenter":"Mr. Sagheer Muhammad","authors":[{"name":"Mr. Sagheer Muhammad","aff":"Student, University of Science and Technology Beijing"},{"name":"Prof. Xiaoxia Huang","aff":"Professor, University of Science and Technology, Beijing China"}],"order":1},{"id":"136-1436","title":"Antifragility Analysis of Cryptocurrency Market Complex Network Based on Risk Spillover","content":"This study constructs a cryptocurrency risk spillover network with the Dcc-Garch-Copula-ΔcoVaR model and simulates various risk shock scenarios via node removal methods. Results reveal increasing market antifragility, evolving risk dynamics, and shifting key nodes, emphasizing the need for targeted regulation of both major and emerging high-activity cryptocurrencies.","presenter":"Ms. Fan Wu","authors":[{"name":"Ms. Fan Wu","aff":"Student, Southeast University, Nanjing, China"},{"name":"Prof. Wei Yin","aff":"Associate Professor, Southeast University"}],"order":2},{"id":"136-1443","title":"Forward and spot market transactions of competitive firms on nonstorable commodities under risk aversion","content":"We develop models to analyze the interplay of random yields, consumer panic behavior and the forward market with spot and forward transactions for competitive firms. It is found that as yield risk increases, risk-averse firms target output appears non-monotonic effect in spot market. Counter-intuitively, a forward market destabilizes spot price.","presenter":"Ms. cheng huang","authors":[{"name":"Ms. cheng huang","aff":"Student, Harbin Institute of Technology"},{"name":"Prof. Guangxin Jiang","aff":"Professor, Harbin Institute of Technology"}],"order":3},{"id":"136-0985","title":"Interest Rate Optimization for Installment Loan","content":"We study interest rate optimization for unsecured installment loans. The decision needs to consider the risks of both market acceptance, default and early repayment. Using an online microloan dataset, we show how to estimate risks considering causal effects and how to simplify and solve this complex constrained nonlinear model.","presenter":"Dr. Sirong Luo","authors":[{"name":"Dr. Sirong Luo","aff":"Professor, Shanghai Univ. of Finance and Economics"}],"order":4}]},{"id":"s444","title":"Panel: Role of AI in current and future healthcare analytics research","track":"Healthcare Analytics","type":"Panel","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"GRAND HALL EAST D","chairs":["Prof. Rachna Shah"],"abstracts":[{"id":"136-2125","title":"Role of AI in current and future healthcare analytics research","content":"This discussion explores AI’s transformative role in healthcare analytics, addressing advancements, challenges, and ethical considerations. Experts will examine AI-driven innovations in diagnosis, treatment, and predictive analytics, highlighting future research directions to enhance healthcare efficiency, accuracy, and patient outcomes.","presenter":"Prof. Rachna Shah","authors":[{"name":"Prof. Rachna Shah","aff":"Professor, University of Minnesota"},{"name":"Prof. Anita Carson","aff":"Professor, Boston University"},{"name":"Prof. Diwas KC","aff":"Professor, Emory University"},{"name":"Prof. Tinglong Dai","aff":"Professor, Johns Hopkins University"},{"name":"Dr. Ujjal Mukherjee","aff":"Associate Professor, University of Illinois Urbana-Champaign"}],"order":1}]},{"id":"s31","title":"Regulatory and Operational Influences on Healthcare Quality","track":"Healthcare Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"PIEDMONT","chairs":["Prof. Yuqian Xu","Ms. Blair Liu"],"abstracts":[{"id":"136-0115","title":"As Hospitals Come and Go: Impacts of Hospital Entry and Exit on Nursing Home Operations","content":"We investigate the effects of hospital entries and closures on nearby nursing home operations. Our findings show that these changes in hospital presence can greatly change the payer mix in nursing homes, increase operational costs, and lower service quality.","presenter":"Ms. Jiaxin Lin","authors":[{"name":"Dr. Shenyang Jiang","aff":"Assistant Professor, Tongji University"},{"name":"Mr. Yuanchen Li","aff":"Assistant Professor, Tongji University"},{"name":"Ms. Jiaxin Lin","aff":"Student, Tongji University"}],"order":1},{"id":"136-0491","title":"From Inspection Backlogs to Quality Decline: How Staffing Shortages Affect U.S. Nursing Homes","content":"This research examines the impact of these inspection delays on nursing home operations. Using a 12-year longitudinal dataset from 2013 to 2024, we find that longer interinspection times led to quality decline in nursing homes, evidenced by an increase in deficiency citations.","presenter":"Dr. Wilson Lin","authors":[{"name":"Dr. Wilson Lin","aff":"Assistant Professor, Santa Clara University"},{"name":"Prof. Lauren Lu","aff":"Professor, Dartmouth College"},{"name":"Prof. Feng (Susan) Lu","aff":"Professor, Purdue University"}],"order":2},{"id":"136-0640","title":"How Nurses' Response to Sepsis Alerts Impacts Physicians' Process Compliance","content":"Using data from a large hospital group in the U.S., we investigate the impact of nurses’ timely completion of alert-related tasks on physicians’ compliance with sepsis care standards. We also examine how this impact changes under heavy workload and prior experiences with false alerts.","presenter":"Dr. Zahra Mobini","authors":[{"name":"Dr. Zahra Mobini","aff":"Assistant Professor, Georgia Institute of Technology"},{"name":"Prof. Mehmet Ayvaci","aff":"Associate Professor, The University of Texas at Dallas"},{"name":"Prof. Ozalp Ozer","aff":"Professor, University of Texas Dallas"}],"order":3},{"id":"136-1909","title":"Promoting Generics: Effects on Pharmaceutical Quality","content":"Generic drugs are vital for affordable healthcare. We analyze the Generic Drug User Fee Amendments (GDUFA), demonstrating that it reduced review times for approval but significantly increased post-approval recall rates, driven by manufacturing issues. Despite this, GDUFA's net benefits remain positive. Policy recommendations aim to balance efficiency with drug quality.","presenter":"Prof. In Joon Noh","authors":[{"name":"Prof. Hessam Bavafa","aff":"Associate Professor, University of Wisconsin-Madison"},{"name":"Prof. Christian Blanco","aff":"Assistant Professor, Ohio State University"},{"name":"Prof. In Joon Noh","aff":"Assistant Professor, Korea University"}],"order":4}]},{"id":"s33","title":"Innovative Mechanisms in Product Development and Market Design","track":"POM-Economics Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"HARRIS","chairs":["Prof. Aditya Jain"],"abstracts":[{"id":"136-0465","title":"Collaborative New Product Development: The Implications of Contract Choice on Cost-sharing in Vertical Channels","content":"It is well known that a buyer expects price commitment from upstream supplier when they collaborate to improve the product quality. We investigate how the possibility of strategic inventory influences the buyer's co-creation effort, product quality, and the supplier's contract choices between short-term transactional and long-term commitment contracts.","presenter":"Prof. Abhishek Roy","authors":[{"name":"Prof. Abhishek Roy","aff":"Assistant Professor, Temple University"},{"name":"Prof. Ganesh Balasubramanian","aff":"Assistant Professor, T A Pai Management Institute, MAHE"}],"order":1},{"id":"136-1961","title":"Quality Differentiation vs. Resource Utilization: Does Product Size Matter?","content":"We investigate how customer-perceived quality and resource consumption differences of products may impact a firm's product line decisions, and how they relate to its success in airline industry. We hypothesize that (1) indirect effects of quality differentiation exist through resource allocation decisions and (2) increasing resource consumptions have negative implications.","presenter":"Dr. Isil Koyuncu","authors":[{"name":"Dr. Muge Yayla-Kullu","aff":"Associate Professor, University of Texas at San Antonio"},{"name":"Dr. Isil Koyuncu","aff":"Assistant Professor, University of Texas at San Antonio"},{"name":"Dr. Dongling Huang","aff":"Associate Professor, California State University Northridge"}],"order":2},{"id":"136-1773","title":"Should I Curate or Not: A Game-theoretic Analysis of P2P Resale Marketplaces","content":"Some peer-to-peer (P2P) resale marketplaces curate used products by quality while many others do not. We investigate the business value of quality curation in P2P resale marketplaces, the impact on an independent retailer, and societal welfare.","presenter":"Dr. Aditya Vedantam","authors":[{"name":"Dr. Aditya Vedantam","aff":"Associate Professor, University of Buffalo"},{"name":"Dr. Emre Demirezen","aff":"Assistant Professor, University of Florida"},{"name":"Dr. Subodha Kumar","aff":"Professor, Temple University"}],"order":3},{"id":"136-0851","title":"Incentivization with Augmented Reality","content":"Augmented reality (AR) devices enable managers to monitor workers precisely. Using game theory, we study whether managers should use such fine-grained observations for incentivization contracts. We examine the effects of agency conflicts and regulatory friction through union-imposed constraints.\r\n","presenter":"Prof. David Wuttke","authors":[{"name":"Mr. Mrunal Mohadikar","aff":"Student, TUM School of Management, HN Campus"},{"name":"Prof. David Wuttke","aff":"Assistant Professor, TUM School of Management, HN Campus"}],"order":4}]},{"id":"s41","title":"OM Applications to Address Human Trafficking &amp; Modern Slavery","track":"Humanitarian Operations and Crisis Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"EMBASSY G","chairs":["Ms. Jennifer Nowicki"],"abstracts":[{"id":"136-0265","title":"Considerations for Defining an “Effective Intervention” into Sex Trafficking","content":"Interventions designed to disrupt sex trafficking and the harm that it causes often have a goal in mind. We present considerations necessary to frame the effectiveness of the intervention. Implications of these considerations for modeling disruptions are presented, along with a case study on sex trafficking network interdiction.","presenter":"Dr. Thomas Sharkey","authors":[{"name":"Dr. Thomas Sharkey","aff":"Professor, Clemson University"},{"name":"Dr. Kayse Maass","aff":"Assistant Professor, Northeastern University"},{"name":"Dr. Lauren Martin","aff":"Associate Professor, University of Minnesota"},{"name":"Mr. Daniel Lopes da Silva","aff":"Student, Clemson"},{"name":"Prof. HART Research Team","aff":"Practitioners, HART Research Team"}],"order":1},{"id":"136-1087","title":"From Digital Footprints to Hidden Networks: A Novel Approach for Illicit Network Detection","content":"With rapid digitalization, illicit networks have moved online. This work introduces a novel model integrating network theory and graph machine learning to classify and predict links between businesses. By leveraging multi-modal digital footprints, the model aims to detect hidden illicit networks demonstrated through a case study on Illicit Massage Businesses.","presenter":"Dr. Osman Ozaltin","authors":[{"name":"Mr. Vasuki Garg","aff":"Student, North Carolina State University"},{"name":"Dr. Osman Ozaltin","aff":"Associate Professor, North Carolina State University"},{"name":"Dr. Maria Mayorga","aff":"Associate Professor, North Carolina State University"},{"name":"Mrs. Sherrie Caltagirone","aff":"Executive Director, Global Emancipation Network"},{"name":"Ms. Margaret Tobey","aff":"Student, North Carolina State University"}],"order":2},{"id":"136-1640","title":"Risk Slate HT: An Integrated platform to investigate and prosecute Human Trafficking Cases","content":"Current case management, investigation and prosecution methods lack analytical tools to fight human trafficking. Traffickers know this: they take advantage of the lack of communication and coordination among law enforcement. In this presentation we introduce a newly designed platform to provide analytics, visualizations and interdiction strategies to law enforcement.","presenter":"Dr. Felipe Aros-Vera","authors":[{"name":"Dr. Felipe Aros-Vera","aff":"Associate Professor, Ohio University"},{"name":"Mr. John Morgan","aff":"Former Detective, Northeast Ohio Human Trafficking Task Force"},{"name":"Ms. Catherine Brown","aff":"Founder, Risk Slate"},{"name":"Mr. Kevin Dalvi","aff":"Founder, Risk Slate"},{"name":"Mr. Mike Florence","aff":"Founder, Risk Slate"}],"order":3},{"id":"136-1624","title":"Modeling IMB Location Dynamics - A Network Simulation Approach","content":"Illicit Massage Businesses (IMBs) are often individual establishments existing within large organizational networks, comparable to facilities operating within traditional corporate structures. By using real IMB network data to assign parameters, we simulate supply/demand dynamics to explore spatial patterns of establishment locations, generate detection probabilities, and understand IMB network resilience.","presenter":"Ms. Jennifer Nowicki","authors":[{"name":"Ms. Jennifer Nowicki","aff":"Student, Penn State University"}],"order":4}]},{"id":"s45","title":"Generative AI for Business","track":"Supply Chain Risk Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"EMBASSY H","chairs":["Prof. Fasheng Xu"],"abstracts":[{"id":"136-0170","title":"Does Renewable Energy Renew Energy Efficiency?","content":"This paper examines whether and how renewable energy adoption influences energy efficiency improvement. Using data from a multinational industrial conglomerate and policy categorization from GenAI, we find that using renewable energy to satisfy an additional 10% of energy demand leads to an additional 2.8% improvement in energy efficiency.","presenter":"Dr. Christopher Chen","authors":[{"name":"Dr. Amrou Awaysheh","aff":"Associate Professor, Indiana University"},{"name":"Dr. Christopher Chen","aff":"Assistant Professor, Indiana University"},{"name":"Prof. Owen Wu","aff":"Associate Professor, Kelley School of Business, Indiana Univ."}],"order":1},{"id":"136-0914","title":"AI Overloading? An Economic Analysis of AI-Driven Personalization in Online Advertising","content":"The rise of AI transforms personalized advertising, enabling precise targeting but increasing computational challenges. This study analyzes profit implications of AI-driven personalization, exploring optimal configurations of targeting accuracy and personalization depth to balance benefits and costs, avoiding inefficiencies from excessive personalization.","presenter":"Mr. Xu Zhang","authors":[{"name":"Mr. Xu Zhang","aff":"Student, School of Management, Fudan University"},{"name":"Dr. Hao Hu","aff":"Student, Georgia Institute of Technology"},{"name":"Prof. Yifan Dou","aff":"Professor, School of Management, Fudan University"}],"order":2},{"id":"136-0982","title":"GenAI Assistance in a Professional Service Market: The Perishing of Second Opinion","content":"We investigate the impact of generative AI (GenAI) adoption in a market of professional services such as medical treatment and financial consulting where the product is a professional opinion. In this environment, consumers benefit from seeking second opinion.","presenter":"Dr. Rachel Chen","authors":[{"name":"Dr. Zheyin Gu","aff":"Associate Professor, University of Connecticut"},{"name":"Dr. Yi Liu","aff":"Assistant Professor, University of Wisconsin-Madison"},{"name":"Dr. Rachel Chen","aff":"Professor, University of California Davis"}],"order":3},{"id":"136-1579","title":"A study with a new occupational AI exposure measure","content":"We present a conceptual framework that decomposes the Turing Transformation into AI's work activity and job opportunity effects. We develop a novel occupational AI exposure measure using a sentence transformer model to compare the semantic similarity between the occupation descriptions and AI patents.","presenter":"Prof. Tingliang Huang","authors":[{"name":"Prof. Yuanyang Liu","aff":"Assistant Professor, University of Tennessee, Knoxville"},{"name":"Prof. Tingliang Huang","aff":"Professor, The University of Tennessee-Knoxville"}],"order":4}]},{"id":"s78","title":"Socially Responsible Innovation","track":"Product Innovation and Technology Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"COURTLAND","chairs":["Prof. Nagarajan Sethuraman"],"abstracts":[{"id":"136-1562","title":"The Effects of Precision Medicine Innovation in a Competitive Drug Market","content":"The pharmaceutical industry stands at a crossroads with precision medicine. While these targeted therapies promise enhanced efficacy through patient-specific treatments, concerns about market viability persist due to smaller patient populations. Our study examines this theoretical tension by analyzing FDA precision medicine approvals, highlighting implications for pharmaceutical innovation.","presenter":"Dr. Jingwen Yang","authors":[{"name":"Dr. Jingwen Yang","aff":"Assistant Professor, University of Nevada Las Vegas"},{"name":"Prof. Anant Mishra","aff":"Professor, University of Minnesota"}],"order":1},{"id":"136-1732","title":"Material and Recycling Technology Choice in the Era of the Global Plastic Treaty","content":"Global CPG firms face increasing pressure to reduce plastic packaging. This study presents a model to examine firms' sourcing and recycling decisions across heterogeneous local recycling environments and market conditions. We analyze the impact of regulatory interventions (virgin plastic caps and recycled content mandates) and provide managerial insights.","presenter":"Mr. Donghyun (Daniel) Choi","authors":[{"name":"Mr. Donghyun (Daniel) Choi","aff":"Student, Georgia Institute of Technology"},{"name":"Prof. Andre Calmon","aff":"Associate Professor, Scheller College of Business"},{"name":"Prof. Beril Toktay","aff":"Professor, Georgia Institute of Technology"}],"order":2},{"id":"136-1859","title":"Impact of Invention Team Gender Diversity on Drug Development Success and Quality","content":"Does having additional women participate in research and product development teams result in more successful and safer products downstream? We examine this question in the context of the pharmaceutical industry which has suffered from historically low women participation in the\r\npatent invention teams.","presenter":"Prof. Nagarajan Sethuraman","authors":[{"name":"Prof. Nagarajan Sethuraman","aff":"Assistant Professor, University of Kansas"},{"name":"Prof. Deepak Jena","aff":"Assistant Professor, Indian School of Business"},{"name":"Prof. Rachna Shah","aff":"Professor, University of Minnesota"}],"order":3}]},{"id":"s89","title":"Analytics and AI in Operations and Supply Chain Management","track":"Behavioral Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"EMBASSY D","chairs":["Prof. John Aloysius","Dr. Rebekah Brau"],"abstracts":[{"id":"136-0738","title":"Human and Algorithm in Tandem: Insights from Automation in Sequential Decision-Making Tasks","content":"Demand-forecasting feeds into inventory-planning. Automating either task impacts the other decision-maker's behavior. we found: 1)Human planners discount human forecasts more than algorithmic ones. 2)Human forecasters anchor more to the service level and show less pattern noise when interacting with human planners. 3)Ultimately, automating demand-forecasting improve overall performance, while automating inventory-planningdoesnot","presenter":"Mr. Seyyed Iman Moosavi","authors":[{"name":"Mr. Seyyed Iman Moosavi","aff":"Student, Tilburg University"},{"name":"Dr. Eirini Spiliotopoulou","aff":"Associate Professor, Tilburg University"},{"name":"Prof. Jan Fransoo","aff":"Professor, Tilburg University"}],"order":1},{"id":"136-1563","title":"Biases of Humans, of AI, and of Humans with AI","content":"Our research examines whether individuals change their behavioral biases when interacting with LLMs that may also exhibit biases. We design a novel interactive AI experiment and show that AI biases indeed impact human decision-making and discover a new form of nudging. Importantly, how humans interact with AI matters for decision-making.","presenter":"Dr. Yang Chen","authors":[{"name":"Dr. Yang Chen","aff":"Assistant Professor, Ivey Biusiness School, Western University"},{"name":"Dr. Sam Kirshner","aff":"Lecturer, University of New South Wales"},{"name":"Prof. Anton Ovchinnikov","aff":"Professor, Queens University"},{"name":"Prof. Meena Andiappan","aff":"Associate Professor, Mcmaster University"},{"name":"Prof. Tracy Jenkin","aff":"Associate Professor, Queen's University"}],"order":2},{"id":"136-0816","title":"Algorithm Adoption and Explanations: An Experimental Study on Self and Other Perspectives","content":"In this work, we conduct behavioral experiments to study whether the party that is affected by a user’s decision (self vs. other) impacts the user’s adoption of ML recommendations. In addition, we study whether the presence vs. absence of explanations—commonly touted to increase ML adoption moderates our results.","presenter":"Ms. Zezhen (Dawn) He","authors":[{"name":"Dr. Fernanda Bravo","aff":"Assistant Professor, UCLA Anderson School of Management"},{"name":"Ms. Zezhen (Dawn) He","aff":"Student, University of Rochester"},{"name":"Prof. Yaron Shaposhnik","aff":"Associate Professor, Simon Business School"},{"name":"Prof. Leon Valdes","aff":"Associate Professor, University of Pittsburgh"}],"order":3},{"id":"136-0300","title":"Behavioral Mechanisms in Predictive Analytics: A Multi-Theoretical Approach to High- and Low-Level Processing Tasks","content":"This paper aims to understand the behavioral mechanisms driving predictive analytics use across high- and low-level processing tasks. We develop hypotheses adopting a multi-theoretical lens, using the Adaptive Character of Thought (ACT) and dual process theories. We then employ a laboratory experiment to test the hypothesized interventions.","presenter":"Dr. Rebekah Brau","authors":[{"name":"Dr. Rebekah Brau","aff":"Assistant Professor, Brigham Young University"},{"name":"Prof. Nada Sanders","aff":"Professor, Northeastern University"},{"name":"Prof. John Aloysius","aff":"Professor, University of Arkansas"}],"order":4}]},{"id":"s107","title":"Empirical Research in Retail Operations","track":"Empirical Research in Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"EMBASSY B","chairs":["Dr. Bengu Ozdemir"],"abstracts":[{"id":"136-0630","title":"The Hidden Cost of Grocery Delivery Platforms","content":"To stay competitive, pure brick-and-mortar grocery retailers increasingly partner with online delivery platforms. Using transaction data of a national grocery chain, we examine how retailers should choose between fixed-fee and pay-per-order structures, considering pricing strategies, customer behavior, and market dynamics to guide optimal partnership decisions in the evolving grocery landscape.","presenter":"Dr. Lina Wang","authors":[{"name":"Dr. Lina Wang","aff":"Assistant Professor, The Pennsylvania State University"},{"name":"Prof. Necati Ertekin","aff":"Associate Professor, University of Minnesota"},{"name":"Dr. Mohammad Nikoofal","aff":"Assistant Professor, Ryerson University"},{"name":"Prof. Mehmet Gumus","aff":"Professor, McGill University"}],"order":1},{"id":"136-0673","title":"The Effect of Inventory Level Disclosure on Online Retail Sales","content":"We use data from several Amazon departments to investigate the effect of inventory level disclosure on online sales. The results suggest that consumers respond differently to low, medium, and high levels of inventory level disclosure across departments after controlling for pricing.","presenter":"Dr. Annibal Sodero","authors":[{"name":"Dr. Annibal Sodero","aff":"Assistant Professor, Ohio State University"},{"name":"Prof. Tolga Aydinliyim","aff":"Associate Professor, Baruch College"},{"name":"Prof. Michael Pangburn","aff":"Professor, University of Oregon"}],"order":2},{"id":"136-0765","title":"Improving order cancellation forecasting: market dynamics, contextual and organizational factors","content":"We combine a proprietary organizational dataset with multiple public datasets to investigate factors leading to order cancellation in the outdoor gears industry. We show the relative strength of market dynamics, contextual, and organizational factors in improving order cancellation forecasting in the industry.","presenter":"Prof. Suman Niranjan","authors":[{"name":"Dr. Annibal Sodero","aff":"Assistant Professor, Ohio State University"},{"name":"Prof. Suman Niranjan","aff":"Assistant Professor, University of North Texas"},{"name":"Dr. Shashank Rao","aff":"Professor, Auburn University"}],"order":3},{"id":"136-1147","title":"Green E-commerce: Environmental Impact of Faster Delivery","content":"We empirically examine the impact of faster delivery on consumer ordering behavior and its subsequent environmental effects. We find faster delivery increases consumer demand but leads to more frequent and smaller orders, which raises logistics costs and carbon emissions. We further explore the mechanisms and mitigating policies.","presenter":"Dr. Jiankun Sun","authors":[{"name":"Ms. Chenshan Hu","aff":"Student, Washington University in St. Louis"},{"name":"Dr. Xiaoyang Long","aff":"Assistant Professor, University of Wisconsin Madison"},{"name":"Dr. Jiankun Sun","aff":"Assistant Professor, Imperial College London"},{"name":"Prof. Dennis Zhang","aff":"Associate Professor, Washington University in St. Louis"}],"order":4}]},{"id":"s123","title":"Panel: Outreach and Dissemination of Humanitarian Research","track":"Humanitarian Operations and Crisis Management","type":"Panel","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"GRAND HALL EAST B","chairs":["Dr. Telesilla Kotsi","Dr. Harwin De Vries"],"abstracts":[{"id":"136-2092","title":"Outreach and Dissemination of Humanitarian Research","content":"Research can improve humanitarian response. This panel explores how to bridge the gap between academia and real-world action. Experts will share strategies for making research accessible to practitioners, policymakers, and communities in crisis. We’ll discuss what works, what doesn’t, and how to ensure that research drives real change.","presenter":"Prof. Maria Besiou","authors":[{"name":"Prof. Maria Besiou","aff":"Professor, Kuehne Logistics University"},{"name":"Dr. Jarrod Goentzel","aff":"Post Doc/Researcher, Massachusetts Institute of Technology"},{"name":"Dr. Diego Vega","aff":"Associate Professor, Hanken School of Economics"},{"name":"Dr. Thomas Breugem","aff":"Associate Professor, Tilburg University"},{"name":"Dr. Harwin De Vries","aff":"Associate Professor, Rotterdam School of Management"}],"order":1}]},{"id":"s124","title":"Innovations in Digital Operations","track":"POM-Economics Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"TECHWOOD","chairs":["Ms. Caitlin Cunningham"],"abstracts":[{"id":"136-0401","title":"Employees or Independent Contractors? Effects of Labor Choices on Digital Platforms","content":"On-demand platforms provide services to consumers through independent contractors, employees, or a hybrid of the two types of workers. This empirical research investigates the effects of these two types of labor forces on a food delivery platform.","presenter":"Mr. Xingjian You","authors":[{"name":"Dr. Zhuoxin (Allen) Li","aff":"Associate Professor, University of Wisconsin-Madison"},{"name":"Mr. Xingjian You","aff":"Student, University of Wisconsin-Madison"},{"name":"Ms. Jianting Zhu","aff":"Student, University of Wisconsin-Madison"}],"order":1},{"id":"136-0648","title":"Channel Stickiness in Omni-Channel Retail: Temporary Shifts or Lasting Changes?","content":"We analyze channel-switching in omni-channel retail. While the pandemic accelerated online channel adoption, the extent of continued reliance on online shopping remains understudied. Using proprietary data with store closures and reopenings, we find that online sales spiked during closures but quickly declined post-reopening, indicating a persistent “stickiness” to offline channels.","presenter":"Ms. Caitlin Cunningham","authors":[{"name":"Ms. Caitlin Cunningham","aff":"Student, University of Washington"},{"name":"Prof. Elina Hwang","aff":"Assistant Professor, University of Washington"},{"name":"Prof. Leela Nageswaran","aff":"Assistant Professor, University of Washington"},{"name":"Prof. Soo-Haeng Cho","aff":"Associate Professor, Carnegie Mellon University"}],"order":2},{"id":"136-1090","title":"Exploring Cryptocurrency Scams: An Evolving Approach to Fraud Detection and Prevention","content":"This research explores the evolving landscape of cryptocurrency scams and fraud detection, focusing on blockchain transactions, scam categorization, and website evolution. It investigates using blockchain for transaction legitimacy verification, the impact of concept drift on machine learning, and the role of crowdsourced data in real-time fraud detection.","presenter":"Dr. Raymond Patterson","authors":[{"name":"Dr. Ram Gopal","aff":"Professor, University of Warwick"},{"name":"Ms. Sanaz Kakavand","aff":"Student, Haskayne School of Business"},{"name":"Dr. Sule Nur Kutlu","aff":"Assistant Professor, University of Calgary"},{"name":"Dr. Raymond Patterson","aff":"Professor, University of Calgary"}],"order":3},{"id":"136-1012","title":"Mechanistic Interpretability for Neural TSP solvers","content":"Neural networks can learn effective heuristics for the NP-hard Traveling Salesman Problem, but their black-box nature limits use for supply chain practitioners. We aim to apply mechanistic interpretability techniques, including sparse autoencoders, to a Graph Transformer solver to extract interpretable heuristics from the model's learned strategies.","presenter":"Mr. Reuben Narad","authors":[{"name":"Mr. Reuben Narad","aff":"Student, University of Washington"},{"name":"Prof. Michael Wagner","aff":"Professor, University of Washington"},{"name":"Prof. Léonard Boussioux","aff":"Assistant Professor, University of Washington"}],"order":4},{"id":"136-0615","title":"Fast TTC and Probabilistic Core Identification","content":"This paper proposes a fast eigenvector-based methodology for optimal matching for a continuum of agents and objects in the system. The methodology helps separate the agents who are likely to be in the core from those not in the core in constant time, O(1).","presenter":"Ms. Irene Aldridge","authors":[{"name":"Ms. Irene Aldridge","aff":"Student, Cornell University"}],"order":5}]},{"id":"s130","title":"Panel: What does the future hold for OPEX in the era of digitalization?","track":"Operational Excellence","type":"Panel","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"BAKER","chairs":["Prof. Jiju Antony"],"abstracts":[{"id":"136-2117","title":"What does the future hold for OPEX in the era of digitalization?","content":"The purpose of the panel discussion is to understand the future research directions of Operational Excellence from the perspectives of leading academics. In addition, a number of pressing issues on OPEX encountered by senior leaders in OPEX from various types of industry and countries will be brought into the panel.","presenter":"Dr. Kevin Linderman","authors":[{"name":"Dr. Kevin Linderman","aff":"Professor, Penn State University"},{"name":"Dr. Bart Lameijer","aff":"Assistant Professor, University of Amsterdam"},{"name":"Prof. Torbjørn Netland","aff":"Professor, ETH Zurich"},{"name":"Prof. Rachna Shah","aff":"Professor, University of Minnesota"},{"name":"Dr. Gopesh Anand","aff":"Professor, University of Illinois Urbana-Champaign"}],"order":1},{"id":"136-2124","title":"Panel: What does the future hold for OPEX in the era of digitalization?1","content":"The purpose of the panel discussion is to understand the future research directions of Operational Excellence from the perspectives of leading academics. In addition, a number of pressing issues on OPEX encountered by senior leaders in OPEX from various types of industry and countries will be brought into the panel.1","presenter":"Prof. Jiju Antony","authors":[{"name":"Prof. Jiju Antony","aff":"Professor, Northumbria University"},{"name":"Dr. Kevin Linderman","aff":"Professor, Penn State University"},{"name":"Dr. Bart Lameijer","aff":"Assistant Professor, University of Amsterdam"},{"name":"Prof. Torbjørn Netland","aff":"Professor, ETH Zurich"},{"name":"Prof. Rachna Shah","aff":"Professor, University of Minnesota"},{"name":"Dr. Gopesh Anand","aff":"Professor, University of Illinois Urbana-Champaign"}],"order":2}]},{"id":"s139","title":"Risk Management, Reinforcement Learning and Analytics","track":"POM-Finance Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"UNIVERSITY","chairs":["Prof. Ye Liu"],"abstracts":[{"id":"136-0794","title":"Clean-Tech Adoption and Risk Hedging","content":"In this study, we propose a model to assist manufacturers in transitioning from conventional to low-carbon technologies, involving initial fixed investment costs. We jointly optimize hedging strategy, capacity decisions, and technology choices to maximize a Conditional Value at Risk objective. We find that risk hedging facilitates adoption of clean technologies.","presenter":"Dr. Liao Wang","authors":[{"name":"Dr. Liao Wang","aff":"Associate Professor, The University of Hong Kong"},{"name":"Prof. David Yao","aff":"Professor, Columbia University"}],"order":1},{"id":"136-0828","title":"Advanced analytics for demand predictions of a financially constrained newsvendor","content":"Firms can invest in advanced analytics to improve demand forecasting. Using a game-theoretic model of a financially constrained newsvendor requiring loans and facing bankruptcy costs, we examine whether these constraints inhibit or encourage such investments. We offer insights into operational decision-making under bankruptcy risks.","presenter":"Ms. Daun Choi","authors":[{"name":"Ms. Daun Choi","aff":"Student, TUM School of Management, HN Campus"},{"name":"Prof. David Wuttke","aff":"Assistant Professor, TUM School of Management, HN Campus"},{"name":"Prof. Robert Graf","aff":"Professor, International University of Applied Sciences"}],"order":2},{"id":"136-1439","title":"Hedging through Deep Reinforcement Learning","content":"We investigate how a privately owned hog farm manages its inventory and uses hedging strategies when the farmer is concerned about risk. The farm faces risks from changing numbers of hogs, production costs, and the prices they can sell. The farm can use financial contracts to reduce these risks.","presenter":"Prof. Ye Liu","authors":[{"name":"Prof. Panos Kouvelis","aff":"Professor, Washington University in St. Louis"},{"name":"Prof. Ye Liu","aff":"Assistant Professor, Syracuse University"},{"name":"Prof. Danko Turcic","aff":"Associate Professor, University of California Riverside"},{"name":"Prof. Aaron (Yunzhe) Qiu","aff":"Assistant Professor, Peking University"}],"order":3},{"id":"136-1444","title":"Blockchain for Bullwhip Effect Mitigation: Role of Information, Automation and Accessibility","content":"This study empirically examines blockchain technology’s role in mitigating the bullwhip effect by reducing demand variability across supply chain layers. We explore mechanisms like enhanced information sharing, process automation and accessibility, and assess blockchain’s value across diverse supply chain integrations and block chain platforms.","presenter":"Mr. Shi Qiu","authors":[{"name":"Mr. Shi Qiu","aff":"Student, University of Illinois at Urbana Champaign"},{"name":"Prof. Sridhar Seshadri","aff":"Professor, University of Illinois Urbana-Champaign"},{"name":"Prof. Nikolay Osadchiy","aff":"Associate Professor, Emory University"}],"order":4}]},{"id":"s143","title":"Optimizing Digital Strategies, Supply Chains, and Healthcare Innovations","track":"Disruptive Technologies and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"KENNESAW","chairs":["Dr. Xianghui (Richard) Peng"],"abstracts":[{"id":"136-0498","title":"The Role of Blockchain Technology in Supply Chain Resilience","content":"This study explores how BCT can improve SC resilience of a firm. Data was collected from 261 firms from Malaysian Electrical and Electronics (E&amp;E) sector using a close-ended questionnaire. PLS-SEM was used to aid the analysis. The findings painted a complex picture of the interplay between BCT and SC resilience.","presenter":"Dr. Sharfuddin Khan","authors":[{"name":"Prof. Muhammad Shujaat Mubarik","aff":"Associate Professor, Heriot-Watt University"},{"name":"Dr. Sharfuddin Khan","aff":"Assistant Professor, University of Regina"},{"name":"Prof. Simonov Kusi-Sarpong","aff":"Associate Professor, Sheffield Hallam University"},{"name":"Prof. Samuel Fosso-Wamba","aff":"Professor, Toulouse Business School"}],"order":1},{"id":"136-1082","title":"Blockchain-Driven Safety Management in Lithium-Ion Battery Circular Supply Chains: A Design Science Approach","content":"This study explores blockchain technology's potential to enhance safety management in circular supply chains (CSCs), focusing on lithium-ion batteries. Using a design science research framework, we developed and evaluated a blockchain-based architecture to balance efficiency, security, and energy costs. The findings offer insights for proactive safety management in CSCs.","presenter":"Ms. Zhuowen Chen","authors":[{"name":"Ms. Zhuowen Chen","aff":"Student, Worcester Polytechnic Institute"},{"name":"Prof. Joseph Sarkis","aff":"Professor, Worcester Polytechnic Institute"}],"order":2},{"id":"136-1279","title":"Optimizing Family-Centered Genetic Testing Product Portfolio and Pricing","content":"Genetic testing is vital for cancer early diagnosis and targeted therapies, and assessing family risks. However, few patients and their families undergo testing. This study investigates the portfolio design and pricing of family-centered genetic testing. The results offer recommendations on maximizing health benefits for families and addresses the technological scalability.","presenter":"Dr. Ying Cao","authors":[{"name":"Dr. Ying Cao","aff":"Assistant Professor, Penn State Erie"},{"name":"Dr. Xinyu Wei","aff":"Assistant Professor, California State University, Chico"},{"name":"Dr. Edwin Wang","aff":"Assistant Professor, University of Massachusetts Boston"},{"name":"Dr. Xianghui (Richard) Peng","aff":"Associate Professor, Penn State University Erie"},{"name":"Dr. Victor Prybutok","aff":"Professor, University of North Texas"}],"order":3},{"id":"136-1282","title":"Optimization of clickstream and revenue management based on a practical experiment","content":"The rapid growth of digital services has amplified the importance of optimizing online user experiences and revenue strategies. This research investigates the impact of price visibility on clickstream behavior and revenue generation in a real company setting.","presenter":"Dr. Edwin Wang","authors":[{"name":"Dr. Edwin Wang","aff":"Assistant Professor, University of Massachusetts Boston"},{"name":"Dr. Yajun Lu","aff":"Assistant Professor, Jacksonville State University"},{"name":"Dr. Lingfei Luan","aff":"Assistant Professor, Psychological Science and Neuroscience"}],"order":4}]},{"id":"s146","title":"Economics of IS","track":"Information Systems and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"EMBASSY E","chairs":["Mr. Xinyu Zang","Dr. Anurag Garg"],"abstracts":[{"id":"136-1610","title":"Insuring Autonomous Vehicles: Perspectives from Operations Management","content":"The objective of our study is to model issues related to the insurance of autonomous vehicles. We use optimization and game theory to generate insights about monopolistic and competitive markets. Our models allow us to characterize equilibrium, analyze its properties, and provide useful insights.","presenter":"Dr. Amin Abbasi-Pooya","authors":[{"name":"Dr. Amin Abbasi-Pooya","aff":"Assistant Professor, Arkansas State University"},{"name":"Prof. Nagarajan Sethuraman","aff":"Assistant Professor, University of Kansas"},{"name":"Prof. Suman Mallik","aff":"Professor, University of Kansas"}],"order":1},{"id":"136-0445","title":"Joining or Not? The Strategic Role of Platforms in Bug Bounty Programs","content":"Firms face decisions on launching bug bounty programs via platforms. We analytically model the interplay between firms and platforms, exploring how platform strategies influence firms' choices. This research provides actionable insights into optimizing collaboration between platforms and firms to maximize security improvements and mutual benefits.","presenter":"Ms. Yiming Sun","authors":[{"name":"Ms. Yiming Sun","aff":"Student, Texas Tech University"},{"name":"Dr. Yi Gao","aff":"Assistant Professor, Texas Tech University"},{"name":"Prof. Sumanta Singha","aff":"Assistant Professor, Texas Tech University"}],"order":3},{"id":"136-0495","title":"Digitalization and Business Performance : mediation role of Supply Chain Responsiveness and Competitive advantage","content":"This study examines how digitalization (DIG) enhances supply chain responsiveness (SCR), competitive advantage (CA), and business performance (BP) in manufacturing. Using data from 200 professionals, sequential mediation analysis revealed that DIG improves SCR and CA, boosting BP. Insights guide managers in leveraging DIG for strategic benefits.","presenter":"Prof. Poonam Garg","authors":[{"name":"Prof. Poonam Garg","aff":"Professor, Institute of Management Technology , Ghaziabad"},{"name":"Dr. Atul Garg","aff":"Engagement Director, Tata Consultancy Services"}],"order":4},{"id":"136-1235","title":"Straying or Staying: The Impact of Token Incentives on User Defection and Retention","content":"Token incentive, a unique strategy in the blockchain ecosystem, offers unique benefits and challenges in enhancing user engagement for blockchain-based platforms. Using a quasi-natural experiment design, we investigate two token incentive campaigns centered around a leading decentralized exchange platform.","presenter":"Mr. Xinyu Zang","authors":[{"name":"Mr. Jian Li","aff":"Student, Xi'an Jiaotong University"},{"name":"Dr. Xiang(Shawn) Wan","aff":"Assistant Professor, Santa Clara University"},{"name":"Mr. Xinyu Zang","aff":"Assistant Professor, University of Missouri At Kansas City"},{"name":"Prof. Kenny Cheng","aff":"Professor, University of Florida"},{"name":"Dr. Xi Zhao","aff":"Professor, Xi'an Jiaotong University"}],"order":5}]},{"id":"s152","title":"Advancing Healthcare Quality and Patient Experience","track":"Healthcare Analytics","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"GRAND HALL EAST D","chairs":["Ms. Zlatana Nenova","Prof. Jong Youl Lee","Prof. Yeongin Kim"],"abstracts":[{"id":"136-0051","title":"The Impacts of Electronic Health Record Note Usage by Physicians on Quality of Care","content":"Using EHR audit logs and an instrumental variable approach, we study the impact of lead physicians' clinical note activity on inpatient length of stay and 30-day readmission rates. We find that increased note activity significantly reduces both, highlighting the critical role of clinical notes in enhancing efficiency and outcomes.","presenter":"Dr. Gaurav Jetley","authors":[{"name":"Dr. Gaurav Jetley","aff":"Assistant Professor, Colorado State University Fort Collins"},{"name":"Dr. He Zhang","aff":"Assistant Professor, Cal Poly"}],"order":1},{"id":"136-0224","title":"Hospital System Affiliation and Patient Experiences","content":"We examine how a hospital's affiliation to a healthcare system impacts its operations and patient experience. Our findings indicate that system affiliation is associated with a decline in patient experiences.","presenter":"Prof. Jong Youl Lee","authors":[{"name":"Prof. Jong Youl Lee","aff":"Assistant Professor, Florida International University"},{"name":"Dr. Min Chen","aff":"Associate Professor, Florida International University"},{"name":"Prof. Jong Myeong Lim","aff":"Assistant Professor, Miami Herbert Busienss School"}],"order":2},{"id":"136-0303","title":"Telehealth, Health Equity, and the Management of Chronic Health Conditions in Vulnerable Populations","content":"We use a Difference-in-Differences approach to examine the effect of telehealth adoption on visit frequency among patients with diabetes and its impact on health equity. Our results suggest that telehealth improves access to care. However, these effects are less pronounced for Hispanic-Latino patients.","presenter":"Dr. Cristina M. De Haro","authors":[{"name":"Dr. Cristina M. De Haro","aff":"Post Doc/Researcher, University of California Irvine"},{"name":"Prof. Behnaz Bojd","aff":"Assistant Professor, University of California Irvine"},{"name":"Prof. John Billimek","aff":"Associate Professor, University of California, Irvine"},{"name":"Prof. Vijay Gurbaxani","aff":"Professor, University of California Irvine"}],"order":3},{"id":"136-1584","title":"Automated Discovery of Concerns for Nurse Turnover from Social Media","content":"This study analyzes nurse burnout using Twitter data, employing text analytics and machine learning to identify symptoms across demographics. Findings reveal variations in burnout indicators, enabling targeted interventions. The research highlights social media’s potential for real-time monitoring, informing policies and resource allocation to address nurse well-being in healthcare systems.","presenter":"Dr. Zhilei Qiao","authors":[{"name":"Dr. Zhilei Qiao","aff":"Assistant Professor, UAB"},{"name":"Dr. Abdulaziz Ahmed","aff":"Assistant Professor, University of Alabama Birmingham"},{"name":"Ms. Sarah L Robertson","aff":"Post Doc/Researcher, Universitat Autonoma de Barcelona (UAB)"},{"name":"Prof. Xiaoni Zhang","aff":"Professor, Universitat Autonoma de Barcelona (UAB)"}],"order":4},{"id":"136-1681","title":"A patient prospective on treatments for substance use disorder","content":"We collect data on U.S. residents. Our goal is to (1) identify features of rehabilitation programs which help people with substance use disorder regain control over their lives and (2) understand if rehabilitation facilities reach out to enquire how a patient is doing post discharge.","presenter":"Ms. Zlatana Nenova","authors":[{"name":"Ms. Zlatana Nenova","aff":"Assistant Professor, Wake Forest University"},{"name":"Dr. David Rea","aff":"Assistant Professor, Lehigh University"},{"name":"Prof. Margret Bjarnadottir","aff":"Assistant Professor, University of Maryland"},{"name":"Dr. Madeline Marks","aff":"Assistant Professor, University of Maryland"}],"order":5}]},{"id":"s163","title":"Empirical Analysis of New Retail Models","track":"Empirical Research in Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"INMAN","chairs":["Ms. Natalie Epstein"],"abstracts":[{"id":"136-1385","title":"Circular business models in fashion retail: Examining customers’ engagement in take-back initiatives","content":"Circular business models, such as take-back and resale initiatives, are described as a potential solution to address sustainability challenges in retail. We study customer behavior in response to engaging in a retailer's take-back program by analyzing more than four years of transaction data from a Nordic apparel retailer.","presenter":"Mr. Christoph Baldauf","authors":[{"name":"Mr. Christoph Baldauf","aff":"Assistant Professor, Stockholm School of Economics"},{"name":"Ms. Malin Wennberg","aff":"Student, Stockholm Business School"}],"order":1},{"id":"136-1585","title":"The Operational Impact of Customer Location in On-Demand Services","content":"The Operational Impact of Customer Location in On-Demand Services","presenter":"Ms. Natalie Epstein","authors":[{"name":"Ms. Natalie Epstein","aff":"Student, HBS"},{"name":"Prof. Santiago Gallino","aff":"Associate Professor, The Wharton School"},{"name":"Prof. Antonio Moreno","aff":"Associate Professor, Harvard University"}],"order":2},{"id":"136-1611","title":"Trust Dynamics in Supply Chain Capacity Decisions","content":"We explore the role of trust and trustworthiness in coordinating a dyadic supply chain via an experimental newsvendor game. Parties receive divergent demand forecasts, and can choose to coordinate ahead of making capacity investments. We study how different a-priori levels of trust and trustworthiness can explain in-game behavior and performance.","presenter":"Dr. Jose Lopez","authors":[{"name":"Dr. Jose Lopez","aff":"Assistant Professor, Texas A&amp;M University"},{"name":"Dr. Kyle Hyndman","aff":"Professor, University of Texas Dallas"}],"order":3},{"id":"136-1154","title":"The impact of loading-unloading zones on the last-mile logistics for nanostores in emerging markets","content":"This doctoral dissertation investigates the impact of loading-unloading zones on last-mile logistics for nanostores in emerging markets. Our field experiments in Mexico reveal significant reductions in carbon emissions, noise, and traffic congestion. The dissertation contributes to academic literature while offering practical solutions to address parking challenges in urban logistics.","presenter":"Dr. Camilo Mora Quiñones","authors":[{"name":"Dr. Camilo Mora Quiñones","aff":"Post Doc/Researcher, Tecnologico De Monterrey"}],"order":4}]},{"id":"s174","title":"Sustainabilty in Food and Agriculture Supply Chains","track":"Agriculture and Food Supply Chains","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"VININGS","chairs":["Mr. Sandeep Srinivas"],"abstracts":[{"id":"136-0363","title":"Pricing Strategy under hyperinflation Economy","content":"This paper examines pricing and production decisions in a hyper-inflation environment. Governments often try to suppress economic struggles by announcing inflation rates that are lower than the actual figures. We empirically show the impact of the inflation rate and the ambiguity on consumers' purchase decision.","presenter":"Mr. Haoran Yu","authors":[{"name":"Mr. Haoran Yu","aff":"Student, Syracuse University"},{"name":"Prof. Burak Kazaz","aff":"Professor, Whitman School of Management"},{"name":"Prof. Scott Webster","aff":"Professor, Arizona State University Tempe"}],"order":1},{"id":"136-0535","title":"From Waste to Welfare: The Effect of Foodtech Platforms on Food Insecurity","content":"Food insecurity in the US coexists with significant food waste. This study examines the impact of a foodtech platform focused on reducing retail food waste, on food insecurity. Our findings show that the platform’s entry decreases local food insecurity, especially in high-poverty regions, and that its effect complements food banks.","presenter":"Mr. Sandeep Srinivas","authors":[{"name":"Mr. Sandeep Srinivas","aff":"Student, University of Illinois at Urbana Champaign"},{"name":"Prof. Gautam Pant","aff":"Professor, University of Illinois at Urbana Champaign"},{"name":"Dr. Ujjal Mukherjee","aff":"Associate Professor, University of Illinois Urbana-Champaign"}],"order":2},{"id":"136-0737","title":"Of the first five US states with food waste bans, Massachusetts alone reduced landfilled waste","content":"Diverting food waste from landfills is key to reducing emissions. We compile a comprehensive waste dataset spanning 36 states to evaluate the first five bans. Contrary to policymakers' expectations, we cannot reject a null effect for four states. However, there is a silver lining: Massachusetts achieved a 7.3% waste reduction.","presenter":"Ms. Fiorentia Zoi Anglou","authors":[{"name":"Ms. Fiorentia Zoi Anglou","aff":"Student, University of Texas Austin"},{"name":"Prof. Robert Sanders","aff":"Assistant Professor, University of California San Diego"},{"name":"Prof. Yannis Stamatopoulos","aff":"Associate Professor, The University of Texas at Austin"}],"order":3},{"id":"136-1402","title":"Enhancing Sustainability: Smallholder Farmers' Incentives for Sharing Yield Data Information","content":"Recent technological advancements have expanded agriculture-related data accessible to small farmers. We examine when smallholder farmers are incentivized to share yield uncertainty information and its sustainability implications. Farmers’ decisions are influenced by market structure and information accuracy, highlighting the need for alignment and economic incentives to ensure sustainable land use.","presenter":"Mr. Jae-Hyuck Park","authors":[{"name":"Mr. Jae-Hyuck Park","aff":"Assistant Professor, New Jersey Institute of Technology"},{"name":"Prof. Hyoduk Shin","aff":"Professor, University of California San Diego"}],"order":4}]},{"id":"s184","title":"Inventory Management","track":"Retail Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"FAIRLIE","chairs":["Dr. Yao Chen"],"abstracts":[{"id":"136-0434","title":"A Newsvendor Model with Theft","content":"We revisit the newsvendor model with theft-related inventory shrinkage. In addition to the direct revenue loss, theft-related inventory shrinkage has costs due to inventory underage or overage. We provide a newsvendor with random demand and theft, provide preliminary analysis, and discuss results from a simulation study.","presenter":"Mr. Md Shoaib Ullash","authors":[{"name":"Dr. Dincer Konur","aff":"Associate Professor, Texas State University"},{"name":"Mr. Md Shoaib Ullash","aff":"Student, Texas State University"}],"order":1},{"id":"136-0643","title":"Do Not Look Too Far: Performance of Myopic Policies for Inventory Management at Retail Stores","content":"We study a multi-item, multi-period stock allocation problem in retail stores under capacity and minimum presentation constraints. We propose a myopic-inspired ordering policy, which does not rely on full information of the demand distribution. Our analysis demonstrates the near-optimal performance of myopic policies in capacity-constrained retail environments.","presenter":"Mr. Mohammad Razzaghi Kashani","authors":[{"name":"Mr. Mohammad Razzaghi Kashani","aff":"Student, University of Houston"},{"name":"Dr. Mehdi Farahani","aff":"Assistant Professor, University of Houston"}],"order":2},{"id":"136-0899","title":"Sequential decision making in perishable inventory planning","content":"To harmonize perishable supply chains, planners need to anticipate a series of future orders. This study presents a model for sequentially deciding upon the latter. To make the model representative, non-stationary demand is considered. State-of-science problem formulations are elaborated. This study pinpoints the usefulness of prediction intervals in inventory planning.","presenter":"Mr. Adhurim Imeri","authors":[{"name":"Mr. Adhurim Imeri","aff":"Student, WU (Vienna University of Economics and Business)"},{"name":"Prof. Gerald Reiner","aff":"Professor, Vienna Univ of Econ &amp; Business Admin"}],"order":3},{"id":"136-0318","title":"The More Calculative, the Better? Automation with a Customizable Inventory System and Salesforce Profit Protection","content":"As an increasing number of firms delegate the purchasing responsibilities of their salesforces to external parties, we investigate the benefits of such delegation for both the firm and the salesperson. Moreover, we examine whether salesforce profit protection effectively safeguards salespeople's profits from decline. Our study yields intriguing, counterintuitive findings.","presenter":"Ms. Xiaoting Jiao","authors":[{"name":"Ms. Xiaoting Jiao","aff":"Student, University of Science and Technology of China"},{"name":"Dr. Subodha Kumar","aff":"Professor, Temple University"},{"name":"Prof. Yugang Yu","aff":"Professor, University of Science and Technology of China"}],"order":4}]},{"id":"s208","title":"Recent Advances in AI and LLM","track":"Digital Platforms, Innovations and Transformations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"GREENBRIAR","chairs":["Dr. Tu Ni"],"abstracts":[{"id":"136-1056","title":"Take Caution in Using LLMs as Human Surrogates: Scylla Ex Machina","content":"Recent studies suggest LLMs closely align with human behavior, leading some to propose using them as surrogates in social science. However, we argue LLMs differ fundamentally from human cognition. In a recent game, LLMs fail to demonstrate human-level reasoning, with diverse, unpredictable failures linked to input language, roles, and safeguards.","presenter":"Mr. Yuan Gao","authors":[{"name":"Mr. Yuan Gao","aff":"Student, Boston University"},{"name":"Prof. Dokyun Lee","aff":"Associate Professor, Boston University"},{"name":"Prof. Gordon Burtch","aff":"Associate Professor, Boston University"},{"name":"Prof. Sina Fazelpour","aff":"Assistant Professor, Northeastern University"}],"order":1},{"id":"136-1801","title":"Reward Modeling with Ordinal Feedback: Wisdom of the Crowd","content":"Learning a reward model (RM) from human preferences has been an important component in aligning large language models (LLMs). We propose a framework for learning RMs under ordinal feedback which generalizes the case of binary preference feedback to any arbitrary granularity.","presenter":"Mr. Shang Liu","authors":[{"name":"Mr. Shang Liu","aff":"Student, Imperial College Business School, Imperial College London"},{"name":"Dr. Xiaocheng Li","aff":"Assistant Professor, Imperial College London"}],"order":2},{"id":"136-1501","title":"Calibrated Coarsening in Human-AI Interaction","content":"AI signals can aid decision-making, but cognitive biases often hinder impact. Coarsening signals at optimal thresholds improves outcomes by adapting to biases and being portable across contexts. Using a Bayesian persuasion framework and randomized experiment with loan underwriters, we demonstrate, empirically and theoretically, that coarsened AI signals enhance decision-making effectiveness.","presenter":"Ms. Ruru Hoong","authors":[{"name":"Ms. Ruru Hoong","aff":"Student, Harvard Business School"},{"name":"Ms. Bnaya Dreyfuss","aff":"Student, Economics"}],"order":4}]},{"id":"s232","title":"Retail, Supply Chain, and Technology","track":"Supply Chain Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"EMBASSY A","chairs":["Prof. Greys Sosic","Prof. Hailong Cui"],"abstracts":[{"id":"136-1344","title":"Coordinating Operational and Financial Roles of Distributors in Supply Chains","content":"In developing countries, we observe that distributors often fulfill two roles in a supply chain: boosting demand and providing financing. The primary goal of this paper is to examine how a manufacturer should contract with the distributor to coordinate these two roles.","presenter":"Dr. Jin YAO","authors":[{"name":"Dr. Nitish Jain","aff":"Associate Professor, London Business School"},{"name":"Prof. S. Alex Yang","aff":"Professor, London Business School"},{"name":"Dr. Jin YAO","aff":"Assistant Professor, Lingnan Univ"}],"order":1},{"id":"136-1526","title":"Influencing Customers and Product Returns","content":"Digital platforms allow firms to encourage online orders through influencers’ posts or reviews, which may be skewed in favour of a purchase. However, customers who ordered under such influence can ultimately return the product. We study how a firm’s influence decision may be intertwined with its pricing and refund policy.","presenter":"Prof. Xiao Huang","authors":[{"name":"Mr. Reza Nazari Khanmiri","aff":"Student, Concordia University"},{"name":"Prof. Xiao Huang","aff":"Professor, Concordia University"},{"name":"Prof. Georges Zaccour","aff":"Professor, Hec Montreal"}],"order":2},{"id":"136-1626","title":"Optimal Pricing and Logistics Decisions in Platform Competition: Insights from a Game-Theoretic Model","content":"This paper examines how e-commerce platform competition shapes fee structures and market outcomes. Duopolies favor high-logistics-fee, low-commission-rate strategies, contrasting with monopolists' low-logistics-fee, high-commission-rate approach. Reducing logistics fees benefits sellers and consumers in low competition but erodes platform profits; in high competition, it aids platforms and consumers while challenging seller profitability.","presenter":"Ms. Yao Li","authors":[{"name":"Ms. Yao Li","aff":"Student, Northwestern University Kellogg School o"},{"name":"Prof. Lauren Lu","aff":"Professor, Dartmouth College"},{"name":"Prof. Jan Van Mieghem","aff":"Professor, Northwestern University"}],"order":3},{"id":"136-1674","title":"Impact of Auto Franchise Laws on EV Adoption","content":"This paper empirically examines the influence of EV franchise laws on EV adoption. Using the synthetic control method and machine learning, we establish the causal effect of these laws on EV adoption. Our findings offer valuable insights for policymakers and businesses seeking to decarbonize the transportation sector.","presenter":"Mr. Andrey Makhanov","authors":[{"name":"Mr. Andrey Makhanov","aff":"Student, University of North Carolina at Chapel Hill"},{"name":"Prof. Nur Sunar","aff":"Associate Professor, Kenan-Flagler Business School"},{"name":"Prof. Jayashankar Swaminathan","aff":"Professor, University of North Carolina Chapel Hill"}],"order":4},{"id":"136-1915","title":"Investigating the Relationship between Supply Network Structures and Firm Performance","content":"In this study, we examine the relationship between firms' supply network structures and their performance in a cross-industry context. We use two network-level measures (network density and network centralization) as indicators of different supply network structures. Our results suggest that supply network structures have differential effects on performance across industries.","presenter":"Dr. Gyusuk Lee","authors":[{"name":"Dr. Gyusuk Lee","aff":"Assistant Professor, IE BUSINESS SCHOOL"},{"name":"Prof. Sri Talluri","aff":"Professor, Michigan State University"},{"name":"Prof. Sriram Narayanan","aff":"Professor, Michigan State University"}],"order":5}]},{"id":"s241","title":"Workshop Amazon’s Last Mile logistics","track":"Data Science, Analytics and AI","type":"Workshop","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"ROSWELL","chairs":["Prof. Sebastian Souyris","Dr. Chinmoy Mohapatra"],"abstracts":[{"id":"136-2042","title":"Amazon’s Last Mile logistics: Jurisdiction, Demand, Capacity, and Labor planning.","content":"Amazon’s advanced analytics in Last Mile logistics, covering Jurisdiction, Demand, Capacity, and Labor planning. We'll examine how data-driven insights, predictive modeling, and GenAI enhance decision-making, improve efficiency, and reduce costs in final-mile delivery. Through real-life examples from Amazon’s Last Mile, we'll demonstrate how these technologies revolutionize","presenter":"Dr. Chinmoy Mohapatra","authors":[{"name":"Dr. Chinmoy Mohapatra","aff":"Senior Research Scientist, Amazon.com"}],"order":1}]},{"id":"s263","title":"Insights on Digital Marketplace","track":"POM-Marketing Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"DUNWOODY","chairs":["Mr. Yunhyoung Kim"],"abstracts":[{"id":"136-0490","title":"Incrementality Experimentation in Online Advertising","content":"This research investigates how competition influences platforms' incentives to enable incrementality experimentation in online advertising. Our model demonstrates that advertisers benefit from experimentation through improved bidding efficiency, but platforms offer experimentation tools only under high competition, mitigating risks of non-incremental ads while maximizing surplus extraction from incremental clicks.","presenter":"Dr. Jason Choi","authors":[{"name":"Dr. Jason Choi","aff":"Assistant Professor, University of Maryland"},{"name":"Prof. Amin Sayedi","aff":"Assistant Professor, University of Washington"}],"order":1},{"id":"136-1253","title":"How a Comment Restriction Policy on News Platforms Reshapes User Engagement","content":"This study investigates the spillover effects of removing the comment section in some categories on a major platform. Using an exogenous policy change as a natural experiment, it examines how restrictions influence user behaviors within the targeted categories and unrelated ones. These findings offer critical insights for comment moderation strategies.","presenter":"Mr. Yeohong Yoon","authors":[{"name":"Ms. Yeolim (Bella) Yoon","aff":"Student, University of Minnesota"},{"name":"Prof. Linli Xu","aff":"Associate Professor, University of Minnesota"},{"name":"Mr. Yeohong Yoon","aff":"Student, Emory University"}],"order":2},{"id":"136-2030","title":"Zip-code Targeted Mobile Advertising for Small and Medium Businesses","content":"This paper investigates whether and how Zip-code targeted mobile ads work for small and medium businesses. We analyze a large-scale field study of Zip-code targeting based on customers’ current GPS locations. We provide the first evidence that Zip-code targeted mobile ads significantly improve local businesses’ mobile and physical traffic.","presenter":"Mr. Mingyu (Max) Joo","authors":[{"name":"Dr. Inyoung Chae","aff":"Associate Professor, Sungkyunkwan University"},{"name":"Dr. Seunghyun Kim","aff":"Assistant Professor, Northeastern University"},{"name":"Mr. Mingyu (Max) Joo","aff":"Associate Professor, University of California, Riverside"},{"name":"Dr. Alex Kim","aff":"Associate Professor, Sungkyunkwan University"}],"order":3},{"id":"136-1843","title":"Short-form Video Recommendation Algorithm for Doomscrolling","content":"We study human decision-making in short-form video consumption and explore its interaction with recommendation algorithms. The decision-making process within short-form video platforms is modeled using sequential Bayesian learning and neuroscientific framework, which explains the phenomenon of doomscrolling even with the lower matching quality recommended videos.","presenter":"Mr. Yunhyoung Kim","authors":[{"name":"Mr. Yunhyoung Kim","aff":"Student, Marketing, Carlson School of Management"},{"name":"Prof. Haitao (Tony) Cui","aff":"Professor, University of Minnesota"}],"order":4}]},{"id":"s272","title":"Empirical Societal Ops","track":"Operations and Society","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"SPRING","chairs":["Dr. Chris Parker"],"abstracts":[{"id":"136-0354","title":"Last-mile Delivery in Health Care: Drone Delivery for Blood Products in Rwanda","content":"We examine whether and the extent to which the adoption of delivery drones for last-mile delivery of blood products impacts inventory management and health outcomes. We find substantial heterogeneity in effects, highlighting key considerations for decision makers allocating scarce resources to improve hospital operations and health outcomes.","presenter":"Ms. Harriet Jeon","authors":[{"name":"Ms. Harriet Jeon","aff":"Student, Wharton School, University of Pennsylvan"},{"name":"Prof. Hummy Song","aff":"Assistant Professor, The Wharton School"},{"name":"Dr. Jean-Baptiste Mazarati","aff":"Assistant Professor, University of Global Health Equity, Rwanda"},{"name":"Prof. Claudio Lucarelli","aff":"Associate Professor, The Wharton School"},{"name":"Mr. Donatien Ngabo","aff":"Director, Ministry of Health, Rwanda"}],"order":1},{"id":"136-0452","title":"How Operational Updates Shape Emotional and Behavioral Responses to Disasters","content":"Relief organizations are expected to release operational updates on their websites and social media during their disaster response. We use text analysis, econometrics and online experiments to understand the effect of relief organizations’ operational updates on public's emotions and behavior during wildfire response.","presenter":"Dr. Sebastian Villa","authors":[{"name":"Dr. Sebastian Villa","aff":"Assistant Professor, University of Colorado Boulder"},{"name":"Prof. Patricia Moravec","aff":"Assistant Professor, Indiana University Bloomington"},{"name":"Dr. Eunae Yoo","aff":"Assistant Professor, Indiana University Bloomington"},{"name":"Prof. Lu (Lucy) Yan","aff":"Associate Professor, Indiana University Bloomington"},{"name":"Prof. Alfonso Pedraza-Martinez","aff":"Professor, Mendoza College of Business"}],"order":2},{"id":"136-1210","title":"Wages and Tipping on On-Demand Service Platforms","content":"Several platforms have been reducing their wage contribution and relying more on customers' tips to compensate workers. Motivated by these practices, we develop a game theory model and conduct incentivized experiments to study how a platform’s wage and tipping policy impact customers’ reciprocal behavior towards the platform and workers.","presenter":"Mr. Swanand Kulkarni","authors":[{"name":"Mr. Swanand Kulkarni","aff":"Post Doc/Researcher, Tuck School of Business"},{"name":"Prof. Laurens Debo","aff":"Professor, Dartmouth College"},{"name":"Prof. Raghav Singal","aff":"Assistant Professor, Tuck School of Business"}],"order":3}]},{"id":"s301","title":"Recent Advances in Global Supply Chain Management","track":"Manufacturing Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"LENOX","chairs":["Dr. Varun Gupta"],"abstracts":[{"id":"136-0857","title":"Achieving Emergent Symmetry in High Tech Supply Chains","content":"For manufacturers, it is important that all components are available when assembling their end-product. Overall delay is determined by the supplier with the largest backlog, so the manufacturer wants suppliers to invest in excess production capacity. We consider the decentralized optimization problem where suppliers determine their own optimal service rate.","presenter":"Ms. Mirjam Meijer","authors":[{"name":"Ms. Mirjam Meijer","aff":"Assistant Professor, Kühne Logistics Univesity"},{"name":"Mr. Dennis Schol","aff":"Post Doc/Researcher, Eindhoven University of Technology"},{"name":"Dr. Willem Van Jaarsveld","aff":"Associate Professor, Eindhoven University of Technology"},{"name":"Prof. Maria Vlasiou","aff":"Professor, University of Twente"},{"name":"Prof. Bert Zwart","aff":"Professor, Eindhoven University of Technology"}],"order":1},{"id":"136-1918","title":"Economic Impact of Food Waste and Loss Reduction: Integrated Supply Chain and Market Approach","content":"Food waste and loss (FWL) is a grand challenge throughout food supply chain. We present an integrated food supply chain and market approach to study the economic impact of reducing FWL on both domestic market and imports and exports, with a case study on the U.S. grape supply chain.","presenter":"Dr. Hoa Hoang","authors":[{"name":"Prof. Haitao Li","aff":"Professor, University of Missouri St Louis"},{"name":"Dr. Wyatt Thompson","aff":"Professor, University of Missouri"},{"name":"Dr. Hoa Hoang","aff":"Post Doc/Researcher, University of Missouri"}],"order":2},{"id":"136-1941","title":"Collaborative Efforts for Improving Process Inefficiency in Retailer’s Backroom: A Game-Theoretic Analysis","content":"Inventory inaccuracies in retail backrooms lead to stockouts, lost sales, and dissatisfied customers. Using a game-theoretic model, we explore collaborative strategies, including cost-sharing contracts and process optimization, to improve inventory accuracy. Our findings highlight conditions for effective collaboration and offer managerial insights to enhance supply chain performance and backroom operations.","presenter":"Dr. Varun Gupta","authors":[{"name":"Dr. Ashutosh Sarkar","aff":"Associate Professor, IIM kozhikode"},{"name":"Dr. Varun Gupta","aff":"Associate Professor, University of North Georgia"}],"order":3},{"id":"136-0903","title":"The Made in America Flagwashing Triad: Manufacturers, Consumers, and the FTC","content":"There are tremendous advantages in marketing a product as \"made in USA,\" Yet, given that supply chains are so globally integrated, many U.S. products do not comply with the MUSA standards. In this study, we use secondary data to create typology to understand and detect overstated and false claims.","presenter":"Dr. Jason Woldt","authors":[{"name":"Dr. Jason Woldt","aff":"Assistant Professor, University of Wisconsin Oshkosh"}],"order":4}]},{"id":"s311","title":"Revenue Management in Platform Markets","track":"Revenue Management and Pricing","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"MARIETTA","chairs":["Xiaotang Yang","Dr. Yun Zhou"],"abstracts":[{"id":"136-0624","title":"On-Demand Food Delivery with Compensation Services","content":"In food delivery services, failure to meet promised delivery times results in delivery delays and potential loss of future orders. This paper presents an analytical model that examines how promised delivery times affect the decisions of platforms, customers, and drivers, and the impact of customer compensation policies.","presenter":"Dr. Yanling Zhuang","authors":[{"name":"Dr. Yanling Zhuang","aff":"Post Doc/Researcher, McMaster University"},{"name":"Dr. Elkafi Hassini","aff":"Professor, Mcmaster University"},{"name":"Dr. Yun Zhou","aff":"Associate Professor, Mcmaster University"},{"name":"Dr. Yufei Yuan","aff":"Professor, Mcmaster University"}],"order":1},{"id":"136-0995","title":"Dynamic Competition in Online Retailing: Implications of Customer-to-Customer Interactions","content":"Online retailing has a pervasive feature: Customers are constantly engaged in social interactions that influence their purchase decisions. In a competitive environment, we take a novel perspective to distinguish two types of customer-to-customer interactions. Our goal is to investigate their respective impacts on the dynamic competition in online retailing.","presenter":"Dr. Xin Geng","authors":[{"name":"Dr. Xin Geng","aff":"Assistant Professor, University of Miami"},{"name":"Dr. Zheyu Jiang","aff":"Assistant Professor, Nanjing University"},{"name":"Prof. Nan Yang","aff":"Professor, University of Miami"},{"name":"Prof. Renyu Zhang","aff":"Associate Professor, The Chinese University of Hong Kong"}],"order":2},{"id":"136-1113","title":"Share or Solo? Platform Operations and Social Choices in Ride-Hailing","content":"We study the optimal amount of ride-sharing on a ride-hailing platform. We find that a platform will induce a positive amount of ride-sharing only when riders' arrival rate is sufficiently high. A social planner tends to incentivize more ride-sharing than a profit-maximizing platform but may charge higher prices.","presenter":"Dr. Zhoupeng (Jack) Zhang","authors":[{"name":"Prof. Ming Hu","aff":"Professor, University of Toronto"},{"name":"Dr. Jianfu Wang","aff":"Associate Professor, City University of Hong Kong"},{"name":"Dr. Hengda Wen","aff":"Post Doc/Researcher, University of Toronto"},{"name":"Dr. Zhoupeng (Jack) Zhang","aff":"Assistant Professor, University at Buffalo, SUNY"}],"order":3},{"id":"136-1920","title":"Platform Entry and Vendor Competition in On-Demand Economy","content":"We investigate the impact of platform entry on vendor competitive dynamics. We show that the platform-enabled sharing of couriers can improve delivery efficiency and lower delivery costs but may intensify vendor competition through per-order delivery subsidy, placing them in a prisoner’s dilemma that ultimately lowers their profits.","presenter":"Dr. Xiaotang Yang","authors":[{"name":"Mr. Arseniy Gorbushin","aff":"Student, Rotman School of Management"},{"name":"Prof. Ming Hu","aff":"Professor, University of Toronto"},{"name":"Dr. Xiaotang Yang","aff":"Post Doc/Researcher, University of Toronto"},{"name":"Dr. Yun Zhou","aff":"Associate Professor, Mcmaster University"}],"order":4}]},{"id":"s332","title":"Panel: Silver Economy","track":"Service Operations","type":"Panel","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"EMBASSY C","chairs":["Prof. Rohit Verma","Ms. Diep Pham"],"abstracts":[{"id":"136-2093","title":"Silver Prosperity Index (SPI","content":"In this session, we will discuss a newly proposed Silver Prosperity Index (SPI), which aims to address the expansive economic potential of the “silver economy” and the importance of digital and technological inclusivity in the lives of seniors.","presenter":"Prof. Rohit Verma","authors":[{"name":"Prof. Rohit Verma","aff":"Professor, University of South Carolina"},{"name":"Ms. Diep Pham","aff":"Student, Darla Moore School of Business"},{"name":"Prof. Kejia Hu","aff":"Associate Professor, University of Oxford"},{"name":"Dr. Xin Ding","aff":"Associate Professor, Rutgers Business School"}],"order":1}]},{"id":"s333","title":"Workshop: Innovation in Operations Research (OR)/ Operations Management (OM): Fostering POM and Community in Problem Formulation","track":"POM and Community","type":"Workshop","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"EMBASSY F","chairs":["Dr. Sadan Kulturel-Konak"],"abstracts":[{"id":"136-2052","title":"Innovation in Operations Research (OR)/ Operations Management (OM): Fostering Equity and Justice in Problem Formulation","content":"This interactive workshop introduces innovative ways for introductory courses to incorporate justice and equity into OR/OM problems, traditionally dominated by cost, benefit, and efficiency considerations. Participants will collaborate to critique, refine, and test example problems and pedagogical strategies. Feedback will shape resources to advance socially responsible OR/OM education.","presenter":"Dr. Sadan Kulturel-Konak","authors":[{"name":"Dr. Sadan Kulturel-Konak","aff":"Professor, Penn State Berks"},{"name":"Dr. Abdullah Konak","aff":"Professor, Penn State Berks"}],"order":1}]},{"id":"s377","title":"Panel: AI for Health and Wellbeing","track":"Practice Leaders","type":"Panel","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"Learning Center","chairs":["Prof. Tinglong Dai"],"abstracts":[{"id":"136-2130","title":"Panel: AI for Health and Wellbeing","content":"This panel brings together leading experts from industry and academia to discuss successes, practical challenges and ethical considerations involved in integrating AI into the ecosystem of health and wellbeing.","presenter":"Prof. Pinar Keskinocak","authors":[{"name":"Prof. Pinar Keskinocak","aff":"Professor, Georgia Institute of Technology"},{"name":"Dr. Rosalia Tungaraza","aff":"AVP, AI, Baptist Health South Florida"},{"name":"Dr. Nabile Safdar","aff":"Chief AI Officer &amp; Associate Chief Healthcare Information Officer, Emory Healthcare Network"},{"name":"Dr. Tariq Qureshi","aff":"Vice President Neurosciences + Heart &amp; Vascular, Grady Health System"},{"name":"Dr. Lakshmi Dasi","aff":"Founder &amp; CTO, DASI Simulations"}],"order":1}]},{"id":"s397","title":"Energy, EV, and Sustainable Technologies","track":"Sustainable Operations Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"1:45 PM","end":"3:15 PM","startMin":825,"room":"GRAND HALL EAST C","chairs":["Ms. Solmaz Abbaspour"],"abstracts":[{"id":"136-0128","title":"Electric vs Flex-Fuel Vehicles – Impact of Government Policies on Automaker’s Choice Between Green Technologies","content":"Addressing the automaker’s dilemma between EV and FFV (or Hybrid), we discuss how current endowment level, CV’s resale value, and fuel cost-saving potentials moderate the effect of government policies on automaker’s decisions. We also study the environmental implications and how the choices evolve when there is an out-of-factory modification service.","presenter":"Mr. Satyajit Roy","authors":[{"name":"Mr. Satyajit Roy","aff":"Student, Indian Institute of Management Bangalore"},{"name":"Prof. Sreelata Jonnalagedda","aff":"Associate Professor, Indian Institute of Management Bangalore"},{"name":"Prof. Haritha Saranga","aff":"Professor, Indian Institute of Management Bangalore"}],"order":1},{"id":"136-1698","title":"Joint Optimization of Battery Inventory and Service Quotation in Electric Vehicle Battery-as-a-Service Networks","content":"We study an inventory system-based battery swapping network for electric vehicles, where battery swapping stations provide waiting time quotations to customers who then choose stations or leave based on these quotes. We optimize the network performance by jointly determining battery inventory levels and quotation strategies.","presenter":"Mr. Ruihan Zeng","authors":[{"name":"Dr. Shi Chen","aff":"Associate Professor, Michael G. Foster School of Business"},{"name":"Prof. Kamran Moinzadeh","aff":"Professor, University of Washington"},{"name":"Mr. Ruihan Zeng","aff":"Student, University of Washington"}],"order":3},{"id":"136-1750","title":"Optimal Megawatt Charging Station Investment and Design: Mitigating Peak Demand","content":"A megawatt charging (MWC) station design is proposed for heavy-duty EV freight trucks. To overcome challenges in MWC, such as grid integration and demand charges, we utilize on-site batteries and solar panels. Via min-cost network flow formulation, we analyze the power allocation and investment decisions and their implications.","presenter":"Mr. Ridvan Aksu","authors":[{"name":"Mr. Ridvan Aksu","aff":"Student, University of Alabama Tuscaloosa"},{"name":"Dr. Mesut Yavuz","aff":"Associate Professor, University of Alabama Tuscaloosa"}],"order":5},{"id":"136-1205","title":"Who Drive Electric Vehicles in Alabama?","content":"We present a zip code-level dataset from Alabama relating electric vehicle (EV) adoption to various social, economical, technological and political factors. We also compare Alabama to other states in the nation, and highlight the challenges faced in different stages of EV adoption.","presenter":"Dr. Mesut Yavuz","authors":[{"name":"Dr. Mesut Yavuz","aff":"Associate Professor, University of Alabama Tuscaloosa"}],"order":7},{"id":"136-1094","title":"Equitable Supply-Demand Balancing: Tailoring Equitable Incentives for Demand Response Programs in Power Grids","content":"Demand response programs shift electricity use from peak to off-peak times using incentives. We explore equitable policies that balance efficiency and fairness across demographic groups. Our findings aim to guide utilities in designing strategies that enhance sustainability and equity, ensuring diverse customer participation in a balanced energy management system.","presenter":"Ms. Solmaz Abbaspour","authors":[{"name":"Ms. Solmaz Abbaspour","aff":"Student, Isenberg School of Management"},{"name":"Dr. Senay Solak","aff":"Professor, University of Massachusetts Amherst"}],"order":8}]},{"id":"s10","title":"POM and Community","track":"POM and Community","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"EMBASSY F","chairs":["Mr. Abhinav Shubham"],"abstracts":[{"id":"136-0034","title":"Racial and Gender Biases in Customer Satisfaction Surveys: Evidence from a Restaurant Chain","content":"We study racial and gender biases in customer satisfaction surveys using 1.5 million transactions and 260 thousand customer surveys from a casual-dining restaurant chain in the US. We find that customer ratings are biased against racial minority and female servers. We explore the mechanisms of discrimination and propose mitigation strategies.","presenter":"Mr. Masoud Kamalahmadi","authors":[{"name":"Mr. Masoud Kamalahmadi","aff":"Assistant Professor, Miami Herbert Busienss School"},{"name":"Dr. Qiuping Yu","aff":"Associate Professor, Georgetown University"},{"name":"Prof. Yong-Pin Zhou","aff":"Professor, University of Washington"}],"order":1},{"id":"136-1704","title":"Buying Cheap: Brand Switching During Economic Distress and Its Disparate Impact on Consumers","content":"Improving the surplus of low-income consumers during economic distress is of primary concern for many governments. This paper uses an economic model to investigate consumers' brand switching during economic distress and highlights its disparate impact on low-income consumers.","presenter":"Prof. Somya Singhvi","authors":[{"name":"Prof. Divya Singhvi","aff":"Assistant Professor, New York University"},{"name":"Mr. Shantanu Dutta","aff":"Professor, University of Southern California"},{"name":"Prof. Somya Singhvi","aff":"Assistant Professor, University of Southern California"}],"order":2},{"id":"136-1919","title":"Circular Solutions: Glass Bottle Reusing, Policy Impacts, and Environmental Outcomes","content":"Glass containers are often perceived as environmentally beneficial, but they are only greener when properly reused and recycled. We study a milk manufacturer’s joint packaging, pricing, and sustainability promotion strategies under a deposit-refund framework. We investigate the influence of legislation and identify conditions where stakeholder objectives align with environmental goals.","presenter":"Dr. Neda Mirzaeian","authors":[{"name":"Dr. Neda Mirzaeian","aff":"Assistant Professor, University of Texas at Dallas"},{"name":"Prof. Savannah Tang","aff":"Assistant Professor, SMU Cox School of Business"}],"order":3}]},{"id":"s35","title":"Humanitarian Operations and SDGs","track":"Humanitarian Operations and Crisis Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"GRAND HALL EAST B","chairs":["Prof. Adriana Leiras"],"abstracts":[{"id":"136-0531","title":"AI for social good: A paradox theory perspective","content":"This study explores the tensions among organizational and technical elements in shaping AI, and how organizations manage these tensions to create social impact. Specifically, we use a paradox lens to investigate tensions among learning, belonging, organizing, and performing dimensions that influence AI and how it impacts social good","presenter":"Prof. Nezih Altay","authors":[{"name":"Dr. Renee Pratt","aff":"Post Doc/Researcher, ."},{"name":"Prof. Jack Crumbly","aff":"Assistant Professor, Tuskegee University"},{"name":"Prof. Raktim Pal","aff":"Professor, James Madison University"},{"name":"Prof. Nezih Altay","aff":"Professor, Depaul University"}],"order":1},{"id":"136-1026","title":"From Setback to Breakthroughs:Transforming Financial Investment Perspectives for Disaster Risk Reduction and Management in Brazil","content":"The increasing disaster impacts in Brazil, such as floods and landslides, demand strategic management. This study analyzes pre- and post-disaster investments, showing that prioritizing preparedness significantly reduces deaths and affected populations. A system dynamics approach offers insights to policymakers to enhance disaster management, minimize socioeconomic impacts, and build resilience.","presenter":"Prof. Adriana Leiras","authors":[{"name":"Ms. Maria Angélica Gomes da Silva","aff":"Student, Pontifícia Universidade Católica do Rio de Janeiro - PUC-Rio"},{"name":"Dr. Luiza Cunha","aff":"Post Doc/Researcher, Universidade de São Paulo"},{"name":"Prof. Adriana Leiras","aff":"Associate Professor, Pontifícia Universidade Católica do Rio de Janeiro - PUC-Rio"}],"order":2},{"id":"136-1834","title":"Local humanitarian procurement for market resilience: a case study in Sustainable Development Goal 9","content":"Humanitarian operations are instrumental to achieving the sustainable development goals (SDGs). Using multi-method case studies of UN projects, this paper evaluates the role humanitarian procurement has in fostering new resilient industry, innovation and infrastructure (SDG 9), and find that leveraging humanitarian procurement can stimulate new service markets in low-resource settings","presenter":"Dr. Diego Vega","authors":[{"name":"Ms. Claire Travers","aff":"Student, Hanken School of Economics"},{"name":"Dr. Diego Vega","aff":"Associate Professor, HUMLOG Institute"}],"order":3},{"id":"136-1440","title":"Understating public policies considering the relationship between SDGs, Climate Change and Humanitarian Operations","content":"This study identifies appropriate public policies to achieve the Sustainable Development Goals (SDGs), minimize Climate Change (CC), and enhancing Humanitarian Operations (HOs) considering a systems thinking approach. Through a literature review, the preliminary findings highlight that public policies must be adapted, considering economic, social, and environmental factors.","presenter":"Prof. Adriana Leiras","authors":[{"name":"Dr. Raissa Bravo","aff":"Post Doc/Researcher, PUC Rio"},{"name":"Dr. Brenda Cardoso","aff":"Professor, Para State University"},{"name":"Dr. Luiza Cunha","aff":"Post Doc/Researcher, Universidade de São Paulo"},{"name":"Prof. Adriana Leiras","aff":"Associate Professor, Pontifícia Universidade Católica do Rio de Janeiro - PUC-Rio"}],"order":4}]},{"id":"s56","title":"Emerging Topics in Sustainable OM","track":"Sustainable Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"GRAND HALL EAST C","chairs":["Dr. Junhao Vincent Yu","Prof. Tim Kraft"],"abstracts":[{"id":"136-0506","title":"Buyer Management of a Supplier’s Social Responsibility Risk: Prevention, Detection, and Remediation","content":"We study how retailers can proactively manage their suppliers' responsibility risk. We focus on a retailer's risk management strategy and consider three tactics the retailer can deploy—prevention, detection, and remediation—and study how combining the three can help the retailer achieve optimal results.","presenter":"Dr. Junhao Vincent Yu","authors":[{"name":"Dr. Junhao Vincent Yu","aff":"Assistant Professor, Miami University"},{"name":"Prof. Tim Kraft","aff":"Associate Professor, North Carolina State University"}],"order":1},{"id":"136-0647","title":"Impact of Supply Chain Structures on Child Labor Violations","content":"This study examines child labor violations in US supply chains. Our analysis reveals that extended supply chain tiers and supplier network complexity significantly increase child labor violation risks, particularly in sectors with high subcontracting. Results emphasize the need for enhanced sourcing and enforcement strategies.","presenter":"Mr. Fred Bao","authors":[{"name":"Prof. Ashish Kabra","aff":"Assistant Professor, University of Maryland"},{"name":"Mr. Fred Bao","aff":"Student, University of Maryland - College Park"}],"order":2},{"id":"136-0672","title":"Combating excessive overtime in global supply chains","content":"Suppliers operating in developing economies may force their workforce to work excessive overtime, resulting in potentially significant damage to the brand image of multinational enterprises. In this paper, we develop a game-theoretic model of a dyadic supply chain to analyze a buyer’s operational strategies to combat the excessive overtime issue.","presenter":"Dr. Chuanya Jiao","authors":[{"name":"Dr. Chuanya Jiao","aff":"Assistant Professor, University of Science and Technology of China"},{"name":"Dr. Anyan Qi","aff":"Associate Professor, University of Texas Dallas"},{"name":"Dr. Jiayu Chen","aff":"Assistant Professor, University of Oklahoma"}],"order":3},{"id":"136-0918","title":"Watt’s Next: Navigating the Surge in Electric Vehicle Adoption and its Implications for Grid Operations","content":"With the surge in the number of Electric Vehicles (EVs), utilities can manage the increased load and demand variations using grid-scale batteries, and through managed charging of EVs. We establish optimal grid operations and provide policy guidance on EV adoption targets and investments in energy infrastructure for the future.","presenter":"Dr. Karthik Murali","authors":[{"name":"Dr. Karthik Murali","aff":"Associate Professor, Oregon State University"},{"name":"Dr. Siddharth Prakash Singh","aff":"Assistant Professor, UCL School of Management"},{"name":"Prof. Owen Wu","aff":"Associate Professor, Indiana University"},{"name":"Dr. Mesut Yavuz","aff":"Associate Professor, University of Alabama Tuscaloosa"}],"order":4}]},{"id":"s68","title":"Behavioral Biases and Power Dynamics in Procurement and Supply Chain Decision-Making","track":"Procurement and Supplier Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"LENOX","chairs":["Dr. Han Oh"],"abstracts":[{"id":"136-0126","title":"Newsvendor double-counting bias in automatic grocery retail replenishment","content":"This paper empirically shows store managers of a supermarket chain are susceptible to a novel bias when increasing automatic store replenishment orders: newsvendor double-counting. This bias suggests that decision-makers may apply the newsvendor logic mentally when they encounter an algorithmic order proposal as if this proposal is a demand forecast.","presenter":"Dr. Bengu Ozdemir","authors":[{"name":"Dr. Bengu Ozdemir","aff":"Assistant Professor, University of Wisconsin-Whitewater"},{"name":"Dr. Antti Tenhiala","aff":"Associate Professor, IE BUSINESS SCHOOL"}],"order":1},{"id":"136-0950","title":"Late Payments, Higher Prices? An Experimental Investigation of Competitive Procurement","content":"Late payments are common across supply chains and a key challenge for businesses. We contribute by documenting important features about their likelihood and severity, formulating and solving a theoretical model grounded in these features which suggests a policy tool to reduce late payments and validating the model in an experiment.","presenter":"Dr. Kyle Hyndman","authors":[{"name":"Dr. Kyle Hyndman","aff":"Professor, University of Texas Dallas"},{"name":"Dr. Matthew Walker","aff":"Lecturer, Newcastle University Business School"}],"order":2},{"id":"136-1400","title":"Behavioral Aspects In The Design Of Procurement Auctions: The Capacity To Bid","content":"We conduct an empirical investigation of large-scale tenders of pharmaceutical products performed by German health insurance companies to study which tender designs influence the number of participants. We focus on organizational biases affecting entire organizations and how a buyer should consider the bidder's \"capacity to bid\".","presenter":"Prof. Ivan Lugovoi","authors":[{"name":"Prof. Ivan Lugovoi","aff":"Assistant Professor, Kühne Logistics University"},{"name":"Prof. Jurgen Mihm","aff":"Professor, INSEAD"}],"order":3},{"id":"136-0473","title":"The Role of Buyer Power and Buyer Needs in Allocating Limited Product Supply","content":"This research using experiment methodology seeks to understand the impact of buyer power and buyer needs when dealing with limited product availability. Using the organizational justice theory lens, we explore how managers balance the often-competing principles of equity, equality, and need when making allocation decisions.\r\n","presenter":"Dr. Zach Zacharia","authors":[{"name":"Dr. Saif Mir","aff":"Assistant Professor, Lehigh University"},{"name":"Dr. David Rea","aff":"Assistant Professor, Lehigh University"},{"name":"Dr. Zach Zacharia","aff":"Associate Professor, Lehigh University"}],"order":4}]},{"id":"s82","title":"PITM Best Student Paper Competition","track":"Product Innovation and Technology Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"COURTLAND","chairs":["Mrs. Sidika Candogan","Prof. Konstantinos Stouras"],"abstracts":[{"id":"136-2082","title":"How Success Affects Repeat Initiative Taking: Investigating Inter-Idea Times for Employee-Driven Idea Generation","content":"We examine how prior success influences sustained idea generation. Analyzing 5,206 ideas from 1,971 employees, we find that success leads to repeat initiative-taking but also increases inter-idea times. Innovators delay new ideas to justify their identity without improving quality, posing risks for organizations reliant on high-quality contributions.","presenter":"Mr. Felix Mosner","authors":[{"name":"Mr. Felix Mosner","aff":"Student, University of Cologne"},{"name":"Prof. Fabian Sting","aff":"Professor, University of Cologne"},{"name":"Dr. Dirk Deichmann","aff":"Professor, Erasmus University Rotterdam"}],"order":1},{"id":"136-2083","title":"New Technology Adoption and Peer Effects among Service Workers: Evidence from Aadhaar Enabled Payment System","content":"Using detailed daily-level transaction data of 10 million Aadhaar Enabled Payment System transactions, we examine whether agents with peers adapt better to technology as compared to agents without peer. We also examine how peer effects work differently based on peer experience and level of competition.","presenter":"Ms. Deepanshi Bhardwaj","authors":[{"name":"Ms. Deepanshi Bhardwaj","aff":"Student, University College London"},{"name":"Prof. Bilal Gokpinar","aff":"Professor, University College London"},{"name":"Dr. Ashwini Chhatre","aff":"Professor, Indian School of Business"}],"order":2},{"id":"136-2084","title":"Solver Capacity Utilization and Allocation on Crowdsourcing Platforms: An Experimental Study","content":"We employ a game-theoretic model combined with laboratory experiments to examine how solvers allocate and utilize their capacity across multiple contests as a crowdsourcing platform expands. Our experimental findings reveal that platform growth does not inherently diminish the profit per contest.","presenter":"Mr. RAMAZAN KIZILYILDIRIM","authors":[{"name":"Mr. RAMAZAN KIZILYILDIRIM","aff":"Student, University College London"},{"name":"Dr. C. Gizem Korpeoglu","aff":"Assistant Professor, Eindhoven University of Technology"},{"name":"Dr. Ersin Korpeoglu","aff":"Associate Professor, University College London"},{"name":"Dr. Mirko Kremer","aff":"Professor, Frankfurt School of Finance &amp; Management"}],"order":3},{"id":"136-2089","title":"Designing Data Science Contests: The Role of Training vs Test Splits - BSPC","content":"We present a theory of data science contests that focuses on how contest data split influences the participant behavior. Previous research suggests a balanced data split to enhance model consistency. We show that this middle-ground approach can invite sub-optimal submissions, preventing the host from accurately identifying the best model. (BSPC)","presenter":"Ms. Ping-Chieh Huang","authors":[{"name":"Ms. Ping-Chieh Huang","aff":"Student, University of California, San Diego"},{"name":"Prof. Zhe Zhang","aff":"Assistant Professor, University of California San Diego"},{"name":"Prof. Sanjiv Erat","aff":"Associate Professor, University of California, San Diego"}],"order":4},{"id":"136-2090","title":"The Role of Contextual Information in Customer Reviews: A Field Experiment (BSPC)","content":"We conducted a randomized field experiment in partnership with Singapore's largest online mental health platform. We find that, revealing contextual information about the review writer alongside each review can increase the conversion rate by 42%, and increase the average number of bookings per customer by 87%. (BSPC)","presenter":"Mr. Guang Cheng","authors":[{"name":"Mr. Guang Cheng","aff":"Student, National University of Singapore"},{"name":"Mrs. Sidika Candogan","aff":"Assistant Professor, NUS Business School"},{"name":"Dr. Joel Goh","aff":"Associate Professor, NUS Business School"},{"name":"Prof. Bilal Gokpinar","aff":"Professor, University College London"}],"order":5}]},{"id":"s87","title":"Crowdfunding","track":"Information Systems and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"EMBASSY E","chairs":["Ning Luo","Prof. Yeongin Kim"],"abstracts":[{"id":"136-0922","title":"Imitating the Extremely Successful or the Moderately Successful? The Impact of Imitation on Crowdfunding Performance","content":"This paper applies imitative learning theory to analyze 97,368 Kickstarter projects, exploring how imitating influences funding performance in crowdfunding. It finds that the effects of imitating extremely successful and moderately successful projects are opposite and moderated by project intervals and creators’ experience, contributing to crowdfunding research and the operation practice.","presenter":"Ms. Jiayue Wang","authors":[{"name":"Ms. Jiayue Wang","aff":"Student, Renmin University of China"},{"name":"Mr. Changqing Zhuo","aff":"Student, Renmin University of China"},{"name":"Dr. Shouwang Lu","aff":"Assistant Professor, Beijing Jiaotong University"},{"name":"Prof. Kanliang Wang","aff":"Professor, Renmin University of China"}],"order":1},{"id":"136-1042","title":"Money Changes Everything? Corporate Contributions and Volunteer Engagement in an Online Crowdsourcing Platform","content":"We examines the impact of corporate participation on volunteer contributions in OpenStreetMap. Analyzing data from Brazil (2017–2022), we find corporate involvement significantly increases volunteer activity. Corporations’ broad contributions inspire volunteers to focus on underserved areas, enhancing the platform’s quality and scope, addressing debates on corporate-volunteer dynamics.","presenter":"Mr. Yuqing Cheng","authors":[{"name":"Mr. Yuqing Cheng","aff":"Student, Arizona State University"},{"name":"Prof. Abhishek Nagaraj","aff":"Associate Professor, UCBerkeley"},{"name":"Dr. Eunae Yoo","aff":"Assistant Professor, Indiana University Bloomington"},{"name":"Prof. Elliot Rabinovich","aff":"Professor, Arizona State University Tempe"}],"order":2},{"id":"136-0943","title":"Tit for Tat: Costly and Costless Feedback and Solver Participation in Creative Crowdsourcing Contests","content":"This study uses a randomized field experiment to find that solvers exhibit reciprocal behavior in crowdsourcing contests. Namely, costless positive feedback (textual) increases the number of solutions, while costly feedback (in-contest tipping) increases submission quality. Moreover, these effects are robust to alternative specifications and potential outliers.","presenter":"Dr. Swanand Deodhar","authors":[{"name":"Dr. Swanand Deodhar","aff":"Associate Professor, Indian Institute of Management Ahmedabad"},{"name":"Dr. Samrat Gupta","aff":"Associate Professor, Indian Institute of Management Ahmedabad"},{"name":"Ms. Romika Dhingra","aff":"Post Doc/Researcher, Indian Institute of Management Ahmedabad"},{"name":"Dr. Mani Subramani","aff":"Associate Professor, University of Minnesota"}],"order":3},{"id":"136-1769","title":"Political Campaigns in the Digital Age: The Impact of Social Media Advertising on Political Contributions.","content":"We investigate the influence of social media advertising on individual contributions in U.S. Senate elections. Our findings reveal that social media ads boost donations, particularly when targeting out-of-state donors. The ads' fundraising effectiveness is further moderated by election dynamics, highlighting the strategic importance of social media in political campaign fundraising.","presenter":"Mr. Youshin Kwak","authors":[{"name":"Mr. Youshin Kwak","aff":"Student, Goizueta Business School"}],"order":4}]},{"id":"s90","title":"Technology and Operations","track":"Behavioral Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"EMBASSY D","chairs":["Ms. Bing Bai"],"abstracts":[{"id":"136-0114","title":"Residential Energy Technology","content":"We study how changes in residential energy technology, like solar power, batteries, heat pumps, and EVs change electricity consumption of households.","presenter":"Prof. Christian Kaps","authors":[{"name":"Prof. Christian Kaps","aff":"Assistant Professor, Harvard Business School"}],"order":1},{"id":"136-1019","title":"Uncovering Consequences of Virtual Nurse Admission and Discharge Decisions","content":"This study investigates the impact of virtual nursing services on hospital admission and discharge processes, focusing on their effects on patient outcomes. Our findings highlight the need for healthcare practitioners to carefully balance inpatient care efficiency with quality when integrating virtual nurse services into their operations.","presenter":"Ms. Blair Liu","authors":[{"name":"Ms. Blair Liu","aff":"Student, University of North Carolina Chapel Hill"},{"name":"Prof. Yuqian Xu","aff":"Associate Professor, UNC Chapel Hill"},{"name":"Prof. Bradley Staats","aff":"Professor, University of North Carolina Chapel Hill"}],"order":2},{"id":"136-1274","title":"Timing Matters: Crowd-sourcing Workers in On-demand Freight Matching Platforms","content":"We study a freight-matching platforms seeking carriers to fulfill requests from customers for a future pick-up date. We find that both the sourcing cost of drivers and the matching probability are associated with the request lead time.","presenter":"Mr. Jingxuan Geng","authors":[{"name":"Mr. Jingxuan Geng","aff":"Student, Temple University"},{"name":"Prof. Guangwen Kong","aff":"Associate Professor, Temple University"},{"name":"Prof. Qiuping Yu","aff":"Associate Professor, Georgetown University"}],"order":3}]},{"id":"s116","title":"Managing Service Platforms, Waiting, and Virtual Queues","track":"Service Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"EMBASSY C","chairs":["Prof. Craig Froehle","Adam Arveson"],"abstracts":[{"id":"136-0118","title":"Order Ahead for Pickup: Promise or Peril?","content":"Mobile technologies enable customers to order ahead at quick-service restaurants, parallelizing travel and order processing. However, our model shows this can paradoxically lower throughput compared to onsite ordering. Allowing cancellations or setting rejection thresholds may restore efficiency, while a combined strategy optimizes the management of order-ahead services for best results.","presenter":"Ms. Ke Sun","authors":[{"name":"Ms. Ke Sun","aff":"Post Doc/Researcher, McGill University"},{"name":"Dr. Yunan Liu","aff":"Associate Professor, North Carolina State University"},{"name":"Prof. Luyi Yang","aff":"Assistant Professor, University of California Berkeley"}],"order":1},{"id":"136-0145","title":"How a Wait's Presentation Affects Its Perceived Cost","content":"As virtual waits replace physical queues, managers today must decide how to communicate wait characteristics to customers. We experimentally demonstrate that this decision can substantially influence customer behavior. Clock-framed waits, like Uber, convey information accurately but are unappealing. Conversely, people systematically underestimate the duration and disutility of queues.","presenter":"Dr. Blair Flicker","authors":[{"name":"Dr. Blair Flicker","aff":"Assistant Professor, University of South Carolina"},{"name":"Dr. Charlie Hannigan","aff":"Assistant Professor, University of Southern California"}],"order":2},{"id":"136-0471","title":"No Call, No Show: Impact of No Show on Customer Retention in On-Demand Services","content":"With the surge in online-to-offline services, platforms face growing concerns about service provider no-shows, such as a handyman hired on TaskRabbit not showing up. Analyzing data from a European cleaning platform, we empirically assess how service provider no-shows impact customer.","presenter":"Prof. Nil Karacaoglu","authors":[{"name":"Prof. Nil Karacaoglu","aff":"Assistant Professor, The Ohio State University"},{"name":"Ms. Simin Li","aff":"Assistant Professor, Tulane University"}],"order":3},{"id":"136-0799","title":"Understanding Queue Abandonment: The Role of Wait-Time Communication and Distraction","content":"In queues with highly variable wait times, such as in an emergency department, managers are tasked with designing queues that encourage customers to stay. Through a controlled experiment, we examine how customers respond to varied levels of information and distractions while they wait.","presenter":"Mr. Adam Arveson","authors":[{"name":"Mr. Adam Arveson","aff":"Student, University of Cincinnati"},{"name":"Dr. Kanix Wang","aff":"Assistant Professor, University of Cincinnati"},{"name":"Dr. Yinghao Zhang","aff":"Associate Professor, University of Cincinnati"},{"name":"Prof. Craig Froehle","aff":"Professor, University of Cincinnati"}],"order":4}]},{"id":"s119","title":"Operational Excellence in Healthcare","track":"Operational Excellence","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"BAKER","chairs":["Dr. Deepa Goradia"],"abstracts":[{"id":"136-0436","title":"Impact of Telehealth on Low Virtualizable Disease","content":"This study examines the effect of telehealth at different points in the care continuum on healthcare utilization. We focus on low virtualizable diseases such as Acute Myocardial Infarctions (AMI). Using panel data on AMI-related healthcare utilization, we study the direct and interaction effects of telehealth “types\" on hospital performance measures.","presenter":"Prof. Sidhartha Das","authors":[{"name":"Dr. Deepika Gopukumar","aff":"Assistant Professor, Saint Louis University"},{"name":"Prof. Nirup Menon","aff":"Professor, George Mason University"},{"name":"Prof. Sidhartha Das","aff":"Professor, George Mason University"},{"name":"Prof. Amitava Dutta","aff":"Professor, George Mason University"}],"order":1},{"id":"136-0107","title":"Hospital Diversity Management Programs: Exploratory Analysis of Antecedents and Consequences","content":"This study explores how hospital diversity management programs (DMPs) affect healthcare delivery and operations, considering the interplay between staff diversity, patient demographics, and hospital management practices.","presenter":"Dr. Aaron Bonnett","authors":[{"name":"Dr. Aaron Bonnett","aff":"Assistant Professor, Sam Houston State University"},{"name":"Prof. Gregory Heim","aff":"Professor, Texas A&amp;M University College Station"},{"name":"Ms. Pelin Kesrit","aff":"Student, Texas A&amp;M University"},{"name":"Dr. Seung Jun Lee","aff":"Associate Professor, Chung-Ang University"}],"order":2},{"id":"136-0478","title":"Utilizing Specialists and Nurse Practitioners on Improving Accountable Care Organizations’ Efficiency: An Optimization Framework","content":"Accountable Care Organizations (ACOs) were established to provide high-quality care while managing costs. However, while some ACOs have successfully achieved these goals, many have faced challenges, particularly with a shortage of primary care physicians (PCPs). We propose a data-driven optimization framework to maximize ACO efficiency.","presenter":"Dr. Mayukh Majumdar","authors":[{"name":"Dr. Mayukh Majumdar","aff":"Assistant Professor, University of San Diego"},{"name":"Dr. Anupam Agrawal","aff":"Associate Professor, Texas A&amp;M University College Station"},{"name":"Prof. Arun Sen","aff":"Professor, Texas A&amp;M University College Station"},{"name":"Prof. Chelliah Sriskandarajah","aff":"Professor, Texas A&amp;M University College Station"}],"order":3}]},{"id":"s129","title":"Aligning digital with OPEX","track":"Operational Excellence","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"AUBURN","chairs":["Dr. Matteo Bernasconi"],"abstracts":[{"id":"136-0538","title":"Riding the bell curve of lean and digitalization program alignment – A social capital perspective","content":"Based on a multiple case study design, this paper found that lean and digitalization program manager’s alignment rides a bell-curved challenge journey established in three distinct stages. Social capital theory adds a nuanced understanding towards alignment challenges and strategies adding to the recent debate about integrating lean and digitalization.","presenter":"Prof. Thomas Friedli","authors":[{"name":"Mr. Lorenzo Pirrone","aff":"Student, University of St. Gallen"},{"name":"Dr. Matteo Bernasconi","aff":"Student, Universitat St. Gallen"},{"name":"Dr. Mark Grothkopp","aff":"Post Doc/Researcher, Universitat St. Gallen"},{"name":"Prof. Thomas Friedli","aff":"Professor, University of St. Gallen"}],"order":1},{"id":"136-0539","title":"It takes two to tango: The maturity-relationship of lean and digitalization programs","content":"This paper applied a mixed-method approach investigating the maturity-relationship of lean and digitalization programs. Necessary condition analysis and a subsequent qualitative coding study revealed that an advanced lean program presents the prerequisite for higher digitalization program maturity. Maturity dimensions within the proposed maturity model evolve alongside progressive and cumulative patterns.","presenter":"Prof. Thomas Friedli","authors":[{"name":"Mr. Lorenzo Pirrone","aff":"Student, University of St. Gallen"},{"name":"Prof. Thomas Friedli","aff":"Professor, University of St. Gallen"}],"order":2},{"id":"136-0868","title":"When drones meet warehouses: inventory automation driving operational excellence","content":"Drones can be employed for quasi-real-time monitoring of inventories. This generates increased accuracy, leading to higher productivity and enabling operational excellence. We develop a sustainability model (economic, environmental, and social) to assess these benefits based on data from more than 100 warehouses employing autonomous flying drones for inventory automation.","presenter":"Dr. Leonardo Leoni","authors":[{"name":"Dr. Leonardo Leoni","aff":"Post Doc/Researcher, University of Florence"},{"name":"Mr. Saverio Ferraro","aff":"Student, University of Florence"},{"name":"Prof. Filippo De Carlo","aff":"Professor, University of Florence"}],"order":3},{"id":"136-1537","title":"Transforming Process Maps into Predictive Models for Continuous Improvement","content":"This session introduces attendees to discrete event simulation, showcasing its application identifying bottlenecks, evaluating scenarios, and improving workflows. Participants will evolve process maps into predictive models to rapidly design, test, and validate improvements. This hands-on approach builds confidence in process changes before real-world implementation.","presenter":"Mrs. Peg Pennington","authors":[{"name":"Mrs. Peg Pennington","aff":"President, MoreSteam"},{"name":"Mrs. Lindsay Van Dyne","aff":"VP of Marketing, MoreSteam"}],"order":4}]},{"id":"s136","title":"Innovative Retail Strategies: Pricing, Placement, and Customization","track":"Retail Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"FAIRLIE","chairs":["Dr. Paolo Letizia","Dr. Haileab Hilafu"],"abstracts":[{"id":"136-0392","title":"A sustainable retailer's optimal pricing decision under competition","content":"We consider a market with two existing retailers selling two categories of products--packaged goods and fresh products--to consumers with different willingness to pay and utility for sustainability. We model the entry of a sustainable retailer who sells packaged goods into this market and analyze her optimal pricing decision.","presenter":"Prof. Eda Kemahlioglu-Ziya","authors":[{"name":"Prof. H. Sebastian Heese","aff":"Professor, North Carolina State University"},{"name":"Prof. Eda Kemahlioglu-Ziya","aff":"Associate Professor, North Carolina State"},{"name":"Dr. Olga Perdikaki","aff":"Associate Professor, University of South Carolina"}],"order":1},{"id":"136-0605","title":"The Impact of Planogram Design and Display Fees on Retail Category Management","content":"We study a retailer’s category management strategy in the presence of planogram design incentives and display fees. We show that prime shelf location in the retailer's store can be an effective management lever to control the competition dynamics among manufacturers and may generate value for all firms.","presenter":"Prof. Alper Nakkas","authors":[{"name":"Prof. Yasin Alan","aff":"Associate Professor, Vanderbilt University"},{"name":"Prof. Mumin Kurtulus","aff":"Associate Professor, Vanderbilt University"},{"name":"Prof. Alper Nakkas","aff":"Assistant Professor, University of Texas Arlington"}],"order":2},{"id":"136-1007","title":"Rethinking the Eye-Level Effect: A Field Experiment in Convenience Stores","content":"Retailers often place products on eye-level shelves to increase sales, but it's unclear how reorganizing other shelves impacts this strategy. This study uses a field experiment to explore whether different shelf arrangements, all designed to position a product at eye level, affect the effectiveness of this placement.","presenter":"Prof. Necati Ertekin","authors":[{"name":"Ms. Zahra Jalali","aff":"Student, McGill University"},{"name":"Prof. Maxime Cohen","aff":"Professor, McGill University"},{"name":"Prof. Necati Ertekin","aff":"Associate Professor, University of Minnesota"},{"name":"Prof. Mehmet Gumus","aff":"Professor, McGill University"}],"order":3},{"id":"136-1080","title":"Does Mass Customization Protect Firms Against Product Returns?","content":"Mass customization enables firms to cater to consumer segments that prioritize product variety and individuality. However, it also exposes businesses to significant costs when these tailored products are returned. This study examines the impact of customization and personalization on product return rates through empirical analysis.","presenter":"Dr. Haileab Hilafu","authors":[{"name":"Dr. Christoph Fuchs","aff":"Professor, Universität Wien, Austria"},{"name":"Dr. Paolo Letizia","aff":"Associate Professor, University of Tennessee"},{"name":"Dr. Haileab Hilafu","aff":"Associate Professor, University of Tennessee Knoxville"},{"name":"Dr. Anupam Agrawal","aff":"Associate Professor, Texas A&amp;M University College Station"}],"order":4}]},{"id":"s144","title":"Disruptive Technologies and Strategic Decision-Making in Business and Urban Systems","track":"Disruptive Technologies and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"KENNESAW","chairs":["Dr. Duc Vu"],"abstracts":[{"id":"136-0168","title":"Transforming Urban Operations: The Role of Disruptive Technologies in Smart City Management","content":"This paper investigates how disruptive technologies—such as IoT and blockchain—are reshaping operations management within smart cities. By enhancing urban infrastructure, enabling real-time data insights, and improving public service delivery, these innovations are driving cities toward sustainability and efficiency. Current academic research is reviewed to highlight emerging trends and best practices.","presenter":"Dr. Lucy Rackliff","authors":[{"name":"Dr. Lucy Rackliff","aff":"Senior Lecturer, Aston University, School of Engineering"},{"name":"Dr. Reem Hadeed","aff":"Lecturer, Aston University, School of Engineering"},{"name":"Prof. Manolya Kavakli-Thorne","aff":"Professor, Aston University Birmingham"}],"order":1},{"id":"136-0408","title":"Is Compatibility Always Better? Electric Vehicle Manufacturers’ Strategies with Fast Chargers","content":"We investigate the decision problem of competing electric vehicle (EV) manufacturers regarding the compatibility of their fast chargers with EVs, their pricing strategies, and how these decisions impact EV adoption. We develop a sequential game-theoretic model and show that mutual compatibility does not always lead to the highest EV adoption.","presenter":"Mr. Ranit Saha","authors":[{"name":"Mr. Ranit Saha","aff":"Student, Indian Institute of Management Calcutta"},{"name":"Prof. Sumanta Basu","aff":"Professor, Indian Institute of Management Calcutta"},{"name":"Prof. Balram Avittathur","aff":"Professor, Indian Institute of Management Calcutta"}],"order":2},{"id":"136-1177","title":"Truck vs Drone for Delivery Network","content":"Emerging technologies such as drone delivery offer unprecedented delivery speed and adaptable delivery lead times. Whereas, traditional delivery methods (e.g., trucks) have the advantage of reducing operational costs. We analyze the trade-offs of these two delivery modes and study which mode(s) should be offered by a retailer.","presenter":"Dr. Duc Vu","authors":[{"name":"Dr. Sandun Perera","aff":"Associate Professor, University of Nevada, Reno"},{"name":"Dr. Duc Vu","aff":"Assistant Professor, University of Michigan-Flint"}],"order":3},{"id":"136-1232","title":"How Does the Stock Market View Firms' AI-Related Initiatives?","content":"This research examines the financial impact of public announcements of U.S. firms related to generative AI and investigates how this impact varies based on firm characteristics. I also compare the impact with that of general information technology investment announcements.","presenter":"Dr. Junyoung Park","authors":[{"name":"Dr. Junyoung Park","aff":"Assistant Professor, Auburn University"}],"order":4}]},{"id":"s153","title":"From Data to Decisions: Advancing Healthcare with Analytics","track":"Healthcare Analytics","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"GRAND HALL EAST D","chairs":["Prof. Nan Liu","Dr. Miao Bai"],"abstracts":[{"id":"136-0087","title":"When Team Familiarity Backfires: Evidence from Cardiac Teams in the Emergency Room","content":"Using records of teamwork on percutaneous coronary intervention (PCI) procedures for emergency department (ED) patients in a cardiology hospital from 2014 to 2021, we estimated the U-shaped effects of team familiarity on the teamwork process and patient health outcomes. We demonstrate the robust results using various estimation models.","presenter":"Mr. Xiaohan Chen","authors":[{"name":"Mr. Xiaohan Chen","aff":"Student, Xiamen University"},{"name":"Dr. Yao Li","aff":"Assistant Professor, Southern University of Sci and Tech"},{"name":"Prof. Lauren Lu","aff":"Professor, Dartmouth College"},{"name":"Prof. Feng (Susan) Lu","aff":"Professor, Purdue University"},{"name":"Prof. Weifen Zhuang","aff":"Professor, Xiamen University"}],"order":1},{"id":"136-0487","title":"Helping the Captive Audience: Advance Notice of Diagnostic Service for Hospital Inpatients","content":"Inpatients are often treated as \"on-demand\" for hospital diagnostic service, and they are notified only when service capacity is available. This arrangement causes chaos and inefficiencies in operations. We propose \"advance notice\", an innovative scheduling paradigm that strikes a fine balance between the classic advance scheduling and allocation scheduling paradigms.","presenter":"Dr. Miao Bai","authors":[{"name":"Dr. Miao Bai","aff":"Assistant Professor, University of Connecticut"},{"name":"Prof. Nan Liu","aff":"Associate Professor, Boston College"},{"name":"Dr. Zheng Zhang","aff":"Assistant Professor, Zhejiang University"}],"order":2},{"id":"136-0708","title":"Disease Bundling or Specimen Bundling? Cost- and Capacity-Efficient Strategies for Multidisease Testing with Genetic Assays","content":"We develop the Pareto frontier for cost- and capacity-efficient testing designs for infectious disease screening, considering multiplexing (disease bundling), where one assay detects multiple diseases using one specimen; and pooling (specimen bundling), where specimens from multiple subjects\r\nare tested with one assay. We develop structural properties and managerial insights.","presenter":"Dr. Hussein El Hajj","authors":[{"name":"Dr. Douglas Bish","aff":"Professor, University of Alabama"},{"name":"Dr. Ebru Bish","aff":"Professor, The University of Alabama"},{"name":"Dr. Hussein El Hajj","aff":"Assistant Professor, Santa Clara University"}],"order":3},{"id":"136-0856","title":"Balancing Personalized Medicine and One-Size-Fits-All: Navigating Trade-Offs in Complexity, Efficiency, and Equity","content":"Personalized medicine improves outcomes and reduce health disparities by tailoring guidelines to individual characteristics but are often challenging to implement. We propose an explainable clustering method to decide the optimal intensity and configuration of population stratification, aiming to minimize health inequalities while ensuring the guidelines remain practical and implementable.","presenter":"Dr. Reza Skandari","authors":[{"name":"Dr. Reza Skandari","aff":"Assistant Professor, Imperial College London"},{"name":"Ms. Niloofar Zamani Foroushani","aff":"Student, Imperial College London"},{"name":"Ms. Narges Mohammadi","aff":"Student, Imperial College London"}],"order":4}]},{"id":"s164","title":"Transportation and Platform Operations","track":"POM-Economics Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"TECHWOOD","chairs":["Dr. Zenan Zhou","Dr. Lina Wang"],"abstracts":[{"id":"136-0978","title":"Is Machine Learning Truly Learning? An Operations Perspective on Campus Delivery Robots","content":"This study examines the operational effectiveness of machine learning in campus delivery robots. Using historical data, it evaluates AI’s ability to adapt over time and improve delivery performance. The research focuses on generating actionable insights to enhance delivery systems and advance the practical contributions of machine learning in real-world operations.","presenter":"Ms. Rang Gong","authors":[{"name":"Ms. Rang Gong","aff":"Student, Ohio State University"},{"name":"Dr. Xiang Wan","aff":"Associate Professor, Ohio State University"}],"order":1},{"id":"136-1078","title":"The Impact of Smart Mobility on Urban Crime: Evidence from Bike-Sharing","content":"This study examines the impact of bike-sharing on urban crime, highlighting its crime-reducing effects through micromobility, particularly in congested areas. Using Chicago bike-sharing and crime data, we find a crime-reducing effect and explore mechanisms and implications for urban safety across diverse neighborhood characteristics.","presenter":"Dr. Zenan Zhou","authors":[{"name":"Ms. Wen Ya Shen","aff":"Student, Arizona State University"},{"name":"Dr. Zenan Zhou","aff":"Assistant Professor, Arizona State University"},{"name":"Dr. Jiding Zhang","aff":"Assistant Professor, Arizona State University"},{"name":"Prof. Pei-yu Chen","aff":"Professor, Arizona State University"}],"order":2},{"id":"136-1490","title":"Modeling the Influence of Unpaid Effort in Delivery Agents’ Choices in Last-Mile Platforms","content":"Using a dynamic discrete choice model, we empirically analyze delivery agents' job selection decisions on last-mile platforms. Our results show that increased travel distance between jobs significantly reduces the likelihood of selecting a job, outweighing other factors such as payout amounts and delivery lead times.\r\n\r\n\r\n\r\n\r\n\r\n\r\n","presenter":"Dr. Lina Wang","authors":[{"name":"Dr. Lina Wang","aff":"Assistant Professor, The Pennsylvania State University"},{"name":"Prof. Stanley Lim","aff":"Assistant Professor, Michigan State University"},{"name":"Prof. Elliot Rabinovich","aff":"Professor, Arizona State University Tempe"}],"order":3},{"id":"136-1598","title":"Short-Term Vacation Rentals’ Spillover Effects on Local Business Foot Traffic","content":"This study examines the spillover impacts of short-term vacation rentals (STVRs) on local industries. By employing a stacked Difference-in-Differences methodology, it explores various moderating factors, including regional characteristics and property features. The research highlights hotel demand influences and event-driven variations on local economic dynamics.","presenter":"Dr. Zenan Zhou","authors":[{"name":"Dr. Zenan Zhou","aff":"Assistant Professor, Arizona State University"},{"name":"Prof. Elliot Rabinovich","aff":"Professor, Arizona State University Tempe"},{"name":"Prof. Karen Donohue","aff":"Professor, Arizona State University"}],"order":4}]},{"id":"s173","title":"Making the Right Call: Managing Resources, Ethics, and Fair Distribution","track":"Operations and Society","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"SPRING","chairs":["Dr. Soh Hyun Chu","Dr. Telesilla Kotsi"],"abstracts":[{"id":"136-0472","title":"Proactive Staging of Resources for Migratory Crises","content":"Migration crises are complex emergencies featured by evolving uncertainty in human needs. We use stochastic programming to position border resources, considering economic costs and deprivation from unmet needs. Our study strengthens strategic and operational decision-making at international borders through the insights derived from previously unexplored interplay between location, (re-)distribution, time.","presenter":"Ms. Fatemeh Farajzadeh","authors":[{"name":"Ms. Fatemeh Farajzadeh","aff":"Student, Worcester Polytechnic Institute"},{"name":"Ms. Shannon Song","aff":"Student, Worcester Polytechnic Institute"},{"name":"Dr. Luke Caddell","aff":"General Surgery Resident, Stanford University"},{"name":"Sarah Stanlick","aff":""},{"name":"Dr. Fabricio Murai","aff":"Associate Professor, Worcester Polytechnic Institute"},{"name":"Dr. Andrew Trapp","aff":"Associate Professor, Worcester Polytechnic Institute"}],"order":1},{"id":"136-0608","title":"The effect of managerial influence on supplier selection decisions","content":"Supplier selection, a key aspect of sourcing strategies, is expected to be an objective process. This study examines how buyers allow management to influence their selection decisions, even if it leads to unethical behavior. The aim is to better understand buyers' decision-making processes and mitigate this common yet questionable practice.","presenter":"Ms. Fanny Chen","authors":[{"name":"Ms. Fanny Chen","aff":"Student, Rotterdam School of Management"},{"name":"Prof. Finn Wynstra","aff":"Professor, Rotterdam School of Management, Erasmus"},{"name":"Dr. Jan Van Dalen","aff":"Associate Professor, Erasmus University Rotterdam"}],"order":2},{"id":"136-1578","title":"Automated Detection of Potential Human Trafficking in Crisis Contexts","content":"Humanitarian crises heighten trafficking risks for displaced populations. The Ukraine conflict prompted a ML model on Telegram using NLP. We used multilingual translation, feature standardization, and data balancing to improve detection. This approach integrates automated detection with resource allocation, enabling prioritized interventions and a scalable framework for anti-trafficking efforts.","presenter":"Mr. Amir Jamali","authors":[{"name":"Mr. Amir Jamali","aff":"Student, Worcester Polytechnic Institute"},{"name":"Prof. Renata Konrad","aff":"Associate Professor, Worcester Polytechnic Institute"},{"name":"Mr. Navid Ziaei","aff":"Student, Worcester Polytechnic Institute"},{"name":"Dr. Laura Dean","aff":"Associate Professor, MIllikin university"}],"order":3},{"id":"136-1726","title":"Strategic Interactions in Surplus Drug Donations: A Game Theory and Experimental Approach","content":"We employ game theory to model strategic interactions between Corporate Social Responsibility and Supply Chain teams in pharmaceutical firms, focusing on surplus drug donations. Controlled experiments explore how monetary incentives and operational transparency influence supply chain managers’ decisions, identifying factors that align donation strategies with operational objectives in complex environments.","presenter":"Dr. Telesilla Kotsi","authors":[{"name":"Dr. Telesilla Kotsi","aff":"Assistant Professor, Fisher College of Business"},{"name":"Dr. Soh Hyun Chu","aff":"Assistant Professor, Erasmus University Rotterdam"},{"name":"Prof. James Hill","aff":"Professor, Ohio State University"}],"order":4}]},{"id":"s175","title":"Sustainability in Food Supply Chain and Food Waste","track":"Agriculture and Food Supply Chains","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"VININGS","chairs":["Dr. Ismail Kirci"],"abstracts":[{"id":"136-1946","title":"On the Vertical Spillover Effect of Online Ratings on Platform Competition","content":"In online marketplaces, vendors often display differing average ratings across platforms. We use behavioral experiments in food delivery setting to explore how these discrepancies impact platform competition.Results reveal a vertical spillover effect: consumers are more likely to select a platform where their preferred vendor has a higher average rating.","presenter":"Dr. Yulia Vorotyntseva","authors":[{"name":"Dr. Yulia Vorotyntseva","aff":"Assistant Professor, University of St. Thomas"},{"name":"Dr. Aleksi Aaltonen","aff":"Assistant Professor, Stevens Institute of Technology"},{"name":"Dr. Subodha Kumar","aff":"Professor, Temple University"},{"name":"Dr. Paul Pavlou","aff":"Professor, University of Miami Business School"}],"order":1},{"id":"136-1954","title":"It’s still good! Date labels &amp; food waste","content":"This study examines a retailer's decisions on date labeling, production frequency, and batch size for a perishable product, considering biological shelf life, costs, revenues, and consumer attitudes. It finds that retailers may set shorter date labels than actual shelf life, increasing food waste as consumers discard safe-to-eat products.","presenter":"Mrs. Parisa Shahsavand","authors":[{"name":"Prof. Dorothee Honhon","aff":"Associate Professor, University of Texas Dallas"},{"name":"Ms. Iva Rashkova","aff":"Assistant Professor, Washington University"},{"name":"Mrs. Parisa Shahsavand","aff":"Student, The University of Texas at Dallas"}],"order":2},{"id":"136-0505","title":"Should grocery stores remove date labels? Implications for food waste reduction","content":"This paper evaluates two date labeling strategies: mixing new and near-expiry products without labels (Strategy M) and displaying two labels while selling both (Strategy DB). Findings reveal that these two strategies alternately dominate in profitability, with Strategy M potentially achieving greater food waste reduction at the retail level.","presenter":"Ms. Shuxian Xiao","authors":[{"name":"Ms. Shuxian Xiao","aff":"Student, University at Buffalo, SUNY"},{"name":"Prof. Charles Wang","aff":"Associate Professor, Suny At Buffalo"},{"name":"Prof. Mike Wei","aff":"Associate Professor, University at Buffalo"}],"order":4},{"id":"136-1935","title":"Inventory and Pricing Strategies for Perishable Goods: Demand Sensitivity and Waste Impact","content":"We investigate the optimal inventory and pricing strategies for perishable items, taking into account demand sensitivity to both price and remaining product lifetime. We develop a model that reflects consumer behavior, and investigate dynamic pricing until expiration, fixed pricing with a product disposal option, and a hybrid approach.","presenter":"Dr. Ismail Kirci","authors":[{"name":"Dr. Ismail Kirci","aff":"Assistant Professor, Gies College Of Business"},{"name":"Prof. Dorothee Honhon","aff":"Associate Professor, University of Texas Dallas"}],"order":5}]},{"id":"s209","title":"Operations in Emerging Technologies","track":"Digital Platforms, Innovations and Transformations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"GREENBRIAR","chairs":["Dr. Zihao Qu","Mr. Xingyu Bai"],"abstracts":[{"id":"136-0215","title":"Online Learning and Capacity Management in Cloud-Cost Optimization","content":"Consider a learning problem in cloud-cost optimization: a firm chooses from various cloud resources to process tasks. Resources can be used on-demand or reserved at reduced rates. Orders arrive dynamically with unknown service rates. The objective is to minimize the cost incurred in serving orders over a finite time horizon.","presenter":"Dr. Zhichao Feng","authors":[{"name":"Dr. Zhichao Feng","aff":"Assistant Professor, Hong Kong Polytechnic Univ"},{"name":"Prof. Milind Dawande","aff":"Professor, The University of Texas at Dallas"},{"name":"Prof. Ganesh Janakiraman","aff":"Professor, The University of Texas at Dallas"},{"name":"Dr. Anyan Qi","aff":"Associate Professor, University of Texas Dallas"}],"order":1},{"id":"136-0449","title":"Cloud Cost Optimization: Model, Bounds, and Asymptotics","content":"Motivated by the rapid growth of the cloud cost management and optimization (CCMO) industry to support the exploding cloud-computing market, we study an infinite-horizon, stochastic optimization problem from the viewpoint of a firm that employs cloud resources to process incoming orders (or jobs) over time.","presenter":"Dr. Zihao Qu","authors":[{"name":"Dr. Zihao Qu","aff":"Assistant Professor, University of Massachusetts Amherst"},{"name":"Prof. Milind Dawande","aff":"Professor, The University of Texas at Dallas"},{"name":"Prof. Ganesh Janakiraman","aff":"Professor, The University of Texas at Dallas"}],"order":2},{"id":"136-1240","title":"Blockchain Adoption Insurance","content":"Blockchain adoption insurance, mitigates bias in claims evaluation by using independent assessors. Assessors vote collectively, and their compensation aligns with the majority decision, promoting impartial judgments over company profit-driven biases. This model offers a transparent alternative to traditional insurance practices.","presenter":"Mr. Leon Leng","authors":[{"name":"Prof. Rowena Gan","aff":"Assistant Professor, Southern Methodist University"},{"name":"Mr. Leon Leng","aff":"Student, Michael G. Foster School of Business"}],"order":3}]},{"id":"s222","title":"Advancements in Healthcare Analytics","track":"Supply Chain Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"GRAND HALL EAST A","chairs":["Mr. Xi (Henry) Lin"],"abstracts":[{"id":"136-1939","title":"Early Warning Index for Patient Deteriorations in Hospitals","content":"Early patient deterioration warning allows physicians to manage high-risk patients proactively. We integrate multimodal data to develop a novel Early Warning Index (EWI) model, currently in a pilot study, that predicts aggregated risks for deterioration events, achieving 0.878 C-statistics on a large-scale database, outperforming current methods by 30%.","presenter":"Ms. Yu Ma","authors":[{"name":"Prof. Dimitris Bertsimas","aff":"Professor, MIT Operations Research Center"},{"name":"Ms. Yu Ma","aff":"Student, Massachusetts Institute of Technology"},{"name":"Dr. Kimberly Villalobos Carballo","aff":"Lecturer, Massachusetts Institute of Technology"}],"order":1},{"id":"136-0233","title":"Predicting Long-Term Opioid use: An Interpretable Machine Learning Approach","content":"We introduce the Long-Term Opioid Use Risk (LTOUR), a simple, interpretable risk-scoring table developed using optimization-based machine learning. Trained on California prescription data, LTOUR performs comparably to state-of-the-art models while offering greater simplicity and practicality, enabling healthcare providers to identify high-risk patients for early intervention.","presenter":"Mr. Jingyuan Hu","authors":[{"name":"Dr. Fernanda Bravo","aff":"Assistant Professor, UCLA Anderson School of Management"},{"name":"Mr. Jingyuan Hu","aff":"Student, University of California Los Angeles"},{"name":"Prof. Elisa Long","aff":"Professor, UCLA Anderson School of Management"}],"order":2},{"id":"136-1173","title":"Instance Segmentation, Detection and Classification of Teeth in Dental Panoramic X-ray Images","content":"As AI adoption grows in healthcare, dental X-ray images show potential for automated diagnostics and personalized treatment. This study develops a unified framework for tooth segmentation, detection, and classification in panoramic X-rays using advanced deep learning models. By leveraging hierarchical datasets, it aims to improve diagnostic precision and work efficiency.","presenter":"Ms. Jee Hae Ha","authors":[{"name":"Ms. Jee Hae Ha","aff":"Student, University of California Irvine"},{"name":"Mr. Richard Dubach","aff":"Student, University of California Irvine"},{"name":"Prof. Hope Schau","aff":"Professor, University of California Irvine"}],"order":3},{"id":"136-1731","title":"Routing with Delayed Revelation of Feature Information","content":"We study the routing problem for heterogeneous customer arrivals, while the detailed individual features are unavailable upon arrival and only revealed later after detailed evaluation. We propose a two-stage approach for this problem with an easy-to-implement decision rule derived from the fluid model.","presenter":"Prof. Xiaoquan Gao","authors":[{"name":"Prof. Xiaoquan Gao","aff":"Assistant Professor, Singapore Management University"},{"name":"Prof. Pengyi Shi","aff":"Associate Professor, Purdue University"}],"order":4}]},{"id":"s223","title":"Supply Chain Resilience and Industry Studies","track":"Supply Chain Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"EMBASSY A","chairs":["Dr. Gokce Esenduran","Dr. Burcu Tan Erciyes"],"abstracts":[{"id":"136-0677","title":"Designing and Managing a Supply Chain for Electric Vehicle Battery Recycling","content":"Recycling EV batteries is vital for sustainable automotive transportation as it reduces the need for new virgin raw materials. We model fleet turnover with a closed-loop supply chain, exploring uncertainty in collecting batteries from automotive fleet and offering insights for the design and implementation of efficient policies.","presenter":"Dr. Sergey Naumov","authors":[{"name":"Dr. Sergey Naumov","aff":"Assistant Professor, Penn State"}],"order":1},{"id":"136-1122","title":"Evaluating outsourced manufacturing in the medical devices industry","content":"We empirically examine the implications of outsourcing manufacturing on the quality of medical devices. We utilize data from a medical device manufacturer to assess the impact of changes in ownership on selected products.","presenter":"Dr. Oliver von Dzengelevski","authors":[{"name":"Dr. Oliver von Dzengelevski","aff":"Lecturer, ETH Zurich"},{"name":"Dr. John Gray","aff":"Professor, Ohio State University"},{"name":"Prof. Torbjørn Netland","aff":"Professor, ETH Zurich"}],"order":2},{"id":"136-0440","title":"AI Enhanced Supply Chains - Emergent Regulatory and Technology Risks and Opportunities","content":"We examine AI-driven Fairness, Accountability, and Transparency (FAccT) technologies and forward-looking regulations such as the EU’s AI Act (AIA) in the context of supply chain design and oversight. Based on a literature review and managerial interviews, we posit a risk assessment framework and identify algorithm implementations alongside data analytics opportunities.","presenter":"Prof. Nitin Joglekar","authors":[{"name":"Prof. Nitin Joglekar","aff":"Associate Professor, Villanova University"},{"name":"Dr. Patel Patel","aff":"Associate Professor, Villanova University"},{"name":"Dr. Gary Graham","aff":"Associate Professor, Liverpool John Moores University"}],"order":3}]},{"id":"s242","title":"Optimizing Work, Scheduling, and Healthcare with Data-Driven Decisions","track":"Data Science, Analytics and AI","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"ROSWELL","chairs":["Dr. Han Ye"],"abstracts":[{"id":"136-2059","title":"Does Machine Learning Shift Job Requirements? Impacts on Entry-Level Opportunities","content":"Machine learning (ML) shifts human workers toward more complex and novel scenarios that demand higher professional expertise. We find that firms utilizing ML significantly raise job requirements for work experience and skills. Our findings underscore the evolving nature of work in the ML era and its implications for workforce development.","presenter":"Dr. Charles Liu","authors":[{"name":"Prof. Yuanyang Liu","aff":"Assistant Professor, University of Tennessee, Knoxville"},{"name":"Dr. Charles Liu","aff":"Associate Professor, The University of Tennessee-Knoxville"},{"name":"Prof. Tingliang Huang","aff":"Professor, The University of Tennessee-Knoxville"},{"name":"Mr. Pedro Masi","aff":"Student, University of Tennessee, Knoxville"}],"order":1},{"id":"136-2060","title":"Asymptotically Optimal Appointment Scheduling in the Presence of Patient Unpunctuality","content":"In this work, we consider the optimal appointment scheduling problem for a large-scale patient system where patients arrive unpunctually. Using heavy-traffic approximations, we develop asymptotically optimal scheduling policies to maximize expected profit. We examine the performance of these schedules under different unpunctuality scenarios on real data in a simulation study.","presenter":"Dr. Xin Liu","authors":[{"name":"Dr. Nikolai Lipscomb","aff":"Associate Professor, University of North Carolina at Chapel Hill"},{"name":"Dr. Xin Liu","aff":"AI Expert, Amazon"},{"name":"Prof. Vidyadhar Kulkarni","aff":"Professor, University of North Carolina Chapel Hill"}],"order":2},{"id":"136-2061","title":"A Framework for Preventive Intervention and Resource Optimization for Population Level Diabetes Care","content":"We propose a decision framework for predictive diabetes encounter management using machine learning on clinical, demographic, and socioeconomic data. Our model predicts patient health risks and optimally allocates encounters to improve outcomes. We highlight theoretical contributions, equitable healthcare delivery, and implementation strategies for data-driven, personalized chronic care management.","presenter":"Dr. Han Ye","authors":[{"name":"Dr. Ujjal Mukherjee","aff":"Associate Professor, University of Illinois Urbana-Champaign"},{"name":"Dr. Han Ye","aff":"Associate Professor, Lehigh University"},{"name":"Dr. Dilip Chhajed","aff":"Professor, Purdue University"},{"name":"Dr. Collin Roloff","aff":"Medical Professional, Christie Clinic"}],"order":3}]},{"id":"s258","title":"Information and Inter-Firm Strategic Decision Making","track":"POM-Marketing Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"DUNWOODY","chairs":["Prof. Jian Chen","Dr. Xue Li"],"abstracts":[{"id":"136-2033","title":"Quality Revelation and Scheme Choice: The Impact of Online Review on Firm and Platform","content":"Consumers usually evaluate the firm’s quality disclosure and online reviews together to mitigate quality uncertainties since most products possess both search and experience attributes. We set up a stylized model to investigate the firm’s disclosure strategy on search quality when online reviews mostly focus on experience quality.","presenter":"Prof. Hongyan Xu","authors":[{"name":"Prof. He Huang","aff":"Professor, Chongqing University"},{"name":"Dr. Yufeng Yang","aff":"Student, Chongqing University"},{"name":"Prof. Hongyan Xu","aff":"Professor, Chongqing University"},{"name":"Prof. Tingting Nian","aff":"Assistant Professor, University of California Irvine"},{"name":"Mr. Mingrui Zhang","aff":"Assistant Professor, University of Denver"}],"order":1},{"id":"136-0424","title":"Online Selling Mode Selection under Demand Uncertainty and Upstream Competition","content":"This study investigates the online selling mode selection among the reseller mode, marketplace mode, and hybrid mode for two upstream manufacturers, incorporating demand uncertainty and upstream competition. Our findings shed light on the significant role of the production cost, competition intensity and commission rate in selecting selling modes.","presenter":"Ms. Xianmei Zhang","authors":[{"name":"Ms. Xianmei Zhang","aff":"Student, Southeast University"},{"name":"Prof. Weili Xue","aff":"Professor, Southeast University"}],"order":2},{"id":"136-2032","title":"Return Policies for Search and Experience Goods Selling in an Online Platform","content":"This paper examines two different return policies, emerging on various online platforms. We investigate the interaction between sellers and platforms and examine different roles of return policies especially when products are experience goods and consumers may have some mismatch perception on product quality.","presenter":"Dr. Xue Li","authors":[{"name":"Dr. Xue Li","aff":"Associate Professor, Beijing Foreign Studies University"},{"name":"Dr. Chong Zhang","aff":"Assistant Professor, Tilburg University"}],"order":3}]},{"id":"s295","title":"Innovation in Service Design","track":"Product Innovation and Technology Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"INMAN","chairs":["Dr. Abhishek Deshmane"],"abstracts":[{"id":"136-0069","title":"Tolerance for Failure in Innovation: Evidence from the Motion Picture Industry","content":"We analyze a motion picture dataset of 7,901 unique projects spanning 93 years to examine team members' tolerance for failure at project initiation. Our findings show that explorative projects exhibit a higher tolerance for failure while exploitative projects exhibit a lower tolerance for failure in team composition.","presenter":"Mr. Ferhat Caliskan","authors":[{"name":"Dr. Jeremy Kovach","aff":"Assistant Professor, University of North Texas"},{"name":"Mr. Ferhat Caliskan","aff":"Student, University of North Texas"}],"order":1},{"id":"136-1370","title":"Harnessing Technological Innovation through Operational Customization: Streamlining Virtual Triage Adoption in Acute Care","content":"This study explores virtual triage adoption in acute care, emphasizing the importance of operational customization for maximizing its benefits. Through a queueing game model, we uncover trade-offs between informativeness and volume, demonstrating that higher accuracy does not always yield better outcomes. Aligning predictive technology with system context is thus critical.","presenter":"Prof. Jiatao Ding","authors":[{"name":"Prof. Jiatao Ding","aff":"Assistant Professor, Nanyang Technological University"},{"name":"Dr. Michael Freeman","aff":"Assistant Professor, INSEAD"},{"name":"Prof. Sameer Hasija","aff":"Professor, INSEAD"}],"order":2},{"id":"136-1813","title":"Changing course: How analogies direct problem-solving pivots","content":"A pivot requires abandoning the current strategy and identifying a new, more effective, strategy. Abandonment can be incredibly difficult when some sucess has been achieved, thus limiting the ability to recognize better strategies. We show that some types of analogies can be remarkably effective to enable individuals to pivot.","presenter":"Dr. Jeremy Hutchison-Krupat","authors":[{"name":"Dr. Jeremy Hutchison-Krupat","aff":"Associate Professor, University of Cambridge"},{"name":"Dr. Panos Markou","aff":"Assistant Professor, Darden School of Business"}],"order":3},{"id":"136-1363","title":"Digital Curation To Manage Visitor Flows: Experimental Evidence from the Van Gogh Museum","content":"This research examines digital curation in experience design through experiments at the Van Gogh Museum. Using visitor data from multimedia tour variations, we demonstrate how digital nudges can optimize museum experiences by improving visitor routing, increasing art engagement, and reducing congestion while maintaining satisfaction levels.","presenter":"Dr. Abhishek Deshmane","authors":[{"name":"Prof. Ali Aouad","aff":"Assistant Professor, Massachusetts Institute of Technology"},{"name":"Dr. Abhishek Deshmane","aff":"Assistant Professor, Georgia Institute of Technology"},{"name":"Prof. Victor Martínez-De-Albéniz","aff":"Professor, IESE Business School"}],"order":4}]},{"id":"s312","title":"Innovative Practices in Emerging Business Dynamics","track":"Revenue Management and Pricing","type":"Regular","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"MARIETTA","chairs":["Dr. Sentao Miao","Ms. Alys Liang","Ms. Liting Chen"],"abstracts":[{"id":"136-1188","title":"Algorithmic Precision and Human Decision: A Study of Interactive Optimization for School Schedules","content":"Selecting public school schedules to reduce busing costs is a difficult policy and operational problem. We develop a structural model of collaboration between optimizers and policymakers, use insights to design an interactive optimization approach, applied to move high school starts later in San Francisco while reducing transportation expenses.","presenter":"Dr. Arthur Delarue","authors":[{"name":"Dr. Arthur Delarue","aff":"Assistant Professor, Georgia Institute of Technology"},{"name":"Prof. Zhen Lian","aff":"Assistant Professor, Yale School of Management"},{"name":"Prof. Sébastien Martin","aff":"Assistant Professor, Kellogg School of Management"}],"order":1},{"id":"136-1458","title":"A/B Testing Under Products Stockouts","content":"This paper proposes a method for estimating A/B test effects in retail markets affected by product stockouts. Stockouts can bias treatment effect estimates by influencing purchase probability. The proposed approach accounts for this interference, reducing bias and enhancing the accuracy of treatment effect estimates in environments with varying product availability.","presenter":"Ms. Liting Chen","authors":[{"name":"Ms. Liting Chen","aff":"Student, McGill University"},{"name":"Prof. Maxime Cohen","aff":"Professor, McGill University"},{"name":"Dr. Sentao Miao","aff":"Assistant Professor, University of Colorado Boulder"}],"order":2},{"id":"136-1605","title":"Fresh Rating Systems: Structure, Incentives, and Fees","content":"Rating systems aggregate customer reviews into a numeric measure of service quality. However, not all reviews — and consequently, not all ratings — are equally informative. In this paper, we explore how to modify rating systems to address the issue of stale reviews.","presenter":"Prof. Titing Cui","authors":[{"name":"Prof. Titing Cui","aff":"Assistant Professor, University of Tulsa"},{"name":"Prof. Michael Hamilton","aff":"Assistant Professor, University of Pittsburgh"}],"order":3},{"id":"136-1607","title":"Inventory Commingling on An E-Commerce Platform","content":"Amazon's inventory commingling strategy pools third-party sellers’ products to reduce fulfillment costs. While sellers save on pre-handling costs, they risk potential profit losses if counterfeit or defective products are misattributed to them. Using a model of heterogeneous product quality, we explore sellers’ decisions and the platform’s profit-maximizing mechanism.","presenter":"Ms. Hanqi Wen","authors":[{"name":"Ms. Hanqi Wen","aff":"Student, University of Michigan"},{"name":"Prof. Izak Duenyas","aff":"Professor, University of Michigan - Ann Arbor"},{"name":"Prof. Joline Uichanco","aff":"Associate Professor, University of Michigan"}],"order":4}]},{"id":"s326","title":"Tutorial: Registered Reports Review for Field Experiments","track":"Empirical Research in Operations Management","type":"Tutorial","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"EMBASSY B","chairs":["Dr. Rogelio Oliva","Dr. Rafael Escamilla"],"abstracts":[{"id":"136-2088","title":"Registered Reports Review for Field Experiments","content":"Registered Reports follow a two-stage process where hypotheses are outlined and peer reviewed before experimental execution. Such a review process holds great promise for field experiments, which are risky and difficult to replicate. In this session, we will discuss the motivation and publication strategy for Registered Reports in OM.","presenter":"Dr. Rogelio Oliva","authors":[{"name":"Dr. Rogelio Oliva","aff":"Professor, Texas A&amp;M University College Station"},{"name":"Dr. Rafael Escamilla","aff":"Assistant Professor, Arizona State University"},{"name":"Dr. Huseyn Abdulla","aff":"Assistant Professor, University of Tennessee Knoxville"}],"order":1}]},{"id":"s363","title":"Responding to Complex and Human-Made Disasters","track":"Humanitarian Operations and Crisis Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"EMBASSY G","chairs":["Mr. Angelo Soto Vergel"],"abstracts":[{"id":"136-0154","title":"Adaptation in Humanitarian Logistics: Examining Complex Adaptive Systems in Armed Conflict","content":"This paper examines humanitarian logistics (HL) systems in armed conflict settings where volatile environments exacerbate logistical challenges. Leveraging Complex Adaptive Systems theory and system dynamics to examine how HL systems are impacted by conflict settings and the causal polarities influencing critical success factors","presenter":"Ms. Tamara Kirkwood-Wright","authors":[{"name":"Ms. Tamara Kirkwood-Wright","aff":"Student, Hanken School of Economics"}],"order":1},{"id":"136-0066","title":"On the Disclosure of Defensive Posture: Adversarial Belief Formation and Target Selection Decisions","content":"This research studies how people – who are motivated to attack one among multiple targets – respond when receiving information from a defender regarding the deployment of new security measures at those targets. Using data from a behavioral experiment, we analyze adversarial belief formation and target selection decisions.","presenter":"Dr. Kyle Hunt","authors":[{"name":"Dr. Kyle Hunt","aff":"Assistant Professor, University at Buffalo"},{"name":"Dr. Sule Guney","aff":"Assistant Professor, University of California Irvine"},{"name":"Dr. Richard John","aff":"Professor, University of Southern California"},{"name":"Dr. Jun Zhuang","aff":"Professor, University at Buffalo"}],"order":2},{"id":"136-0780","title":"Education in Emergencies: A Logisticians Role in SDG 4 for Displaced children","content":"More than 35M children are displaced by disaster worldwide; nearly half lack reliable access to education. The statistics are worse for girls, older children, and children with disabilities. UNICEF cites the main issues as Data Gaps, Effective Response, and Coordination Challenges. We explore opportunities and challenges for HAL researchers.","presenter":"Prof. Julie Niederhoff","authors":[{"name":"Prof. Julie Niederhoff","aff":"Associate Professor, Syracuse University"}],"order":3},{"id":"136-0228","title":"Private fundraising from live streaming for humanitarian logistics preparedness","content":"The thesis explores the concept of live streaming, how charities have used it to raise funds from individual donors during (fundraising) live streams, and its potential application in humanitarian assistance to support logistics preparedness activities – an area traditionally funded by institutional and corporate donors.","presenter":"Ms. Nicole Nguyen","authors":[{"name":"Ms. Nicole Nguyen","aff":"Student, Hanken School of Economics"}],"order":4},{"id":"136-0236","title":"Rapid Deployment of LoRaWAN and TinyML-based Geolocation Systems for Efficient Post-Disaster Survivor Detection","content":"This research presents a rapidly deployable geolocation system integrating LoRaWAN and TinyML for efficient post-disaster survivor detection. The system enables low-latency identification of survivors in challenging environments. Field-tested in Gramalote, Colombia, this system enhances disaster response by optimizing communication, prioritization, and resource allocation in humanitarian operations.","presenter":"Mr. Angelo Soto Vergel","authors":[{"name":"Mr. Angelo Soto Vergel","aff":"Student, University at Buffalo, SUNY"},{"name":"Dr. Diana Ramirez-Rios","aff":"Assistant Professor, The State University of New York at Buffalo"},{"name":"Dr. Juan Velez","aff":"Professor, Universidad del Norte"},{"name":"Dr. Rene Amaya-Mier","aff":"Associate Professor, Universidad del Norte"}],"order":5}]},{"id":"s378","title":"Panel: Responsible AI in Practice","track":"Practice Leaders","type":"Panel","invited":"Invited","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"Learning Center","chairs":["Prof. Pelin Pekgun","Dr. Andreea Popescu"],"abstracts":[{"id":"136-2127","title":"Panel: Responsible AI in Practice","content":"This panel session brings together leading experts from industry and academia to discuss strategies for implementing AI responsibly and ethically in the practice of production and operations; how to ensure fairness, transparency, and accountability, while fostering trust and long-term stakeholder value.\r\n","presenter":"Prof. Pascal Van Hentenryck","authors":[{"name":"Prof. Pascal Van Hentenryck","aff":"Professor, Georgia Institute of Technology"},{"name":"Dr. Ronald Menich","aff":"VP, Advanced Analytics and Data Science, Catalina"},{"name":"Dr. Pratik Mital","aff":"Research Science Manager, Amazon"},{"name":"Dr. Ioana Mazare","aff":"SVP and GM, The Data Lodge (A DSG Company)"},{"name":"Dr. Andreea Popescu","aff":"Senior Director of Data Science, Operations , Shipt"}],"order":1}]},{"id":"s384","title":"Analytical Approaches to Risk and Decision-Making in Complex Systems","track":"Supply Chain Risk Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"EMBASSY H","chairs":["Dr. Pedro Gerum"],"abstracts":[{"id":"136-1354","title":"Supply Chain Visibility, Traceability, and Transparency: A Systematic Literature Review from a Data-Driven Perspective","content":"This research defines supply chain visibility, traceability, and transparency from a data perspective, focusing on data requirements, archetypes, and analysis. It addresses blind spots in extended supply chain tiers, emphasizing end-to-end investigation. A data-driven implementation framework is proposed to enhance visibility, traceability, and transparency across the end-to-end supply chains.","presenter":"Ms. Wei Nie","authors":[{"name":"Ms. Wei Nie","aff":"Student, University of Cambridge"},{"name":"Dr. Naoum Tsolakis","aff":"Associate Professor, University of Cambridge"},{"name":"Dr. Mukesh Kumar","aff":"Associate Professor, University of Cambridge"}],"order":1},{"id":"136-1581","title":"The impact of the presidential election on firms with a domestic manufacturing strategy","content":"The results of U.S. election was a an event that financial markets did not fully anticipate. Given that the Trump administration has threaten to impose significant tariffs on imports to the U.S., we use an event study methodology to assess the abnormal return on firms tied to domestic manufacturing.","presenter":"Dr. Jason Woldt","authors":[{"name":"Dr. Jason Woldt","aff":"Assistant Professor, University of Wisconsin Oshkosh"}],"order":2},{"id":"136-1800","title":"Research on supply chain risk propagation mechanism under heterogeneous time-dependent SIS model","content":"We study the supply chain risk through the heterogeneous and time-dependent SIS model. Through the N-intertwined mean field approximation (NIMFA) model, we identify the critical threshold of supply chain risk propagation. In addition, we design an accurate simulation model and use the likelihood ratio method to accelerate the simulation process.","presenter":"Mr. Jiangnan Shi","authors":[{"name":"Mr. Jiangnan Shi","aff":"Student, Harbin Institute of Technology"},{"name":"Prof. Guangxin Jiang","aff":"Professor, Harbin Institute of Technology"}],"order":3},{"id":"136-1983","title":"Designing A Wildfire Prediction Model by Satellite Images and AI","content":"We aim to develop an AI-driven wildfire prediction system using satellite imagery to enable rapid response through golden time alerts and ensure sustained surveillance through continuous monitoring. The study enhances wildfire detection, prediction, and response while assessing related economic and social losses through a cost-benefit analysis, offering actionable insights.","presenter":"Mr. Minseok Kim","authors":[{"name":"Mr. Minseok Kim","aff":"Assistant Professor, Southern Illinois University - Edwardsville"},{"name":"Dr. Yao Zhao","aff":"Professor, Rutgers University"},{"name":"Dr. Soohyun Cho","aff":"Assistant Professor, Rutgers University"}],"order":4},{"id":"136-0194","title":"Game-theoretical approach to inspection scheduling","content":"We explore using search games for inspection decision-making. In this context, a \"Searcher\" aims to locate strategically hidden \"faults\" placed by a \"Hider.\" We study different game variations to capture the diverse factors influencing real-world inspection scenarios, including the nature of the search space itself.","presenter":"Dr. Pedro Gerum","authors":[{"name":"Dr. Pedro Gerum","aff":"Assistant Professor, Cleveland State University"},{"name":"Dr. Thomas Lidbetter","aff":"Associate Professor, Rutgers Business School"}],"order":5}]},{"id":"s385","title":"Platform Collaboration and Supplier Strategies in E-Commerce","track":"Procurement and Supplier Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"HARRIS","chairs":["Prof. John Maleyeff"],"abstracts":[{"id":"136-0193","title":"Synergetic Dynamics Between SMEs and Platforms in Business-to-Business E-Commerce","content":"This pioneering research integrates synergy theory with evolutionary game modeling to analyze SME-platform collaboration in cross-border business-to-business (B2B) e-commerce. Validated through numerical simulation and case study, the novel approach reveals that government facilitation, initial collaboration intent, and fair benefit-cost sharing drive cooperative outcomes, offering groundbreaking insights for policy design.","presenter":"Mr. Chunfeng Feng","authors":[{"name":"Mr. Chunfeng Feng","aff":"Student, School of Economics, Guangxi University"},{"name":"Mr. Bao Feng","aff":"Student, School of Economics, Guangxi University"}],"order":1},{"id":"136-1070","title":"Evaluating the Impact of Tolerances when Estimating Inventory Record Inaccuracy (IRI) for Beverage Distribution","content":"We utilize Bayesian Latent-lognormal (LLN) regression to analyze count data with measurement error. First with simulated data and then with actual data from a beverage supply company, we show the impact of ignoring measurement error, due to tolerances, on IRI rate estimates for determining single-period order replenishments for the company.","presenter":"Prof. Toyin Clottey","authors":[{"name":"Prof. Toyin Clottey","aff":"Professor, Wayne State University"},{"name":"Prof. Wc Benton","aff":"Professor, Ohio State University"}],"order":2},{"id":"136-0830","title":"Sustainable Vendor Benchmarking: A Fuzzy Kano, SWARA, ROV, and TOPSIS Approach","content":"The current research focuses on the assessment of green vendor hierarchy and evaluation at Tier-1 for Industry 4.0 with the aid of Fuzzy-Kano, SWARA, ROV, and TOPSIS. It identifies and discusses must-be criteria, assesses vendor performance, and compares ROV and TOPSIS in a case study of a bricks industry.","presenter":"Dr. Mani Venkatesh","authors":[{"name":"Dr. Kottala Sri Yogi","aff":"Assistant Professor, Symbiosis Institute of Business Management, Hyderabad"},{"name":"Dr. Mani Venkatesh","aff":"Associate Professor, Asper School of Business"}],"order":3},{"id":"136-1482","title":"Online Supplier Selection for E-commerce Firms","content":"Firms using drop-shipping must choose suppliers to fulfill orders in real time. Suppliers vary in fulfillment accuracy, fulfillment speed, order acceptance, and cost. These trade-offs are difficult to manage when they are uncertain and must be predicted. We investigate methods for selecting suppliers in real time considering these factors.","presenter":"Dr. Emily Griffin","authors":[{"name":"Dr. Thomas Cassidey","aff":"Assistant Professor, California State University East Bay"},{"name":"Dr. Emily Griffin","aff":"Assistant Professor, Babson College"},{"name":"Dr. Burcu Keskin","aff":"Professor, University of Alabama Tuscaloosa"}],"order":4},{"id":"136-0283","title":"Multi-Criteria Supplier Selection Using a Unified Economic Scale","content":"A structured supplier selection model compares multiple criteria on a unified economic scale. Each criterion is iteratively evaluated for each pair of suppliers using group consensus that results in a set of indifference probabilities. These probabilities are used to determine criterion weights that transform expected cost differences into supplier rankings.","presenter":"Ms. Shuting Peng","authors":[{"name":"Prof. John Maleyeff","aff":"Associate Professor, Boston University"},{"name":"Ms. Shuting Peng","aff":"Student, Boston University"},{"name":"Mr. Boyu Wang","aff":"Student, Boston University"}],"order":5}]},{"id":"s389","title":"Advances in Transportation and Logistics","track":"Aviation, Transportation, and Logistics Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"UNIVERSITY","chairs":["Dr. Fei (Sophie) Song"],"abstracts":[{"id":"136-0533","title":"Applicability Analysis of the 15-Minute City Concept: Insights from Urban Mobility Perspective","content":"To investigate the development of the 15-minute city, this study conducted community-level accessibility assessments by incorporating actual traveler needs and leveraging city road networks. The results highlighted the shortcomings of 15-minute city planning, particularly for pedestrian accessibility. This study offers recommendations for improving the 15-minute accessibility based on the result.","presenter":"Ms. Xuan Feng","authors":[{"name":"Ms. Xuan Feng","aff":"Student, Tianjin University"},{"name":"Prof. Ning Jia","aff":"Professor, Tianjin university"}],"order":1},{"id":"136-0071","title":"Assessing the Role of Transportation Aircraft","content":"Transportation aircraft are one of the most important factors in sustaining the success of the operational environment today. With this awareness, various countries have built their own aircraft and the number of these ones has increased. This study has contributed to the problem of which aircraft will enter force structure.","presenter":"Mr. Erhan BERK","authors":[{"name":"Mr. Erhan BERK","aff":"Student, National Defence University"}],"order":2},{"id":"136-1923","title":"Exploring the Development Potential of Dockless Bike Sharing: Perspectives on Regional Equity and Autonomous Redistribution","content":"Dockless bike sharing (DBS) has emerged as popular urban shared transportation. We explored the development potential of DBS from the perspective of urban regional equity. A Transformer model was employed to analyze development potential in different urban regions. By integrating regional equity and self-sustainability, a Development Potential Index is proposed.","presenter":"Ms. Xuan Feng","authors":[{"name":"Ms. Xuan Feng","aff":"Student, Tianjin University"},{"name":"Ms. Xin Zhang","aff":"Student, Tianjin Univercity"},{"name":"Prof. Ning Jia","aff":"Professor, Tianjin university"}],"order":3},{"id":"136-0484","title":"Better to deliver tomorrow morning than late today?","content":"This study investigates the time-of-day effect on customer perceptions of online seller logistics service quality (LSQ) using over 42 million Alibaba orders. Results show delivery time significantly impacts LSQ ratings, amplified by promised service. Machine learning highlights time-of-day as the top predictor, contributing to LSQ theory and practical insights.","presenter":"Dr. Yuhang Xu","authors":[{"name":"Dr. Fei (Sophie) Song","aff":"Assistant Professor, Bowling Green State University"},{"name":"Dr. Yuhang Xu","aff":"Associate Professor, Bowling Green State University"},{"name":"Dr. Heng Chen","aff":"Assistant Professor, University of Nebraska Lincoln"},{"name":"Prof. Kunpeng Zhang","aff":"Associate Professor, University of Maryland"}],"order":4}]},{"id":"s413","title":"Hospital Performance, Supply Chains, and Quality Improvement","track":"Healthcare Operations Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-09","dow":"Friday","day":9,"mon":"May"},"start":"4:30 PM","end":"6:00 PM","startMin":990,"room":"PIEDMONT","chairs":["Prof. Samuel Allen"],"abstracts":[{"id":"136-1072","title":"Performance measurement and management in hospitals: The use of outcomes and process metrics","content":"The aim of this research is to analyze how hospitals use outcomes and process metrics to improve performance. Using the case study method, this research finds there are different uses of outcomes and process metrics and different forces that hinder and enable their potential to improve hospital performance.","presenter":"Dr. Rodolfo Catena","authors":[{"name":"Dr. Rodolfo Catena","aff":"Assistant Professor, University College London"},{"name":"Dr. Elena Azzolini","aff":"Associate Professor, Humanitas University"}],"order":1},{"id":"136-0887","title":"Reshaping the Chain: The Impact of Mergers and Acquisitions on Hospital Supplier Replacement","content":"This study investigates the dynamics of hospital supplier relationships following mergers and acquisitions, focusing on target hospitals. Analyzing 11,326 M&amp;A events with advanced econometric models, it finds that established relationships and market dominance reduce supplier abandonment risk. Insights support strategies for enhancing supplier resilience and optimizing post-merger supply chain stability.","presenter":"Ms. Linying CAO","authors":[{"name":"Ms. Linying CAO","aff":"Student, Tianjin University"},{"name":"Dr. Yuxiao Ye","aff":"Assistant Professor, Tianjin University"}],"order":3},{"id":"136-0685","title":"How a dedicated post-discharge unit can reduce hospital congestion and costs","content":"Inpatients ready for transfer to post-acute care facilities may experience nonmedical stays until a suitable facility is found, contributing to overcrowding. We show that a “post-discharge unit” is efficient for hospitals with over 4% of such patients, increasing access to beds by 13% and reducing costs by 2%–21%.","presenter":"Dr. Maryam Khatami","authors":[{"name":"Dr. Maryam Khatami","aff":"Assistant Professor, University of North Texas Denton"},{"name":"Prof. Jon Stauffer","aff":"Associate Professor, Mays Business School, Texas A&amp;M University"},{"name":"Prof. Mark Lawley","aff":"Professor, Texas A&amp;M University College Station"}],"order":5},{"id":"136-1761","title":"Implementing and Sustaining Healthcare Quality Improvement: Case Study Examining Feedback Structure and Dynamics","content":"Robust process improvement (RPI) is a quality improvement (QI) approach intended to overcome typical QI challenges with implementation and sustainability. We report findings from a mixed methods simulation study. Our results indicate that RPI and QI can both fall victim to traps common to complex implementations without broader organizational involvement.","presenter":"Prof. Samuel Allen","authors":[{"name":"Prof. Samuel Allen","aff":"Technical Analyst, Professor, RAND"},{"name":"Dr. Andrada Tomoaia-Cotisel","aff":"Policy Researcher, RAND"},{"name":"Dr. Eric Thomas","aff":"Professor, UT Houston-Memorial Hermann Center for Healthcare Quality and Safety"}],"order":6}]},{"id":"s21","title":"Panel: POM and Community Papers","track":"POM and Community","type":"Panel","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY F","chairs":["Dr. Wei Wei"],"abstracts":[{"id":"136-2118","title":"Panel: Publishing Diversity, Equity, and Inclusion Papers","content":"This panel invites researchers whose papers were accepted by POM's special issue, \"Diversity, Equity, and Inclusion in Operations and Supply Chain Management.\" The panelists will share the journeys of these papers.","presenter":"Dr. Wei Wei","authors":[{"name":"Dr. Wei Wei","aff":"Assistant Professor, University of New Hampshire"},{"name":"Dr. Kaitlin Wowak","aff":"Associate Professor, University of Notre Dame"},{"name":"Dr. Feyza G. Sahinyazan","aff":"Assistant Professor, Simon Fraser University"},{"name":"Prof. Amir Karimi","aff":"Assistant Professor, University of Texas at San Antonio"},{"name":"Dr. Christopher Zobel","aff":"Professor, Virginia Tech"}],"order":1}]},{"id":"s47","title":"Healthcare Analytics/Operation","track":"Healthcare Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"PIEDMONT","chairs":["Prof. Guihua Wang","Dr. Jiayi Liu"],"abstracts":[{"id":"136-1182","title":"Physician-Hospital Integration and Quality Outcomes: The Role of Financial Incentives Faced by U.S. Hospitals","content":"The healthcare industry has witnessed a growing trend toward vertical integration between hospitals and physician. Existing research presents mixed evidence regarding its impact on costs and outcomes. This study fills in the gap of examining relationship between hospital-physician vertical integration and performance under financial incentive programs.","presenter":"Ms. Jingyun Su","authors":[{"name":"Ms. Jingyun Su","aff":"Student, Miami Herbert Busienss School"},{"name":"Prof. Jong Myeong Lim","aff":"Assistant Professor, Miami Herbert Busienss School"}],"order":1},{"id":"136-1326","title":"Small Area Estimation of Case Growths for Timely COVID-19 Outbreak Detection","content":"A fundamental challenge in COVID-19 outbreak detection is balancing the accuracy vs. speed tradeoff for small sample size estimation. We develop an algorithm, Transfer Learning Generalized Random Forest (TLGRF), that balances this tradeoff.","presenter":"Dr. Zhaowei She","authors":[{"name":"Dr. Zhaowei She","aff":"Assistant Professor, Singapore Management University"},{"name":"Mr. Zilong Wang","aff":"Student, Georgia Institute of Technology"},{"name":"Dr. Jagpreet Chhatwal","aff":"Associate Professor, Harvard University"},{"name":"Prof. Turgay Ayer","aff":"Professor, Georgia Tech"}],"order":2},{"id":"136-2145","title":"Heterogeneous Effects of Ambulance Response Time on Patient No-Show Behavior","content":"We examine how ambulance response time affects the likelihood of a caller’s no-show. Using detailed EMS data and instrumental variable regression to address endogeneity, we find longer delays significantly increase no-shows. Delay sensitivity varies by age, severity, and proximity, offering implications for EMS triage, resource allocation, and communication strategies.","presenter":"Mr. Mohammadmahdi Tahergandomabadi","authors":[{"name":"Mr. Mohammadmahdi Tahergandomabadi","aff":"Student, University of Texas at Dallas"},{"name":"Dr. Nancy Wang","aff":"STEAM Learning Club, STEAM Learning Club"},{"name":"Dr. Behrooz Pourghannad","aff":"Assistant Professor, University of Oregon"},{"name":"Prof. Guihua Wang","aff":"Associate Professor, University of Texas Dallas"}],"order":3},{"id":"136-1719","title":"Surgical Task Switching: Implications for Transplant Quality","content":"Psychological experiments have shown that task switching imposes cognitive burdens, increases task completion times, and leads to more errors. However, real-world evidence on its effects in professional settings remains scarce. This study provides causal evidence of the impact of task switching on performance in a high-stakes context: organ transplantation.","presenter":"Dr. Jiayi Liu","authors":[{"name":"Dr. Jiayi Liu","aff":"Assistant Professor, Virginia Polytechnic Institute And State University"},{"name":"Dr. Yiwen Jin","aff":"Assistant Professor, University of Calgary"}],"order":4}]},{"id":"s53","title":"Advances in Energy Resilience","track":"Energy and Natural Resource Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"TECHWOOD","chairs":["Dr. Kai Pan"],"abstracts":[{"id":"136-0507","title":"Energy consumption of limited response to weather","content":"Smart technologies have improved pricing strategies, but residential Demand Response (DR) programs often fall short due to external factors like weather and consumers' cognitive limitations. A novel framework analyzes these behaviors, highlighting how pricing and information costs shape demand, offering insights for better energy market strategies.","presenter":"Prof. Fariba Farajbakhsh Mamaghani","authors":[{"name":"Prof. Fariba Farajbakhsh Mamaghani","aff":"Assistant Professor, Tulane University"},{"name":"Prof. Saed Alizamir","aff":"Associate Professor, University of Virginia"},{"name":"Dr. Shouqiang Wang","aff":"Associate Professor, University of Texas Dallas"}],"order":1},{"id":"136-1358","title":"Managing resilient hydrogen-renewable microgrids: A multi-time scale optimization framework","content":"This study proposes an integrated electricity-hydrogen system for standalone microgrids powered by renewable energy sources. The system utilizes hydrogen for both short and long-term energy storage to mitigate renewable intermittency while satisfying direct hydrogen demand. A multi-timescale optimization framework determines optimal hydrogen production and storage strategies across varying temporal horizons.","presenter":"Dr. Yashar Ghiassi-Farrokhfal","authors":[{"name":"Mr. Ehsan Aghamohammadzadeh","aff":"Student, Rotman School of Management"},{"name":"Dr. Ece Cigdem Karakoyun","aff":"Assistant Professor, Erasmus University Rotterdam"},{"name":"Dr. Yashar Ghiassi-Farrokhfal","aff":"Associate Professor, Rotterdam School of Management"}],"order":2},{"id":"136-0268","title":"OPTIMAL LOCATION OF THERMAL PLANTS CONSIDERING TRANSMISSION LOSSES AND FUEL TRANSPORTATION COST","content":"This research is motivated by the Government of Ghana (GoG) decision to relocate a 250 MW thermal plant about 250km from its current location. We investigate the soundness of GOG’s decision by considering the important factors at play including costs related to transmission losses and fuel transportation.","presenter":"Dr. Iddrisu Awudu","authors":[{"name":"Dr. Anthony Afful-Dadzie","aff":"Associate Professor, University of Ghana"},{"name":"Dr. Iddrisu Awudu","aff":"Assistant Professor, Quinnipiac University"},{"name":"Dr. Eric Afful-Dadzie","aff":"Assistant Professor, University of Ghana"}],"order":3},{"id":"136-0564","title":"Managing Shared Mobility Systems with Electric Vehicles Under Correlated Demand Uncertainties","content":"Using electric vehicles (EVs) with vehicle-to-grid (V2G) technology enhances sustainability but restricts accessibility. Optimizing initial EV allocation is vital, given uncertainties in trip demands. We propose a two-stage distributionally robust optimization model to minimize costs while considering correlated uncertainties, improving operational efficiency and reducing costs by up to 4.66%.","presenter":"Dr. Kai Pan","authors":[{"name":"Mr. Ziliang Jin","aff":"Student, The Hong Kong Polytechnic University"},{"name":"Prof. Yun Fong Lim","aff":"Professor, Singapore Management University"},{"name":"Dr. Kai Pan","aff":"Associate Professor, The Hong Kong Polytechnic University"}],"order":4}]},{"id":"s55","title":"Waste Reduction in Supply Chains","track":"Sustainable Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"GRAND HALL EAST C","chairs":["Dr. Karthik Murali"],"abstracts":[{"id":"136-0017","title":"Seeing Beauty in Ugly Produce: Do Ugly Produce Retailers Reduce Food Waste?","content":"Ugly produce refers to visually imperfect but edible produce. While advocates claim retail ugly produce helps reduce food waste, skeptics argue it can meet demand elsewhere, like in restaurants. We model the entire produce supply chain to holistically evaluate the impact of retail ugly produce on food waste.","presenter":"Dr. Zheng Han","authors":[{"name":"Dr. Zheng Han","aff":"Assistant Professor, DePaul University"},{"name":"Prof. Bin Hu","aff":"Professor, Naveen Jindal School of Management"},{"name":"Prof. Milind Dawande","aff":"Professor, University of Texas Dallas"}],"order":1},{"id":"136-0024","title":"The Environmental and Social Implications of Pay-what-you-want Food Waste Supermarket","content":"Donating edible surplus food is a preferred food recovery approach. An emerging type of donation outlet is pay-what-you-want food waste supermarkets where consumers can purchase edible salvaged food at a price that they are willing to pay. In this paper, we analyze the environmental and social of this pricing scheme.","presenter":"Mr. Xi (Henry) Lin","authors":[{"name":"Mr. Xi (Henry) Lin","aff":"Student, University of California Irvine"},{"name":"Prof. Luyi Gui","aff":"Associate Professor, University of California Irvine"},{"name":"Prof. Luyi Yang","aff":"Assistant Professor, University of California Berkeley"}],"order":2},{"id":"136-0745","title":"2004–2024: Unpacking two decades of food date labeling in the US and UK","content":"Food date labels, such as \"use by\" and \"sell by,\" are largely misinterpreted by consumers, leading (among others) to 7-10% of US food waste annually. We use past regulatory variation, voluntary changes to these formats, and field data to study the impact of date label formats on consumer behavior.","presenter":"Ms. Fiorentia Zoi Anglou","authors":[{"name":"Ms. Fiorentia Zoi Anglou","aff":"Student, University of Texas Austin"},{"name":"Prof. Robert Sanders","aff":"Assistant Professor, University of California San Diego"},{"name":"Prof. Yannis Stamatopoulos","aff":"Associate Professor, The University of Texas at Austin"}],"order":3},{"id":"136-1135","title":"Survival Analysis for Managing Animal Rescue","content":"Using data from a Dallas municipal shelter, we develop a method to optimize euthanasia policies, balancing the trade-off between longer stays improving adoption probabilities and overcrowding reducing them. Our approach estimates the number of lives saved compared to current practices, offering actionable insights for improving shelter outcomes.","presenter":"Ms. Qiuxia Chen","authors":[{"name":"Ms. Qiuxia Chen","aff":"Student, University of Texas Dallas"},{"name":"Prof. Elena Katok","aff":"Professor, The University of Texas at Dallas"},{"name":"Prof. Ernan Haruvy","aff":"Professor, McGill University"}],"order":4}]},{"id":"s64","title":"Disruptions in Inventory, Manufacturing, and Medical Waste Management","track":"Supply Chain Risk Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY H","chairs":["Dr. Manish Tripathy"],"abstracts":[{"id":"136-0779","title":"Showroom locating problem: models and analyses","content":"In this study, we introduce an integrated showroom locating, pricing, and inventory management model. It is shown that this model can be solved in polynomial time. Capacitated version of the problem is NP-hard and approximation heuristic is proposed. Numerical analyses provide insights on how showroom location and pricing decisions interact.","presenter":"Dr. Dincer Konur","authors":[{"name":"Dr. Dincer Konur","aff":"Associate Professor, Texas State University"}],"order":1},{"id":"136-1481","title":"Reconsideration of outsourcing decision in global supply chain","content":"This paper studies the outsourcing decision of an original equipment manufacturer (OEM) in three outsourcing and sourcing strategies: staying in the tariff country, transferring to another country, or reshoring back to the home country.","presenter":"Dr. Jiayuan Zhang","authors":[{"name":"Dr. Jiayuan Zhang","aff":"Assistant Professor, University of Wisconsin-Whitewater"},{"name":"Dr. Yuwen Chen","aff":"Associate Professor, University of Rhode Island"}],"order":2},{"id":"136-1844","title":"A multi-objective resilient network design problem for medical waste management supply chain","content":"This research addresses the resilience of medical waste management in humanitarian supply\r\nchains under disruptions through a novel multi-objective optimization framework.\r\nThe study integrates traditional logistics metrics with network resiliency considerations,\r\nemphasizing inventory cost, transportation cost, and node criticality as key objectives.","presenter":"Mr. Amir Sadeghi","authors":[{"name":"Mr. Amir Sadeghi","aff":"Student, North Carolina State University"},{"name":"Mr. Amirreza Sahebi Fakhrabad","aff":"Student, North Carolina State University"},{"name":"Dr. Robert Handfield","aff":"Professor, North Carolina State University"}],"order":3},{"id":"136-0753","title":"Coopetition Strategies within Integrated &amp; Independent Firms: Price, Quality, Brand, and Sourcing Implications","content":"We consider a vertically integrated Manufacturer &amp; Supplier pair, an independent Supplier, and an independent Manufacturer. The suppliers make components of differing quality levels and supply these components to the manufacturers who undertake value addition operations before selling to\r\nconsumers. We analyze the pricing, quality, and sourcing decisions.","presenter":"Dr. Manish Tripathy","authors":[{"name":"Dr. Manish Tripathy","aff":"Assistant Professor, DePaul University"},{"name":"Dr. Shubham Gupta","aff":"Assistant Professor, New Jersey Institute of Technology"}],"order":4}]},{"id":"s69","title":"Current Topics in Procurement","track":"Procurement and Supplier Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"MARIETTA","chairs":["Dr. Seongtae Kim","Dr. Jie Lian"],"abstracts":[{"id":"136-1652","title":"A Supply Chain Advantage in Disruptive Times: New Perspectives on ESG Strategy","content":"This study uses the COVID-19 pandemic to reveal that enhanced ESG practices improve firm resilience, boosting return on assets by 0.124% per 1% ESG increase. Stronger ties with suppliers and buyers drive these gains, highlighting the strategic value of targeted ESG practices in enhancing supply chain resilience.","presenter":"Mr. Wenting Li","authors":[{"name":"Mr. Wenting Li","aff":"Student, Arizona State University Tempe"},{"name":"Prof. Yimin Wang","aff":"Associate Professor, Arizona State University"}],"order":1},{"id":"136-1368","title":"The financial impact of supply chain restructuring amid mega-disruptions","content":"Firms respond to mega-events, such as climate change, US-China tensions, Russia-Ukraine war, and COVID-19 pandemic, by restructuring their supply chains (e.g., relocation). Using event study analysis, we find that the market reacts negatively to announcements of supply chain restructuring amid the events, more specifically for activities external to the firm.","presenter":"Dr. Nishat Choudhury","authors":[{"name":"Dr. Nishat Choudhury","aff":"Post Doc/Researcher, Aalto University"},{"name":"Dr. Seongtae Kim","aff":"Assistant Professor, Aalto University"},{"name":"Dr. Sangho Chae","aff":"Associate Professor, University of Warwick"},{"name":"Dr. Byung-Gak Son","aff":"Senior Lecturer, Cass Business School"}],"order":2},{"id":"136-1547","title":"Suppliers’ Trade Credit Response to Buyers’ Operational Disruptions","content":"We invert the traditional buyer-supplier relationship to investigate suppliers’ financial strategies in response to disruptions in buyer operations. Three sources of archival data spanning from 2010 to 2019 examine the use of trade credits to respond to the operational disruption of partners.","presenter":"Mr. Alexander Schmidt","authors":[{"name":"Mr. Alexander Schmidt","aff":"Student, University of Oklahoma"},{"name":"Dr. Jeffrey Schmidt","aff":"Associate Professor, University of Oklahoma"}],"order":3},{"id":"136-0873","title":"Towards sustainable procurement in agricultural supply chains: the role of cooperatives","content":"Cocoa farmer cooperatives act as procurement intermediaries that align informal farmer practices with global market requirements. Findings reveal cooperatives mitigate risks, stabilize supply chains, and foster supplier innovation and sustainability via trust-based governance and resource pooling. The study offers insights into leveraging informal networks for sustainable procurement across agri-supply chains.","presenter":"Dr. Ghadafi Razak","authors":[{"name":"Dr. Ghadafi Razak","aff":"Post Doc/Researcher, Warwick Business School"}],"order":4}]},{"id":"s74","title":"Circular &amp; Sustainable Supply Chains","track":"Sustainable Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY G","chairs":["Dr. Erin McKie"],"abstracts":[{"id":"136-1608","title":"Examining the Cost Impact of the German Supply Chain Due Diligence Act","content":"In 2023, the German government enacted stringent legislation requiring firms with more than 3K employees to conduct extensive due diligence on their supply chains. Affected firms criticized the associated cost burden and disadvantages vis-à-vis international competitors. We empirically investigate the effects of the German supply chain legislation on affected firms.","presenter":"Prof. Julia Hartmann","authors":[{"name":"Prof. Julia Hartmann","aff":"Professor, European Business School"},{"name":"Prof. H. Sebastian Heese","aff":"Professor, North Carolina State University"},{"name":"Prof. Tim Kraft","aff":"Associate Professor, North Carolina State University"},{"name":"Prof. Shawn Mankad","aff":"Associate Professor, North Carolina State University"}],"order":1},{"id":"136-1629","title":"Improving Recycling Quality through AI &amp; Green Nudges: Evidence from a Field Experiment","content":"Recycling is a critical waste management process; however, its efficacy is frequently limited by quality issues stemming from consumer behaviors. Through a field experiment, we leverage AI technology to administer green nudges to improve recycling behaviors of 7,600 households in a Midwest community.","presenter":"Dr. Erin McKie","authors":[{"name":"Dr. Erin McKie","aff":"Assistant Professor, Ohio State University"},{"name":"Prof. Aravind Chandrasekaran","aff":"Professor, Ohio State University"},{"name":"Mr. Nikhil Sharma","aff":"Student, Ohio State University"}],"order":2},{"id":"136-1635","title":"VR-Aided Transparency in Zero Waste Management","content":"Many zero waste programs worldwide face challenges achieving their goals due to low resident engagement. This study uses a field experiment to examine how policymakers and firms can effectively leverage virtual reality-aided transparency to encourage sustainable behavioral change, fostering greater resident participation and success in zero waste programs.","presenter":"Prof. Necati Ertekin","authors":[{"name":"Prof. Necati Ertekin","aff":"Associate Professor, University of Minnesota"},{"name":"Prof. Atalay Atasu","aff":"Professor, INSEAD"},{"name":"Prof. Amitava Chattopadhyay","aff":"Professor, INSEAD"},{"name":"Prof. Luk Van Wassenhove","aff":"Professor, INSEAD"}],"order":3},{"id":"136-1739","title":"Electrifying Away Climate Change: Heat Pumps’ and Installation Capacity’s Effect on Emissions and Grid Load","content":"Heat pump purchases are lower than needed to decarbonize home heating, in part due to limited installation capacity. Moreover, heat pumps’ high electricity demand may cause blackouts. Using a dynamic model parameterized to Massachusetts, we explore subsidies for consumers and for contractor training to spur adoption while limiting grid load.","presenter":"Mr. Alexander Kuptel","authors":[{"name":"Mr. Alexander Kuptel","aff":"Student, MIT Sloan School of Management"},{"name":"Prof. John Sterman","aff":"Professor, MIT Sloan School of Management"}],"order":4}]},{"id":"s79","title":"Strategic Pathways in Entrepreneurship, Branding, and Standardization","track":"Product Innovation and Technology Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"COURTLAND","chairs":["Prof. Junghee Lee"],"abstracts":[{"id":"136-0055","title":"Look Before You Leap? An Operational Analysis of Hybrid Entrepreneurship","content":"In this paper, we investigate the ongoing debate between fully committed entrepreneurship and the hybrid approach. To compare the merits of these two approaches, we develop a model where the entrepreneur's learning is proportional to their exploration effort. We derive the optimal allocation of effort for entrepreneurs.","presenter":"Mr. Zeya Wang","authors":[{"name":"Mr. Zeya Wang","aff":"Assistant Professor, University of Dayton"},{"name":"Dr. Morvarid Rahmani","aff":"Associate Professor, Georgia Institute of Technology"},{"name":"Dr. Karthik Ramachandran","aff":"Professor, Georgia Institute of Technology"}],"order":1},{"id":"136-1424","title":"Governance Structures in SSOs and Firm Strategy","content":"This study explores how the governance structures of Standard-Setting Organizations (SSOs) influence strategic patenting behavior, focusing on the impact of decision-making mechanisms on firm collaboration versus competition. By analyzing various SSO governance models, we provide insights into how these structures shape patent strategies and drive the evolution of technology standards.","presenter":"Dr. Yang Yang","authors":[{"name":"Prof. Junghee Lee","aff":"Assistant Professor, University of Notre Dame"},{"name":"Dr. Yang Yang","aff":"Assistant Professor, University of Notre Dame"}],"order":2},{"id":"136-0331","title":"Darkside of Knowledge Spillover via Common Suppliers: An Empirical Investigation","content":"We examine empirically unintended knowledge spillover between competitors via their common suppliers using buyer supplier network data from FactSet. This analysis is important as firms may invest in suppliers who could be linked to their rivals also. Therefore, it is critical to devise strategies to reduce instance of such spillover.","presenter":"Mr. Nitin Jain","authors":[{"name":"Mr. Nitin Jain","aff":"Student, IIM Udaipur"},{"name":"Dr. Anirban Adhikary","aff":"Associate Professor, IIM Udaipur"},{"name":"Dr. Sreejith Kumar Krishnakumar","aff":"Assistant Professor, Indian Institute of Management Udaipur"},{"name":"Prof. Sourav Bikash Borah","aff":"Assistant Professor, IIM Ahmedabad"}],"order":3},{"id":"136-1006","title":"The Impact of Dual Conceptualizations of Brand Equity on Radical Product Launch Strategy","content":"This paper explores how a market challenger should launch a radical innovation to surpass a market leader’s product, factoring in consumer's heterogenous brand equity perceptions. Using a game-theoretic model, we derive insights into how differing brand equity conceptualizations and the leader’s adaptability in brand equity influence the challenger’s launch strategy.","presenter":"Prof. Junghee Lee","authors":[{"name":"Prof. Junghee Lee","aff":"Assistant Professor, University of Notre Dame"},{"name":"Dr. Mallapragada Girish","aff":"Associate Professor, Indiana University"},{"name":"Dr. Daewon Sun","aff":"Professor, University of Notre Dame"},{"name":"Dr. Dennis Yu","aff":"Associate Professor, Clarkson University"}],"order":4}]},{"id":"s93","title":"Social Responsibility in Behavioral Operations","track":"Behavioral Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY D","chairs":["Prof. Leon Valdes","Mr. Gabriel Pensamiento"],"abstracts":[{"id":"136-0404","title":"Selection, Payment, and Information Assessment in Social Audits: A Behavioral Experiment","content":"Through an incentivized experiment, we study how social audits are influenced by being paid and/or chosen by the audited party in a context of noisy information. We find evidence for more lenient decisions when auditors are chosen, while being paid has no effect. We also observe evidence of reciprocity.","presenter":"Mr. Gabriel Pensamiento","authors":[{"name":"Mr. Gabriel Pensamiento","aff":"Student, University of Pittsburgh"},{"name":"Prof. Leon Valdes","aff":"Associate Professor, University of Pittsburgh"}],"order":1},{"id":"136-0719","title":"Highway happiness or road rage? Daily goal-disruptive events, communication dynamics, and fuel consumption","content":"We examine truck drivers' emotional reactions to goal-disruptive events and resulting fuel consumption in a multisource data set combining an experience sampling survey of truck drivers’ daily emotions across four weeks, archival electronic messaging information on driver-dispatcher communication, and onboard computer data recordings of driving behavior.","presenter":"Prof. Prisca Brosi","authors":[{"name":"Prof. Prisca Brosi","aff":"Associate Professor, Kuehne Logistics University"},{"name":"Prof. Wladislaw Rivkin","aff":"Associate Professor, TRINITY COLLEGE DUBLIN"},{"name":"Prof. Henrik Leopold","aff":"Professor, Kühne Logistics University"},{"name":"Prof. Jason Shaw","aff":"Professor, Nanyang Technological University"},{"name":"Prof. Jan Fransoo","aff":"Professor, Tilburg University"}],"order":2},{"id":"136-0383","title":"Designing Effective Fundraising Campaigns: Behavioral Insights","content":"This study examines how fundraisers maximize donations under budget constraints, focusing on financial incentives (matching or gift unlock) and solicitation methods (simultaneous or sequential). Using a game-theoretic model and laboratory experiments, we provide insights into effective fundraising strategies and behavioral deviations in donor responses.","presenter":"Mr. Pramit Ghosh","authors":[{"name":"Dr. Ignacio Rios Uribe","aff":"Assistant Professor, UT Dallas"},{"name":"Dr. Anyan Qi","aff":"Associate Professor, University of Texas Dallas"},{"name":"Mr. Pramit Ghosh","aff":"Student, University of Texas at Dallas"}],"order":3},{"id":"136-1288","title":"More than \"how do you do?\" - Detailed empirical neuroscience experiment insights into worker well-being","content":"With human-centric Industry 5.0 objectives, well-being has garnered attention. Yet, detailed measures for this evanescent concept are scarce. We provide new suggestions with neuroscience experiment insights from a lab assembly workplace, adopting cortical and cardiac measures and comparing them to self-reported evaluations of workload and stress, alongside behavioural data.","presenter":"Prof. Rachna Shah","authors":[{"name":"Prof. Matthias Klumpp","aff":"Associate Professor, Politecnico Di Milano"},{"name":"Prof. Marco Mandolfo","aff":"Assistant Professor, Politecnico Di Milano"},{"name":"Prof. Charles Corbett","aff":"Professor, UCLA Anderson School of Management"},{"name":"Prof. Rachna Shah","aff":"Professor, University of Minnesota"},{"name":"Dr. Arnd Meiser","aff":"Post Doc/Researcher, Universität Oldenburg"}],"order":4}]},{"id":"s106","title":"Decision Support for Humanitarian Operations","track":"Humanitarian Operations and Crisis Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"GRAND HALL EAST B","chairs":["Dr. Jarrod Goentzel"],"abstracts":[{"id":"136-1686","title":"\"Comparative Analysis of Medical Countermeasure Distribution Channels During Health Emergencies: Mexico and the United States\"","content":"This study analyzes medical countermeasure distribution channels during COVID-19 in Mexico and the United States, focusing on service capacity, process flow, and resource utilization. Using qualitative analysis, discrete event simulation, and queuing theory, it identifies bottlenecks and capacities, offering insights to optimize future distribution strategies for health emergencies globally.","presenter":"Ms. Marisol Romero Mancilla","authors":[{"name":"Ms. Marisol Romero Mancilla","aff":"Student, Monterrey Institute of Techonology and Higher Education"},{"name":"Dr. Jarrod Goentzel","aff":"Post Doc/Researcher, Massachusetts Institute of Technology"},{"name":"Prof. Angel Ruiz","aff":"Professor, Universite Laval"}],"order":1},{"id":"136-1695","title":"Improving supply chain network resilience: A framework for diagnosing vulnerabilities to identify adaptation strategies","content":"We investigate the resilience of supply chain distribution networks through a three-step methodological approach that involves: 1) realistic network generation, using first design principles, 2) network disruption, and 3) network evaluation. We conclude by highlighting the pivotal role of network structures in preserving network robustness and unveil potential adaptation strategies.","presenter":"Ms. Chelsey Graham","authors":[{"name":"Ms. Chelsey Graham","aff":"Student, MIT"},{"name":"Dr. Jarrod Goentzel","aff":"Post Doc/Researcher, Massachusetts Institute of Technology"},{"name":"Prof. Ozlem Ergun","aff":"Professor, Northeastern University"}],"order":2},{"id":"136-0847","title":"Interplay of Autonomy Frustration and Calling: Effects on Coordination and Performance in Humanitarian Organizations","content":"Coordination within humanitarian organizations is hindered by autonomy frustration. Interviews and surveys reveal that practitioners with a strong sense of calling better manage these frustrations, reducing negative impact on coordination and operational performance. From behavioral operations perspective, addressing autonomy issues and hiring for calling are crucial for improving intra-organizational coordination.","presenter":"Dr. Mojtaba Salem","authors":[{"name":"Dr. Mojtaba Salem","aff":"Assistant Professor, Kühne Logistics University"},{"name":"Prof. Niels Van Quaquebeke","aff":"Professor, Kuehne Logistics University"},{"name":"Prof. Lea Ruesch","aff":"Assistant Professor, IE BUSINESS SCHOOL"},{"name":"Prof. Maria Besiou","aff":"Professor, Kuehne Logistics University"}],"order":3},{"id":"136-1596","title":"Healthcare supply chain resilience to surges in demand","content":"When medical emergencies create sudden surges in the demand for medical supplies, it is crucial to respond rapidly. We use a simulation model to explore the effectiveness of several strategies for increasing supply chain responsiveness. We find that substitute products are more effective than increasing inventory.","presenter":"Dr. Erica Gralla","authors":[{"name":"Mr. Matthew Beigh","aff":"Student, George Washington University"},{"name":"Dr. Erica Gralla","aff":"Associate Professor, George Washington University"}],"order":4}]},{"id":"s111","title":"Platform Bias, Delivery, &amp; Strategy","track":"Empirical Research in Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY B","chairs":["Prof. Hailong Cui"],"abstracts":[{"id":"136-0103","title":"Dynamic Discrimination on Online Learning Platforms","content":"Using data from a major online learning platform, we find that racial discrimination increases over time as new users remain active and repeatedly engage with the platform. The growing discrimination is primarily driven by the reinforcement of initial discrimination through accumulating lower reputation metrics and a smaller repeat customer base.","presenter":"Ms. Peibo Zhang","authors":[{"name":"Ms. Peibo Zhang","aff":"Student, Emory University"},{"name":"Prof. Xinyu Cao","aff":"Associate Professor, Chinese Univ of Hong Kong"},{"name":"Prof. Dennis Zhang","aff":"Associate Professor, Washington University in St. Louis"},{"name":"Prof. Ruomeng Cui","aff":"Professor, Emory University"}],"order":1},{"id":"136-0264","title":"Flattening the Curve? On-Demand Delivery Platforms and Customer Visits to Restaurants","content":"This empirical paper investigates how online food delivery influences demand patterns in the context of restaurants. We introduce methods to quantify the demand patterns and identify the antecedents that shape the demand curve.","presenter":"Dr. Yixuan Liu","authors":[{"name":"Dr. Yixuan Liu","aff":"Assistant Professor, Chinese Europe International Business School"},{"name":"Dr. Zhuoxin (Allen) Li","aff":"Associate Professor, University of Wisconsin-Madison"}],"order":2},{"id":"136-0638","title":"Unpacking the Value of On-demand Delivery on Retail Success","content":"Retailers have been increasingly providing on-demand delivery services to better satisfy consumers. When a retailer cannot offer on-demand delivery by itself, is it worth obtaining such service through a third-party platform? We conduct an empirical analysis to explore these partnerships' impacts on retailers' financial and operational performance","presenter":"Ms. Yawen Zheng","authors":[{"name":"Ms. Yawen Zheng","aff":"Student, Ohio State University"},{"name":"Dr. Xiang Wan","aff":"Associate Professor, Ohio State University"}],"order":3},{"id":"136-0693","title":"A Data-driven Bundling Strategy for Crowd-sourced Logistics","content":"We propose a data-driven bundling strategy for crowd-sourced logistics, addressing low acceptance rates by modeling driver choice behaviors and substitution effects. Reformulated into scalable optimization approaches, our method improves acceptance rates by 39.72% in a Southeast Asia case study, enhancing delivery efficiency and service quality.","presenter":"Dr. Jiachen Wei","authors":[{"name":"Dr. Jiachen Wei","aff":"Post Doc/Researcher, Michigan State University"},{"name":"Prof. Stanley Lim","aff":"Assistant Professor, Michigan State University"},{"name":"Dr. XIAOBO LI","aff":"Assistant Professor, National University of Singapore"}],"order":4}]},{"id":"s127","title":"Improving pharmaceutical supply chains","track":"Operational Excellence","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"BAKER","chairs":["Dr. Hanu Tyagi"],"abstracts":[{"id":"136-1807","title":"Does production location impact medication quality? An empirical study on the effectiveness variations","content":"While global production offers promising avenues for cost reduction, it also introduces challenges in maintaining consistent quality standards. Our study offers insights for regulatory bodies on optimizing inspection procedures and ensuring consistent quality control across borders to safeguard public health.","presenter":"Prof. Xinyu Liang","authors":[{"name":"Prof. Xinyu Liang","aff":"Assistant Professor, INSEAD"},{"name":"Prof. Jun Li","aff":"Associate Professor, University of Michigan Ann Arbor"},{"name":"Prof. In Joon Noh","aff":"Assiatnt Professor, Korea University"}],"order":5}]},{"id":"s131","title":"Improving Healthcare Operations","track":"Operational Excellence","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"BAKER","chairs":["Dr. Yingchao Lan"],"abstracts":[{"id":"136-0782","title":"Early Intervention for Chronic Pain: Reducing Surgeries, Opioid Use, and Healthcare Costs","content":"Chronic pain is an increasing public health concern. It affects an estimated 50 million adults in the United States each year and contributes to substantial healthcare costs and lost productivity. we explore whether early intervention by pain management specialists can reduce unnecessary surgeries, opioid prescriptions, and overall healthcare costs.","presenter":"Mr. Buyun Li","authors":[{"name":"Mr. Buyun Li","aff":"Student, Indiana University"},{"name":"Dr. Mohammad Zhalechian","aff":"Assistant Professor, Kelley School of Business, Indiana Univ."},{"name":"Dr. Christopher Chen","aff":"Assistant Professor, Indiana University Bloomington"},{"name":"Prof. Jonathan Helm","aff":"Professor, Kelley School of Business"}],"order":1},{"id":"136-1567","title":"Legislation Driven Interorganizational Knowledge Spillovers–An Empirical Investigation of the Quality Payment Program","content":"This study delves into the efficacy of legislative actions in driving broader changes beyond targeted organizations, facilitated by shared-personnel-enabled interorganizational spillovers of related knowledge, which covers a wide spectrum of knowledge that is not directly associated with an individual’s area of expertise.","presenter":"Dr. Yingchao Lan","authors":[{"name":"Dr. Mengyang Pan","aff":"Associate Professor, Southwestern University of Finance and Economics"},{"name":"Dr. Luv Sharma","aff":"Associate Professor, University of South Carolina"},{"name":"Dr. Yingchao Lan","aff":"Associate Professor, University of Nebraska Lincoln"}],"order":2},{"id":"136-1571","title":"Becoming Strategically Ready for Lean Healthcare Deployment: A Multiple Case Study","content":"We present a descriptive exploratory study of a novel conceptualization of lean management by examining what becoming strategically ready for lean management deployment in healthcare entails. We advance scholarly theorization and practice understanding of lean management deployment competence defined by structural and functional capabilities.","presenter":"Dr. Fernando Naranjo","authors":[{"name":"Dr. David Barrett","aff":"Assistant Professor, Ivey Business School, Western University"},{"name":"Dr. Fernando Naranjo","aff":"Assistant Professor, Niagara University"},{"name":"Dr. Larry Menor","aff":"Associate Professor, Ivey Business School, Western University"}],"order":3}]},{"id":"s145","title":"Data-Driven Strategies for Optimization, Transparency, and Consumer Trust","track":"Disruptive Technologies and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"KENNESAW","chairs":["Mr. Feiteng Huang"],"abstracts":[{"id":"136-0923","title":"Beyond Required Disclosure: How Self-Revealed Vulnerability in Sustainability Practices Shapes Consumer Perceptions of Apparel Brands.","content":"This study investigates how transparency in sustainability reporting influences consumer behavior by examining whether apparel brands that disclose both achievements and shortcomings in environmental and social practices gain more consumer favor than those practicing selective disclosure. The research explores effects on trust, quality perception, purchase intention, and willingness to pay.","presenter":"Ms. Amolwan Jittamai","authors":[{"name":"Ms. Amolwan Jittamai","aff":"Student, University of Houston"},{"name":"Dr. Ravi Aron","aff":"Professor, University of Houston"}],"order":1},{"id":"136-1052","title":"Dynamic Substitution Strategies for Perishable Products in Food Retailing","content":"Dynamic substitution strategies in food retail optimize the allocation of perishable products under uncertain demand. Our model periodically determines order quantities and product allocation, maximizing revenues while accounting for future profits. Using real-world retailer data, numerical studies validate its effectiveness in maximizing revenues and managing perishables efficiently.","presenter":"Ms. Ke Sun","authors":[{"name":"Ms. Ke Sun","aff":"Post Doc/Researcher, McGill University"},{"name":"Prof. Yichuan Ding","aff":"Associate Professor, McGill University"},{"name":"Prof. Mehmet Gumus","aff":"Professor, McGill University"}],"order":2},{"id":"136-1245","title":"Strategic A-B Testing","content":"We study A-B testing challenges at the business unit level, including unobserved agent efforts and imperfect control groups. Analyzing levers like soliciting agents’ counterfactual reports and leveraging control groups, we show that under moderate incentive misalignment, relying solely on agents’ reports can yield more accurate estimations than incorporating control groups.","presenter":"Ms. Guoxing He","authors":[{"name":"Ms. Guoxing He","aff":"Student, The University of Hong Kong"},{"name":"Prof. Stefanus Jasin","aff":"Professor, University of Michigan"},{"name":"Dr. Wei Zhang","aff":"Associate Professor, Hong Kong University"}],"order":4}]},{"id":"s147","title":"IS-OM Interface Research","track":"Information Systems and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY E","chairs":["Mr. Xinzhi Rao"],"abstracts":[{"id":"136-0649","title":"App Store Restriction and Content Supply","content":"We investigate the impact of the App Store's new improvement restrictions on app update behavior, as well as their subsequent effects on downloads and ratings. Our findings reveal that stricter improvement restrictions lead to an increase in app updates but may result in a decrease in ratings.","presenter":"Ms. Jingyan Dai","authors":[{"name":"Ms. Jingyan Dai","aff":"Student, University of Florida"},{"name":"Mr. Qili Wang","aff":"Student, University of Florida"},{"name":"Ms. Shu He","aff":"Assistant Professor, University of Florida"},{"name":"Prof. Liangfei Qiu","aff":"Professor, University of Florida"}],"order":1},{"id":"136-1155","title":"The Impact of Amazon’s Wholesale Program on Seller Revenue","content":"We examine how third-party sellers’ participation in Amazon’s wholesale program affects their sales volume and revenue. We employ difference-in-differences method to assess impact of participation in wholesale program. Our results indicate involvement in Amazon’s wholesale initiative is associated with a significant reduction in both sales volume and sales.","presenter":"Mr. Xinzhi Rao","authors":[{"name":"Mr. Xinzhi Rao","aff":"Student, University of Florida"},{"name":"Prof. Yuan Sun","aff":"Professor, Zhejiang Gongshang University"},{"name":"Prof. Liangfei Qiu","aff":"Professor, University of Florida"}],"order":2},{"id":"136-0468","title":"Sequential Consumer Options: Modeling Return Periods and Delayed Trade-in Opportunities","content":"This paper examines the strategic implications of offering consumers sequential recovery options: returns followed by trade-ins. We model how window-lengths among these options affect consumer decision-making and the potential for retailer profit maximization.","presenter":"Mr. Yorick Sanders","authors":[{"name":"Mr. Yorick Sanders","aff":"Student, Texas Tech University"},{"name":"Prof. Sumanta Singha","aff":"Assistant Professor, Texas Tech University"}],"order":4},{"id":"136-1207","title":"Shielding Wallets with Firewalls: How Privacy Laws Induce Public Finance Costs","content":"We quantify the economic value of privacy, finding that state privacy laws raise municipal borrowing costs, especially in counties with data breaches, higher education, and business presence. These laws negatively impact local economies, and we advocate for technology-driven privacy solutions using privacy-enhancing technologies as a superior alternative.","presenter":"Ms. Shu He","authors":[{"name":"Ms. Qianqian Zhuang","aff":"Student, HKUST"},{"name":"Dr. Yanzhen Chen","aff":"Assistant Professor, HKUST"},{"name":"Ms. Shu He","aff":"Assistant Professor, University of Florida"}],"order":5}]},{"id":"s158","title":"Using Analytics to Improve Healthcare Delivery","track":"Healthcare Analytics","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"GRAND HALL EAST D","chairs":["Dr. Claudia Rosales"],"abstracts":[{"id":"136-1421","title":"Medical Countermeasures During Public Health Emergencies - Does Information Sharing Among Health System Coalition Help?","content":"Hospitals face challenges managing capacity during public health emergencies. This study examines the impact of treatment-based countermeasures and health registry participation on hospital capacity, highlighting how adaptive strategies and information-sharing improve resource efficiency and inform policies for healthcare delivery during crises.","presenter":"Dr. Sukrit Pal","authors":[{"name":"Dr. Sukrit Pal","aff":"Assistant Professor, Iowa State University"},{"name":"Prof. Anand Nair","aff":"Professor, Northeastern University"}],"order":1},{"id":"136-1475","title":"Can Free Clinics Improve Hospitals’ Profits? A Seemingly Paradox","content":"In this study, we investigate the profitability of hospitals in the United States that operate indigent care clinics. First, we ask whether a greater extent of indigent care services leads to a higher degree of profitability. Next, we explore the mechanisms underlying this seemingly paradoxical relationship.\r\n","presenter":"Dr. Mei Li","authors":[{"name":"Dr. Mei Li","aff":"Associate Professor, University of Oklahoma"}],"order":2},{"id":"136-1514","title":"Mitigation Strategies for Critical Supply Chains","content":"We study how hospital purchasing practices can help or hinder recovery efforts during severe disruptions. Using hospital data between 2018 - 2021 we study the effect of order variability and market share on suppliers’ fill rate. Our research provides insights that can help inform purchasing practices amid severe disruptions.","presenter":"Dr. Claudia Rosales","authors":[{"name":"Dr. Claudia Rosales","aff":"Assistant Professor, University of Arkansas - Fayetteville"},{"name":"Dr. Andrew Balthrop","aff":"Assistant Professor, University of Arkansas"},{"name":"Dr. David Dobrzykowski","aff":"Professor, University of Arkansas - Fayetteville"}],"order":3},{"id":"136-1616","title":"A Bayesian State Space Model for Managing Demand Surges in the Emergency Department","content":"This research develops a Bayesian state space model for forecasting emergency department (ED) arrivals. The proposed method outperforms traditional methods, especially during demand surges. The full distributional forecast, available in closed form, supports providing probabilistic statements about potential crowding events in real time.","presenter":"Dr. David Rea","authors":[{"name":"Dr. David Rea","aff":"Assistant Professor, Lehigh University"},{"name":"Dr. Karou Irie","aff":"Associate Professor, University of Tokyo"},{"name":"Dr. Tevfik Aktekin","aff":"Professor, University of New Hampshire"}],"order":4}]},{"id":"s176","title":"New Frontiers in Agricultural Operations","track":"Agriculture and Food Supply Chains","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"VININGS","chairs":["Prof. Felix Papier","Dr. Canberk Ucel"],"abstracts":[{"id":"136-1383","title":"The impact of government input and output subsidies on income inequality among risk-averse farmers","content":"We develop models to analyze the impact of input and output farm subsidies on risk-averse farmers and the government. Interestingly, both types of subsidies reduce overall income inequality as measured by the Gini coefficient. However, they lead to an increased income disparity among farmers with heterogeneous resources.","presenter":"Ms. cheng huang","authors":[{"name":"Ms. cheng huang","aff":"Student, Harbin Institute of Technology"},{"name":"Prof. Guangxin Jiang","aff":"Professor, Harbin Institute of Technology"}],"order":1},{"id":"136-0525","title":"Managing Operations of a Hog Farm Facing Volatile Markets: Inventory and Selling Strategies","content":"We study the optimal selling strategy for a dynamic finishing stage planning problem of a pork producer who, at the beginning of each week, must decide what hogs to sell to a meatpacker, on the open market, and what hogs to hold until the following week.","presenter":"Prof. Ye Liu","authors":[{"name":"Prof. Panos Kouvelis","aff":"Professor, Washington University in St. Louis"},{"name":"Prof. Ye Liu","aff":"Assistant Professor, Syracuse University"},{"name":"Prof. Aaron (Yunzhe) Qiu","aff":"Assistant Professor, Peking University"},{"name":"Prof. Danko Turcic","aff":"Associate Professor, University of California Riverside"}],"order":2},{"id":"136-1848","title":"The Role and Impact of Farmer Producer Organizations on Farmer and Consumer Welfare","content":"We explore how farmer producer organizations (FPOs) like cooperatives impact the income of small farmers along with the availability of a crop to consumers. We identify the conditions under which the FPOs can be efficient in achieving their intended objectives.","presenter":"Prof. Prashant Chintapalli","authors":[{"name":"Prof. Prashant Chintapalli","aff":"Assistant Professor, Ivey Business School"},{"name":"Prof. Christopher Tang","aff":"Professor, University of California Los Angeles"}],"order":4},{"id":"136-0772","title":"Improving Farm Practices and Productivity Through Expert Advice","content":"This study investigates the role of geographic proximity to expert agricultural extension agents in improving practice diffusion and productivity among smallholder farms. Using data from 1,998 farms in the Philippines, we find that proximity enhances adoption of effective practices and boosts productivity by 36%, with significant social and economic benefits.","presenter":"Dr. Canberk Ucel","authors":[{"name":"Dr. Canberk Ucel","aff":"Assistant Professor, ESSEC Business School"},{"name":"Prof. Diwas KC","aff":"Professor, Emory University"}],"order":6}]},{"id":"s189","title":"Advancing Service Operations: Insights into Consumer and Worker Behavior","track":"Service Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY C","chairs":["Dr. Li Ding"],"abstracts":[{"id":"136-0332","title":"Impact of Requested Pick-up Time on On-Demand Last-Mile Delivery","content":"This study investigates the impact of restaurant pick-up deadline on on-demand food delivery drivers’ earnings and service quality, using proprietary data from a Korean food delivery outsourcing firm. The paper explores how firm’s deadline policies influence the drivers’ batching decision, which drives their earnings and service quality.","presenter":"Dr. Jaeyoung Kim","authors":[{"name":"Dr. Kevin Park","aff":"Assistant Professor, University of Dayton"},{"name":"Dr. Jaeyoung Kim","aff":"Assistant Professor, University of Dayton"},{"name":"Dr. Mark Jacobs","aff":"Professor, University of Dayton"},{"name":"Dr. Suhyung Lee","aff":"Senior reseaecher, Korea Airports Corp."}],"order":1},{"id":"136-0598","title":"Too Good To Waste: Reducing Food Waste Through Markdown Platforms","content":"This paper examines online food markdown platforms’ impact on profitability and sustainability. Using a game-theoretical model, we show that while markdown platforms typically enhance profitability for restaurants over discarding food, they can lead to increased food waste under certain conditions.","presenter":"Ms. Linghui Feng","authors":[{"name":"Ms. Linghui Feng","aff":"Student, Boston University"},{"name":"Prof. Pnina Feldman","aff":"Associate Professor, Darden School of Business"},{"name":"Prof. Robert Swinney","aff":"Associate Professor, Duke University Durham"}],"order":2},{"id":"136-1382","title":"Ka-Ching: The Impact of Cash-on-Delivery on Drivers’ Behavior","content":"Cash on Delivery (COD) is a popular payment method on delivery platforms. While COD may offer benefits for drivers by providing immediate access to liquid cash, it potentially increases risks associated with cash management. We explore COD's impact on workers' platform engagement and its broader implications for platforms.","presenter":"Dr. Li Ding","authors":[{"name":"Dr. Saharsh Agarwal","aff":"Assistant Professor, Indian School of Business"},{"name":"Dr. Vivek Choudhary","aff":"Assistant Professor, Nanyang Technological University"},{"name":"Dr. Li Ding","aff":"Assistant Professor, Nanyang Technological University"}],"order":3},{"id":"136-1437","title":"Conspicuous Consumption in Resale and Rental Markets","content":"We uncover the optimal channel portfolio of a conspicuous supplier, considering the factors of exclusivity and conformity effects of snobs and followers respectively. We find the coexistence of the two markets enlarges the market size, and creates a win-win-win situation for the supplier, snobs, and followers alike.","presenter":"Prof. Gang Li","authors":[{"name":"Mr. Di Wu","aff":"Student, Xi'An Jiaotong University"},{"name":"Prof. Gang Li","aff":"Professor, Xi'an Jiaotong University"},{"name":"Dr. Xiajun Pan","aff":"Associate Professor, University of Florida"}],"order":4}]},{"id":"s203","title":"Assortment, Shelf Space, and Promotion Planning","track":"Retail Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"FAIRLIE","chairs":["Prof. Aditya Jain"],"abstracts":[{"id":"136-0603","title":"Personalized Promotion Planning with Strategic Customers","content":"We study the personalized promotion planning problem of a retailer who faces strategic, repeat customers. We modify the reward of a contextual bandit algorithm to reflect how promotions influence future demand heterogeneously across customers. Our approach extends the personalized dynamic pricing literature by integrating strategic consumer behaviors like stockpiling.","presenter":"Dr. Ozge Yapar","authors":[{"name":"Dr. Chloe Glaeser","aff":"Assistant Professor, Kenan-Flagler Business School"},{"name":"Dr. Ozge Yapar","aff":"Assistant Professor, Indiana University Bloomington"}],"order":1},{"id":"136-1050","title":"Joint shelf design and space planning problem with placement types","content":"This presentation addresses shelf space allocation on perforated racks where products can be hung and/or shelved, affecting product dimensions. A linear program and a matheuristic have been developed to optimize layouts for maximum profit. Case studies demonstrate the efficiency of both approaches and provide valuable managerial insights.","presenter":"Dr. Sandra Zajac","authors":[{"name":"Dr. Sandra Zajac","aff":"Post Doc/Researcher, Cath. University Eichstaett Ingolstadt"},{"name":"Prof. Heinrich Kuhn","aff":"Professor, Cath. University Eichstaett Ingolstadt"}],"order":2},{"id":"136-0763","title":"Personalized Assortment Planning in Distribution Channels with Demand Learning Considerations","content":"This work presents an analytical framework for optimizing a distributor's product assortment catalog for individual small retailers. Retailers make repeated purchases, learning about consumer demand in a Bayesian manner. The model captures the distributor's tradeoff between retaining retailers and mitigating the risk of product substitution leading to lower margins.","presenter":"Dr. Yulia Vorotyntseva","authors":[{"name":"Dr. Yulia Vorotyntseva","aff":"Assistant Professor, University of St. Thomas"}],"order":3},{"id":"136-1895","title":"Store-Wide Shelf Space Planning with Health Considerations","content":"Epidemics like COVID-19 highlighted the importance of safety in public spaces. We address shelf-space allocation in a grocery store via a nonlinear integer program that allocates product categories to shelves in a way that minimizes traffic density, and reduce infections. Queueing theory is used in formulating the health metrics.","presenter":"Dr. Bacel Maddah","authors":[{"name":"Dr. Bacel Maddah","aff":"Professor, American University of Beirut"},{"name":"Prof. Ahmed Ghoniem","aff":"Professor, University of Massachusetts Amherst"},{"name":"Dr. Tulay Flamand","aff":"Assistant Professor, University of Colorado Denver Business School"}],"order":4}]},{"id":"s210","title":"Emerging Analytics: Green Innovation and Uncertainty","track":"Digital Platforms, Innovations and Transformations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"GREENBRIAR","chairs":["Dr. Jafar Namdar"],"abstracts":[{"id":"136-0275","title":"Enhancing Collaboration over Blockchain adoption for combating counterfeit electronics","content":"This study uses evolutionary game theory to examine blockchain adoption in remanufacturing, addressing transparency challenges and counterfeit risks. It analyzes the dynamics between OEMs and platforms, highlighting internal and external factors influencing a sustainable blockchain consortium for improved traceability in electronic product remanufacturing.","presenter":"Ms. Sahar Ebrahimi Bajgani","authors":[{"name":"Ms. Sahar Ebrahimi Bajgani","aff":"Student, WORCESTER POLYTECHNIC INSTITUTE"},{"name":"Mr. Davoud Hosseinnezhad","aff":"Student, University of Limerick"},{"name":"Dr. Sara Saberi","aff":"Assistant Professor, Worcester Polytechnic Institute"},{"name":"Prof. Fuminori Toyasaki","aff":"Professor, York University"}],"order":1},{"id":"136-0353","title":"Global Supply Chains Rewired: Adapting to Disruptive Events","content":"This research uses stochastic actor-oriented models to analyze the evolution of the global supply chain network across different years. We study how various company features (location or financial performance) explain the way companies choose with their business partners before, during, and after disruptive events like the COVID-19 pandemic.","presenter":"Dr. John Rios","authors":[{"name":"Dr. John Rios","aff":"Lecturer, University of Georgia"},{"name":"Mrs. Elaheh seyedalikhani","aff":"Student, University of Iowa"},{"name":"Dr. Kang Zhao","aff":"Professor, University of Iowa"},{"name":"Dr. Suyong Song","aff":"Assistant Professor, University of Iowa"}],"order":2},{"id":"136-0284","title":"Delivery task operational characteristics and driver behaviors","content":"Crowdshipping platforms often face drivers' supply uncertainty, making driver engagement and retention critical success factors. Using the Income Opportunity Effect perspective, we investigate how the operational characteristics of delivery tasks and monetary incentives influence driver behavior. Econometrics analyses on a dataset retrieved from a large US retailer present new insights.","presenter":"Dr. Nicolo Masorgo","authors":[{"name":"Dr. Nicolo Masorgo","aff":"Assistant Professor, Miami University"},{"name":"Dr. David Dobrzykowski","aff":"Professor, University of Arkansas - Fayetteville"},{"name":"Dr. Brian Fugate","aff":"Associate Professor, University of Arkansas - Fayetteville"},{"name":"Prof. Christopher Tang","aff":"Professor, University of California Los Angeles"}],"order":4},{"id":"136-1671","title":"The Green Ripple Effect: Unraveling Green Innovation Diffusion in Supply Chain Networks","content":"This study examines green innovation diffusion in global supply chain networks using 410,000 firm linkages and 2.4 million patents (2010–2020). Employing structural econometrics and spatial causal analysis, findings show firms align with customers' green innovations but reduce internal efforts when suppliers innovate in green, focusing instead on other innovation areas.","presenter":"Mr. Nima Safaei","authors":[{"name":"Mr. Nima Safaei","aff":"Student, University of Illinois at Urbana Champaign"},{"name":"Dr. Jafar Namdar","aff":"Assistant Professor, Michigan State University"},{"name":"Prof. Shagun Pant","aff":"Associate Professor, University of Illinois at Urbana Champaign"},{"name":"Prof. Gautam Pant","aff":"Professor, University of Illinois at Urbana Champaign"}],"order":5},{"id":"136-1591","title":"Effectiveness of Alternative Network Configurations in the Airline Industry under Large-Scale Disruptions","content":"In this study, we focus on analyzing the effectiveness of alternative network configurations in the service industry under large-scale disruptions. Using network data from the US domestic aviation industry, we test the short- and long-term efficacy of alternative network configurations on airline operational performance under disruptions.","presenter":"Mr. Seongwon Park","authors":[{"name":"Mr. Seongwon Park","aff":"Student, Michigan State University"},{"name":"Dr. Chandrasekhar Manchiraju","aff":"Assistant Professor, Michigan State University"},{"name":"Prof. Srinivas Talluri","aff":"Professor, Michigan State University"},{"name":"Dr. Ashutosh Bhave","aff":"Assistant Professor, University of Arkansas"}],"order":6}]},{"id":"s230","title":"Recent Advances in Data-Driven Decision Making","track":"Service Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"INMAN","chairs":["Prof. Divya Singhvi"],"abstracts":[{"id":"136-0979","title":"Target-Following Online Resource Allocation Using Proxy Assignments","content":"We study a target-following variation of online resource allocation. The decision-maker must assign sequentially arriving jobs to a resource, and is penalized for deviating from nonstationary target allocations. The goal is to minimize the total costs incurred. We propose a novel optimal algorithm for this problem.","presenter":"Dr. Chamsi Hssaine","authors":[{"name":"Dr. Chamsi Hssaine","aff":"Assistant Professor, University of Southern California, Marshall School of Business"},{"name":"Prof. Huseyin Topaloglu","aff":"Professor, Cornell University"},{"name":"Prof. Garrett van Ryzin","aff":"Professor, Amazon"}],"order":1},{"id":"136-1096","title":"Heterogeneous Treatment Effects in Panel Data","content":"We introduce a novel method for estimating heterogeneous treatment effects in panel data with general treatment patterns. Our approach is supported by theoretical guarantees, demonstrating convergence to the true treatment effects. Empirical evaluations further show that our method delivers more accurate and interpretable estimates compared to existing alternatives.","presenter":"Ms. Emily Zhang","authors":[{"name":"Prof. Retsef Levi","aff":"Professor, MIT"},{"name":"Dr. Elisabeth Paulson","aff":"Assistant Professor, Harvard Business School"},{"name":"Prof. Georgia Perakis","aff":"Professor, Massachusetts Institute of Technology"},{"name":"Ms. Emily Zhang","aff":"Student, MIT"}],"order":2},{"id":"136-1236","title":"Humans vs. Algorithms: Understanding Student Perceptions of College Applications Recommendations","content":"We investigate student adoption of college application recommendations from algorithmic versus human counselors through a survey-based experiment among high school students. Students preferred human counselors, citing greater trust in their intent and ability. Resistance to algorithms is strongly tied to the norm of \"prestige-chasing\".","presenter":"Mr. Hemanshu Das","authors":[{"name":"Mr. Hemanshu Das","aff":"Student, Yale School of Management"},{"name":"Dr. Sofoklis Goulas","aff":"Research Fellow in Economic Studies, Brookings"},{"name":"Prof. Faidra Monachou","aff":"Assistant Professor, Yale School of Management"}],"order":3},{"id":"136-1516","title":"Discretization, Stability and Robustness","content":"We propose a novel data-driven robust optimization approach avoiding constructing uncertainty sets and linking uncertainties across the feature space through learning stability. This allows for robustness without assuming worst-case scenarios at every observation. We apply this to electricity and inventory problems, achieving solutions five times more robust than existing methods.","presenter":"Mr. Rares Cristian","authors":[{"name":"Mr. Rares Cristian","aff":"Student, Massachusetts Institute of Technology"},{"name":"Prof. Georgia Perakis","aff":"Professor, Massachusetts Institute of Technology"}],"order":4}]},{"id":"s233","title":"Business Innovations Toward Sustainable Prosperity","track":"Supply Chain Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY A","chairs":["Ms. Alys Liang"],"abstracts":[{"id":"136-1661","title":"Bulk versus Sequential Product Returns: Algorithms and Insights for Assortment Planning","content":"In this paper, we present, study and compare two distinct customer choice frameworks crafted to model the step-by-step process through which consumers order products, and then subsequently decide which to keep and which to return based on their realized preferences. We study the classic assortment optimization problem under both models.","presenter":"Mr. Jacob Feldman","authors":[{"name":"Mr. Jacob Feldman","aff":"Associate Professor, Washington University St Louis"},{"name":"Mrs. Sahika Sahan","aff":"Student, Washington University in St. Louis"}],"order":1},{"id":"136-1680","title":"Coordinating Perishable Product Supply Chains","content":"In supply chains, double marginalization creates inefficiencies. Traditional strategies, like increasing order quantities, often fail for perishables due to limited shelf life. Our study extends coordination theories by incorporating perishability and investigating the broader implications for supply chain performance, particularly in relation to food waste reduction.","presenter":"Dr. Xiaoyue Yan","authors":[{"name":"Dr. Xiaoyue Yan","aff":"Assistant Professor, University of Oregon"},{"name":"Prof. Elena Belavina","aff":"Associate Professor, Cornell University"}],"order":2},{"id":"136-1872","title":"Designing Size Inclusive Fashion Assortments","content":"Size stockouts, particularly among plus sizes, are a persistent challenge in fashion retailing, harming both revenue and perceptions of size inclusivity. We develop static assortment optimization algorithms to find profitable yet size inclusive fashion assortments.","presenter":"Mr. Alireza Alavi","authors":[{"name":"Mr. Alireza Alavi","aff":"Student, McGill University"},{"name":"Prof. Mehmet Gumus","aff":"Professor, McGill University"},{"name":"Prof. Javad Nasiry","aff":"Professor, Mcgill University"}],"order":3},{"id":"136-1987","title":"Distributionally Robust Group Testing with Correlation Information","content":"We improve Dorfman’s group testing by incorporating the consideration of correlation between subjects using distributionally robust optimization. In single-cluster settings, large groups are optimal under high correlation, individual testing under high prevalence. In multi-cluster setting, our model prescribes mix pools across clusters, particularly at lower levels of prevalence and correlation.","presenter":"Dr. Aiqi Zhang","authors":[{"name":"Dr. Aiqi Zhang","aff":"Assistant Professor, Wilfrid Laurier University"}],"order":4}]},{"id":"s243","title":"Big Data Analytics, Behavioral Modeling, and Coalition Financing in Supply Chain","track":"Aviation, Transportation, and Logistics Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"UNIVERSITY","chairs":["Dr. Dennis Yu"],"abstracts":[{"id":"136-0612","title":"Modeling Parking Choice Behavior for Shared Autonomous Vehicles Using Multinomial Logit Approach","content":"We investigate intentional parking choice behavior using the Structural Equation Modeling-Multinomial Logit (SEM-MNL) framework to analyze travelers' parking preferences. We find that ride time, travel cost, and parking cost significantly impact parking choices, while the effects of waiting time, cruising cost, and traffic emissions diminish as parking duration increases.","presenter":"Dr. Chen Xiang","authors":[{"name":"Dr. Chen Xiang","aff":"Lecturer, Texas A&amp;M University - Central Texas"},{"name":"Prof. Yong Peng","aff":"Professor, Chongqing Jiaotong University"},{"name":"Dr. Dennis Yu","aff":"Associate Professor, Clarkson University"}],"order":1},{"id":"136-0621","title":"Navigating Supply Chain Disruptions: Big Data Insights from Grocery Retailers during the Pandemic Time","content":"This study analyzes big data from U.S. grocery retailers during COVID-19 to uncover patterns in shortages, price fluctuations, and purchasing behaviors. Coupled with demographic data, it highlights fairness issues in grocery supply during shortages. Recommendations include diversified sourcing, robust inventory management, and addressing inequities to ensure resilience and fairness.","presenter":"Prof. Ram Ganeshan","authors":[{"name":"Prof. Ram Ganeshan","aff":"Professor, College of William &amp; Mary"},{"name":"Prof. Tonya Boone","aff":"Professor, College of William and Mary"},{"name":"Prof. Jing Liang","aff":"Associate Professor, Chengdu University of Technology"},{"name":"Prof. Yu Xia","aff":"Professor, College of William and Mary"}],"order":2},{"id":"136-0010","title":"Analyzing the Value of Coalition Financing","content":"Supply chain participants commonly face capital constraints in practice. Individual financing is popularly applied under various financing programs. However, coordination can be an issue. In this study, we suggest coalition financing and examine its benefits in supply chain coordination and profit improvements. We thus offer guidelines for businesses.","presenter":"Dr. Xun Xu","authors":[{"name":"Prof. Xiaofeng Xie","aff":"Associate Professor, Sichuan University"},{"name":"Dr. Xun Xu","aff":"Associate Professor, California State University Dominguez Hills"},{"name":"Dr. Fengying Zhang","aff":"Professor, Sichuan University"}],"order":3}]},{"id":"s247","title":"AI, Analytics, and Optimization","track":"Data Science, Analytics and AI","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"ROSWELL","chairs":["Mr. Ragip Gurlek"],"abstracts":[{"id":"136-0695","title":"Contextual Data-Integrated Newsvendor Solution with Operational Data Analytics (ODA)","content":"We analyze the inventory decision for an unknown demand that may be learned from historical data of the demand and related covariates. We apply the operational data analytics (ODA) framework to formulate the data-integration model and the validation model. The ODA solution demonstrates superior performance with finite sample size.","presenter":"Mr. Jian Wu","authors":[{"name":"Prof. Qi Feng","aff":"Professor, Purdue University"},{"name":"Prof. George Shanthikumar","aff":"Professor, Purdue University"},{"name":"Mr. Jian Wu","aff":"Student, Purdue University"}],"order":1},{"id":"136-0948","title":"The Dilemma of Design Changes When Hosting Online Events","content":"This study examines the impact of design changes (additional features introduced during event) on user engagement within the context of the r/place event. Findings indicate that while design changes significantly enhance engagement among existing users, they do not affect the engagement of first-time users.","presenter":"Mr. Shizhen Chen","authors":[{"name":"Mr. Shizhen Chen","aff":"Student, Emory University"},{"name":"Prof. Tian Chan","aff":"Associate Professor, Emory University"},{"name":"Prof. Anandhi Bharadwaj","aff":"Professor, Emory University"},{"name":"Mr. Gerald Kane","aff":"Professor, University of Georgia"}],"order":2},{"id":"136-1161","title":"Generative Multi-Task Learning for Customer Base Analysis: Evidence from 1,001 Companies","content":"We introduce the Customer-Based Multi-Task Transformer, a unified generative multi-task learning model for panel data, addressing upstream customer behaviors (acquisition, repeat purchases, spend) and downstream outcomes (cohort/company-level sales). Validated on a dataset of 1,001 companies, It outperforms 14 benchmarks, reducing revenue prediction error by 34%-65% while balancing generalization and specialization.","presenter":"Ms. Kyeongbin Kim","authors":[{"name":"Ms. Kyeongbin Kim","aff":"Student, Emory University"},{"name":"Prof. Daniel McCarthy","aff":"Assistant Professor, Emory University"},{"name":"Prof. Dokyun Lee","aff":"Associate Professor, Boston University"}],"order":3},{"id":"136-1225","title":"A Data-Driven Optimization Framework to Improve Search Advertising Efficiency","content":"Search advertising is a rapidly growing industry, with global spending estimated at $279 billion. This study presents a data-driven optimization framework to improve the search advertising efficiency in higher education marketing, measured by first contacts per advertisement dollar. Leveraging a keyword-day dataset, we examine the decision journeys of prospective students.","presenter":"Mr. Kerim U. Kizil","authors":[{"name":"Mr. Kerim U. Kizil","aff":"Student, Texas A&amp;M University"},{"name":"Dr. Rajiv Mukherjee","aff":"Assistant Professor, Texas A&amp;M University College Station"},{"name":"Prof. Balakrishna Shetty","aff":"Professor, Mays Business School"},{"name":"Prof. Chelliah Sriskandarajah","aff":"Professor, Texas A&amp;M University College Station"},{"name":"Prof. Jon Stauffer","aff":"Associate Professor, Mays Business School, Texas A&amp;M University"}],"order":4}]},{"id":"s250","title":"Perpectives on the Impact of Operations and AI on Society","track":"Operations and Society","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"SPRING","chairs":["Mr. El Ghali Zerhouni"],"abstracts":[{"id":"136-1174","title":"The Narrative AI Advantage? A Field Experiment on Generative AI-Augmented Evaluations of Early-Stage Innovations","content":"Integrating artificial intelligence into innovation evaluation presents unique challenges at the intersection of human judgment and AI capabilities. Through randomized field experiments with MIT Solve's Global Health Equity Challenge (n=228 evaluators), we examine how AI assistance affects screening outcomes.","presenter":"Prof. Léonard Boussioux","authors":[{"name":"Prof. Jacqueline Lane","aff":"Assistant Professor, Harvard Business School"},{"name":"Prof. Léonard Boussioux","aff":"Assistant Professor, University of Washington"},{"name":"Prof. Charles Ayoubi","aff":"Assistant Professor, ESSEC Business School"}],"order":1},{"id":"136-1348","title":"Clustered Multi-Task Learning for Prediction of Adverse Pregnancy Outcomes","content":"In clinical prediction models, combining individual indicators into a composite outcome can help overcome issues associated with single outcomes such as low predictability and low prevalence, but their clinical utility may be limited. We develop an optimization framework to simultaneously cluster related outcomes and learn model parameters for each cluster.","presenter":"Ms. Sun Ju Lee","authors":[{"name":"Ms. Sun Ju Lee","aff":"Student, Georgia Institute of Technology"},{"name":"Dr. Gian-Gabriel Garcia","aff":"Assistant Professor, Georgia Institute of Technology"}],"order":2},{"id":"136-1261","title":"Price Optimization and Food Waste in Secondary Markets - An Empirical Analysis","content":"In the context of the growing market for surplus food, we estimate a structural model of demand using hourly data from Too Good To Go and analyze store entry using an optimization framework. Counterfactual analysis shows that flexible pricing policies can both reduce food waste and enhance store revenue.","presenter":"Ms. Yizhuo Dong","authors":[{"name":"Ms. Yizhuo Dong","aff":"Student, UCLA Anderson School of Management"},{"name":"Prof. Auyon Siddiq","aff":"Assistant Professor, UCLA Anderson School of Management"},{"name":"Prof. Jingwei Zhang","aff":"Assistant Professor, Cornell University"}],"order":3},{"id":"136-2023","title":"Business Processes for Impact: The Operational Model of AIC-Thane","content":"India's focusing on building entrepreneurial ecosystem to achieve the national goal of self-reliance. This paper presents the case study of AIC-Thane (not-for-profit incubator) with the aim to study how its values-driven model and operational processes (startup selection, mentoring, resource allocation, and compliance) are designed to support startups with social impact.","presenter":"Prof. Karuna Jain","authors":[{"name":"Mr. Yuvraj Singh","aff":"Student, Indian Institute of Technology Bombay"},{"name":"Prof. Karuna Jain","aff":"Professor, Indian Institute of Technology Bombay"},{"name":"Dr. Uday Wankawala","aff":"CEO, AIC Thane"}],"order":4}]},{"id":"s255","title":"Digital Economy: Incentives, Technology, and Market Structure","track":"Information Systems and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"AUBURN","chairs":["Dr. Zixuan Meng"],"abstracts":[{"id":"136-2078","title":"Digital Ownership in the Era of Decentralization","content":"Blockchain technology shifts digital markets from mere possession to true ownership,\r\nenabling the resale of digital goods like books and music. This paper develops an analytical\r\nmodel to examine its impact on market outcomes and stakeholder benefits, highlighting\r\ndifferent mechanisms when blockchain is enabled by different agents (creator vs. platform).","presenter":"Dr. Yi Gao","authors":[{"name":"Dr. Yi Gao","aff":"Assistant Professor, Texas Tech University"},{"name":"Dr. Zixuan Meng","aff":"Assistant Professor, The University of Texas at Dallas"},{"name":"Dr. Ming Fan","aff":"Professor, University of Washington"}],"order":1},{"id":"136-2079","title":"Urgent vs. Non-Urgent Inquiries: An Empirical Study of Engaging Voluntary Contributions in Online Communities","content":"Online Q&amp;A platforms connect geographically dispersed users, especially in occupation-\r\nspecific communities like freight drivers. We examine how users respond to urgent and\r\nnon-urgent questions and the effects of platform incentives. Using a Hidden Markov Model,\r\nwe reveal heterogeneous motivation shifts and unintended sub-group formations\r\ninfluencing participation and engagement.","presenter":"Dr. Yuchen Liu","authors":[{"name":"Dr. Yuchen Liu","aff":"Assistant Professor, University of Florida"},{"name":"Prof. Ye Shi","aff":"Associate Professor, University of Science and Technology of China"},{"name":"Dr. Yong Tan","aff":"Professor, University of Washington"}],"order":2},{"id":"136-2080","title":"Bridging the Gap: Underprivileged LPs, Smart‐Contract Tools, and Transparency in DeFi","content":"Decentralized Finance innovations claim to bring equitable outcome for everyone. We investigate whether smart‐contract benefit DeFi liquidity providers, especially the underprivileged. Using Uniswap’s data, we find performance gains, but lower adoption and algorithmic aversion among the underprivileged. Transparency mitigates algorithm aversion, highlighting trust as a critical driver.","presenter":"Mr. Allen Zhao","authors":[{"name":"Mr. Allen Zhao","aff":"Assistant Professor, Grand Valley State University"},{"name":"Dr. Zixuan Meng","aff":"Assistant Professor, The University of Texas at Dallas"},{"name":"Dr. Eric Zheng","aff":"Professor, The University of Texas at Dallas"}],"order":3},{"id":"136-0850","title":"A comparative analysis of blockchains along scalability, security, and decentralization","content":"Blockchains face the trilemma of balancing scalability, security, and decentralization. Through a systematic review, data analysis, and expert evaluation of top cryptocurrencies, we identify trade-offs across these dimensions. Our findings provide a framework for technical and non-technical stakeholders and demonstrate how various blockchains balance the trilemma.","presenter":"Mr. Michael Mertel","authors":[{"name":"Mr. Michael Mertel","aff":"Student, Friedrich-Alexander Universitat Erlangen-Nurnberg"},{"name":"Mr. Lars Friedrich","aff":"Student, Friedrich-Alexander Universitat Erlangen-Nurnberg"},{"name":"Prof. Kai-Ingo Voigt","aff":"Professor, Friedrich-Alexander Universitat Erlangen-Nurnberg"}],"order":4}]},{"id":"s284","title":"Sociotechnical Implications of Generative AI","track":"Generative AI and Societal Sustainable Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"HARRIS","chairs":["Dr. Nicholas Brown"],"abstracts":[{"id":"136-0391","title":"Enhancing the Wisdom of Crowds When Experts Use Algorithmic Advice","content":"Generating accurate forecasts is crucial for managerial decision making. Human forecasters can improve their accuracy by incorporating algorithmic advice. However, providing identical advice to a crowd of forecasters creates a shared-information bias. We derive a Bayesian model of judgment aggregation to extract the wisdom of a crowd of AI-assisted experts.","presenter":"Mr. Angshuman Pal","authors":[{"name":"Mr. Angshuman Pal","aff":"Student, Kelley School of Business, Indiana Univ."},{"name":"Prof. Asa Palley","aff":"Associate Professor, Kelley School of Business, Indiana Univ."},{"name":"Prof. Ville Satopaa","aff":"Associate Professor, INSEAD"}],"order":1},{"id":"136-0694","title":"Bias Encoded: Human Raters and Algorithmic Content Moderation","content":"Generative artificial intelligence platforms adopt algorithmic content moderation to mitigate digital toxicity. This approach involves training algorithms on data annotated by humans. This manual work is often outsourced to workers overseas. Through a mixed-methods study, we examine the impact of culture on algorithmic outputs. We contribute to universal ethics discourses.","presenter":"Ms. Carolina Reis","authors":[{"name":"Ms. Carolina Reis","aff":"Student, Virginia Tech"}],"order":2},{"id":"136-1649","title":"Augmented Intelligence for Smarter Supply Chains to Achieve Resilience and Sustainability","content":"The transition from prediction machines to collaborative generative problem-solvers presents the potential for AI to transform a host of supply chain and operational practices where artificial agents complement knowledge workers. We map out the inherent challenges and opportunities in the augmented intelligence paradigm.","presenter":"Dr. Cigdem Gurgur","authors":[{"name":"Dr. Cigdem Gurgur","aff":"Associate Professor, Purdue University"}],"order":3},{"id":"136-0768","title":"How and Why Does Generative AI Training Intensity Impact Team Performance?","content":"Organizations across the globe are increasingly investing in Generative AI trainings. However, the impact of these trainings on performance has not been systematically examined. In this study, we conduct a field experiment to examine how and why Generative AI training intensity influences team performance.","presenter":"Dr. Arjun Kadian","authors":[{"name":"Dr. Arjun Kadian","aff":"Assistant Professor, Florida International University"},{"name":"Ms. Zheyi Xu","aff":"Student, University of South Florida"},{"name":"Prof. Sunil Mithas","aff":"Professor, USF"},{"name":"Ms. Nidhi Kalani","aff":"Student, University of South Florida"}],"order":4},{"id":"136-0791","title":"AI Chatbots Go Phishing","content":"Whereas users forage for information on social media, they actively seek information from AI chatbots. We posit that information-processing type influences phishing susceptibility, namely that users will more likely succumb to social engineering through chatbots than social media. We operationalize an AI chatbot and web app to investigate our hypothesis.","presenter":"Dr. Nicholas Brown","authors":[{"name":"Dr. Nicholas Brown","aff":"Assistant Professor, Indiana University"}],"order":5}]},{"id":"s340","title":"Addressing Problems in Manufacturing Planning","track":"Manufacturing Operations","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"LENOX","chairs":["Dr. Kevin Sweeney"],"abstracts":[{"id":"136-0011","title":"Workload Balancing in Project Scheduling","content":"A single-item or small-series production environment can be represented as a project consisting of a set of precedence-related activities that require time and resources to be performed. The resources represent, for example, production personnel. We present a mixed binary linear program for minimizing the makespan subject to workload balancing constraints.","presenter":"Prof. Norbert Trautmann","authors":[{"name":"Ms. Nina Ackermann","aff":"Student, Department of Business Administration"},{"name":"Ms. Tamara Bigler","aff":"Post Doc/Researcher, Department of Business Administration"},{"name":"Prof. Norbert Trautmann","aff":"Professor, Department of Business Administration"}],"order":1},{"id":"136-1418","title":"Sequential scheduling modeled as a queueing series","content":"We model a capacitated system with batch-splitting as a queueing system. Objectives include minimizing processing time, maximizing quantity, or meeting probability of finish goals.","presenter":"Prof. Gregory DeYong","authors":[{"name":"Prof. Gregory DeYong","aff":"Associate Professor, Southern Illinois University Carbondale"},{"name":"Dr. Tomcy Thomas","aff":"Lecturer, Southern Illinois University"}],"order":2},{"id":"136-1977","title":"Resource-Constrained Project Scheduling with Interdependent Stochastic Benefits for Intelligent Manufacturing","content":"In the context of technological upgrades during the intelligent manufacturing transformation, this paper addresses the RCPSP with stochastic, interdependent benefits using an MDP framework and a DRL-based approach. Our method is validated using real-world manufacturing cases, demonstrating significant improvements in production efficiency and resource utilization.","presenter":"Mr. Xiaohang Liu","authors":[{"name":"Mr. Xiaohang Liu","aff":"Student, Tsinghua University Department of IE"},{"name":"Mr. Hailei Gong","aff":"Student, Tsinghua University"},{"name":"Prof. Zhi-Hai Zhang","aff":"Associate Professor, Tsinghua University"}],"order":3},{"id":"136-0127","title":"The sole optimal continuous sampling plan improved with risk control scheme","content":"We construct the D-value model to compare the optimal continuous sampling plans (OCSP) and discover that under the higher quality requirement OCSP-3 and in all other situations OCSP-1 should be adopted for the in-control process. We improve the risk control in OCSP based on the estimator of process yield index.","presenter":"Dr. Chunzhi Li","authors":[{"name":"Dr. Chunzhi Li","aff":"Lecturer, East China Jiaotong University"},{"name":"Ms. Tingqi Yang","aff":"Student, East China Jiaotong University"}],"order":4},{"id":"136-1546","title":"Competitive Dynamics and Job Shop Scheduling Mechanisms with Heterogeneous Customers","content":"We explore a manufacturing system with two competing job shops and heterogenous customer classes. Using a stochastic utility model, we create an agent-based simulation to examine the performance of various scheduling priority rules under this competitive scenario to determine the optimal strategy for each shop under various conditions.","presenter":"Dr. Kevin Sweeney","authors":[{"name":"Dr. Kevin Sweeney","aff":"Associate Professor, Rochester Institute of Technology"},{"name":"Dr. Stanislaus Solomon","aff":"Associate Professor, Southern Illinois University Edwardsvill"}],"order":5}]},{"id":"s342","title":"Featured Speaker Series Tutorial: AI in Business Research","track":"Tutorials and Workshops in Research and Teaching","type":"Tutorial","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"Learning Center","chairs":["Dr. Meng Li"],"abstracts":[{"id":"136-2073","title":"Featured Speaker Series_Tutorial_AI in Business Research","content":"Artificial intelligence (AI) has a significant impact on the operating processes of numerous companies as well as on our daily lives. In this tutorial, I discuss and develop a framework for AI and review the literature on the interface of AI and operations management.","presenter":"Dr. Meng Li","authors":[{"name":"Dr. Meng Li","aff":"Professor, University of Houston"}],"order":1}]},{"id":"s371","title":"Consumer Choice and Market Dynamic","track":"POM-Marketing Interface","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"DUNWOODY","chairs":["Dr. Fang Fang"],"abstracts":[{"id":"136-0241","title":"Optimal Search for Tiered Product Information","content":"We extend Branco etc (2012 Marketing Science) to study the optimal search policy for products with different tiers and characterize the optimal stopping rules for purchase, no purchase, or start new tier. Our results suggest the seller arranges the attributes at each tier via the informativeness to cost ratio.","presenter":"Prof. Zhen Liu","authors":[{"name":"Prof. Zhen Liu","aff":"Associate Professor, Benedictine University"}],"order":1},{"id":"136-1323","title":"What drives autonomous cars? Role of Trust in Diffusion of Autonomous Car Adoption","content":"Understanding human behavior helps investigate opportunities and risks in operations and policy decisions regarding adaptation of AI driven technologies. We developed a survey instrument based on a novel model combining three theories from Information Systems and Marketing to identify factors affecting consumer behavior towards autonomous car adoption.","presenter":"Dr. Elham Torabi","authors":[{"name":"Dr. Elham Torabi","aff":"Associate Professor, James Madison University"},{"name":"Dr. Gizem Atav","aff":"Associate Professor, James Madison University"},{"name":"Mr. Will Jones","aff":"Student, James Madison University"}],"order":2},{"id":"136-0130","title":"Leasing vs Selling Under Battery-life Uncertainty – An EV-maker’s Choice of Business Model","content":"The uncertainty in battery life is a major concern for commercial EV buyers. In a two-period game theoretic model, we study a profit-maximizing automaker's choice of business model and quantity decisions. We extend the discussion by investigating how the scenario changes in presence of an EPR regulation.","presenter":"Mr. Satyajit Roy","authors":[{"name":"Mr. Satyajit Roy","aff":"Student, Indian Institute of Management Bangalore"},{"name":"Prof. Sreelata Jonnalagedda","aff":"Associate Professor, Indian Institute of Management Bangalore"},{"name":"Prof. Haritha Saranga","aff":"Professor, Indian Institute of Management Bangalore"}],"order":3},{"id":"136-0347","title":"Will Right to Repair Protect Small Businesses and Consumers?","content":"The Right to Repair (RTR) policy requires the original equipment manufacturers (OEMs) to offer replacement parts separately. We construct an analytical model containing one OEM and one competing third-party to examine RTR. Results identifies conditions when RTR benefits the OEM while hurts consumers or the third-party and may increases waste.","presenter":"Dr. Fang Fang","authors":[{"name":"Dr. Fang Fang","aff":"Associate Professor, CAL STATE LOS ANGELES"},{"name":"Dr. Bobby Zhou","aff":"Associate Professor, University of Maryland - College Park"}],"order":4}]},{"id":"s446","title":"Tribute to Christopher S Tang I","track":"Honoring Retirees","type":"Panel","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"GRAND HALL EAST A","chairs":["Prof. Manmohan Sodhi","Prof. Hau Lee"],"abstracts":[{"id":"136-2137","title":"Can we use technology to achieve the UN SDGs?","content":"Technology is one way to achieve the UN SDGs without worrying too much about behavioral changes. But can it offer effective solutions? I will discuss a primarily technological problem—the sustainability of satelltie operations in space—to explore whether or not technology can offer solutions.","presenter":"Prof. Manmohan Sodhi","authors":[{"name":"Prof. Manmohan Sodhi","aff":"Professor, Bayes Business School"}],"order":1},{"id":"136-2134","title":"Information Sharing in Supply Chains: Ethical Viewpoint","content":"Transparency is a key facet of responsible supply chain management, prominently highlighted in Professor Tang's work. This paper studies the ethical challenges surrounding information sharing and deception in supply chains. We explore trust dynamics and ethical frameworks to evaluate the moral complexities of deceptive practices in supply","presenter":"Prof. Soo-Haeng Cho","authors":[{"name":"Prof. Soo-Haeng Cho","aff":"Professor, Carnegie Mellon University"},{"name":"Prof. Tae Wan Kim","aff":"Professor, Carnegie Mellon University"}],"order":2},{"id":"136-2135","title":"Blockchain-enabled Supply Chain Financing","content":"We customize an AI LLM to analyze textual data on blockchain-enabled supply chain financing, identifying patterns linking financing frictions, blockchain features, and solution outcomes. This supports the UN's goal of advancing innovative technology to expand small-scale enterprises' access to financial services, including affordable credit.","presenter":"Prof. Volodymyr Babich","authors":[{"name":"Prof. Volodymyr Babich","aff":"Professor, Georgetown University"},{"name":"Mr. Sairam Sriraman","aff":"Student, TUM School of Management"},{"name":"Prof. David Wuttke","aff":"Associate Professor, TUM School of Management, HN Campus"},{"name":"Prof. Eve Rosenzweig","aff":"Professor, Emory University"}],"order":3},{"id":"136-2136","title":"The Medical AI Revolution: A Progress Report","content":"Medical AI is revolutionizing healthcare, with over 1,000 FDA-cleared AI devices by 2025. While growth offers great promise, regulatory hurdles persist. This talk discusses the commercialization pathway of medical AI devices, their patient safety implications, and the FDA's Predetermined Change Control Plans (PCCP) to improve device safety and adaptability.","presenter":"Prof. Tinglong Dai","authors":[{"name":"Prof. Tinglong Dai","aff":"Professor, Johns Hopkins University"}],"order":4}]},{"id":"s2","title":"Emerging Approaches to Solving Manufacturing Challenges in a Dynamic Landscape","track":"Manufacturing Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"LENOX","chairs":["Dr. Mayukh Majumdar"],"abstracts":[{"id":"136-1535","title":"Do Shareholders Reward Near Shoring? The Impact of Near Shoring on Shareholder Wealth","content":"Manufacturing location decisions can be complex as upper management attempts to balance competing demands from various stakeholders. This paper uses event study methodology to examine the impact of nearshoring announcements on stock prices from 2011 to 2024. The impact of nearshoring on firm profitability is discussed.","presenter":"Mr. Muhammad Umar Farooq","authors":[{"name":"Mr. Muhammad Umar Farooq","aff":"Student, New Mexico State University"}],"order":1},{"id":"136-1465","title":"Price of fairness in scheduling problems","content":"We investigate the price of fairness to know the extent of sacrifice in the optimality of a scheduling decision to be perceived fair by various stakeholders. In this presentation, we discuss the important issues of efficiency and fairness and some possible approaches to analyze such practical situations.","presenter":"Dr. Jatinder Gupta","authors":[{"name":"Dr. Jatinder Gupta","aff":"Retired, University of Alabama Huntsville"}],"order":2},{"id":"136-2071","title":"Supply Chain Planning: A Case for Hybrid Cross-Docks","content":"We study the logistics planning problem encountered in practice for a supply chain consisting of a Hybrid Cross Dock (HCD) facility. The HCD allows the storage of materials for a short period of time without charging inventory holding costs. The research shows that HCD","presenter":"Dr. Manoj Vanajakumari","authors":[{"name":"Dr. Manoj Vanajakumari","aff":"Associate Professor, University of North Carolina Wilmington"},{"name":"Dr. Haoying Sun","aff":"Associate Professor, University of Kentucky"},{"name":"Prof. Chelliah Sriskandarajah","aff":"Professor, Texas A&amp;M University College Station"}],"order":3},{"id":"136-1564","title":"Supplier Selection in Manufacturing: Addressing Network Complexity, Component Commonality, and Supplier Capability","content":"In today's manufacturing landscape, especially in the automotive industry, selecting suppliers has become complex and critical. The complexity arises due to intricate manufacturing processes, supplier capabilities, and variabilities in their processes. We address these issues by developing a modeling framework grounded in real-world inputs, generating actionable managerial insights.","presenter":"Dr. Mayukh Majumdar","authors":[{"name":"Dr. Mayukh Majumdar","aff":"Assistant Professor, University of San Diego"},{"name":"Dr. Anupam Agrawal","aff":"Associate Professor, Texas A&amp;M University College Station"},{"name":"Dr. Anand Paul","aff":"Professor, University of Florida"},{"name":"Dr. Tharanga Rajapakshe","aff":"Associate Professor, University of Florida"}],"order":4}]},{"id":"s14","title":"Women Salute! Celebrating Female Researchers in POMS","track":"POM and Community","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY F","chairs":["Mr. Max Ji"],"abstracts":[{"id":"136-1644","title":"Wasserstein Autoregressive Moving Average Model for Distribution-valued Time Series Analytics","content":"Distribution-valued time series (DVTS), where each observation is a probability distribution, are widely encountered. For example, data reported by the Consumer Expenditure Surveys (CES), Bureau of Labor Statistics, only contain time-varying means and standard errors. We propose a Wasserstein autoregressive moving average (WARMA) model to analyze DVTS reported by CES.","presenter":"Ms. Yujing Huang","authors":[{"name":"Ms. Yujing Huang","aff":"Student, University at Buffalo"},{"name":"Dr. Xiaoyu Chen","aff":"Assistant Professor, University at Buffalo"}],"order":1},{"id":"136-1523","title":"A Game-Theoretic and MCDA Framework for Arctic Development: Balancing Economic Interests, Security, and Indigenous Rights","content":"This study employs game theory and MCDA to address Arctic development challenges by balancing economic growth, indigenous rights, and sustainability. Strategic interactions among stakeholders are modeled using sequential and non-cooperative game theory, while policy impacts are evaluated to propose data-driven strategies ensuring equity, environmental sustainability, and cultural respect.","presenter":"Ms. Yiqi Zhao","authors":[{"name":"Ms. Yiqi Zhao","aff":"Student, University at Buffalo"},{"name":"Dr. Jun Zhuang","aff":"Professor, University at Buffalo"}],"order":2},{"id":"136-0746","title":"Creating a Better Pipeline for Females in Operations Management","content":"There is a clear business case for gender diversity in operations management. Unfortunately, there are barriers that make the field unattractive for females beyond what firms can offer. This study addresses POM education and how partnership with industry could increase and retain female graduates in the field.","presenter":"Dr. Katie Kenny","authors":[{"name":"Dr. Katie Kenny","aff":"Post Doc/Researcher, Erasmus University Rotterdam"}],"order":3}]},{"id":"s25","title":"Healthcare Payment Models","track":"Healthcare Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"PIEDMONT","chairs":["Dr. Zahra Mobini"],"abstracts":[{"id":"136-1809","title":"How Payment Models Shape Prescribing Behaviors: Evidence from the Oncology Care Model","content":"Chemotherapy drugs are a major contributor to the high spending in oncologic care, representing almost 40% of total costs. We empirically study the Oncology Care Model (OCM) by Centers for Medicare &amp; Medicaid Services, which targets to reduce oncology care costs, on physicians’ prescribing behavior for novel therapies.","presenter":"Prof. Xinyu Liang","authors":[{"name":"Prof. Xinyu Liang","aff":"Assisatnt Professor, INSEAD"},{"name":"Prof. Jun Li","aff":"Associate Professor, University of Michigan Ann Arbor"},{"name":"Prof. Ravi Anupindi","aff":"Professor, University of Michigan Ann Arbor"},{"name":"Prof. Lindsey Herrel","aff":"Associate Professor, University of Michigan, Ann Arbor"}],"order":5}]},{"id":"s42","title":"Humanitarian Logistics and Supply Chain","track":"Humanitarian Operations and Crisis Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"GRAND HALL EAST B","chairs":["Mr. Austin Saragih"],"abstracts":[{"id":"136-0147","title":"Keep Water Flowing: The Hidden Crisis of Rural Water Management","content":"In rural Africa, people rely on communal handpumps for clean drinking water. But these handpumps break down frequently. Thus, we study how can NGOs proactively maintain and reactively repair these handpumps to ensure continuous access to water.","presenter":"Prof. Chengcheng Zhai","authors":[{"name":"Prof. Chengcheng Zhai","aff":"Assistant Professor, Mendoza College of Business"},{"name":"Prof. Rodney Parker","aff":"Associate Professor, Indiana University"},{"name":"Prof. Kurt Bretthauer","aff":"Professor, Indiana University"},{"name":"Prof. Alfonso Pedraza-Martinez","aff":"Professor, Mendoza College of Business"},{"name":"Prof. Jorge Mejia","aff":"Associate Professor, Indiana University"}],"order":2},{"id":"136-0235","title":"A Location-Allocation Model for Food Distribution in Post-Disaster Environments","content":"This study develops a location-allocation model for post-disaster food distribution, minimizing social costs of survivor suffering and delivery operations. Using the Houston Food Bank network as a case, it optimizes POD locations, allocations, and relief strategies, incorporating deprivation cost functions and Hurricane Harvey data to enhance disaster response effectiveness.","presenter":"Mr. Angelo Soto Vergel","authors":[{"name":"Mr. Angelo Soto Vergel","aff":"Student, University at Buffalo, SUNY"},{"name":"Dr. Diana Ramirez-Rios","aff":"Assistant Professor, The State University of New York at Buffalo"},{"name":"Dr. Trilce Encarnacion","aff":"Assistant Professor, University of Missouri St Louis"},{"name":"Ms. Johanna Amaya","aff":"Assistant Professor, Pennsylvania State University"}],"order":3},{"id":"136-0789","title":"Emergency Management Cycle: Mitigation, Preparedness, and Response Design for Disaster","content":"We integrate mitigation, preparedness, and response design for disasters as an end-to-end emergency management cycle. We establish that optimizing for mitigation is an instance of minimzing non-monotone non-submodular optimization problem. We then solve it via reformulation and approximation with approximation guarantee. We apply this to Florida's mitigation strategy.","presenter":"Mr. Austin Saragih","authors":[{"name":"Mr. Austin Saragih","aff":"Student, Massachusetts Institute of Technology"}],"order":4}]},{"id":"s44","title":"Information Design in Operations Management","track":"Supply Chain Risk Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY H","chairs":["Dr. Tao Lu"],"abstracts":[{"id":"136-0025","title":"The Value of Information Design in Supply Chain Management","content":"This paper studies an information design problem of a retailer in a two-tier supply chain that procures a single type of product from a supplier. For this setup, we characterize the optimal information disclosure policy of the retailer.","presenter":"Prof. Huseyin Gurkan","authors":[{"name":"Prof. Ozan Candogan","aff":"Professor, University of Chicago"},{"name":"Prof. Huseyin Gurkan","aff":"Assistant Professor, ESMT Berlin"}],"order":1},{"id":"136-0613","title":"Boxless Shipping: Balancing Sustainability and Security in Package Delivery","content":"We explore optimal packaging strategies for online retailers, focusing on boxless shipping to address environmental waste and theft concerns. Using an information design framework, we demonstrate profit gains of up to 221% and environmental benefits. However, we highlight outcomes depend on sensitivity of customers to theft and privacy.","presenter":"Dr. Neda Mirzaeian","authors":[{"name":"Prof. Stanley Lim","aff":"Assistant Professor, Michigan State University"},{"name":"Dr. Neda Mirzaeian","aff":"Assistant Professor, University of Texas at Dallas"},{"name":"Dr. Shouqiang Wang","aff":"Associate Professor, University of Texas Dallas"}],"order":2},{"id":"136-0660","title":"Information Design for Guiding Farmers in Crop Selection","content":"We explores how the government can strategically communicate information regarding the uncertain market potential of a new variety to local farmers within a framework of information design. We find that the government opts for full disclosure only when the market demand of the new variety exhibits significant fluctuations.","presenter":"Mr. Jingye Huang","authors":[{"name":"Mr. Jingye Huang","aff":"Student, Southern University of Sci and Tech"},{"name":"Mr. Zhenxiao Chen","aff":"Student, Southern University of Science and Technology"},{"name":"Dr. Qiaochu He","aff":"Associate Professor, Southern University of Sci and Tech"}],"order":3},{"id":"136-1145","title":"Preventing Innovation Misappropriation Through Strategic Information Design","content":"This paper examines innovation misappropriation risks in partnerships where a well-established firm seeks a small firm's expertise. Using a Bayesian persuasion model, we analyze how the small firm can design optimal information disclosure strategies to influence cooperation while mitigating misappropriation risks, balancing innovation benefits and strategic interactions with the principal.","presenter":"Prof. Feng Tian","authors":[{"name":"Ms. Meng Chen","aff":"Student, Southern University of Science and Technology"},{"name":"Dr. Xiaoshuai Fan","aff":"Assistant Professor, Southern University of Sci and Tech"},{"name":"Prof. Feng Tian","aff":"Assistant Professor, the University of Hong Kong"}],"order":4},{"id":"136-1572","title":"Machine Prediction, Human Newsvendor, and Information Design","content":"A machine is provided to forecast demand for a human newsvendor. Demand depends on objective data that the machine can incorporate and domain-specific factors that only the human can assess with a cognitive effort. We analyze the optimal design of machine precision to maximize the expected monetary profit.","presenter":"Dr. Tao Lu","authors":[{"name":"Dr. Tao Lu","aff":"Associate Professor, University of Connecticut"}],"order":5}]},{"id":"s54","title":"Renewables, Storage, and Safety in the Evolving Energy Landscape","track":"Energy and Natural Resource Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"TECHWOOD","chairs":["Dr. Seyed Amin Seyed Haeri"],"abstracts":[{"id":"136-1031","title":"Grid-Scale Mobile Battery Energy Storage Systems","content":"Energy storage helps match intermittent renewable supply to demand and is crucial for low-carbon energy systems. We consider mobile batteries as a storage technology that can be relocated to exploit spatial heterogeneity in prices. We develop a framework to operate mobile batteries and compare performance to stationary batteries across markets.","presenter":"Mr. Vishrut Rana","authors":[{"name":"Mr. Vishrut Rana","aff":"Student, The Wharton School"},{"name":"Prof. Christian Kaps","aff":"Assistant Professor, Harvard Business School"},{"name":"Prof. Serguei Netessine","aff":"Professor, The Wharton School"}],"order":1},{"id":"136-1139","title":"Do Energy Generation Flexibility Facilitate More Intermittent Investments? Evidence from the U.S. Electricity Industry","content":"This study explores how operational flexibility shapes the interplay between renewable and conventional generation technologies in the U.S. (2002–2019). Flexible investments complement renewables, enhancing grid reliability despite intermittency. Policy frameworks, competition, and gas infrastructure influence these dynamics, providing critical insights for advancing sustainable energy transition strategies.","presenter":"Dr. Seyed Amin Seyed Haeri","authors":[{"name":"Dr. Seyed Amin Seyed Haeri","aff":"Assistant Professor, Coastal Carolina University"},{"name":"Dr. Ahmet Colak","aff":"Assistant Professor, Clemson University"},{"name":"Prof. Safak Yucel","aff":"Associate Professor, Georgetown University"}],"order":2},{"id":"136-1292","title":"Powering Down Wildfires by Enhancing Utility Grid Inspection and Maintenance","content":"Wildfire management is becoming significantly important in the US and other countries. As utility companies are responsible for a lot of major wildfires, they have initiated several programs to combat wildfires. We present an optimal inspection and maintenance policy for the utilities' power grid to reduce wildfire risk.","presenter":"Mr. Abolfazl Taghavi","authors":[{"name":"Mr. Abolfazl Taghavi","aff":"Student, UCLA Anderson School of Management"},{"name":"Prof. Ali Fattahi","aff":"Assistant Professor, Johns Hopkins University"},{"name":"Prof. Sriram Dasu","aff":"Associate Professor, University of Southern California"},{"name":"Prof. Reza Ahmadi","aff":"Professor, University of California Los Angeles"}],"order":3}]},{"id":"s59","title":"Improving Mental Healthcare","track":"Healthcare Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"PIEDMONT","chairs":["Dr. Wilson Lin"],"abstracts":[{"id":"136-0042","title":"High Stakes, Low Spirits: Unveiling the Mental Health Impact of Online Sports Gambling","content":"We undertake an empirical investigation into the influence of online sports gambling on mental health, leveraging a distinctive national panel dataset. Our analysis uncovers compelling evidence that online sports gambling is linked to a deterioration in mental health, unveiling a plausible causal pathway.","presenter":"Mr. Jiayuan Tian","authors":[{"name":"Mr. Jiayuan Tian","aff":"Student, University of Florida"},{"name":"Dr. Guohou Shan","aff":"Assistant Professor, Northeastern University"},{"name":"Prof. Liangfei Qiu","aff":"Professor, University of Florida"}],"order":1},{"id":"136-1777","title":"Enhancing campus mental health counseling centers: Strategies for improved support and student well-being.","content":"This research investigates how mental health counseling centers on college campuses can better support students in times of distress.","presenter":"Dr. Wilson Lin","authors":[{"name":"Prof. Amber Xiaoyan Liu","aff":"Assistant Professor, Santa Clara University"},{"name":"Dr. Wilson Lin","aff":"Assistant Professor, Santa Clara University"},{"name":"Dr. Hussein El Hajj","aff":"Assistant Professor, Santa Clara University"}],"order":2},{"id":"136-1812","title":"GenAI-Empowered Social Chatbot Conversation Design and Mental Health: Evidence from a Large-Scale Field Experiment","content":"This study explores whether GenAI chatbots enhance mental health. In a field experiment with 1,675 users, it measured weekly self-evaluated mental health scores and controlled conversation design via initiation messages. Results show that when chatbots requested support, users’ mental health improved by 4.4%, driven by increased self-esteem from providing support.","presenter":"Mr. Donggyu (David) Min","authors":[{"name":"Mr. Donggyu (David) Min","aff":"Student, Kaist"},{"name":"Prof. Sunghun Chung","aff":"Assistant Professor, George Washington University"},{"name":"Prof. Chul Ho Lee","aff":"Assistant Professor, Kaist"},{"name":"Prof. Xitong Li","aff":"Professor, Hec Paris"}],"order":3}]},{"id":"s70","title":"Impacts and Evolution of Supply Networks","track":"Procurement and Supplier Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"MARIETTA","chairs":["Dr. Yang Yang-Sun"],"abstracts":[{"id":"136-1857","title":"Supply Network Co-Embeddedness Between Rivals and Its Impacts on Competition","content":"This study examines how structural equivalence in firm-rival dyads impacts competition dissimilarity and performance disparity. Analyzing 157,624 dyad-year observations with dynamic panel models, we find that structural equivalence significantly influences ROA disparity through competition dissimilarity, highlighting the role of shared supply network partners in shaping competitive outcomes.","presenter":"Dr. Yang Yang-Sun","authors":[{"name":"Dr. Yang Yang-Sun","aff":"Associate Professor, Baylor University"},{"name":"Dr. Mengge Li","aff":"Assistant Professor, University of Texas at El Paso"},{"name":"Dr. Xiaojin Sun","aff":"Associate Professor, Oklahoma State University"},{"name":"Dr. Tingting Yan","aff":"Professor, Texas Tech University"}],"order":1},{"id":"136-1233","title":"Glocalization in Procurement Strategy – The Case of a Global Telecom Firm's Data Center Construction","content":"Glocalization in procurement strategy involves balancing global sourcing with local availability and adaptation to enhance supply chain resilience and market penetration. To support its global expansion, this telecommunications manufacturer balances sourcing from its home country and local sourcing by considering product costs, transportation, lead time, tariffs, local standards, and regulations.","presenter":"Dr. Chaodong Han","authors":[{"name":"Mr. Kailong Yao","aff":"Data Center Manager, ZTE Global"},{"name":"Dr. Chaodong Han","aff":"Professor, Towson University"}],"order":3},{"id":"136-1044","title":"Supply Chain Network Resilience: How Network Complexity Affects Resilience in Complex Adaptive Systems","content":"Global supply networks are facing disruptions from COVID-19, geopolitical conflicts, and climate change, prompting firms to increase their resilience. This study examines how the structural complexity of supply networks, i.e., diversity and centralization, affects risk propagation and resilience during disruptions from the perspective of complex adaptive systems, using agent-based modelling.","presenter":"Mr. Mohammad Rishehchi Fayyaz","authors":[{"name":"Mr. Mohammad Rishehchi Fayyaz","aff":"Student, Université Libre de Bruxelles"},{"name":"Dr. Evelyne Vanpoucke","aff":"Professor, Université Libre de Bruxelles"},{"name":"Dr. Canan Kocabasoglu Hillmer","aff":"Professor, City University - London"},{"name":"Dr. Oben Ceryan","aff":"Senior Lecturer, Bayes Business School"}],"order":4},{"id":"136-1862","title":"Rethinking Supply Chain Relocation: A Holistic Framework for Supply Base Distance","content":"This research addresses the growing interest in supply chain relocation by proposing a holistic measure of supply base distance. Beyond geographical distance, the study incorporates cultural, economic, and political dimensions to provide a comprehensive framework for understanding firm-supplier relationships amid nearshoring, friend-shoring, and reshoring trends.","presenter":"Dr. Yang Yang-Sun","authors":[{"name":"Dr. Yang Yang-Sun","aff":"Associate Professor, Baylor University"},{"name":"Dr. Kang Hsu","aff":"Assistant Professor, Georgia Southern University"},{"name":"Dr. Sangho Chae","aff":"Associate Professor, University of Warwick"}],"order":5}]},{"id":"s85","title":"Design, Behavior, and Performance Issues in the Knowledge Economy","track":"Product Innovation and Technology Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"COURTLAND","chairs":["Dr. Sina Moghadas Khorasani"],"abstracts":[{"id":"136-0039","title":"Product Line Design and Planning for Startups","content":"This paper delves into the challenges of product line design and planning for startups, including limited resources, market uncertainty, and diverse customer preferences. Through a model-based investigation, we explore strategies for optimizing market coverage while mitigating the risks of\r\ncannibalization in the pursuit of startup success.","presenter":"Mr. Zeya Wang","authors":[{"name":"Prof. Sreekumar Bhaskaran","aff":"Associate Professor, Southern Methodist University"},{"name":"Dr. Karthik Ramachandran","aff":"Professor, Georgia Institute of Technology"},{"name":"Mr. Zeya Wang","aff":"Assistant Professor, University of Dayton"}],"order":1},{"id":"136-0041","title":"How Do Loyalty Programs Affect Multichannel Bookings? An Empirical Investigation","content":"Using a unique dataset obtained from a major hotel group, we empirically investigate how loyalty discounts affect customers’ booking channel choices. We utilize a quasi-natural experiment based on an exogenous change of the loyalty discount in a subset of hotels in our dataset to construct a difference-in-difference model.","presenter":"Mr. Shuaishuai Yang","authors":[{"name":"Dr. Antoine Feylessoufi","aff":"Assistant Professor, Vanderbilt University"},{"name":"Dr. Ersin Korpeoglu","aff":"Associate Professor, University College London"},{"name":"Mr. Shuaishuai Yang","aff":"Student, University College London"}],"order":2},{"id":"136-0046","title":"Does Virtual Take Longer? An Empirical Investigation of Service Time in Telemental Health","content":"We examine the causal relationship between telemedicine adoption and service time by using the visit-level patient data for psychology visits in the U.S.. We find that telemedicine significantly reduces visit duration for younger, actively employed patients, while it increases service time for older, retired population.","presenter":"Ms. Yupu Sun","authors":[{"name":"Ms. Yupu Sun","aff":"Student, University College London"},{"name":"Dr. Ersin Korpeoglu","aff":"Associate Professor, University College London"}],"order":3},{"id":"136-0999","title":"A Machine Learning Framework for Project Performance Prediction, Interpretation, and Inference","content":"In the knowledge economy, project performance is central to enterprise functioning, growth, and renewal. In this paper, we offer a data-driven machine-learning-based analytic pipeline to predict, interpret, and infer the nature and severity of cost or schedule overrun a project will experience.","presenter":"Dr. Sina Moghadas Khorasani","authors":[{"name":"Mr. Xiaochen Gao","aff":"Student, University of California, San Diego"},{"name":"Dr. Sina Moghadas Khorasani","aff":"Assistant Professor, Vanderbilt University"},{"name":"Prof. Vish Krishnan","aff":"Professor, University of California San Diego"},{"name":"Dr. Lakshminarayana Nittala","aff":"Assistant Professor, University of Dayton"},{"name":"Ms. Siqi Wang","aff":"Student, University of California San Diego"}],"order":4}]},{"id":"s94","title":"Designing Algorithms to Enhance Human Performance","track":"Behavioral Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY D","chairs":["Prof. Kris Ferreira","Mr. Matthew DosSantos DiSorbo"],"abstracts":[{"id":"136-0053","title":"The AI Who Cried Wolf: Helping Humans Overcome Their Accuracy Obsession","content":"Humans trust accurate algorithms, even when they shouldn't. In an online lab experiment, we find performance falls by more than 80% when humans use optimal, but inaccurate, algorithms, compared to sub-optimal, but accurate, algorithms. We introduce interventions that educate people about optimal algorithms; these interventions reverse the 'accuracy obsession.'","presenter":"Mr. Matthew DosSantos DiSorbo","authors":[{"name":"Mr. Matthew DosSantos DiSorbo","aff":"Student, Harvard Business School"},{"name":"Prof. Kris Ferreira","aff":"Assistant Professor, Harvard Business School"}],"order":1},{"id":"136-0393","title":"Algorithm Meets Memory: Data-Driven Performance Boosts for Learning","content":"How can we use algorithmic design to improve human learning? In this project, we optimize over a discovered memory model, using spaced repetition to improve recall and long-term retention. Our structural estimation framework uncovers the underlying structure and dependencies of memory, improving student performance while staying interpretable.","presenter":"Ms. Xufei Liu","authors":[{"name":"Prof. Gad Allon","aff":"Professor, The Wharton School"},{"name":"Ms. Xufei Liu","aff":"Student, The Wharton School"},{"name":"Prof. Ken Moon","aff":"Assistant Professor, The Wharton School"}],"order":2},{"id":"136-0929","title":"Using Embeddings To Understand AI Decision Making","content":"Recent works in OR/OM explore /how/ to better train AI for decision making. A complementary question is: When we /do/ successfully train the AI, what rules did the AI actually learn? In this talk, we show how the geometry of a network’s learned embeddings could shed light on this question.","presenter":"Dr. X.Y. Han","authors":[{"name":"Dr. X.Y. Han","aff":"Assistant Professor, Booth School of Business"}],"order":3},{"id":"136-1665","title":"Online Learning for Increasing Parental Engagement On Ed Tech Platforms","content":"Ensuring universal access to quality education, particularly in developing countries, remains a formidable challenge. A key issue that affects educational outcomes among low-income households is limited parent involvement. In this work, we discuss results from a series of experiments that leverage behavioral nudges to resolve this challenge.","presenter":"Prof. Divya Singhvi","authors":[{"name":"Mr. Alex Okuno","aff":"Student, New York University"},{"name":"Prof. Divya Singhvi","aff":"Assistant Professor, New York University"},{"name":"Prof. Somya Singhvi","aff":"Assistant Professor, University of Southern California"}],"order":4}]},{"id":"s98","title":"Emerging Topics in Public Sector Operations","track":"Sustainable Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY G","chairs":["Prof. Jingwei Zhang"],"abstracts":[{"id":"136-0602","title":"Do Predictive Scheduling Laws Work?","content":"Unpredictable work schedules can negatively affect the welfare of service workers. Motivated by recent proposals to implement a predictive scheduling law, where employers must give advance notice for any schedule changes, we build a game-theoretic model to analyze the effect of the law and validate our findings with empirical evidence.","presenter":"Dr. Wee Kiat Lee","authors":[{"name":"Dr. Wee Kiat Lee","aff":"Assistant Professor, Nanyang Technological University"},{"name":"Dr. Yao Cui","aff":"Associate Professor, Cornell University"},{"name":"Prof. Karan Girotra","aff":"Professor, Cornell University"}],"order":1},{"id":"136-1014","title":"Time-Expanded School District Design Under Uncertainty","content":"We consider time-expanded public school district design models that allow districts to plan for multiple years and incorporate uncertainty in future student enrollment. Importantly, these models consider continuity in students’ educational experiences over time periods that may include the opening and closing of schools. \r\n","presenter":"Ms. Aysu Ozel","authors":[{"name":"Ms. Aysu Ozel","aff":"Student, Northwestern University"},{"name":"Prof. Karen Smilowitz","aff":"Professor, Northwestern University"}],"order":2},{"id":"136-1062","title":"Fair and Efficient Nonprofit Inventory Management under Display-Dependent Demand","content":"Inspired by warehouse data from a regional food bank in the US, we develop a novel model of nonprofit inventory management with the dual objective of balancing display fairness and throughput efficiency. We characterize optimal policies, identify factors driving fairness-efficiency trade-off and propose interventions to improve both objectives.","presenter":"Ms. Yuan Shi","authors":[{"name":"Prof. Mahyar Eftekhar","aff":"Associate Professor, Arizona State University Tempe"},{"name":"Ms. Yuan Shi","aff":"Student, Massachusetts Institute of Technology"},{"name":"Prof. Yanchong Zheng","aff":"Professor, Massachusetts Institute of Technology"}],"order":3},{"id":"136-1828","title":"Budget Allocation in Public Transit Planning for Different Income Groups","content":"Budget allocation in public transit planning is complex, shaped by resource constraints and diverse needs of different income groups. This paper characterizes the optimal pricing and transit time decisions for different income groups to maximize ridership, and shows that optimal allocation depends critically on income disparity","presenter":"Prof. Jingwei Zhang","authors":[{"name":"Prof. Owen Wu","aff":"Associate Professor, Indiana University"},{"name":"Prof. Jingwei Zhang","aff":"Assistant Professor, Cornell University"}],"order":4}]},{"id":"s128","title":"Digital Technologies in Manufacturing","track":"Operational Excellence","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"BAKER","chairs":["Dr. Daniel Kwasnitschka"],"abstracts":[{"id":"136-0584","title":"Supporting Physically Demanding Assembly Tasks With Exoskeletons: Effects on Worker Efficiency and Stress","content":"While the ergonomic benefits of exoskeletons are well-documented, their behavioral effects remain largely unexplored. This study examines the impact of back-and-shoulder exoskeletons on assembly workers' stress levels through a field experiment using physiological sensors and surveys. The study offers novel insights into the influence of exoskeletons on worker well-being.","presenter":"Mr. Jannick Fiedler","authors":[{"name":"Mr. Jannick Fiedler","aff":"Student, ETH Zurich"},{"name":"Prof. Torbjørn Netland","aff":"Professor, ETH Zurich"}],"order":1},{"id":"136-0688","title":"Rosy Signals and Postponement: Teeing up Future Risk in Maintenance Operations","content":"This study explores factors affecting maintenance quality and associated risks. Through interviews and analysis of 64,044 forklift maintenance services, we highlight risks from extended preventive maintenance intervals and over-reliance on positive signals (sensors) like battery charge. Findings emphasize timely maintenance and caution against misinterpreting signals, impacting long-term equipment reliability.","presenter":"Dr. Mateus do Rego Ferreira Lima","authors":[{"name":"Dr. Mateus do Rego Ferreira Lima","aff":"Assistant Professor, Kelley School of Business, Indiana Univ."},{"name":"Prof. Elliot Bendoly","aff":"Professor, Ohio State University"},{"name":"Dr. Nathan Craig","aff":"Assistant Professor, Ohio State University"},{"name":"Prof. Kenneth Boyer","aff":"Professor, Ohio State University"}],"order":2},{"id":"136-0227","title":"Real-Time Object Detection using AI for Enhanced Operational Efficiency","content":"In Operations the picking process often fails due to human errors requiring technological support to avoid further inefficiencies in the manufacturing process. We developed and evaluated with industry experts an AI-solution using real-time object detection to ensure 100% correct part picking according to the ERP system´s order.","presenter":"Mr. Md Khalid Siddiqui","authors":[{"name":"Mr. Md Khalid Siddiqui","aff":"Lecturer, University of Applied Science Neu-Ulm"},{"name":"Mr. Benjamin Hofmann","aff":"Lecturer, University of Applied Science Neu-Ulm"},{"name":"Dr. Jürgen Professor Grinninger","aff":"Professor, University of Applied Science Neu-Ulm"}],"order":4},{"id":"136-1824","title":"Leveraging Artificial Intelligence to Enhance Visionary Leadership and Performance Outcomes","content":"Visionary leadership often faces challenges due to unclear vision formulation and limited opportunities for communication within large organizations. This study explores how Artificial Intelligence (AI) can support leaders in crafting and disseminating visionary statements. We hypothesize that visionary leadership, facilitated by AI, enhances frontline workers’ task performance and promotive voice.","presenter":"Dr. Daniel Kwasnitschka","authors":[{"name":"Dr. Daniel Kwasnitschka","aff":"Assistant Professor, University of South Carolina"},{"name":"Prof. Henrik Franke","aff":"Assistant Professor, University of Cologne"},{"name":"Prof. David Waldman","aff":"Professor, Arizona State University"}],"order":6}]},{"id":"s148","title":"Emerging Technologies in Retail","track":"Information Systems and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY E","chairs":["Ms. Jingjing Weng"],"abstracts":[{"id":"136-0182","title":"Pricing in Live Streaming E-Commerce: Integrating Customer Type Analysis","content":"Influencers can demonstrate products and interact with customers on Live streaming e-commerce (LSE) platforms, reducing product uncertainty and raising the consumers' purchasing intention. In this research, we analytically model product-oriented and influencer-oriented customers to understand how online stores alter LSE frequency and pricing decisions to boost their revenue better.","presenter":"Mr. Yuan Dong","authors":[{"name":"Mr. Yuan Dong","aff":"Student, Temple University"},{"name":"Dr. Guohou Shan","aff":"Assistant Professor, Northeastern University"},{"name":"Dr. Subodha Kumar","aff":"Professor, Temple University"}],"order":1},{"id":"136-0199","title":"Are Smart Contracts Smart Enough? A Game Theoretic Approach for Implementing Blockchain-Enabled Group Purchasing","content":"This study examines the impact of blockchain adoption and smart contracts on supply chain profitability, focusing on a supplier and two competing retailers facing uncertain demand. While blockchain enables group purchasing and automates transactions, it requires information sharing, posing challenges for firms balancing operational benefits and competitive risks.","presenter":"Mr. Amirhossein Ranjbar","authors":[{"name":"Mr. Amirhossein Ranjbar","aff":"Student, Temple University"},{"name":"Dr. Subodha Kumar","aff":"Professor, Temple University"}],"order":2},{"id":"136-0659","title":"STAT v.s. Routine: Lie about service urgency","content":"Misuse of STAT in diagnostic medical services undermines its purpose, often reflecting system inefficiencies rather than true urgency. Our research explores the mechanisms behind false STAT reporting and proposes solutions to address priority inflation, ensuring timely care for genuinely urgent cases.","presenter":"Ms. Jingyi Peng","authors":[{"name":"Dr. Miao Bai","aff":"Assistant Professor, University of Connecticut"},{"name":"Prof. Guangwen Kong","aff":"Associate Professor, Temple University"},{"name":"Ms. Jingyi Peng","aff":"Student, Temple University"}],"order":3},{"id":"136-1944","title":"Pricing And Convenience Considerations In Omnichannel Assortment Planning","content":"This study addresses optimizing assortment planning and pricing for omnichannel grocery retailers using a mixed-integer nonlinear program. It jointly considers channel assortments and prices based on consumer preferences. A realistic case study quantifies channel convenience effects revealing useful insights. Model linearization aids in computational tractability.","presenter":"Mr. Joshua Gladstone","authors":[{"name":"Mr. Joshua Gladstone","aff":"Student, University of Massachusetts Amherst"},{"name":"Prof. Ahmed Ghoniem","aff":"Professor, University of Massachusetts Amherst"},{"name":"Dr. Bacel Maddah","aff":"Professor, American University of Beirut"}],"order":4}]},{"id":"s154","title":"Behavioral Healthcare Operations","track":"Healthcare Analytics","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"GRAND HALL EAST D","chairs":["Prof. Claire Senot"],"abstracts":[{"id":"136-0108","title":"Do Medical Malpractice Lawsuits impact physician clinical decision making: An empirical investigation","content":"In this study we investigate the existence of defensive medicine behavior by physicians following a malpractice lawsuit and the boundary conditions on this behavior.","presenter":"Dr. Luv Sharma","authors":[{"name":"Dr. Luv Sharma","aff":"Associate Professor, University of South Carolina"},{"name":"Dr. Deepa Goradia","aff":"Associate Professor, Georgia State University"},{"name":"Dr. Mengyang Pan","aff":"Associate Professor, Southwestern University of Finance and Economics"}],"order":1},{"id":"136-0112","title":"Minority Figures: Tokenism and Team Prosocial Behavior","content":"What is the effect of including a 'token' woman in a team on the prosocial behavior of the team and the token themselves? We investigate with a unique dataset of 50,000 observations of prosocial decisions in a healthcare setting and rigorous empirical models.","presenter":"Prof. Rob Glew","authors":[{"name":"Prof. Rob Glew","aff":"Assistant Professor, Mcgill University"},{"name":"Prof. Claire Senot","aff":"Associate Professor, Tulane University"}],"order":2},{"id":"136-0888","title":"Operational Overload: The Impact of Workload on High-Skilled Workforce Attrition","content":"Worker attrition is a significant and costly issue that disrupts operations across various sectors. This study seeks to explore how workload's various dimensions may have distinct relationships with voluntary attrition among knowledge workers.This investigation responds to the pressing need for insights into workforce retension strategies, particularly in knowledge-intensive enviornments.","presenter":"Ms. Blair Liu","authors":[{"name":"Ms. Blair Liu","aff":"Student, University of North Carolina Chapel Hill"},{"name":"Prof. Diwas KC","aff":"Professor, Emory University"},{"name":"Prof. Bradley Staats","aff":"Professor, University of North Carolina Chapel Hill"}],"order":3},{"id":"136-1434","title":"Examining Safety-Net Hospital Under-Performance on Patient Experience through the Horn Effect","content":"CMS uses the HCAHPS survey to measure patient experience and financially penalize under-performing hospitals. However, safety-net hospitals voice concerns that their hospitals systemically under-perform on HCAHPS. This paper formally tests whether safety-net hospitals are subject to a horn effect using a public-payer mix threshold that determines eligibility for care subsidies.","presenter":"Ms. Ankita Shirahatti","authors":[{"name":"Ms. Ankita Shirahatti","aff":"Student, Questrom School of Business"},{"name":"Prof. Anita Carson","aff":"Professor, Boston University"}],"order":4}]},{"id":"s178","title":"Responsible Operations in Agriculture and Food Supply Chains","track":"Agriculture and Food Supply Chains","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"VININGS","chairs":["Prof. Can Zhang"],"abstracts":[{"id":"136-0189","title":"A Multiperiod Multicommodity Capacitated International Agricultural Trade Network Equilibrium Model with Applications to Ukraine","content":"Disasters worldwide have affected the trade of agricultural commodities needed for food security. We construct a multiperiod multicommodity international agricultural trade network equilibrium model with capacity constraints on the production, transportation, and storage. Numerical examples inspired by the effects of Russia’s invasion of Ukraine on agricultural trade are presented.","presenter":"Mr. Dana Hassani","authors":[{"name":"Mr. Dana Hassani","aff":"Student, University of Massachusetts Amherst"},{"name":"Prof. Anna Nagurney","aff":"Professor, University of Massachusetts Amherst"},{"name":"Dr. Oleg Nivievskyi","aff":"Assistant Professor, Kyiv School of Economics"},{"name":"Dr. Pavlo Martyshev","aff":"Post Doc/Researcher, Kyiv School of Economics"}],"order":1},{"id":"136-0579","title":"Optimal Investment of Farming Mechanization","content":"Adopting mechanization in farming is a fundamental and sustainable approach to increase agricultural productivity. We study a farmer's optimal procurement of seeds and farming mechanization for a single crop under budget constraint in one cropping season. We show the optimal investment policy of a monopoly farmer and farmers in competition.","presenter":"Prof. Ying Zhang","authors":[{"name":"Prof. Ying Zhang","aff":"Assistant Professor, Santa Clara University"},{"name":"Prof. Jayashankar Swaminathan","aff":"Professor, University of North Carolina Chapel Hill"}],"order":2},{"id":"136-0871","title":"Yielding to the Weather: How Climate Change Impacts Planting Decisions and Consumers","content":"Climate change is affecting crop yields worldwide and presenting threats to the global food supply chain. We characterize the impact of climate change on crops’ yields on consumers and agricultural firms. Our results show that a lack of coordination between competing firms could be hurting consumers and firms alike.","presenter":"Mr. Yaniv Ravid","authors":[{"name":"Dr. Hongqiao Chen","aff":"Assistant Professor, Nanjing University"},{"name":"Prof. Ming Hu","aff":"Professor, University of Toronto"},{"name":"Mr. Yaniv Ravid","aff":"Student, Rotman School of Management"},{"name":"Dr. Wenbin Wang","aff":"Professor, Shanghai Univ. of Finance and Economics"}],"order":3},{"id":"136-1509","title":"Reducing Food Waste: The Impact of Online Grocery Shopping","content":"The adoption and use of online grocery shopping have rapidly increased in recent years. This paper examines how the advent of online grocery shopping influences household and retail-level decisions and analyzes its role in reducing food waste along the supply chain.","presenter":"Ms. Jimin Park","authors":[{"name":"Ms. Jimin Park","aff":"Student, Massachusetts Institute of Technology"},{"name":"Prof. Yanchong Zheng","aff":"Professor, Massachusetts Institute of Technology"}],"order":4}]},{"id":"s190","title":"Human AI Interaction","track":"Service Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY C","chairs":["Prof. Kejia Hu","Mr. Fan Zhang"],"abstracts":[{"id":"136-1143","title":"Improving Process Flow in a Child-Welfare System: A Data-Driven Approach.","content":"We study the problem of a case manager of a Child Welfare Organization (CWO). \r\nThey receive suspected cases of child maltreatment and provide services to child and family. CWOs are short-staffed. In collaboration with a CWO, we study to maximize throughput and reduce the error rates in determining case resolutions.","presenter":"Mr. Shubham Akshat","authors":[{"name":"Mr. Shubham Akshat","aff":"Assistant Professor, University of Houston"},{"name":"Prof. Alan Scheller-Wolf","aff":"Professor, Tepper School of Business"},{"name":"Ms. Lindsey Lacey","aff":"Analyst, ."},{"name":"Ms. Justine Galbraith","aff":"Analyst, ."}],"order":1},{"id":"136-1675","title":"Aligning Incentives in E-Commerce Refund Disputes: Contract Design and AI Copilots","content":"E-commerce platforms face challenges in managing refund disputes. This study first develops an optimal contract design between platforms and agents to mitigate moral hazard in traditional dispute resolution. We then extend the model to examine how AI copilots' integration transforms contract design and agent behavior in refund decision-making processes.","presenter":"Ms. Qiaowen Guo","authors":[{"name":"Ms. Qiaowen Guo","aff":"Student, Washington University in St. Louis"},{"name":"Dr. Fuqiang Zhang","aff":"Professor, Washington University St Louis"}],"order":2},{"id":"136-0218","title":"How do retailers’ cash preferences and customer self-regulation shape adoption of cashless payments?","content":"High transaction fees and a strong preference for cash discourage the adoption of cashless payments in Japan. Many retailers encourage cash payment, while customers also view cash as beneficial. We develop a game-theoretic model to examine how these dynamics influence the growth of cashless payment systems.","presenter":"Dr. Hisashi Kurata","authors":[{"name":"Dr. Hisashi Kurata","aff":"Professor, Yokohama National University"}],"order":3},{"id":"136-1212","title":"Digital Transformation Pathway: Hiring Strategy for Business and Data Specialists","content":"This study examines two human capital strategies of firm's digital transformation: equipping business specialists with data skills and equipping data specialists with business acumen. Our findings suggest that business specialists with data skills contribute more to enhancing firm performance.","presenter":"Mr. Fan Zhang","authors":[{"name":"Prof. Kejia Hu","aff":"Associate Professor, University of Oxford"},{"name":"Prof. Yuanyang Liu","aff":"Assistant Professor, University of Tennessee, Knoxville"},{"name":"Mr. Fan Zhang","aff":"Student, Northwestern University"}],"order":4}]},{"id":"s204","title":"Customer Behavior in Retail Operations","track":"Retail Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"FAIRLIE","chairs":["Prof. Yannis Stamatopoulos","Prof. Jacob Zeng"],"abstracts":[{"id":"136-0369","title":"Algorithmic Nudging for Energy Savings and Environment: Evidence from an IoT Platform","content":"We study how algorithmic nudging can reduce energy consumption using data from an IoT platform.","presenter":"Prof. Jacob Zeng","authors":[{"name":"Prof. Jacob Zeng","aff":"Assistant Professor, Gonzaga University"},{"name":"Dr. Serasu Duran","aff":"Assistant Professor, University of Calgary"},{"name":"Prof. Nil Karacaoglu","aff":"Assistant Professor, The Ohio State University"},{"name":"Prof. Nur Sunar","aff":"Associate Professor, Kenan-Flagler Business School"}],"order":1},{"id":"136-0973","title":"Consumer Valuation of Sustainable Product Attributes (SPA)","content":"We systematically study the valuation of sustainable product attributes, which replace product attributes tied to negative externalities. Such sustainable alternatives often involve trade-offs, imposing private costs for consumers in exchange for public benefits. Conventional approaches to the valuation of SPAs pose significant conceptual and practical challenges.","presenter":"Dr. Jingyao Huang","authors":[{"name":"Dr. Jingyao Huang","aff":"Assistant Professor, University of Missouri At Kansas City"},{"name":"Dr. Ranjit Christopher","aff":"Associate Professor, University of Missouri- Kansas City"},{"name":"Prof. Fernando Machado","aff":"Professor, Católica Lisbon School of Business &amp; Economics"}],"order":2},{"id":"136-1805","title":"Expanding Retail Opportunities: Leveraging Secondhand Consumption for Product Personalization and Positioning","content":"This paper explores secondhand consumption as a strategic opportunity for personalization and sustainability, based on ethnographic research at a US thrift store. Findings highlight its potential for new and secondhand retailers to meet diverse consumer needs, enhance positioning strategies, and promote personalization without contributing to overproduction.","presenter":"Dr. Mariella Zavala","authors":[{"name":"Dr. Mariella Zavala","aff":"Assistant Professor, Gonzaga University"}],"order":3},{"id":"136-1324","title":"Enhancing Customer Retention in Quick Commerce Grocery Market Using Machine Learning and Explainable AI","content":"This study enhances the traditional LRFM framework with the ‘Delivery rate’ and ‘Purchase quantity’ metrics for loyalty prediction in grocery quick commerce. Using PCA, K-means clustering, and hybrid machine learning, it identifies key loyalty drivers. LIME-based explainable insights guide retention strategies, driving satisfaction and growth in the competitive market.","presenter":"Mr. Rahul Chavhan","authors":[{"name":"Mr. Rahul Chavhan","aff":"Student, IIT Bombay"},{"name":"Prof. Pankaj Dutta","aff":"Professor, Indian Institute of Technology Bombay"}],"order":5}]},{"id":"s217","title":"Algorithms and Operations in Healthcare, Real Estate, and Supply Chains","track":"Disruptive Technologies and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"KENNESAW","chairs":["Dr. Xiaojin Liu","Ms. Deepanshi Bhardwaj"],"abstracts":[{"id":"136-0324","title":"Adapting to Market Uncertainties: The Effect of Industry Concentration on Supplier Differentiation","content":"Amidst rising market uncertainties, firms recognize the increasing need to develop efficient, effective, and adaptable supply chains. We conduct an empirical investigation into how a focal firm's position in a concentrated product market affects its supply chain reconstruction, specifically in terms of vertical integration and supply-base differentiation.","presenter":"Dr. Feng Cheng","authors":[{"name":"Dr. Xiaojin Liu","aff":"Associate Professor, Virginia Commonwealth University"},{"name":"Dr. Feng Cheng","aff":"Assistant Professor, Towson University"},{"name":"Dr. Kedong Chen","aff":"Assistant Professor, Old Dominion University"},{"name":"Dr. Pankaj Kumar","aff":"Associate Professor, Virginia Tech"}],"order":1},{"id":"136-0493","title":"Resolving a Statistical Challenge in Healthcare Risk Adjustment","content":"Inspired by a recent change proposed by CMS, we develop a novel estimation algorithm to improve the prediction accuracy of the HHS-HCC risk adjustment model. We empirically demonstrate that our method achieves nearly perfect actuarial equivalence across all patient risk classes.","presenter":"Dr. Kanix Wang","authors":[{"name":"Dr. Kanix Wang","aff":"Assistant Professor, University of Cincinnati"},{"name":"Dr. Zhaowei She","aff":"Assistant Professor, Singapore Management University"}],"order":2},{"id":"136-1045","title":"Healthcare Algorithms and Racial Disparities","content":"Healthcare algorithms are increasingly used for diagnosis, treatment, prognosis, risk stratification, and resource allocation. While promising for improving care quality, concerns persist about their potential to perpetuate biases and exacerbate inequities. We quantify the effects of healthcare algorithms on clinical outcomes, with a focus on their impact on racial disparities.","presenter":"Dr. Qi Wang","authors":[{"name":"Dr. Qi Wang","aff":"Post Doc/Researcher, Boston University"},{"name":"Dr. Jiayi Liu","aff":"Assistant Professor, Virginia Polytechnic Institute And State University"},{"name":"Prof. Anandhi Bharadwaj","aff":"Professor, Emory University"}],"order":3},{"id":"136-1738","title":"Impact of an Online Platform’s Algorithmic Upgrades on Local Employment","content":"This study explores the effects of an online platform’s algorithmic upgrades on local employment. Using employment data from the real estate industry across regions, our analysis reveals a significant negative impact, particularly in poorer areas and regions with high technology penetration. These findings provide important insights for policy formulation.","presenter":"Dr. Xiaojin Liu","authors":[{"name":"Ms. Lingyu Li","aff":"Student, Virginia Commonwealth University"},{"name":"Prof. Yeongin Kim","aff":"Assistant Professor, Wake Forest University"},{"name":"Dr. Xiaojin Liu","aff":"Associate Professor, Virginia Commonwealth University"}],"order":5}]},{"id":"s219","title":"Navigating Uncertainty in Innovation and Entrepreneurship","track":"Product Innovation and Technology Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"AUBURN","chairs":["Dr. Sinan Erzurumlu"],"abstracts":[{"id":"136-0477","title":"Noisy Sequential &amp; Parallel Testing of Designs: Theory and Experiment","content":"Many decision tasks, from choosing the appropriate product design to selecting the go-to-market strategy, may be conceptualized as a search process where the decision maker evaluates multiple alternatives with the goal of selecting one. We experimentally study how the managers make these decisions in the face of measurement errors.","presenter":"Prof. Sanjiv Erat","authors":[{"name":"Ms. Ping-Chieh Huang","aff":"Student, University of California, San Diego"},{"name":"Prof. Sanjiv Erat","aff":"Associate Professor, University of California, San Diego"},{"name":"Prof. Sreekumar Bhaskaran","aff":"Associate Professor, Southern Methodist University"}],"order":1},{"id":"136-0597","title":"AI Use, Startup Funding, and Performance: Evidence from British Startup Firms","content":"We examine the investment patterns of venture capitalists related to AI in British \r\nstartup firms. We try to answer key questions such as: Whether AI ventures attract more funding? Whether the novelty of AI affects the amount of VC funding? And whether the investment contributes to firm success?","presenter":"Ms. Yiyao Zhou","authors":[{"name":"Ms. Yiyao Zhou","aff":"Student, UCL School of Management"},{"name":"Prof. Bilal Gokpinar","aff":"Professor, University College London"},{"name":"Prof. Onesun Yoo","aff":"Associate Professor, University College London"}],"order":2},{"id":"136-0724","title":"Evaluating the Implementation of AI-Motion Recognition for Home-Based Physical Therapy","content":"This research evaluates the implementation of AI-driven motion recognition technology for home-based physical therapy. Findings from a 12-week clinical trial demonstrate improved exercise adherence and recovery outcomes. In-depth interviews with patients and therapists provide insights for the successful integration and adoption of AI-powered health solutions in clinical practice.","presenter":"Mr. Pierre Gautreau","authors":[{"name":"Mr. Pierre Gautreau","aff":"Student, York University"},{"name":"Prof. Moren Levesque","aff":"Professor, York University"}],"order":3}]},{"id":"s226","title":"Online platforms and emerging technologies","track":"Digital Platforms, Innovations and Transformations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"GREENBRIAR","chairs":["Dr. Wenchang Zhang"],"abstracts":[{"id":"136-1313","title":"Disintermediation evidence from a cleaning platform","content":"We develop a framework to detect disintermediation using run-of-the-mill, observational transaction data. The framework can be applied to any two-sided platform with repeat customer-service provider interactions. We validate our framework using extensive simulations and provide evidence of disintermediation in a European cleaning platform.","presenter":"Prof. Simin Li","authors":[{"name":"Prof. Nil Karacaoglu","aff":"Assistant Professor, The Ohio State University"},{"name":"Prof. Simin Li","aff":"Assistant Professor, Tulane University"},{"name":"Prof. Yannis Stamatopoulos","aff":"Associate Professor, The University of Texas at Austin"}],"order":1},{"id":"136-1818","title":"A structural forest estimation of heterogeneous newsvendor models","content":"We develop a causal forest method to perform structural estimation for newsvendor models with large heterogeneities. We demonstrate the statistical properties of this method and validate its accuracy through simulation experiments. Applying this method to healthcare data, we analyze surgeons’ decision-making in scheduling operating rooms.","presenter":"Dr. Mengfei Li","authors":[{"name":"Dr. Mengfei Li","aff":"Student, Fudan University"},{"name":"Prof. Guihua Wang","aff":"Associate Professor, University of Texas Dallas"},{"name":"Dr. Wenchang Zhang","aff":"Assistant Professor, Kelley School of Business"},{"name":"Prof. Xiaole Wu","aff":"Professor, Fudan University"}],"order":2},{"id":"136-1870","title":"Design of Resale Platforms","content":"We study resale platforms, which enable individuals to supplement their income by selling products to others. Combining theory and empirics, we illustrate how competition among resellers intensifies with platform growth, resulting in lower margins and reduced search effort. We analyze platform design interventions that mitigate the adverse effects on resellers.","presenter":"Dr. Ilan Morgenstern","authors":[{"name":"Dr. Ilan Morgenstern","aff":"Student, Yale University"},{"name":"Prof. Divya Singhvi","aff":"Assistant Professor, New York University"},{"name":"Prof. Somya Singhvi","aff":"Assistant Professor, University of Southern California"},{"name":"Prof. Daniela Saban","aff":"Assistant Professor, Stanford University"}],"order":3},{"id":"136-1974","title":"Can AI Replace Human Judgment? Evidence from Online Advertising Campaigns","content":"This study examines the effect of AI-driven keyword auction campaigns on e-commerce sellers’ performance. It reveals that although AI enhances sales revenue, manually configured campaigns surpass automated ones by utilizing sellers’ private knowledge, market dynamics, and bidding strategies. The findings highlight the complementary role of human expertise alongside AI automation","presenter":"Mr. Saradhi Somarouthu","authors":[{"name":"Mr. Saradhi Somarouthu","aff":"Student, Kelley School of Business"}],"order":4}]},{"id":"s231","title":"Online Advertising, and Digital Marketplaces and Platforms","track":"Service Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"INMAN","chairs":["Dr. Sami Najafi-Asadolahi"],"abstracts":[{"id":"136-0190","title":"From Hatchbacks to Minivans: Optimizing Acceptance and Packing Decisions on Two-Sided Car-Shipping Platforms","content":"We consider a two-sided platform facilitating car-shipping services that faces stochastic arrivals of demand and supply. The platform's problem is categorized into two separate cases: excess-trucks/excess-cars case. We propose different policies for different cases and show their asymptotic-optimality when arrival rates scale up at a rate of n.","presenter":"Mr. Haokun Du","authors":[{"name":"Mr. Haokun Du","aff":"Student, The University of Texas at Dallas"},{"name":"Mr. Arun Kumar Rout","aff":"Assistant Professor, State University of New York"},{"name":"Prof. Milind Dawande","aff":"Professor, The University of Texas at Dallas"},{"name":"Prof. Ganesh Janakiraman","aff":"Professor, The University of Texas at Dallas"}],"order":1},{"id":"136-1995","title":"Optimal Service Matching Policy in Mixed Ride-Hailing Platforms with Autonomous Vehicles","content":"As the penetration of Autonomous Vehicles in ride-hailing services continues to increase, mixed ride-hailing platforms have emerged, offering both AVs and traditional human-driven vehicles. However, not all consumers are willing to accept AVs, hence, we explore the service matching modes and pricing strategies of platforms account for diverse user preferences.","presenter":"Mr. Jiyuan Guo","authors":[{"name":"Mr. Jiyuan Guo","aff":"Student, College of Management and Economics, Tianjin University"},{"name":"Prof. Shuai Ling","aff":"Professor, Tianjin Uinversity"},{"name":"Prof. Shoufeng Ma","aff":"Professor, Tianjin University"}],"order":2},{"id":"136-0926","title":"Understanding Customer Preferences for Virtual versus In-Person Services","content":"As multi-channel services become more common, understanding the value customers place on virtual and in-person services has become increasingly important. Using data from a provider with in-person and virtual channels, we examine how service delivery channels and attributes—such as duration and distance—shape customer choices.","presenter":"Mr. Omer Berk Olmez","authors":[{"name":"Mr. Omer Berk Olmez","aff":"Student, Baruch College, Graduate Center, CUNY"},{"name":"Prof. Alex Mills","aff":"Professor, Baruch College"}],"order":3},{"id":"136-2004","title":"Optimal Steady-State Advertiser-Agency Contracts for Digital Display Advertising","content":"We develop a steady-state optimization framework for advertiser-agency contracts in digital display advertising. Given agency pricing, the advertiser’s optimal spending and arrival rates replicate the same revenue and bidding outcomes the agency would independently choose. This ensures that the agency’s bidding strategies fully align with advertiser financial objectives in equilibrium.","presenter":"Dr. Sami Najafi-Asadolahi","authors":[{"name":"Prof. Naren Agrawal","aff":"Professor, Leavey School of Business"},{"name":"Dr. Sami Najafi-Asadolahi","aff":"Associate Professor, Santa Clara University"},{"name":"Prof. Stephen Smith","aff":"Professor, Santa Clara University"}],"order":4}]},{"id":"s234","title":"Supply Chain Sustainability","track":"Supply Chain Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY A","chairs":["Ms. Jaachinma Okafor"],"abstracts":[{"id":"136-0179","title":"Fortifying Distribution Network Nodes Subject to Different Disruption Levels at Each Node","content":"We consider a distribution network in which flow disruptions may occur. Our proposed model determines node fortification levels that maximize service availability under a limited budget and various assumptions on network structure, the nature of potential disturbances, and their associated probability distributions.","presenter":"Ms. Pelin Kesrit","authors":[{"name":"Ms. Pelin Kesrit","aff":"Student, Texas A&amp;M University"},{"name":"Dr. Bahar Cavdar","aff":"Assistant Professor, Rensselaer Polytechnic Institute"},{"name":"Prof. Joseph Geunes","aff":"Professor, Texas A&amp;M University College Station"}],"order":1},{"id":"136-0244","title":"Competition for acquisition between non-profit and for-profit organizations in the resale used apparel market","content":"Charities and for-profit organizations compete for the acquisition of consumers’ used apparel. Social and economic factors matter for consumers’ disposal decisions. We study how disposal decisions are impacted by the (1) organizations’ profit orientation, (2) financial reward level, and (3) convenience level by conducting incentivized discrete-choice laboratory experiments.","presenter":"Ms. Sabrina Rinder","authors":[{"name":"Ms. Sabrina Rinder","aff":"Student, University of Graz"},{"name":"Prof. Marc Reimann","aff":"Professor, University of Graz"},{"name":"Prof. Gil Souza","aff":"Professor, University of Tennessee Knoxville"},{"name":"Prof. Guido Voigt","aff":"Professor, Universitaet Hamburg"}],"order":2},{"id":"136-0252","title":"Alleviating consumers anxiety for Electric Vehicles: Balancing vehicle range and charging network","content":"EV adoption remains slow due to range anxiety, high costs, and insufficient charging infrastructure. This research investigates the interaction between vehicle range and charging network density, proposing a systems approach to alleviate consumer anxiety and enhance market equilibrium and environmental outcomes.","presenter":"Mr. Vikash Kumar","authors":[{"name":"Mr. Vikash Kumar","aff":"Student, Ivey Business School"},{"name":"Prof. Gal Raz","aff":"Associate Professor, Ivey Business School, Western University"}],"order":3},{"id":"136-0508","title":"Incentivizing Voluntary Supplier GHG Emissions Reduction","content":"This study explores strategies for firms to incentivize suppliers to voluntarily reduce their emissions, focusing on upstream impacts. Employing a behavioral experiment and game-theoretic analysis, we identify mechanisms that align supplier incentives with corporate carbon reduction goals, offering actionable insights for managing emissions in response to evolving consumer preferences.","presenter":"Ms. Jaachinma Okafor","authors":[{"name":"Ms. Jaachinma Okafor","aff":"Student, The University of Tennessee-Knoxville"},{"name":"Prof. Marc Reimann","aff":"Professor, University of Graz"},{"name":"Prof. Gil Souza","aff":"Professor, University of Tennessee Knoxville"},{"name":"Prof. Guido Voigt","aff":"Professor, Universitaet Hamburg"}],"order":4}]},{"id":"s256","title":"AI in Business","track":"Data Science, Analytics and AI","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"ROSWELL","chairs":["Ms. Zezhen (Dawn) He"],"abstracts":[{"id":"136-1269","title":"Identification of key factors on carbon neutrality readiness in China's regional manufacturing under rule mining","content":"This study constructs a data mining technology framework based on interpretable ensemble learning, and proposes the concept of Carbon Neutrality Readiness in Manufacturing (CNRM). The key factors and synergistic relationships of CNRM in China are identified from regional level, and the strong association rules under the type regions are extracted.","presenter":"Ms. Yifan Zhang","authors":[{"name":"Ms. Yifan Zhang","aff":"Student, Southeast University, Nanjing, China"},{"name":"Prof. Wenping Wang","aff":"Professor, Southeast University, Nanjing, China"}],"order":1},{"id":"136-1058","title":"Exploring Community Equity Using Google Maps Reviews","content":"This study examines community inequity through the lens of Google Maps review data, leveraging user-generated content to gain insights into perceptions of disparities across communities. Our findings highlight patterns in customer sentiment that reflect underlying inequities, offering a novel approach to understanding and addressing community challenges through digital platforms.","presenter":"Ms. Hongli Ye","authors":[{"name":"Ms. Hongli Ye","aff":"Assistant Professor, University of Florida"},{"name":"Mr. Lingyao Li","aff":"Assistant Professor, University of South Florida"},{"name":"Mr. Songhua Hu","aff":"Post Doc/Researcher, MIT"}],"order":2},{"id":"136-0909","title":"Supervised Learning for Maintenance Optimization","content":"We propose a new non-parametric learning method for data-driven maintenance optimization, where the machine's condition is monitored during its lifetime. We prove our method converges fast to the optimal policy with exponentially-reducing error margins, and show its effectiveness compared to existing methods on two case studies.","presenter":"Mr. Joost van der Haar","authors":[{"name":"Mr. Joost van der Haar","aff":"Student, KU Leuven"},{"name":"Dr. Collin Drent","aff":"Assistant Professor, Eindhoven University of Technology"},{"name":"Prof. Robert Boute","aff":"Professor, KU Leuven"}],"order":3},{"id":"136-1016","title":"Model Agnostic Inter-Temporal Explanations","content":"Predictions over time may seem inconsistent despite high model accuracy, due to environmental stochasticity and uncertainty. To address this, we propose inter-temporal explanations—a novel approach designed to clarify the reasons behind such inconsistencies in model predictions, with the goal of mitigating users' negative reactions to perceived inconsistency.","presenter":"Ms. Zezhen (Dawn) He","authors":[{"name":"Ms. Zezhen (Dawn) He","aff":"Student, University of Rochester"},{"name":"Prof. Yaron Shaposhnik","aff":"Associate Professor, Simon Business School"}],"order":4}]},{"id":"s262","title":"Platforms, Recommendation Systems, and Automation","track":"POM-Marketing Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"DUNWOODY","chairs":["Prof. Baojun Jiang","Dr. Tianxin Zou"],"abstracts":[{"id":"136-0143","title":"Brand External Advertising and Platform Strategy on Product Discoverability","content":"A retail platform faces a tradeoff in its design of product discoverability: a higher level of product discoverability increases the purchase likelihood for shoppers on the platform, but causes “leakages” in brands’ external awareness advertising, reducing brands’ advertising incentives and consequently the platform’s shopper traffic.","presenter":"Mr. Guangzhi Chen","authors":[{"name":"Mr. Guangzhi Chen","aff":"Student, Warrington College of Business"},{"name":"Dr. Zheyin Gu","aff":"Associate Professor, University of Connecticut"},{"name":"Dr. Tianxin Zou","aff":"Assistant Professor, Warrington College of Business"}],"order":1},{"id":"136-1936","title":"Algorithmic Collusion of Pricing and Advertising on E-commerce Platforms","content":"Online sellers have been adopting AI learning algorithms to automatically make product pricing and advertising decisions on e-commerce platforms. We empirically investigate the impact of these learning algorithms when sellers make pricing and advertising decisions together. We find learning algorithms can facilitate beneficial outcomes for consumers, sellers, and platforms.","presenter":"Ms. Hangcheng Zhao","authors":[{"name":"Ms. Hangcheng Zhao","aff":"Student, University of Pennsylvania"},{"name":"Mrs. Ron Berman","aff":"Associate Professor, University of Pennsylvania"}],"order":2},{"id":"136-0144","title":"Designing Recommendation Systems on Content Platforms: Trading off Quality and Variety","content":"We reveal a tradeoff between the provision of content quality and variety on a content platform's recommendation system. While emphasizing content's fit benefits consumers and the platform, emphasizing quality in recommendations may hurt consumers by reducing the variety of content produced and the chance for trendy content's emergence.","presenter":"Dr. Tianxin Zou","authors":[{"name":"Dr. Tianxin Zou","aff":"Assistant Professor, Warrington College of Business"},{"name":"Dr. Yue Wu","aff":"Associate Professor, university of pittsburg"},{"name":"Mr. Miklos Sarvary","aff":"Professor, Columbia University"}],"order":3},{"id":"136-0653","title":"The welfare effect of Right-to-Repair (RTR) policies","content":"Right-to-Repair (RTR) policies ensure that consumers have the ability to repair products themselves or choose independent repair providers, without being limited to the original manufacturers’ authorized repair channels. However, our analysis shows that RTR polices can potentially harm consumer welfare.","presenter":"Mr. Suming Hu","authors":[{"name":"Dr. Shu Hu","aff":"Assistant Professor, Southwest Jiaotong University"},{"name":"Mr. Suming Hu","aff":"Student, Washington University in St Louis"},{"name":"Prof. Baojun Jiang","aff":"Professor, Washington University in St. Louis"},{"name":"Prof. Hang Wei","aff":"Professor, Shanghai Univ. of Finance and Economics"}],"order":4}]},{"id":"s282","title":"Advances in Optimization and Logistics Applications","track":"Aviation, Transportation, and Logistics Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"UNIVERSITY","chairs":["Prof. Rui Zhang"],"abstracts":[{"id":"136-0886","title":"Solving the Pollution Routing Problem with Hilly Topography","content":"This study addressees the pollution routing problem under a particular setting that includes irregular topography and speed optimization. We propose two solution approaches (approximate and exact) for solving modified Solomon benchmarks and newly constructed real-life problem instances. Results show the good performance of proposed methods and suggest several managerial insights.","presenter":"Prof. Yasel Costa","authors":[{"name":"Prof. Yasel Costa","aff":"Professor, Zaragoza Logistics Center (ESG50985993)"},{"name":"Prof. William Sarache","aff":"Professor, Universidad Nacional De Colombia"},{"name":"Prof. David Lai","aff":"Associate Professor, Queen Mary University of London"}],"order":1},{"id":"136-0216","title":"A Dynamic Strategic Plan for Transition to a Clean Bus Fleet using Multistage Stochastic Programming","content":"We propose a multistage stochastic program to optimize strategic plans for clean bus fleet transition, considering the uncertainty scenarios in cost and efficiency. Our optimization model minimizes the total expected cost subject to emission targets and budget restrictions. As a case study, we focus on the Istanbul public bus network.","presenter":"Dr. Burak Kocuk","authors":[{"name":"Mr. Neman Karimi","aff":"Student, Sabanci University"},{"name":"Dr. Burak Kocuk","aff":"Associate Professor, Sabanci University Tuzla Vd 7360078450"},{"name":"Dr. Tugce Yuksel","aff":"Assistant Professor, Sabanci University"}],"order":2},{"id":"136-0739","title":"Relay-Hub Network Design for Consolidation Planning Under Demand Variability","content":"We develop a two-stage stochastic program for designing relay-based transportation networks under demand uncertainty. By designing a decomposition-based branch-and-cut algorithm, we solve large-scale problems for a U.S. car manufacturer. Our results offer insights into inducing flexibility in relay networks to hedge against demand variability while minimizing transportation costs.","presenter":"Prof. Mathieu Dahan","authors":[{"name":"Mr. Onkar Anand Kulkarni","aff":"Student, Georgia Institute of Technology"},{"name":"Prof. Mathieu Dahan","aff":"Assistant Professor, Georgia Institute of Technology"},{"name":"Prof. Benoit Montreuil","aff":"Professor, Georgia Institute of Technology"}],"order":3},{"id":"136-1464","title":"EFFECTION: An Exact Solution Approach for the Formation and Routing of Worker Teams","content":"We present a novel, exact solution approach for the Team Formation and Routing Problem (TFRP) for airport ground handling operations to minimize the sum of weighted completion times for baggage loading and unloading tasks. The proposed approach dynamically detects time points with continuous time to obtain exact solutions.","presenter":"Prof. Rui Zhang","authors":[{"name":"Prof. Jiliu Li","aff":"Associate Professor, Northwestern Polytechnical University"},{"name":"Mr. Jinfeng Yang","aff":"Student, Northwestern Polytechnical University"},{"name":"Prof. Rui Zhang","aff":"Associate Professor, University of Colorado Boulder"},{"name":"Mr. Nan Huang","aff":"Student, Huazhong University of Science and Technology"}],"order":4}]},{"id":"s308","title":"Managing bottom-up Participation in Humanitarian Operations","track":"Operations and Society","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"SPRING","chairs":["Mr. Daan van Beek"],"abstracts":[{"id":"136-0544","title":"Incentive mechanism to stimulate information sharing for the purpose of joint procurement","content":"Humanitarian organizations (HOs) must share information for effective joint procurement. Potentially losing competitive advantage, HOs are reluctant to share information. Our principal-agent approach illustrates that the optimality of incentives to share information depends on the degree of heterogeneity of HOs, nuancing concurrent understanding of sources of competition, such as funding.","presenter":"Mr. Daan van Beek","authors":[{"name":"Mr. Daan van Beek","aff":"Student, Kuehne Logistics University"},{"name":"Prof. Andreas Gernert","aff":"Assistant Professor, Kuehne Logistics University"},{"name":"Prof. Maria Besiou","aff":"Professor, Kuehne Logistics University"}],"order":1},{"id":"136-0547","title":"Empowering Frontline Voices: Driving Innovation and Responsiveness in Humanitarian Operations","content":"This mixed-method study explores how frontline workers' voices drive bottom-up innovation, improving humanitarian operations' responsiveness. However, excessive input can overwhelm leaders and hinder crisis response. The findings highlight the need to balance listening to frontline workers with managing input to ensure effective innovation and operational success in challenging environments.","presenter":"Prof. Lea Ruesch","authors":[{"name":"Prof. Lea Ruesch","aff":"Assistant Professor, IE BUSINESS SCHOOL"},{"name":"Dr. Mojtaba Salem","aff":"Assistant Professor, Kühne Logistics University"},{"name":"Dr. Ilka Gleibs","aff":"Associate Professor, London School of Economics"}],"order":2},{"id":"136-0841","title":"Impact of Training on Humanitarian Operations Performance","content":"Training humanitarian practitioners is crucial yet challenging due to funding constraints. This study, based on field observations, surveys, and interviews, evaluates the Global Logistics Cluster's Logistics Response Training (LRT). Findings highlight LRT's role in enhancing leadership and emergency response skills, describing how it may contribute to improved humanitarian operations performance.","presenter":"Dr. Mojtaba Salem","authors":[{"name":"Dr. Mojtaba Salem","aff":"Assistant Professor, Kühne Logistics University"},{"name":"Mrs. Vasiliki Tsitsopoulou","aff":"Student, Kühne Logistics University"},{"name":"Prof. Maria Besiou","aff":"Professor, Kuehne Logistics University"}],"order":3},{"id":"136-1431","title":"When Crowds Take Control: Shaping Resources Through Contingent Earmarking Decisions","content":"Crowds assert control over the resources they allocate to organizations, particularly in humanitarian contexts. We examine three donation modes: earmarking, non-earmarking, and what we term contingent earmarking that enables donors to set redistribution terms. Experiments show that contingent earmarking balances transparency-efficiency trade-offs, boosting donations and improving HO fund reallocation.","presenter":"Ms. Hooria Sajjad","authors":[{"name":"Ms. Hooria Sajjad","aff":"Student, Kühne Logistics University gGmbH"},{"name":"Ms. Christina Raasch","aff":"Professor, Kuehne Logistics University"},{"name":"Prof. Maria Besiou","aff":"Professor, Kuehne Logistics University"}],"order":4}]},{"id":"s343","title":"Featured Speaker Series Workshop: Renewable Energy and Circularity: An Operations Perspective","track":"Tutorials and Workshops in Research and Teaching","type":"Workshop","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"Learning Center","chairs":["Prof. Atalay Atasu"],"abstracts":[{"id":"136-2074","title":"Featured Speaker Series_Workshop_Renewable Energy and Circularity: An Operations Perspective","content":"In this workshop, we will introduce the broader idea of a circular economy, demonstrate why it is essential in the renewable energy transition, and try to shed light on its fundamental principles, misconceptions, and the research need for realism in the same space.","presenter":"Prof. Atalay Atasu","authors":[{"name":"Prof. Atalay Atasu","aff":"Professor, INSEAD"}],"order":1}]},{"id":"s383","title":"Risk Models and Metrics","track":"Supply Chain Risk Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY H","chairs":["Dr. William Haskell"],"abstracts":[{"id":"136-0067","title":"Sustainable Supplier Selection: from Operational to ESG-based Risk Assessment","content":"Aligned with the Sustainable Development Goals (SDGs), this research develops a comprehensive supplier selection framework that integrates Environmental, Social, and Governance (ESG) considerations. Using mathematical modeling, it assesses risks across financial, operational, and social dimensions, providing a holistic approach to sustainable supplier selection and enhancing long-term supply chain resilience.","presenter":"Prof. Leili Soltanisehat","authors":[{"name":"Prof. Leili Soltanisehat","aff":"Assistant Professor, University of Massachusetts Dartmouth"}],"order":5}]},{"id":"s394","title":"Generative AI Applications in the Education Sector","track":"Generative AI and Societal Sustainable Operations","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"HARRIS","chairs":["Dr. De Liu"],"abstracts":[{"id":"136-1660","title":"Fostering Ethical, Responsible and Digitally Proficient Students through AI-Driven Exploration","content":"We designed a novel course project integrating Gen-AI which galvanizes students' desire for greater tech literacy. The AI-powered activity encircles environmental and social issues. We aim to profile hallucination and contra-factual bias rates across several salient Environmental-Social-Governance (ESG) pillars. The project tackles the challenges with data diversity and algorithmic bias.","presenter":"Dr. Cigdem Gurgur","authors":[{"name":"Dr. Cigdem Gurgur","aff":"Associate Professor, Purdue University"}],"order":10},{"id":"136-1329","title":"Is ChatGPT for Learning a Boon or Bane? Evidence and Intervention Design","content":"We offered students search engine, ChatGPT, or GD-GPT (a customized ChatGPT that helps students discover answers independently) during practice but not during subsequent assessments. Compared to search engine, ChatGPT improved practice scores but lowered assessment scores. GD-GPT matched ChatGPT in practice but outperformed ChatGPT and search engines in assessments.","presenter":"Dr. De Liu","authors":[{"name":"Dr. Tao Li","aff":"Assistant Professor, University of Science and Technology of China"},{"name":"Dr. De Liu","aff":"Professor, University of Minnesota"},{"name":"Prof. Teng Ye","aff":"Assistant Professor, University of Minnesota"}],"order":11},{"id":"136-1336","title":"Design and Evaluation of A Gamified Generative AI Chatbot for Canvas LMS Courses","content":"To help students better engage in learning and achieve better performance, we develop a system that integrates the conversational features of Generative AI Chatbot with the motivational affordances of gamificationlearning. Our field experiment shows the effectiveness of the integrated design and holds implications for other applications.","presenter":"Dr. De Liu","authors":[{"name":"Dr. Tao Li","aff":"Assistant Professor, University of Science and Technology of China"},{"name":"Dr. De Liu","aff":"Professor, University of Minnesota"},{"name":"Dr. Radhika Santhanam","aff":"Professor, University of Oklahoma"},{"name":"Dr. Scott Schanke","aff":"Assistant Professor, University of Wisconsin - Milwaukee"},{"name":"Mr. Ramin Zandvakili","aff":"Student, University of Minnesota"}],"order":12},{"id":"136-1373","title":"University students' task performance: human, AI, or hybrid? Evidence from a field experiment","content":"Relying on a field experiment, we examine how the presence of generative AI can influence students’ decisions regarding some tasks they are requested to perform as a part of their educational process in a university course, the evaluators’ beliefs, as well as the final student performance.","presenter":"Prof. Paolo Roma","authors":[{"name":"Prof. Paolo Roma","aff":"Professor, Universita Degli Studi Di Palermo"},{"name":"Mr. Giuseppe Crapa","aff":"Student, Universita Degli Studi Di Palermo"},{"name":"Prof. Azzurra Morreale","aff":"Associate Professor, Lappeenranta University of Technology"},{"name":"Prof. Luigi Mittone","aff":"Professor, Università degli Studi di Trento"}],"order":13}]},{"id":"s401","title":"Transparency in Sustainable Supply Chains","track":"Sustainable Operations Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"GRAND HALL EAST C","chairs":["Mr. Chulhwan Kwon"],"abstracts":[{"id":"136-1893","title":"Carbon disclosure with different consumer valuation towards ways of emission reduction","content":"We consider about whether and how to disclosure carbon emission reduction when consumers have different valuation towards the ways of reducing emissions, such as using green technology and carbon offsetting. We find partial disclosure can be the optimal strategy.","presenter":"Dr. Guowei Dou","authors":[{"name":"Dr. Guowei Dou","aff":"Associate Professor, Shenzhen University"}],"order":1},{"id":"136-1184","title":"Orchestration capabilities during Environmental Product Declarations implementation: An exploratory study of the lighting industry","content":"This research explores the development of Environmental Product Declarations (EPDs) in the European lighting sector. Using a typological approach and case studies, it examines how lighting manufacturers coordinate internally (e.g., R&amp;D, procurement, sustainability) and externally (suppliers) to meet the new demands of reporting EPDs.","presenter":"Mr. Giuseppe Crapa","authors":[{"name":"Mr. Giuseppe Crapa","aff":"Student, Universita Degli Studi Di Palermo"},{"name":"Prof. Paolo Roma","aff":"Associate Professor, Universita Degli Studi Di Palermo"},{"name":"Prof. Manfredi Bruccoleri","aff":"Professor, Universita Degli Studi Di Palermo"},{"name":"Dr. Veronica Villena","aff":"Associate Professor, Arizona State University"}],"order":2},{"id":"136-0712","title":"Buyer’s Strategic Commitment to Contract Terms Before Knowing the Outcome of a Sustainability Audit","content":"We model a supply chain in which the buyer audits the supplier’s compliance with the social and environmental code of conduct. We investigate the effect of the buyer’s upfront commitment to price and quantity on supplier’s compliance to the sustainability code of conduct.","presenter":"Prof. Hossein Rikhtehgar Berenji","authors":[{"name":"Prof. Hossein Rikhtehgar Berenji","aff":"Associate Professor, Pacific University"},{"name":"Prof. Nagesh Murthy","aff":"Professor, University of Oregon"}],"order":3},{"id":"136-0591","title":"Save the Planet and Maintain Competitiveness: The Role of Mandatory Climate Risk Disclosures","content":"Global climate change is one of the most pressing issues nowadays. We propose to apply PSM and DiD methods to examine the true impact of CRD in the UK. We postulate that the impact is stronger under more complimentary assets and higher differentiation scores based on their sustainability reports.","presenter":"Mr. Shucheng MIAO","authors":[{"name":"Mr. Shucheng MIAO","aff":"Student, The Hong Kong Polytechnic University"}],"order":4},{"id":"136-1211","title":"Unveiling Transparency: Factors Influencing Upstream GHG Emissions Disclosure in Supply Chains","content":"This research examines effects of manufacturers’ attributes on driving supplier transparency for greenhouse gas emissions. Using the Awareness-Motivation-Capability framework, it shows that buyers with a larger sustainability team and familiar with reporting systems are associated with extended supply chain transparency whereas a public sustainability report was associated with lower transparency.","presenter":"Mr. Chulhwan Kwon","authors":[{"name":"Mr. Chulhwan Kwon","aff":"Student, Arizona State University Tempe"},{"name":"Dr. Kevin Dooley","aff":"Professor, Arizona State University Tempe"},{"name":"Dr. Veronica Villena","aff":"Associate Professor, Arizona State University"}],"order":5}]},{"id":"s447","title":"Tribute to Christopher S Tang II","track":"Honoring Retirees","type":"Panel","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"GRAND HALL EAST A","chairs":["Prof. Manmohan Sodhi","Prof. Hau Lee"],"abstracts":[{"id":"136-2138","title":"Tribute to Christopher S. Tang","content":"Tribute to Christopher S. Tang","presenter":"Prof. Charles Corbett","authors":[{"name":"Prof. Charles Corbett","aff":"Professor, UCLA Anderson School of Management"},{"name":"Prof. Christian Blanco","aff":"Assistant Professor, Ohio State University"},{"name":"Prof. Felipe Caro","aff":"Professor, UCLA Anderson School of Management"}],"order":1},{"id":"136-2142","title":"The Inspiring contributions of Professor Christopher Tang to socially-responsible operations, farming and agriculture","content":"This talk presents the inspiring works of Professor Christopher Tang on the topic of sustainable and socially-responsible operations. It focuses on farming and agriculture, and emphasizes how market information improves farmer payments, pricing and production decisions of agricultural goods, fundamentally improving the lives of smallhold farmers.","presenter":"Prof. Burak Kazaz","authors":[{"name":"Prof. Burak Kazaz","aff":"Professor, Whitman School of Management"}],"order":2},{"id":"136-2139","title":"Tribute to Christopher Tang","content":"Tribute to Christopher Tang","presenter":"Prof. Jan Fransoo","authors":[{"name":"Prof. Jan Fransoo","aff":"Professor, Tilburg University"},{"name":"Ms. Simone Balvers","aff":"Student, Tilburg University"},{"name":"Mr. Guan-Yuan Wang","aff":"Student, Tilburg University"}],"order":3},{"id":"136-2143","title":"Integrating Supply Chain Finance for Sustainable Development","content":"We examine operations-finance integration in promoting sustainable development. Market frictions, such as information asymmetry and transaction costs, often negatively affect small- and medium-sized enterprises and the poor. We review the literature on alleviating such frictions in this setting. Finally, we propose future research directions on green supply chain finance.","presenter":"Prof. Jing Wu","authors":[{"name":"Prof. Jing Wu","aff":"Associate Professor, The Chinese University of Hong Kong"},{"name":"Dr. Yuxuan Zhang","aff":"Assistant Professor, University of International Business And Economics"}],"order":4}]},{"id":"s4","title":"Advances in Supply Chain Management","track":"Manufacturing Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"LENOX","chairs":["Dr. Anand Paul","Ms. Na Zhang"],"abstracts":[{"id":"136-0396","title":"The Effects of Competition Between Fair Trade Organizations","content":"This study explores the effects of competition on fair trade operations. Two competing FTOs have the same goal of easing the poverty of farmers, albeit with contrasting strategies to achieve the goal. We show that competition between the two FTOs brings mainstreaming and greenwashing at the same time.","presenter":"Mr. Daehoon Jung","authors":[{"name":"Mr. Daehoon Jung","aff":"Student, University of Florida"},{"name":"Dr. Seung Jae Park","aff":"Associate Professor, Yonsei University"}],"order":1},{"id":"136-0429","title":"To Endorse or Not? The Role of Influencers in Conspicuous Consumption","content":"Celebrity endorsement (CE) is a prevalent business practice. We propose a stylized rational expectations framework of CE. We found that under certain conditions, when the proportion of snobs is either notably low or sufficiently high, it is more advantageous for the firm to abstain from CE adoption.","presenter":"Ms. Qian Su","authors":[{"name":"Ms. Qian Su","aff":"Student, University of Colorado Boulder"},{"name":"Mrs. Xiaoyang Zhou","aff":"Professor, Xi'an Jiaotong University"},{"name":"Dr. Chuan He","aff":"Professor, University of Colorado Boulder"}],"order":2},{"id":"136-0639","title":"Long-Term Procurement with Supply Risks: Incentives for Smooth Production Flow","content":"Smooth production flow is essential but vulnerable to dynamic supply risks. We study long-term procurement contracts and derive an optimal design featuring initial quantity distortions and future quantity pooling. This approach integrates tiered pricing with wholesale contracts, mitigates agency issues, and strengthens supply chain resilience and performance.","presenter":"Dr. Xiao Xiao","authors":[{"name":"Dr. Dawei Jian","aff":"Assistant Professor, University of Wisconsin-Milwaukee"},{"name":"Prof. Mohsen Elhafsi","aff":"Professor, University of California Riverside"},{"name":"Dr. Xiao Xiao","aff":"Assistant Professor, California State University Stanislaus"}],"order":3},{"id":"136-1513","title":"Optimizing Basestocks in Production-Inventory Systems with Stochastic Supply-Chain Disruptions","content":"Consider multi-item, multi-warehouse firms. Raw materials flow just-in-time. Items inventories and production are managed by basestock policies. Demands, production times, and transportation times are stochastic. The production process experiences supply-chain disruptions, whose frequency and duration are random. We study the problem of determining optimal basestocks when unfilled demands are back-ordered.","presenter":"Dr. Antonio Arreola-Risa","authors":[{"name":"Dr. Antonio Arreola-Risa","aff":"Associate Professor, Mays Business School"},{"name":"Prof. Hau Lee","aff":"Retired, Stanford University"},{"name":"Dr. Bo Li","aff":"Associate Professor, Ningo Supply Chain Innovation Institute China"}],"order":4}]},{"id":"s48","title":"Applications of Resilience","track":"Supply Chain Risk Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"EMBASSY H","chairs":["Prof. Peng-Chu Chen"],"abstracts":[{"id":"136-2054","title":"Improving Port Resilience: A Bayesian Network and DEMATEL-Based Analysis of Resilience Strategy Interactions","content":"Port disruptions can ripple through supply chains, causing significant operational and economic impacts. This study integrates Bayesian Networks and DEMATEL to assess resilience strategies' interdependencies. A case study in northern Colombia identifies 19 strategies, highlighting adaptive and restorative capacities. Findings guide resource allocation, enhancing operational readiness and supply chain continuity.","presenter":"Dr. Gina Galindo","authors":[{"name":"Dr. Fernando González-Solano","aff":"Associate Professor, Universidad Autónoma del Caribe"},{"name":"Dr. Gina Galindo","aff":"Assistant Professor, Universidad del Norte"},{"name":"Mr. Daniel Romero","aff":"Student, SUNY Polytechnic Institute"}],"order":1},{"id":"136-0743","title":"Resilient Relay Logistics Network Design Using Topology-Based Optimization","content":"We design resilient logistics networks by locating hubs to optimize weighted k-shortest-path resilience metrics. By developing tailored decomposition-based algorithms, we show that our networks outperform traditional designs under stochastic disruptions, with minimal cost impact, as demonstrated in a case study for a China-based parcel delivery company.","presenter":"Prof. Mathieu Dahan","authors":[{"name":"Mr. Onkar Anand Kulkarni","aff":"Student, Georgia Institute of Technology"},{"name":"Prof. Mathieu Dahan","aff":"Assistant Professor, Georgia Institute of Technology"},{"name":"Prof. Benoit Montreuil","aff":"Professor, Georgia Institute of Technology"}],"order":2},{"id":"136-0269","title":"Supply Chain Disruption Strategies: Theory vs Practice","content":"This research draws on a case study of six firms in the automotive and heavy equipment manufacturing who experienced severe disruptions in production. The gap between theory and practical application are discussed. Lessons learned are discussed and findings show that single source supply is still considered best practice.","presenter":"Dr. Rebecca Clemons","authors":[{"name":"Dr. Rebecca Clemons","aff":"Associate Professor, Indiana University"}],"order":3},{"id":"136-0019","title":"Optimizing Batch Withdrawal Strategies for Non-Safety-Related Defects under Risk Sensitivity","content":"We explore risk-averse strategies for managing non-safety-related failures in warranty-protected products. We compare active and passive approaches, and examine optimal withdrawal timing strategies under two risk quantification methods. Finally, we highlight the robustness of maximum likelihood estimation for identifying failure probability parameters when initially unknown during the warranty period.","presenter":"Dr. Belleh Fontem","authors":[{"name":"Dr. Belleh Fontem","aff":"Assistant Professor, University of Massachusetts Lowell"},{"name":"Dr. Kelly Hellman","aff":"Assistant Professor, University of Massachusetts Lowell"}],"order":4}]},{"id":"s50","title":"Generative AI and Online Platforms","track":"Generative AI and Societal Sustainable Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"HARRIS","chairs":["Dr. Guohou Shan"],"abstracts":[{"id":"136-0178","title":"Can large language models provide useful feedback on research papers? A large-scale empirical analysis.","content":"Expert feedback lays the foundation of rigorous research. However, the rapid growth of scholarly production and intricate knowledge specialization challenge the conventional scientific feedback mechanisms. Leveraging GPT-4, we developed a system to provide automated feedback on scientific papers, which we evaluated through a combination of retrospective and prospective study design.","presenter":"Mr. Hancheng Cao","authors":[{"name":"Mr. Hancheng Cao","aff":"Student, Stanford University"}],"order":1},{"id":"136-1669","title":"Fostering a Trusted Ecosystem for Digital Responsibility in Algorithmic AI Systems","content":"Although generative algorithmic thinking models have emerged with promising capabilities in the Industry 5.0 age, these systems' predictions need to be traced, which limits their ability to explain and interpret and reduces users' confidence in them. We construct a conceptual framework fostering a trusted ecosystem for digital responsibility.","presenter":"Dr. Cigdem Gurgur","authors":[{"name":"Dr. Cigdem Gurgur","aff":"Associate Professor, Purdue University"}],"order":2},{"id":"136-0352","title":"How Does Generative AI Usage Affect the Coding Performance of Developers?","content":"Generative AI (GenAI) techniques have recently advanced at a rapid rate. However, the impact of GenAI on developers’ coding performance remains an empirical question. To examine whether and how GenAI usage impacts developers’ coding performance in terms of both quantity and quality. We design two studies.","presenter":"Dr. Guohou Shan","authors":[{"name":"Dr. Guohou Shan","aff":"Assistant Professor, Northeastern University"},{"name":"Prof. Michael Rivera","aff":"Assistant Professor, The Business School"},{"name":"Dr. Subodha Kumar","aff":"Professor, Temple University"}],"order":3},{"id":"136-0701","title":"The Double-Edged Roles of Generative AI in the Creative Process: Experiments on Design Work","content":"Our research investigates the human-GenAI co-creation process, finding that GenAI enhances ideation for all creators but influences implementation differently based on expertise. Low-expertise designers benefit throughout, while high-expertise designers face reduced efficiency and creativity in implementation due to expertise fixation, highlighting intricate dynamic impacts of GenAI on creativity.","presenter":"Dr. Gang Wang","authors":[{"name":"Dr. Jinghui (Jove) Hou","aff":"Assistant Professor, University of Houston"},{"name":"Dr. Lei Wang","aff":"Assistant Professor, University of Utah"},{"name":"Dr. Gang Wang","aff":"Assistant Professor, University of Delaware"},{"name":"Prof. Jiannan Wang","aff":"Professor, University of Delaware"},{"name":"Prof. Shuai Yang","aff":"Professor, Donghua University"}],"order":4},{"id":"136-1104","title":"AI Characters in Online Social Community: Evidence Through a Field Experiment","content":"The integration of LLM empowered AI characters into online social communities has shown the potential to transform online digital landscape. Relying on a field experiment, we study how AI characters affect user engagement, social network structures, and spillover effects in the short- and long-run.","presenter":"Prof. Frank Li","authors":[{"name":"Prof. Frank Li","aff":"Assistant Professor, Sauder School of Business, UBC"},{"name":"Prof. Shiyang Gong","aff":"Professor, The Business School"},{"name":"Prof. Li Guo","aff":"Professor, The Business School"},{"name":"Prof. Yuetao Gao","aff":"Professor, The Business School"},{"name":"Prof. Yinliang Tan","aff":"Associate Professor, China Europe International Business School"},{"name":"Erik Brynjolfsson","aff":""}],"order":5}]},{"id":"s71","title":"Challenges in Transitioning to Low-Carbon Economy","track":"Energy and Natural Resource Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"TECHWOOD","chairs":["Ms. Nilsu Uzunlar"],"abstracts":[{"id":"136-0078","title":"Greenness and its Discontents: Operational Implications of Investor Pressure","content":"Public firms are exerting efforts to reduce carbon emissions in response to environmental pressure from investors. We study the operational implications of two environmental assessment metrics utilized by investors by comparing two differently regulated settings where the firm discloses the unit impact (intensity regime) and the total impact (absolute regime).","presenter":"Ms. Nilsu Uzunlar","authors":[{"name":"Ms. Nilsu Uzunlar","aff":"Student, Carnegie Mellon University"},{"name":"Prof. Alan Scheller-Wolf","aff":"Professor, Tepper School of Business"},{"name":"Prof. Sridhar Tayur","aff":"Professor, Carnegie Mellon University"}],"order":1},{"id":"136-0089","title":"The Effects of Competition on Corporate Sustainability","content":"We investigate the relationship between competition and market composition, with a focus on the adoption of green technologies and corporate social responsibility. We find that cooperative markets lead to higher green market share and socially responsible investment than competitive markets, highlighting the tension between environmental sustainability and market competition.","presenter":"Dr. Mike Gordon","authors":[{"name":"Prof. Titing Cui","aff":"Assistant Professor, University of Tulsa"},{"name":"Prof. Esther Gal-Or","aff":"Professor, University of Pittsburgh"},{"name":"Dr. Mike Gordon","aff":"Assistant Professor, Virginia Polytechnic Institute And State University"},{"name":"Prof. Michael Hamilton","aff":"Assistant Professor, University of Pittsburgh"},{"name":"Prof. Jennifer Shang","aff":"Professor, University of Pittsburgh"}],"order":2},{"id":"136-0140","title":"Optimal Allocation of Mangrove Trees to Remove Environmental Pollutants in Cartagena Bay","content":"Phytoremediation involves using plants to remove environmental pollutants. This technique is a cost-effective alternative to cleaning up contaminated shallow groundwater, air, soil, sediment, and sludge, either alone or in combination with other remediation alternatives. This research examines green infrastructure by optimally allocating phytoremediation efforts funded with pollution taxes.","presenter":"Dr. Sandra Buzon-Vargas","authors":[{"name":"Dr. Sandra Buzon-Vargas","aff":"Assistant Professor, Sam Houston State University"},{"name":"Dr. Neil Diaz","aff":"Lecturer, University of Houston"}],"order":4}]},{"id":"s76","title":"Sustainability in Action: Diverse Approaches to Operational Challenges","track":"Sustainable Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"EMBASSY G","chairs":["Prof. Suvrat Dhanorkar","Mr. Max Ji"],"abstracts":[{"id":"136-0054","title":"Closer to Home: An Estimate-then-Optimize Approach to Improve Access to Healthcare Services","content":"Geographic inequalities in healthcare access arise from structural barriers, provider shortages, and decentralized planning. Proximity to providers varies, complicating facility location decisions. This study introduces an estimate-then-optimize framework using aggregate data to estimate travel cost impacts on healthcare utilization and optimize facility placement.","presenter":"Mr. Jingyuan Hu","authors":[{"name":"Dr. Fernanda Bravo","aff":"Assistant Professor, UCLA Anderson School of Management"},{"name":"Mr. Jingyuan Hu","aff":"Student, University of California Los Angeles"},{"name":"Prof. Elisa Long","aff":"Professor, UCLA Anderson School of Management"}],"order":1},{"id":"136-0474","title":"The Power of Post-Purchase Messages in Shaping Post-Purchase Consumer Behaviors in Online Retail","content":"Online shopping can result in product returns when expectations formed from online descriptions differ from the actual product. To address these gaps, some retailers use post-purchase messages during shipping and delivery. This study experimentally examines how such messages influence product returns, positive word-of-mouth, and future repurchase behavior.","presenter":"Dr. Punya Chatterjee","authors":[{"name":"Dr. Punya Chatterjee","aff":"Assistant Professor, University of Memphis"},{"name":"Dr. Susana Jaramillo","aff":"Assistant Professor, University of Memphis"},{"name":"Dr. Ganga Urumutha Hewage","aff":"Assistant Professor, University of Memphis"}],"order":3},{"id":"136-0787","title":"Spin the Bottle Bill: Deposit-Refund System Policy and Reverse Supply Chain Design","content":"Our study optimizes California's Bottle Bill using a bi-level-mixed-integer-non-linear program. It jointly optimizes redemption values, manufacturers' fees, and recycling center locations to improve recycling rates. Our approximation approach transforms the bi-level problem into single-level and solves it optimally. Our results offer policy options to achieve California's 80% recycling goal.","presenter":"Mr. Austin Saragih","authors":[{"name":"Mr. Austin Saragih","aff":"Student, Massachusetts Institute of Technology"},{"name":"Ms. Lara Pontes","aff":"Student, UFPB"},{"name":"Prof. Saurabh Amin","aff":"Professor, Massachusetts Institute of Technology"},{"name":"Prof. Jan Fransoo","aff":"Professor, Tilburg University"}],"order":4},{"id":"136-1676","title":"Supplier Diversity, Governance and Carbon Emission Reduction","content":"We examine the impact of supplier diversity on supplier engagement regarding carbon emissions and consequent carbon footprint reduction using a multi-industry panel data drawn from 2013-2017. We also explore the impact of supply base diversity on the selection and effectiveness of governance strategies for reducing greenhouse gas (GHG) emissions.","presenter":"Mr. Andrey Makhanov","authors":[{"name":"Ms. Herbie Huang","aff":"Student, Kenan-Flagler Business School"},{"name":"Prof. Sriram Narayanan","aff":"Professor, Michigan State University"},{"name":"Prof. Jayashankar Swaminathan","aff":"Professor, University of North Carolina Chapel Hill"},{"name":"Mr. Andrey Makhanov","aff":"Student, University of North Carolina at Chapel Hill"}],"order":5}]},{"id":"s77","title":"Operational Strategies in Healthcare","track":"Healthcare Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"PIEDMONT","chairs":["Prof. Craig Froehle"],"abstracts":[{"id":"136-0333","title":"An Empirical Investigation of R&amp;D Strategy and Clinical Trial Design","content":"This study examines the impact of eligibility criteria in clinical trials on drug approval, effectiveness, and inclusivity. Using AI-driven models, we analyze how criteria evolve across trial phases, their influence on FDA approval and post-market outcomes, and the role of firm size in balancing trial success with broader patient population.","presenter":"Dr. Kanix Wang","authors":[{"name":"Dr. Zhaowei She","aff":"Assistant Professor, Singapore Management University"},{"name":"Dr. Kanix Wang","aff":"Assistant Professor, University of Cincinnati"},{"name":"Dr. Liang Xu","aff":"Assistant Professor, Singapore Management University"}],"order":1},{"id":"136-0428","title":"Emerging Workflow Technologies in Healthcare: Dynamic Resourcefulness for Health System and Vendor Success","content":"As hospitals increasingly seek AI to improve workflows, they are challenged with deciding which emerging technology (ET) vendors to choose. We present a two-part mixed methods study and identify an interplay between ET vendor resources and capabilities that influence the sourcing of workflow solutions by large health system customers.","presenter":"Prof. Wiljeana Glover","authors":[{"name":"Prof. Wiljeana Glover","aff":"Associate Professor, Babson College"},{"name":"Prof. Dessislava Pachamanova","aff":"Professor, Babson College"},{"name":"Mr. Derick Simmons","aff":"Student, Saint Louis University"},{"name":"Ms. Robin Sodano","aff":"Chief Information Officer, UMass Memorial Health"},{"name":"Dr. Eric Alper","aff":"Chief Quality Officer and Chief Clinical Informatics Officer at UMass Memorial Health, UMass Memorial Health"}],"order":2},{"id":"136-0520","title":"When Is Standardization Most Beneficial for Improving Clinical Outcomes? The Moderating Role of Operational Failures","content":"We examined how operational failures impact the effectiveness of standardization on clinical outcomes. We find that standardization improves outcomes in environments with frequent operational failures, but offers little benefit in environments with few operational failures This highlights the importance of context in determining when standardization is most beneficial.","presenter":"Dr. Qi Wang","authors":[{"name":"Dr. Qi Wang","aff":"Post Doc/Researcher, Boston University"},{"name":"Prof. Sarah Zheng","aff":"Associate Professor, Victoria University"},{"name":"Prof. Anita Carson","aff":"Professor, Boston University"}],"order":3}]},{"id":"s80","title":"Improving Efficiency Through Data-Driven Decision-Making","track":"Product Innovation and Technology Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"COURTLAND","chairs":["Mr. Pierre Gautreau","Dr. Timofey Shalpegin"],"abstracts":[{"id":"136-1095","title":"Strategic Planning for the Reverse Logistics of Wind Turbines","content":"This study addresses the Reverse Logistics Planning Problem for Wind Turbines, optimizing the allocation of decommissioned turbine components across disposal, recycling, and remanufacturing channels. By considering multi-modal transportation costs, carbon emissions, and operational setups, the objective is to maximize profitability, balancing revenue against fixed, operating, and environmental costs.","presenter":"Dr. Siqiang Guo","authors":[{"name":"Dr. Siqiang Guo","aff":"Assistant Professor, University of Missouri-St. Louis"},{"name":"Prof. Haitao Li","aff":"Assistant Professor, University of Missouri St Louis"}],"order":2},{"id":"136-1735","title":"Optimizing Operating Room Scheduling and Ensuring Fairness in Managing Waitlists for Joint Replacements","content":"Inefficiencies in surgical services are leading contributors to rising costs and increasing wait times, resulting in deterioration of quality of life for patients. A multiobjective optimization pipeline was employed leveraging 10 years of data from a large Canadian hospital to improve efficiency and fairness in surgical scheduling for joint replacements.","presenter":"Mr. Michael Simone","authors":[{"name":"Mr. Michael Simone","aff":"Student, University of Toronto"},{"name":"Dr. Johnathan Lex","aff":"Post Doc/Researcher, University of Toronto"},{"name":"Mr. Aazad Abbas","aff":"Student, University of Toronto"},{"name":"Dr. Cari Whyne","aff":"Professor, University of Toronto"},{"name":"Dr. Elias Khalil","aff":"Professor, University of Toronto"}],"order":3},{"id":"136-0725","title":"Biotech-Pharma Alliances: Predicting Breakups Following Drug Launches with Machine Learning","content":"This study examines the vulnerability of biotech-pharma alliances to termination following pharmaceutical partners’ drug launches. Using machine learning on 3,717 terminated alliances, we identify predictors at alliance formation that signal post-launch termination risks. Findings provide actionable insights for biotech firms and contribute to innovation management literature on alliance stability.","presenter":"Mr. Pierre Gautreau","authors":[{"name":"Mr. Pierre Gautreau","aff":"Student, York University"},{"name":"Prof. Moren Levesque","aff":"Professor, York University"},{"name":"Prof. Annapoornima Subramanian","aff":"Associate Professor, National University of Singapore"},{"name":"Prof. Vareska Van De Vrande","aff":"Professor, Erasmus University Rotterdam"},{"name":"Dr. Adam Diamant","aff":"Assistant Professor, York University"}],"order":4}]},{"id":"s95","title":"Emerging Topics in Behavioral Operations","track":"Behavioral Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"EMBASSY D","chairs":["Prof. Somya Singhvi","Ms. Jimin Park"],"abstracts":[{"id":"136-1158","title":"Reference-dependent effects in volunteering: Expected vs. experienced effort","content":"Nonprofits often rely on volunteers to accomplish different tasks. We design an incentivized experiment to study how someone's effort being above or below expectations affect their re-engaging decision. In doing so, we study the role of reference-dependent preferences in a not-for-profit setting, comparing it against a similar for-profit setting.","presenter":"Mr. Gabriel Pensamiento","authors":[{"name":"Prof. Mahyar Eftekhar","aff":"Associate Professor, Arizona State University Tempe"},{"name":"Mr. Gabriel Pensamiento","aff":"Student, University of Pittsburgh"},{"name":"Prof. Leon Valdes","aff":"Associate Professor, University of Pittsburgh"}],"order":1},{"id":"136-1670","title":"Improving Worker Learning in the Gig Economy","content":"We explore how algorithmic recommendations influence gig workers' behaviors, focusing on their learning processes. Analyzing over one million retail delivery orders, we uncover a learning curve and shifts in reliance on algorithms. Our findings highlight the need for adaptive recommendation systems that align with workers' evolving strategies.","presenter":"Prof. Park Sinchaisri","authors":[{"name":"Ms. Shunan Jiang","aff":"Student, University of California, Berkeley"},{"name":"Prof. Park Sinchaisri","aff":"Assistant Professor, University of California Berkeley"}],"order":2},{"id":"136-1742","title":"The Ratings Trap: Prior Ratings, Gender and Instructor Outcomes in Higher Ed","content":"Instructor ratings guide learners' course choices but may introduce bias. Through online experiments, we find low prior ratings harm instructor evaluations, especially for instructor-focused questions. Apart from existing evidence of gender bias in traditional classrooms, online learners show opposite-gender and confirmation biases, with cognitive load intensifying these effects.","presenter":"Ms. Tong Wang","authors":[{"name":"Dr. Monika Heller","aff":"Post Doc/Researcher, University College London"},{"name":"Prof. Kamalini Ramdas","aff":"Professor, London Business School"},{"name":"Ms. Tong Wang","aff":"Student, London Business School"}],"order":3},{"id":"136-1760","title":"A Good Reputation Is More Valuable than Money: Designing Incentive Mechanisms for Good Advice","content":"People seek experienced advisors for complex decisions under uncertainty. This study compares monetary and reputation-based incentives to induce good advice. Reputation concerns promote effort and screen out bad advisors, while monetary incentives boost quantity but not quality. Reputation systems may outperform financial rewards in fostering better advice.","presenter":"Dr. Xiao Zhang","authors":[{"name":"Dr. Fei Jia","aff":"Assistant Professor, Saint Louis University"},{"name":"Dr. Jing Li","aff":"Assistant Professor, Saint Louis University"},{"name":"Dr. Xiao Zhang","aff":"Assistant Professor, Saint Louis University"}],"order":5}]},{"id":"s104","title":"Application-Based Humanitarian Network Analysis and Planning","track":"Humanitarian Operations and Crisis Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"GRAND HALL EAST B","chairs":["Dr. Marie-Eve Rancourt"],"abstracts":[{"id":"136-1028","title":"Enhancing Wildfire Evacuation Preparedness: Insights into Evacuee Behavior to Develop Simulation Models","content":"A 2023 survey explores the evacuation process and the role of evacuee behavior in enhancing wildfire preparedness. Findings allow the development of simulation models to estimate evacuation durations and minimize risks to populations. This research bridges behavioral insights and practical tools, offering tailored safety recommendations to wildfire-affected communities.","presenter":"Dr. Marie-Eve Rancourt","authors":[{"name":"Ms. Joelle Cormier","aff":"Student, HEC Montréal"},{"name":"Dr. Valérie Bélanger","aff":"Associate Professor, HEC Montréal"},{"name":"Prof. Julie Paquette","aff":"Associate Professor, HEC Montréal"},{"name":"Dr. Marie-Eve Rancourt","aff":"Associate Professor, HEC Montréal"}],"order":1},{"id":"136-1343","title":"Route Planning for Post-Disaster Field Assessments Under Uncertainty","content":"This study introduces the Stochastic Field Assessment Routing problem, which integrates sampling and routing for post-disaster field evaluation teams. A key challenge is the uncertainty of key informant availability, addressed by incorporating backup sites. Using comprehensive data from the 2023 Türkiye earthquakes, we propose practical heuristics to support recovery efforts.","presenter":"Prof. Burcu Balcik","authors":[{"name":"Prof. Burcu Balcik","aff":"Professor, Ozyegin University"},{"name":"Dr. Jessica Rodriguez-Pereira","aff":"Assistant Professor, Universitat Politècnica de Catalunya"},{"name":"Dr. Marie-Eve Rancourt","aff":"Associate Professor, HEC Montréal"},{"name":"Ms. Asena Kaplan","aff":"Student, Ozyegin University"}],"order":2},{"id":"136-1453","title":"Health Product Availability in the Presence of Cash Constraints: A Study of Community Health Enterpreneurs","content":"Community health entrepreneurs (CHEs) sell health products in small rural stores, but frequently experience stock-outs due to cash constraints. How to relieve cash constraints in rural areas is currently unclear. We address this question by studying the effects of a cashflow game and decentralized consignment stock locations on CHE sales.","presenter":"Dr. Harwin De Vries","authors":[{"name":"Ms. Lisanne van Rijn","aff":"Lecturer, Rotterdam School of Management"},{"name":"Dr. Harwin De Vries","aff":"Associate Professor, Rotterdam School of Management"},{"name":"Mr. Luuk Veelenturf","aff":"Associate Professor, Rotterdam School of Management"}],"order":3}]},{"id":"s108","title":"Social Media and Platform Economy","track":"Empirical Research in Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"EMBASSY B","chairs":["Dr. Wee Kiat Lee"],"abstracts":[{"id":"136-0370","title":"Shift Commitment in the Gig Economy: A Study with a Food Delivery Platform","content":"Platforms often face a challenge in maintaining an adequate supply of gig workers to meet the fluctuating customer demand throughout the day. In this study, we empirically studied how platforms can resolve the demand and supply imbalances through incentivizing the gig workers to commit to certain shifts.","presenter":"Dr. Wee Kiat Lee","authors":[{"name":"Dr. Wee Kiat Lee","aff":"Assistant Professor, Nanyang Technological University"},{"name":"Dr. Yao Cui","aff":"Associate Professor, Cornell University"},{"name":"Dr. Qi Li","aff":"Assistant Professor, Chinese Univ of Hong Kong (Shenzhen)"}],"order":1},{"id":"136-0510","title":"Online Mapping Errors and Their Impact on Last-Mile Delivery Operations","content":"We examine online mapping errors in urban last-mile delivery by measuring discrepancies between actual and mapped delivery addresses. Quantifying these errors, we analyze their impact on operations, including delays and missed deliveries. We conclude with policy recommendations to improve the efficiency and reliability of last-mile delivery services.","presenter":"Mr. Yuqing Cheng","authors":[{"name":"Mr. Yuqing Cheng","aff":"Student, Arizona State University"},{"name":"Prof. Elliot Rabinovich","aff":"Professor, Arizona State University Tempe"},{"name":"Prof. Stanley Lim","aff":"Assistant Professor, Michigan State University"}],"order":2},{"id":"136-0644","title":"Uncovering the Impact of Government Agencies’ Involvement on Users’ Voluntary Contributions","content":"Our study uses difference-in-differences estimation to investigate how police involvement affects users’ voluntary contributions based on a leading online neighborhood platform. We show that police involvement leads to a decrease in voluntary posts from users. Additionally, we assess the impact on the quality of posts and the offline crime rate.","presenter":"Ms. Jingyan Dai","authors":[{"name":"Ms. Jingyan Dai","aff":"Student, University of Florida"},{"name":"Mr. Qili Wang","aff":"Student, University of Florida"},{"name":"Ms. Shu He","aff":"Assistant Professor, University of Florida"},{"name":"Prof. Liangfei Qiu","aff":"Professor, University of Florida"}],"order":3},{"id":"136-1273","title":"Replacing What Could Be Repaired: Structural Analysis of Two-Stage Diagnostic Decisions in Managing Shared-Bike Returns","content":"We develop a structural estimation model to analyze two-stage diagnostic decisions made by inspectors and workers, which are modeled as a strategic interaction governed by a Bayesian Nash Equilibrium. Our framework provides actionable insights for mitigating inefficiencies in multi-agent diagnostic decision systems and is generalizable to other credence goods industries.","presenter":"Mr. Jingxuan Geng","authors":[{"name":"Prof. Hailong Cui","aff":"Assistant Professor, University of Minnesota"},{"name":"Mr. Jingxuan Geng","aff":"Student, Temple University"},{"name":"Prof. Guangwen Kong","aff":"Associate Professor, Temple University"}],"order":4}]},{"id":"s134","title":"Improving Regularity and Reducing Risks in Operations","track":"Operational Excellence","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"BAKER","chairs":["Mrs. Jane Iversen"],"abstracts":[{"id":"136-0049","title":"Tradeoffs and Spillovers in Safety and Completion Time Management","content":"Implementing a laboratory experiment, we observe the effects of Public Relative Performance Feedback and Best Practice Sharing on completion time and safety. Higher safety is evaluated as reductions of musculoskeletal disorder risk. Results include that the best practice discussions focused on safety observably spillover to the benefit of completion time.","presenter":"Ms. Soh Hyun Chu","authors":[{"name":"Ms. Soh Hyun Chu","aff":"Assistant Professor, Rotterdam School of Management"},{"name":"Prof. Elliot Bendoly","aff":"Professor, Ohio State University"},{"name":"Prof. James Hill","aff":"Professor, Ohio State University"}],"order":1},{"id":"136-0221","title":"Production Quality Under Exogenous Shock: Food Processing During COVID-19","content":"The COVID-19 pandemic halted production at many manufacturing facilities. However, the US food processing industry was considered essential, and these facilities continued to operate. Using the attention-based view of organizational behavior and change, we examine whether and how the changes necessitated by the pandemic impacted food production quality.","presenter":"Dr. Zachary Wright","authors":[{"name":"Dr. Zachary Wright","aff":"Assistant Professor, Brigham Young University"},{"name":"Dr. John Gray","aff":"Professor, Ohio State University"},{"name":"Prof. George Ball","aff":"Associate Professor, Kelley School of Business, Indiana Univ."},{"name":"Dr. Gopesh Anand","aff":"Professor, University of Illinois Urbana-Champaign"},{"name":"Mr. David Ruttenberg","aff":"Student, University of Michigan"}],"order":2},{"id":"136-1714","title":"Improving Regularity and Continuity of Care: The Impact of Virtual Visit Utilization","content":"This study examines care regularity and continuity as potential mechanisms underlying the positive impact of virtual visits on patient health outcomes. We find that increased virtual visit utilization is associated with improved regularity and continuity, and that both partially mediate the relationship between virtual visit use and improved patient health.","presenter":"Mrs. Jane Iversen","authors":[{"name":"Mrs. Jane Iversen","aff":"Student, Ohio State University"},{"name":"Prof. Aravind Chandrasekaran","aff":"Professor, Ohio State University"}],"order":4},{"id":"136-0556","title":"The Impact of Inspections on Operational Risk: Uncovering Learning and Forgetting Patterns","content":"Operational risk, one of the top three risks in financial services, has become a critical issue globally, with regulators mandating stringent controls and inspections to prevent severe financial losses. We collaborate with a large commercial bank to investigate the impact of inspections on employee performance.","presenter":"Mr. Zhanzhi Zheng","authors":[{"name":"Mr. Zhanzhi Zheng","aff":"Student, UNC Kenan-Flagler Business School"},{"name":"Prof. Yuqian Xu","aff":"Associate Professor, UNC Chapel Hill"},{"name":"Prof. Bradley Staats","aff":"Professor, University of North Carolina Chapel Hill"}],"order":5}]},{"id":"s155","title":"Advances in Health Care Operations and Information Systems","track":"Healthcare Analytics","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"GRAND HALL EAST D","chairs":["Dr. Niam Yaraghi"],"abstracts":[{"id":"136-0457","title":"Multi-channel Healthcare: Impact of Asynchronous Telemedicine Adoption on Patient Flow","content":"This paper examines a multi-channel healthcare system combining in-person care and asynchronous telemedicine (AT). Using VHA data and a difference-in-differences approach, we find AT improves efficiency by reducing in-person wait times (37.5%), enhancing patient triage, and increasing throughput. Findings highlight AT’s benefits and implications for capacity planning and patient referrals.","presenter":"Prof. Hao Ding","authors":[{"name":"Prof. Sokol Tushe","aff":"Assistant Professor, University of South Florida"},{"name":"Prof. Hao Ding","aff":"Assistant Professor, Auburn University"},{"name":"Prof. Diwas KC","aff":"Professor, Emory University"},{"name":"Prof. Donald Lee","aff":"Associate Professor, Emory University"}],"order":1},{"id":"136-0645","title":"The Impact of Telehealth Expansion on Doctor Shopping and Drug Overdose","content":"Telehealth expansion during COVID-19 increased opioid prescriptions, doctor shopping, and overdoses, with limited impact on treatment access for opioid use disorder. Using staggered difference-in-differences analysis, this study highlights telehealth’s mixed outcomes, particularly for addicted patients, offering critical insights for policymakers balancing care accessibility with preventing misuse amid the substance abuse.","presenter":"Ms. Xiru Pan","authors":[{"name":"Ms. Xiru Pan","aff":"Student, University of Miami"},{"name":"Dr. Niam Yaraghi","aff":"Associate Professor, University of Miami"},{"name":"Mr. Masoud Kamalahmadi","aff":"Assistant Professor, Miami Herbert Busienss School"},{"name":"Dr. Michael French","aff":"Professor, University of Miami"}],"order":2},{"id":"136-1854","title":"Will Machines Take Over? Algorithms for Human-Machine Collaborative Decision Making in Healthcare","content":"This study presents a cost-effective diagnostic system for allocating mammography interpretation tasks between AI and radiologists, ensuring patient safety. Using a two-threshold policy based on algorithmic risk scores, it minimizes costs by combining automation and delegation strategies. Back-testing shows potential savings of 20.9%, with broader implications for AI-human collaboration workflows.","presenter":"Prof. Mehmet Eren Ahsen","authors":[{"name":"Prof. Mehmet Eren Ahsen","aff":"Assistant Professor, University of Illinois at Urbana Champaign"},{"name":"Prof. Mehmet Ayvaci","aff":"Associate Professor, The University of Texas at Dallas"},{"name":"Dr. Radha Mookerjee","aff":"Assistant Professor, University of Texas Dallas"}],"order":3},{"id":"136-0387","title":"Telehealth’s double-edged sword: The hidden costs of expanding virtual access to care","content":"Leveraging the variation in telehealth adoption rates during the COVID-19 pandemic across different specialties of a major health system, we show that telehealth’s potential to expand access may come at the cost of less time per patient, increased workload for physicians, and revenue losses for healthcare organizations.","presenter":"Mr. Masoud Kamalahmadi","authors":[{"name":"Mr. Masoud Kamalahmadi","aff":"Assistant Professor, Miami Herbert Busienss School"},{"name":"Prof. Jong Myeong Lim","aff":"Assistant Professor, Miami Herbert Busienss School"}],"order":4}]},{"id":"s165","title":"Sustainable Supply Chain Practices and Outcomes","track":"Procurement and Supplier Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"MARIETTA","chairs":["Dr. William Diebel"],"abstracts":[{"id":"136-0852","title":"Truth or Dare? Verifying vs. Engaging for Supplier Sustainability","content":"Supplier sustainability audits often fall short, prompting some buyers to implement alternative monitoring methods. We compare a buyer’s supplier enhancement strategy under two different methods: the supplier self-reports versus the buyer relies on a predictive signal about the supplier’s capability. In the latter, the buyer can also invest in accuracy.","presenter":"Ms. Elif Kuscu","authors":[{"name":"Ms. Elif Kuscu","aff":"Student, University of Zurich"},{"name":"Prof. Tim Kraft","aff":"Associate Professor, North Carolina State University"},{"name":"Prof. Tarkan Tan","aff":"Professor, University of Zurich"},{"name":"Dr. Özge Tüncel","aff":"Post Doc/Researcher, Eindhoven University of Technology"}],"order":1},{"id":"136-1132","title":"Environmental Supply Chain Enabled Science-Based Target Commitments","content":"Amid growing climate urgency, understanding factors driving corporate carbon reduction commitments is crucial. We propose firms with stronger environmental supply chain orientations are more likely to adopt Science-Based Targets initiative (SBTi) commitments. Using multi-source data, we reveal how proactive and reactive mechanisms enable these commitments, offering insights for climate action.","presenter":"Dr. William Diebel","authors":[{"name":"Dr. William Diebel","aff":"Assistant Professor, Darla Moore School of Business"},{"name":"Prof. Robert Klassen","aff":"Professor, Ivey Business School, Western University"}],"order":2},{"id":"136-1179","title":"Interpreting Buyer-Supplier Relationships through Empathy: Cognitive and Behavioral Practices","content":"Supply chain disruptions often result from supplier challenges, and traditional punitive buyer actions damage relationships and product quality. This study introduces \"buyer empathy\", firms’ ability to understand and support suppliers, as an alternative. Through agricultural case studies we show that empathetic practices improve reciprocity and resiliency when suppliers face difficulties.","presenter":"Ms. Parisa Rajabi","authors":[{"name":"Ms. Parisa Rajabi","aff":"Student, Ivey Biusiness School, Western University"},{"name":"Prof. Robert Klassen","aff":"Professor, Ivey Business School, Western University"}],"order":3},{"id":"136-1360","title":"To Tell the Truth or Not: Honesty in Supply Chain Sustainability Reporting","content":"This research investigates supplier honesty in sustainability reporting using a vignette experiment. Focusing on the roles of trust, dependence, and perceived consequences, it explores factors influencing suppliers’ decisions to truthfully disclose information. Findings aim to provide insights for improving supply chain transparency and support sustainable supply chain practices.","presenter":"Ms. Xiao Liu","authors":[{"name":"Ms. Xiao Liu","aff":"Student, Stockholm School of Economics"},{"name":"Prof. Pär Ahlström","aff":"Professor, Stockholm School of Economics"}],"order":4}]},{"id":"s169","title":"Emerging Technology and Operations Managemengt","track":"Information Systems and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"EMBASSY E","chairs":["Mr. Yonghua Ji"],"abstracts":[{"id":"136-2066","title":"The Interaction between IoT Data Sharing and Demand Information Sharing","content":"With the development of IoT technology, manufacturers can access consumer usage data through smart products. This paper studies retailers' incentive for sharing demand in an IoT setting. We find that the wholesale retailer will voluntarily share the demand information, whereas the agency retailer is reluctant to share such information.","presenter":"Mr. Yonghua Ji","authors":[{"name":"Dr. Wei Lu","aff":"Student, University of Science and Technology of China"},{"name":"Dr. Can Sun","aff":"Assistant Professor, University of Science and Technology of China"},{"name":"Mr. Yonghua Ji","aff":"Professor, University of Alberta"}],"order":1},{"id":"136-2065","title":"Navigating the Unknown: Optimizing Advertising Strategies in the Face of Ad Auction Uncertainty","content":"Firms launching advertising campaigns through real-time auctions face uncertainty regarding the number of impressions they will ultimately receive. We propose a diffusion equation that incorporates the inherent randomness of ad auctions. By analyzing a real-world dataset, we discover that firms often operate sub-optimally by disregarding the influence of auction uncertainty.","presenter":"Mr. Wangsheng Zhu","authors":[{"name":"Mr. Wangsheng Zhu","aff":"Assistant Professor, Hong Kong University of Science and Technology"}],"order":2},{"id":"136-1380","title":"Data protection capability disclosure strategies and data-empowered decision making in platform ecosystems","content":"We consider the impact of heterogeneous users’ privacy concerns and explore the conditions under which the platform should disclose its data protection capability information and what its and complementors’ optimal level of data empowerment efforts is. Furthermore, we analyze how the cost-sharing and user subsidy strategies affect these results.","presenter":"Ms. Qianqian WANG","authors":[{"name":"Ms. Qianqian WANG","aff":"Student, Tongji University"},{"name":"Prof. Qiang CHEN","aff":"Professor, Tongji University"}],"order":3},{"id":"136-0575","title":"Impact of Company Engagement on Bug Bounty Program Benefits","content":"Firms need to find cost-effective ways to increase the efficiency of their bug bounty programs. We empirically examine the impact of the engagement of internal security teams with external hackers on the program benefits and find that higher engagement leads to higher quality of reports received by the program.","presenter":"Ms. Shreya Gokhale","authors":[{"name":"Ms. Shreya Gokhale","aff":"Student, University of Illinois Urbana-Champaign"},{"name":"Mr. Abhijeet Ghoshal","aff":"Associate Professor, UIUC"},{"name":"Dr. Gopesh Anand","aff":"Professor, University of Illinois Urbana-Champaign"},{"name":"Mr. Yang Gao","aff":"Assistant Professor, University of Illinois Urbana-Champaign"}],"order":4}]},{"id":"s179","title":"Agriculture Innovations and Subsidies","track":"Agriculture and Food Supply Chains","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"VININGS","chairs":["Prof. Ying Zhang","Dr. Heng Chen"],"abstracts":[{"id":"136-0063","title":"Leveraging innovative online platforms to combat food waste","content":"Online platforms, including Too Good to Go, use an innovative approach to addressing food waste. Retailers in these platforms sell their surplus food in \"surprise bags\" at discounted prices. Using game-theoretical models, we examine customer's and retailer's decisions and resulting outcomes.","presenter":"Dr. Zhangchen Hu","authors":[{"name":"Dr. Wei Wei","aff":"Assistant Professor, University of New Hampshire"},{"name":"Dr. Zhangchen Hu","aff":"Assistant Professor, California State University Fullerton"},{"name":"Dr. Dawei Jian","aff":"Assistant Professor, University of Wisconsin-Milwaukee"}],"order":1},{"id":"136-0815","title":"Outcome-Based Pricing for Precision Agriculture Services","content":"Precision agriculture (PA) has been introduced to address ongoing challenges of food shortage. In this paper we explore how outcome-based pricing (OBP) for PA affects various stakeholders considering that PA service providers can learn by doing. We also provide policymakers with general guidelines for implementing government intervention under OBP.","presenter":"Dr. Heng Chen","authors":[{"name":"Dr. Heng Chen","aff":"Assistant Professor, University of Nebraska Lincoln"},{"name":"Prof. Ying Zhang","aff":"Assistant Professor, Santa Clara University"}],"order":2},{"id":"136-1377","title":"Impact of Officials Livestream in Agricultural Sales","content":"This study shows that a single livestream by local government officials can boost sustainable agricultural sales. Using data from Alibaba’s 2020 “The County Mayor Is Here” event, findings reveal that government-led livestreams drive higher, more lasting sales than those by influencers, especially in regions with larger populations and savings.","presenter":"Dr. Wenbin Wang","authors":[{"name":"Mrs. Yi Long","aff":"Student, Shanghai Univ. of Finance and Economics"},{"name":"Dr. Wenbin Wang","aff":"Professor, Shanghai Univ. of Finance and Economics"},{"name":"Prof. Hang Wei","aff":"Professor, Shanghai Univ. of Finance and Economics"},{"name":"Prof. Tian Xie","aff":"Professor, Shanghai Univ. of Finance and Economics"}],"order":3},{"id":"136-1899","title":"Sustainable Sourcing of Agricultural Products: Fixed vs. Flexible Premiums","content":"Sustainability certifications have gained increasing popularity for agricultural product sourcing. To support smallholder farmers in improving their livelihoods, these certifications require firms to pay a premium for certified crops above the market price. This paper explores the design of these premiums.","presenter":"Prof. Can Zhang","authors":[{"name":"Prof. Vishal Agrawal","aff":"Professor, Georgetown University"},{"name":"Prof. Can Zhang","aff":"Associate Professor, Duke University"}],"order":4}]},{"id":"s197","title":"College of Service Operations Paper Competition I","track":"Service Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"EMBASSY C","chairs":["Prof. Benjamin Lawrence"],"abstracts":[{"id":"136-2107","title":"Service Best Paper Presentation: The Implications of Generic Responses in Online Customer Service Operations","content":"This study analyzes social media data from a major U.S. bank to examine the impact of generic responses on customer engagement and satisfaction. Using machine learning and a quasi-experimental approach, we find that while generic responses boost engagement, they lower satisfaction. However, strategic use can enhance both, offering insights.","presenter":"Mrs. Jitsama Tanlmai","authors":[{"name":"Mrs. Jitsama Tanlmai","aff":"Student, McGill University"},{"name":"Prof. Warut Khern-Am-Nuai","aff":"Associate Professor, Mcgill University"},{"name":"Dr. Wreetabrata Kar","aff":"Assistant Professor, State University of New York at Buffalo"},{"name":"Prof. Yossiri Adulyasak","aff":"Associate Professor, HEC Montréal"}],"order":1},{"id":"136-2108","title":"Service Best Paper Presentation: Fresh Rating Systems- Structure, Incentives, and Fees","content":"Rating systems aggregate customer reviews into a numeric measure of service quality. However, not all reviews — and consequently, not all ratings — are equally informative. This paper explores how to modify rating systems to address the issue of stale reviews.","presenter":"Prof. Titing Cui","authors":[{"name":"Prof. Titing Cui","aff":"Assistant Professor, University of Tulsa"},{"name":"Prof. Michael Hamilton","aff":"Assistant Professor, University of Pittsburgh"}],"order":2},{"id":"136-2111","title":"Service Best Paper Presentation: Small Area Estimation of Case Growths for Timely COVID-19 Outbreak Detection","content":"A fundamental challenge in COVID-19 outbreak detection is balancing the accuracy vs. speed tradeoff for small sample size estimation. In this paper, we develop an algorithm, Transfer Learning Generalized Random Forest (TLGRF), that balances this tradeoff.","presenter":"Mr. Zilong Wang","authors":[{"name":"Dr. Zhaowei She","aff":"Assistant Professor, Singapore Management University"},{"name":"Mr. Zilong Wang","aff":"Student, Georgia Institute of Technology"},{"name":"Dr. Jagpreet Chhatwal","aff":"Associate Professor, Harvard University"},{"name":"Prof. Turgay Ayer","aff":"Professor, Georgia Tech"}],"order":3}]},{"id":"s201","title":"Sustainability in Retail Operations","track":"Retail Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"FAIRLIE","chairs":["Dr. Aditya Balaram"],"abstracts":[{"id":"136-0289","title":"No Spoilers: Food Waste and Supply Chain Traceability","content":"We investigate the conditions under which supply chain traceability may lead to a reduction in food waste. We find that the retailer's profit maximization motive often hinders waste reduction unless the supplier shares batch-level information, penalties are optimally set, and the retailer invests in process improvement.","presenter":"Prof. Rob Glew","authors":[{"name":"Prof. Javad Nasiry","aff":"Professor, Mcgill University"},{"name":"Prof. Rob Glew","aff":"Assistant Professor, Mcgill University"}],"order":1},{"id":"136-0325","title":"Does Less Result in More? The Role of Information and Rewards in Clothing Take-Back Programs","content":"Take-back programs for clothing aim to reduce textile waste, but are challenged by low participation rates. We examine the effect of different information and reward levels on consumers’ propensity to return their used clothes through three experiments involving over 3,500 subjects. Our results offer several key managerial insights.","presenter":"Dr. Erin McKie","authors":[{"name":"Dr. Erin McKie","aff":"Assistant Professor, Ohio State University"},{"name":"Prof. Anna Saez de Tejada Cuenca","aff":"Assistant Professor, IESE Business School"},{"name":"Prof. Vishal Agrawal","aff":"Professor, Georgetown University"}],"order":2},{"id":"136-0342","title":"Designing Repair and Take-Back Programs To Improve Consumer Participation In Circular Fashion","content":"Fashion retailers aim to reduce their environmental impact by offering circular solutions for products that have reached their end-of-life. Two commonly offered solutions are repair and take-back programs. We examine how such programs should be offered in order to increase consumer participation in them.","presenter":"Dr. Aditya Balaram","authors":[{"name":"Dr. Punya Chatterjee","aff":"Assistant Professor, University of Memphis"},{"name":"Dr. Aditya Balaram","aff":"Assistant Professor, Loyola Marymount University"}],"order":3},{"id":"136-0453","title":"Platform Reselling Models: Profitability and Sustainability Considerations","content":"The circular economy idea gave rise to various apparel reuse models. We investigate the four models for reselling pre-owned apparel: a trade-in, brand-owned marketplace, third-party platform, and third-party marketplace. We find that all four models can be better for the brand. We also discuss the sustainability of each model.","presenter":"Dr. Aditya Vedantam","authors":[{"name":"Ms. Mariia Petryk","aff":"Assistant Professor, George Mason University"},{"name":"Dr. Aditya Vedantam","aff":"Associate Professor, University of Buffalo"},{"name":"Dr. Emre Demirezen","aff":"Assistant Professor, University of Florida"}],"order":4},{"id":"136-1952","title":"Flexibility in fulfillment of online retailing with green orders","content":"Nowadays, customers favor longer delivery times over paying extra for green deliveries, enabling companies to consolidate shipments and providing some leniency in order fulfillment. This paper studies time flexibility in fulfilling green orders, using a model that determines preparation dates given customers' willingness to wait under uncertain demand and capacities.","presenter":"Dr. Imen Ben Mohamed","authors":[{"name":"Dr. Imen Ben Mohamed","aff":"Assistant Professor, EM-Lyon business school"},{"name":"Dr. Yann Bouchery","aff":"Associate Professor, Kedge Business School"},{"name":"Prof. Walid Klibi","aff":"Professor, Kedge Business School"}],"order":5}]},{"id":"s229","title":"Innovative Applications in Pricing Management","track":"Digital Platforms, Innovations and Transformations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"GREENBRIAR","chairs":["Dr. Jiayu Chen","Dr. Chuanya Jiao"],"abstracts":[{"id":"136-0373","title":"Ride-Hailing Platforms: A Near-Optimal Policy for Pricing, Matching, and Spatial Routing","content":"We study an infinite-horizon, stochastic, dynamic profit-maximization problem for an on-demand ride-hailing platform, with a one-time pricing decision and real-time driver-customer-matching decisions. We establish a theoretical upper bound, and design a near optimal policy whose performance gap with respect to this bound vanishes in a meaningful asymptotic regime.","presenter":"Dr. Yang BO","authors":[{"name":"Dr. Yang BO","aff":"Assistant Professor, CUHK Business School"},{"name":"Prof. Guangwen Kong","aff":"Associate Professor, Temple University"}],"order":1},{"id":"136-0750","title":"Equilibrium Analysis of Competition under Diffusion-Choice Models","content":"This research investigates dynamic pricing in competitive innovation product markets characterized by differentiated product offerings, pronounced life cycle characteristics, and oligopoly competition. We apply a competitive diffusion-choice model to study forward-looking firms’ pricing strategies and provide a framework for examining pricing and pricing-related policies.","presenter":"Dr. Binghan Kou","authors":[{"name":"Dr. Binghan Kou","aff":"Post Doc/Researcher, Arizona State University Tempe"},{"name":"Dr. Hongmin Li","aff":"Professor, Arizona State University Tempe"},{"name":"Prof. Scott Webster","aff":"Professor, Arizona State University Tempe"}],"order":2},{"id":"136-0955","title":"Multi-Product Dynamic Upgrades","content":"Travel industry upgrades are typically static. This paper examines dynamic upgrades via push notifications between booking and check-in, proposing a general multi-level policy and simpler single-level heuristics. Using discrete convex analysis, we identify monotonicity properties in optimal single-level policies, offering practical, efficient upgrade strategies.","presenter":"Dr. Tiancheng Zhao","authors":[{"name":"Dr. Xiao Zhang","aff":"Assistant Professor, Saint Louis University"},{"name":"Dr. Tiancheng Zhao","aff":"Assistant Professor, Saint Louis University"},{"name":"Dr. Justin Goodson","aff":"Associate Professor, Saint Louis University"}],"order":3},{"id":"136-1231","title":"Pricing with Causal Inference","content":"The price response model is the central component for pricing and revenue management. However, to accurately estimate the response model needs to consider causal effect of pricing. We analyze and demonstrate the differences between considering and without considering causal effects in a joint inventory-pricing problem.","presenter":"Dr. Sirong Luo","authors":[{"name":"Dr. Sirong Luo","aff":"Professor, Shanghai Univ. of Finance and Economics"}],"order":4}]},{"id":"s240","title":"Data Analytics in Operations Management","track":"Supply Chain Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"EMBASSY A","chairs":["Prof. Qi Feng","Mr. Jian Wu"],"abstracts":[{"id":"136-0196","title":"Harnessing Large Language Models for Market Research: A Data-augmentation Approach","content":"Large Language Models (LLMs) show promise for data generation in conjoint analysis, though a gap remains between LLM-generated and human data. We propose a novel data augmentation method that integrates both data while addressing the inherent gap. Empirical studies validate our approach, demonstrating reduced estimation error and improved scalability.","presenter":"Dr. Selene Mengxin Wang","authors":[{"name":"Dr. Selene Mengxin Wang","aff":"Assistant Professor, University of Texas Dallas"},{"name":"Prof. Dennis Zhang","aff":"Associate Professor, Washington University in St. Louis"},{"name":"Prof. Heng Zhang","aff":"Assistant Professor, Arizona State University"}],"order":1},{"id":"136-0626","title":"Online Learning for Inventory Control with Fairness Constraints","content":"We address the inventory management problem for multiple stores, with the objective being to maximize the total expected profit of the stores when demand distribution is unknown while ensuring a fairness constraint on the span of the service levels. We propose online learning algorithms achieving tight regret bounds","presenter":"Prof. Jingwen Tang","authors":[{"name":"Prof. Jingwen Tang","aff":"Assistant Professor, University of Miami Business School"},{"name":"Prof. Boxiao (Beryl) Chen","aff":"Associate Professor, University of Illinois at Chicago"},{"name":"Prof. Cong Shi","aff":"Associate Professor, University of Miami Business School"}],"order":2},{"id":"136-0698","title":"Operational Data Analytics (ODA) Embedded Neural Network Learning for the Newsvendor Problem with General Demand","content":"We analyze the data-integrated contextual newsvendor problem with a general demand model and high dimensional covariates. Utilizing the structural properties in the decision problem, we develop an efficient Operational Data Analytics (ODA) embedded neural network solution.","presenter":"Mr. Jian Wu","authors":[{"name":"Prof. Qi Feng","aff":"Professor, Purdue University"},{"name":"Prof. George Shanthikumar","aff":"Professor, Purdue University"},{"name":"Mr. Jian Wu","aff":"Student, Purdue University"}],"order":3},{"id":"136-2037","title":"OMGPT: A Sequence Modeling Framework for Data-driven Operational Decision Making","content":"We build OMGPT, a GPT model for sequential decision tasks in operations research, using a general sequence modeling framework unifying dynamic pricing, inventory, resource allocation, and queueing. OMGPT leverages massive pre-training data, removes structural assumptions, and directly maps history to actions. A Bayesian perspective theoretically supports its remarkable performance.","presenter":"Mr. Hanzhao Wang","authors":[{"name":"Mr. Hanzhao Wang","aff":"Student, Imperial College London"},{"name":"Prof. Kalyan Talluri","aff":"Professor, Imperial College London"},{"name":"Dr. Xiaocheng Li","aff":"Assistant Professor, Imperial College London"},{"name":"Mr. Shang Liu","aff":"Student, Imperial College London"}],"order":4}]},{"id":"s267","title":"Innovative Marketing Strategies","track":"POM-Marketing Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"DUNWOODY","chairs":["Dr. Xiajun Pan","Prof. Hongseok Jang"],"abstracts":[{"id":"136-0785","title":"Regulating Platform Self-Preferencing in Add-on Markets","content":"Platforms, as base product providers, often engage in self-preferencing activities in add-on markets, leading to antitrust concerns. We study welfare impacts of regulations on two common types of self-preferencing: while banning functionality self-preferencing can be Pareto-improving, banning distribution self-preferencing can hurt the platform, consumers, and third-party add-on developers.","presenter":"Dr. Tianxin Zou","authors":[{"name":"Dr. Zheyin Gu","aff":"Associate Professor, University of Connecticut"},{"name":"Prof. Xinxin Li","aff":"Professor, University of Connecticut"},{"name":"Dr. Tianxin Zou","aff":"Assistant Professor, Warrington College of Business"}],"order":1},{"id":"136-1074","title":"Real-Time Narrative Strategies in Live Streaming E-Commerce: Impact on Consumer Engagement and Sales","content":"This study explores how real-time narrative strategies—Resonance Trigger, Contextual Embedding, and Narrative Progression—impact audience engagement and sales in live-streaming e-commerce. Using transcript data and field experiments, it examines the moderating roles of interaction intensity and focus, offering marketers insights into optimizing storytelling and interactivity for better e-commerce outcomes.","presenter":"Dr. Hans Wang","authors":[{"name":"Dr. Hans Wang","aff":"Student, Indiana University Bloomington"},{"name":"Dr. Xingyu Wang","aff":"Assistant Professor, Chongqing University"},{"name":"Prof. Krista Li","aff":"Associate Professor, Indiana University -Bloomington"}],"order":2},{"id":"136-2031","title":"Talking without Speaking: Paid Trolls on Social Media and Court Decision","content":"This article aims to investigate how public opinions and paid trolls may affect the outcome of legal disputes between opposing parties. Our research indicates that firms involved in lawsuits with social media engagement may purchase paid trolls to influence public opinions and the legal court ruling.","presenter":"Prof. Haitao (Tony) Cui","authors":[{"name":"Prof. Haitao (Tony) Cui","aff":"Professor, University of Minnesota"},{"name":"Dr. Yi Liu","aff":"Assistant Professor, University of Wisconsin-Madison"}],"order":3},{"id":"136-1220","title":"Probabilistic Selling for Vertically Differentiated Products: The Role of Consumers’ Gambling Behavior","content":"We examine probabilistic selling for vertically differentiated products when consumers exhibit gambling behaviors. Consumers purchasing the probabilistic product derive a sense of excitement or disappointment depending on the product received. We demonstrate that this gambling behavior makes probabilistic selling more attractive than shown in previous studies.","presenter":"Ms. Zhechao Yang","authors":[{"name":"Ms. Zhechao Yang","aff":"Student, University of Florida"},{"name":"Prof. Hongseok Jang","aff":"Assistant Professor, Tulane University"},{"name":"Dr. Xiajun Pan","aff":"Associate Professor, University of Florida"},{"name":"Dr. Yang Yang","aff":"Associate Professor, UF"}],"order":4}]},{"id":"s276","title":"Innovations in Operations: Managing Uncertainty, Privacy, and Platform Dynamics","track":"Aviation, Transportation, and Logistics Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"UNIVERSITY","chairs":["Dr. Junyu Cao","Ms. Feihong Hu"],"abstracts":[{"id":"136-1350","title":"Privacy-Preserving Inventory Control","content":"This paper addresses privacy issues in the multistage inventory control problems. Leveraging reinforcement learning , we propose a differentially private algorithm that ensures privacy preservation and sample efficiency. Theoretical and experimental results demonstrate the algorithm's effectiveness and privacy benefits on both real and synthetic datasets.","presenter":"Ms. GUANGYAN GAN","authors":[{"name":"Ms. GUANGYAN GAN","aff":"Student, Nanyang Technological University"},{"name":"Mr. Hanzhang Qin","aff":"Student, Massachusetts Institute of Technology"},{"name":"Dr. Zhenzhen Yan","aff":"Assistant Professor, Nanyang Technological University"}],"order":1},{"id":"136-1009","title":"First-in-first-out (FIFO) or highest-energy-first-out (HEFO)? A tale of two electric vehicle (EV) battery swapping policies","content":"In this paper, considering random service requests and random status of incoming batteries, we focus on the operations management of an individual battery swapping station, and propose mean-variance DRO models to compare FIFO and HEFO swapping policies in different scenarios. We verify the analytical results via numerical experiments.","presenter":"Dr. Mengyi Sha","authors":[{"name":"Prof. Wei Qi","aff":"Associate Professor, Tsinghua University Department of IE"},{"name":"Dr. Mengyi Sha","aff":"Post Doc/Researcher, Tsinghua University"},{"name":"Prof. Yuli Zhang","aff":"Associate Professor, Beijing Institute of Technology"}],"order":3},{"id":"136-1921","title":"The Impact of Automation on Workers when Workers are Strategic: The Case of Ride-Hailing","content":"We examine how the introduction of autonomous vehicles (AVs) impacts the strategic behavior and welfare of human drivers. We show that the presence of AVs can incentivize drivers to adopt more efficient repositioning strategies, creating a win-win scenario for both the platform and the drivers.","presenter":"Dr. Xiaotang Yang","authors":[{"name":"Prof. Saif Benjaafar","aff":"Professor, University of Michigan, Ann Arbor"},{"name":"Dr. Zicheng Wang","aff":"Post Doc/Researcher, University of Minnesota"},{"name":"Dr. Xiaotang Yang","aff":"Post Doc/Researcher, University of Toronto"}],"order":4},{"id":"136-1771","title":"Fresh on the Go: Combatting Food Deserts with Mobile Markets","content":"We explore data-driven solutions to address food deserts using mobile markets, focusing on intra-day replenishment of perishable products. We optimize revenue while ensuring fairness across multiple locations at food deserts, providing a sustainable business model to improve food accessibility in underserved communities.","presenter":"Ms. Feihong Hu","authors":[{"name":"Dr. Junyu Cao","aff":"Assistant Professor, University of Texas Austin"},{"name":"Ms. Feihong Hu","aff":"Student, University of Texas Austin"},{"name":"Dr. Wei Qi","aff":"Associate Professor, Tsinghua University"}],"order":5}]},{"id":"s281","title":"Innovative Technologies and Operations Management","track":"Disruptive Technologies and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"KENNESAW","chairs":["Mrs. Zhihan (Helen) Wang"],"abstracts":[{"id":"136-0192","title":"AI and Analytics Partnerships: The Shareholder Value for Biopharmaceutical Firms","content":"Biopharmaceutical firms increasingly form strategic partnerships, with the goal of leveraging AI and analytics technologies to enhance operations. This paper, using event study methodology, finds that these partnerships boost shareholder value. Prelaunch R&amp;D and multi-therapy collaborations yield higher returns, with firm characteristics further moderating the value derived from such collaborations.","presenter":"Prof. Jiatao Ding","authors":[{"name":"Prof. Jiatao Ding","aff":"Assistant Professor, Nanyang Technological University"},{"name":"Dr. Michael Freeman","aff":"Assistant Professor, INSEAD"},{"name":"Prof. Niyazi Taneri","aff":"Associate Professor, University of Cambridge"}],"order":1},{"id":"136-1643","title":"Enhancing Telemental Health Uptake: The Critical Role of Technological Infrastructure and Parity","content":"This study investigates the drivers of telemental health adoption and its impact on population mental health condition, using 2018 Rural Health Care Program funding increase as a natural experiment. Findings underscore the need to combine technological infrastructure with supportive policies to boost telehealth uptake and improve public health outcomes.","presenter":"Dr. Yi Tang","authors":[{"name":"Dr. Yi Tang","aff":"Assistant Professor, University of New Mexico"},{"name":"Prof. Eric Xu","aff":"Assistant Professor, Mississippi State University"},{"name":"Prof. Kingshuk Sinha","aff":"Professor, University of Minnesota"}],"order":2},{"id":"136-1864","title":"From Red Tape to Regtech: How Do Online Platforms Facilitate International Trade?","content":"Leveraging shipment-level custom data from 2013 to 2017, we quantify the impact of a regulatory technology (RegTech) platform for processing value-added tax (VAT) rebates on regional exports in China. Specifically, we show that such technology facilities international trade by reducing the waiting time for tax rebates.","presenter":"Mrs. Zhihan (Helen) Wang","authors":[{"name":"Mr. Jingyuan Cui","aff":"IMF, International Monetary Fund"},{"name":"Mrs. Zhihan (Helen) Wang","aff":"Student, University of Michigan, Ann Arbor"},{"name":"Prof. Andrew Wu","aff":"Associate Professor, Ross School of Business"}],"order":3},{"id":"136-1877","title":"Analyzing Social Media Discourse on Child Protective Services","content":"The rise of social media platforms like Reddit has provided a valuable lens through which to study public discourse on child protective services (CPS). This project leverages large language models to analyze Reddit posts discussing CPS, aiming to uncover patterns and sentiments and their relationship to post quality and effectiveness.","presenter":"Prof. Savannah Tang","authors":[{"name":"Prof. Savannah Tang","aff":"Assistant Professor, SMU Cox School of Business"}],"order":4}]},{"id":"s325","title":"Panel: Celebrating the Special Issue of POM","track":"POM and Community","type":"Panel","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"EMBASSY F","chairs":["Dr. Priyank Arora","Prof. Dwaipayan Roy"],"abstracts":[{"id":"136-2119","title":"Panel: Celebrating the Special Issue of POM on DEI","content":"This panel will showcase and celebrate the Special Issue of POM on “Diversity, Equity, and Inclusion in Operations and Supply Chain Management.” In addition to discussing the special issue's journey from inception to fruition, the panelists will also share thoughts on future research.","presenter":"Dr. Priyank Arora","authors":[{"name":"Dr. Priyank Arora","aff":"Associate Professor, University of South Carolina"},{"name":"Prof. Dwaipayan Roy","aff":"Assistant Professor, University of Virginia"},{"name":"Dr. Wenjie Tang","aff":"Associate Professor, University of Vienna"},{"name":"Dr. Chris Parker","aff":"Associate Professor, Darden School of Business"},{"name":"Dr. Subodha Kumar","aff":"Professor, Temple University"},{"name":"Prof. Charles Corbett","aff":"Professor, UCLA Anderson School of Management"}],"order":1}]},{"id":"s351","title":"Features Speaker Series Tutorial: Operations Management meets Life Cycle Analysis: How can we help each other better inform sustainability decisions?","track":"Tutorials and Workshops in Research and Teaching","type":"Tutorial","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"Learning Center","chairs":["Prof. Vishal Agrawal","Dr. Antonio Cavallin Toscani"],"abstracts":[{"id":"136-2075","title":"Features Speaker Series_Tutorial_Operations Management meets Life Cycle Analysis","content":"Over the past two decades, Sustainable Operations studies have increasingly incorporated LCA to assess environmental outcomes of business and policy decisions. This session highlights how Operations Management (OM) and LCA can collaborate to enhance the evaluation of sustainable business strategies.\r\n","presenter":"Prof. Vishal Agrawal","authors":[{"name":"Prof. Vishal Agrawal","aff":"Professor, Georgetown University"},{"name":"Prof. Antonio Toscani","aff":"Assistant Professor, University of Padova"}],"order":1}]},{"id":"s352","title":"Hospitality Research and Food Access","track":"Service Operations","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"INMAN","chairs":["Prof. Barry Cross"],"abstracts":[{"id":"136-1804","title":"The effects of near misses in hospitality quality audits","content":"In the hospitality industry, the margins between passing and failing quality audits are small; the audit result can cause significant benefits or immense costs. Analysis of random, unannounced quality audits in hotels shows the influence that a near miss has on future service quality performance.","presenter":"Mr. Peter Carrera","authors":[{"name":"Mr. Peter Carrera","aff":"Student, Ohio State University"},{"name":"Prof. Kenneth Boyer","aff":"Professor, Ohio State University"}],"order":1},{"id":"136-0222","title":"Investigating Service Scripts as a Coordinating Mechanism in Complex, High-Touch Service Contexts","content":"Extant research assumes that service scripts are ill-suited for coordinating complex, unpredictable service activities because they stymie the flexibility and discretion such environments demand. However, little research has investigated this axiom. We investigate service scripts as a coordination mechanism in healthcare- an archetype of complex, high-touch service environments.","presenter":"Dr. Onyi Dillibe","authors":[{"name":"Dr. Onyi Dillibe","aff":"Assistant Professor, University of North Carolina Greensboro"}],"order":2},{"id":"136-1466","title":"Prompting Topic Diversity for Positive Reviews: Moderating Effects of Seasonality and Hotel Features","content":"Positive online reviews help attract customers. Using advanced NLP techniques, we examine the impact of topic diversity—capturing whether a review covers diverse features or focuses on one or two aspects—on review sentiment. Additionally, we explore the moderating roles of tourism seasonality and hotel attributes.","presenter":"Ms. Yunfan Wang","authors":[{"name":"Ms. Yunfan Wang","aff":"Student, IE BUSINESS SCHOOL"},{"name":"Prof. Emmanouil Avgerinos","aff":"Associate Professor, IE BUSINESS SCHOOL"},{"name":"Prof. Konstantina Valogianni","aff":"Associate Professor, IE BUSINESS SCHOOL"},{"name":"Mr. Berend Dumas","aff":"Data Scientist , IE BUSINESS SCHOOL"}],"order":3},{"id":"136-2063","title":"Timing a vacation","content":"This paper discusses quantitative models for timing a vacation. The models used in this research are all based on multicriteria decisions and their extensions. This decision-making study begins with eliminating poor dates, next three analytical ranking models are introduced for selecting the best timing for vacation in a resort.","presenter":"Prof. Fariborz Partovi","authors":[{"name":"Prof. Fariborz Partovi","aff":"Professor, Drexel University"}],"order":5},{"id":"136-0135","title":"Take the Productivity Challenge: Teaching &amp; Enabling Productivity","content":"Countries and companies are prioritizing productivity, yet it remains an abstract, elusive concept, especially in service organizations. In this extended session, your hosts will use a mini-case to set the tone and facilitate a teaching workshop on enabling greater focus on productivity in your classrooms. Requesting 60 minute session.","presenter":"Prof. Barry Cross","authors":[{"name":"Prof. Barry Cross","aff":"Assistant Professor, Queens University"},{"name":"Dr. Matthew Walsman","aff":"Assistant Professor, Rutgers Business School"}],"order":6}]},{"id":"s372","title":"Panel: Technology at the Crossroads - Ethical Dilemmas in Operations for Social Good","track":"Operations and Society","type":"Panel","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"SPRING","chairs":["Dr. Telesilla Kotsi"],"abstracts":[{"id":"136-2086","title":"Panel: Technology at the Crossroads - Ethical Dilemmas in Operations for Social Good","content":"This panel examines ethical dilemmas arising from the increasing use of technology in operations for social good. Topics include humanitarian logistics, algorithmic decision-making, and resource allocation. Panelists will discuss how to balance efficiency with fairness, address unintended consequences, and ensure technology-driven operations align with ethical and societal objectives.","presenter":"Dr. Mateus do Rego Ferreira Lima","authors":[{"name":"Dr. Telesilla Kotsi","aff":"Assistant Professor, Fisher College of Business"},{"name":"Dr. Mateus do Rego Ferreira Lima","aff":"Assistant Professor, Kelley School of Business, Indiana Univ."},{"name":"Dr. Yoonseock Son","aff":"Assistant Professor, University of Notre Dame"},{"name":"Prof. Anant Mishra","aff":"Professor, University of Minnesota"},{"name":"Dr. Rogelio Oliva","aff":"Professor, Texas A&amp;M University College Station"}],"order":1}]},{"id":"s396","title":"Business Strategies to Mitigate Climate Change","track":"Sustainable Operations Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"GRAND HALL EAST C","chairs":["Mr. Ranit Saha"],"abstracts":[{"id":"136-0881","title":"An Integrated Process-Oriented Framework of Low Carbon Manufacturing Networks","content":"The research question is How can manufacturing companies implement carbon reduction projects within their supply networks? Drawing upon multiple case studies, we develop a process model addressing supply network stages, emission reduction, and process changes. Findings contribute to sustainable supply chain literature with empirical evidence capturing decarbonization complexity.","presenter":"Dr. Zheng Liu","authors":[{"name":"Dr. Jialun Hu","aff":"Senior Lecturer, Royal Holloway, University of London"},{"name":"Dr. Zheng Liu","aff":"Associate Professor, University of Greenwich"},{"name":"Dr. Yongjiang Shi","aff":"Associate Professor, Cambridge University"}],"order":1},{"id":"136-0891","title":"How do carbon finance and demand updates affect production decisions and environmental outcomes?","content":"We address the uncertainties in both product demand and carbon trading markets. The carbon finance instruments, such as carbon options and carbon forwards, along with the demand updates, are integrated into profit maximization models. The impact on manufacturing decisions and environmental outcomes is analyzed and compared under varying market conditions.","presenter":"Ms. LIN QIN","authors":[{"name":"Ms. LIN QIN","aff":"Student, Southeast University"},{"name":"Prof. Weida Chen","aff":"Professor, Southeast University"}],"order":2},{"id":"136-1953","title":"Firm Entry and Environmental Impact in the Amazon Rainforest","content":"This study examines a firm's decision to address collective action problems, such as climate change, focusing on whether its entry into the Amazon rainforest leads to deforestation or preservation. We explore the environmental implications of resource extraction by firms in this critical ecosystem.","presenter":"Prof. Joshua Ignatius","authors":[{"name":"Prof. Joshua Ignatius","aff":"Professor, Aston Business School"},{"name":"Dr. Rui Li","aff":"Associate Professor, University of Electronic Science &amp; Technology of China"},{"name":"Prof. Ted Feldpausch","aff":"Professor, University of Exeter"},{"name":"Ms. Yaru You","aff":"Student, University of Electronic Science &amp; Technology of China"}],"order":4},{"id":"136-2055","title":"nderstanding challenges to the adoption of low global warming potential refrigerants in an emerging economy","content":"The international mandate for regulating the usage of harmful refrigerants worldwide can be addressed by encouraging the use of the low global warming potential (GWP) refrigerants but the emerging economies face challenges for its adoption. This study aims to identify the factors that influence the adoption and explore their relationship.","presenter":"Dr. Kunal Ganguly","authors":[{"name":"Dr. Kunal Ganguly","aff":"Professor, IIM kashipur"}],"order":5},{"id":"136-0409","title":"Shall Ye (Not) Do It Thyself? Retailer Strategies to Validate Manufacturer's Sustainability Claims","content":"We analyze the decision-making problem of a retailer regarding whether it should employ in-house monitoring or ask for third-party certifications to validate the sustainability claims of a manufacturer. We developed a sequential game-theoretic model and showed that the retailer should monitor independently when consumers are less suspicious about those claims.","presenter":"Mr. Ranit Saha","authors":[{"name":"Mr. Ranit Saha","aff":"Student, Indian Institute of Management Calcutta"},{"name":"Mr. Raunak Joshi","aff":"Student, Indian Institute of Management Calcutta"},{"name":"Prof. Sumanta Basu","aff":"Professor, Indian Institute of Management Calcutta"}],"order":6}]},{"id":"s435","title":"Reinforcement Learning Models","track":"Data Science, Analytics and AI","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"ROSWELL","chairs":["Ms. Fatemeh Fakhredin"],"abstracts":[{"id":"136-1361","title":"A continuous-time event-based reinforcement learning approach for scheduling multiproduct pipelines","content":"We propose a novel continuous-time, event-based reinforcement learning approach for scheduling multiproduct pipelines with a single source and destination. The model incorporates variable flow rates, minimum batch sizes, forbidden product sequences, and tank capacity constraints. The objective is to maximize demand satisfaction while adhering to all operational constraints.","presenter":"Mr. Mouad SIDKI","authors":[{"name":"Mr. Mouad SIDKI","aff":"Student, Mohammed VI Polytechnic University"}],"order":1},{"id":"136-1557","title":"Model-Free Reinforcement Learning for Nonstationary Inventory Control via State Representation Learning","content":"We consider inventory control problems with uncertain, nonstationary demand. The latter is impacted by hidden, exogenous factors that cannot be precisely quantified and integrated in replenishment policies. We formalize this as a partial observable Markov decision process and construct state representations that lead to approximate solutions using model-free reinforcement learning.","presenter":"Mrs. Nele Amiri","authors":[{"name":"Mrs. Nele Amiri","aff":"Student, KU Leuven"},{"name":"Dr. Denis Steckelmacher","aff":"Post Doc/Researcher, Vrije Universiteit Brussel"},{"name":"Dr. Maximiliano Udenio","aff":"Associate Professor, KU Leuven"}],"order":2},{"id":"136-2028","title":"Optimizing a Multi-Echelon Inventory Management with Backordering and Capacity Constraints via Deep Reinforcement Learning","content":"We explore a multi-echelon inventory management system characterized by backordering, lead time uncertainty, and capacity constraints, utilizing Deep Reinforcement Learning (DRL). We seek to answer the question: Does DRL produce better policies for such complex operational problems than state-of-the-art heuristics and standard reinforcement learning techniques?","presenter":"Ms. Fatemeh Fakhredin","authors":[{"name":"Prof. Joern Meissner","aff":"Professor, Kuehne Logistics University"},{"name":"Ms. Fatemeh Fakhredin","aff":"Student, Kuehne Logistics University"}],"order":3}]},{"id":"s445","title":"Honoring Cheryl Gaimon: Evolution and Future Directions of Research in Management of Technology","track":"Honoring Retirees","type":"Panel","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"GRAND HALL EAST A","chairs":["Prof. Janice Carrillo","Prof. Sanjiv Erat","Dr. Karthik Ramachandran"],"abstracts":[{"id":"136-2129","title":"Honoring Cheryl Gaimon: Evolution and Future Directions of Research in Management of Technology","content":"The speakers will discuss their perspectives on how research in MOT has evolved in the past and the critical research directions they anticipate in the future.","presenter":"Prof. Janice Carrillo","authors":[{"name":"Prof. Janice Carrillo","aff":"Professor, University of Florida"},{"name":"Prof. Sanjiv Erat","aff":"Associate Professor, University of California, San Diego"},{"name":"Dr. Karthik Ramachandran","aff":"Professor, Georgia Institute of Technology"},{"name":"Dr. Ling Xue","aff":"Associate Professor, University of Georgia"}],"order":1}]},{"id":"s3","title":"Emerging Trends in Manufacturing Operations","track":"Manufacturing Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"LENOX","chairs":["Mr. Kerim U. Kizil"],"abstracts":[{"id":"136-0601","title":"Mastering Additive and Selective Product Options in Assemblies","content":"Customers can choose among additive and selective options covering a range of probabilities and process times; as assembly lines are designed for the long term, those choices create challenges for efficient line balancing. Using proactive fuzzy logic, we extend our general assembly line balancing approach to obtain the optimal takt.","presenter":"Mr. Philipp Pithan","authors":[{"name":"Mr. Philipp Pithan","aff":"Student, WHU - Otto Beisheim School of Management"},{"name":"Prof. Arnd Huchzermeier","aff":"Professor, WHU - Otto Beisheim School of Management"}],"order":1},{"id":"136-1120","title":"Minimizing the Number of Late Parts in Additive Manufacturing System","content":"We assess the computational complexity and primary issues with nesting and scheduling of parts in an Additive Manufacturing System. This paper also develops a pair of heuristics to address the number of late parts in AM and provides numerically generated samples to test their performance.","presenter":"Mr. Michael Stott","authors":[{"name":"Mr. Michael Stott","aff":"Student, Texas A&amp;M University"},{"name":"Prof. Chelliah Sriskandarajah","aff":"Professor, Texas A&amp;M University College Station"},{"name":"Prof. Jon Stauffer","aff":"Associate Professor, Mays Business School, Texas A&amp;M University"}],"order":2},{"id":"136-1213","title":"Assessing Business Operation Impacts of Direct-to-Consumer Beer Delivery Laws on the Craft Beer Industry","content":"This study examines the economic impact of Direct-to-Consumer (DtC) beer shipping laws on the craft beer industry. Using policy changes in select states as natural experiments, the research employs Difference-in-Difference analysis to evaluate how these laws affect brewery product innovation, market dynamics, and consumer behavior.","presenter":"Mr. Qilong Zhu","authors":[{"name":"Mr. Qilong Zhu","aff":"Student, Texas A&amp;M University"},{"name":"Prof. Gregory Heim","aff":"Professor, Texas A&amp;M University College Station"}],"order":3},{"id":"136-0202","title":"Strategic Choices for OEMs: Building Brands Through Direct Livestreaming or Partnering with Livestreaming Influencers","content":"Many OEMs are not satisfied with supplying downstream brand clients to share profits. They establish their own brand through livestream sales either with their own live streamers or collaborating with influencers. We examine OEMs’ live-streaming strategies and the reactions from downstream brand clients using a two-period game theoretical model.","presenter":"Mr. Si Liu","authors":[{"name":"Dr. Yue Guo","aff":"Associate Professor, Southern University of Science and Technology"},{"name":"Mr. Si Liu","aff":"Student, Mcmaster University"},{"name":"Dr. Wenyi Xia","aff":"Assistant Professor, HEC Montréal"},{"name":"Dr. YI Zhu","aff":"Assistant Professor, Kent State University"}],"order":4}]},{"id":"s23","title":"Generative AI Transforming Markets and Society","track":"Generative AI and Societal Sustainable Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"HARRIS","chairs":["Mr. Qili Wang"],"abstracts":[{"id":"136-0822","title":"Patients’ participation in process design and trust in generative artificial intelligence","content":"There is a lack of solutions to improve patient trust from the construction process of healthcare AI. To investigate this, the research team will rigorously design and execute reliable randomized controlled trials based on intervention based research (IBR) to determine the effectiveness of interventions.","presenter":"Prof. Lujie Chen","authors":[{"name":"Mr. Yanwu Song","aff":"Student, University of Science and Technology of China"},{"name":"Prof. Lujie Chen","aff":"Reader, Xi'an JiaoTong-Liverpool University"},{"name":"Prof. Fu Jia","aff":"Professor, University of York, UK"}],"order":1},{"id":"136-0158","title":"Less is More: The Impact of Flexible PIN-Based Matching in a Ride-Hailing Platform","content":"Our study suggests that upfront matching with extensive information may lead to inefficiencies in peer-to-peer markets with high market thickness. We highlight that a more flexible matching mechanism with constrained pre-match information can enhance platform efficiency and serve as an effective alternative to additional financial incentives offered by the platforms.","presenter":"Ms. Mengwei Qu","authors":[{"name":"Ms. Mengwei Qu","aff":"Student, University of Connecticut"},{"name":"Dr. Bowen Lou","aff":"Assistant Professor, University of Southern California"},{"name":"Dr. Chen Liang","aff":"Assistant Professor, University of Connecticut"},{"name":"Dr. Milan Miric","aff":"Associate Professor, University of Southern California"}],"order":2},{"id":"136-0654","title":"The Impact of Beauty Filter Restrictions on Teen Behavior and Well-Being: Evidence from TikTok","content":"This study examines TikTok's global policy restricting beauty filter access for users under 18, focusing on its effects on teenage platform behavior, content creation, and well-being. Using a difference-in-differences approach with observational data, we explore the policy's implications for AI-driven moderation, user engagement, and mental health outcomes.","presenter":"Mr. Tong Shen","authors":[{"name":"Ms. Aiwen Hu","aff":"Student, Shenzhen Foreign Languages School"},{"name":"Mr. Tong Shen","aff":"Student, University of Connecticut"},{"name":"Prof. Yuexuan Wang","aff":"Professor, The University of Hong Kong"}],"order":3},{"id":"136-0686","title":"Echoes of Biases: How Stigmatizing Language Affects AI Performance","content":"This study examines how stigmatizing language in electronic health records affects AI-driven mortality predictions, highlighting significant racial disparities. It further identifies an intriguing behavior among clinicians during EHR recording as a key mechanism and develops an SL-Adjusted Transformer to improve prediction performance and fairness, addressing racial disparities in healthcare AI.","presenter":"Mr. Yizhi Liu","authors":[{"name":"Mr. Yizhi Liu","aff":"Student, University of Maryland - College Park"},{"name":"Dr. Weiguang Wang","aff":"Assistant Professor, Johns Hopkins University Carey Business"},{"name":"Prof. Guodong \"Gordon\" Gao","aff":"Professor, Carey Business School"},{"name":"Prof. Ritu Agarwal","aff":"Professor, Carey Business School"}],"order":4},{"id":"136-1333","title":"“Generate” the Future of Work through AI: Empirical Evidence from Online Labor Markets","content":"Leveraging an extensive dataset from a prominent online labor market, we empirically investigate how Generative AI influences labor demand, supply, market competition, and matching outcomes. In response to these overarching market changes, we also document the strategies workers employ to transition their skills.","presenter":"Mr. Xingchen Xu","authors":[{"name":"Mr. Xingchen Xu","aff":"Student, University of Washington"}],"order":5}]},{"id":"s30","title":"Suppliers and Community","track":"POM and Community","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"EMBASSY F","chairs":["Dr. Minelle Silva"],"abstracts":[{"id":"136-0334","title":"Examining Gender Diversity and Injustice Among Supply Chain Executives","content":"Using compensation and operational performance data of publicly traded firms in the US, we find that women hold only 6% of positions but earn higher compensation. Observable factors fail to explain their underrepresentation, suggesting systemic injustices. Findings urge transformative action to advance gender equity and social justice in SCM.","presenter":"Dr. Anna Land","authors":[{"name":"Dr. Anna Land","aff":"Assistant Professor, Boise State University"},{"name":"Dr. James Kroes","aff":"Professor, Boise State University"}],"order":1},{"id":"136-1103","title":"From effectiveness to equity: designing allocation in food aid programs for traditional peoples and communities","content":"In this paper, we formulate and analyze a mathematical model to design effective and equitable food distribution strategies by which governments can allocate food baskets to traditional populations, such as indigenous, quilombolas, and extractive people. Using the concept of fair share, we model equity based on populations and geographic areas.","presenter":"Prof. Adriana Leiras","authors":[{"name":"Dr. Negreiros Fabiola","aff":"Post Doc/Researcher, Pontifícia Universidade Católica do Rio de Janeiro - PUC-Rio"},{"name":"Ms. Daniela Quenaya","aff":"Student, Pontifícia Universidade Católica do Rio de Janeiro - PUC-Rio"},{"name":"Dr. Douglas Alem","aff":"Associate Professor, University of Edinburgh"},{"name":"Prof. Adriana Leiras","aff":"Associate Professor, Pontifícia Universidade Católica do Rio de Janeiro - PUC-Rio"}],"order":2},{"id":"136-1118","title":"A learning perspective on inclusive puchasing practices","content":"Interest in diversity, equity, and inclusion (DEI) practices has broken through firms’ boundaries over time. This archival study investigates how boundary objects configure inclusive purchasing practices through multi-level learning. Results show five boundary objects were revealed across levels that represented methods the firms employed to span boundaries for inclusive purchasing.","presenter":"Dr. Minelle Silva","authors":[{"name":"Dr. Minelle Silva","aff":"Associate Professor, Asper School of Business"}],"order":3}]},{"id":"s51","title":"Planning for our Energy Future","track":"Energy and Natural Resource Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"AUBURN","chairs":["Dr. Karthik Murali"],"abstracts":[{"id":"136-0100","title":"The optimal bidding of a virtual power plant in the negative price electricity market","content":"To address issues with the burgeoning renewable energy supply in the Jeju, the Korean government has reformed the local electricity market. We consider the optimal bidding problem of a virtual power plant in the market, and shows the experimental results through the tests based on real data.","presenter":"Prof. Dong Gu Choi","authors":[{"name":"Mr. Jonghyeok Lee","aff":"Student, POSTECH"},{"name":"Mr. Youngdoo Choi","aff":"Student, POSTECH"},{"name":"Prof. Dong Gu Choi","aff":"Associate Professor, POSTECH"}],"order":2},{"id":"136-0270","title":"Renewable Energy Servicizing for Residential Homes in Developing Countries","content":"Energy access remains a critical challenge in developing countries. This paper proposes a servicizing model where firms install and maintain solar-battery systems for households, enabling access to renewable energy via usage-based payments. Analytical modeling and simulations using Nigerian household data highlight the model's profitability, reliability and potential for sustainable energy.","presenter":"Ms. Jaachinma Okafor","authors":[{"name":"Ms. Jaachinma Okafor","aff":"Student, The University of Tennessee-Knoxville"},{"name":"Dr. Russell Barton","aff":"Professor, Penn State University University Park"},{"name":"Dr. Paolo Letizia","aff":"Associate Professor, University of Tennessee"},{"name":"Prof. Gil Souza","aff":"Professor, University of Tennessee Knoxville"}],"order":3}]},{"id":"s57","title":"Business and Climate Change","track":"Sustainable Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"GRAND HALL EAST C","chairs":["Prof. Safak Yucel","Prof. Soudipta Chakraborty"],"abstracts":[{"id":"136-0299","title":"When Workers Monitor: How Engagement with Energy Management Systems Affects Energy Efficiency","content":"We examine the impact of worker engagement with energy management systems (EMS) on energy efficiency in manufacturing. We highlight the importance of human interventions in unlocking the full potential of EMS technology. We offer managerial implications on the effective utilization of the EMS to improve energy efficiency in manufacturing operations.","presenter":"Mr. Donggyu Jeon","authors":[{"name":"Mr. Donggyu Jeon","aff":"Student, Kelley School of Business, Indiana Univ."},{"name":"Dr. Christopher Chen","aff":"Assistant Professor, Indiana University - Kelley School of Business"},{"name":"Prof. Owen Wu","aff":"Associate Professor, Indiana University - Kelley School of Business"},{"name":"Dr. Amrou Awaysheh","aff":"Associate Professor, Indiana University - Kelley School of Business"}],"order":1},{"id":"136-0326","title":"Green Ride-Hailing: Impact on Environment and Consumers","content":"Ride-hailing services are rapidly adopting green vehicles, but their impact on emissions and customers remains unclear. We find that adding green vehicles can increase emissions under certain conditions and characterize the market conditions under which adding green vehicles is beneficial for all customer types, including those who are environmentally insensitive.","presenter":"Prof. Yuexing Li","authors":[{"name":"Prof. N. Bora Keskin","aff":"Associate Professor, Duke University Durham"},{"name":"Prof. Yuexing Li","aff":"Assistant Professor, Johns Hopkins University"},{"name":"Prof. Nur Sunar","aff":"Associate Professor, Kenan-Flagler Business School"}],"order":2},{"id":"136-0962","title":"Reduce and Reveal: Emissions Abatement and Disclosure in Supply Chains","content":"We consider a firm and its supplier, both of whom exert effort to reduce emissions in the supply chain. The firm then discloses these emissions to investors to influence its capital-market valuation. We study the relationship between the firm’s information disclosure strategy and emissions abatement efforts in the supply chain.","presenter":"Prof. Soudipta Chakraborty","authors":[{"name":"Prof. Vishal Agrawal","aff":"Professor, Georgetown University"},{"name":"Prof. Soudipta Chakraborty","aff":"Assistant Professor, University of Kansas"}],"order":3},{"id":"136-1111","title":"EV Batteries: Economic &amp; Environmental Impacts of Repurposing &amp; Recycling","content":"Electric vehicle and energy storage markets stimulate the demand for batteries and in turn the critical minerals. We build a two-stage model to capture the first and second life of EV batteries and study the economic and environmental implications of recycling and repurposing.\r\n","presenter":"Prof. Metin Cakanyildirim","authors":[{"name":"Dr. Lingling Shi","aff":"Assistant Professor, Mcmaster University"},{"name":"Dr. Sila Cetinkaya","aff":"Professor, Southern Methodist University"},{"name":"Prof. Metin Cakanyildirim","aff":"Professor, University of Texas Dallas"}],"order":4}]},{"id":"s65","title":"Irresponsibility and Misconduct in Supply Chains","track":"Supply Chain Risk Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"EMBASSY H","chairs":["Mr. Finn Petersen"],"abstracts":[{"id":"136-0874","title":"Supply Chain Risk and Resolution: An Empirical Study of Stock Market Reactions","content":"The estimation of supply chain risk and resolution of supply chain risk has been challenging due to missing firm-level data. We propose a measure based on textual analysis of quarterly earnings calls. While SC risk has a negative effect on stock returns, we find that resolution has a positive effect","presenter":"Prof. Kai Hoberg","authors":[{"name":"Mr. Keno Theile","aff":"Student, Kühne Logistics University"},{"name":"Dr. Christian Hofer","aff":"Professor, University of Arkansas"},{"name":"Prof. Vinod Singhal","aff":"Professor, Georgia Institute of Technology"},{"name":"Prof. Kai Hoberg","aff":"Professor, Kühne Logistics University"}],"order":1},{"id":"136-1551","title":"The Impact of Deregulation on Supply Chain Compliance and Firm Outcomes","content":"Conflict mining incites regional violence and forced labor, posing operational risks to firms’ supply chains. We explore firm compliance with the Dodd-Frank Act (and its subsequent deregulation) to evaluate risk management systems, finding that strong systems improve firms’ financial risks and market valuation while mitigating impacts of prior ESG violations.","presenter":"Ms. Jennifer Nowicki","authors":[{"name":"Ms. Jennifer Nowicki","aff":"Student, Penn State University"},{"name":"Prof. Brian Lee","aff":"Assistant Professor, Pennsylvania State University"},{"name":"Dr. Kevin Linderman","aff":"Professor, Penn State University"}],"order":2},{"id":"136-0514","title":"Optimal Procurement Contract under Random Yield and Information Asymmetry","content":"We study a contract design problem for a retailer working with a supplier who holds private information. Using mechanism design theory, we model the problem as a two-stage screening game to derive the retailer's optimal procurement contract. We then conduct sensitivity analyses to derive managerial insights.","presenter":"Dr. Xinyan Cao","authors":[{"name":"Dr. Xinyan Cao","aff":"Associate Professor, Northern Illinois University"},{"name":"Prof. Xiang Fang","aff":"Associate Professor, University of Colorado Denver"},{"name":"Dr. Yuanjie He","aff":"Professor, California State Polytech University Pomona"},{"name":"Dr. Wei Hu","aff":"Associate Professor, Nankai Univeristy"},{"name":"Dr. Xiao Xiao","aff":"Assistant Professor, California State University Stanislaus"}],"order":3},{"id":"136-1340","title":"Are Chief Sustainability Officers Guardians Of Environmental Justice?","content":"We investigate whether appointing a Chief Sustainability Officer (CSO) can reduce environmental injustice (i.e. the unequal exposure of underserved communities to toxic releases). Analyzing U.S. manufacturing data from 2000 to 2020, we find that CSO appointments decrease toxic releases, especially in underserved communities. Thereby reducing environmental injustice.\r\n\r\n","presenter":"Mr. Finn Petersen","authors":[{"name":"Mr. Finn Petersen","aff":"Student, University of Minnesota"},{"name":"Prof. Vibhuti Dhingra","aff":"Assistant Professor, York University"},{"name":"Prof. Rachna Shah","aff":"Professor, University of Minnesota"}],"order":4}]},{"id":"s81","title":"Innovative business models in NPD","track":"Product Innovation and Technology Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"COURTLAND","chairs":["Prof. Sreekumar Bhaskaran"],"abstracts":[{"id":"136-0595","title":"Sustainable Franchising Model Innovation: A Stage-Based Contract for Reciprocal Exchange and Sustainability","content":"We examine a reciprocal exchange mechanism for generating sustainable franchising model innovation consistent with the perspective of social exchange theory. We develop a stage-based contract to characterize the franchisor’s ESG efforts and earnings shares. Our empirical analysis offers practical implications for two-stage contracts involving sustainable franchisor-franchisee relationships.","presenter":"Dr. Sinan Erzurumlu","authors":[{"name":"Dr. Sinan Erzurumlu","aff":"Professor, Babson College"},{"name":"Prof. Phil Kim","aff":"Professor, Babson College"}],"order":1},{"id":"136-1004","title":"Distribution Contracts for Digital Content Supply Chains in the Presence of Piracy","content":"We show that in the presence of piracy, an increase in the platform’s commission rate under an agency (revenue-sharing) contract can sometimes benefit a digital content manufacturer; and that due to anti-piracy collaborative efforts, the wholesale contract can outperform the agency contract for the manufacturer, the platform, and consumers.","presenter":"Prof. Abhishek Roy","authors":[{"name":"Dr. Prasenjit Mandal","aff":"Associate Professor, NEOMA Business School"},{"name":"Prof. Abhishek Roy","aff":"Assistant Professor, Temple University"}],"order":2},{"id":"136-1136","title":"Decoding Biases in Fake Review Detection: Human versus Algorithmic Decision-Making","content":"Decision-making shapes lives and societal outcomes, yet biases persist in humans and AI. This study examines gender and race biases in online deception detection, using empirical analysis and experiments. Findings reveal discriminatory patterns in detecting fake reviews, offering insights for policies to ensure fairness in decision-making.","presenter":"Dr. Arunima Chhikara","authors":[{"name":"Dr. Arunima Chhikara","aff":"Assistant Professor, University of Kansas"},{"name":"Dr. Anurag Garg","aff":"Assistant Professor, University of Kansas"},{"name":"Prof. Naveen Kumar","aff":"Associate Professor, University of Oklahoma"},{"name":"Prof. Liangfei Qiu","aff":"Professor, University of Florida"}],"order":3},{"id":"136-1141","title":"From Factories to Streets? The Impact of Ridesharing Services on Labor Turnover in US Manufacturing","content":"The rapid growth of ride-sharing platforms has transformed urban transportation and employment patterns, yet their labor market spillover effects on traditional sectors like manufacturing remain unexplored. In this study, we examine the question: Does the entry of ride-sharing platforms yield a material short-term change in labor turnover in manufacturing firms?","presenter":"Ms. Yasaman Asayesh","authors":[{"name":"Ms. Yasaman Asayesh","aff":"Student, University of Minnesota"},{"name":"Prof. Anant Mishra","aff":"Professor, University of Minnesota"}],"order":4},{"id":"136-1741","title":"Optimal Loyalty Program Design in a Multichannel Context","content":"Platforms may help hotels reach more customers but hotels lose the profit margin due to commissions. Hotels would like to attract new customers but keep the recurring ones to book though their direct channel. We explore theoretically how to design an optimal loyalty program calibrated by a novel proprietary dataset.","presenter":"Dr. Antoine Feylessoufi","authors":[{"name":"Dr. Antoine Feylessoufi","aff":"Assistant Professor, Vanderbilt University"},{"name":"Dr. Ersin Korpeoglu","aff":"Associate Professor, University College London"},{"name":"Ms. Mika Sumida","aff":"Assistant Professor, University of Southern California"}],"order":5}]},{"id":"s96","title":"Behavioral Insights in Technology and Service Design","track":"Behavioral Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"EMBASSY D","chairs":["Prof. Craig Froehle","Dr. Yinghao Zhang","Mr. Chia-Chun Yang"],"abstracts":[{"id":"136-0361","title":"AI-Powered Bidding in Procurement auctions","content":"As AI increasingly shapes online auctions, this study examines algorithmic overbidding in second-price procurement auctions using Deep Q-Networks. We identify mechanisms driving overbidding, develop an analytical model of algorithmic equilibrium, and propose strategies to mitigate risks. Our findings offer insights into balancing AI innovation with governance in competitive auctions.","presenter":"Dr. Jingyi Tian","authors":[{"name":"Dr. Jingyi Tian","aff":"Post Doc/Researcher, University of Houston"},{"name":"Dr. Meng Li","aff":"Professor, University of Houston"}],"order":2},{"id":"136-0528","title":"Effects of Task and Anthropomorphism on Customers' Decisions to Use AI-powered Service Agent","content":"AI-powered service agents (AISA) are increasingly common. However, customers’ experiences have been variable, with few firms fully realizing the operational benefits they expected. Using experimental methods, we study how trust and perceived performance risk influence customers’ preference for AISA and what factors can drive customers’ perceptions or trust and risk.","presenter":"Mr. Chia-Chun Yang","authors":[{"name":"Mr. Chia-Chun Yang","aff":"Student, University of Cincinnati"},{"name":"Prof. Craig Froehle","aff":"Professor, University of Cincinnati"},{"name":"Dr. Yinghao Zhang","aff":"Associate Professor, University of Cincinnati"}],"order":3},{"id":"136-0947","title":"Beyond Averages: How Do Customers Respond to Wait Time Distributions?","content":"We conduct a series of human-subjects experiments to examine whether customers also consider distributional information about the wait, beyond just the expected waiting time. Participants made choices between two time-money bundles: a short wait with a small monetary payoff and a longer, potentially stochastic wait with a larger monetary payoff.","presenter":"Dr. Kyle Hyndman","authors":[{"name":"Dr. Evgeny Kagan","aff":"Assistant Professor, Carey Business School"},{"name":"Prof. Andrew Davis","aff":"Associate Professor, Cornell University"},{"name":"Dr. Kyle Hyndman","aff":"Professor, University of Texas Dallas"}],"order":4}]},{"id":"s121","title":"Responsible and Sustainable Operations","track":"Sustainable Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"EMBASSY G","chairs":["Prof. Can Zhang"],"abstracts":[{"id":"136-0343","title":"Digitalization of government-to-person (G2P) payments: process configurations, payment misdirection and reduced uptake of social-assistance","content":"Governments in low- and middle-income countries are undertaking large-scale digitalization of social assistance payments using centralized configurations for supply-side efficiencies. Using a natural experiment on 14MN payments in India’s workfare program, we find that centralized configurations reduce work uptake due to payments credited to bank accounts not preferred by recipients.","presenter":"Mr. Rakesh Allu","authors":[{"name":"Mr. Rakesh Allu","aff":"Student, Cornell University"},{"name":"Ms. Maya Ganesh","aff":"Assistant Professor, Indian Institute of Management Bangalore"},{"name":"Prof. Sarang Deo","aff":"Professor, Indian School of Business"},{"name":"Dr. Sripad Devalkar","aff":"Associate Professor, Indian School of Business"},{"name":"Ms. Ramya Munjuluri","aff":"Student, INSEAD"}],"order":1},{"id":"136-0417","title":"Enhancing disaster response: The crucial role of Information flow and coordination in humanitarian logistics","content":"Effective disaster response relies on optimizing logistics and coordination. This study analyzes Logistics Cluster meeting minutes, a coordination mechanism, to explore the influence of diverse information flow, coordination, and leadership on collaboration and engagement, addressing key challenges and uncovering insights into effective humanitarian logistics during crises.","presenter":"Mr. Vahid Khodaee","authors":[{"name":"Mr. Vahid Khodaee","aff":"Student, Kühne logistics university"},{"name":"Prof. Andreas Gernert","aff":"Assistant Professor, Kuehne Logistics University"},{"name":"Prof. Laura Turrini","aff":"Associate Professor, European Business School"},{"name":"Prof. Lea Ruesch","aff":"Assistant Professor, IE BUSINESS SCHOOL"},{"name":"Prof. Maria Besiou","aff":"Professor, Kuehne Logistics University"}],"order":2},{"id":"136-1780","title":"Strategic Delay in Grocery Delivery Platforms","content":"This study explores strategic order delay in grocery delivery platforms, analyzing the interplay between store inventory management and platform delay strategies using a queueing model. Findings highlight conditions under which platforms should delay deliveries to optimize service and manage inventory effectively.","presenter":"Prof. Guangwen Kong","authors":[{"name":"Prof. Guangwen Kong","aff":"Associate Professor, Temple University"},{"name":"Mr. Hao Jiang","aff":"Student, Temple University"},{"name":"Prof. Yue Zhang","aff":"Assistant Professor, Penn State"}],"order":3},{"id":"136-1906","title":"Impact of energy storage on electricity prices and GHG emissions","content":"Energy storage serves as a practical solution to address the challenges arising from the high penetration of renewable energy sources in the electricity system. In this study, we analyze the role of energy storage, its impact on prices and GHG emissions, and provide insights with significant policy implications.","presenter":"Mr. Jin-Yang Hu","authors":[{"name":"Mr. Jin-Yang Hu","aff":"Student, Duke University"},{"name":"Prof. Kevin Shang","aff":"Professor, Duke University Durham"},{"name":"Prof. Can Zhang","aff":"Associate Professor, Duke University"}],"order":4}]},{"id":"s149","title":"Crowd-based Platforms, Fintech, and Firm Productivity","track":"Information Systems and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"EMBASSY E","chairs":["Dr. Yi Gao"],"abstracts":[{"id":"136-0627","title":"Adaptive Work Configurations: Leveraging Workforce Agility for Enhancing Firm Performance","content":"This study analyzes data from over 3,300 firms across 21 countries to assess how workforce agility impacts firm performance during turbulence. Firms implementing adaptable work configurations early experienced higher sales growth, while those reverting to traditional setups saw declines, highlighting the importance of timing and adaptability for resilience.","presenter":"Dr. Changran Fan","authors":[{"name":"Dr. Changran Fan","aff":"Assistant Professor, Lewis University"},{"name":"Dr. Xinyu Fu","aff":"Assistant Professor, Georgia State University"},{"name":"Prof. Narayan Ramasubbu","aff":"Associate Professor, University of Pittsburgh"}],"order":1},{"id":"136-0890","title":"Will the Fork Be with You? How Forks Drive User Contributions on Open-Source Platforms","content":"Forks allow users to copy repositories for contributions (social forks) or bookmarking (archive forks). Analyzing data from over 10,000 GitHub users, we find social forks uniquely drive new project creation and contributions to all projects, while both fork types encourage contributions to projects that received forks.","presenter":"Mr. Jiarui Yan","authors":[{"name":"Mr. Jiarui Yan","aff":"Student, University of Washington"},{"name":"Ms. Xue Tan","aff":"Assistant Professor, Cox School of Business"},{"name":"Dr. Yong Tan","aff":"Professor, University of Washington"}],"order":2},{"id":"136-1795","title":"All Rights Reserved? An Economic Analysis of Copyright Policy on AI-Generated Content","content":"As AI-generated content (AIGC) grows, copyrightability becomes critical. Traditional laws deny copyright due to lack of human authorship, but new policies consider substantial human input. An analytical model reveals a tradeoff: stronger copyright encourages human effort but may reduce AI quality, misaligning content quality and social welfare goals.","presenter":"Dr. Yi Gao","authors":[{"name":"Dr. Yi Gao","aff":"Assistant Professor, Texas Tech University"},{"name":"Dr. Zhe Wang","aff":"Assistant Professor, City University of Hong Kong"},{"name":"Dr. Juan Feng","aff":"Professor, Tsinghua University"}],"order":3},{"id":"136-1797","title":"Impact of Market Influencer Trades: Evidence from NFT Market","content":"Influential market participants can significantly shape market trends. This study explores how the purchases by market influencers, including whales and celebrities, affect the Non-Fungible Token (NFT) market. Our findings have profound implications for the cryptocurrency market, highlighting the need for participants to assess the impacts of influencer purchases.","presenter":"Ms. Kaiyu Zhang","authors":[{"name":"Ms. Kaiyu Zhang","aff":"Student, University of Florida"},{"name":"Mr. Qili Wang","aff":"Student, University of Florida"},{"name":"Prof. Runyu Chen","aff":"Associate Professor, University of International Business and Economicsonal"},{"name":"Prof. Liangfei Qiu","aff":"Professor, University of Florida"}],"order":4}]},{"id":"s156","title":"Generative Artificial Intelligence for Healthcare","track":"Healthcare Analytics","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"GRAND HALL EAST D","chairs":["Dr. Xunyu Chen"],"abstracts":[{"id":"136-1663","title":"Racing with Generative AI: Impact of Conversational Agents on Mental Health Counselors","content":"This study investigates the impact of Generative AI (GenAI) on mental health counselors. Post-GenAI launch data reveal enhanced counselor performance and patient engagement, showcasing a competitive response. Counselors offered more informational but less emotional support, highlighting shifts in strategies amid AI integration in mental health care.","presenter":"Dr. Seokjun Youn","authors":[{"name":"Dr. Chenxi Guo","aff":"Student, Beijing Institute of Technology"},{"name":"Dr. Xunyu Chen","aff":"Assistant Professor, Virginia Commonwealth University"},{"name":"Dr. Seokjun Youn","aff":"Assistant Professor, University of Arizona"},{"name":"Dr. Karen Xie","aff":"Associate Professor, University of Connecticut"},{"name":"Dr. Wei Chen","aff":"Associate Professor, University of Connecticut"}],"order":1},{"id":"136-1756","title":"Unraveling Generative Artificial Intelligence for Effective Mental Support","content":"The rise of generative AI (GenAI) offers a cost-effective way to deliver high-quality mental support. Using data from an online mental health community impacted by covert GenAI use, we analyze GenAI’s support effectiveness compared to human support and explore the factors driving these differences.","presenter":"Dr. Xunyu Chen","authors":[{"name":"Dr. Xunyu Chen","aff":"Assistant Professor, Virginia Commonwealth University"},{"name":"Ms. Lingyu Li","aff":"Student, Virginia Commonwealth University"},{"name":"Dr. Xiaojin Liu","aff":"Associate Professor, Virginia Commonwealth University"},{"name":"Dr. Victoria Yoon","aff":"Professor, Virginia Commonwealth University"}],"order":2},{"id":"136-1830","title":"Beyond Words: Unveiling the Effect of Physician’s Use of Audio Communication in Online Healthcare Communities","content":"Recently, many online healthcare communities (OHCs) have added multimodal communication channels (e.g., text, audio) to facilitate physician-patient interaction. This quasi-natural experiment examines how the doctor's use of audio communication, in addition to text messages, affects patient emotional/informational support and doctor social/economic returns.","presenter":"Dr. Xunyu Chen","authors":[{"name":"Dr. Xunyu Chen","aff":"Assistant Professor, Virginia Commonwealth University"},{"name":"Dr. Seokjun Youn","aff":"Assistant Professor, University of Arizona"},{"name":"Prof. Yeongin Kim","aff":"Assistant Professor, Wake Forest University"}],"order":3},{"id":"136-2062","title":"Empowering Mental Health Support: A Theory-Driven and RAG-Enhanced Multi-Agent Large Language Model Design","content":"Mental health support can benefit significantly from scalable and responsive technologies like Large Language Models (LLMs). However, their potential remains underexplored. This work proposes a multi-agent design using optimal matching theory and Retrieval Augmented Generation (RAG) to boost LLM performance. Preliminary results indicate the effectiveness of this approach.","presenter":"Dr. Xunyu Chen","authors":[{"name":"Dr. Yolanda Li","aff":"Assistant Professor, Kennesaw State University"},{"name":"Dr. Xunyu Chen","aff":"Assistant Professor, Virginia Commonwealth University"},{"name":"Dr. Mateusz Dolata","aff":"Professor, University of Zurich"}],"order":4}]},{"id":"s166","title":"Corporate Social Responsibility and AI-Driven Decision-Making in Supplier Management","track":"Procurement and Supplier Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"MARIETTA","chairs":["Dr. Anne Dohmen"],"abstracts":[{"id":"136-0208","title":"Supplier-Initiated and Buyer-Imposed Social Responsibility Codes of Conduct","content":"We study how a voluntary social responsibility code of conduct for the supplier affects the buyer's decision to impose its own code on a supplier. We show the buyer may impose its code on a supplier that has adopted the voluntary code but not on a supplier without any code.","presenter":"Dr. Han Zhang","authors":[{"name":"Dr. Han Zhang","aff":"Assistant Professor, Michigan State University"},{"name":"Dr. Fei Gao","aff":"Associate Professor, Indiana University Bloomington"},{"name":"Dr. Mevan Jayasinghe","aff":"Associate Professor, Michigan State University"},{"name":"Prof. Sriram Narayanan","aff":"Professor, Michigan State University"}],"order":1},{"id":"136-0611","title":"The Effect of AI Demand Planning System Attributes on Demand Planner Behavior and Performance","content":"Our research investigates how different attributes of an AI demand planning system impact human performance in demand planning tasks. We consider AI smartness, explainability, and anthropomorphism, and how these attributes impact private information processing. Our findings report the effects of these AI attributes on demand planner behavior and performance.","presenter":"Mr. Finnegan McKinley","authors":[{"name":"Mr. Finnegan McKinley","aff":"Student, University of Arkansas"},{"name":"Prof. John Aloysius","aff":"Professor, University of Arkansas"},{"name":"Dr. Rebekah Brau","aff":"Assistant Professor, Brigham Young University"}],"order":2},{"id":"136-0530","title":"Strategic Volume Allocation in Health Product Procurement: Shaping Innovation and Welfare","content":"Managing pooled procurement of health products is critical to improving healthcare outcomes in most countries. This research examines the structure of allocation policies that help health product pooled procurement managers align suppliers’ innovation investments for the benefit of member countries.","presenter":"Prof. Scott Webster","authors":[{"name":"Prof. Yimin Wang","aff":"Associate Professor, Arizona State University"},{"name":"Prof. Scott Webster","aff":"Professor, Arizona State University Tempe"}],"order":3},{"id":"136-1349","title":"Insurance or Liability? The Effects of CSR on Stakeholder Reactions to CSIR","content":"The study proposes a model that explains the conditions under which corporate social responsibility (CSR) acts as insurance or liability subsequent to corporate social irresponsibility (CSIR), depending on the type of CSR reputation and the severity of CSIR. It draws on results from a vignette experiment with supply chain managers.","presenter":"Ms. Ruth Schueltken","authors":[{"name":"Mr. Maximilian Merath","aff":"Student, University of Mannheim"},{"name":"Ms. Ruth Schueltken","aff":"Post Doc/Researcher, University of Mannheim"},{"name":"Prof. Christoph Bode","aff":"Professor, University of Mannheim"}],"order":4}]},{"id":"s182","title":"Operations in Food and Last-Mile Deliveries","track":"Agriculture and Food Supply Chains","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"VININGS","chairs":["Dr. Wenchang Zhang"],"abstracts":[{"id":"136-0889","title":"Omnichannel Operations in On-Demand Delivery Platform with Buy-Online-and-Pick-up-in-Store","content":"On-demand delivery platforms now provide consumers with the option to buy online and pick up in-store(BOPS). We examine such an omnichannel on-demand economy, where consumers decide how their orders are delivered: by independent couriers or by themselves. We study the impact of BOPS on platform pricing strategies and welfare metrics.","presenter":"Mr. Yu Guo","authors":[{"name":"Mr. Yu Guo","aff":"Student, University of Science and Technology of China"},{"name":"Dr. Fei Gao","aff":"Associate Professor, Indiana University Bloomington"},{"name":"Dr. Wenchang Zhang","aff":"Assistant Professor, Kelley School of Business"},{"name":"Dr. Liu Ming","aff":"Assistant Professor, Chinese Univ of Hong Kong (Shenzhen)"}],"order":1},{"id":"136-1972","title":"Balancing Complexity and Competitiveness in FMCG Food Supply Chains","content":"In the FMCG food supply chain, product diversity enhances competitiveness but complicates inventory control. This study introduces a novel metric to quantify this trade-off, offering insights into balancing diversity and efficiency. The findings propose strategies to optimize supply chain performance by addressing the challenges posed by diverse product offerings.","presenter":"Dr. Yue Zhao","authors":[{"name":"Dr. Yue Zhao","aff":"Post Doc/Researcher, University of Toronto"},{"name":"Prof. Stanley Lim","aff":"Assistant Professor, Michigan State University"}],"order":3},{"id":"136-2041","title":"Distance-Based Fee Design of Rapid Delivery","content":"We examine the evolving landscape of the rapid delivery service industry, focusing on the strategic variations in pricing structures and service offerings. Utilizing a stylized queueing model, we analyze the effects of a distance-based delivery price on various stakeholders across various customer-density environments.","presenter":"Dr. Mingliu Chen","authors":[{"name":"Dr. Manlu Chen","aff":"Assistant Professor, Renmin University of China"},{"name":"Dr. Mingliu Chen","aff":"Assistant Professor, University of Texas Dallas"},{"name":"Prof. Ming Hu","aff":"Professor, University of Toronto"},{"name":"Dr. Jianfu Wang","aff":"Associate Professor, City University of Hong Kong"}],"order":5},{"id":"136-1647","title":"Restaurant Density and Delivery Speed in Food Delivery Platforms","content":"This paper studies the operational effects of increasing restaurant density on food delivery platforms. Using theoretical modeling and data from a Chinese platform, we show delivery pooling dominates customer expansion and cannibalization, enhancing delivery speed, sales, but reducing order sizes. Results highlight the importance of optimizing density for platform growth.","presenter":"Dr. Wenchang Zhang","authors":[{"name":"Dr. Wenchang Zhang","aff":"Assistant Professor, Kelley School of Business"},{"name":"Mr. Zhanzhi Zheng","aff":"Student, UNC Kenan-Flagler Business School"},{"name":"Prof. Ruomeng Cui","aff":"Professor, Emory University"}],"order":6}]},{"id":"s186","title":"Empirical Retail Operations-1","track":"Retail Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"FAIRLIE","chairs":["Prof. Santiago Gallino","Mr. Borja Apaolaza"],"abstracts":[{"id":"136-0293","title":"Order timing under cash constraints: digital orders in the nanostore setting","content":"The suppliers of millions of nanostores are implementing digital ordering tools. We explore how extended ordering windows, that are enabled by these tools, influence shopkeepers' ordering behavior in the nanostore retail setting. We integrate an empirical analysis based on observational data from a real nanostore supply chain with behavioral experiments.","presenter":"Dr. Rafael Escamilla","authors":[{"name":"Ms. Simone Balvers","aff":"Student, Tilburg University"},{"name":"Dr. Rafael Escamilla","aff":"Assistant Professor, Arizona State University"},{"name":"Dr. Sebastian Villa","aff":"Assistant Professor, University of Colorado Boulder"}],"order":1},{"id":"136-0296","title":"Algorithmic Assortment Curation: An Empirical Study of Buybox in Online Marketplaces","content":"We assess the Buybox’s influence on marketplace dynamics by examining its staggered introduction within a major product category in a leading online marketplace. Our results show that the Buybox’s implementation increases the number of orders and enhances the efficiency of the customer journey.","presenter":"Prof. Nil Karacaoglu","authors":[{"name":"Prof. Santiago Gallino","aff":"Associate Professor, The Wharton School"},{"name":"Prof. Nil Karacaoglu","aff":"Assistant Professor, The Ohio State University"},{"name":"Prof. Antonio Moreno","aff":"Associate Professor, Harvard University"}],"order":2},{"id":"136-0399","title":"Be the Buyer - Leveraging the Wisdom of the Crowd in E-Commerce Assortment Planning","content":"We study the business practice where a retailer seeks input from customers on the desirability of a product and bases their assortment planning decisions on these votes. We collaborate with an apparel rental platform and find that the service improves business performance. We investigate potential mechanisms that drive this improvement.","presenter":"Prof. Leela Nageswaran","authors":[{"name":"Prof. Leela Nageswaran","aff":"Assistant Professor, University of Washington"},{"name":"Prof. Yu Kan","aff":"Assistant Professor, Indiana University"},{"name":"Prof. Uttara Ananthakrishnan","aff":"Assistant Professor, Carnegie Mellon University"}],"order":3},{"id":"136-0486","title":"Rented Today, Bought Tomorrow: Buyout Pricing in Circular Economy Fashion Retail","content":"Consumer preferences are driving a shift to circular economy practices in fashion. Collaborating with a fashion rental subscription service, we develop a data-driven buyout pricing framework that optimizes revenues by balancing rental and sales income while accounting for garment lifespan, popularity, and customer demand dynamics.","presenter":"Mr. Borja Apaolaza","authors":[{"name":"Mr. Borja Apaolaza","aff":"Student, The Wharton School, University of Pennsylvania"},{"name":"Prof. Gerard Cachon","aff":"Professor, The Wharton School"},{"name":"Prof. Santiago Gallino","aff":"Associate Professor, The Wharton School"},{"name":"Prof. Antonio Moreno","aff":"Associate Professor, Harvard University"}],"order":4}]},{"id":"s198","title":"College of Service Operations Paper Competition II","track":"Service Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"EMBASSY C","chairs":["Prof. Benjamin Lawrence"],"abstracts":[{"id":"136-2110","title":"Service Best Paper Presentation: Assortment Optimization with Replacement Options for Retail Platforms with Stockout Risk","content":"Online platforms often prompt customers to select a preferred and replacement option due to stockouts. In this study, we examine assortment optimization under this choice model, proving NP-hardness. We develop efficient approximation schemes and, using Instacart data, show that adaptive strategies for replacement options significantly boost revenue.","presenter":"Mr. Yuheng Wang","authors":[{"name":"Mr. Yuheng Wang","aff":"Student, Cornell University"},{"name":"Prof. Dmitry Mitrofanov","aff":"Assistant Professor, Boston College"},{"name":"Prof. Huseyin Topaloglu","aff":"Professor, Cornell University"}],"order":1},{"id":"136-2094","title":"Service Best Paper Presentation: The Value of Last-Mile Delivery in Online Retail","content":"This study the value of last-mile delivery via a quasi-experiment with Alibaba. Using staggered DiD, we found home delivery significantly increased customer spending. To optimally utilize delivery capacity, we leverage causal AI to target the most valuable customers under capacity and fairness constraints, maximizing business profits without compromising social equity.","presenter":"Mr. Zhikun Lu","authors":[{"name":"Mr. Zhikun Lu","aff":"Student, Emory University"},{"name":"Prof. Ruomeng Cui","aff":"Professor, Emory University"}],"order":4},{"id":"136-2112","title":"Service: Revitalizing the In-Store Experience: An Empirical Study on the Spillover Effects of Experiential Services","content":"Retailers are adopting experiential services to increase foot traffic to stores. However, it remains unclear whether introducing such a service leads to positive spillover effects on the main-store service, rather than cannibalizing existing sales. This paper provides the first empirical documentation of the spillover effects and mechanisms behind the observed","presenter":"Prof. Stanley Lim","authors":[{"name":"Dr. Bengu Ozdemir","aff":"Assistant Professor, University of Wisconsin-Whitewater"},{"name":"Prof. Stanley Lim","aff":"Assistant Professor, Michigan State University"}],"order":5}]},{"id":"s200","title":"Issues in Supply Chain Risk Management","track":"Supply Chain Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"EMBASSY A","chairs":["Dr. Manoj Malhotra"],"abstracts":[{"id":"136-1928","title":"Disruption Management in Distribution Networks","content":"We investigate the impact of macro-level disruptions on distribution network efficiency. The paper assesses the effects of disruption events, providing a realistic depiction of how these impacts propagate throughout the network. We assess the efficacy of alternative risk mitigation strategies in appeasing the impact of such disruptions.","presenter":"Prof. Srinivas Talluri","authors":[{"name":"Dr. Maggie Dong","aff":"Professor, University of New South Wales"},{"name":"Dr. SunAh Kim","aff":"Associate Professor, University of New South Wales"},{"name":"Prof. Srinivas Talluri","aff":"Professor, Michigan State University"},{"name":"Dr. Chandrasekhar Manchiraju","aff":"Assistant Professor, Michigan State University"},{"name":"Dr. Ching-Fu Chen","aff":"Professor, National Cheng Kung University Taiwan"}],"order":1},{"id":"136-0840","title":"The Impact of Supply Shocks on Firm Performance: Role of Operational Efficiency","content":"We explore the impacts of supply shocks on firm performance in the US manufacturing sector. Employing a difference-in-differences approach, we find that firms with greater operational efficiency prior to the shock perform better in the aftermath. Our results underscore the benefit of operational efficiency in responding to supply shocks.","presenter":"Mr. Jihyun Park","authors":[{"name":"Mr. Jihyun Park","aff":"Student, Yonsei University"},{"name":"Prof. Seung Jae Park","aff":"Associate Professor, Yonsei University"}],"order":2},{"id":"136-1927","title":"Efficiency of Strategy Portfolios in the Face of Complex Supply Chain Disruptions","content":"This study investigates whether complex supply chain disruptions necessitate more complex risk management strategies. To answer this, we built an empirically grounded discrete event simulation model and tested the efficiency of multi-strategy portfolios in managing complex disruptions induced by COVID-19 pandemic.","presenter":"Dr. Hakan Yildiz","authors":[{"name":"Dr. Hakan Yildiz","aff":"Associate Professor, Wayne State University"},{"name":"Dr. Tingting Yan","aff":"Professor, Texas Tech University"},{"name":"Dr. Marc Hatton","aff":"Assistant Professor, Georgia Southern University"},{"name":"Dr. John Fowler","aff":"Professor, Arizona State University Tempe"},{"name":"Prof. Thomas Kull","aff":"Associate Professor, Arizona State University Tempe"}],"order":3}]},{"id":"s205","title":"Emerging Topics in Retail Operations-1","track":"Retail Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"BAKER","chairs":["Dr. Xiajun Pan","Ms. Yi Tong"],"abstracts":[{"id":"136-0609","title":"Consumer Waste of Fresh and Processed Food","content":"Customers may purchase fresh and processed versions of a food, with the processed food serving as a backup when the customer cannot go shopping. We show that this behavior can cause food waste, and a longer preservation period of the processed food can worse the food waste.","presenter":"Prof. Bin Hu","authors":[{"name":"Prof. Bin Hu","aff":"Professor, Naveen Jindal School of Management"}],"order":1},{"id":"136-1053","title":"Shrinkflation or Price Increase: The Role of Fairness","content":"Considering consumers with limited attention, this study compares the firm’s two distinct strategic responses to inflation: Price Increase vs. Product Downsizing. Additionally, we explore the influence of consumers' fairness concerns on the firm's decisions.","presenter":"Ms. Yi Tong","authors":[{"name":"Ms. Yi Tong","aff":"Student, University of Florida"},{"name":"Dr. Xiajun Pan","aff":"Associate Professor, University of Florida"},{"name":"Prof. Hongseok Jang","aff":"Assistant Professor, Tulane University"}],"order":2},{"id":"136-1206","title":"Bottle Bill: Return, Refund, and Recycle","content":"We study the pricing and environmental implications of the \"bottle\" bill which requires that consumers be charged a monetary deposit on beverage containers at the point of sale and they can claim a refund of the deposit upon returning the containers (to redemption centers or retailers) for recycling.","presenter":"Dr. Shiliang Cui","authors":[{"name":"Dr. Shiliang Cui","aff":"Professor, McDonough School of Business"},{"name":"Prof. Luyi Yang","aff":"Assistant Professor, University of California Berkeley"},{"name":"Dr. Sai Zhao","aff":"Post Doc/Researcher, University of Chinese Academy of Sciences"}],"order":3},{"id":"136-1525","title":"A Novel Return Policy: Negotiating Refunds Without Returns","content":"This work is motivated by our interaction with an online retailer selling customized dresses. A novel practice we observe is the retailer's handling consumers' return requests through negotiations on refunds without returns (NROR). We show that NROR has the potential to bring win-win-win outcomes to retailers, consumers, and the environment.","presenter":"Prof. Tingliang Huang","authors":[{"name":"Ms. Ziqin Gao","aff":"Student, University of Science and Technology of China"},{"name":"Mr. Ganquan Huang","aff":"Post Doc/Researcher, University of Science and Technology of China"},{"name":"Prof. Tingliang Huang","aff":"Professor, The University of Tennessee-Knoxville"},{"name":"Prof. Yan Liu","aff":"Professor, University of Science and Technology of China"},{"name":"Prof. Yugang Yu","aff":"Professor, University of Science and Technology of China"}],"order":4}]},{"id":"s236","title":"Digital Platforms and Innovations - A Mechanism Design Approach","track":"Digital Platforms, Innovations and Transformations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"GREENBRIAR","chairs":["Arun Kumar Rout"],"abstracts":[{"id":"136-0165","title":"Combating Overbilling in Outsourced Projects: A Dynamic Auditing Mechanism","content":"The practice of overbilling, where an external agent charges a firm more than what is deemed reasonable for the outsourced service, has been well-acknowledged as a notorious and long-standing problem across major industries. We consider a repeated-interaction principal-agent setting and develop a non-monetary dynamic auditing mechanism to mitigate overbilling.","presenter":"Mr. Like Bu","authors":[{"name":"Mr. Like Bu","aff":"Student, The University of Texas at Dallas"},{"name":"Prof. Shivam Gupta","aff":"Associate Professor, University of Nebraska Lincoln"},{"name":"Prof. Ganesh Janakiraman","aff":"Professor, The University of Texas at Dallas"},{"name":"Prof. Milind Dawande","aff":"Professor, The University of Texas at Dallas"}],"order":1},{"id":"136-0760","title":"Pay With Your Data: Optimal Data-Sharing Mechanisms for AI Services","content":"In this paper, we examine how firms offering AI services can effectively acquire large volumes of training data from their consumers to improve the accuracy of the machine learning (ML) models that drive these services.,","presenter":"Dr. Chandrasekhar Manchiraju","authors":[{"name":"Mr. Sameer Mehta","aff":"Assistant Professor, Erasmus University"},{"name":"Dr. Chandrasekhar Manchiraju","aff":"Assistant Professor, Michigan State University"},{"name":"Prof. Milind Dawande","aff":"Professor, The University of Texas at Dallas"},{"name":"Prof. Ganesh Janakiraman","aff":"Professor, The University of Texas at Dallas"}],"order":2},{"id":"136-1150","title":"Designing Income Sharing Loans in Education Sector: A Non-profit Organization Perspective","content":"In this study, we address the increasing concern over rising student debt in the U.S. and inspired by the implementation of Income-Sharing Loans (ISLs) at Stanford Law School through the non-profit Flywheel Fund, we explore the optimal design of ISLs to address this financial challenge from a student welfare-perspective.","presenter":"Dr. Goutham Takasi","authors":[{"name":"Dr. Goutham Takasi","aff":"Assistant Professor, University of Alabama Tuscaloosa"}],"order":3}]},{"id":"s253","title":"Empirical Insights into Supply Chain Dynamics: Efficiency, Labor Violations, and Data-Driven Analysis","track":"Supply Chain Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"GRAND HALL EAST A","chairs":["Prof. Guanyi Lu"],"abstracts":[{"id":"136-0133","title":"The Downside, Upside, or Curvilinear Side of Idle time? Evidence from A Retail Chain","content":"We examine the impact of idle time on cashier productivity in a retail chain.","presenter":"Prof. Guanyi Lu","authors":[{"name":"Dr. Xingzhi Jia","aff":"Assistant Professor, Renmin University of China"},{"name":"Prof. Guanyi Lu","aff":"Associate Professor, Florida State University"},{"name":"Prof. Gang Wang","aff":"Professor, florida state university"}],"order":1},{"id":"136-0240","title":"Supply Chain Data and Analysis","content":"This study investigates and compares the four commonly used supply chain databases and introduces a data-focused roadmap for supply chain research using secondary data sources. The study presents a process from data source selection, and unit of analysis decision, to the treatments of common econometric issues.","presenter":"Prof. Kefeng Xu","authors":[{"name":"Prof. Yan Dong","aff":"Professor, University of South Carolina"},{"name":"Dr. Fan Zou","aff":"Assistant Professor, The Pennsylvania State University"},{"name":"Dr. Yuqi Peng","aff":"Assistant Professor, Salisbury University"},{"name":"Dr. Sining Song","aff":"Assistant Professor, University of Maryland, College Park"},{"name":"Prof. Kefeng Xu","aff":"Professor, University of North Carolina at Greensbo"}],"order":2},{"id":"136-1387","title":"Supply Chain Disruptions and Labor Violations: An Empirical Investigation","content":"We aim to determine if major supply chain disruptions contribute to increased labor violations and examine how the impact (if any) varies across industries as well as overtime. By leveraging COVID as an exogenous shock and performing staggered DID analyses, our study aims to provide implications for companies and regulators.","presenter":"Dr. Li Ding","authors":[{"name":"Dr. Li Ding","aff":"Assistant Professor, Nanyang Technological University"},{"name":"Prof. Basak Kalkanci","aff":"Associate Professor, Georgia Institute of Technology"}],"order":3}]},{"id":"s268","title":"Frontiers of Applied Game Theory at POM-Marketing Interface","track":"POM-Marketing Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"DUNWOODY","chairs":["Prof. Shubhranshu Singh","Prof. Weining Bao"],"abstracts":[{"id":"136-0518","title":"Balancing Act: Content Moderation, Toxicity, and User Engagement Dynamics","content":"This paper investigates how content moderation policies affect toxic content creation and positive user engagement on social media. Findings reveal moderation can have mixed effects—reducing positive engagement when most users are toxic and exhibiting a U-shaped pattern when most users are non-toxic.","presenter":"Prof. Ying Bao","authors":[{"name":"Prof. Ying Bao","aff":"Assistant Professor, University of Illinois at Urbana Champaign"},{"name":"Ms. Jessie Liu","aff":"Assistant Professor, Johns Hopkins University"}],"order":1},{"id":"136-0516","title":"Investment Incentives and Design Strategies for Autonomous Vehicles","content":"Automotive manufacturers are integrating various levels of automation in a vehicle. We explore the optimal vehicle design and manufacturer’s incentives to invest in automation and its reliability. Applying game theoretic modelling, we find that integrating automation is profitable and it enhances safety than vehicles without automation when driving is inconvenient.","presenter":"Mr. Tridib Guha","authors":[{"name":"Mr. Tridib Guha","aff":"Student, IIM Udaipur"},{"name":"Prof. Shubhranshu Singh","aff":"Associate Professor, Johns Hopkins University"}],"order":2},{"id":"136-0512","title":"Infrastructure Investment and Product Development in a Mixed Oligopoly","content":"In consumption contexts where designing new products is fairly resource intensive, public agencies often make substantial infrastructure investments that improve social welfare. In these markets, private firms leverage these investments to design products that generate profits. In this paper, we study public-private interaction and its implications in such a market.","presenter":"Prof. Shubhranshu Singh","authors":[{"name":"Prof. Yogesh Joshi","aff":"Professor, University of Maryland - College Park"},{"name":"Prof. Shubhranshu Singh","aff":"Associate Professor, Johns Hopkins University"}],"order":3},{"id":"136-0953","title":"Information Interdependence and Competitive Data Protection Investment","content":"This paper examines a firm's incentives to invest in data protection to mitigate the risk of compromising consumer privacy, in the context of duopoly competition and behavior-based pricing. Strong intra-firm information interdependence can motivate greater investment in privacy protection, while strong inter-firm information interdependence may deter such efforts.","presenter":"Prof. Weining Bao","authors":[{"name":"Prof. Weining Bao","aff":"Assistant Professor, University of Connecticut"},{"name":"Prof. Yuxin Chen","aff":"Professor, New York University"},{"name":"Prof. Ping Xiao","aff":"Professor, Melbourne Business School"}],"order":4}]},{"id":"s274","title":"Technological Advancements in Logistics and Transportation Management","track":"Aviation, Transportation, and Logistics Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"UNIVERSITY","chairs":["Dr. Varun Gupta"],"abstracts":[{"id":"136-0267","title":"Analysis of a Plug-in Hybrid Electric Airplane","content":"A new 19-passenger regional airliner powered by 8 electric engines is being developed by Auro Aero. A regional airline has proposed using the plane to serve routes in south Florida. The session explores the feasibility of the idea and describes an exercise suitable for use in the classroom.","presenter":"Prof. F. Robert Jacobs","authors":[{"name":"Prof. F. Robert Jacobs","aff":"Emeritus Professor, Indiana University Bloomington"}],"order":1},{"id":"136-1994","title":"An Empirical Study on Unattended Delivery in Japan","content":"This paper presents the research framework and hypotheses on the factors encouraging and discouraging unattended delivery by individual recipients in Japan, based on the merits and demerits for them. The impact of alternative delivery options on the acceptance of unattended delivery is considered also.","presenter":"Prof. Yoshiki MATSUI","authors":[{"name":"Prof. Yoshiki MATSUI","aff":"Professor, The Open University of Japan"}],"order":2},{"id":"136-1882","title":"Public-Private Partnerships to Mitigate Cybersecurity Threats to Logistics Activities","content":"This case-based study explores cybersecurity threats facing logistics companies, emphasizing public-private partnerships (PPPs) for mitigation. Using surveys and case studies, it identifies prevalent threats, evaluates preparedness, and assesses the impact on logistics operations. Findings inform PPP-driven strategies for enhanced cybersecurity, fostering resilience and safeguarding economic and logistical infrastructure.","presenter":"Dr. Varun Gupta","authors":[{"name":"Dr. Varun Gupta","aff":"Associate Professor, University of North Georgia"},{"name":"Dr. Lu Xu","aff":"Assistant Professor, University of North Georgia"},{"name":"Dr. Zuoming Liu","aff":"Associate Professor, University of North Georgia"},{"name":"Dr. Mohan Menon","aff":"Professor, University of North Georgia"},{"name":"Dr. Tamirat Abegaz","aff":"Associate Professor, University of North Georgia"}],"order":3}]},{"id":"s283","title":"AI, Consumer Behavior, and Strategic Decision-Making in Digital Markets","track":"Disruptive Technologies and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"KENNESAW","chairs":["Mr. Mingrui Zhang"],"abstracts":[{"id":"136-1152","title":"Search between the Lines: Field Experiment, Structural Estimation, and LLM-based Optimization","content":"This paper explores how horizontal recommendation rankings influence consumer decisions during a two-stage search process. Using data from an online reading platform, it examines the effects of item positioning and text features on consumer search costs and utility. A sequential search model highlights insights into text-based decision-making.","presenter":"Ms. JIN LIU","authors":[{"name":"Mr. Xingchen Xu","aff":"Student, University of Washington"},{"name":"Ms. JIN LIU","aff":"Student, University of Science and Technology of China"}],"order":1},{"id":"136-1181","title":"Advertising, Brand Licensing, or Both? Marketing Strategies in a Duopoly","content":"Brand licensing and advertising are widely used strategies to boost brand awareness. Unlike advertising, favorable market responses from licensing enhance brand, while negative feedback dilutes it. We build a game-theoretic model to explore optimal utilization of advertising and brand licensing in monopoly and duopoly markets.","presenter":"Prof. Hongyan Xu","authors":[{"name":"Prof. Hongyan Xu","aff":"Professor, Chongqing University"},{"name":"Dr. Xiaowei Liu","aff":"Student, Chongqing University"},{"name":"Dr. Yu Zhou","aff":"Professor, Chongqing University"},{"name":"Prof. Sammi Tang","aff":"Associate Professor, University of Miami"},{"name":"Dr. Yongjian Li","aff":"Professor, Nankai University"}],"order":2},{"id":"136-1327","title":"Policy Learning with Unmeasured Confounding","content":"This paper investigates the optimal assignment of treatments from observational data when the unconfoundedness assumption fails. In the presence of unmeasured confounders, the welfare function cannot be point-identified. We employ the marginal sensitivity model to derive partial identification sets and construct efficient orthogonal moments to evaluate the worst-case scenarios.","presenter":"Ms. Xi Zheng","authors":[{"name":"Ms. Xi Zheng","aff":"Student, University of Washington"},{"name":"Mr. Gaoqian Xu","aff":"Student, University of Washington"},{"name":"Prof. Zequn Jin","aff":"Lecturer, SUFE"}],"order":3},{"id":"136-1779","title":"AI on the Line: Privacy Implications of LLMs in Telemarketing","content":"This study analyzes nearly 3 million interaction records from a leading Chinese financial platform to examine how LLM-powered telemarketing robots, compared to traditional IVR and human agents, influence consumer privacy concerns, and how the use of sensitive borrower data during model training may intensify these concerns.","presenter":"Mr. wenkang qiu","authors":[{"name":"Mr. wenkang qiu","aff":"Student, Chongqing University"}],"order":4}]},{"id":"s299","title":"Emerging Topics in Economics of Information Systems","track":"Information Systems and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"SPRING","chairs":["Dr. Leila Hosseini"],"abstracts":[{"id":"136-0671","title":"Win-Curves: A Micro-foundation","content":"Real-time bidding (RTB) has become an important avenue for selling digital ad space. A win-curve in this context defines the bid required to achieve a desired win probability. Our work presents a formal framework that rigorously explains how win-curves emerge in RTB, providing key insights into their formation and behavior.","presenter":"Dr. Shailender Joseph","authors":[{"name":"Dr. Shailender Joseph","aff":"Student, The University of Texas at Dallas"},{"name":"Prof. Ganesh Janakiraman","aff":"Professor, The University of Texas at Dallas"},{"name":"Prof. Milind Dawande","aff":"Professor, The University of Texas at Dallas"},{"name":"Prof. Vijay Mookerjee","aff":"Professor, The University of Texas at Dallas"}],"order":1},{"id":"136-0835","title":"The Informational Value of AI-generated Review Summary for Hotels","content":"With the rise of AI in online platforms, AI-generated review summaries distill extensive user reviews into concise insights, influencing user perceptions of hotels. This study examines the informational value of these summaries compared to traditional reviews, offering insights for platforms to optimize review presentations for better user engagement and decision-making.","presenter":"Ms. Luoying Chen","authors":[{"name":"Ms. Luoying Chen","aff":"Student, University of Texas at Dallas"},{"name":"Prof. Amit Mehra","aff":"Professor, University of Texas Dallas"},{"name":"Prof. Siddhartha Sharma","aff":"Assistant Professor, Indiana University Bloomington"}],"order":2},{"id":"136-0907","title":"Designing Personalized Employee Incentive Plans Using Causal Machine Learning and Analytics","content":"We design a novel, data-driven system using causal machine learning and analytics to optimize employee incentives in dynamic service environments. Partnering with a global company, our system personalizes bonuses for customer support agents by leveraging contextual information, achieving a 4.77% customer satisfaction increase ($4.66M yearly savings) compared to homogeneous treatments.","presenter":"Mr. Yiheng An","authors":[{"name":"Mr. Yiheng An","aff":"Student, Wake Forest University"},{"name":"Prof. Jia Li","aff":"Associate Professor, Wake Forest University"},{"name":"Dr. Jeffrey Camm","aff":"Professor, Wake Forest University"}],"order":4},{"id":"136-1728","title":"User Opinion Mining for Effective Product Recommendations","content":"Traditional recommendation systems focus on co-purchases but ignore user heterogeneity in preferences. With growing products, diminishing feature differences and increasing returns, it’s critical to develop a recommendation system that incorporates users’ opinions about product features. In this paper, we explore a review-based recommendation system that considers co-reviews and product features.","presenter":"Ms. Abiha Anjum","authors":[{"name":"Prof. Rajiv Garg","aff":"Associate Professor, Emory University"},{"name":"Ms. Abiha Anjum","aff":"Student, Emory University"}],"order":5},{"id":"136-1948","title":"Software Licensing and Learning Support Strategies When Customers Face Learning Curve Uncertainty","content":"In a Bayesian dynamic model, we study software vendor strategies given: 1) Customers learn to use the software according to a learning curve. 2) The learning curve’s shape is unknown to customers before adoption but can be learned through experience. We show that learning curve uncertainty significantly affects vendor strategies.","presenter":"Dr. Mingdi Xin","authors":[{"name":"Dr. Mingdi Xin","aff":"Associate Professor, University of California Irvine"}],"order":6}]},{"id":"s328","title":"Surgical and Emergency Care And Data-Driven Operations","track":"Healthcare Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"PIEDMONT","chairs":["Dr. Sandeep Rath"],"abstracts":[{"id":"136-2040","title":"Heterogeneous Patient Response to Uniform Increase in Emergency Department Attendance Fee: A Territory-Wide Study","content":"A uniform 80% ED attendance fee increase in Hong Kong reduced overall visits by 8.9%, mainly among less urgent cases, while preserving access for critical patients. Using a difference-in-differences approach on 12 million visits (2014–2019), the study highlights financial policies as effective tools to alleviate ED overcrowding without harming patients.","presenter":"Dr. Eric Park","authors":[{"name":"Prof. Hyun Seok (Huck) Lee","aff":"Associate Professor, KUBS(Korea University Business School)"},{"name":"Dr. Eric Park","aff":"Assistant Professor, Wake Forest University"},{"name":"Prof. Timothy Rainer","aff":"Professor, The University of Hong Kong"}],"order":1},{"id":"136-1296","title":"The Effects of Physician Focus and Manufacturer Variation on Surgical Supply Waste","content":"Understanding how physicians’ procedure focus and manufacturer variation influence surgical supply waste is important for improving efficiency in surgical ORs. We analyzed proprietary data consisting of 1,790,000 surgical items used in 274,644 surgeries, and show that physician focus reduces supply waste and cost while manufacturer variation differentially moderates these relationships.","presenter":"Dr. Rajib Dutta","authors":[{"name":"Dr. Rajib Dutta","aff":"Assistant Professor, Miami University"},{"name":"Dr. David Dobrzykowski","aff":"Professor, University of Arkansas - Fayetteville"},{"name":"Dr. Brian Fugate","aff":"Associate Professor, University of Arkansas - Fayetteville"},{"name":"Dr. Claudia Rosales","aff":"Assistant Professor, University of Arkansas - Fayetteville"}],"order":3},{"id":"136-1011","title":"Block Scheduling of Operating Rooms with Guaranteed Delivery to Surgeons","content":"We propose a modeling approach, based on value-at-risk, for time block scheduling of surgeons that meets a prespecified service level for each surgeon. We present theoretical results that help formulate the problem and solve it efficiently. We perform numerical experiments on real data from a large urban hospital.","presenter":"Dr. Saharnaz Mehrani","authors":[{"name":"Dr. Saharnaz Mehrani","aff":"Assistant Professor, Florida Atlantic University"}],"order":5},{"id":"136-1063","title":"Data-Driven Approach to the Surgical Block Auto-Release Decision","content":"Surgical block allocation balances surgeon scheduling and OR utilization. Unused blocks are auto-released for open access before surgery, requiring a trade-off between predictability and efficiency. Using historical booking data, we developed a data-driven approach to optimize auto-release timing, enhancing OR utilization without compromising scheduling predictability in a large medical center.","presenter":"Dr. Sandeep Rath","authors":[{"name":"Dr. Sandeep Rath","aff":"Assistant Professor, University of North Carolina Chapel Hill"},{"name":"Dr. Moe Lim","aff":"Professor, UNC Health"}],"order":7}]},{"id":"s338","title":"Tutorial: Infectious disease modeling, evaluating interventions, and resource allocation","track":"Humanitarian Operations and Crisis Management","type":"Tutorial","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"GRAND HALL EAST B","chairs":["Prof. Pinar Keskinocak"],"abstracts":[{"id":"136-2091","title":"Infectious disease modeling, evaluating interventions, and resource allocation","content":"Infectious diseases pose challenges and threaten population health in around the world. Global and regional issues further exacerbate the risk of infectious diseases. We will discuss examples of how modeling and analytics can inform decision-making related to prevention and control, improve equity and outcomes, and support efforts towards eradication.","presenter":"Prof. Pinar Keskinocak","authors":[{"name":"Prof. Pinar Keskinocak","aff":"Professor, Georgia Institute of Technology"}],"order":1}]},{"id":"s354","title":"Featured Speaker Series Panel: Disability Employment – Key Challenges, Research, and Opportunities for Inter-disciplinary Work","track":"Tutorials and Workshops in Research and Teaching","type":"Panel","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"Learning Center","chairs":["Prof. Sriram Narayanan"],"abstracts":[{"id":"136-2076","title":"Featured Speaker Series_Panel_Disability Employment – Key Challenges, Research, and Opportunities for Inter-disciplinary Work","content":"The interdisciplinary panel will explore the broader challenges of disability employment and approaches to solving the challenges through accessibility. We will discuss research issues concerning inclusion from multiple lenses, including operations, rehabilitation, and systems engineering.","presenter":"Prof. Sriram Narayanan","authors":[{"name":"Prof. Sriram Narayanan","aff":"Professor, Michigan State University"}],"order":1}]},{"id":"s380","title":"New Technology and Behavioral Operations","track":"Behavioral Operations Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"INMAN","chairs":["Prof. Marcos Dieste"],"abstracts":[{"id":"136-0802","title":"Game Analysis and Income Distribution of Stakeholders in the \"Blockchain + \" Factoring Financing Business","content":"Factoring financing helps SMEs activate receivables. However, non-cooperation among stakeholders and unfair income distribution affect business implementation. Blockchain technology serves as a trust machine. We discuss the dynamic game behaviors of stakeholders in \"Blockchain+\" factoring and apply a modified Shapley value method for alliance profit distribution.","presenter":"Ms. Jingrong Li","authors":[{"name":"Ms. Jingrong Li","aff":"Student, Renmin University of China"}],"order":1},{"id":"136-1341","title":"Dynamic Processes of Digital Technology Acceptance: Worker-Management Interactions in Manufacturing Companies","content":"This study employs a multiple-case study approach to investigate digital technology acceptance in manufacturing companies, conceptualized as a dynamic process shaped by worker-management interactions. It examines communication methods, employees' genuine involvement, and feedback integration, emphasizing the evolution of cognition-action iterations and management roles during the implementation of digital technologies.","presenter":"Prof. Marcos Dieste","authors":[{"name":"Prof. Marcos Dieste","aff":"Assistant Professor, Department of Management and Engineering"},{"name":"Prof. Ambra Galeazzo","aff":"Professor, Department of Economics and Management ‘Marco Fanno’"},{"name":"Prof. Laura Macchion","aff":"Associate Professor, Department of Management and Engineering"}],"order":2},{"id":"136-0861","title":"Research on the construction and sharing decision of new energy vehicle manufacturers' charging stations","content":"As more and more new energy vehicle manufacturers open their charging stations to other automakers, it is particularly important to explore their behavior patterns and deep-seated driving mechanisms. Based on above, utilizing Cournot game model, this paper discusses the optimal charging station sharing mode selection of new energy vehicle manufacturers.","presenter":"Ms. Ruirui Yang","authors":[{"name":"Ms. Ruirui Yang","aff":"Student, Southeast University"},{"name":"Ms. Xiaochen Yan","aff":"Student, Southeast University"},{"name":"Prof. Weili Xue","aff":"Professor, Southeast University"}],"order":3},{"id":"136-1270","title":"How Conversational AI can Support Data-Driven Decision-Making by Micro-Retailers","content":"In a survey of 10,000 retailers in Mexico, we found that few use their systems’ data for decision-making. To study how Conversational AI can support them, we performed web-based laboratory experiments and field experiments, identifying the potential to increase sales and profit.","presenter":"Mr. Fabio Castro","authors":[{"name":"Mr. Fabio Castro","aff":"Student, Massachusetts Institute of Technology"},{"name":"Dr. Sreedevi Rajagopalan","aff":"Post Doc/Researcher, Massachusetts Institute of Techno"},{"name":"Dr. Josue Velazquez-Martinez","aff":"Professor, Massachusetts Institute of Technology"}],"order":4},{"id":"136-1472","title":"Advancing the Theory of Employee Acceptance of Digital Technologies: A Literature Review","content":"This paper reviews 81 studies on digital technology acceptance, identifying 32 key antecedents and emphasizing employees’ roles in integration. It proposes updating the UTAUT model with thematic categories, paradoxical elements, and emotions, while offering insights into acceptance as a dynamic process shaped by worker-manager interactions in industrial contexts.","presenter":"Prof. Marcos Dieste","authors":[{"name":"Prof. Marcos Dieste","aff":"Assistant Professor, Department of Management and Engineering"},{"name":"Prof. Ambra Galeazzo","aff":"Professor, Department of Economics and Management ‘Marco Fanno’"},{"name":"Prof. Laura Macchion","aff":"Associate Professor, Department of Management and Engineering"}],"order":5}]},{"id":"s391","title":"Transportation Research","track":"Empirical Research in Operations Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"EMBASSY B","chairs":["Dr. Eman Almehdawe"],"abstracts":[{"id":"136-1059","title":"From Taint to Turnover: Understanding Driver Stress and Stigma in Indian Trucking","content":"With a double-digit growth rate, India’s logistics sector faces a unique problem. The trucking sector has seen dwindling interest among individuals in taking on the trucking profession over the past two decades. Using the job demands-resources model, we find the intrinsic reason for the diminishing interest in the profession.","presenter":"Mr. Pankesh Dhadwal","authors":[{"name":"Mr. Pankesh Dhadwal","aff":"Student, IIM Indore"},{"name":"Prof. Shrihari Sohani","aff":"Associate Professor, IIM Indore"},{"name":"Prof. Saurabh Chandra","aff":"Professor, IIM Indore"},{"name":"Dr. Sayantan Mukherjee","aff":"Assistant Professor, IIM Indore"}],"order":1},{"id":"136-0747","title":"Flight Cancellations as a Strategic Response to Disruptions: Insights from the CrowdStrike IT Outage","content":"This study investigates flight cancellations as a strategic response to operational disruptions, focusing on the CrowdStrike IT outage. Using a DID approach, we analyzed cancellation patterns at the carrier-route level. Results highlight how airlines adapt operations during disruptions, providing insights into recovery strategies and minimizing service impacts.","presenter":"Ms. Tianyu Xu","authors":[{"name":"Ms. Tianyu Xu","aff":"Student, Ohio State University"},{"name":"Dr. Xiang Wan","aff":"Associate Professor, Ohio State University"}],"order":2},{"id":"136-1996","title":"How Charging Services Shape Consumer Behavior: Insights from China’s Electric Vehicle Market","content":"We examine the impact of EV manufacturers’ strategy of operating public charging stations. By integrating this strategy as a charging service attribute into a generalized utility model, we quantify its impact and analyze its interaction with driving range and public charging infrastructure, based on data from the Chinese EV market.","presenter":"Ms. Ruolin Yao","authors":[{"name":"Ms. Ruolin Yao","aff":"Student, Tianjin university COME"},{"name":"Prof. Shuai Ling","aff":"Professor, Tianjin Uinversity"}],"order":3},{"id":"136-0726","title":"The Relation Between Travel, Replenishment and Tank Count: Evidence from Fuel Delivery Services","content":"The study explores the link between replenishment time, travel, and number of tanks in a fuel delivery service. The findings are - (i) replenishment time decreases with number of tanks, increases with travel time per mile, (ii) travel time per mile increases with number of tanks, decreases with replenishment time.","presenter":"Dr. Pradeep K. Pendem","authors":[{"name":"Dr. Pradeep K. Pendem","aff":"Assistant Professor, University of Oregon"},{"name":"Prof. Nagesh Murthy","aff":"Professor, University of Oregon"}],"order":4},{"id":"136-0619","title":"Modeling the Stochastic Charging Behavior of Electric Vehicles Using Charging Data","content":"Using data from approximately 320,000 charging sessions in Saskatchewan over a year, the research identifies key temporal factors influencing charging frequency. A stochastic model is developed to predict charging events and durations. The findings offer data-driven insights for policymakers and contribute to the literature on EV infrastructure planning.","presenter":"Dr. Eman Almehdawe","authors":[{"name":"Dr. Eman Almehdawe","aff":"Associate Professor, University of Regina"}],"order":5}]},{"id":"s437","title":"Forecasting and Prediction Models","track":"Data Science, Analytics and AI","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"ROSWELL","chairs":["Mr. Firat Kilci"],"abstracts":[{"id":"136-0614","title":"Conditional Optimization: A Theoretical Framework for Predict-then-Optimize Problems","content":"This paper introduces Conditional Optimization (CO) as a novel theoretical approach to finding ex-ante optimal closed-form solutions for Predict-then-Optimize (PO) problems. Additionally, I derive a closed-form Conditional Optimizer that minimizes the expected loss function effectively.","presenter":"Ms. Irene Aldridge","authors":[{"name":"Ms. Irene Aldridge","aff":"Student, Cornell University"}],"order":1},{"id":"136-0967","title":"On the Value of Cross-Item Information in Forecasting Volatile Demand of MFCs","content":"This paper empirically explores the value of cross-item information in Micro Fulfillment Center (MFC) environments. Using relational analysis and empirical methods, we evaluate the impact of the data on machine learning. This study contributes to a framework for quantifying the value of internal information, offering actionable insights for data-driven decision-making.","presenter":"Ms. Minjeong An","authors":[{"name":"Ms. Minjeong An","aff":"Student, Yonsei University"},{"name":"Ms. Lee Dong Hee","aff":"Student, Yonsei University"},{"name":"Prof. Seung Hwan Jung","aff":"Associate Professor, Yonsei University"}],"order":2},{"id":"136-1426","title":"Customer Segmentation and Loyalty Prediction: A Hybrid Approach Using LRMF and ANN Models","content":"This research defined customer segmentation using LRFM with K-means with Sam’s club retail dataset, and the result was validated by Silhouette Coefficient Index. Further, a backpropagation ANN was used to form a prediction model at a 92% accuracy. Justifications were made to the imbalance dataset. Limitations would be stated.","presenter":"Mr. Clement Okolo","authors":[{"name":"Mr. Clement Okolo","aff":"Student, University of Louisiana at Lafayette"},{"name":"Prof. Sonya Hsu","aff":"Associate Professor, University of Louisiana at Lafayette"}],"order":3},{"id":"136-1657","title":"Predicting Spare Part Demand for Efficient Inventory Management","content":"High-tech firms face challenges managing spare part inventory due to short life cycles and uncertain demand. In this study, we propose a Bayesian method to predict the mean and variance of the demand, achieving service level targets from the product launch with lower inventory compared to benchmark methods.","presenter":"Mr. Firat Kilci","authors":[{"name":"Mr. Firat Kilci","aff":"Student, University of Texas Austin"},{"name":"Prof. Genaro Gutiérrez","aff":"Associate Professor, The University of Texas at Austin"},{"name":"Dr. Saurabh Bansal","aff":"Professor, Penn State University University Park"}],"order":4}]},{"id":"s449","title":"Transform Project Management Education with Cutting-Edge Simulations","track":"Tutorials and Workshops in Research and Teaching","type":"Tutorial","invited":"Contributed","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"2:15 PM","end":"3:45 PM","startMin":855,"room":"TECHWOOD","chairs":["Mr. Samie Penkar"],"abstracts":[{"id":"136-2141","title":"Transform Project Management Education with Cutting-Edge Simulations","content":"Join us for an interactive and insightful talk on how project management simulations are reshaping the way we teach—and students learn—project management and agile practices. Discover how leading universities are using Simulation Powered Learning’s immersive simulations to complement classroom instruction and bridge the gap between theory and real-world application.","presenter":"Mr. Samie Penkar","authors":[{"name":"Mr. Samie Penkar","aff":"Co-Founder, Simulation Powered Learning"}],"order":1}]},{"id":"s5","title":"Emerging Topics in Operations Management","track":"Manufacturing Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"LENOX","chairs":["Goutham Takasi"],"abstracts":[{"id":"136-0084","title":"Flight Delay Dynamics: Unraveling the Impact of Airport-Network-Spilled Propagation on Airline On-Time Performance","content":"Flight delay prediction is vital for airline operations. This study investigates the influence of the propagation of flight delays throughout the airport network via interconnected flights, a mechanism we term Airport-Network-Spilled Propagation (ANSP). Our time-dependent network method quantifies ANSP effects in real-time, improving prediction accuracy and enabling better operational decisions.","presenter":"Dr. Yajun Lu","authors":[{"name":"Dr. Yajun Lu","aff":"Assistant Professor, Jacksonville State University"},{"name":"Dr. Yi Tan","aff":"Assistant Professor, University of Alabama in Huntsville"},{"name":"Prof. Lu Wang","aff":"Assistant Professor, Ball State University"}],"order":1},{"id":"136-0164","title":"Procurement for Assembly Systems under Information Asymmetry and Supply Risk: Optimal Mechanisms","content":"We study a mechanism design problem faced by a firm assembling a product from multiple components. For each component, the firm has access to an unreliable supplier with privately known cost and supply uncertainty, and a reliable supply source. Our result is an optimal mechanism and a practical screening implementation.","presenter":"Mr. Like Bu","authors":[{"name":"Mr. Like Bu","aff":"Student, The University of Texas at Dallas"},{"name":"Prof. Milind Dawande","aff":"Professor, The University of Texas at Dallas"},{"name":"Prof. Ganesh Janakiraman","aff":"Professor, The University of Texas at Dallas"}],"order":2},{"id":"136-1146","title":"A Prior-Free, Asymptotically Efficient Mechanism for Two-Sided Platforms with Dynamic Arrivals","content":"We consider a two-sided platform that matches dynamically arriving buyers and sellers and incurs a cost for waiting agents. Platform aims to design an efficiency-maximizing mechanism. We develop a prior-free mechanism, derive a closed-form upper bound on its absolute efficiency gap, and show that it is asymptotically efficient.","presenter":"Dr. Arun Kumar Rout","authors":[{"name":"Dr. Arun Kumar Rout","aff":"Assistant Professor, State University of New York"},{"name":"Prof. Ganesh Janakiraman","aff":"Professor, The University of Texas at Dallas"},{"name":"Prof. Milind Dawande","aff":"Professor, The University of Texas at Dallas"}],"order":3},{"id":"136-0650","title":"Contextual Dynamic Pricing: Algorithms, Optimality, and Local Differential Privacy Constraints","content":"We study the contextual dynamic pricing problem where a firm sells products to T sequentially arriving consumers that behave according to an unknown demand model. We first show that the optimal regret upper bound is of order sqrt(dT). We then further study the problem under privacy constraints.","presenter":"Prof. Zifeng Zhao","authors":[{"name":"Prof. Zifeng Zhao","aff":"Assistant Professor, University of Notre Dame"}],"order":4}]},{"id":"s8","title":"Designing for a broader view in Service Operations","track":"POM and Community","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"EMBASSY F","chairs":["Dr. Yi Tang"],"abstracts":[{"id":"136-0201","title":"The Role of Contextual Information in Customer Reviews: A Field Experiment on a Mental-health Platform","content":"We conducted a randomized field experiment in partnership with Singapore's largest online mental health platform. We find that, revealing contextual information about the review writer alongside each review can increase the conversion rate by 42%, and increase the average number of bookings per customer by 87%.","presenter":"Mr. Guang Cheng","authors":[{"name":"Mr. Guang Cheng","aff":"Student, National University of Singapore"},{"name":"Mrs. Sidika Candogan","aff":"Assistant Professor, NUS Business School"},{"name":"Dr. Joel Goh","aff":"Associate Professor, NUS Business School"},{"name":"Prof. Bilal Gokpinar","aff":"Professor, University College London"}],"order":1},{"id":"136-1409","title":"Measuring Demographic Alignment: A Novel Approach and Its Impact on Performance","content":"We investigate how demographic alignment between managers and employees affects performance. We develop a novel measure based on Kullback-Leibler divergence, which is more aligned with the theoretical framing of congruence in the literature than commonly used measures. We then use a hotel dataset to quantify how demographic alignment matters.","presenter":"Mr. Will Stamey","authors":[{"name":"Mr. Will Stamey","aff":"Student, University of Notre Dame"},{"name":"Prof. Eve Rosenzweig","aff":"Professor, Emory University"},{"name":"Prof. Ken Kelley","aff":"Professor, University of Notre Dame"}],"order":3},{"id":"136-0106","title":"Green E-commerce: Environmental Impact of Fast Delivery","content":"In this paper, we empirically investigate how an increase in delivery speed influences consumer purchasing behavior and how this would further lead to environmental issues. Then, we explore different mechanisms to explain our empirical results and accordingly, propose delivery pricing policies to achieve both environmental benefits and decent company revenues.","presenter":"Ms. Chenshan Hu","authors":[{"name":"Ms. Chenshan Hu","aff":"Student, Washington University in St. Louis"},{"name":"Dr. Xiaoyang Long","aff":"Assistant Professor, University of Wisconsin Madison"},{"name":"Dr. Jiankun Sun","aff":"Assistant Professor, Imperial College London"},{"name":"Prof. Dennis Zhang","aff":"Associate Professor, Washington University in St. Louis"}],"order":4},{"id":"136-1646","title":"Designing an AI-Enabled Online Mental Health Service Referral Platform","content":"There is a huge gap between the supply and demand of mental health services. One primary reason for such a gap is the lack of awareness of available mental healthcare resources. In this study, we propose a personalized mental health service referral platform delivered through a chatbot.","presenter":"Dr. Yi Tang","authors":[{"name":"Dr. Yi Tang","aff":"Assistant Professor, University of New Mexico"},{"name":"Prof. Kingshuk Sinha","aff":"Professor, University of Minnesota"},{"name":"Mr. Adam Moen","aff":"Founder and Principal, ."}],"order":5}]},{"id":"s72","title":"Efficiency and Innovation in Energy Markets","track":"Energy and Natural Resource Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"TECHWOOD","chairs":["Prof. Fariba Farajbakhsh Mamaghani"],"abstracts":[{"id":"136-0104","title":"The impact of energy audit on energy efficiency","content":"We analyze the effect of energy audits on the adoption of energy efficiency improvement activities and find a nonlinear relationship between them. We then investigate the underlying reasons for this relationship.","presenter":"Prof. Jihyo Kim","authors":[{"name":"Prof. Jihyo Kim","aff":"Associate Professor, Korea Advanced Institute of Science and Technology (KAIST)"},{"name":"Prof. Seongkyoon Jeong","aff":"Assistant Professor, University of Tennessee Knoxville"}],"order":1},{"id":"136-0161","title":"Shades of Green: The Hidden Impact of Prosumers and Its Mitigation","content":"This study explores the rise of prosumers—consumers who generate renewable energy—and their impact on utilities and other consumers. A model reveals that, despite reducing non-renewable energy use, prosumers introduce grid uncertainties that elevate costs for traditional consumers. Policy recommendations include reverse-linear subsidies to balance prosumer adoption with social equity.","presenter":"Prof. Junghee Lee","authors":[{"name":"Prof. Junghee Lee","aff":"Assistant Professor, University of Notre Dame"},{"name":"Prof. Ming Hu","aff":"Professor, University of Toronto"},{"name":"Prof. Yinliang Tan","aff":"Associate Professor, China Europe International Business School"},{"name":"Prof. Lai Wei","aff":"Associate Professor, Shanghai Jiaotong Univerisity"}],"order":2},{"id":"136-1110","title":"Aggregation of Distributed Energy Resources","content":"We study different aggregation models to aggregate distributed energy resources (DERs). There is an aggregator who, with the knowledge of DERs’ utility functions and generations, procures electricity from DERs, and sells them in the wholesale market. Our goal is to design efficient aggregations that achieve socially optimal outcomes.","presenter":"Dr. Zuguang Gao","authors":[{"name":"Dr. Zuguang Gao","aff":"Assistant Professor, University of California, Irvine"},{"name":"Prof. Khaled Alshehri","aff":"Assistant Professor, King Fahad University of Petroleum &amp; Minerals"},{"name":"Prof. John Birge","aff":"Professor, University of Chicago"}],"order":3},{"id":"136-1667","title":"Dismissal of Demand Dependence Disappoints and Deceives: The Case of Microgrid Generation and Storage Investments","content":"Microgrids are localized energy systems that serve institutions like universities and data centers. Comprising generators and consumers, microgrids act as supplementary suppliers alongside the grid, supported by storage capabilities. Determining optimal generation and storage capacities for microgrids presents challenges due to uncertainties in demand, prices, and most importantly, their dependence.","presenter":"Mr. Jiarui Wei","authors":[{"name":"Mr. Jiarui Wei","aff":"Student, University of Texas at Dallas"},{"name":"Prof. Fariba Farajbakhsh Mamaghani","aff":"Assistant Professor, Tulane University"},{"name":"Prof. Metin Cakanyildirim","aff":"Professor, University of Texas Dallas"}],"order":4}]},{"id":"s83","title":"The impact of technology and policy on collaboration","track":"Product Innovation and Technology Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"COURTLAND","chairs":["Prof. Tian Chan"],"abstracts":[{"id":"136-0028","title":"The Effect of US-China Decoupling on Investment in Semiconductor Manufacturing","content":"We estimate a structural model to study the effect of US-China decoupling on investments in contract manufacturing capacity for semiconductor chips. Our unique dataset combines a comprehensive sample of worldwide fab-level capacity investments and a representative sample of global contract manufacturing orders for semiconductors 2004--2015.","presenter":"Prof. Ran Zhuo","authors":[{"name":"Prof. Ran Zhuo","aff":"Assistant Professor, University of Michigan, Ann Arbor"},{"name":"Prof. Audrey Tiew","aff":"Assistant Professor, New York University"}],"order":1},{"id":"136-0033","title":"The Impact of Artificial Intelligence on Scientific Collaboration","content":"This study examines the impact of artificial intelligence on scientific collaboration networks, focusing on researchers who cited the AlphaFold paper. Using a staggered difference-in-differences approach, we analyze how these scientists' collaboration patterns changed after publishing work citing AlphaFold. We plan to highlight AI's transformative role in reshaping scientific collaboration.","presenter":"Dr. Hyunwoo Park","authors":[{"name":"Prof. Hyun Ju Jung","aff":"Assistant Professor, K A I S T"},{"name":"Dr. Hyunwoo Park","aff":"Associate Professor, Seoul National University"}],"order":2},{"id":"136-0928","title":"Mobilizing the Silent Majority for Collective Action in Online Communities","content":"Most members in an online community (OC) are latent—they may join the community but may stay silent. Yet OCs have demonstrated the capacity to successfully deliver collective action projects. Our paper theorizes how the influence structure of an OC affects the ability of an OC to succeed in collective-action projects.","presenter":"Mr. Shizhen Chen","authors":[{"name":"Mr. Shizhen Chen","aff":"Student, Emory University"},{"name":"Prof. Tian Chan","aff":"Associate Professor, Emory University"},{"name":"Prof. Anandhi Bharadwaj","aff":"Professor, Emory University"}],"order":3},{"id":"136-1868","title":"Employee Turnover: The Interplay of Work-Life Balance and Compensation","content":"We examine how relative compensation and work-life balance perceptions drive employee turnover through within-company and across-company comparisons. Using employee movement data and Glassdoor ratings with instrumental variables, we show how salary gaps asymmetrically moderate work-life balance's impact on turnover decisions across different cultural contexts.","presenter":"Dr. Abhishek Deshmane","authors":[{"name":"Dr. Abhishek Deshmane","aff":"Assistant Professor, Georgia Institute of Technology"},{"name":"Dr. Hyunwoo Park","aff":"Associate Professor, Seoul National University"},{"name":"Dr. Morvarid Rahmani","aff":"Associate Professor, Georgia Institute of Technology"}],"order":4}]},{"id":"s92","title":"Behavioral OM for the Society","track":"Behavioral Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"EMBASSY D","chairs":["Dr. Sebastian Villa","Mr. Vinit Tipnis"],"abstracts":[{"id":"136-0459","title":"Emissions Framing and Individual Differences on Solar Panel Adoption Valuation","content":"This study explores how emissions-saving framings impact consumers’ valuation of solar panel adoption. Using an experimental design, we compare a blind condition with transparent framings of reduced emissions when installing. We investigate framing effects, mechanisms, and individual characteristics to inform strategies that enhance residential solar adoption and support climate goals.","presenter":"Ms. Veronica Marrero","authors":[{"name":"Ms. Veronica Marrero","aff":"Student, University of Colorado Boulder"},{"name":"Dr. Gloria Urrea","aff":"Assistant Professor, University of Colorado Boulder"},{"name":"Prof. David Drake","aff":"Assistant Professor, University of Colorado Boulder"}],"order":1},{"id":"136-0552","title":"Labeling the Supply Chain: Signaling Supply Chain Transparency to Consumers Through Eco-Labels","content":"Consumers increasingly value firms' sustainability efforts on social and environmental dimensions. These efforts are typically disclosed through eco-labels on packaging that simplify complex suuply chain practices into binary signals. We explore how the inclusion of eco-labels across different sustainability dimensions affects consumer perceptions of firm performance, examining spillovers between dimensions.","presenter":"Ms. Katelyn Thompson","authors":[{"name":"Ms. Katelyn Thompson","aff":"Student, Univ of South Carolina"},{"name":"Dr. Priyank Arora","aff":"Associate Professor, University of South Carolina"},{"name":"Dr. Blair Flicker","aff":"Assistant Professor, University of South Carolina"}],"order":2},{"id":"136-0667","title":"Post-COVID Pricing Dynamics in the Apartment Rental Market","content":"This study examines the dynamics of apartment rental price changes following COVID-19. Using data from multiple properties across different U.S. markets, the analysis reveals significant variations in rent increases, driven by property and market heterogeneity, offering fresh insights into factors influencing the apartment rental market’s response to the pandemic.","presenter":"Mr. Haibo Zhu","authors":[{"name":"Mr. Haibo Zhu","aff":"Student, University of South Carolina"},{"name":"Prof. Pelin Pekgun","aff":"Professor, Wake Forest University"},{"name":"Dr. Necati Tereyagoglu","aff":"Associate Professor, University of South Carolina"}],"order":3},{"id":"136-1060","title":"Queuing &amp; Donations: Effects of Waiting Time in Checkout Charity","content":"Firms frequently give consumers the option to donate to a nonprofit organization (NPO) at checkout counters. This approach improves firm’s image and allows NPOs to gain additional sources of donations. Through experiments, we investigate how queue-related attributes influence consumers’ donation at checkouts. Our findings have implications for optimizing charitable giving.","presenter":"Mr. Vinit Tipnis","authors":[{"name":"Mr. Vinit Tipnis","aff":"Student, Indiana University Bloomington"},{"name":"Dr. Sebastian Villa","aff":"Assistant Professor, University of Colorado Boulder"},{"name":"Dr. Eunae Yoo","aff":"Assistant Professor, Indiana University Bloomington"}],"order":4}]},{"id":"s132","title":"Transforming Delivery and Transportation Services","track":"Operational Excellence","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"BAKER","chairs":["Dr. Wee Meng Yeo"],"abstracts":[{"id":"136-0775","title":"Ridesharing for enhanced operations stability","content":"Ridesharing supports operations stability by addressing recruitment challenges and parking constraints through demand-responsive transport. It offers flexible commuting options, enhancing employee accessibility and satisfaction. By reducing parking demand, it optimizes space utilization and lowers infrastructure costs. This adaptive solution fosters workplace efficiency, sustainability, and resilience in urban and organizational settings.","presenter":"Dr. Wee Meng Yeo","authors":[{"name":"Dr. Wee Meng Yeo","aff":"Senior Lecturer, Glasgow University"},{"name":"Dr. Adrian Choo","aff":"Associate Professor, Michigan State University"},{"name":"Dr. Boray Huang","aff":"Freelance, ."}],"order":1},{"id":"136-1718","title":"Designing Assessment Teams for World Class Performance: Empirical Evidence from a Global Manufacturer","content":"We examine how the composition of assessment teams influences the implementation and outcomes of continuous process improvement programs in manufacturing. Analyzing 224 continuous improvement assessments, we find that language proficiency and specific types of experience among team members significantly affect scoring and subsequent manufacturing performance.","presenter":"Dr. Christopher Chen","authors":[{"name":"Dr. Christopher Chen","aff":"Assistant Professor, Indiana University Bloomington"},{"name":"Dr. Amrou Awaysheh","aff":"Associate Professor, Indiana University Indianapolis"},{"name":"Dr. Justin Kistler","aff":"Assistant Professor, University of Tennessee Knoxville"}],"order":2},{"id":"136-1965","title":"Service Oriented Considerate Routing: Data, Predictions and Robust Decisions","content":"Motivated by a real-world cold chain logistics dataset, we introduce the Courier Assigned Location Mismatch (CALM) metric that captures the couriers' unfamiliarity with delivery locations. Our novel Service Oriented Considerate Routing model, shown related to robust optimization, incorporates the CALM metric to assign routes within familiar territories, effectively improving punctuality.","presenter":"Dr. Yue Zhao","authors":[{"name":"Dr. Yue Zhao","aff":"Post Doc/Researcher, University of Toronto"},{"name":"Prof. Zhixing Luo","aff":"Professor, Nanjing University"},{"name":"Prof. Stanley Lim","aff":"Assistant Professor, Michigan State University"},{"name":"Prof. Caihua Chen","aff":"Professor, Nanjing University"},{"name":"Prof. Melvyn Sim","aff":"Professor, National University of Singapore"}],"order":3},{"id":"136-1310","title":"Expedited Service Promises: Evidence From a Food Ordering Platform","content":"We empirically investigate the impact of expedited service promises (ESP) on a food ordering platform. Employing a quasi-experimental design, we discover that ESPS disproportionately increase on-demand order sales. Further, the food items with good on-time performance and are hot dishes experience the most sales boost from ESP.","presenter":"Prof. Simin Li","authors":[{"name":"Prof. Simin Li","aff":"Assistant Professor, Tulane University"},{"name":"Prof. Nil Karacaoglu","aff":"Assistant Professor, The Ohio State University"},{"name":"Prof. Luyi Yang","aff":"Assistant Professor, University of California Berkeley"}],"order":4}]},{"id":"s167","title":"Procurement in Complex Supply Networks","track":"Procurement and Supplier Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"MARIETTA","chairs":["Dr. Christoph Schmidt","Mr. Christian Wagner"],"abstracts":[{"id":"136-1036","title":"Impact of Power Asymmetry on the Resilience of Supply Chain Networks Amid Catastrophic Disruptions","content":"COVID-19 caused unprecedented supply disruptions, highlighting the need for resilience. Although many factors contribute, this empirical research focuses on often-overlooked aspect of power asymmetry. Despite the accepted drawbacks during normal times, the study hypothesizes that during catastrophic disruptions, asymmetric power distributions could positively impact the resilience of complex intertwined supply","presenter":"Mr. Mohammad Rishehchi Fayyaz","authors":[{"name":"Mr. Mohammad Rishehchi Fayyaz","aff":"Student, Université Libre de Bruxelles"},{"name":"Dr. Evelyne Vanpoucke","aff":"Professor, Université Libre de Bruxelles"},{"name":"Dr. Canan Kocabasoglu Hillmer","aff":"Professor, City University - London"}],"order":1},{"id":"136-0908","title":"Lost in Translation? The Role of CEO Cultural Similarity in Supply Chain Relationship Duration","content":"We find that when customer and supplier CEOs share common cultural origins, it correlates positively with the duration of their supply chain relationship. Our path analysis further reveals that cultural similarity extends supply chain duration by mitigating transaction costs. Overall, our findings align with the tenets of transaction costs theory.","presenter":"Dr. Gary Chen","authors":[{"name":"Dr. Gary Chen","aff":"Assistant Professor, DePaul University"},{"name":"Dr. Sheng Liu","aff":"Assistant Professor, Northeastern Illinois University"},{"name":"Dr. Xiaohong (Sara) Wang","aff":"Professor, Northeastern Illinois University"}],"order":2},{"id":"136-0124","title":"To Help or not to Help? Customer Performance Feedback and Supplier R&amp;D Search","content":"This study explores the positive relationship between customers' performance shortfalls and suppliers' R&amp;D search. We further investigate how firm interlocks may moderate the relationship between customers’ performance shortfalls and suppliers’ R&amp;D search. Results support our hypotheses, emphasizing the importance of supply chain partners' performance in strategy and innovation research.","presenter":"Mr. Yuyang Liu","authors":[{"name":"Mr. Yuyang Liu","aff":"Student, Tongji University"},{"name":"Prof. Guofeng Ma","aff":"Professor, Tongji University"}],"order":3},{"id":"136-0260","title":"Spillover Effects of Social Sustainability Incidents Occurring in Complex Supply Networks","content":"Social sustainably incidents often occur within complex supply networks. We examine the spillover effects of 142 incidents and find a mean decline of -0.34% in focal firm's shareholder value. Expanding our study, we assess how network complexity and focal firms' control over the network influence the spillover effects.","presenter":"Mr. Christian Wagner","authors":[{"name":"Mr. Christian Wagner","aff":"Student, ETH Zürich"},{"name":"Prof. Christoph Schmidt","aff":"Associate Professor, University of Bath"},{"name":"Prof. Stephan Wagner","aff":"Professor, ETH Zurich"}],"order":4}]},{"id":"s170","title":"Emerging Topics in Decision Analysis","track":"Information Systems and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"EMBASSY E","chairs":["Dr. Xiao Xiao"],"abstracts":[{"id":"136-0682","title":"Rating Systems under Customer Disconfirmation Bias: Asymptotic Behavior and Granularity","content":"Online ratings reflect disconfirmation bias, where customers factor expectation-experience gaps into their ratings. We analyze three systems, complete, aggregate, and average ratings, showing that beliefs converge to product quality under small bias but diverge otherwise. Platforms can ensure accurate learning with granular rating systems, influencing convergence and learning speed.","presenter":"Dr. Qian (Ken) ZHANG","authors":[{"name":"Dr. Qian (Ken) ZHANG","aff":"Assistant Professor, California State Polytech University Pomona"},{"name":"Prof. Arian Aflaki","aff":"Assistant Professor, Pitt Business"}],"order":1},{"id":"136-0426","title":"From Dominance to Decline: A Global Perspective of Ridehailing Incumbents through Social Media Lens","content":"Our study investigates riders’ and drivers’ attitudes toward ridehailing incumbents based on 4 million social media data spanning over a decade. Leveraging machine learning and text mining approaches, we provide evidence of widespread dissatisfaction among both riders and drivers, alongside an increase in negative sentiment and anger towards incumbents.","presenter":"Prof. Arnab Bisi","authors":[{"name":"Mr. Souradeep Koley","aff":"Student, Indian Institute of Technology Roorkee"},{"name":"Prof. Mukesh Kumar Barua","aff":"Professor, Indian Institute of Technology Roorkee"},{"name":"Prof. Arnab Bisi","aff":"Associate Professor, Johns Hopkins University Carey Business"}],"order":3},{"id":"136-1806","title":"Copy and Paste: The Impact of Redundancy of Clinical Notes on In-Hospital Mortality","content":"This study investigates the impact of copy-and-paste (CP) practices in ICU clinical notes on in-hospital mortality. Analyzing a large dataset, findings reveal CP reduces mortality in physician notes but increases it in nursing notes, highlighting divergent effects due to distinct roles. Insights inform tailored documentation strategies for improved patient outcomes.","presenter":"Dr. He Zhang","authors":[{"name":"Dr. Gaurav Jetley","aff":"Assistant Professor, Colorado State University Fort Collins"},{"name":"Dr. He Zhang","aff":"Assistant Professor, Cal Poly"}],"order":4},{"id":"136-1301","title":"Risk Sharing in a Two-Level Supply Chain with Variable Capacity and Random Yield","content":"This study examines production uncertainty in supply chains, speciﬁcally focusing on Variable Capacity (VC) and Random Yield (RY) in both centralized and decentralized systems. It explores their eﬀects on supply chain eﬃciency, decision-making, and member relationships. Findings reveal that VC and RY's inﬂuence on supply chains varies by context.","presenter":"Dr. Xiao Xiao","authors":[{"name":"Dr. Xiao Xiao","aff":"Assistant Professor, California State University Stanislaus"},{"name":"Prof. Ting Luo","aff":"Associate Professor, California State University Fullerton"},{"name":"Dr. Feng Zhou","aff":"Assistant Professor, California State University Stanislaus"},{"name":"Dr. Junhee Kim","aff":"Assistant Professor, California State University Stanislaus"},{"name":"Prof. Saejoon Kim","aff":"Associate Professor, California State University Stanislaus"}],"order":5}]},{"id":"s194","title":"LLMs and Generative AI in Operations Management","track":"Supply Chain Risk Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"EMBASSY H","chairs":["Dr. Xiaocheng Li"],"abstracts":[{"id":"136-1305","title":"Can large language models simulate product usage?","content":"This study develops a framework leveraging LLMs to simulate product usage tailored to specific roles and functions. By generating realistic, role-specific user interactions, it provides actionable insights into feature design, usability, and adoption. Evaluation reveals alignment with real-world behaviors, advancing AI-driven product development and user research","presenter":"Mr. Hancheng Cao","authors":[{"name":"Mr. Hancheng Cao","aff":"Student, Stanford University"}],"order":1},{"id":"136-1614","title":"Group-Sparse Matrix Factorization for Transfer Learning of Word Embeddings","content":"This study introduces a two-stage transfer learning estimator with a group-sparse penalty to adapt word embeddings to domain-specific contexts using limited data. It ensures efficient learning by focusing on words with altered meanings, provides generalization error bounds, and guarantees computational efficiency, outperforming existing NLP fine-tuning methods in empirical evaluations.","presenter":"Prof. Kan Xu","authors":[{"name":"Prof. Kan Xu","aff":"Assistant Professor, Arizona State University"},{"name":"Prof. Hamsa Bastani","aff":"Associate Professor, University of Pennsylvania"}],"order":2},{"id":"136-1803","title":"OMGPT: Generative Pre-trained Transformers for Operational Decision Making","content":"We build a Generative Pre-training Transformer (GPT) model from scratch to solve sequential decision-making tasks arising in contexts of operations research, management science, and business which we call as OMGPT.","presenter":"Mr. Shang Liu","authors":[{"name":"Mr. Shang Liu","aff":"Student, Imperial College Business School, Imperial College London"},{"name":"Dr. Xiaocheng Li","aff":"Assistant Professor, Imperial College London"},{"name":"Mr. Hanzhao Wang","aff":"Student, Imperial College London"},{"name":"Prof. Kalyan Talluri","aff":"Professor, Imperial College London"}],"order":3}]},{"id":"s202","title":"Empirical Retail Operations-2","track":"Retail Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"FAIRLIE","chairs":["Dr. Lina Wang"],"abstracts":[{"id":"136-0295","title":"Causal Product Networks: A Data-driven Methodology for Modeling Basket-Shopping Consumer Behavior","content":"The purchase of one product affects the purchases of others in a shopping basket. We propose a causal discovery approach to learn the underlying causal structure among product purchases from observational shopping basket data and construct a causal product network (CPN) to describe these latent interactions.","presenter":"Mr. Ziwei Zhu","authors":[{"name":"Prof. Vishal Gaur","aff":"Professor, Cornell University"},{"name":"Dr. Nur Kaynar","aff":"Assistant Professor, Cornell University"},{"name":"Mr. Ziwei Zhu","aff":"Student, Cornell University"}],"order":1},{"id":"136-0359","title":"Bias in Offline Retailing Experiment: Evidence and Solution","content":"Product-based randomization, where a random subset of products receives treatment while others serve as controls, is commonly used in offline retailing experiments. We show this can result in biased causal inference due to consumer substitution and complementarity behaviors. We propose a double-machine-learning-based debiasing method with theoretical guarantees and empirical performance.","presenter":"Ms. Jiayi Zhang","authors":[{"name":"Ms. Zhiqi Zhang","aff":"Student, Washington University in St. Louis"},{"name":"Prof. Dennis Zhang","aff":"Associate Professor, Washington University in St. Louis"},{"name":"Prof. Ruohan Zhan","aff":"Assistant Professor, Hong Kong University of Science and Technology"},{"name":"Ms. Jiayi Zhang","aff":"Student, Washington University in St. Louis"}],"order":5},{"id":"136-1710","title":"An Empirical Analysis of Dynamic Pricing in Supermarkets","content":"Perishable dynamic pricing can mitigate retail food waste, but its effectiveness is not well understood. This study analyzes dynamic pricing using transaction data from a Japanese grocery chain, estimating consumer preferences for freshness. Exploiting quasi-experimental policy variations, it quantifies the welfare effects and food waste impact of dynamic pricing","presenter":"Mr. Kohei Hayashida","authors":[{"name":"Mr. Kohei Hayashida","aff":"Student, Rady School of Management"}],"order":6},{"id":"136-0555","title":"Unveiling Operational Processes: The Impact of Real-time Videos on Operational Outcomes","content":"In the digital age, merchants are presented with an expanding range of resources to enhance operational transparency for customers. This paper explores a new method to enhance operational transparency for merchants on digital platforms: displaying real-time videos of their operational processes.","presenter":"Mr. Zhanzhi Zheng","authors":[{"name":"Mr. Zhanzhi Zheng","aff":"Student, UNC Kenan-Flagler Business School"},{"name":"Prof. Yuqian Xu","aff":"Associate Professor, UNC Chapel Hill"},{"name":"Prof. Bradley Staats","aff":"Professor, University of North Carolina Chapel Hill"}],"order":7}]},{"id":"s211","title":"Contemporary Issues in Operations Management","track":"Digital Platforms, Innovations and Transformations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"GREENBRIAR","chairs":["Dr. Jaeyoung Kim"],"abstracts":[{"id":"136-0664","title":"Family Medicine Co-location with Hospital Campuses: How Health System Integration can Impact Operations","content":"Co-locating family medicine offices with hospital campuses can transform emergency department (ED) operations by altering patient mix. This study investigates how co-location impacts low- and high-acuity patient arrivals using a difference-in-difference approach, revealing an increased proportion of emergent cases and implications for optimizing ED resources.","presenter":"Prof. Benjamin Grant","authors":[{"name":"Prof. Benjamin Grant","aff":"Assistant Professor, Clemson University"},{"name":"Mr. Thomas Ross","aff":"Student, Clemson University"}],"order":1},{"id":"136-0974","title":"The impact of schedule consistency on delivery worker productivity and turnover","content":"We investigate how two types of schedule consistency—hour-of-the-day (HOTD) and\r\nday-of-the-week (DOTW)—affect worker productivity and turnover in the context of last-\r\nmile delivery services. We find that 1) HOTD consistency not only improves productivity\r\nbut also decreases turnover, 2) DOTW consistency increases productivity but also\r\nincreases turnover.","presenter":"Dr. Kevin Park","authors":[{"name":"Dr. Kevin Park","aff":"Assistant Professor, University of Dayton"},{"name":"Dr. Xiaodan Pan","aff":"Assistant Professor, Concordia University"},{"name":"Dr. Martin Dresner","aff":"Professor, University of Maryland"},{"name":"Dr. Suhyung Lee","aff":"Senior reseaecher, Korea Airports Corp."}],"order":2},{"id":"136-0904","title":"Optimal Control in Two-class Bass Models with Competition","content":"We consider the optimal control problem in a two-class Bass system. The control is the instantaneous allocation of scarce resources to each class at every point to minimize the cumulative loss in the system. We provide structures and characteristics of an optimal policy and compare with a practical policy.","presenter":"Dr. Hojun Choi","authors":[{"name":"Dr. Hojun Choi","aff":"Assistant Professor, Colorado School of Mines"},{"name":"Dr. Ohad Perry","aff":"Associate Professor, Southern Methodist University"},{"name":"Prof. Achal Bassamboo","aff":"Professor, Northwestern University"}],"order":3}]},{"id":"s245","title":"Learning and Applications in Operations Management","track":"Supply Chain Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"EMBASSY A","chairs":["Dr. Wenchang Zhang","Dr. Mengfei Li"],"abstracts":[{"id":"136-1037","title":"Multiproduct Inventory Systems with Upgrading: Replenishment, Allocation, and Online Learning","content":"We study joint ordering and upgrading in a multiproduct system over T periods, addressing both known and unknown demand distributions. We propose a stochastic gradient descent with perturbed gradient (SGD-PG) algorithm, achieving optimal regret bounds. Numerical experiments demonstrate efficacy and highlight conditions where upgrading maximizes profitability for practitioners.","presenter":"Prof. Jingwen Tang","authors":[{"name":"Prof. Jingwen Tang","aff":"Assistant Professor, University of Miami Business School"},{"name":"Prof. Izak Duenyas","aff":"Professor, University of Michigan - Ann Arbor"},{"name":"Prof. Cong Shi","aff":"Associate Professor, University of Miami Business School"},{"name":"Prof. Nan Yang","aff":"Professor, University of Miami"}],"order":1},{"id":"136-1666","title":"Managing Multihoming Workers in the Gig Economy","content":"We address how gig workers choose between competing platforms, integrating proprietary ride-hailing data with public data. Using simulation and machine learning to overcome data limitations, we structurally estimate perceived costs driving forward-looking decisions and explore the impact of pay schemes and incentives on labor supply and platform operations.","presenter":"Prof. Park Sinchaisri","authors":[{"name":"Prof. Gad Allon","aff":"Professor, The Wharton School"},{"name":"Prof. Maxime Cohen","aff":"Professor, McGill University"},{"name":"Prof. Ken Moon","aff":"Assistant Professor, The Wharton School"},{"name":"Prof. Park Sinchaisri","aff":"Assistant Professor, University of California Berkeley"}],"order":2},{"id":"136-1819","title":"Dissecting the Learning Curve for Supply Chain Efficiency and Stability: An Empirical Analysis","content":"This study explores how learning impacts efficiency and consistency in SME supply chains, analyzing procurement, preparation, production, and shipment stages. Using empirical methods, findings show cumulative production doubles improve efficiency by 3.9% and consistency by 27%. A learning-based optimization model increases profits by 3.9%, offering actionable insights for managerial decision-making.","presenter":"Dr. Mengfei Li","authors":[{"name":"Dr. Mengfei Li","aff":"Student, Fudan University"},{"name":"Dr. Wenchang Zhang","aff":"Assistant Professor, Kelley School of Business"},{"name":"Dr. Yue Cheng","aff":"Assistant Professor, Peking University"},{"name":"Dr. Liu Ming","aff":"Assistant Professor, Chinese Univ of Hong Kong (Shenzhen)"},{"name":"Prof. Xiaole Wu","aff":"Professor, Fudan University"}],"order":3},{"id":"136-1925","title":"Can AI Replace Human Judgment? Evidence from Keyword Auction Campaigns","content":"This study investigates the impact of AI-automated keyword auction campaigns on e-commerce sellers’ performance. It finds that while AI boosts sales revenue, manually configured campaigns outperform automated ones by leveraging sellers’ private insights, eg. market dynamics and bidding strategies. The results underscore the complementary value of human expertise and AI","presenter":"Mr. Rohit Dhonukshe","authors":[{"name":"Mr. Rohit Dhonukshe","aff":"Student, Indiana University Bloomington"}],"order":4}]},{"id":"s259","title":"Emerging topics on platforms","track":"POM-Marketing Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"DUNWOODY","chairs":["Dr. Rachel Chen","Dr. Xuying Zhao"],"abstracts":[{"id":"136-0163","title":"Driver Safety Through Rewards","content":"We consider a budget constrained not-for-profit platform that rewards drivers for safe driving. Based on practice we develop two types -- targeted and self-selection -- of reward schemes. We derive insights by comparing the performance of these schemes with easy to implement schemes adopted by the platform.","presenter":"Dr. Tharanga Rajapakshe","authors":[{"name":"Prof. Suresh Muthulingam","aff":"Professor, Penn State University University Park"},{"name":"Dr. Tharanga Rajapakshe","aff":"Associate Professor, University of Florida"},{"name":"Prof. Debjit Roy","aff":"Professor, Indian Institute of Management Ahmedabad"}],"order":1},{"id":"136-0665","title":"ONLINE INFLUENCERS' EFFECTIVENESS AND SOCIAL VALUE CREATION: A STUDY IN SUBSISTENCE MARKETPLACES","content":"This study develops a framework identifying key characteristics of social media influencers who can drive social and behavioural change among bottom-of-the-pyramid consumers. Through qualitative interviews, this study attempts to offer insights for marketers and policymakers to effectively leverage influencers for social value creation in the subsistence marketplaces.","presenter":"Prof. Aditya Billore","authors":[{"name":"Prof. Aditya Billore","aff":"Professor, Indian Institute of Management Indore"},{"name":"Ms. Shobhita Mehra","aff":"Student, Indian Institute of Management Indore"}],"order":2},{"id":"136-1582","title":"A new study of modern customization","content":"We study customization as new technologies such as AI emerge.","presenter":"Mr. Jinyi Liu","authors":[{"name":"Mr. Jinyi Liu","aff":"Student, University of Tennessee, Knoxville"},{"name":"Prof. Tingliang Huang","aff":"Professor, The University of Tennessee-Knoxville"},{"name":"Mr. Ganquan Huang","aff":"Post Doc/Researcher, University of Science and Technology of China"}],"order":3},{"id":"136-1766","title":"Seeding vs. Time-Limited Freemium as Catalysts for the Adoption of Software Applications","content":"We explore two strategies through which developers can catalyze adoption by helping consumers directly or indirectly learn the value of their products - seeding and time-limited freemium. We show that adoption costs and individual depreciation of value can play critical roles in enabling seeding to emerge as a dominant strategy.","presenter":"Prof. Marius Niculescu","authors":[{"name":"Prof. Yifan Dou","aff":"Professor, Fudan University"},{"name":"Dr. Hao Hu","aff":"Student, Georgia Institute of Technology"},{"name":"Prof. Marius Niculescu","aff":"Associate Professor, Georgia Institute of Technology"},{"name":"Prof. D.J. Wu","aff":"Professor, Georgia Institute of Technology"}],"order":4},{"id":"136-1883","title":"When Less is More: Analysis and Empirical Evidence of Control Limit Strategies in a Telemedicine","content":"This research investigates a telemedicine platform enabling patients to obtain multiple diagnoses. We analyze the impact of commission-based pricing and control limits on doctor participation and platform profitability.","presenter":"Prof. Guangwen Kong","authors":[{"name":"Prof. Guangwen Kong","aff":"Associate Professor, Temple University"},{"name":"Mr. Jingxuan Geng","aff":"Student, Temple University"},{"name":"Prof. Marco Qin","aff":"Assistant Professor, Temple University"}],"order":5}]},{"id":"s285","title":"Economic Landscape of Generative AI in Digital Disruptions","track":"Generative AI and Societal Sustainable Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"HARRIS","chairs":["Dr. Yi Gao"],"abstracts":[{"id":"136-0853","title":"Learning to Adopt Generative AI","content":"We develop a Bayesian learning model that incorporates demographic heterogeneities in both the utility and signal functions. Leveraging a clickstream dataset, we estimate the model and find significant learning and utility divides across various demographic attributes. Besides, we document a phenomenon termed the belief trap and show related intervention strategies.","presenter":"Mr. Xingchen Xu","authors":[{"name":"Mr. Xingchen Xu","aff":"Student, University of Washington"}],"order":1},{"id":"136-1266","title":"On the Safety of Large Language Models","content":"The increasing use of Large Language Models (LLMs) has transformed the landscape of information retrieval. However, these systems are vulnerable to adversarial attacks. We investigate the dynamics of adversarial attacks on LLMs. Our findings have significant implications for LLM system security design.","presenter":"Prof. Xiyang Hu","authors":[{"name":"Prof. Xiyang Hu","aff":"Assistant Professor, Arizona State University"}],"order":2},{"id":"136-1656","title":"Audience Reactions to Artists Embracing Generative AI: Insights from Digital Art","content":"This study investigates the impact of artists adopting generative AI on audience perceptions. While overall quantity and sentiment of audience comments remains stable, inexperienced artists experience heightened criticism and scrutiny. These reactions suggest audience resistance to AI integration in art, emphasizing the importance of artistic intentionality in shaping perceptions.","presenter":"Ms. Yingxin Zhou","authors":[{"name":"Ms. Yingxin Zhou","aff":"Student, Georgia State University"},{"name":"Dr. Ling Xue","aff":"Associate Professor, University of Georgia"},{"name":"Dr. Arun Rai","aff":"Professor, Georgia State University"}],"order":3},{"id":"136-1725","title":"Effects of AI Summarization on User Engagement and Openness","content":"The rise of GenAI in social media summarization presents new opportunities and challenges for addressing media polarization and alleviate echo chambers. Partnering with an AI start-up, KOAT, we explore the potentials of LLM to create personalized news summaries that present counter-attitudinal content in a cross-partisan empathetic way.","presenter":"Ms. Shuang Gao","authors":[{"name":"Dr. Katsiaryna Siamionava","aff":"Assistant Professor, Arizona State University"},{"name":"Ms. Shuang Gao","aff":"Student, Arizona State University"},{"name":"Dr. Jiding Zhang","aff":"Assistant Professor, Arizona State University"},{"name":"Prof. Pei-yu Chen","aff":"Professor, Arizona State University"}],"order":4},{"id":"136-0181","title":"Enhancing Supply Chain Transparency Using A GenAI-Solution","content":"Firms must ensure transparency among their supply chain networks, as the EU's corporate sustainability due diligence directive (CSDDD) requires upstream and downstream visibility. While firms hinder transparency initiatives due to economic concerns, we developed an AI solution that provides insights into data from diverse perspectives.","presenter":"Prof. Tobias Engel","authors":[{"name":"Mr. Gökhan Cenk","aff":"Lecturer, University of Applied Science Neu-Ulm"},{"name":"Mr. Benjamin Hofmann","aff":"Lecturer, University of Applied Science Neu-Ulm"},{"name":"Prof. Tobias Engel","aff":"Professor, University of Applied Science Neu-Ulm"}],"order":5}]},{"id":"s289","title":"Strategic Decision-Making in Retail and Supply Chains","track":"Disruptive Technologies and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"KENNESAW","chairs":["Ms. Qiaodan He"],"abstracts":[{"id":"136-1226","title":"Let Consumers Make a Choice? An Analytical Model of Online Retailer Product Displays","content":"Online retailers face a trade-off between showcasing within-category and across-category product displays. This study develops a game-theoretic model and reveals when firms should decide display types versus letting consumers choose their preferred display types, offering theoretical insights and practical guidance on balancing depth and width for effective online shopping experiences.","presenter":"Ms. Qiaodan He","authors":[{"name":"Ms. Qiaodan He","aff":"Student, Lehigh University"},{"name":"Prof. James Dearden","aff":"Professor, Lehigh University"},{"name":"Dr. David Zhang","aff":"Assistant Professor, Lehigh University"},{"name":"Prof. Oliver Yao","aff":"Professor, University of Delaware"}],"order":1},{"id":"136-1272","title":"Pricing and Physical Channel Choice Strategies for a Multi-channel Retailer Under Consumer Showrooming and Webrooming","content":"We propose an innovative offline deployment for multi-channel retailers called showrooms where consumers can evaluate but cannot buy. We explore how multi-channel retailers choose between full-functional stores and showrooms when consumers engage in showrooming and webrooming behaviors.","presenter":"Mr. Jingxuan Geng","authors":[{"name":"Mr. Jingxuan Geng","aff":"Student, Temple University"},{"name":"Prof. Amit Mehra","aff":"Professor, University of Texas Dallas"},{"name":"Dr. Subodha Kumar","aff":"Professor, Temple University"}],"order":2},{"id":"136-1689","title":"Can Learning-by-doing Hurt Profit? The Case of Outsourcing and Supplier Encroachment","content":"We used a two-period supply chain model to investigate how the CM’s learning-by-doing ability to reduce production cost affects profits. Surprisingly, stronger learning ability doesn't always increase profits, because for certain circumstances, the OEM reduces outsourcing to deter CM encroachment. Stronger learning is always beneficial, though, for negotiable wholesale prices.","presenter":"Dr. Yaqin Sun","authors":[{"name":"Dr. Yaqin Sun","aff":"Lecturer, Lehigh University"},{"name":"Prof. Wenjing Shen","aff":"Associate Professor, Drexel University"}],"order":4}]},{"id":"s337","title":"Panel: A Dialog on Predictive Analytics in Supply Chain Relationships","track":"Tutorials and Workshops in Research and Teaching","type":"Panel","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"Learning Center","chairs":["Prof. Wc Benton"],"abstracts":[{"id":"136-2077","title":"Panel_A Dialog on Predictive Analytics in Supply Chain Relationships","content":"This panel discussion will delve into predictive analytics for the supply chain relationships which leverages statistical algorithms, data, and machine learning techniques to identify the likelihood of future outcomes. Learn from academic leaders and practitioners about the challenges, successes, and future trends in this area.","presenter":"Prof. Wc Benton","authors":[{"name":"Prof. Wc Benton","aff":"Professor, Ohio State University"}],"order":1}]},{"id":"s349","title":"Social Responsibility and Resilience in Agricultural Supply Chains","track":"Agriculture and Food Supply Chains","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"VININGS","chairs":["Dr. Narendra Malalgoda"],"abstracts":[{"id":"136-0915","title":"How Supply Chains Can Contribute to Healthy and Sustainable Diets","content":"This study investigates how food supply chains influence the availability of healthy and sustainable diets. By utilizing Dynamic Capabilities framework and interviewing industry stakeholders we analyse effective strategies that optimize food production, distribution and consumption to support public health outcomes while promoting environmental sustainability.","presenter":"Dr. Hafize Sahin Ersoz","authors":[{"name":"Dr. Hafize Sahin Ersoz","aff":"Post Doc/Researcher, Cranfield University"},{"name":"Prof. Michael Bourlakis","aff":"Professor, Cranfield University"}],"order":1},{"id":"136-0302","title":"Agricultural Stakeholder Adaptation: Comparative Analysis of Resilience Strategies in India and Bangladesh","content":"This study examines resilience mechanisms among 1,362 agricultural retailers in India and Bangladesh. Analysis reveals that long-term supplier relationships and adequate inventory management strengthen resilience, while limited access to credit and training hinders it. Despite regional differences, findings highlight critical factors for building robust agricultural retail networks.","presenter":"Prof. Manoj Dora","authors":[{"name":"Prof. Manoj Dora","aff":"Professor, Anglia Ruskin University"}],"order":2},{"id":"136-1541","title":"Dissolving Philoetius’ Sustainability Paradox: A Systems Perspective on Supply Chain Sustainability and Circularity","content":"The paradox concept in supply chain sustainability is explored using Philoetius from Homer’s Odyssey to examine food waste challenges. A UK grocery retailer case study and the PHILOETIUS model highlight managing trade-offs during COVID-19 disruptions, providing a foundation for further research and practical applications.","presenter":"Prof. Samuel Allen","authors":[{"name":"Prof. Samuel Allen","aff":"Technical Analyst, Professor, RAND"},{"name":"Prof. Joseph Sarkis","aff":"Professor, Worcester Polytechnic Institute"},{"name":"Dr. Xun Wang","aff":"Lecturer, Cardiff University"},{"name":"Prof. Sharon Johnson","aff":"Professor, Worcester Polytechnic Institute"},{"name":"Dr. Khalid Saeed","aff":"Professor, Worcester Polytechnic Institute"}],"order":3},{"id":"136-1106","title":"Supply chain social standards implementations: the case of coffee supply chain in Vietnam","content":"In emerging markets, suppliers implement labour and human rights requirements only to comply with requirements from international buyers; thus, it is unclear whether they lead to meaningful changes in working conditions. This research aims to uncover suppliers’ perceptions regarding social standards and their outcomes in Vietnam’s coffee supply chain.","presenter":"Dr. Phuong Tran","authors":[{"name":"Dr. Phuong Tran","aff":"Lecturer, University of Bristol"}],"order":5},{"id":"136-0814","title":"Sustainable Grain Transport in Canada: Role of Short-Line Railways","content":"This study explores the feasibility of short-line railways to enhance sustainability in grain transport amidst declining grain elevators in Canada. Using a mixed-methods approach, it assesses economic, environmental, and social impacts, emphasizing rural resilience and sustainable development. Findings will guide policy and investments for a resilient grain supply chain.","presenter":"Dr. Narendra Malalgoda","authors":[{"name":"Mr. Tharaka De Alwis","aff":"Student, University of Manitoba"},{"name":"Mr. Supul Muhandiram","aff":"Student, University of Manitoba"},{"name":"Dr. Narendra Malalgoda","aff":"Assistant Professor, University of Manitoba"},{"name":"Dr. Mani Venkatesh","aff":"Associate Professor, Asper School of Business"}],"order":6}]},{"id":"s357","title":"College of Service Operations - Emerging Scholar and Lifetime Achievement Award","track":"Service Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"EMBASSY C","chairs":["Prof. Benjamin Lawrence"],"abstracts":[{"id":"136-2128","title":"College of Service Operations emerging scholar and lifetime achievement award","content":"This session is for the College of Service Operations emerging scholar and lifetime achievement award.","presenter":"Prof. Benjamin Lawrence","authors":[{"name":"Prof. Benjamin Lawrence","aff":"Associate Professor, Georgia State University"}],"order":1}]},{"id":"s358","title":"Social Platforms","track":"Information Systems and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"SPRING","chairs":["Prof. Vasundhara Sharma"],"abstracts":[{"id":"136-1404","title":"Rarity is in the Eye of the Beholder: Impact of Rarity Tools on NFT Marketplaces","content":"Understanding the trade dynamics of NFTs is essential for their market sustainability. Recent tools have started providing rarity ranking for NFTs within a collection. As rarity is a key driver of an NFT's value, we investigate the impact of displaying these rankings on collections.","presenter":"Prof. Ahmed Timoumi","authors":[{"name":"Prof. Ahmed Timoumi","aff":"Assistant Professor, Indian School of Business"},{"name":"Prof. Vasundhara Sharma","aff":"Assistant Professor, Indian School of Business"},{"name":"Dr. Subodha Kumar","aff":"Professor, Temple University"}],"order":1},{"id":"136-1203","title":"Interoperability in Decentralized Social Media: Threads, Fediverse, and EU Digital Market Act","content":"This research examines the impact of integrating Threads with the Fediverse on user engagement and platform interoperability, particularly under the EU Digital Market Act. It analyzes the technical, social, and regulatory implications of this integration, assessing alignment with EU regulations for fair competitions.","presenter":"Mr. Xiaoxiao Wang","authors":[{"name":"Mr. Xiaoxiao Wang","aff":"Student, Temple University"},{"name":"Dr. Subodha Kumar","aff":"Professor, Temple University"}],"order":2},{"id":"136-0279","title":"Monitoring Content Piracy on Social Platforms","content":"We consider enforcement efforts in the setting where the content is sold through a platform. In our model setting along with the subscription-based legal content on the platform, there is free illegal content that generates revenue through advertisements for the platform. We analyze scenarios of illegal content monitoring.","presenter":"Prof. Jishnu Hazra","authors":[{"name":"Prof. Tarun Jain","aff":"Professor, Indian Institute of Management Bangalore"},{"name":"Prof. Jishnu Hazra","aff":"Professor, Indian Institute of Management Bangalore"},{"name":"Prof. T.C.E. Cheng","aff":"Professor, The Hong Kong Polytechnic University"}],"order":3},{"id":"136-1630","title":"Multifaceted Jeopardies of Curtailing Brand Activism on LGBTQ: A Natural Experiment","content":"Facing pressure from polarized consumer opinions on socio-political issues, brands may reduce activism to minimize conflict. This study examines the impact of Target’s 2023 decision to curtail LGBTQ+ activism by removing Pride Month displays. Using difference-in-differences analysis, findings reveal a 4.6%–5% sales decline, driven by loyal customers, with Walmart benefiting.","presenter":"Xiangnan Zhang","authors":[{"name":"Prof. Xueming Luo","aff":"Professor, Temple University"},{"name":"Xiangnan Zhang","aff":"Student, Temple University"}],"order":4},{"id":"136-1484","title":"Network Externalities and Anti-Piracy Strategies in Digital Products","content":"Many firms add online-only features to boost value through network externalities, which also help fight piracy. However, traditional anti-piracy methods are still needed as fully online software is not always practical. This study uses a game theory model to explore how network externalities shape decisions on software quality and anti-piracy.","presenter":"Mr. Zeming Wang","authors":[{"name":"Mr. Zeming Wang","aff":"Student, University of Groningen"},{"name":"Dr. Jasper Veldman","aff":"Associate Professor, University of Groningen"},{"name":"Prof. Ruud Teunter","aff":"Professor, University of Groningen"}],"order":5}]},{"id":"s359","title":"The College of SCM Best Student Paper Competition","track":"Supply Chain Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"GRAND HALL EAST A","chairs":["Dr. Joel Goh","Dr. Rob Basten"],"abstracts":[{"id":"136-2096","title":"Evaluating time window assortments in online grocery delivery","content":"Online grocery services require customers to be present at delivery, creating time window constraints that impact profitability. We develop an analytical model to evaluate time window assortments, analyzing trade-offs between demand and delivery efficiency. Our insights help businesses design optimal assortments, aligning operations strategy with market conditions for economic viability.","presenter":"Ms. Katrin Waßmuth","authors":[{"name":"Ms. Katrin Waßmuth","aff":"Student, University of Mannheim"},{"name":"Dr. Niels Agatz","aff":"Associate Professor, Rotterdam School of Management"},{"name":"Prof. Moritz Fleischmann","aff":"Professor, University of Mannheim"}],"order":1},{"id":"136-2097","title":"Whiplash: Congestion Dissipation in a Disrupted Circulatory Shipping System","content":"We model supply chain disruption impacts in a circulatory shipping system using fluid dynamics, revealing inbound/outbound congestion and a whiplash effect from uneven ship distribution. Extending to bipartite networks and diffusion models, we integrate predictions with machine learning, reducing vessel recovery time errors by 10%-30% in Shanghai Port.","presenter":"Ms. Chaoyu Zhang","authors":[{"name":"Ms. Chaoyu Zhang","aff":"Student, University of Toronto"},{"name":"Prof. Ming Hu","aff":"Professor, University of Toronto"}],"order":2},{"id":"136-2098","title":"Adapting to Gig Economy Dynamics: Network and Staffing Strategies for Long-Haul Trucking Platforms","content":"We analyze the trade-off between traditional point-to-point and relay network models in long-haul trucking. Using data from a large trucking platform, we show that longer trip-duty lengths reduce driver reliability. Under such network-sensitive supply behavior, we identify conditions where relay networks become cost-optimal, a win-win for service providers and drivers.","presenter":"Ms. Himani Ananthula","authors":[{"name":"Ms. Himani Ananthula","aff":"Student, Kellogg School of Management"},{"name":"Dr. Milind Sohoni","aff":"Professor, The State University of New York at Buffalo"},{"name":"Prof. Achal Bassamboo","aff":"Professor, Northwestern University"}],"order":3},{"id":"136-2099","title":"Two-sided Benefits of Price Transparency in Smallholder Supply Chains","content":"Using a novel supply chain model, we study how information platforms can be designed to provide mutual benefits to suppliers and buyers in smallholder supply chains. Our findings help explain variations in existing empirical results and offer practical guidance to platform designers on identifying target markets and optimizing transparency levels.","presenter":"Ms. Yuan Shi","authors":[{"name":"Ms. Yuan Shi","aff":"Student, Massachusetts Institute of Technology"},{"name":"Prof. Joann de Zegher","aff":"Assistant Professor, MIT"},{"name":"Prof. Irene Lo","aff":"Assistant Professor, Stanford University"}],"order":4},{"id":"136-2100","title":"Retail on Wheels: A Time-Sensitive Traveling Salesman Problem","content":"This paper investigates mobile retail operations, where stores are equipped with wheels, migrating and perching to serve customers at different locations. We provide a model that incorporates time-sensitive factors. We establish asymptotic analysis and managerial insights. Our findings demonstrate that mobility can potentially enhance profitability by improving customer proximity.","presenter":"Mr. Zhuolun Dong","authors":[{"name":"Mr. Zhuolun Dong","aff":"Student, University of Texas Austin"},{"name":"Dr. Junyu Cao","aff":"Assistant Professor, University of Texas Austin"},{"name":"Dr. Wei Qi","aff":"Associate Professor, Tsinghua University"}],"order":5}]},{"id":"s360","title":"HOCM Best Paper Competition","track":"Humanitarian Operations and Crisis Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"GRAND HALL EAST B","chairs":["Prof. Irineu de Brito Junior"],"abstracts":[{"id":"136-0330","title":"A Little Goes a Long Way: How Investments Boost Volunteer Productivity","content":"Using data from the Humanitarian OpenStreetMap Team's Community Microgrant Program, we find that upfront investments boost volunteer contributions nearly tenfold. Our findings also show that to maximize impact in developing countries, non-profit organizations should prioritize investments that also improve volunteers' livelihoods (e.g., providing technology or financial stipends).","presenter":"Dr. Eunae Yoo","authors":[{"name":"Dr. Eunae Yoo","aff":"Assistant Professor, Indiana University Bloomington"},{"name":"Dr. Gloria Urrea","aff":"Assistant Professor, University of Colorado Boulder"}],"order":1},{"id":"136-1065","title":"A behavior-driven framework for shelter network design and evacuation planning problem: An application to Haiti","content":"In collaboration with the World Bank, we present a decision-support tool for shelter network design and evacuation planning using bi-level optimization framework. The model incorporates evacuees' utility function based on the Fogg Behavior Model and adapts to disaster evolution through a Flood Evolution Index, enabling authorities to make behavior-driven decisions","presenter":"Ms. Maedeh Sharbaf","authors":[{"name":"Ms. Maedeh Sharbaf","aff":"Student, Massachusetts Institute of Technology"},{"name":"Dr. Marie-Eve Rancourt","aff":"Associate Professor, HEC Montréal"},{"name":"Dr. Valérie Bélanger","aff":"Associate Professor, HEC Montréal"}],"order":2},{"id":"136-0134","title":"Optimal Policies for Supermarket Donation of Perishables with Profit and Waste Considerations under Demand Uncertainty","content":"This study optimizes supermarket donation strategies for perishable products with uncertain demand, with the objective of maximizing profit. We also demonstrate that, under certain conditions, our proposed policy effectively reduces food waste throughout the entire food bank supply chain and outperforms existing policies, such as no-donation and last-minute donation strategies.","presenter":"Ms. Shabnam Salehi","authors":[{"name":"Ms. Shabnam Salehi","aff":"Student, The University of Alabama"},{"name":"Dr. Irem Sengul Orgut","aff":"Assistant Professor, University of Alabama"},{"name":"Dr. Emmett Lodree","aff":"Professor, University of Alabama Tuscaloosa"}],"order":3},{"id":"136-0820","title":"Dynamic Relief Provision Planning for En Route Refugee: Shaping Probabilistic Movements Using Migration Pull Drivers","content":"The number of internationally displaced refugees has alarmingly reached 37.9 million individuals by 2024. Massive refugee movements force them into dire living conditions with inaccessibility to essential resources. We study a dynamic optimization problem to cost-efficiently optimize periodic and equitable relief provisioning via capacitated mobile facilities for migrating refugee groups.","presenter":"Mr. Amirreza Pashapour","authors":[{"name":"Mr. Amirreza Pashapour","aff":"Student, Koç University"},{"name":"Dr. Dilek Gunnec","aff":"Associate Professor, Ozyegin University"},{"name":"Prof. F. Sibel Salman","aff":"Professor, Koc University"},{"name":"Dr. Eda Yucel","aff":"Associate Professor, TOBB University of Economics and Technology"}],"order":4}]},{"id":"s368","title":"College of Healthcare Operations Management (CHOM) Best Paper Competition","track":"Healthcare Analytics","type":"Regular","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"GRAND HALL EAST D","chairs":["Dr. Ebru Bish","Dr. Xin Ding"],"abstracts":[{"id":"136-2103","title":"Machine Learning-Guided Cancer Screening: Benefits of Proactive Care","content":"We study the real-world effects of a machine learning-guided colorectal cancer screening program deployed at a health system in Pennsylvania. Utilizing a regression discontinuity design based on the predicted risk score for having cancer, we evaluate the causal effects of the program on screening uptake and patient mortality.","presenter":"Prof. Minje Park","authors":[{"name":"Prof. Minje Park","aff":"Assistant Professor, The University of Hong Kong"},{"name":"Prof. Carri Chan","aff":"Assistant Professor, Columbia University"},{"name":"Dr. Keith Boell","aff":"Chief Quality Officer / Geisinger, Geisinger"},{"name":"Dr. Elliot Mitchell","aff":"Senior Data Scientist, Geisinger"},{"name":"Dr. Abdul Tariq","aff":"Associate Vice President (Data Science), Children’s Hospital of Philadelphia"}],"order":1},{"id":"136-2106","title":"Telehealth’s Double-Edged Sword: Hidden Costs of Expanding Virtual Access to Care","content":"Leveraging the variation in telehealth adoption rates during the COVID-19 pandemic across various specialties of a major health system, we show that telehealth’s potential to expand access may come at the cost of less time per patient, increased workload for physicians, and revenue losses for healthcare organizations.","presenter":"Mr. Masoud Kamalahmadi","authors":[{"name":"Mr. Masoud Kamalahmadi","aff":"Assistant Professor, Miami Herbert Busienss School"},{"name":"Prof. Jong Myeong Lim","aff":"Assistant Professor, Miami Herbert Busienss School"}],"order":2},{"id":"136-2104","title":"Optimizing Surveillance Protocols for Hospital-Acquired Infections Case of MRSA","content":"Roommates of nosocomial methicillin-resistant Staphylococcus aureus cases are isolated and undergo surveillance testing. But, the optimal post-exposure surveillance testing method and timing are unknown. We develop a MDP model to optimize the testing decisions for roommates of MRSA cases in hospitals to minimize the loss of quality-adjusted life years.","presenter":"Ms. Esma Akgun","authors":[{"name":"Ms. Esma Akgun","aff":"Student, University of Waterloo"},{"name":"Dr. F. Erenay","aff":"Assistant Professor, University of Waterloo"},{"name":"Dr. Sibel Alumur Alev","aff":"Associate Professor, University of Waterloo"}],"order":3},{"id":"136-2105","title":"Small Area Estimation of Case Growths for a Timely COVID-19 Outbreak Detection","content":"A fundamental challenge in COVID-19 outbreak detection is balancing the accuracy versus speed tradeoff for small sample size estimation. We develop an algorithm, Transfer Learning Generalized Random Forest (TLGRF), which balances this tradeoff.","presenter":"Dr. Zhaowei She","authors":[{"name":"Dr. Zhaowei She","aff":"Assistant Professor, Singapore Management University"},{"name":"Mr. Zilong Wang","aff":"Student, Georgia Institute of Technology"},{"name":"Dr. Jagpreet Chhatwal","aff":"Associate Professor, Harvard University"},{"name":"Prof. Turgay Ayer","aff":"Professor, Georgia Tech"}],"order":4}]},{"id":"s393","title":"AI and Learning","track":"Empirical Research in Operations Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"EMBASSY B","chairs":["Mr. Michael Mertel"],"abstracts":[{"id":"136-0064","title":"Blockchain-Enabled Transparency and Adaptability in Sustainable Supply Chains","content":"This study examines how blockchain, combined with circular economy principles and digital ecosystems, enhances supply chain adaptability and sustainability. The findings highlight significant improvements in performance, resource efficiency, and carbon footprint reduction, offering practical insights for managers and policymakers aiming to achieve sustainability goals in modern supply chains.","presenter":"Mr. Shafiul Bashar","authors":[{"name":"Mr. Shafiul Bashar","aff":"Student, University of Science and Technology Beijing"},{"name":"Prof. Daoping Wang","aff":"Professor, University of Science and Technology Beijing"},{"name":"Mrs. Marwah Rafiq","aff":"Student, University of Science and Technology Beijing"}],"order":1},{"id":"136-0441","title":"Human-Artificial Intelligence Collaboration: An Experimental Design","content":"Human-artificial intelligence (AI) collaboration has the potential to transform operations. Managers have varying levels of willingness to use AI technologies based on their operations and supply chains. This study examines how factors like anthropomorphism, accuracy, social interaction, job insecurity, and cost influence the managers willingness to use AI technologies.","presenter":"Mr. Nagendra kumar","authors":[{"name":"Mr. Nagendra kumar","aff":"Student, IIM Ranchi"},{"name":"Prof. Rajeev Kumar","aff":"Assistant Professor, Indian Institute of Management Ranchi"}],"order":2},{"id":"136-0848","title":"Integrating blockchain and IoT for sustainability","content":"This study examines how blockchain-based IoT systems promote resource efficiency by analyzing three real-world implementations. In a socio-technical systems approach, we detail their system architecture across key areas and offer actionable recommendations for designing blockchain-based IoT systems to address the growing urgency for resource efficiency.","presenter":"Mr. Michael Mertel","authors":[{"name":"Mr. Michael Mertel","aff":"Student, Friedrich-Alexander Universitat Erlangen-Nurnberg"},{"name":"Ms. Hannah Altenburg","aff":"Post Doc/Researcher, Friedrich-Alexander Universitat Erlangen-Nurnberg"},{"name":"Prof. Julian Marius Müller","aff":"Student, Friedrich-Alexander Universitat Erlangen-Nurnberg"},{"name":"Prof. Kai-Ingo Voigt","aff":"Professor, Friedrich-Alexander Universitat Erlangen-Nurnberg"}],"order":3},{"id":"136-1727","title":"Student Performance Across Different Course and Assessment Modalities","content":"We analyzed student performances across online, in-person and hybrid course formats, and proctoring tests. We identify patterns based on the data collected from decision science and operations management courses for six years. We discuss the implications of the findings towards achieving equivalency in learning outcomes across course modalities.","presenter":"Dr. Vishwanath Hegde","authors":[{"name":"Dr. Vishwanath Hegde","aff":"Professor, California State University East Bay"},{"name":"Dr. Zinovy Radovilsky","aff":"Professor, California State University East Bay"}],"order":4}]},{"id":"s395","title":"Empirical Research in Sustainable Supply Chains","track":"Sustainable Operations Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"EMBASSY G","chairs":["Ms. IBTISAAMA AHMED"],"abstracts":[{"id":"136-0934","title":"Supplier Environmental Stewardship: Unraveling Buyer-Supplier Dynamics Through Social Contagion Theory Perspective","content":"This study investigates contagion effects in supply chains, examining how buyers influence suppliers' environmental sustainability. Using Social Contagion Theory and analyzing 678 buyer-supplier dyads, it reveals conditional effects: buyer performance fosters supplier improvement when dependency is high, while ESG risks weaken positive impacts. Insights advance sustainability management practices.","presenter":"Dr. Fei (Sophie) Song","authors":[{"name":"Dr. Prabhjot Mukandwal","aff":"Assistant Professor, Wayne State University"},{"name":"Mr. Laharish Guntuka","aff":"Assistant Professor, Rochester Institute of Technology"},{"name":"Dr. Fei (Sophie) Song","aff":"Assistant Professor, Bowling Green State University"}],"order":1},{"id":"136-1949","title":"A Network Approach to Scope 3 Emissions","content":"We present a network-based methodology for estimating Scope 3 emissions by combining Scope 1, Scope 2, and B2B transaction data. In an empirical application, our method obtains higher results than 60% of companies in our sample (2010–2021). We discuss the error bounds of the estimation and potential applications.","presenter":"Mr. Nicolas Romero Diaz","authors":[{"name":"Mr. Nicolas Romero Diaz","aff":"Student, Vlerick Business School"},{"name":"Dr. Maximiliano Udenio","aff":"Associate Professor, KU Leuven"},{"name":"Prof. David Veredas","aff":"Professor, Vlerick Business School"},{"name":"Mr. Wim Van Hyfte","aff":"Global Head of ESG Investments &amp; Research, Candriam"}],"order":2},{"id":"136-1894","title":"Harnessing Renewable Portfolio Standards for Sustainable Futures: An Empirical Examination of Spillover Effects","content":"Public policy designs must work in lockstep with firms’ environmental policies if they are to play a vital role in mitigating greenhouse gas (GHG) emissions. We examine the causal effects of state-level policies on firm-level GHG emissions, particularly emphasizing the spillover effects of policies on unregulated firms in different markets.","presenter":"Ms. Chunjie Zhao","authors":[{"name":"Ms. Chunjie Zhao","aff":"Student, Clark University"},{"name":"Prof. Anqi Wu","aff":"Assistant Professor, Florida International University"},{"name":"Dr. Ramanath Subramanyam","aff":"Associate Professor, University of Illinois Urbana-Champaign"}],"order":3},{"id":"136-0901","title":"PARENT SIGNALING AND FACILITY OPERATIONS: HOW FIRMS USE THEIR NETWORK OF FACILITIES TO GREENWASH.","content":"This study looks at how firms use their network of facilities to greenwash. It highlights not only facility sustainable operations, but also, parent firms strategic use of facilities depending on their characteristics. My dataset is a merge of the EPA data, compustat financials, and SEC 10K filings.","presenter":"Ms. IBTISAAMA AHMED","authors":[{"name":"Ms. IBTISAAMA AHMED","aff":"Student, GEORGIA SOUTHERN UNIVERSITY"}],"order":4}]},{"id":"s403","title":"Topics in Sustainable Operations","track":"Sustainable Operations Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"GRAND HALL EAST C","chairs":["Dr. Zakaria El Hathat"],"abstracts":[{"id":"136-1167","title":"Analyzing the effects of knowledge management on organizational performance through knowledge utilization and sustainability","content":"This study explores the relationship between knowledge management, knowledge utilization, sustainability, and organizational performance. The results of the theoretical model indicate that knowledge utilization and sustainability fully mediate the relationship between KM and performance. They have direct and positive effects on organizational performance while being positively influenced by KM.","presenter":"Mrs. Faezeh Mohaghegh","authors":[{"name":"Mrs. Faezeh Mohaghegh","aff":"Student, Washington State University Pullman"},{"name":"Dr. Halil Zaim","aff":"Associate Professor, Alfred University"},{"name":"Dr. Valid Dzenopoljac","aff":"Associate Professor, Zayed University"},{"name":"Dr. Aleksandra Dženopoljac","aff":"Academic manager, SP Jain School of Global Management"},{"name":"Dr. Nick Bontis","aff":"Vice president, CONCACAF"}],"order":1},{"id":"136-0829","title":"Eco-Synergy: Modelling the Green Path to Sustainable Business","content":"This work examines the moderating effect of environmental factors on sustainable business practices as supported by Structural Equation Modeling of data collected from 804 participants representing 15 manufacturing firms. This study elicits that regulation, economic motives, culture, and technology determine sustainability. Suggestions provided are aimed at improving sustainability management plans.","presenter":"Dr. Mani Venkatesh","authors":[{"name":"Dr. Kottala Sri Yogi","aff":"Assistant Professor, Symbiosis Institute of Business Management, Hyderabad"},{"name":"Dr. Shankar Chanagala","aff":"Assistant Professor, GITAM Business School Hyderabad"},{"name":"Dr. Mani Venkatesh","aff":"Associate Professor, University of Manitoba"}],"order":2},{"id":"136-0146","title":"Impatience in e-commerce purchasing? A construal-level theory approach for environmental and self-versus-others priming","content":"This study applies construal level theory to explore how purchasing for oneself versus others, along with environmental priming, influences the degree and type of impatience in online shoppers. It also examines how the interaction effect between environmental priming and buying for oneself versus others affects impatience degree and type.","presenter":"Dr. Jiayuan Zhang","authors":[{"name":"Dr. Jiayuan Zhang","aff":"Assistant Professor, University of Wisconsin-Whitewater"},{"name":"Dr. Sundarraj Rangaraja","aff":"Professor, Indian Institute of Technology Madras"},{"name":"Dr. Venkataraghavan Krishnaswamy","aff":"Associate Professor, Indian Institute of Management, Tiruchirapalli"}],"order":3},{"id":"136-0767","title":"Strategic Responses to Government Loan Programs: Green Technology Startups in Competitive Markets","content":"This study examines how government loans influence the behavior of startups in green industries, particularly under varying competitive conditions. The research offers actionable insights for designing effective policies that promote long-term sustainability. Furthermore, the findings contribute to an understanding of how startups adapt their strategies to navigate competitive pressures.","presenter":"Ms. Huizi Yan","authors":[{"name":"Ms. Huizi Yan","aff":"Student, Yonsei University"},{"name":"Dr. Seung Hwan Jung","aff":"Assistant Professor, Yonsei University"}],"order":5},{"id":"136-1645","title":"Understanding Public Perceptions of Space Mining: A Data Mining Approach","content":"This study leverages advanced data mining techniques to analyze public perceptions of space mining on Facebook. We identify key themes and engagement drivers by examining a large dataset of posts. Our findings offer valuable insights for industry stakeholders to develop sustainable operations management strategies for space resource utilization.","presenter":"Dr. Zakaria El Hathat","authors":[{"name":"Dr. Zakaria El Hathat","aff":"Assistant Professor, Rabat Business School, International University of Rabat"},{"name":"Dr. Raja Sreedharan","aff":"Senior Lecturer, CARDIFF METROPOLITAN UNIVERSITY"},{"name":"Dr. Tarik Zouadi","aff":"Associate Professor, Rabat Business School, International University of Rabat"}],"order":6}]},{"id":"s407","title":"Advancing Operational Excellence in Services","track":"Operational Excellence","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"INMAN","chairs":["Mr. Zhikun Lu"],"abstracts":[{"id":"136-1850","title":"The Value of Last-Mile Delivery in Online Retail","content":"We study the value of last-mile delivery via a quasi-experiment with Alibaba. Using staggered DiD, we found home delivery significantly increased customer spending. To optimally utilize delivery capacity, we leverage causal AI to target the most valuable customers under capacity and fairness constraints, maximizing business profits without compromising social equity.","presenter":"Mr. Zhikun Lu","authors":[{"name":"Mr. Zhikun Lu","aff":"Student, Emory University"},{"name":"Prof. Ruomeng Cui","aff":"Professor, Emory University"},{"name":"Prof. Tianshu Sun","aff":"Professor, Cheung Kong Graduate School of Business"},{"name":"Mr. Lixia Wu","aff":"Data Scientist, Alibaba Group"}],"order":1},{"id":"136-0992","title":"Discretion in Automated Supermarket Replenishment: Censorship Bias and Self-inflicted Stockouts","content":"Censorship bias may cause a paradox in which decision-makers order less than algorithmic suggestions after a stockout. We examine the stockout implications of this bias by using data from a supermarket chain. By accounting for the endogeneity, we show that censorship bias is as prevalent as anchoring bias.","presenter":"Dr. Bengu Ozdemir","authors":[{"name":"Dr. Bengu Ozdemir","aff":"Assistant Professor, University of Wisconsin-Whitewater"},{"name":"Dr. Antti Tenhiala","aff":"Associate Professor, IE BUSINESS SCHOOL"}],"order":2},{"id":"136-1001","title":"The impact of hospital unit closure on operational performance in proximal hospitals","content":"We use claims-level unbalanced panel-data over an 8-year period (2013-2020) from 222 New York State hospitals to examine the effect of hospital-unit closure on other proximal hospitals’ performance. We also explore variables that moderate the effect","presenter":"Ms. Minjeong Kang","authors":[{"name":"Ms. Minjeong Kang","aff":"Student, University of Minnesota"},{"name":"Prof. Rachna Shah","aff":"Professor, University of Minnesota"}],"order":3},{"id":"136-0983","title":"Does Machine Learning Help Flights Depart On Time?","content":"This study evaluates the impact of AI-driven ML tools on airlines’ operational performance. Our research focuses on the first AI-driven ML platform in the airline industry. Using a Difference-in-Differences approach, the findings reveal a significant 19.6% reduction in departure delays, showcasing its operational benefits.","presenter":"Ms. Rang Gong","authors":[{"name":"Ms. Rang Gong","aff":"Student, Ohio State University"},{"name":"Dr. Xiang Wan","aff":"Associate Professor, Ohio State University"}],"order":4}]},{"id":"s411","title":"Digital Transformation and Smart Healthcare Systems","track":"Healthcare Operations Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"PIEDMONT","chairs":["Dr. Rajib Dutta"],"abstracts":[{"id":"136-1683","title":"INDUSTRY 4.0 IS IN THE HOSPITAL. DIGITAL TWINS IN HEALTH – INITIATIVES AND APPLICATIONS","content":"This study is a systematic review of Digital Twin in Smart Hospital. The results contribute to understanding the potential of this innovation technology in 4.0 Health Industry. The final Framework is a big deal for equity in health, it contributes to 3 from 17 Sustainable Development Goals (SDGs).","presenter":"Mr. ENIDO Ramos","authors":[{"name":"Mr. ENIDO Ramos","aff":"Student, unicamp"},{"name":"Dr. Ieda Makiya","aff":"Professor, Unicamp"},{"name":"Dr. Francisco Cesar","aff":"Professor, Instituto Federal de São Paulo - IFSP"}],"order":1},{"id":"136-1391","title":"Rethinking Healthcare: Virtual Care Centers and Service Redesign in a Digital Era","content":"Digitalization has a major impact on healthcare operations and redefines the jobs of healthcare professionals and healthcare delivery for patients. Through an in-depth investigation of the introduction of a Dutch hospital’s virtual care center, we highlight how it triggers the (re-)design and development of new and existing healthcare services.","presenter":"Dr. Vincent Peters","authors":[{"name":"Dr. Vincent Peters","aff":"Assistant Professor, Department of Information Systems and Operations Management"},{"name":"Mr. Tom Aben","aff":"Post Doc/Researcher, Department of Information Systems and Operations Management"}],"order":3},{"id":"136-0562","title":"Healthcare Digital Transformation: Configurations for the management of digital resources","content":"The article addresses how hospitals manage digital resources to foster healthcare digital transformation. Through qualitative case studies in three hospitals (private, public, and research-oriented), we explore the implementation of different strategies. Our findings reveal distinct digital resource management configurations aligned with each hospital's business model.","presenter":"Mr. Lucas Miguel Correia","authors":[{"name":"Mr. Lucas Miguel Correia","aff":"Student, Federal University of Rio Grande do Sul"},{"name":"Prof. Alejandro Frank","aff":"Professor, Federal University of Rio Grande do Sul"}],"order":5},{"id":"136-1298","title":"Examining the effects of RTLS in Hospitals: The moderating role of operational complexity","content":"Real-time location systems (RTLS) can help healthcare organizations to improve efficiency and reduce cost by facilitating real-time tracking of inventory, equipment, personnel, and patients. We analyze 12,129 hospital-year observations and show that RTLS enables hospitals to reduce inventory per bed. Detailed results and implications will be discussed at the conference.","presenter":"Dr. Rajib Dutta","authors":[{"name":"Dr. Rajib Dutta","aff":"Assistant Professor, Miami University"},{"name":"Dr. David Dobrzykowski","aff":"Professor, University of Arkansas - Fayetteville"},{"name":"Dr. Randy Bradley","aff":"Associate Professor, University of Tennessee"}],"order":7}]},{"id":"s438","title":"Impact of AI and Analytics on Decision Making","track":"Data Science, Analytics and AI","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"ROSWELL","chairs":["Prof. Mo Liu"],"abstracts":[{"id":"136-0803","title":"Impact of Bullet Screen Comments in Small Livestreams on Consumer Purchase Intention","content":"Small livestreams have low influence, but slower bullet screen comments are more easily noticed by consumers. Using the Bayesian topic modeling algorithm, we analyze the thematic content of bullet screen comments in small livestreams and explore the mechanism through which these comments affect consumer purchase intention.","presenter":"Ms. Jingrong Li","authors":[{"name":"Ms. Jingrong Li","aff":"Student, Renmin University of China"}],"order":1},{"id":"136-1979","title":"Achieving Robust Data-driven Contextual Decision Making in a Data Augmentation Way","content":"This paper focuses on CO problem, where covariates can be exploited to reduce the uncertainty. We train a robust decision rule for the problem through a DRO model. And we use a data augmentation based SGD method to solve and find optimal decision rules.","presenter":"Mr. Zhaoen Li","authors":[{"name":"Mr. Zhaoen Li","aff":"Student, Tsinghua University"},{"name":"Dr. Maoqi Liu","aff":"Assistant Professor, School of Management, Shandong University"},{"name":"Prof. Zhi-Hai Zhang","aff":"Associate Professor, Tsinghua University"}],"order":2},{"id":"136-1757","title":"Rapid response to changing decision-making environments: A diffusion model-based optimization approach","content":"Responsiveness and flexibility are essential in decision-making, with responsiveness requiring quick solutions and flexibility demanding adaptation to changing environments. Novel learning-based approaches offer speed but struggle with dynamic decision environments. Therefore, we propose a diffusion model-inspired method that balances responsiveness and flexibility, generating sub-gradients for feasible solutions without requiring retraining.","presenter":"Mr. Xianzhe Wang","authors":[{"name":"Mr. Xianzhe Wang","aff":"Student, Beijing University of Chemical Technology"}],"order":3},{"id":"136-0713","title":"Active Learning For Contextual Linear Optimization: A Margin-Based Approach","content":"We develop the first active learning algorithm for the contextual linear optimization. Specifically, we develop a learning method that sequentially decides whether to request the ``labels'' of feature samples from an unlabeled data stream, where the labels correspond to the parameters of an optimization model for linear programming.","presenter":"Prof. Mo Liu","authors":[{"name":"Prof. Mo Liu","aff":"Assistant Professor, University of North Carolina at Chapel Hill"},{"name":"Prof. Paul Grigas","aff":"Associate Professor, University of California, Berkeley"},{"name":"Dr. Heyuan Liu","aff":"Research Scientist, Industrial engineering"},{"name":"Prof. Max Shen","aff":"Professor, University of Hongkong"}],"order":4}]},{"id":"s448","title":"AI AGE – Transforming Commercial Pharmaceutical Functions with Artificial Intelligence","track":"Information Systems and Operations Management","type":"Tutorial","invited":"Invited","date":{"iso":"2025-05-10","dow":"Saturday","day":10,"mon":"May"},"start":"4:00 PM","end":"5:30 PM","startMin":960,"room":"UNIVERSITY","chairs":["Mr. Ankit Kohli","Dr. Shubham Gupta"],"abstracts":[{"id":"136-2140","title":"AI AGE – Transforming Commercial Pharmaceutical Functions with Artificial Intelligence","content":"The pharmaceutical industry is at a pivotal moment, driven by AI-led innovations that are redefining commercial functions. AI AGE (Artificial Intelligence, Automation, and Generative Experiences) is revolutionizing the way pharma companies engage with healthcare professionals. This session will explore how AI-powered insights, automation, and GenAI are reshaping key commercial operations.","presenter":"Mr. Ankit Kohli","authors":[{"name":"Mr. Ankit Kohli","aff":"AI Leader, ."}],"order":1}]},{"id":"s11","title":"Promoting Access in Essential Services and Platforms","track":"POM and Community","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY F","chairs":["Dr. Soh Hyun Chu"],"abstracts":[{"id":"136-0057","title":"Enhancing Access to Family Planning Services: Challenges and Opportunities for OM Research","content":"Providing access to family planning services is a \"development best-buy\". However, more than 200 million women have an unmet need for modern contraceptives, especially in rural areas. In this talk, we discuss the barriers in addressing this gap and how OM research can contribute.","presenter":"Dr. Harwin De Vries","authors":[{"name":"Dr. Harwin De Vries","aff":"Associate Professor, Rotterdam School of Management"}],"order":1},{"id":"136-0206","title":"Platform Design with Prosocial Participants: Lessons from 412Connect","content":"In this study we consider some of the challenges Black-owned businesses face and design a platform facilitates interactions between student users and participating businesses. We describe the project from its conception, paying special attention to our motivations, community ties, design choices, and new theory that was needed.","presenter":"Prof. Michael Hamilton","authors":[{"name":"Mr. Alex Dichristofano","aff":"Student, Washington University in St Louis"},{"name":"Prof. Michael Hamilton","aff":"Assistant Professor, University of Pittsburgh"},{"name":"Ms. Qiqi Hao","aff":"Student, University of Pittsburgh"},{"name":"Prof. Sera Linardi","aff":"Associate Professor, University of Pittsburgh"}],"order":2},{"id":"136-0232","title":"The Impact of Virtual Visit Adoption on Ambulatory Care Utilization and Patient Health Outcomes","content":"This study evaluates virtual visit adoption within ambulatory care. We find that virtual visits replace some in-person appointments without increasing total visits, and reduce ER visits and hospitalizations. Notably, there is significant effect heterogeneity with respect to a patient’s race, socioeconomic status, and gender, where some underserved populations benefit disproportionately.","presenter":"Mrs. Jane Iversen","authors":[{"name":"Mrs. Jane Iversen","aff":"Student, Ohio State University"},{"name":"Dr. Yingchao Lan","aff":"Assistant Professor, University of Nebraska Lincoln"},{"name":"Prof. Aravind Chandrasekaran","aff":"Professor, Ohio State University"}],"order":3}]},{"id":"s18","title":"Optimally Serving Communities Through POM","track":"POM and Community","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY E","chairs":["Prof. Vanitha Virudachalam"],"abstracts":[{"id":"136-0148","title":"Gender Diversity in Rural Water Management","content":"In rural Africa, people rely on communal handpumps for clean drinking water. They are managed through an informal governance structure known as Water User Committee (WUC). In this project we investigate the role of WUC gender composition impact handpump functionality.","presenter":"Prof. Chengcheng Zhai","authors":[{"name":"Prof. Chengcheng Zhai","aff":"Assistant Professor, Mendoza College of Business"},{"name":"Dr. Kaitlin Wowak","aff":"Associate Professor, University of Notre Dame"}],"order":2},{"id":"136-0439","title":"Raising the Rainbow Flag: Impact of LGBTQ+ Safety Cues on Service Provider Selection","content":"We consider service settings in which clients choose their best-suited service provider based on information about the provider’s attributes. We aim to understand how inclusion of information about provider’s support of the LGBTQ+ community—in the form of safety cues such as a rainbow flag—impacts the client’s selection process.","presenter":"Dr. Priyank Arora","authors":[{"name":"Dr. Priyank Arora","aff":"Associate Professor, University of South Carolina"},{"name":"Dr. Mert Cetin","aff":"Assistant Professor, Rotterdam School of Management"},{"name":"Prof. Dorothee Honhon","aff":"Associate Professor, University of Texas Dallas"}],"order":3},{"id":"136-0717","title":"30 Million Canvas Grading Records Reveal Widespread Sequential Bias and System-Induced Surname Initial Disparity","content":"We present an analysis of over 30 million Canvas grading records, revealing a significant bias in sequential grading. Furthermore, we show that the system design of Canvas, which pre-orders submissions by student surnames, transforms the sequential bias into a significant disadvantage for students with alphabetically lower-ranked surname initials.","presenter":"Mrs. Zhihan (Helen) Wang","authors":[{"name":"Mrs. Zhihan (Helen) Wang","aff":"Student, University of Michigan, Ann Arbor"},{"name":"Mr. Jiaxin Pei","aff":"Student, University of Michigan"},{"name":"Prof. Jun Li","aff":"Associate Professor, Ross School of Business"}],"order":4}]},{"id":"s22","title":"Emerging Topics in Supply Chain Management","track":"Manufacturing Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"LENOX","chairs":["Mr. Shiwei Chai"],"abstracts":[{"id":"136-0939","title":"Privacy-Preserving Recommendation Game: The strategic role of ambiguity","content":"We examine cohort-based privacy protection, where platforms use consumer rankings of sellers to provide personalized recommendations. This approach encourages consumers to share preferences more willingly by reducing price discrimination and helping them find better-aligned choices. For platforms and sellers, increased sharing boosts demand, while privacy-preserving recommendations ease competition between sellers.","presenter":"Mr. Yuxin Liu","authors":[{"name":"Mr. Yuxin Liu","aff":"Student, University of Pittsburgh"},{"name":"Dr. Jiong Sun","aff":"Associate Professor, Purdue University"}],"order":1},{"id":"136-1144","title":"Generalized Traffic Equilibrium with Ride-hailing and Customer Waiting","content":"We develop a generalized traffic equilibrium model that considers ride-hailing services such as Uber and Lyft and the queueing dynamics that explicitly capture customer waiting. Existence of an equilibrium is derived under mild conditions, which classical queueing models happen to satisfy. The proposed model is validated using the Sioux-Falls network.","presenter":"Mr. Wei Gu","authors":[{"name":"Mr. Wei Gu","aff":"Student, University of Southern California"}],"order":2},{"id":"136-1162","title":"Contextual Dynamic Pricing: Algorithms, Optimality, and Local Differential Privacy","content":"We study the contextual dynamic pricing problem where a firm sells products to sequentially arriving consumers that behave according to an unknown demand model. The demand model is a GLM with a d-dimensional feature vector. We show the optimal regret bound is O(sqrt(dT)). We further study the problem under privacy.","presenter":"Prof. Zifeng Zhao","authors":[{"name":"Prof. Zifeng Zhao","aff":"Assistant Professor, University of Notre Dame"}],"order":3},{"id":"136-0666","title":"Enhancing Make-to-Order Manufacturing Agility: When Flexible Capacity Meets Dynamic Pricing","content":"We study a make-to-order production environment with base and surge capacity as well as the ability to adjust product pricing. An interesting interplay between the capacity adjustment and the dynamic pricing is discovered: price may not monotonically increase in congestion level when capacity adjustment incurs a fixed cost.","presenter":"Mr. Shiwei Chai","authors":[{"name":"Dr. Xu Sun","aff":"Assistant Professor, University of Miami Business School"},{"name":"Mr. Shiwei Chai","aff":"Student, University of Florida"},{"name":"Dr. Anand Paul","aff":"Professor, University of Florida"},{"name":"Prof. Lingjiong Zhu","aff":"Associate Professor, Florida State University"}],"order":4}]},{"id":"s27","title":"Learning from Humanitarian Operations Management Research","track":"Humanitarian Operations and Crisis Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"GRAND HALL EAST B","chairs":["Marianne Jahre","Dr. Mojtaba Salem"],"abstracts":[{"id":"136-0366","title":"The Least Painful Option: Responders’ Preferences for the Allocation of Scarce Relief Items","content":"Scarce relief items must be allocated to the beneficiaries following every disaster, which confronts decision-makers with the suffering of those who could not receive them. Conducting an experiment with field responders, we find that the pain arising from criticality of items, and the proximity to the beneficiaries influence decision-making.","presenter":"Prof. Prisca Brosi","authors":[{"name":"Dr. Minlian Wu","aff":"Post Doc/Researcher, University of Science and Technology of China"},{"name":"Prof. Prisca Brosi","aff":"Associate Professor, Kuehne Logistics University"},{"name":"Prof. Maria Besiou","aff":"Professor, Kuehne Logistics University"}],"order":1},{"id":"136-0529","title":"On the interface of law and humanitarian logistics","content":"In this paper, through a series of interviews, we explore how law and legal frameworks impact humanitarian logistics and how each party (law professionals and humanitarian logisticians) views the other. Our findings open a window to an unexplored area of humanitarian operations management.","presenter":"Prof. Nezih Altay","authors":[{"name":"Dr. Isabell Storsjö","aff":"Post Doc/Researcher, University of Turku"},{"name":"Prof. Nezih Altay","aff":"Professor, Depaul University"},{"name":"Prof. Gyöngyi Kovács","aff":"Professor, HUMLOG Institute"}],"order":2},{"id":"136-1086","title":"Future Research Trends in Humanitarian Operations Management","content":"This presentation explores future research trends in humanitarian operations management from an analytics perspective.","presenter":"Prof. Alfonso Pedraza-Martinez","authors":[{"name":"Prof. Alfonso Pedraza-Martinez","aff":"Professor, Mendoza College of Business"}],"order":3},{"id":"136-1664","title":"How Humanitarian Logistics Can Inform the Fight Against Human Trafficking","content":"With an estimated 50 million victims around the world, Human Trafficking can -and should- be considered a humanitarian crisis. In this presentation, we explore how tools and methods developed for Humanitarian Logistics can inform and support the fight against this crime in the United States.","presenter":"Dr. Felipe Aros-Vera","authors":[{"name":"Dr. Felipe Aros-Vera","aff":"Associate Professor, Ohio University"}],"order":4}]},{"id":"s32","title":"Strategic Interactions in Retail and Healthcare: Approaches and Innovations","track":"POM-Economics Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"VININGS","chairs":["Dr. Eren Cil"],"abstracts":[{"id":"136-0684","title":"Design of Returnless Refunds in Online Retailing","content":"Online retailers often allow customers to return a product for a full refund, but sometimes benefit from letting customers keep the product while granting the refund, depending on the reverse logistics costs. We analyze the optimal structure of such a refund policy for a firm while considering strategic consumer behavior.","presenter":"Dr. Alireza Yazdani","authors":[{"name":"Dr. Alireza Yazdani","aff":"Assistant Professor, California State Polytech University Pomona"},{"name":"Dr. Eren Cil","aff":"Associate Professor, University of Oregon"},{"name":"Dr. Monire Jalili","aff":"Assistant Professor, Bentley University"},{"name":"Prof. Michael Pangburn","aff":"Professor, University of Oregon"}],"order":1},{"id":"136-0715","title":"Patient-Centric Innovation in Service Modalities for End-Stage Renal Disease","content":"We analyze a framework for offering dialysis at remote locations to ease travel for ESRD patients. Our study identifies conditions under which Medicare incentivizes mobile clinics through shared-savings policies and examines the trade-off between hospitalization costs and provider savings, highlighting scenarios where the provider may be worse off.","presenter":"Dr. Eren Cil","authors":[{"name":"Dr. Mona Jabbari","aff":"Assistant Professor, University of Colorado Colorado Springs"},{"name":"Dr. Eren Cil","aff":"Associate Professor, University of Oregon"},{"name":"Prof. Nagesh Murthy","aff":"Professor, University of Oregon"}],"order":2},{"id":"136-0944","title":"Data Transactions and Price Competition: The Role of Product Positioning Differences","content":"This paper develops a game-theoretic model to investigate data transactions between firms in Bertrand competition. The results show that greater product positioning differences increase data exchange volumes, which can soften competition. This research contributes to understanding the dynamics of data transactions and competitive strategies in contemporary markets.","presenter":"Mr. Changqing Zhuo","authors":[{"name":"Ms. Jiayue Wang","aff":"Student, Renmin University of China"},{"name":"Mr. Changqing Zhuo","aff":"Student, Renmin University of China"},{"name":"Dr. Shouwang Lu","aff":"Assistant Professor, Beijing Jiaotong University"},{"name":"Prof. Kanliang Wang","aff":"Professor, Renmin University of China"}],"order":3},{"id":"136-1896","title":"Speculative Market Dynamics using Classical Control Theory","content":"Speculative bubbles are driven by the interplay of current prices, future expectations, and risk perception. These features are functionally similar to those used in proportional-integral-derivative (PID) controllers. This paper brings classical control theory into economic systems modeling by proposing an endogenized behavioral PID controller framework to model speculative market dynamics.","presenter":"Dr. James Paine","authors":[{"name":"Dr. James Paine","aff":"Assistant Professor, Bucknell University"}],"order":4}]},{"id":"s52","title":"Current Topics in The Energy Transition","track":"Energy and Natural Resource Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"TECHWOOD","chairs":["Prof. Christian Kaps"],"abstracts":[{"id":"136-0021","title":"Multi-Storage: Power vs. Energy - When To Transition Between Storage Technologies","content":"We develop a model where a cost-minimizing utility considers co-investing in two distinct storage technologies - an energy-limited technology, like batteries, and a power-limited technology, like hydrogen - to be jointly used for load-shifting purposes, accounting also for their different efficiency levels.","presenter":"Prof. Christian Kaps","authors":[{"name":"Prof. Christian Kaps","aff":"Assistant Professor, Harvard Business School"},{"name":"Prof. Simone Marinesi","aff":"Assistant Professor, University of Pennsylvania"}],"order":1},{"id":"136-0023","title":"The Role of Driver Behavior and Interpretability in The Vehicle-to-Grid Market","content":"Electric vehicles (EVs) have the potential to provide distributed energy storage to the electric grid and allow for greater renewable capacity. However for EV drivers to participate, interpretability and driver behavior must be accounted for. In this work, we introduce a driver-focused dynamic optimization model that addresses these challenges.","presenter":"Ms. Leann Thayaparan","authors":[{"name":"Prof. Georgia Perakis","aff":"Professor, Massachusetts Institute of Technology"},{"name":"Ms. Leann Thayaparan","aff":"Assistant Professor, Johns Hopkins University Carey Business"}],"order":2},{"id":"136-1189","title":"Battery Operations in Electricity Markets: Strategic Behavior and Distortions","content":"We propose an analytically tractable model of price-making batteries in electricity markets. The profit-maximizing battery distorts decisions in 3 ways: quantity withholding, shift from day-ahead to real-time, and reduction in real-time responsiveness. Price of Anarchy is always between 9/8 and 4/3, so incentive misalignment is nontrivial but bounded.","presenter":"Mr. Jerry Anunrojwong","authors":[{"name":"Mr. Jerry Anunrojwong","aff":"Student, Columbia University"},{"name":"Prof. Santiago Balseiro","aff":"Associate Professor, Columbia University"},{"name":"Prof. Omar Besbes","aff":"Professor, Columbia University"},{"name":"Prof. Bolun Xu","aff":"Assistant Professor, Columbia University"}],"order":3}]},{"id":"s84","title":"Frontier topics in Innovation and Technology Management","track":"Product Innovation and Technology Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"COURTLAND","chairs":["Dr. Antoine Feylessoufi"],"abstracts":[{"id":"136-1190","title":"Cultures for Innovation","content":"This paper examines how organizations can create a culture where unknown and unpredictable novel innovations are pursued. Culture is an overlooked dimension of organizational innovation and we demonstrate the pivotal role that culture plays in successful innovation. We then explore how organizations can tailor their culture to maximize innovation.","presenter":"Prof. Rob Glew","authors":[{"name":"Prof. Rob Glew","aff":"Assistant Professor, Mcgill University"},{"name":"Dr. Jeremy Hutchison-Krupat","aff":"Associate Professor, University of Cambridge"}],"order":1},{"id":"136-1364","title":"Sunflowers' Souvenirs: Exploring the Effect of Visitor Engagement on Museum Shop Retail","content":"This study examines how visitor engagement with artworks influences souvenir purchasing at the Van Gogh Museum. Using visitor movement data and sales records, we demonstrate how interaction draw (breadth of engagement) and interaction immersion (depth of engagement) affect shop selection and purchase decisions, providing insights for optimizing museum retail strategies.","presenter":"Dr. Abhishek Deshmane","authors":[{"name":"Dr. Abhishek Deshmane","aff":"Assistant Professor, Georgia Institute of Technology"}],"order":2},{"id":"136-0849","title":"Does the blockchain matter in NFT adoption?","content":"This study explores whether the underlying blockchain influences NFT purchase decisions. Using a sequential mixed-methods approach, we interviewed and subsequently surveyed NFT owners. Our findings reveal which attributes of the underlying blockchain matter to users in their decision-making to purchase an NFT and provide novel insights into NFT adoption behavior.","presenter":"Mr. Michael Mertel","authors":[{"name":"Mr. Michael Mertel","aff":"Student, Friedrich-Alexander Universitat Erlangen-Nurnberg"}],"order":3}]},{"id":"s114","title":"Money at the bottom of the pyramid","track":"Empirical Research in Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY B","chairs":["Mr. Rakesh Allu","Ms. Deepanshi Bhardwaj"],"abstracts":[{"id":"136-0519","title":"Co-learning with new technology","content":"At the onset of a new payment system in India, we investigate the role of bank-agent and customer co-learning to adapt better to technology change. We use a granular transaction-level data of banking agents and transactional error rates.","presenter":"Ms. Deepanshi Bhardwaj","authors":[{"name":"Ms. Deepanshi Bhardwaj","aff":"Student, University College London"}],"order":1},{"id":"136-0811","title":"Unlocking the Operational Potential of Nanostores via a Buy-Now Pay-Later Program","content":"We study how Buy-Now Pay-Later (BNPL) trade credit can foster business performance for Base-of-Pyramid retail storekeepers, leveraging granular data from East Africa. By employing difference-in-difference estimators, we suggest that inclusive BNPL policies would better support cash-constrained retailers. With quantile treatment effect models, we show that BNPL can greatly benefit nanostores.","presenter":"Mr. Guan-Yuan Wang","authors":[{"name":"Mr. Guan-Yuan Wang","aff":"Student, Tilburg University"},{"name":"Prof. Jan Fransoo","aff":"Professor, Tilburg University"},{"name":"Dr. Han Oh","aff":"Assistant Professor, Tilburg University"}],"order":2},{"id":"136-1367","title":"Mobile Money Operations at the Bottom of the Pyramid","content":"This paper examines mobile money operations at the bottom of the pyramid, focusing on community service providers jointly managing cash and wallet inventories. We identify conditions under which coupling these inventories enhances or hinders efficiency, offering insights into optimizing operations for underserved communities through integrated versus independent inventory management.","presenter":"Prof. Jiatao Ding","authors":[{"name":"Prof. Jiatao Ding","aff":"Assistant Professor, Nanyang Technological University"},{"name":"Dr. Bhavani Shanker Uppari","aff":"Assistant Professor, Singapore Management University"}],"order":3},{"id":"136-1398","title":"Enhancing Mobile Money Service Levels Via Cross-Agent and Cross-Platform Pooling","content":"Mobile money growth relies on the success of the agents who facilitate the transactions. Using a mobile money platform's data, we explore the potential of cross-agent and cross-platform budget pooling to increase service levels. We compare this with traditional loans to agents from both a system and individual level.","presenter":"Dr. Chris Parker","authors":[{"name":"Prof. Jason Acimovic","aff":"Associate Professor, Penn State University State College"},{"name":"Dr. Karthik Balasubramanian","aff":"Assistant Professor, Howard University School of Business"},{"name":"Prof. David Drake","aff":"Assistant Professor, University of Colorado Boulder"},{"name":"Dr. Chris Parker","aff":"Associate Professor, Darden School of Business"}],"order":4}]},{"id":"s122","title":"Behavioral OM in the Workplace","track":"Behavioral Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY D","chairs":["Prof. Kris Ferreira","Mr. Matthew DosSantos DiSorbo"],"abstracts":[{"id":"136-0522","title":"Collaborating with AI vs humans: The impact on productivity and wellbeing","content":"The use of AI decision-support tools can benefit operational efficiency. However, it can also impact employee wellbeing. In this paper, we utilize human-subject lab experiments to examine how collaborating with an AI tool (versus a human co-worker) impacts both worker performance (quality, speed) and wellbeing.","presenter":"Prof. Tim Kraft","authors":[{"name":"Prof. Tim Kraft","aff":"Associate Professor, North Carolina State University"},{"name":"Prof. Shawn Mankad","aff":"Associate Professor, North Carolina State University"},{"name":"Dr. Eirini Spiliotopoulou","aff":"Associate Professor, Tilburg University"},{"name":"Prof. Yanchong Zheng","aff":"Professor, Massachusetts Institute of Technology"}],"order":1},{"id":"136-0446","title":"Consumer Responses to Time Limits","content":"Prior research shows that time limits optimize company revenue because of decreases in service time variance, assuming that customers seek to maximize their utilities accounting for both their own and others’ actions. We experimentally test these assumptions and explore how any behavioral shifts impact service relationships.","presenter":"Dr. Michelle Kinch","authors":[{"name":"Dr. Michelle Kinch","aff":"Assistant Professor, Dartmouth College"},{"name":"Prof. Pnina Feldman","aff":"Associate Professor, Darden School of Business"},{"name":"Dr. Ella Segev","aff":"Professor, The Hebrew University of Jerusalem"}],"order":2},{"id":"136-1672","title":"The Impact of Precision on Improving Human Sequential Decision-Making","content":"We investigate how AI-based recommendation systems influence sequential decision-making, using a virtual electric vehicle driving game to study charging decisions under uncertainty. Experimental results reveal how humans respond to recommendations and learn over time. Insights inform the design of adaptive systems that account for deviations, enhancing long-term decision-making efficiency.","presenter":"Prof. Park Sinchaisri","authors":[{"name":"Prof. Philippe Blaettchen","aff":"Assistant Professor, Bayes Business School"},{"name":"Prof. Park Sinchaisri","aff":"Assistant Professor, University of California Berkeley"}],"order":3}]},{"id":"s133","title":"Topics in Operational Excellence","track":"Operational Excellence","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"BAKER","chairs":["Dr. Fan Zou"],"abstracts":[{"id":"136-1005","title":"Network Structures and Innovation Resilience: An Empirical Study on Star Inventors During Times of Distress","content":"Star inventors are crucial for firms’ innovation competitiveness. We examine how network structures influence stars’ innovation resilience during times of distress. Findings reveal that network constraints and shared secondary contacts mitigate the negative impacts of disruption, with network redundancies proving beneficial for maintaining innovation performance under operational disruptions.","presenter":"Dr. Xiaojin Liu","authors":[{"name":"Dr. Pankaj Kumar","aff":"Associate Professor, Virginia Tech"},{"name":"Dr. Xiaojin Liu","aff":"Associate Professor, Virginia Commonwealth University"},{"name":"Prof. Anant Mishra","aff":"Professor, University of Minnesota"}],"order":1},{"id":"136-1119","title":"Health Insurance and Labor Productivity: Evidence from US Manufacturing","content":"Although health insurance is a central topic of interest at the business-societal interface globally, its impact on labor productivity remains unclear and contested. We examine how health insurance affects labor productivity in the context of the US manufacturing industry.","presenter":"Ms. Yasaman Asayesh","authors":[{"name":"Ms. Yasaman Asayesh","aff":"Student, University of Minnesota"},{"name":"Prof. Anant Mishra","aff":"Professor, University of Minnesota"},{"name":"Prof. Arzi Adbi","aff":"Assistant Professor, National University of Singapore"}],"order":2},{"id":"136-1429","title":"The Impact of U.S. Billion-Dollar Weather and Climate Disasters on Firm-Level Innovation","content":"We use data from the NOAA and the USPTO to study the relationship between extreme weather events and innovation within impacted firms. Our results indicate that while climate events generally impede overall innovation, they also stimulate the advancement of green innovation within affected companies.","presenter":"Mr. Max Ji","authors":[{"name":"Prof. Suvrat Dhanorkar","aff":"Associate Professor, Penn State University State College"},{"name":"Mr. Max Ji","aff":"Student, Penn State"},{"name":"Prof. Suresh Muthulingam","aff":"Professor, Penn State University University Park"}],"order":3},{"id":"136-1545","title":"Revolutionizing Root Cause Analysis with Machine Learning: From Insight to Prevention","content":"Traditional root cause analysis tools struggle to meet the demands of today’s complex and data-rich environments. This session explores how machine learning techniques, such as classification and regression trees, enhance RCA by analyzing vast datasets, predicting issues, and uncovering multiple contributing factors, empowering organizations to detect and prevent issues effectively.","presenter":"Mrs. Peg Pennington","authors":[{"name":"Mrs. Peg Pennington","aff":"President, MoreSteam"},{"name":"Mrs. Lindsay Van Dyne","aff":"VP of Marketing, MoreSteam"}],"order":4}]},{"id":"s157","title":"Outpatient Clinics Scheduling and Analytical Modeling in Hospitals","track":"Healthcare Analytics","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"GRAND HALL EAST D","chairs":["Prof. Vikram Tiwari"],"abstracts":[{"id":"136-0364","title":"Appointment Scheduling of Outpatient Clinical Services under Uncertain Patient Flows","content":"We study outpatient appointment scheduling problem, considering random patient arrivals, cancellations, and attendance. For long horizons, we derive an efficient probabilistic allocation policy by optimizing a closed-form function. For limited horizons, we propose a simple sequential scheduling process using pre-determined diagrams, computed by ranking the margins of scalar functions.","presenter":"Dr. Yang Yang","authors":[{"name":"Prof. Frank Chen","aff":"Professor, City University of Hong Kong"},{"name":"Prof. Qi Feng","aff":"Professor, Purdue University"},{"name":"Prof. George Shanthikumar","aff":"Professor, Purdue University"},{"name":"Dr. Yang Yang","aff":"Post Doc/Researcher, Purdue University"}],"order":1},{"id":"136-0940","title":"Server Scheduling Problem in Healthcare Environments","content":"This study focuses on scheduling servers in multi-job, multi-processor environments, such as healthcare, manufacturing, and service industries. We develop a novel formulation and efficient solution methodology for optimal job and server assignment, applied to hemodialysis clinical services. Results are compared with current strategies, highlighting efficiency improvements.","presenter":"Dr. Farbod Farhadi","authors":[{"name":"Dr. Farbod Farhadi","aff":"Associate Professor, Babson College"},{"name":"Dr. Sina Ansari","aff":"Assistant Professor, Driehaus College of Business"},{"name":"Dr. Francisco Moroni","aff":"Assistant Professor, Universidad Diego Portales"}],"order":2},{"id":"136-0956","title":"The Burden of Evidence for Operations Research in Hospitals","content":"What evidence is used to make strategic operational decisions in hospitals? We explore this question (and resulting challenges and opportunities) through a variety of examples to illustrate how metrics of success can differ between hospital stakeholders and the academic community and the implications of this for OR practice.","presenter":"Dr. Martin Copenhaver","authors":[{"name":"Dr. Martin Copenhaver","aff":"Systems engineer/Assistant professor, Johns Hopkins Hospital and Johns Hopkins University"}],"order":3},{"id":"136-1774","title":"LLM-Extracted Sentiment and ICD-10 Data for Identifying Patient Risk Factors: Predicting Adverse Health Outcomes","content":"This study investigates whether LLM-extracted patient-reported sentiments, such as anxiety and urgency, combined with ICD-10-coded conditions, can predict adverse health outcomes. By developing a predictive model integrating sentiments with EHR data, we aim to enhance early detection of clinical deterioration, improving patient safety and timely interventions in outpatient care.","presenter":"Ms. Megha Pawar","authors":[{"name":"Ms. Megha Pawar","aff":"Student, University of Cincinnati"},{"name":"Mr. Jeffrey Shaffer","aff":"Assistant Professor, University of Cincinnati"},{"name":"Dr. Dong-Gil Ko","aff":"Associate Professor, University of Cincinnati"}],"order":4}]},{"id":"s172","title":"AI in Action: Reshaping Operations Management","track":"Information Systems and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"SPRING","chairs":["Prof. Mehmet Eren Ahsen"],"abstracts":[{"id":"136-1858","title":"Improving the Performance of AI on Target Populations Using Custom Ensembles: Application in Screening Mammography","content":"This study introduces an adaptive ensemble method to enhance AI generalizability by reweighting outputs of multiple algorithms. Tested on a mammography dataset, the method outperformed previous performance in AUROC, sensitivity, and specificity. Leveraging just 10% of data for fine-tuning, this approach scales AI performance across diverse healthcare populations","presenter":"Prof. Mehmet Eren Ahsen","authors":[{"name":"Prof. Mehmet Eren Ahsen","aff":"Assistant Professor, University of Illinois at Urbana Champaign"},{"name":"Prof. Mehmet Ayvaci","aff":"Associate Professor, The University of Texas at Dallas"}],"order":1},{"id":"136-1826","title":"Leveraging Generative AI to Improve Judgmental Forecasting in Supply Chain Management","content":"Increasing complexity, uncertainty and ambiguity within supply chains lead to the need to support judgemental forecasting using Generative AI tools. With this work, we want to identify the obstacles and possible negative consequences of using Generative AIl in practice comparing the deployment of such tools in similar applications.","presenter":"Prof. Bernd Hellingrath","authors":[{"name":"Mr. Anirudh Ravi","aff":"Student, University of Muenster"},{"name":"Prof. Bernd Hellingrath","aff":"Professor, University of Muenster"}],"order":2},{"id":"136-0481","title":"Nexus between Supply Chain Digitalization, Resilience, and Performance: A Conceptual Model","content":"The interplay between supply chain digitalization, resilience, and performance remains ambiguous and understudied, leaving critical gaps in theory and practice. This working paper leverages the dynamic capabilities, technology paradox, and contingency theories to develop a novel conceptual model that explains both the bright and dark sides of digitalization for resilience.","presenter":"Mrs. Atiyeh Kazeroonimonfared","authors":[{"name":"Mrs. Atiyeh Kazeroonimonfared","aff":"Student, Ted Rogers School of Management, Toronto Metropolitan University"},{"name":"Mrs. Ravi Vatrapu","aff":"Professor, Ted Rogers School of Management, Toronto Metropolitan University"}],"order":3},{"id":"136-1642","title":"Scaling Challenges in Decentralized Autonomous Organizations","content":"This research examines the impact of growing Decentralized Autonomous Organization (DAO) communities on member ownership and innovation. The study highlights critical challenges in balancing growth and governance effectiveness within decentralized ecosystems.","presenter":"Dr. Jing Tian","authors":[{"name":"Dr. Jing Tian","aff":"Assistant Professor, Penn State University"}],"order":4}]},{"id":"s191","title":"Empirical Service Operations on Technology and future of work","track":"Service Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY C","chairs":["Prof. Qiuping Yu"],"abstracts":[{"id":"136-0397","title":"How Forced Intervention Facilitates Long-term Algorithm Adoption","content":"Using the field experiment in an online education company, we find that forced algorithm usage increases its post-experiment usage by 15.8 percentage points. We develop a theoretical model to derive empirical strategies for exploring mechanisms behind and find that learning is a key driver for long-term algorithm adoption.","presenter":"Ms. Chenshan Hu","authors":[{"name":"Prof. Xinyu Cao","aff":"Associate Professor, Chinese Univ of Hong Kong"},{"name":"Ms. Chenshan Hu","aff":"Student, Washington University in St. Louis"},{"name":"Dr. Jiankun Sun","aff":"Assistant Professor, Imperial College London"},{"name":"Prof. Dennis Zhang","aff":"Associate Professor, Washington University in St. Louis"}],"order":1},{"id":"136-0572","title":"A Two-Sided Structural Model for Food Delivery Markets","content":"This paper develops a two-sided structural model for food delivery platforms, capturing customer choices among platforms and restaurants alongside restaurants' platform participation decisions. Leveraging platform and restaurant-level data, we estimate demand patterns, competitive dynamics, and restaurants' strategic behaviors. Employing counterfactual simulations, we derive insights into platforms' geographic expansion strategies.","presenter":"Mr. Zhikun Lu","authors":[{"name":"Mr. Zhikun Lu","aff":"Student, Emory University"},{"name":"Dr. Wenchang Zhang","aff":"Assistant Professor, Kelley School of Business"},{"name":"Prof. Ruomeng Cui","aff":"Professor, Emory University"}],"order":2},{"id":"136-0573","title":"Reconciling Flexibility with Predictability: A Study on Gig Worker-driven Scheduling and Productivity","content":"This study examines whether gig workers’ control over scheduling reconciles companies’ demand for flexibility with predictability. Analyzing data from a global retail platform’s customer service center, we find that last-minute shifts, especially those selected within two hours, outperform two-day-advance shifts in worker attendance, customer satisfaction, and FCR rates.","presenter":"Ms. Weijie Sun","authors":[{"name":"Ms. Weijie Sun","aff":"Student, Fudan University"},{"name":"Prof. Qiuping Yu","aff":"Associate Professor, Georgetown University"},{"name":"Prof. Tianjun Feng","aff":"Professor, Fudan University"}],"order":3},{"id":"136-0569","title":"Productivity, Revenue Efficiency, and SDG Alignment: A Study of Indian Cooperative Banks","content":"This research analyses the performance of state and district-level cooperative banks in supporting agriculture and rural development. Post two-stage Data Envelopment Analysis methodology to benchmark these banks' production and revenue efficiencies, it develops DEA based SDG scores to study their alignment with the social and sustainability objectives.","presenter":"Dr. Sajeev George","authors":[{"name":"Dr. Sajeev George","aff":"Professor, S P Jain Inst. of Management &amp; Research"},{"name":"Dr. Sapna Malya","aff":"Associate Professor, S P Jain Inst. of Management &amp; Research"}],"order":4}]},{"id":"s228","title":"Dynamic Pricing and Risk Management","track":"Supply Chain Risk Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY H","chairs":["Dr. Parshan Pakiman"],"abstracts":[{"id":"136-0209","title":"Adaptive Learning for Joint Pricing and Inventory Control","content":"We study the joint pricing and inventory control problem of $n$ products over $T$ periods, under backlog demand feedback. Conventional approaches cannot be directly adopted due to the lack of first order feedback. We propose a nonparametric adaptive learning algorithm with a novel structure of double loops.","presenter":"Ms. Jingyuan Wang","authors":[{"name":"Ms. Jingyuan Wang","aff":"Student, New York University"},{"name":"Prof. Yining Wang","aff":"Assistant Professor, University of Florida"},{"name":"Prof. Boxiao (Beryl) Chen","aff":"Associate Professor, University of Illinois at Chicago"},{"name":"Prof. Zhengyuan Zhou","aff":"Retired, New York University"}],"order":1},{"id":"136-0210","title":"Dynamic Control of a Multiclass Omnichannel Production System","content":"We study a stochastic network model of a make-to-order and make-to-stock omnichannel production system catering to price-and-delay-sensitive customers. The firm maximizes long-run average proﬁt via dynamic pricing, production scheduling, and admission control decisions. Solving an approximating Brownian control problem in heavy traffic, we propose a policy for the original system.","presenter":"Mr. Amir Alwan","authors":[{"name":"Mr. Amir Alwan","aff":"Assistant Professor, University of Wisconsin-Milwaukee"},{"name":"Prof. Nasser Barjesteh","aff":"Assistant Professor, University of Toronto"}],"order":2},{"id":"136-0628","title":"LEGO: Optimal Online Learning under Sequential Price Competition","content":"We consider price competition among multiple sellers over a finite selling horizon under an unknown linear demand model. A decentralized policy is proposed, which leads sellers to the Nash equilibrium and meanwhile achieves optimal order-of-sqrt{T} regret for each seller. Sellers do not need to communicate once the selling horizon starts.","presenter":"Mr. Shukai Li","authors":[{"name":"Mr. Shukai Li","aff":"Student, Northwestern University"},{"name":"Prof. Cong Shi","aff":"Associate Professor, University of Miami Business School"},{"name":"Prof. Sanjay Mehrotra","aff":"Professor, Northwestern University"}],"order":3},{"id":"136-1491","title":"Self-adapting Risk Management in Dynamic Pricing with Demand Learning","content":"Consider dynamically pricing a product with unknown demand. Because frequent price adjustments are restricted, suboptimal prices from inaccurate demand estimates can apply to many customers, posing a high risk of revenue loss. We develop a pricing-with-demand-learning algorithm that self-adapts to data arrivals, gracefully transitioning from risk minimization to revenue maximization.","presenter":"Dr. Parshan Pakiman","authors":[{"name":"Prof. Boxiao (Beryl) Chen","aff":"Associate Professor, University of Illinois at Chicago"},{"name":"Prof. Selva Nadarajah","aff":"Associate Professor, University of Illinois at Chicago"},{"name":"Dr. Parshan Pakiman","aff":"Post Doc/Researcher, Booth School of Business"},{"name":"Prof. Stefanus Jasin","aff":"Professor, University of Michigan"}],"order":4}]},{"id":"s235","title":"AI and Innovation in Healthcare: Equity and Wellbeing","track":"Healthcare Analytics","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"INMAN","chairs":["Dr. Muhammad Zia Hydari"],"abstracts":[{"id":"136-1218","title":"Going beyond Algorithm Aversion: Empathy and Emotions in Rule-Based and GenAI in Mental Healthcare","content":"The global mental health crisis, worsened by COVID-19, is compounded by a lack of qualified professionals. This study explores whether advanced AI agents, capable of emotional support and empathy, can enhance trust, reduce distrust, and promote self-disclosure in mental health contexts. A 3x2 experiment examines AI-empathy effects on treatment-seeking behaviors.","presenter":"Prof. Alan Wang","authors":[{"name":"Mr. Mohammad Rahimi","aff":"Student, Virginia Tech"},{"name":"Dr. Wenqi Shen","aff":"Assistant Professor, Virginia Tech"},{"name":"Prof. Alan Wang","aff":"Professor, Virginia Tech"},{"name":"Prof. Paul Lowry","aff":"Professor, Virginia Tech"},{"name":"Prof. Pearl Chiu","aff":"Professor, Virginia Tech"}],"order":1},{"id":"136-1658","title":"AI-Driven Innovation in Medical Devices","content":"We analyze how firms leverage AI to develop and seek regulatory approval for new “smart” medical devices that compete with incumbent products. We analyze the characteristics of, and interconnections between, AI-enabled and non-AI devices, offering insights into the role of AI in shaping the medical device innovation landscape.","presenter":"Ms. Yupei Hu","authors":[{"name":"Ms. Yupei Hu","aff":"Student, University of Pittsburgh"},{"name":"Dr. Muhammad Zia Hydari","aff":"Assistant Professor, University of Pittsburgh"},{"name":"Prof. Narayan Ramasubbu","aff":"Associate Professor, University of Pittsburgh"}],"order":3},{"id":"136-1678","title":"Political Affiliation and Mental Health During Crises: Insights from Online Communication","content":"This study explores the relationship between political orientation, social media discussions, and depressive symptoms during and after the COVID-19 pandemic. Using Twitter data and advanced modeling, it highlights the complex interplay of policies, expectations, and online discourse, offering valuable insights for policymakers, mental health professionals, and social media platforms.","presenter":"Ms. Saeede eftekhari","authors":[{"name":"Ms. Saeede eftekhari","aff":"Assistant Professor, Tulane University"},{"name":"Dr. Zhasmina Tacheva","aff":"Assistant Professor, Syracuse University"},{"name":"Prof. Claire Senot","aff":"Associate Professor, Tulane University"}],"order":4}]},{"id":"s237","title":"Advances in Revenue Management","track":"Digital Platforms, Innovations and Transformations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"GREENBRIAR","chairs":["Prof. Ashwin Venkataraman","Mr. Mohammad Amin Farzaneh"],"abstracts":[{"id":"136-1034","title":"Dynamic Pricing for Autonomous On-Demand Delivery Services with Capacity Constraints and Shrinking Choice Sets","content":"Motivated by one company offering autonomous on-demand delivery service, we study dynamic pricing for delivery time windows with capacity constraints, modeling consumer choice via an MNL framework. We propose a heuristic strategy with asymptotic optimality. Numerical experiments demonstrate significant revenue gains, offering practical and adaptable insights for similar applications.","presenter":"Prof. Jingwen Tang","authors":[{"name":"Prof. Jingwen Tang","aff":"Assistant Professor, University of Miami Business School"},{"name":"Prof. Yuqian Xu","aff":"Associate Professor, UNC Chapel Hill"},{"name":"Prof. Cong Shi","aff":"Associate Professor, University of Miami Business School"}],"order":1},{"id":"136-1224","title":"Beyond One-Size-Fits-All: Personalized Delivery and Fulfillment Optimization","content":"We explore the joint optimization of the order fulfillment process with personalized delivery options in e-commerce. Customers can choose from personalized fulfillment options to proceed with the purchase or leave with no purchase. We formulate a stochastic dynamic program and demonstrate the value of personalizing fulfillment options.","presenter":"Mr. Quan Zhou","authors":[{"name":"Mr. Quan Zhou","aff":"Student, Desautels Faculty of Management"},{"name":"Prof. Mehmet Gumus","aff":"Professor, McGill University"},{"name":"Dr. Sentao Miao","aff":"Assistant Professor, University of Colorado Boulder"}],"order":2},{"id":"136-1502","title":"A Feature-based Consideration Set Choice Model for Online Retailing","content":"We propose a feature-based consideration set model for online retail, where customers form a consideration set based on visible product features and make purchases using all features. We solve joint assortment and price optimization under customer heterogeneity, implement estimation, and demonstrate superior prediction accuracy and decision performance over benchmarks.","presenter":"Mr. Mohammad Amin Farzaneh","authors":[{"name":"Mr. Mohammad Amin Farzaneh","aff":"Student, University of Texas Dallas"},{"name":"Prof. Ashwin Venkataraman","aff":"Assistant Professor, University of Texas Dallas"},{"name":"Prof. Sajad Modaresi","aff":"Assistant Professor, University of North Carolina Chapel Hill"}],"order":3},{"id":"136-1612","title":"One-shot Inventory Decision under Capacitated Dynamic Substitution Model: An LP Approach","content":"We consider a one-shot inventory problem in a general model with dynamic substitution, MNL choice model, and an arbitrary set of capacity constraints. We optimally solve the fluid model using an LP sequence, based on which we further construct an asymptotically optimal solution to the stochastic problem.","presenter":"Ms. Alys Liang","authors":[{"name":"Ms. Alys Liang","aff":"Assistant Professor, McGill University"},{"name":"Prof. Stefanus Jasin","aff":"Professor, University of Michigan"},{"name":"Prof. Joline Uichanco","aff":"Associate Professor, University of Michigan"}],"order":4}]},{"id":"s246","title":"Retail Operations and Supply Chain Management","track":"Supply Chain Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY A","chairs":["Prof. Mumin Kurtulus"],"abstracts":[{"id":"136-0867","title":"The Impact of Retail Competition on Store Brand Strategy","content":"We study a supply chain with a single national brand manufacturer that sells to consumers through two competing retailers who have an option to introduce a store brand. We explore the role competitive interactions between the two retailers and the national brand manufacturer on the retailer's store brand strategy.","presenter":"Prof. Mumin Kurtulus","authors":[{"name":"Prof. Mumin Kurtulus","aff":"Associate Professor, Vanderbilt University"},{"name":"Prof. Yasin Alan","aff":"Associate Professor, Vanderbilt University"},{"name":"Dr. Alexander Maslov","aff":"Lecturer, University of Kentucky"},{"name":"Dr. Chunlin Wang","aff":"Student, Vanderbilt University"}],"order":1},{"id":"136-0937","title":"Mergers of Consumer Cooperatives","content":"We study consumer cooperatives that aim to achieve buyer power and maximize their member-consumers’ welfare (rather than profits). We derive conditions under which mergers of consumer cooperatives benefit or harm their member consumers.","presenter":"Dr. Sina Moghadas Khorasani","authors":[{"name":"Dr. Sina Moghadas Khorasani","aff":"Assistant Professor, Vanderbilt University"},{"name":"Dr. C. Gizem Korpeoglu","aff":"Assistant Professor, Eindhoven University of Technology"}],"order":2},{"id":"136-1030","title":"Sales Versus Subscription Business Models in Retail: Price and Assortment Competition","content":"Motivated by retailers’ introduction of subscription services, we study consumers’ self-selection between “buying from seller firms” versus “subscribing to renter firms.” Modeling price and assortment competition among sellers and renters, we characterize a solution wherein the renter’s large assortment at premium prices and the seller’s limited assortment split equilibrium demand.","presenter":"Prof. Aditya Jain","authors":[{"name":"Prof. Aditya Jain","aff":"Associate Professor, Baruch College"},{"name":"Prof. Mehmet Altug","aff":"Associate Professor, George Mason University"},{"name":"Prof. Tolga Aydinliyim","aff":"Associate Professor, Baruch College"},{"name":"Dr. Oben Ceryan","aff":"Senior Lecturer, Bayes Business School"}],"order":3}]},{"id":"s266","title":"Digital Marketing and Algorithm","track":"POM-Marketing Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"DUNWOODY","chairs":["Ms. Fei Long"],"abstracts":[{"id":"136-2024","title":"Does Human-algorithm Feedback Loop Lead To Error Propagation? Evidence from Zillow's Zestimate","content":"We examine how Zillow's algorithm influences home sellers and buyers, revealing a human-algorithm feedback loop in the housing market. However, simulations and an analysis leveraging the COVID-19 shock show that disturbances are short-lived, suggesting that the feedback loop does not lead to persistent error propagation.","presenter":"Dr. Runshan Fu","authors":[{"name":"Dr. Runshan Fu","aff":"Assistant Professor, New York University"},{"name":"Prof. Ginger Jin","aff":"Professor, University of Maryland"},{"name":"Dr. Ming Liu","aff":"Professor, Washington University in St. Louis"}],"order":1},{"id":"136-0675","title":"The influence of social media communications on cause-related marketing sales","content":"Cause-related marketing (C-RM) relies on social media to generate \"buzz\" and ultimately drive sales. This study assesses the true influence of social media communications on C-RM using data from a joint campaing between two Fortune 50 organizations and a non-profit organization.","presenter":"Dr. Annibal Sodero","authors":[{"name":"Dr. Annibal Sodero","aff":"Assistant Professor, Ohio State University"}],"order":2},{"id":"136-2026","title":"Data and Algorithms: Designing Marketplace Analytics for Platform Sellers","content":"We ask why and when an e-commerce platform---capable of designing its own analytics to control sellers' actions---may benefit from open data-access policies to accommodate competing third-party analytics services, despite the potential drawbacks of weakening its data advantages and control.","presenter":"Ms. Fei Long","authors":[{"name":"Dr. Yi Liu","aff":"Assistant Professor, University of Wisconsin-Madison"},{"name":"Ms. Fei Long","aff":"Assistant Professor, University of North Carolina Chapel Hill"}],"order":3}]},{"id":"s275","title":"Emerging Topics in Transportation and Logistics","track":"Aviation, Transportation, and Logistics Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"UNIVERSITY","chairs":["Dr. Yanling Zhuang","Dr. Yun Zhou"],"abstracts":[{"id":"136-0623","title":"Improving order picking efficiency through storage assignment optimization in robotic mobile fulfillment systems","content":"This paper addresses optimal SKU distribution in robotic mobile fulfillment systems to improve picking efficiency. We propose an integer linear program that minimizes rack movements and develop a solution procedure that exploits product affinity and order frequency. The results show significant improvements on real e-commerce datasets over existing heuristics.","presenter":"Dr. Yanling Zhuang","authors":[{"name":"Dr. Yanling Zhuang","aff":"Post Doc/Researcher, McMaster University"},{"name":"Dr. Yun Zhou","aff":"Associate Professor, Mcmaster University"},{"name":"Dr. Elkafi Hassini","aff":"Professor, Mcmaster University"},{"name":"Dr. Yufei Yuan","aff":"Professor, Mcmaster University"},{"name":"Prof. Xiangpei Hu","aff":"Professor, Dalian University of Technology"}],"order":1},{"id":"136-0798","title":"Synergizing Electric and Diesel Fleets for Sustainable Last-Mile Delivery","content":"This study investigates a synergistic logistics model combining long-distance fuel-based transport with last-mile electrified delivery to address urban environmental regulations and operational challenges. A bargaining model is proposed to optimize profit-sharing and operational efficiency, fostering collaboration between traditional logistics firms and EV startups while advancing sustainability in supply chain management.","presenter":"Dr. Si Liu","authors":[{"name":"Dr. Si Liu","aff":"Student, Kent State University"},{"name":"Mrs. Xina Li","aff":"Student, Mcmaster University"},{"name":"Dr. Elkafi Hassini","aff":"Professor, Mcmaster University"},{"name":"Dr. Kai Huang","aff":"Professor, Mcmaster University"}],"order":2},{"id":"136-1077","title":"The Whiplash Effect: Congestion Dissipation in a Disrupted Circulatory System","content":"We build a fluid model in transient states to investigate how disruptions at one port can affect the\r\ndisrupted port and its counterpart in another country in a circulatory container shipping system where a stream of fleets moves goods back and forth between the two ports.","presenter":"Ms. Chaoyu Zhang","authors":[{"name":"Prof. Ming Hu","aff":"Professor, University of Toronto"},{"name":"Ms. Chaoyu Zhang","aff":"Student, University of Toronto"}],"order":3}]},{"id":"s287","title":"Emerging Technologies and Supply Chains","track":"Supply Chain Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"GRAND HALL EAST A","chairs":["Prof. Ali Parlakturk","Prof. Nagarajan Sethuraman"],"abstracts":[{"id":"136-0920","title":"Does Blockchain Facilitate Responsible Sourcing? An Application to the Diamond Supply Chain","content":"Blockchain in the diamond industry, meant to promote ethical sourcing, may incentivize the opposite. Increased market segmentation costs due to blockchain can push retailers towards cheaper, unethical suppliers, hindering resales and reducing transparency.","presenter":"Dr. Dmitrii Sumkin","authors":[{"name":"Dr. Dmitrii Sumkin","aff":"Post Doc/Researcher, University of Illinois Urbana-Champaign"},{"name":"Prof. Sameer Hasija","aff":"Professor, INSEAD"}],"order":1},{"id":"136-1856","title":"Delegated Customization Using Retail 3D Printing","content":"Retail customization with partially 3D printed products has gained significant interest in recent years as a means of offering customized products. we propose a modeling framework that allows for partial customization using 3D printing while also capturing the impact of customer waiting time, quality issues, and inventory management.","presenter":"Prof. Nagarajan Sethuraman","authors":[{"name":"Prof. Nagarajan Sethuraman","aff":"Assistant Professor, University of Kansas"},{"name":"Prof. Ali Parlakturk","aff":"Professor, Kenan-Flagler Business School"},{"name":"Prof. Jayashankar Swaminathan","aff":"Professor, University of North Carolina Chapel Hill"}],"order":2},{"id":"136-1255","title":"Strategic Blockchain Adoption by Manufacturer as Deterrence to the Selling of Counterfeits by Retailer","content":"To mitigate the potential harm of counterfeits, it is critical to understand the retailer's incentive for selling deceptive counterfeits and identify effective countermeasures. Therefore, we examine an online retailer’s motivation to sell deceptive counterfeits with the genuine product and exploring the manufacturer’s strategic blockchain adoption to counteract these sales.","presenter":"Ms. Jingjing Weng","authors":[{"name":"Ms. Jingjing Weng","aff":"Student, Temple University"},{"name":"Prof. Abhishek Roy","aff":"Assistant Professor, Temple University"},{"name":"Dr. Subodha Kumar","aff":"Professor, Temple University"}],"order":3}]},{"id":"s304","title":"Industry-Level Models to Improve Decision-Making and Performance","track":"Industry Studies and Public Policy","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"KENNESAW","chairs":["Dr. Jason Merrick","Prof. Abhishek Ray"],"abstracts":[{"id":"136-1958","title":"Data-driven Tool to Optimize Adaptive Spatiotemporal Pricing in Networks","content":"We develop a Graph Neural Network framework to optimize adaptive pricing, integrating spatial and temporal dimensions. Using Toronto’s parking system as a case study, we examine how pricing changes in one area at a specific time influence demand across the network. This methodology applies to sectors like transportation, energy, etc.","presenter":"Dr. Amir Brudner","authors":[{"name":"Dr. Amir Brudner","aff":"Post Doc/Researcher, University of Toronto"},{"name":"Dr. Mehdi Nourinejad","aff":"Assistant Professor, York University"},{"name":"Prof. Opher Baron","aff":"Professor, University of Toronto"}],"order":2},{"id":"136-0020","title":"A Model of Profits vs. Polarization on Platforms","content":"Can welfare and profit motives coexist? We explore this fundamental question in light of two-sided platforms and growing affective polarization. Our parsimonious two-sided platform model applies the Axelrod attraction-repulsion concept to a Dolbear two-dimensional consumer market where customers are attracted or repelled by one another.","presenter":"Prof. Abhishek Ray","authors":[{"name":"Prof. Abhishek Ray","aff":"Assistant Professor, George Mason University"},{"name":"Prof. Cesar Martinelli","aff":"Professor, George Mason University"}],"order":3},{"id":"136-2020","title":"Inclusive Innovation: Women’s Role in India’s Entrepreneurship Growth","content":"Entrepreneurship is a driver of economic growth and innovation, playing a pivotal role in addressing societal challenges. In India, women remain underrepresented in entrepreneurship although they bring unique strengths. This study explores women’s role in building an inclusive and sustainable ecosystem, unlocking their potential for economic growth and societal progress.","presenter":"Prof. Karuna Jain","authors":[{"name":"Prof. Karuna Jain","aff":"Professor, Indian Institute of Technology Bombay"},{"name":"Mr. Yuvraj Singh","aff":"Student, Indian Institute of Technology Bombay"}],"order":5}]},{"id":"s306","title":"Service delivery in healthcare","track":"Healthcare Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"PIEDMONT","chairs":["Prof. Sokol Tushe"],"abstracts":[{"id":"136-1558","title":"Operations-aware machine learning: Application to forecasting emergency department wait and service times","content":"We introduce an ML methodology that incorporates structural knowledge from operations literature to forecast patient wait and service time distributions. Using real-world emergency department data, we show that our methodology meaningfully improves forecasting accuracy, potentially enhancing patient satisfaction by 20% and increasing hospital earnings by 2.7%.","presenter":"Mr. Ragip Gurlek","authors":[{"name":"Mr. Ragip Gurlek","aff":"Student, Emory University"},{"name":"Prof. Francis De Vericourt","aff":"Professor, ESMT Berlin"},{"name":"Prof. Donald Lee","aff":"Associate Professor, Emory University"}],"order":1},{"id":"136-1705","title":"Bayesian Analysis of Hospital Service Quality. Pre- and Post- COVID-19","content":"We analyze HCAHPS data to study the impact of COVID-19 on latent hospital service quality using a Bayesian framework. Our findings reveal key quality indicators, longitudinal changes pre- and post-pandemic, and hospital characteristics influencing these trends, offering insights for managers and policymakers on healthcare resource optimization.","presenter":"Mr. Daniel Zantedeschi","authors":[{"name":"Mr. Daniel Zantedeschi","aff":"Assistant Professor, University of South Florida"}],"order":2},{"id":"136-1389","title":"Adverse Events in Healthcare: Drivers and Mitigation Strategies","content":"About one in four patients in the U.S. experience harm during healthcare processes due to adverse events. These events not only compromise care quality but also increase hospital costs. This study examines the factors contributing to adverse events and explores strategies to mitigate these risks.","presenter":"Dr. Raymond Lei Fan","authors":[{"name":"Dr. Raymond Lei Fan","aff":"Assistant Professor, Grand Valley State University"},{"name":"Dr. Yuan Ye","aff":"Associate Professor, California State University Sacramento"}],"order":3},{"id":"136-1767","title":"Prescriptive service rate model for healthcare","content":"Service process plays a central role in operations, but the literature on high resolution models that can be used prescriptively in simulations is relatively sparse. We address this gap by developing a data-driven service rate model that matches observed properties of service times across a range of settings, incl. healthcare.","presenter":"Prof. Sokol Tushe","authors":[{"name":"Prof. Sokol Tushe","aff":"Assistant Professor, University of South Florida"},{"name":"Prof. Donald Lee","aff":"Associate Professor, Emory University"},{"name":"Ms. Yixuan Wang","aff":"Student, Emory University"}],"order":4}]},{"id":"s313","title":"Personalized Pricing and Assortment Optimization","track":"Revenue Management and Pricing","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"MARIETTA","chairs":["Prof. Andrew Li","Mr. Lin An"],"abstracts":[{"id":"136-1040","title":"Personalized Assortment Optimization for a Subscription Business Model of Experience Goods","content":"Motivated by rental fashion businesses, we investigate assortment optimization for a subscription business model of experience goods. Our two-stage decision model captures the dynamic process of customers updating their preferences after experiencing products. The proposed approximation algorithm achieves near-optimal results, offering actionable insights for optimizing assortments using signal-to-noise ratios.","presenter":"Mr. Jiannan Xu","authors":[{"name":"Mr. Jiannan Xu","aff":"Student, University of Maryland"},{"name":"Prof. Gah-Yi Ban","aff":"Associate Professor, Imperial College London"},{"name":"Prof. Wedad Elmaghraby","aff":"Professor, University of Maryland"},{"name":"Prof. Beril Toktay","aff":"Professor, Georgia Institute of Technology"}],"order":1},{"id":"136-1849","title":"Dynamic Pricing of Split Stays","content":"Recently, AirBnb introduced new split-stay option for booking a trip with two accomodations as an alternative to single reservations. We develop a dynamic pricing framework that provides the optimal pricing policy for split stays. We find split stays balance the inventory of rooms when it is about to deviate.","presenter":"Ms. Yi Zhuang","authors":[{"name":"Ms. Yi Zhuang","aff":"Student, Zicklin School of Business"},{"name":"Prof. Arash Asadpour","aff":"Associate Professor, Zicklin School of Business"},{"name":"Prof. Yuan-Mao Kao","aff":"Assistant Professor, Zicklin School of Business"}],"order":2},{"id":"136-1875","title":"Assortment Planning with Free Shipping under MNL Choice Model","content":"In this study, we analyze the integrated assortment planning and free shipping strategy decisions under the Multinomial Logit (MNL) model. Three free shipping strategies are analyzed: all-or-none, contingent, and selective free shipping. Each strategy is examined with exogenous table-rate and endogenous flat-rate shipping fees.","presenter":"Dr. Sahika Sahan","authors":[{"name":"Dr. Sahika Sahan","aff":"Assistant Professor, Texas State University"},{"name":"Mrs. Hafila Max Morais","aff":"Student, McCoy College of Business"}],"order":3},{"id":"136-0557","title":"Real-Time Personalization with Simple Transformers","content":"Personalization today is already immensely sophisticated, and recent generative AI tools provided transformational improvements in personalization. In this talk, we develop practical, theoretically-sound guidelines and algorithms for applying generative AI tools to personalization. Specifically, we give an algorithm that, in real-time, optimizes personalization based on simple transformers.","presenter":"Mr. Lin An","authors":[{"name":"Mr. Lin An","aff":"Student, Carnegie Mellon University"},{"name":"Prof. Andrew Li","aff":"Assistant Professor, Carnegie Mellon University"},{"name":"Ms. Vaisnavi Nemala","aff":"Student, Carnegie Mellon University"},{"name":"Mr. Gabriel Visotsky","aff":"Student, Carnegie Mellon University"}],"order":4}]},{"id":"s362","title":"Tutorials in Teaching","track":"Tutorials and Workshops in Research and Teaching","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"Learning Center","chairs":["Prof. Léonard Boussioux","Prof. Arnab Bisi"],"abstracts":[{"id":"136-1985","title":"Interactive Zero-Shot Optimization Programming Education for Business Students Using Colab &amp; ChatGPT","content":"Teaching optimization using Python to business students, zero knowledge on coding, poses significant challenges despite its significance in business analytics. We utilize Colab and Large Language Model to simplify Python-based optimization education, requiring no prior setup and minimal coding knowledge, while also facilitating interactive communication in the classroom.","presenter":"Mr. Minseok Kim","authors":[{"name":"Mr. Minseok Kim","aff":"Assistant Professor, Southern Illinois University Edwardsvill"}],"order":1},{"id":"136-0858","title":"When Text-Mining Meets Decision-Making: A Case Study in Platform Economy","content":"We have developed a machine-learning-based case study where, in the first phase, we used text mining, particularly topic modeling, to cluster large-scale social media data. In phase two, these act as input for experts in multi-criteria decision-making to achieve a consensus in improvement in the firms' overall efficiency.","presenter":"Prof. Arnab Bisi","authors":[{"name":"Mr. Souradeep Koley","aff":"Student, Indian Institute of Technology Roorkee"},{"name":"Prof. Arnab Bisi","aff":"Associate Professor, Johns Hopkins University Carey Business"},{"name":"Prof. Mukesh Kumar Barua","aff":"Professor, Indian Institute of Technology Roorkee"}],"order":2},{"id":"136-1112","title":"Combining Large Language Models and OR/MS to Make Smarter Decisions","content":"Large Language Models offer transformative potential for Operations Research/Management Science (OR/MS) decision-making solutions. Through concrete examples, this tutorial demonstrates how LLMs can accelerate application development, extract structured information from unstructured text, and enable natural language interfaces for analytical models. We provide guidelines for responsible implementation while exploring future integration possibilities.","presenter":"Prof. Léonard Boussioux","authors":[{"name":"Prof. Léonard Boussioux","aff":"Assistant Professor, University of Washington"}],"order":3}]},{"id":"s392","title":"Recall Studies and Logistics","track":"Empirical Research in Operations Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"AUBURN","chairs":["Dr. Camilo Mora Quiñones"],"abstracts":[{"id":"136-0339","title":"The impact of product recalls on reshoring behaviors: Evidence from U.S. public firms","content":"Product recalls are frequent. However, their impact on reshoring behaviors remains unclear. Using data from 550 publicly traded U.S. firms during 2003-2021, our study, grounded in behavioral theory, empirically identifies a U-shaped relationship between the persistence of product recalls and firms’ reshoring behaviors.","presenter":"Ms. Di Liu","authors":[{"name":"Ms. Di Liu","aff":"Student, University of Bristol"},{"name":"Dr. Minhao Zhang","aff":"Associate Professor, University of Bristol"},{"name":"Dr. Xiaolong Shui","aff":"Lecturer, University of Bristol"},{"name":"Dr. Bangdong Zhi","aff":"Lecturer, University of Bristol"},{"name":"Prof. Palie Smart","aff":"Professor, University of Bristol"}],"order":1},{"id":"136-0553","title":"Regulator Intervention and Auto Recall Effectiveness","content":"Despite significant research on product recalls in the automotive industry, how well a recalling firm performs in repairing faulty products has remained unaddressed. We study how regulatory intervention impacts automakers’ remedial performance. Surprisingly, we find that when the regulator initiates a recall, automakers repair significantly lower proportion of affected vehicles.","presenter":"Mr. Ramin Sepehrirad","authors":[{"name":"Mr. Ramin Sepehrirad","aff":"Student, Washington State University"},{"name":"Dr. Kevin Mayo","aff":"Assistant Professor, Washington State University"},{"name":"Prof. George Ball","aff":"Associate Professor, Kelley School of Business, Indiana Univ."}],"order":2},{"id":"136-1156","title":"Optimizing Last-Mile Delivery: Parking-Hub VRP for Urban Logistics Efficiency","content":"This paper introduces a Parking-Hub Vehicle Routing Problem (VRP) model that designates parking hubs near customer clusters to reduce delivery complexity. Representatives deliver on foot, minimizing cruising and illegal parking. Utilizing satellite imagery, GPS traces, and pedestrian infrastructure data, this approach simplifies routing, enhances efficiency, and supports sustainable urban logistics.","presenter":"Dr. Camilo Mora Quiñones","authors":[{"name":"Dr. Camilo Mora Quiñones","aff":"Post Doc/Researcher, Tecnologico De Monterrey"}],"order":3}]},{"id":"s402","title":"Trends in Sustainable Operations Management","track":"Sustainable Operations Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"GRAND HALL EAST C","chairs":["Ms. Otgondulam Boldbaatar"],"abstracts":[{"id":"136-1636","title":"Evolution of Sustainability Practices in the Automotive Supply Chain","content":"The automotive sector is important in the economies of most developed countries. In this study, we examine how environmental and social sustainability practices have evolved in this sector over several years. We also assess the role that various factors such as global location of companies’ headquarters plays on their performance.","presenter":"Dr. Henry Aigbedo","authors":[{"name":"Dr. Henry Aigbedo","aff":"Professor, Oakland University"}],"order":1},{"id":"136-0606","title":"CSO’s Functional Expertise in Operations: Investigating the Impact on Firm’s Environmental Performance","content":"The growing emphasis on sustainability becoming an important part of a firm’s operational priorities. This study investigates how Chief Sustainability Officer’s (CSO) functional background in operations influences firm’s environmental performance. We find CSO’s operations background positively impacts environmental outcomes. We also look into contingency factors that may impact the relationship.","presenter":"Ms. Piyali Majumdar","authors":[{"name":"Ms. Piyali Majumdar","aff":"Student, Indian Institute of Management Udaipur"},{"name":"Dr. Anirban Adhikary","aff":"Associate Professor, IIM Udaipur"}],"order":2},{"id":"136-0838","title":"Exploring Regional Technology, Environment and Policy Influences on Circular Supply Chain Transitions","content":"The shift to circular networks involves different configurations of remanufacturing, recovery, and reverse logistics. Motivated by cases from the automotive battery industry, this study applied configuration and system dynamics perspectives to analyse stakeholder interactions and explore how alternative sociotechnical networks emerge due to different regional contexts, resources and capabilities.","presenter":"Ms. Xinyan Li","authors":[{"name":"Ms. Xinyan Li","aff":"Student, University of Cambridge"},{"name":"Dr. Jagjit Srai","aff":"Professor, University of Cambridge"}],"order":3},{"id":"136-2057","title":"Production and Operations Management’s Contributions to Quality of Life","content":"This study aims at identifying and categorizing our field’s contributions to improving quality of life (QoL). Theoretically we uncover an inherent relation between QoL improvements and Sustainability, which in turn led us to empirically classifying OM’s QoL contributions into People, Planet and Progress dimensions. We discuss different future research avenues.","presenter":"Dr. Carlos Parra","authors":[{"name":"Prof. Sushil Gupta","aff":"Professor, Florida International University"},{"name":"Dr. Carlos Parra","aff":"Assistant Professor, Florida International University"},{"name":"Prof. Hossein Rikhtehgar Berenji","aff":"Associate Professor, Pacific University"}],"order":5},{"id":"136-0394","title":"Identifying Trends in Logistics Facilities in Chicago and Their Impact on the Surrounding Communities","content":"This study analyzes the placement of e-commerce warehouses in Chicago's Metropolitan Area. Using network analysis, results reveal that distribution facilities concentrate near vulnerable communities. Results demonstrate higher PM2.5 pollution levels in low-income, minority neighborhoods versus wealthy, predominantly white areas. The research integrates social, environmental, and traffic impact assessments.","presenter":"Ms. Otgondulam Boldbaatar","authors":[{"name":"Ms. Otgondulam Boldbaatar","aff":"Student, University of Illinois at Chicago"},{"name":"Ms. Bansari Pandit","aff":"Student, University of Illinois at Chicago"},{"name":"Mrs. Carla Tejada","aff":"Post Doc/Researcher, University of Illinois at Chicago"}],"order":6}]},{"id":"s421","title":"Digital Platforms and Entrepreneurship","track":"Digital Platforms, Innovations and Transformations","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"HARRIS","chairs":["Ms. Lishu Xia"],"abstracts":[{"id":"136-0941","title":"Leveraging Digital Platforms for Transformative Entrepreneurial Ecosystems: Enhancing Innovation and Scaling Startups","content":"Paper explores the impact of digital platforms on entrepreneurial ecosystems, focusing on their role in fostering innovation and accelerating startup growth. Highlighting how incubators and innovation hubs are integrating these platforms to optimize resource allocation, enhance mentoring, provide access to global networks, ultimately creating more inclusive and resilient entrepreneurial ecosystems.","presenter":"Prof. Rudra Prakash Pradhan","authors":[{"name":"Mr. Mohd Tabrej Alam","aff":"Student, IIT Kharagpur"},{"name":"Prof. Rudra Prakash Pradhan","aff":"Professor, Indian Institute of Technology Kharagpur"}],"order":1},{"id":"136-0972","title":"Closed Platforms vs. Open Network for Digital Commerce: Challenges and Strategic Pathways","content":"Consumers remain reluctant to adopt Open Network for Digital Commerce (ONDC), favoring closed platforms for familiarity. This study employs a game-theoretic approach to analyze strategies encouraging ONDC adoption. Comparative analysis highlights ONDC’s potential as a viable alternative, offering insights for operators to refine strategies, boost engagement, and support sustainable e-commerce.","presenter":"Prof. Tanmoy Kundu","authors":[{"name":"Prof. Tanmoy Kundu","aff":"Assistant Professor, Indian Institute of Management Indore"},{"name":"Prof. Mark Goh","aff":"Professor, National University of Singapore"},{"name":"Prof. Jiuh-Biing Sheu","aff":"Professor, National Taiwan University"}],"order":2},{"id":"136-1863","title":"Interaction Dynamics Between Users and Platforms: Understanding User Drop-Off in Agricultural Advisory Services","content":"Digital advisory services provide farmers in developing countries with expert knowledge to help increase yields. However, such platforms can lead to interaction fatigue, resulting in user drop-off. By analyzing data from 13 million interactions involving 105,000 unique Indian farmers, we uncover patterns that trigger user drop-off and identify suitable remedies.","presenter":"Mrs. Judy Gachara","authors":[{"name":"Prof. Fabrizio Salvador","aff":"Professor, IE Business School"},{"name":"Dr. Bengu Ozdemir","aff":"Assistant Professor, University of Wisconsin-Whitewater"},{"name":"Mrs. Judy Gachara","aff":"Student, IE University,"}],"order":3},{"id":"136-0949","title":"Understanding Platform Dynamics in B2B-B2C E-Hospital Networks","content":"This study examines how digital and physical infrastructure investments influence the configuration of a fast-growing national multisided healthcare platform. Focusing on standalone, same-side, and cross-side value creation in e-Hospital ecosystems, a system dynamics model is developed to understand the dynamics of platform evolution and development in B2B-B2C healthcare context.","presenter":"Ms. Lishu Xia","authors":[{"name":"Ms. Lishu Xia","aff":"Student, University of Cambridge"},{"name":"Dr. Jagjit Srai","aff":"Professor, University of Cambridge"}],"order":4}]},{"id":"s431","title":"Transportation, Logistics and Inventory","track":"Supply Chain Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY G","chairs":["Prof. Refik Gullu"],"abstracts":[{"id":"136-0906","title":"Transport Costs and Emissions – Analysis of Hub-and-Spoke and Alternative Fuels","content":"This study focuses on economic and environmental impacts of road freight, leveraging vehicle routing and k-means clustering in creating hub-and-spoke model to simulate the practical application of alternative fuel solutions currently commercially available. The findings demonstrate techno-economic performance and feasibility of alternative solutions compared to current practices.","presenter":"Mrs. Clara Rajalehto","authors":[{"name":"Mrs. Clara Rajalehto","aff":"Student, University of Vaasa"},{"name":"Prof. Petri Helo","aff":"Professor, University of Vaasa"}],"order":1},{"id":"136-0411","title":"To Encroach or Entrust the Retailer? A Green Product Manufacturer's Strategies with Green Logistics","content":"We analyze a green product manufacturer's decision-making regarding whether to enjoin the retailer to adopt green logistics or encroach with its own green logistics in the presence of the retailer’s threat of switching to a brown alternative. Interestingly, we find that the retailer may also benefit from the manufacturer’s encroachment.","presenter":"Mr. Ranit Saha","authors":[{"name":"Mr. Ranit Saha","aff":"Student, Indian Institute of Management Calcutta"}],"order":2},{"id":"136-1620","title":"Distributionally Robust Locker Box Planning under Unknown Demand and Dwell Time in Last-Mile Delivery","content":"This study investigates the location-allocation problem for locker box stations with limited capacities, aiming to serve customers with unknown demand and pickup time distributions. The problem is formulated as a two-stage distributionally robust integer program and an efficient algorithm is designed to solve it.","presenter":"Dr. Mohamed Komaki","authors":[{"name":"Dr. Mohamed Komaki","aff":"Associate Professor, Texas A&amp;M University - Commerce"},{"name":"Dr. Karmel Shehadeh","aff":"Assistant Professor, Lehigh University"},{"name":"Dr. Ehsan Teymourian","aff":"Assistant Professor, James Madison University"}],"order":3},{"id":"136-0110","title":"On the Base Stock Inventory Model with Delay Sensitive Heterogenous Customers","content":"We present a base stock inventory model where customers are heterogeneous in their time sensitivity to backordered demand. Considering the waiting time, each customer decides whether to purchase the item or not based on their utility assessment. We obtain equilibrium arrival rates and waiting times under varying customer information levels.","presenter":"Prof. Refik Gullu","authors":[{"name":"Prof. Refik Gullu","aff":"Professor, Bogazici University"},{"name":"Prof. Nesim Erkip","aff":"Professor, Bilkent University"}],"order":4}]},{"id":"s439","title":"Better understanding supply chain risk and disruptions","track":"Data Science, Analytics and AI","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"ROSWELL","chairs":["Mr. Fynn Oldenburg"],"abstracts":[{"id":"136-1079","title":"A Method for Experiments Under Unknown Network Interference","content":"This study addresses the challenge of network interference in randomized experiments, where treatment effects spill over between connected units. We develop a framework that handles complex, unknown interference patterns. Our proposed algorithm effectively estimates treatment effects under network interference, as validated through multiple numerical experiments","presenter":"Mr. Sadegh Shirani","authors":[{"name":"Mr. Sadegh Shirani","aff":"Student, Stanford University"},{"name":"Prof. Mohsen Bayati","aff":"Associate Professor, Stanford University"}],"order":1},{"id":"136-1401","title":"Big Data Architecture for Digital Supply Chain Management","content":"This study addresses gaps in understanding supply chain data by developing a Supply Chain Data Architecture. Using a structured literature review, it maps data types, sources and analytical tools to corresponding supply chain stages and applications. The four-layer model—data schema, management, analytic, and application layers—enhances digital supply chain visibility","presenter":"Dr. Ajeseun Jimo","authors":[{"name":"Dr. Ajeseun Jimo","aff":"Lecturer, Henley Business School"},{"name":"Mr. Deepesh Jayasekara","aff":"Post Doc/Researcher, University of Cambridge"},{"name":"Mr. Jost Wiethölter","aff":"Lecturer, University of Applied Sciences"},{"name":"Mr. Linus Kühl","aff":"Senior Controller, Hellmann Worldwide Logistics"},{"name":"Dr. Mukesh Kumar","aff":"Associate Professor, University of Cambridge"}],"order":2},{"id":"136-1940","title":"Enablers of Implementing Big Data Driven Supply Chain Management Post Covid- An ISM Based Model","content":"In the post-COVID era, as the SC continues to struggle with seamless operations, a data-driven approach has become critical for achieving a competitive advantage. This study identified 14 enablers using the ISM model, highlighting the role of specific enablers in achieving SC resiliency and emphasizing the potential contributions of GenAI","presenter":"Dr. Shraddha Gawankar","authors":[{"name":"Dr. Shraddha Gawankar","aff":"Assistant Professor, Beacom School of Business, University of South Dakota"}],"order":3},{"id":"136-0657","title":"Understanding the impact of supply chain disruptions: A process mining perspective on material stream stability","content":"Our study explores disruption propagation in supply chains using a design science approach with process mining. We identify three types of supply chain activities: amplifiers, forwarders, and mitigators of disruption impact. We provide predictive insights that can enhance resilience, optimize available-to-promise management, and maintain operational efficiency during periods of disruption.","presenter":"Mr. Fynn Oldenburg","authors":[{"name":"Mr. Fynn Oldenburg","aff":"Student, Kuehne Logistics University"},{"name":"Prof. Kai Hoberg","aff":"Professor, Kuehne Logistics University"}],"order":4}]},{"id":"s1","title":"Topics in Humanitarian Operations and Crisis Management","track":"Humanitarian Operations and Crisis Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"GRAND HALL EAST B","chairs":["Dr. Christopher Zobel"],"abstracts":[{"id":"136-0658","title":"Beneficiary appointment scheduling and delivery planning in a conflict setting","content":"This study formulates a new beneficiary appointment scheduling problem for aid delivery in prolonged crises such as conflicts, based on insights from interviews with local humanitarian agencies. We present a mathematical model and a practical heuristic. We present a case study from the Syrian conflict.","presenter":"Prof. Burcu Balcik","authors":[{"name":"Prof. Burcu Balcik","aff":"Professor, Ozyegin University"},{"name":"Prof. Maria Battarra","aff":"Professor, University of Bath"},{"name":"Prof. Melih Celik","aff":"Professor, University of Bath"},{"name":"Dr. Bashar Khoury","aff":"Post Doc/Researcher, University of Religions and Denominations"},{"name":"Dr. Anand Subramanian","aff":"Associate Professor, Universidade Federal da Paraíba"}],"order":1},{"id":"136-0748","title":"Quantifying the effect of social vulnerability on housing damage in natural disasters","content":"Working with the American Red Cross, we explore the relationship between socially vulnerable populations and damage to their homes during an event such as a hurricane. We are working towards a generalizable model, extending our previous focus on a single event to incorporate multiple events.","presenter":"Dr. Andrew Arnette","authors":[{"name":"Dr. Andrew Arnette","aff":"Associate Professor, Virginia Tech"},{"name":"Dr. Christopher Zobel","aff":"Professor, Virginia Tech"},{"name":"Dr. Kiatikun Luangkesorn","aff":"Volunteer - NHQ/National Planner, American Red Cross"},{"name":"Mr. Michael Whitehead","aff":"Government Operations &amp; Planning Integration Manager, American Red Cross"}],"order":2},{"id":"136-0971","title":"Sustainability and Resilience of Local Restaurants in Blacksburg, VA During COVID-19","content":"The COVID-19 pandemic posed significant challenges to the sustainability and resilience of local restaurants in Blacksburg, VA. This situation presents an opportunity to understand how the restaurants adapted to their changing environment. Our research seeks to uncover actionable insights to inform policies supporting local businesses and foster sustainable practices.","presenter":"Ms. Layla Koroleva","authors":[{"name":"Ms. Layla Koroleva","aff":"Student, Virginia Tech"},{"name":"Dr. Christopher Zobel","aff":"Professor, Virginia Tech"},{"name":"Dr. Mike Gordon","aff":"Assistant Professor, Virginia Polytechnic Institute And State University"}],"order":3},{"id":"136-1091","title":"Volunteer Satisfaction in Disaster Management: Roles of Transformational Leadership and Organizational Learning Culture","content":"This study aims to analyze the effect of transformational leadership styles on volunteers' satisfaction and volunteer turnover intention in disaster management. Also, it investigates the interplay between transformational leadership, volunteer work engagement, organizational learning culture, knowledge-sharing intention, and volunteer satisfaction.","presenter":"Dr. Gozde Yanginlar","authors":[{"name":"Dr. Gozde Yanginlar","aff":"Associate Professor, Istanbul Commerce University"},{"name":"Prof. Nezih Altay","aff":"Professor, Depaul University"}],"order":4},{"id":"136-1592","title":"If we don’t do it, who will? Stretching humanitarian operations in the 2014 Ebola Epidemic","content":"The 2014 West Africa Ebola epidemic was an unusually challenging emergency for humanitarian organizations. We use interviews to explore how humanitarian organizations address operational challenges when their existing systems and processes are stretched past their limits. We find they rely on individual ingenuity and perseverance in addition to flexible processes.","presenter":"Dr. Erica Gralla","authors":[{"name":"Ms. Lauren Bateman","aff":"Student, George Washington University"},{"name":"Dr. Erica Gralla","aff":"Associate Professor, George Washington University"}],"order":5}]},{"id":"s12","title":"Addressing Community in Operations Management","track":"POM and Community","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY F","chairs":["Ms. Gulten Busra Karkili"],"abstracts":[{"id":"136-0254","title":"Improving basic retail coverage in Africa: modeling geographic disadvantage among farmers in Senegal","content":"African consumers increasingly rely on 10 million retail points for essentials. The questions in African capitals today are: where does and should retail exist, relative to disadvantaged customer segments? Using census and satellite data, we find the typical Senegalese farmer 26 kilometers to buy goods--for them, this is extremely far.","presenter":"Prof. Mark Brennan","authors":[{"name":"Prof. Mark Brennan","aff":"Assistant Professor, Rutgers University"},{"name":"Prof. Stephen Graves","aff":"Professor, Massachusetts Institute of Technology"},{"name":"Prof. Peter Zhang","aff":"Assistant Professor, Carnegie Mellon University"},{"name":"Prof. Babacar Ndiaye","aff":"Professor, University Cheikh Anta Diop"},{"name":"Mr. Jonars Spielberg","aff":"Student, Massachusetts Institute of Technology"}],"order":1},{"id":"136-1107","title":"Integrating Community-based Adaptation and Decision Modeling for Equitable Transit in Flood-prone Urban Areas","content":"Massachusetts’ MVP program has limitations in involving disadvantaged residents in flood-induced transit challenges. Using GIS and decision modeling, this study identifies decision problems and formulates solutions. The findings emphasize the need for meaningful resident engagement to advance equitable mobility and community-based climate adaptation in urban settings.","presenter":"Mr. Mubarak Iddrisu","authors":[{"name":"Mr. Mubarak Iddrisu","aff":"Student, University of Massachusetts Boston"}],"order":2},{"id":"136-1258","title":"Integrating Cash Transfers and In-Kind Aid in Welfare Assistance Programs","content":"This study develops a framework for government assistance programs that integrate direct cash, restricted cash, and in-kind aid to address the diverse needs of different household types. By optimizing resource allocation, the approach aims to improve the effectiveness of poverty alleviation efforts, providing practical insights for policymakers.","presenter":"Ms. Gulten Busra Karkili","authors":[{"name":"Ms. Gulten Busra Karkili","aff":"Student, University of Massachusetts Amherst"},{"name":"Dr. Senay Solak","aff":"Professor, University of Massachusetts Amherst"},{"name":"Prof. Michael Johnson","aff":"Professor, University of Massachusetts Boston"}],"order":3},{"id":"136-1295","title":"Stakeholder perspectives for policy design: A guaranteed income program","content":"A Massachusetts city is administering a guaranteed income program for low-income residents. We discuss the perspectives of stakeholders, including administrators, analysts and advocates to learn how their experiences, as well as those of program participants, can support decision-making and policy and program design for cities considering similar programs.","presenter":"Prof. Michael Johnson","authors":[{"name":"Prof. Michael Johnson","aff":"Professor, University of Massachusetts Boston"},{"name":"Ms. Elham Hesari","aff":"Student, University of Massachusetts Boston"},{"name":"Ms. Gulten Busra Karkili","aff":"Student, University of Massachusetts Amherst"},{"name":"Dr. Susan Crandall","aff":"Senior Lecturer, University of Massachusetts Boston"}],"order":4}]},{"id":"s19","title":"Community in Operations Management","track":"POM and Community","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY E","chairs":["Dr. Dustin Cole"],"abstracts":[{"id":"136-0513","title":"An Empirical Investigation of Establishment-Level Operations and Occupational Hazards in Minority Communities","content":"Racial factors and differing establishment-level operational characteristics may contribute to disparities in exposure to occupational safety hazards. We investigate whether similar establishments pose disparate occupational injury risks when operating in minority communities. Additionally, we consider the moderating role of random inspections by regulators and successful unionization efforts by employees.","presenter":"Mr. Abhinav Shubham","authors":[{"name":"Mr. Abhinav Shubham","aff":"Student, Georgia Institute of Technology"},{"name":"Dr. Ravi Subramanian","aff":"Professor, Georgia Tech"}],"order":2},{"id":"136-0714","title":"The Needle in the Haystack: The Influence of Highlighting Causes on Online Crowdsourced Charitable Giving","content":"This study uses Kiva data and nudge theory to explore how tagging loans influences microfinance funding. Tags improve funding speed, lender participation, and contributions, especially when related to the cause. The tone of loan descriptions moderates these effects, emphasizing the role of tagging in simplifying donor decisions and enhancing outcomes.","presenter":"Mr. Charles Herron","authors":[{"name":"Mr. Charles Herron","aff":"Student, Auburn University"},{"name":"Dr. Dustin Cole","aff":"Assistant Professor, Auburn University"},{"name":"Dr. Shashank Rao","aff":"Professor, Auburn University"}],"order":3},{"id":"136-0788","title":"Assigning Volunteers to Beneficiaries in a Non-Profit Organization","content":"We explore the tradeoffs between incorporating volunteer and beneficiary preferences in task assignments for a non-profit versus pooling them to alleviate supply-demand mismatch. We endogenize volunteers' participation decisions and contrast the performance outcomes of alternative policies. We suggest ways by which non-profits can better align incentives of all stakeholders.","presenter":"Ms. Shikha Safaya","authors":[{"name":"Ms. Shikha Safaya","aff":"Student, Georgia Institute of Technology"},{"name":"Prof. Basak Kalkanci","aff":"Associate Professor, Georgia Institute of Technology"},{"name":"Dr. Ravi Subramanian","aff":"Professor, Georgia Tech"}],"order":4}]},{"id":"s34","title":"Behavioral Aspects of Retail Operations","track":"POM-Economics Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"VININGS","chairs":["Ms. Ceren Gultekin"],"abstracts":[{"id":"136-1486","title":"Exploring the behavioral and economic impact of returnless refunds","content":"Returnless refunds are increasingly used by retailers to seemingly reduce the cost of processing returns and preserve profit margins. We explore the emerging returnless refunds literature and examine how firms might best utilize returnless refunds in conjunction with traditional return policies. We examine these potential relationships with a behavioral experiment.","presenter":"Mr. Chris Faires","authors":[{"name":"Mr. Chris Faires","aff":"Assistant Professor, Georgia Southern University"},{"name":"Dr. Alan Mackelprang","aff":"Associate Professor, Georgia Southern University"}],"order":1},{"id":"136-1662","title":"Inventory Disclosure When Consumers Anticipate Stock-Out Inconvenience","content":"Retailers use product availability indicators to stimulate full price demand ahead of markdowns. However, recent empirical studies argue scarcity signals may backfire as consumers avoid transacting with limited-availability retailers. We characterize how optimal inventory disclosure and pricing decisions adapt when consumers anticipate the inconvenience of a stock-out experience.","presenter":"Ms. Ceren Gultekin","authors":[{"name":"Prof. Tolga Aydinliyim","aff":"Associate Professor, Baruch College"},{"name":"Ms. Ceren Gultekin","aff":"Student, Baruch College, Graduate Center, CUNY"},{"name":"Ms. Qiuyu Fan","aff":"Student, Columbia University"}],"order":2},{"id":"136-0086","title":"Managing Product Return in Omnichannel Retailing: The Impact of Reverse Logistics Efficiency","content":"Product returns surge as more consumers shift to online shopping, and many of them are uncertain of the fit until the goods are delivered. Using a large-scale proprietary dataset from a dominant omnichannel retailer, we develop econometric models and quantify the effect of the hassle cost stemming from product returns.","presenter":"Prof. Ki Ling Cheung","authors":[{"name":"Dr. Luna (Xingyue) Zhang","aff":"Assistant Professor, University of Washington"},{"name":"Prof. Zhuojun Gu","aff":"Assistant Professor, University at Albany"},{"name":"Prof. Ki Ling Cheung","aff":"Associate Professor, Hong Kong University of Science and Technology"},{"name":"Prof. Alok Gupta","aff":"Professor, University of Minnesota"}],"order":3},{"id":"136-1989","title":"Self-Matching and Competitive Price-Matching Guarantees in Omni-Channel Retailing","content":"We study self-matching and competitive price-matching in omni-channel retailing to characterize optimality conditions for these pricing strategies in competitive markets using game-theoretic models. We analyze the impact of trends like price transparency, fast delivery, and showrooming/webrooming on price-matching decisions and offer managerial insights to enhance profitability and customer retention.","presenter":"Dr. Esmat (Yasi) Sangari","authors":[{"name":"Dr. Esmat (Yasi) Sangari","aff":"Assistant Professor, University of San Francisco"},{"name":"Prof. Izak Duenyas","aff":"Professor, University of Michigan - Ann Arbor"},{"name":"Prof. Seyed Iravani","aff":"Professor, Northwestern University"}],"order":4}]},{"id":"s58","title":"New Models for Circular Operations","track":"Sustainable Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"GRAND HALL EAST C","chairs":["Prof. Felix Papier"],"abstracts":[{"id":"136-0048","title":"Using deposit systems to manage reusable packaging efforts","content":"We study BtC reusable packaging solutions managed via a deposit system. The deposit fee influences both demand and packaging returns. Besides, product pricing can differ for a product if sold with reusable or disposable packaging. We study optimal pricing decisions, and we derive insights to guide practical developments.","presenter":"Dr. Yann Bouchery","authors":[{"name":"Mr. Mahyar Taheri","aff":"Assistant Professor, NEOMA Business School"},{"name":"Dr. Yann Bouchery","aff":"Associate Professor, Kedge Business School"},{"name":"Prof. Sandra Transchel","aff":"Professor, Kuehne Logistics University"},{"name":"Prof. Jan Fransoo","aff":"Professor, Tilburg University"}],"order":1},{"id":"136-0113","title":"The circular Building-as-Material-Bank business model to gain competitive advantage in sourcing","content":"Construction firms are required to re-use building material, which will become increasingly difficult to source. Therefore, firms are testing circular models such as the buildings-as-material-bank (Bamb) to retain material ownership. We develop a simultaneous game of the sourcing of reused material, and study how Bamb affects the construction firms’ competitiveness.","presenter":"Prof. Felix Papier","authors":[{"name":"Prof. Felix Papier","aff":"Professor, ESSEC Business School"}],"order":2},{"id":"136-0618","title":"Profitability and Environmental Sustainability of Consignment Resale Models in Fashion","content":"Some fashion retailers pursue sustainability initiatives by partnering with consignment shops on a resale-as-a-service basis (e.g., J.Crew's ThredUp partnership). This allows customers to send used clothing to a consignment shop, which handles logistics and earns a share of resale profits. We investigate the profitability and environmental impacts of such partnerships.","presenter":"Dr. Punya Chatterjee","authors":[{"name":"Prof. Aydin Alptekinoglu","aff":"Professor, Penn State University University Park"},{"name":"Dr. Punya Chatterjee","aff":"Assistant Professor, University of Memphis"},{"name":"Dr. Adem Orsdemir","aff":"Assistant Professor, University of California Riverside"}],"order":3},{"id":"136-0676","title":"Managerial Efficiency and Ordering Policies in a Circular Economy","content":"Circular economy can reduce primary production if stocks and flows of new and used goods are managed effectively. We conduct experiments where participants choose reordering quantity in a simulated supply chain with increased circularity complexity. Variability of returns often leads to overordering, offsetting benefits of extended product lifecycle.","presenter":"Dr. Sergey Naumov","authors":[{"name":"Dr. Sergey Naumov","aff":"Assistant Professor, Penn State"},{"name":"Dr. Saurabh Bansal","aff":"Professor, Penn State University University Park"},{"name":"Prof. Daniel Guide","aff":"Professor, Penn State University University Park"}],"order":4}]},{"id":"s75","title":"Managing carbon and water","track":"Energy and Natural Resource Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"TECHWOOD","chairs":["Prof. Christian Blanco"],"abstracts":[{"id":"136-0188","title":"Environmental and Economic Impacts of Pooled vs. Separate Carbon Targets","content":"Some firms set separate targets for their Scope 1 and 2 emissions, and Scope 3 emissions, while others set one target for entire emissions. We try to identify when firms prefer one target type over the other, and the implications of the firm’s preference and decisions regarding overall emissions.","presenter":"Dr. Guowei Dou","authors":[{"name":"Dr. Guowei Dou","aff":"Associate Professor, Shenzhen University"},{"name":"Dr. Gokce Esenduran","aff":"Associate Professor, Purdue University"},{"name":"Prof. Christian Blanco","aff":"Assistant Professor, Ohio State University"}],"order":1},{"id":"136-0442","title":"Should a Profit-Maximizing Firm Buy Carbon Offsets or Invite Consumers to Buy Them?","content":"Many firms reduce their residual emissions through carbon offsets. Using a stylized model, we find firms should either offset emissions fully or sell green consumers offsets with the product. When the offset cost is low, a carbon neutral strategy also maximizes the firm profits, leading to a win-win.","presenter":"Dr. Gokce Esenduran","authors":[{"name":"Dr. Gokce Esenduran","aff":"Associate Professor, Purdue University"},{"name":"Prof. H. Sebastian Heese","aff":"Professor, North Carolina State University"},{"name":"Prof. Gil Souza","aff":"Professor, University of Tennessee Knoxville"}],"order":2},{"id":"136-1599","title":"Sustainable Management of a Water Reservoir System Facing Climate Uncertainty","content":"We present a strategic optimization model for the long-term, sustainable management of a system of water reservoirs. Introducing a distributionally robust stochastic shortest path model, we obtain sustainable release policies under climate uncertainty. In a case study for California, our robust policy outperforms the current policy by 40%.","presenter":"Prof. Martin Glanzer","authors":[{"name":"Prof. Felipe Caro","aff":"Professor, UCLA Anderson School of Management"},{"name":"Prof. Martin Glanzer","aff":"Assistant Professor, University of Mannheim"},{"name":"Prof. Kumar Rajaram","aff":"Professor, UCLA Anderson School of Management"}],"order":3}]},{"id":"s86","title":"Empirical Insights on Quality, Innovation, Networks, and Meme-Driven Decision-Making-1","track":"Product Innovation and Technology Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"COURTLAND","chairs":["Dr. Xiaojin Liu","Dr. Pankaj Kumar"],"abstracts":[{"id":"136-0131","title":"Taking My Time to Perfect the Beat","content":"Delaying a pre-announced product launch to enhance product quality is a common strategy. However, the longer the delay, the higher the market’s quality expectations (which are also uncertain) become, creating a complex interplay between time, cost, and quality. We study behavioral decision-making processes in this context.","presenter":"Mr. Hyunsuk Baek","authors":[{"name":"Mr. Hyunsuk Baek","aff":"Student, Arizona State University Tempe"},{"name":"Dr. Huseyn Abdulla","aff":"Assistant Professor, University of Tennessee Knoxville"},{"name":"Prof. Seongkyoon Jeong","aff":"Assistant Professor, University of Tennessee Knoxville"}],"order":1},{"id":"136-0567","title":"Are Memes a Sideshow: Evidence from WallStreetBets","content":"We investigate the prevalence of meme images on investor social media (i.e., WallStreet- Bets) and their influence on financial markets. We find a strong positive association between meme activities and negative earnings surprises, suggesting memes serve as a coping mechanism for adverse market outcomes.","presenter":"Ms. Linmei Huang","authors":[{"name":"Ms. Linmei Huang","aff":"Assistant Professor, Laval University"}],"order":2},{"id":"136-0817","title":"Quality up, technology down? How does quality management affect firms’ innovation?","content":"This study examines the relationship between quality management, particularly the China Quality Award, and firm innovation using data from Chinese listed firms (2007-2020). Findings indicate quality management enhances exploitative innovation but hinders exploratory innovation, with operational complexity potentially mitigating negative impacts.","presenter":"Dr. Xiaojin Liu","authors":[{"name":"Dr. Tianxiu Zhang","aff":"Post Doc/Researcher, Hong Kong Polytechnic University"},{"name":"Prof. Zhijian Cui","aff":"Professor, University of Science and Technology of China"},{"name":"Dr. Xiaojin Liu","aff":"Associate Professor, Virginia Commonwealth University"},{"name":"Prof. Andy C. L. Yeung","aff":"Professor, Hong Kong Polytechnic Univ"}],"order":3}]},{"id":"s97","title":"Behavioral Operations in Service Systems","track":"Behavioral Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY D","chairs":["Ms. Na Zhang","Mr. Shubo Sun"],"abstracts":[{"id":"136-0105","title":"Waiting Together: How To Infer Response Time When Customers Wait In Groups","content":"We introduce a novel model that accommodates customers arriving either individually or in pairs. Through an evaluation of the value of groups ratio information, we show that the provision of additional information does not always yield higher throughput or higher social welfare.","presenter":"Dr. Yanting Li","authors":[{"name":"Dr. Yanting Li","aff":"Assistant Professor, SUNY Brockport"},{"name":"Prof. Ricky Roet-Green","aff":"Associate Professor, University of Rochester"}],"order":1},{"id":"136-0328","title":"Dynamic Pricing and Resource Relocation in a Large Closed Network","content":"We study a dynamic pricing and resource relocation problem within a large closed network. We propose a state-dependent greedy heuristic with a relative optimality gap of O(n^{-2/3}log(n)) compared with the fluid model benchmark in a large-market regime where demand scales with the number of servers.","presenter":"Mr. Shubo Sun","authors":[{"name":"Mr. Shubo Sun","aff":"Student, University of Miami Business School"},{"name":"Dr. Ganggang Xu","aff":"Assistant Professor, University of Miami Business School"},{"name":"Dr. Xu Sun","aff":"Assistant Professor, University of Miami Business School"}],"order":2},{"id":"136-0398","title":"Managing Service Systems with Overconfident Customers","content":"Anecdotal evidence shows customers tend to underestimate the variability of service times. The underlying theory is overconfidence theory. We study how to decide optimal pricing and queue-length-information provision policies to manage a service system where customers are overconfident in their beliefs about service times---customers underestimate the variability of service times.","presenter":"Ms. Na Zhang","authors":[{"name":"Ms. Na Zhang","aff":"Assistant Professor, Wichita State University"},{"name":"Dr. Anand Paul","aff":"Professor, University of Florida"},{"name":"Dr. Xu Sun","aff":"Assistant Professor, University of Miami Business School"}],"order":3},{"id":"136-0403","title":"Invisible Customers in Omnichannel Services","content":"In omnichannel services, while walk-in customers are physically in the store and therefore visible to others, online customers are typically invisible. In this study, we investigate the impact of invisibility on customers’ joining decisions and system performance.","presenter":"Mr. Guanling Yang","authors":[{"name":"Mr. Guanling Yang","aff":"Student, Simon Business School, University of Rochester"},{"name":"Prof. Ricky Roet-Green","aff":"Associate Professor, University of Rochester"}],"order":4}]},{"id":"s110","title":"Responsible Operations Management","track":"Empirical Research in Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY B","chairs":["Dr. Natalie (Ximin) Huang","Dr. Jie Lian"],"abstracts":[{"id":"136-1029","title":"Does your consumer care who certifies your apparel? An experimental investigation","content":"While codes of conduct (CoC) are shown to impact consumer perceptions, it is unclear how different CoC types (buyer’s enforced vs supplier’s voluntarily adopted) are perceived by consumers, depending on the firm's sourcing strategy and presence of supplier's unethical practices. We conduct multiple experiments assess consumers' willingness-to-pay and (dis)trust.","presenter":"Dr. Li Cheng","authors":[{"name":"Dr. Li Cheng","aff":"Assistant Professor, Michigan State University"},{"name":"Dr. Han Zhang","aff":"Assistant Professor, Michigan State University"},{"name":"Prof. Sriram Narayanan","aff":"Professor, Michigan State University"},{"name":"Mr. Jot Singh","aff":"Student, Michigan State University"}],"order":1},{"id":"136-1041","title":"Beyond the Price Tag: Improving Worker Welfare Through Tipping in the Fashion Industry","content":"The global fashion industry prioritizes low-cost production, often at the expense of workers. One solution to improve worker welfare is to allow consumers to provide tips directly to workers. We examine what drives consumer tipping as well as how information should be provided to consumers to maximize tips per order.","presenter":"Dr. Aditya Balaram","authors":[{"name":"Dr. Aditya Balaram","aff":"Assistant Professor, Loyola Marymount University"},{"name":"Dr. Punya Chatterjee","aff":"Assistant Professor, University of Memphis"}],"order":2},{"id":"136-1142","title":"Mandatory Environmental Disclosure and Environmental Performance","content":"Regulators often employ mandatory environmental disclosure regulations as a means to stimulate corporate environmental improvement. This research investigates the broader effects of mandatory environmental disclosure and explores potential synergies or trade-offs between varied environmental policies. Our investigation sheds light on the multidimensional impacts of these regulations.","presenter":"Dr. Jie Lian","authors":[{"name":"Dr. Jie Lian","aff":"Assistant Professor, University of Oklahoma"},{"name":"Prof. Yan Dong","aff":"Professor, University of South Carolina"},{"name":"Prof. Keith Skowronski","aff":"Associate Professor, University of South Carolina"},{"name":"Dr. Sining Song","aff":"Assistant Professor, University of Maryland, College Park"}],"order":3},{"id":"136-0996","title":"Going the Extra Mile? Work place behaviors and performance evaluations","content":"In today's competitive corporate landscape, it is crucial to understand the relationship between workplace behaviors and performance evaluations. We leverage privileged access to communications data spanning over six thousand employees within a firm to analyze the dynamics of employee \"extra mile behaviors” and their effects on performance evaluations.","presenter":"Ms. Priscilla Rodriguez Chaves","authors":[{"name":"Ms. Priscilla Rodriguez Chaves","aff":"Student, INSEAD"},{"name":"Prof. So Yeon Chun","aff":"Professor, INSEAD"},{"name":"Prof. Jurgen Mihm","aff":"Professor, INSEAD"}],"order":4}]},{"id":"s135","title":"Behavioral Considerations in Sociotechnical Operational Systems","track":"Operational Excellence","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"BAKER","chairs":["Dr. Mateus do Rego Ferreira Lima"],"abstracts":[{"id":"136-0687","title":"Operational autonomy and outlet performance: Evidence from a franchise restaurant context","content":"This study examines the outlet-level performance impact of franchisee autonomy across three operational dimensions—supplier-facing, internal, and customer-facing—within a franchise restaurant context. The findings reveal that customizing recipes and offerings significantly boosts customer satisfaction or drives sales growth. However, reliance on alternative suppliers compromises quality.","presenter":"Mr. Jaewoo Lee","authors":[{"name":"Mr. Jaewoo Lee","aff":"Student, University of South Carolina"},{"name":"Prof. Keith Skowronski","aff":"Associate Professor, University of South Carolina"},{"name":"Dr. Sean Handley","aff":"Professor, University of South Carolina"}],"order":1},{"id":"136-1002","title":"Learning to see: Addressing hidden worker inefficiencies through Digitalization","content":"We investigate how digital manufacturing can uncover hidden inefficiencies and their implications for supporting workers. Using a social information asymmetry perspective, we conducted a multiple-case study within 50 companies. We provide insights into three types of hidden inefficiencies due to: (a) unawareness, (b) workers’ errors; (c) buffer creation.","presenter":"Prof. Alejandro Frank","authors":[{"name":"Prof. Alejandro Frank","aff":"Professor, Federal University of Rio Grande do Sul"},{"name":"Prof. Matthias Thurer","aff":"Professor, Chemnitz University of Technology"}],"order":2},{"id":"136-1285","title":"Harnessing Neuroscience in Operations Management: Best Practices and Emerging Insights","content":"This paper explores integrating neuroscience methods into operations management, using tools like EEG, GSR, and eye-tracking to analyze cognition, decision-making, and performance. By connecting neural activity to operational strategies, it aims to enhance understanding of processes like workload management, error mitigation, and adaptive interfaces in supply chain contexts.","presenter":"Prof. Vipul Garg","authors":[{"name":"Prof. Suman Niranjan","aff":"Assistant Professor, University of North Texas"},{"name":"Prof. Vipul Garg","aff":"Assistant Professor, San Antonio"},{"name":"Dr. Janeth Gabaldon","aff":"Assistant Professor, University of Arkansas"},{"name":"Dr. Arunachalam Narayanan","aff":"Professor, University of North Texas"}],"order":3},{"id":"136-1823","title":"Reality Check: Evaluating Wearable Technology in Workforce Pooling Through a Natural Field Experiment","content":"Over a four-year natural field experiment analyzing 59,505 machine status reports, we evaluate the impact of wearable technology on real-time workforce pooling in a global manufacturing firm. The findings show that teams using the technology performed significantly worse compared to control groups without it.","presenter":"Dr. Daniel Kwasnitschka","authors":[{"name":"Dr. Daniel Kwasnitschka","aff":"Assistant Professor, University of South Carolina"},{"name":"Prof. Henrik Franke","aff":"Assistant Professor, University of Cologne"},{"name":"Dr. Richard von Maydell","aff":"Research Fellow, European Commission"}],"order":4}]},{"id":"s159","title":"Harnessing Data and AI: Opportunities and Threats","track":"Healthcare Analytics","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"GRAND HALL EAST D","chairs":["Prof. Bogdan Bichescu"],"abstracts":[{"id":"136-0297","title":"Robust AI-Guided Radiotherapy Planning","content":"Artificial intelligence (AI) guided radiotherapy has the potential to increase access to treatments for traditionally underserved communities. However, AI models can suffer from limited training data, which can jeopardize the treatment. We propose a robust optimization framework that can control for AI model errors, and produce less sensitive treatment plans.","presenter":"Prof. Arkajyoti Roy","authors":[{"name":"Prof. Arkajyoti Roy","aff":"Assistant Professor, University of Texas at San Antonio"}],"order":1},{"id":"136-1428","title":"Evaluating the Impact of Information Sharing on Data Breach Risks in Hospitals","content":"Information sharing enhances critical infrastructure security by fostering collaboration and sharing threat intelligence. Our study examines its impact on hospital data breaches, using data from 2017-2022. Results show an 8% reduction in breach risk for members, with variations based on membership timing, organization size, and system affiliation.","presenter":"Dr. Sung Choi","authors":[{"name":"Dr. Sung Choi","aff":"Assistant Professor, University of Central Florida"},{"name":"Dr. Min Chen","aff":"Associate Professor, Florida International University"}],"order":2},{"id":"136-1432","title":"Insights on ransomware attacks: a comparative analysis of the healthcare sector","content":"This study investigates ransomware attacks on the U.S. healthcare sector, analyzing their impact and contributing factors using data from 2013-2023. Findings show healthcare experiences longer attack durations, especially when ransoms aren't paid. Single-sign-on authentication reduces attack odds by 51%. The study underscores the need for robust cybersecurity measures in healthcare.","presenter":"Dr. Sung Choi","authors":[{"name":"Dr. Sung Choi","aff":"Assistant Professor, University of Central Florida"}],"order":3},{"id":"136-1505","title":"Effects of Continuity of Care on Outcomes: Evidence from CABG Patients","content":"We examine the relationship between continuity of care (CoC) and care outcomes for patients undergoing coronary-artery bypass grafting (CABG). We find that CoC is associated with lower patient length of stay and readmission risk, but does not affect charges. These relationships are moderated by physician utilization and focus.","presenter":"Mr. Dawson Maddox","authors":[{"name":"Mr. Dawson Maddox","aff":"Student, University of Tennessee, Knoxville"}],"order":4}]},{"id":"s192","title":"Platforms and Service Operations","track":"Service Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY C","chairs":["Dr. Necati Tereyagoglu","Dr. Sriram Venkataraman"],"abstracts":[{"id":"136-0651","title":"Transparent or Not? Optimal Performance Feedback to Service Users","content":"In many gamified services, users receive individual performance feedback upon service completion, which shapes their perception of goal achievement and relative status. How transparent should service providers be in their individual performance feedback to maximize the utility users? We employ a Bayesian persuasion framework to determine the optimal policy.","presenter":"Ms. Lin Chen","authors":[{"name":"Ms. Lin Chen","aff":"Student, INSEAD"},{"name":"Prof. Guillaume Roels","aff":"Professor, INSEAD"}],"order":1},{"id":"136-0784","title":"Unveiling Student Frustration in Online Education: Patterns and Interventions","content":"This study investigates methods to identify student frustration by analyzing interaction logs from an online education platform. By detecting behavioral patterns associated with frustration, we aim to provide actionable insights. These findings empower educators to offer timely support and improve engagement.","presenter":"Ms. Ling Li","authors":[{"name":"Dr. Christopher Chen","aff":"Assistant Professor, Indiana University Bloomington"},{"name":"Ms. Ling Li","aff":"Student, Kelley School of Business"},{"name":"Prof. Owen Wu","aff":"Associate Professor, Indiana University"},{"name":"Dr. Wenchang Zhang","aff":"Assistant Professor, Kelley School of Business"}],"order":2},{"id":"136-1697","title":"Generative AI in Practice: Exploring the Role of Humans in the Loop","content":"The emergence of generative AI provides online platforms with an innovative tool to enhance services. However, identifying the most appropriate services to pair with AI remains a challenge. We conduct a field experiment to investigate how human-AI interactions vary across different types of AI, providing insights into optimizing these services.","presenter":"Mr. Yizhe Li","authors":[{"name":"Dr. Hongyan Dai","aff":"Professor, Central University of Finance And Economics"},{"name":"Mr. Yizhe Li","aff":"Student, UNC Kenan-Flagler Business School"},{"name":"Prof. Jayashankar Swaminathan","aff":"Professor, University of North Carolina Chapel Hill"},{"name":"Prof. Yuqian Xu","aff":"Associate Professor, UNC Chapel Hill"}],"order":4}]},{"id":"s215","title":"Emerging Topics in Retail Operations-2","track":"Retail Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"FAIRLIE","chairs":["Prof. Nil Karacaoglu"],"abstracts":[{"id":"136-0494","title":"Generative AI in Action: Field Experimental Evidence on Worker Performance in E-Commerce Customer Service Operations","content":"This study, using a large-scale field experiment with Alibaba, examines the effects of generative AI on e-commerce customer service agents. Generative AI improved service speed and quality, with gains for low performers. Findings highlight its potential to boost efficiency while emphasizing the need for tailored deployment for diverse skill levels.","presenter":"Ms. Xiao Ni","authors":[{"name":"Ms. Xiao Ni","aff":"Student, Fudan University"},{"name":"Prof. Yiwei Wang","aff":"Assistant Professor, Zhejiang University"},{"name":"Dr. Tianjun Feng","aff":"Professor, Fudan University"},{"name":"Prof. Lauren Lu","aff":"Professor, Dartmouth College"}],"order":1},{"id":"136-0521","title":"Inventory Competition, Excess Stocks, and Stockout Costs","content":"We examine excess stocks and stockout costs based on a model of spatial demand and competition in prices and inventories among food retailers. We find higher stockout costs than in prior literature, and excess inventory relative to monopoly conditions. This suggests retail competition contributes to excess food stocks and waste.","presenter":"Dr. Timothy Richards","authors":[{"name":"Dr. Timothy Richards","aff":"Professor, Arizona State University"},{"name":"Dr. Stephen Hamilton","aff":"Professor, California Polytechnic State University San Luis Obispo"},{"name":"Prof. Elliot Rabinovich","aff":"Professor, Arizona State University Tempe"},{"name":"Dr. Lauren Chenarides","aff":"Assistant Professor, Colorado State University"}],"order":2},{"id":"136-0854","title":"Modeling Assortment Decisions in Kenyan Pharmacies","content":"The role of private pharmacies in enhancing access to medicines in developing countries is increasingly recognized. To optimize their impact in delivering essential medicines, this study models pharmacists' assortment decisions using data from a Kenyan inventory software provider.","presenter":"Ms. Johanna Behrens","authors":[{"name":"Prof. Jan Fransoo","aff":"Professor, Tilburg University"},{"name":"Dr. Thomas Breugem","aff":"Associate Professor, Tilburg University"},{"name":"Prof. Prashant Yadav","aff":"Professor, INSEAD"},{"name":"Ms. Johanna Behrens","aff":"Student, Tilburg University"}],"order":3},{"id":"136-1311","title":"Promotional Design for Small Businesses: The Operational Value of Online Deals","content":"In this paper, we empirically study how small service providers use online deals to manage demand swings driven by holidays. We use a structural model built on service providers optimally designing “holiday” deals that anticipate a positive or negative demand shock.","presenter":"Prof. Simin Li","authors":[{"name":"Prof. Simin Li","aff":"Assistant Professor, Tulane University"},{"name":"Prof. Kejia Hu","aff":"Associate Professor, University of Oxford"},{"name":"Prof. Martin Lariviere","aff":"Professor, Northwestern University"}],"order":4}]},{"id":"s238","title":"Advances in Revenue Management and Choice Modeling","track":"Digital Platforms, Innovations and Transformations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"GREENBRIAR","chairs":["Prof. Ashwin Venkataraman","Mr. Mohammad Amin Farzaneh"],"abstracts":[{"id":"136-1223","title":"Customer-Driven Bundle Promotion Optimization at Scale","content":"We study a new class of bundle promotions that are offered during customers need-based shopping. We propose a conditional customer-choice framework and prove the problem is APX-hard. We design a linear-time approximation algorithm with performance guarantee and demonstrate the excellent performance with various numerical examples.","presenter":"Prof. Yuexing Li","authors":[{"name":"Prof. Ali Fattahi","aff":"Assistant Professor, Johns Hopkins University"},{"name":"Prof. Yuexing Li","aff":"Assistant Professor, Johns Hopkins University"},{"name":"Prof. Ozge Sahin","aff":"Associate Professor, Johns Hopkins University"}],"order":1},{"id":"136-1511","title":"Leveraging Assortment Similarities for Data-driven Demand Predictions","content":"We propose simple demand prediction approaches relying solely on the similarity between product assortments, which are data-driven (requiring no ground-truth choice model knowledge), model-free (involving no estimation), and consistent. Our methods outperform common benchmarks in prediction and decision performance on simulated data and demonstrate superior prediction accuracy on real data.","presenter":"Mr. Mohammad Amin Farzaneh","authors":[{"name":"Mr. Mohammad Amin Farzaneh","aff":"Student, University of Texas Dallas"},{"name":"Prof. Ashwin Venkataraman","aff":"Assistant Professor, University of Texas Dallas"},{"name":"Prof. Tarek Abdallah","aff":"Assistant Professor, Northwestern University Kellogg School o"}],"order":2},{"id":"136-1736","title":"Bundling with Doubly Sparse Interactions: Estimation and Assortment Optimization for Bundling under the Multivariate MNL","content":"We present a reformulated multivariate multinomial logit model for bundle purchases, reducing computational complexity by predicting choices in one category conditional on others. Assuming sparse cross-category interactions, we propose efficient estimation and optimization methods, enabling practical applications like assortment optimization and pricing in high-dimensional settings with numerous products and categories.","presenter":"Prof. Heng Zhang","authors":[{"name":"Dr. Selene Mengxin Wang","aff":"Assistant Professor, University of Texas Dallas"},{"name":"Prof. Heng Zhang","aff":"Assistant Professor, Arizona State University"}],"order":3}]},{"id":"s239","title":"Managing Risk in Healthcare via Incentive and Payment Schemes","track":"Supply Chain Risk Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY H","chairs":["Dr. Ozge Yapar"],"abstracts":[{"id":"136-0356","title":"Push or Pull: An Optimal Funding Mechanism for Global Health Products","content":"Drugs for tropical diseases and potential pandemic threats typically do not generate sufficient profit from the market to cover the development costs. In order to induce participation efficiently, a funding agency needs to decide when and how to fund a pharmaceutical firm and manage the aforementioned incentives.","presenter":"Mr. Chenxi Xu","authors":[{"name":"Mr. Chenxi Xu","aff":"Student, Duke University"},{"name":"Prof. David Ridley","aff":"Professor, Duke University"},{"name":"Prof. Peng Sun","aff":"Professor, Duke University Durham"}],"order":1},{"id":"136-0540","title":"The $10 Billion Blind Spot: Resolving a Statistical Challenge in Healthcare Risk Adjustment","content":"Inspired by a recent change proposed by CMS, we develop a novel estimation algorithm to improve the prediction accuracy of the HHS-HCC risk adjustment model. We empirically demonstrate that our method achieves nearly perfect actuarial equivalence across all patient risk classes.","presenter":"Dr. Zhaowei She","authors":[{"name":"Dr. Zhaowei She","aff":"Assistant Professor, Singapore Management University"},{"name":"Dr. Kanix Wang","aff":"Assistant Professor, University of Cincinnati"}],"order":2},{"id":"136-0607","title":"Value-based Pricing and Conditional Approval for Multiple Patient Subgroups","content":"Conditional-approval schemes postpone a treatment’s reimbursement decision until after the collection of post-marketing data to mitigate uncertainty regarding its health-economic value. We use a game-theoretic framework to analyze when to use and how to design such schemes when multiple patient subgroups that differ in health-economic value estimates are identified.","presenter":"Dr. Ozge Yapar","authors":[{"name":"Dr. Ozge Yapar","aff":"Assistant Professor, Indiana University Bloomington"}],"order":3}]},{"id":"s244","title":"Empirical Healthcare Operations","track":"Healthcare Analytics","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"INMAN","chairs":["Prof. Jun Li","Prof. Xinyu Liang"],"abstracts":[{"id":"136-0111","title":"Product Recall Ramifications of Relaxing Software Approval Standards at the FDA","content":"Software is a pivotal dimension of medical device performance, but it can also be a black box. Using a difference-in-differences approach, we find that a 2016 FDA policy change inadvertently allowed firms to fix software-related quality defects while circumventing the negative but necessary consequences of a product recall.","presenter":"Prof. George Ball","authors":[{"name":"Prof. Seongkyoon Jeong","aff":"Assistant Professor, University of Tennessee Knoxville"},{"name":"Mr. Akshat Lakhiwal","aff":"Student, Indiana University"},{"name":"Dr. Eunae Yoo","aff":"Assistant Professor, Indiana University Bloomington"},{"name":"Prof. George Ball","aff":"Associate Professor, Kelley School of Business, Indiana Univ."}],"order":1},{"id":"136-1415","title":"Pharmaceutical quality risk and resilience","content":"We will present progress of federally-funded research on pharmaceutical supply chain quality risk and resilience.","presenter":"Dr. John Gray","authors":[{"name":"Dr. John Gray","aff":"Professor, Ohio State University"},{"name":"Dr. Robert Handfield","aff":"Professor, North Carolina State University"}],"order":2},{"id":"136-1831","title":"The Ripple Effects of Hospital Closures on Nursing Home Demand, Staffing, and Care Quality","content":"Hospital closures have far-reaching consequences for healthcare delivery, yet their impact on nursing homes—a critical component of post-acute and long-term care—remains understudied. This research examines how hospital closures affect nursing home operations, with a focus on the dynamics of demand inflows, care delivery capacity, and quality of care.","presenter":"Prof. Jong Myeong Lim","authors":[{"name":"Prof. Xinyu Liang","aff":"Assistant Professor, INSEAD"},{"name":"Prof. Jong Myeong Lim","aff":"Assistant Professor, Miami Herbert Busienss School"}],"order":3}]},{"id":"s252","title":"Healthcare Supply Chain and Operations","track":"Supply Chain Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY A","chairs":["Dr. Justin Jia"],"abstracts":[{"id":"136-0247","title":"Reimbursement Policy and Drug Shortages","content":"Generic drug shortages have posed significant challenges to the U.S. pharmaceutical industry. Little research has captured the connections among reimbursement policies, shortages, and the influence of GPOs. We analyze a drug supply model that captures the elements and tradeoffs in drug price decisions and prominent effects under the reimbursement policy.","presenter":"Ms. Xuejun Zhao","authors":[{"name":"Ms. Xuejun Zhao","aff":"Assistant Professor, University of North Carolina Charlotte"},{"name":"Dr. Justin Jia","aff":"Associate Professor, University of Tennessee"},{"name":"Prof. Hui Zhao","aff":"Associate Professor, Penn State University University Park"}],"order":1},{"id":"136-0306","title":"Data Driven Optimization of Telehealth Appointments","content":"As medical practices adopt omnichannel service models, scheduling virtual and in-office consultations becomes challenging. We propose a learning-based optimization model using MEPS data to predict patient preferences. We then improve the schedule by minimizing waiting time, physician idle time, and overtime. Service variability, no-shows, same-day appointment requests are also considered.","presenter":"Dr. Ali Dogru","authors":[{"name":"Mr. Emirhan Uzunlar","aff":"Student, University of Nebraska Lincoln"},{"name":"Dr. Ali Dogru","aff":"Assistant Professor, University of Southern Mississippi"},{"name":"Dr. Ibrahim Capar","aff":"Assistant Professor, University of North Carolina Wilmington"},{"name":"Prof. Ozgur Araz","aff":"Professor, University of Nebraska Lincoln"}],"order":2},{"id":"136-0527","title":"Evaluating the Efficacy of Providers’ Compensation Contracts in Improving Participant Retention for Clinical Studies","content":"To improve participant retention, the clinical study sponsors often provide monetary payments to participants and compensate providers (investigators and coordinators) for their efforts. In this work, we examine the cost performance of three widely adopted compensation contracts—fixed, linear, and condition linear—in improving participant retention.","presenter":"Dr. Xueze Song","authors":[{"name":"Dr. Xueze Song","aff":"Assistant Professor, The University of Alabama"},{"name":"Dr. Mili Mehrotra","aff":"Associate Professor, University of Illinois"},{"name":"Dr. Tharanga Rajapakshe","aff":"Associate Professor, University of Florida"}],"order":3},{"id":"136-1088","title":"AI Adoption in Hospital Operations: Influential Factors and Performance Outcomes","content":"Leveraging public and proprietary datasets, we examine the factors influencing hospitals' adoption of artificial intelligence (AI) to enhance operations and its effect on operations performance. We find that hospital size and funding availability are key drivers of AI adoption for operational improvement, which subsequently enhances throughput and reduces waiting times.","presenter":"Mr. Abdullah Salau","authors":[{"name":"Dr. Justin Jia","aff":"Associate Professor, University of Tennessee"},{"name":"Prof. Yuanyang Liu","aff":"Assistant Professor, University of Tennessee, Knoxville"},{"name":"Mr. Abdullah Salau","aff":"Student, University of Tennessee, Knoxville"}],"order":4},{"id":"136-1749","title":"Social Media as a Platform for Opioid Use Disorder Support and Management","content":"Social media platforms are important venues for individuals affected by opioid use disorders to seek support. This project leverages language models to examine the potential impact and perceived helpfulness of these exchanges, considering user engagement and domain-specific factors, and offers actionable insights into fostering more informative and supportive online conversations.","presenter":"Prof. Savannah Tang","authors":[{"name":"Prof. Savannah Tang","aff":"Assistant Professor, SMU Cox School of Business"}],"order":5}]},{"id":"s254","title":"Technology Management","track":"Information Systems and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"SPRING","chairs":["Prof. Rajib Saha"],"abstracts":[{"id":"136-0229","title":"Incentives for Improving Patient Health under mHealth","content":"The use of mobile health (mHealth) can improve health outcomes and increase efficiency. However, patient engagement after adoption remains a challenge. How should incentives be designed to improve patient engagement and health in the context of mHealth? How do they impact the key stakeholders?","presenter":"Dr. ARVIND SAINATHAN","authors":[{"name":"Prof. Saligrama Agnihothri","aff":"Professor, Binghamton University"},{"name":"Dr. ARVIND SAINATHAN","aff":"Associate Professor, NEOMA Business School"},{"name":"Dr. Balaraman Rajan","aff":"Associate Professor, California State University East Bay"}],"order":1},{"id":"136-0499","title":"Analyzing Firm Strategies for Software Marketplaces","content":"In today's cloud-driven environment, software firms increasingly leverage digital marketplaces for distribution. We examine contractual arrangements between software vendors, enterprise users, and marketplace platforms. Our analysis compares how different contracting models impact the dynamics and outcomes for all three stakeholders across the ecosystem.","presenter":"Prof. Rajib Saha","authors":[{"name":"Prof. Rajib Saha","aff":"Associate Professor, Indian School of Business"},{"name":"Dr. ARVIND SAINATHAN","aff":"Associate Professor, NEOMA Business School"}],"order":2},{"id":"136-1842","title":"The Effectiveness of Law and Tech Against Cyberbullying","content":"In this study, we analyze whether online antiharassment laws and their interaction with technological capabilities of the prosecutor’s office influence the incidence of cyberbullying. Methodologically, we use a difference in difference (DID) model in a natural experiment set-up.","presenter":"Dr. Mariana G. Andrade-Rojas","authors":[{"name":"Dr. Mariana G. Andrade-Rojas","aff":"Associate Professor, University of Georgia"}],"order":3},{"id":"136-0372","title":"Social Engagement with Online Deals: The Role of Discounts and Poster Reputation","content":"This study examines the relationship between online discount deals and user comment behavior in online deal communities. Using a large dataset of discounted products, it explores how deal characteristics drive engagement and how deal posters' reputation moderates this relationship, providing insights into user interaction dynamics within these communities.","presenter":"Dr. Tong Wu","authors":[{"name":"Dr. Tong Wu","aff":"Assistant Professor, Western Kentucky University"}],"order":4}]},{"id":"s260","title":"Grocery retailing","track":"POM-Marketing Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"DUNWOODY","chairs":["Prof. Necati Ertekin","Ms. Orchi Bhattacharyya"],"abstracts":[{"id":"136-1134","title":"Enhancing Supply Chain Resilience in Local Food Distribution: Implications for Wholesale Prices and Inventory Management","content":"In this work, we address the operational challenges faced by local food distributors when sourcing from small and medium scale farms. To this end, we partnered with a Michigan-based local food distributor and developed a choice-based framework to accurately estimate customer demand and propose efficient sourcing strategies.","presenter":"Dr. Goutham Takasi","authors":[{"name":"Dr. Goutham Takasi","aff":"Assistant Professor, University of Alabama Tuscaloosa"},{"name":"Prof. Stanley Lim","aff":"Assistant Professor, Michigan State University"},{"name":"Dr. Monireh Mahmoudi","aff":"Assistant Professor, Michigan State University"}],"order":1},{"id":"136-0337","title":"The Interplay Between Platform Private Label Introduction and Supplier Encroachment Format","content":"This study investigates a national brand supplier cooperating with a platform retailer who can introduce high/low-end private label products. The supplier can encroachment the channel with direct format or agency format. By identifying the trade-off between commission rate and direct encroachment cost, it characterizes the equilibrium optimal strategy.","presenter":"Mrs. Xingze Li","authors":[{"name":"Mrs. Xingze Li","aff":"Student, School of Economics and Management, Southeast University"},{"name":"Ms. Xianmei Zhang","aff":"Student, Southeast University"},{"name":"Prof. Weili Xue","aff":"Professor, Southeast University"}],"order":2},{"id":"136-2046","title":"Markdowns to Manage Food Waste and Their Impact on Retail Brand Image","content":"Markdowns effectively reduce retail food waste, but many U.S. retailers hesitate due to brand image concerns. Our experiments show markdowns don’t harm brand perception but highlight the importance of presentation. We also observed geographical differences in responses across the UK, US, Germany, France, and South Africa.","presenter":"Ms. Arzum Akkas","authors":[{"name":"Ms. Arzum Akkas","aff":"Associate Professor, University of Massachusetts"},{"name":"Mr. Remi Trudel","aff":"Professor, Boston University"}],"order":4},{"id":"136-0395","title":"Going Local: Authenticity of Retailers' Buy-from-Local-Suppliers Programs","content":"This study investigates Buy-from-Local-Suppliers programs, in which grocery retailers offer local food products in their assortment. Using data from a Canadian online retailer and an online experiment, we explore the impact of local certifications on sales of local food products, offering insights for effectively leveraging certifications in grocery retailing.","presenter":"Ms. Orchi Bhattacharyya","authors":[{"name":"Ms. Orchi Bhattacharyya","aff":"Student, University of Minnesota - Twin Cities"},{"name":"Prof. Necati Ertekin","aff":"Associate Professor, University of Minnesota"},{"name":"Prof. Mehmet Gumus","aff":"Professor, McGill University"},{"name":"Prof. Karen Donohue","aff":"Professor, University of Minnesota"}],"order":5}]},{"id":"s300","title":"Emerging Technologies in Operations Management","track":"Manufacturing Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"LENOX","chairs":["Prof. Ye Liu"],"abstracts":[{"id":"136-0710","title":"Learning from Click Transition Data: Effectiveness of Greedy Pricing Policy under Dynamic Product Availability","content":"We study how to utilize random clicking behaviors of customers to optimize online retailers' pricing strategies using the real-world data. We introduce a new dynamic attraction click model based on a Markov chain. We demonstrate the effectiveness of an exploration-free online greedy algorithm and derive a sublinear regret bound.","presenter":"Prof. Mo Liu","authors":[{"name":"Prof. Mo Liu","aff":"Assistant Professor, University of North Carolina at Chapel Hill"},{"name":"Dr. Junyu Cao","aff":"Assistant Professor, University of Texas Austin"},{"name":"Prof. Max Shen","aff":"Professor, University of Hongkong"}],"order":1},{"id":"136-0773","title":"Mitigating the Spiral Down Effect: Revenue Management under Branded Fare Structure","content":"This paper addresses challenges in airline revenue management under branded fare structures by introducing a two-phase methodology using an adjusted fare concept and the Bayes Selector algorithm. The approach achieves near-optimal revenue performance, adapts to dynamic demand, and is validated through simulations and case studies, demonstrating significant profitability improvements.","presenter":"Ms. Lan Wu","authors":[{"name":"Ms. Lan Wu","aff":"Student, National University of Singapore"},{"name":"Prof. Changchun Liu","aff":"Associate Professor, Xi'an Jiaotong University"},{"name":"Prof. Chung-Piaw Teo","aff":"Professor, National University of Singapore"},{"name":"Dr. Xun Zhang","aff":"Post Doc/Researcher, National University of Singapore"}],"order":2},{"id":"136-1108","title":"Multi-Agent Socratic Large Language Models Master the Beer Game: A Supply Chain Decision-Making Study","content":"The integration of large language models into organizational decision-making is hindered by their limited domain-specific reasoning. We introduce Socratic Iterative Prompt Engineering, a human-guided methodology to enhance LLMs' domain expertise. Using the beer game simulation, we demonstrate SIPE-enhanced agents outperform baseline LLMs, RAG, and CoT approaches.","presenter":"Prof. Léonard Boussioux","authors":[{"name":"Prof. Léonard Boussioux","aff":"Assistant Professor, University of Washington"},{"name":"Mr. Andrew Chen","aff":"Student, Foster School of Business"},{"name":"Dr. Ming Fan","aff":"Professor, University of Washington"},{"name":"Prof. Apurva Jain","aff":"Associate Professor, University of Washington"}],"order":3},{"id":"136-1264","title":"Performance of simple policies in a dual sourcing inventory system","content":"We consider the performance of simple policies, namely optimal sourcing solely from the regular supplier and TBS policies, in a dual sourcing system. Using previously known results, we characterise performance of these policies in asymptotic regimes and compare their costs against that of the optimal policy.","presenter":"Dr. Sripad Devalkar","authors":[{"name":"Prof. Sridhar Seshadri","aff":"Professor, University of Illinois Urbana-Champaign"},{"name":"Dr. Sripad Devalkar","aff":"Associate Professor, Indian School of Business"}],"order":4},{"id":"136-0954","title":"Newsvendor Problems and Mean-Variance Tradeoffs","content":"We provide a general framework for the solution of mean-variance newsvendor problems and explore the effect of the variance function in its optimal solution. We illustrate our findings with several examples from the literature and extend our results to price-setting newsvendor problems.","presenter":"Dr. Javier Rubio-Herrero","authors":[{"name":"Dr. Javier Rubio-Herrero","aff":"Assistant Professor, University of North Texas"},{"name":"Dr. Melike Baykal-Gursoy","aff":"Associate Professor, Rutgers University"}],"order":5}]},{"id":"s302","title":"Recent Advances in Suppy Chain and Logistics Analytics","track":"Aviation, Transportation, and Logistics Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"UNIVERSITY","chairs":["Dr. Yue Zhao","Mr. Sheng Liu"],"abstracts":[{"id":"136-1963","title":"Distributionally Robust Operations of Networked Distribution Centers at Scale","content":"We study distributionally robust network inventory management with cross-fulfillment using a scenario-based approach that is adaptable to feature information, demand correlation and inventory dynamics. Our framework yields tractable and robust solutions. We demonstrate its superior performance by a case study using data from a major logistics service provider in China.","presenter":"Dr. Aiqi Zhang","authors":[{"name":"Ms. Chenxi Li","aff":"Student, Beijing Institute of Technology"},{"name":"Mr. Sheng Liu","aff":"Assistant Professor, Rotman School of Management"},{"name":"Prof. Wei Qi","aff":"Associate Professor, Tsinghua University Department of IE"},{"name":"Prof. Lun Ran","aff":"Professor, Beijing Institute of Technology"},{"name":"Dr. Aiqi Zhang","aff":"Assistant Professor, Wilfrid Laurier University"}],"order":1},{"id":"136-1968","title":"Robust Workforce Management with Crowdsourced Delivery","content":"We investigate workforce management on crowdsourced delivery platforms with contracted and ad-hoc couriers under uncertainty. By introducing reduced information models to estimate crowdsourcing costs and a robust satisficing model solved via binary search, we demonstrate superior out-of-sample performance, balancing cost minimization and delivery efficiency in uncertain environments.","presenter":"Dr. Yue Zhao","authors":[{"name":"Prof. Chun Cheng","aff":"Professor, Dalian University of Technology"},{"name":"Prof. Melvyn Sim","aff":"Professor, National University of Singapore"},{"name":"Dr. Yue Zhao","aff":"Post Doc/Researcher, University of Toronto"}],"order":2},{"id":"136-1970","title":"Efficient Branching Rules for Optimizing Range and Order-Based Objective Functions","content":"We consider order-based minimization problems, which frequently arise in fairness-oriented or bi-objective optimization. We propose order branching, a generic branching rule that can be used on top of branch and price to tackle such problems. We show how it can be applied on problems like fair capacitated vehicle routing.","presenter":"Prof. Rui Chen","authors":[{"name":"Prof. Rui Chen","aff":"Assistant Professor, Chinese Univ of Hong Kong (Shenzhen)"}],"order":3}]},{"id":"s309","title":"Robust Optimization in Pricing and Revenue Management","track":"Revenue Management and Pricing","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"MARIETTA","chairs":["Mr. Ru Zhang"],"abstracts":[{"id":"136-0217","title":"Relatively Robust Multiproduct Pricing","content":"We develop robust multiproduct pricing under demand uncertainty, using a worst-case profit ratio to measure performance. Leveraging an envelope property simplifies computations. The underlying linear demand model with interval-based parameter inputs generalizes to situations with nonlinear demand. Real-world examples show our approach outperforms results from optimizing standard robustness criteria.","presenter":"Mr. Ru Zhang","authors":[{"name":"Mr. Ru Zhang","aff":"Student, EPFL CDM MTEI TOM"},{"name":"Prof. Thomas Weber","aff":"Associate Professor, EPFL"}],"order":1},{"id":"136-1193","title":"The Best of Many Robustness Criteria in Decision Making: Formulation and Application to Robust Pricing","content":"This paper studies overfitting to robustness criteria in robust pricing under various information structures, and three criteria: revenue, regret, and ratio. Mechanisms optimized for one criterion often perform poorly against other criteria. Remarkably, there are mechanisms achieving good performance across all three criteria simultaneously; decision-makers need not compromise among criteria.","presenter":"Mr. Jerry Anunrojwong","authors":[{"name":"Mr. Jerry Anunrojwong","aff":"Student, Columbia University"},{"name":"Prof. Santiago Balseiro","aff":"Associate Professor, Columbia University"},{"name":"Prof. Omar Besbes","aff":"Professor, Columbia University"}],"order":2},{"id":"136-0690","title":"Trade-off between Seller's Revenue and Buyers' Welfare in Product Line Design through Distributionally Robust Optimization","content":"We focus on a revenue maximizing product line design problem and show that a distributionally robust optimization model of the problem will guarantee a bettter buyers' welfare. This result indicates a motivation of a revenue maximizing decision maker to consider buyers' welfare from the lens of uncertainty aversion.","presenter":"Dr. Maoqi Liu","authors":[{"name":"Dr. Maoqi Liu","aff":"Assistant Professor, School of Management, Shandong University"}],"order":3},{"id":"136-1198","title":"Robust Auction Design with Support Information","content":"The seller wants to sell an item to n i.i.d. buyers and only support [a,b] is known. The objective is worst-case regret or ratio. With low a/b, second-price auctions (SPA) is optimal; with high a/b, the \"pooling auction\" (POOL) is optimal; else, a combination of SPA and POOL is optimal.","presenter":"Mr. Jerry Anunrojwong","authors":[{"name":"Mr. Jerry Anunrojwong","aff":"Student, Columbia University"},{"name":"Prof. Santiago Balseiro","aff":"Associate Professor, Columbia University"},{"name":"Prof. Omar Besbes","aff":"Professor, Columbia University"}],"order":4}]},{"id":"s319","title":"Empirical Research in Operations Management","track":"Supply Chain Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"GRAND HALL EAST A","chairs":["Dr. Shubhobrata Palit"],"abstracts":[{"id":"136-1035","title":"The Effect of CAFE Standards on Environmental and Economic outcomes of automakers","content":"This study empirically examines the impact of U.S. Corporate Average Fuel Economy (CAFE) standards on CO2 emissions and automakers' economic performance. By analyzing technological adoption and vehicle attributes from 2008 to 2019, we find that CAFE standards significantly reduce CO2 emissions while enhancing manufacturers' economic outcomes.","presenter":"Dr. Fahimeh Chomachaei","authors":[{"name":"Dr. Fahimeh Chomachaei","aff":"Assistant Professor, University of Massachusetts Boston"},{"name":"Prof. Robert Klassen","aff":"Professor, Ivey Business School, Western University"}],"order":1},{"id":"136-1247","title":"On state-subsidized medication and its impact on household welfare and worker productivity","content":"This study examines the impact of a state healthcare initiative of establishing a distribution channel for affordable generic medicines. We leverage this natural experiment to evaluate the policy's impact on household welfare and worker productivity by utilizing staggered store-rollout data combined with a large household panel dataset.","presenter":"Mr. Sid Yamalakonda","authors":[{"name":"Ms. Medha Kanakamedala","aff":"Student, Auburn University"},{"name":"Mr. Sid Yamalakonda","aff":"Student, Auburn University"},{"name":"Prof. Kang Bok Lee","aff":"Associate Professor, Auburn University"},{"name":"Prof. Krishanu Rakshit","aff":"Associate Professor, ICN Business School"},{"name":"Dr. Shashank Rao","aff":"Professor, Auburn University"}],"order":2},{"id":"136-1347","title":"Exploring the Influence of Community Structures on Innovation in Supply Networks","content":"This study explores how meso structures in supply networks influence innovation, emphasizing a firm's position within and between communities. By integrating firm attributes like industry and size, we identify supply-related communities and investigate how cross-community diversity and efficiency moderate the relationship between network positioning and innovation capacity.","presenter":"Mr. Ayomide Thompson-Ajayi","authors":[{"name":"Mr. Ayomide Thompson-Ajayi","aff":"Student, Queen Mary University of London"}],"order":3},{"id":"136-1752","title":"How Does Production Outsourcing Influence Working Capital Management","content":"Effective working capital management enables better liquidity, cash flow, and operating performance. In this paper, we argue that a firm’s production outsourcing affects the financial structure, the operating structure, and the risk profile of a firm, thereby changing the calculus for optimizing levels of receivables, payables, and inventory.","presenter":"Dr. Jeremy Kovach","authors":[{"name":"Dr. Jeremy Kovach","aff":"Assistant Professor, University of North Texas"},{"name":"Prof. Morgan Swink","aff":"Professor, Texas Christian University"},{"name":"Dr. Mauricio Rodriguez","aff":"Professor, Texas Christian University"}],"order":4}]},{"id":"s330","title":"Supply Chain Finance","track":"POM-Finance Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"Learning Center","chairs":["Mr. Deepak Agrawal","Prof. Nikolay Osadchiy"],"abstracts":[{"id":"136-0534","title":"Effects of Financial Constraints on Supply Chain Financing Choices and Operational Decisions","content":"This study examines firms' inventory management decisions following the enhanced credit lines from the interstate bank branching laws, which introduced enhanced access to bank credit. Using datasets merged with credit line information from 10-K filings and a DID approach, we find that improved credit access leads to faster inventory turnover.","presenter":"Prof. Anqi Wu","authors":[{"name":"Prof. Anqi Wu","aff":"Assistant Professor, Florida International University"},{"name":"Prof. Qi Wu","aff":"Associate Professor, Case Western Reserve University"},{"name":"Prof. Sridhar Seshadri","aff":"Professor, University of Illinois Urbana-Champaign"}],"order":1},{"id":"136-1092","title":"Invoice Tokenization for Deep-Tier Payables Finance","content":"Blockchain-based invoice tokenization allows tier-1 suppliers to split and transfer manufacturer-backed invoices to tier-2 suppliers. This enables deeper-tier suppliers to secure financing at better rates by leveraging the manufacturer's superior credit rating. The study examines how this tokenization system affects decisions and profitability across different supply chain structures.","presenter":"Prof. Fasheng Xu","authors":[{"name":"Ms. Jing Hou","aff":"Student, Nanjing University"},{"name":"Prof. Burak Kazaz","aff":"Professor, Whitman School of Management"},{"name":"Prof. Fasheng Xu","aff":"Assistant Professor, University of Connecticut"}],"order":2},{"id":"136-1069","title":"Global Supply Chain Disruptions and Product Market Competition","content":"We examine how supply chain disruptions impact firms. We find that sales losses occured only among US firms operating in less competitive industries with the onset of the Covid pandemic. The policy implication is that fostering competition can mitigate the effect of negative supply shocks.","presenter":"Dr. Karca Aral","authors":[{"name":"Dr. Karca Aral","aff":"Associate Professor, Syracuse University"}],"order":3},{"id":"136-0892","title":"Calendar Effect Frictions and Reverse Factoring","content":"Reverse factoring is a widely used supply chain finance practice. We examine how calendar effects introduce frictions and affect suppliers’ discounting decisions under reverse factoring. We find these decisions are affected by the periodic clustering of cash outflows and the desire to signal liquidity to investors at quarter ends.","presenter":"Prof. David Wuttke","authors":[{"name":"Prof. David Wuttke","aff":"Assistant Professor, TUM School of Management, HN Campus"},{"name":"Prof. H. Sebastian Heese","aff":"Professor, North Carolina State University"},{"name":"Prof. Volodymyr Babich","aff":"Professor, Georgetown University"},{"name":"Ms. Begimai Marlenova","aff":"Student, Technische Universitat Munchen"}],"order":4}]},{"id":"s339","title":"Industry Studies Emerging Policy, Trends, and Strategies","track":"Industry Studies and Public Policy","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"KENNESAW","chairs":["Mr. Sparsh Sinha"],"abstracts":[{"id":"136-0997","title":"Navigating Import Restrictions: An Institutional Theory Perspective on Reshoring Decisions","content":"Adopting an Institutional Theory perspective, this study explores how firms respond to coercive pressures from import restrictions when making reshoring decisions. By examining firm and industry level moderating factors, we uncover nuanced responses to these coercive pressures. The findings provide actionable insights for policymakers aiming to encourage reshoring behaviors.","presenter":"Mr. Sparsh Sinha","authors":[{"name":"Mr. Sparsh Sinha","aff":"Student, University of Arkansas"},{"name":"Prof. Matthew Waller","aff":"Professor, University of Arkansas - Fayetteville"}],"order":1},{"id":"136-1905","title":"Regulating a Powerful Intermediary: A Natural Experiment in the Pharmaceutical Supply Chain","content":"Intermediary firms can improve supply chain performance by aggregating supply-demand and facilitating transactions. However, intermediaries have gained extensive power over time and adopted practices that harm other supply chain players. Through a natural experiment, we study the effect of the elimination of one intermediary practice on another supply chain entity.","presenter":"Mr. Nikhil Sharma","authors":[{"name":"Mr. Nikhil Sharma","aff":"Student, Ohio State University"},{"name":"Dr. John Gray","aff":"Professor, Ohio State University"}],"order":2},{"id":"136-1460","title":"Impact of the Biologics Price Competition Act on Biopharmaceutical Innovation","content":"The 2009 Biologics Price Competition and Innovation Act (BPCIA) influenced Biologics License Applications (BLAs), favoring firms with comprehensive application portfolio (New Drugs and Biologics). Enhanced lobbying and marketing capabilities amplified this effect, highlighting how regulatory shifts reshape innovation strategies in pharmaceuticals through changes in property rights allocation.","presenter":"Dr. Marouen Ben-Jebara","authors":[{"name":"Dr. Marouen Ben-Jebara","aff":"Assistant Professor, University of South Carolina Aiken"},{"name":"Dr. Lee Brown","aff":"Associate Professor, Texas Woman's University"},{"name":"Dr. Dinesh Hasija","aff":"Assistant Professor, Augusta University"},{"name":"Dr. Sachin Modi","aff":"Professor, University of Cincinnati"}],"order":3}]},{"id":"s408","title":"Healthcare Economics and Regulation","track":"Healthcare Operations Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"PIEDMONT","chairs":["Ms. Sara Mohammadi"],"abstracts":[{"id":"136-1765","title":"The Impact of Bundled Payments on Healthcare Delivery","content":"This study examines how changes in reimbursement structures, particularly bundled payment programs, influence hospital operational strategies. Using detailed analyses, we explore impacts on healthcare delivery standardization, patient length-of-stay variation, and staffing decisions, highlighting variations across care episodes and providing insights into operational adjustments under bundled payment models.","presenter":"Dr. Anand Bhatia","authors":[{"name":"Dr. Anand Bhatia","aff":"Assistant Professor, IE BUSINESS SCHOOL"},{"name":"Prof. Jayashankar Swaminathan","aff":"Professor, University of North Carolina Chapel Hill"}],"order":1},{"id":"136-1133","title":"Cost-Effective Surveillance Strategies for Early Detection of Cancer Recurrence: Optimal Integration of Imaging and ctDNA","content":"This research develops a data-driven POMDP model to optimize post-cancer surveillance strategies by integrating ctDNA testing with imaging. Using Bayesian methods, it personalizes screening schedules based on patient risk factors, minimizing costs while enhancing early cancer recurrence detection. The approach balances cost-effectiveness and clinical outcomes, supporting informed healthcare policy decisions.","presenter":"Dr. Reza Skandari","authors":[{"name":"Ms. Narges Mohammadi","aff":"Student, Imperial College London"},{"name":"Dr. Reza Skandari","aff":"Assistant Professor, Imperial College London"},{"name":"Dr. Alexander Pearson","aff":"Associate Professor, University of Chicago"}],"order":3},{"id":"136-1148","title":"Impact of Regulation on Deceased-Donor Liver Offer Acceptance and Patient Welfare.","content":"We develop a novel empirical framework that jointly models the patient-centric considerations (exclusive to maximizing the survival chances) and regulatory considerations (to avoid the risk of regulatory scrutiny). Using simulation, we quantify the impact of regulations on the organ nonutilization, waiting list mortality, transplant rate and so on.","presenter":"Mr. Shubham Akshat","authors":[{"name":"Mr. Shubham Akshat","aff":"Assistant Professor, University of Houston"},{"name":"Dr. Liye Ma","aff":"Associate Professor, University of Maryland - College Park"}],"order":4},{"id":"136-0169","title":"Blended Payment Scheme of NHS England: Issues and Remedies","content":"NHS England's blended payment scheme includes fixed and variable elements tied to providers’ planned and actual activity levels to support resource planning. Utilizing a principal-agent model, we show that providers’ planned activity levels and costs under this payment model are suboptimal. We propose a new payment model to address this.","presenter":"Ms. Sara Mohammadi","authors":[{"name":"Ms. Sara Mohammadi","aff":"Student, University College London"},{"name":"Prof. Kenan Arifoglu","aff":"Associate Professor, University College London"},{"name":"Prof. Bilal Gokpinar","aff":"Professor, University College London"}],"order":7}]},{"id":"s420","title":"Behavioral and Technological Trends","track":"Digital Platforms, Innovations and Transformations","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"HARRIS","chairs":["Dr. Hoda Atef Yekta"],"abstracts":[{"id":"136-1653","title":"Stable Matching in Ridesharing","content":"We present optimization models and algorithms to find stable matching solutions in ridesharing where multiple riders are matched together and assigned to a driver. We analyze \"price of stability\" under various scenarios.","presenter":"Dr. Hoda Atef Yekta","authors":[{"name":"Dr. Mohsen Emadikhiav","aff":"Assistant Professor, Florida Atlantic University"},{"name":"Dr. Hoda Atef Yekta","aff":"Assistant Professor, James Madison University"}],"order":1},{"id":"136-1772","title":"Metaverse Influence on Employee Emotional Resilience and Cyber Resilience","content":"Since human errors are fundamental factors in data breaches, the question arises of how the metaverse can affect employees' emotions to improve cyber resilience. This study provides an empirical research model to explore the metaverse and cyber resilience relationship by mediating employees' emotional resilience.","presenter":"Ms. Setareh Daneshgar","authors":[{"name":"Ms. Setareh Daneshgar","aff":"Student, Personal"},{"name":"Dr. Kiarash Sadeghi R","aff":"Assistant Professor, North Carolina A&amp;T State University"},{"name":"Prof. Divesh Ojha","aff":"Associate Professor, University of North Texas"}],"order":2},{"id":"136-1469","title":"Behavioural model on repetitive use intention of Smartphone banking apps","content":"Smartphone banking applications(apps) must be the key to accessing all banking services. This study proposes to identify the various factors that could unravel the factors that enhance technology and human connection to access banking services. A questionnaire survey was used to study the sampled 214 users of smartphone banking apps","presenter":"Prof. Nambirajan Thangasamy","authors":[{"name":"Mr. Maurice Peters","aff":"Student, Pondicherry University"},{"name":"Prof. Nambirajan Thangasamy","aff":"Retired, Pondicherry University"}],"order":3},{"id":"136-0946","title":"Digital Platform Capability and Organizational Innovation","content":"This study explores the impact of digital platform capabilities (DPCC and DPCB) on organizational innovation, with organizational resilience as a mediator and environmental uncertainty as a moderator, based on dynamic capability theory. Findings offer insights for digital transformation and innovation in uncertain environments.","presenter":"Mr. Yuan Kaikai","authors":[{"name":"Mr. Yuan Kaikai","aff":"Student, University of Science and Technology of China"},{"name":"Prof. Xiaoli Hu","aff":"Associate Professor, University of Science and Technology of China"},{"name":"Prof. Zhong Qi","aff":"Associate Professor, University of Science and Technology of China"},{"name":"Mrs. Zhang Tianyi","aff":"Post Doc/Researcher, Institute of Advanced Technology, University of Science and Technology of China"}],"order":4}]},{"id":"s433","title":"Supply Chain Finance","track":"Supply Chain Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY G","chairs":["Ms. Tiantian Li"],"abstracts":[{"id":"136-0859","title":"Blockchain-enabled Capital-constrained Supply Chain Financing and Operating Strategies","content":"Blockchain technology provides emerging solutions for supply chain finance. This study focuses on a capital-constrained supply chain. We consider internal and external financing of the supply chain and analyze two blockchain-enabled financing models: supplier-led and retailer-led. The impact of blockchain technology on participants' financing and operating strategies is investigated.","presenter":"Ms. Yang Wang","authors":[{"name":"Ms. Yang Wang","aff":"Student, Shanghai Jiao Tong University"},{"name":"Prof. Jianwen Luo","aff":"Professor, Shanghai Jiao Tong University"}],"order":1},{"id":"136-0804","title":"The Strategic Capacity Expansion Investment Financing by The Leasing Company","content":"Due to the risk associated with capital investments, a manufacturer is unable to borrow from a bank. Therefore, we investigate the manufacturer’s problem to determine the timing, amount, and interest rate needed to be paid to secure financing for its strategic capacity expansion from a leasing company (secondary financial institution)","presenter":"Dr. Jatinder Gupta","authors":[{"name":"Dr. Jatinder Gupta","aff":"Retired, University of Alabama Huntsville"},{"name":"Dr. Chieh Lee","aff":"Associate Professor, National Sun Yat-Sen University"},{"name":"Prof. Yu-Chen Yang","aff":"Associate Professor, National Sun Yat-Sen University"},{"name":"Ms. Shania Perdana","aff":"Student, National Sun Yat-Sen University"}],"order":2},{"id":"136-0844","title":"From Single to Portfolio Financing: The Role of Factoring in Combating Payment Delays","content":"This study finds that a portfolio financing model incorporating factoring, compared to single financing modes based on buyer credit (order financing) or supplier credit (bank financing), enhances suppliers’ financing feasibility. When buyer credit is low or product sales cycles are long, suppliers should use this model to mitigate risks.","presenter":"Ms. Tiantian Li","authors":[{"name":"Ms. Tiantian Li","aff":"Student, Shanghai Jiao Tong University"},{"name":"Prof. Jianwen Luo","aff":"Professor, Shanghai Jiao Tong University"}],"order":3}]},{"id":"s440","title":"Analytics and the Environment","track":"Data Science, Analytics and AI","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"ROSWELL","chairs":["Dr. Isil Koyuncu"],"abstracts":[{"id":"136-0350","title":"Environmental Efficiency Measurement and Data Envelopment Analysis","content":"This study examines the essential factors for measuring environmental efficiency. Existing methodologies, such as Data Envelopment Analysis (DEA), are validated, and new findings are introduced to address limitations, providing enhanced approaches for assessing environmental performance and promoting sustainability.","presenter":"Dr. Dariush Khezrimotlagh","authors":[{"name":"Dr. Dariush Khezrimotlagh","aff":"Associate Professor, Pennsylvania State University Harrisburg"}],"order":1},{"id":"136-0989","title":"A Causal Machine Learning Approach to Analyzing Weather and Occupancy Effects on Rail Transportation Delays","content":"This paper investigates how weather conditions and passenger occupancy levels contribute to delays in rail public transportation. By applying Modified Causal Forest, the research examines how these factors affect delays under different circumstances. The findings offer valuable insights to enhance transportation planning and improve operational efficiency.","presenter":"Ms. Elham Ahmadi","authors":[{"name":"Ms. Elham Ahmadi","aff":"Student, Kühne Logistics University"},{"name":"Prof. Andre Ludwig","aff":"Professor, Kühne Logistics University"},{"name":"Prof. Henrik Leopold","aff":"Professor, Kühne Logistics University"}],"order":2},{"id":"136-1357","title":"Leveraging Open Data for Enhanced Visibility and Security in Critical Minerals Supply Chains","content":"Critical mineral supply chains face challenges like geopolitical risks, resource scarcity, and sustainability concerns. This research explores leveraging publicly accessible open data to enhance end-to-end supply chain visibility and security. Findings provide insights into mitigating supply risks, fostering resilience, and ensuring sustainable operations in global supply chains.","presenter":"Ms. Wei Nie","authors":[{"name":"Ms. Wei Nie","aff":"Student, University of Cambridge"},{"name":"Dr. Naoum Tsolakis","aff":"Associate Professor, University of Cambridge"},{"name":"Dr. Mukesh Kumar","aff":"Associate Professor, University of Cambridge"}],"order":3},{"id":"136-1784","title":"Machine Learning-Guided Matheuristic for Mixed-Fleet Green Vehicle Routing","content":"This study tackles a mixed-fleet green vehicle routing problem, comparing optimization efforts for conventional and electric vehicles. A machine learning-guided matheuristic improves search efficiency, balancing exploration and exploitation. The customer-set-based decomposition framework combines route generation and set partitioning. Computational experiments demonstrate competitive results with existing methods.","presenter":"Dr. Isil Koyuncu","authors":[{"name":"Dr. Isil Koyuncu","aff":"Assistant Professor, University of Texas at San Antonio"},{"name":"Dr. Mesut Yavuz","aff":"Associate Professor, University of Alabama Tuscaloosa"}],"order":4}]},{"id":"s6","title":"Equity in Humanitarian Operations","track":"Humanitarian Operations and Crisis Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"GRAND HALL EAST B","chairs":["Dr. Iman Parsa"],"abstracts":[{"id":"136-0200","title":"Vulnerability Based Prioritization in Disaster Planning Efforts: Benefits and Trade-offs","content":"Humanitarian logistics literature commonly uses Equity, Efficiency, and Effectiveness objectives. However, it is essential to acknowledge that disasters disproportionately affect vulnerable groups. This paper introduces an alternative measure prioritizing vulnerable populations in disaster planning, aiming for a more inclusive and compassionate disaster management strategy.","presenter":"Dr. Feyza G. Sahinyazan","authors":[{"name":"Dr. Feyza G. Sahinyazan","aff":"Assistant Professor, Simon Fraser University"},{"name":"Dr. Halenur Sahin","aff":"Assistant Professor, TOBB University of Economics and Technology"},{"name":"Dr. A. Irfan Mahmutogullari","aff":"Post Doc/Researcher, KU Leuven"}],"order":1},{"id":"136-0636","title":"Efficiency and Fairness in Resource Allocation: The Role of Outside Options","content":"In many real-world scenarios, individual rationality constraints need to be accounted for when allocating scarce resources (e.g., humanitarian aid, vaccines). We analyse the efficiency-fairness trade-off when allocations are constrained by outside options, and demonstrate that this trade-off is critically dependent on outside options.","presenter":"Dr. Thomas Breugem","authors":[{"name":"Dr. Thomas Breugem","aff":"Associate Professor, Tilburg University"},{"name":"Prof. Andreas Gernert","aff":"Assistant Professor, Kuehne Logistics University"}],"order":2},{"id":"136-0335","title":"Chaotic Warehousing in Humanitarian Logistics. Unraveling the Strategic Chaos","content":"This study proposes a dynamic storage method for humanitarian warehouses that integrates ABC storage, chaotic storage, and fuzzy classification. The method employs fuzzy logic to allocate shelving slots in receiving areas based on fill levels and proximity. It minimizes handling and enhances efficiency, effectively addressing demand uncertainty in humanitarian logistics.","presenter":"Ms. Agatha Da Silva Ovando","authors":[{"name":"Mr. Marcos Lima-Gutierrez","aff":"Student, Universidad Privada Boliviana"},{"name":"Ms. Agatha Da Silva Ovando","aff":"Student, Universidad Privada Boliviana"},{"name":"Prof. Irineu de Brito Junior","aff":"Associate Professor, Sao Paulo State University - UNESP"},{"name":"Dr. Mario Chong","aff":"Professor, Universidad del Pacifico"}],"order":3},{"id":"136-1129","title":"Mobile labs and outbreak prevention in low- and middle-income countries: optimality and equity","content":"Surveillance can help prevent outbreaks of infectious diseases, but is limited in poor, rural areas. Mobile laboratories can help identify outbreaks, however their value compared to investments in local health facilities is unclear. We analyze the value of mobile labs considering the existing health system and discuss potential equity concerns.","presenter":"Dr. Iman Parsa","authors":[{"name":"Ms. Mette Wagenvoort","aff":"Student, Erasmus University Rotterdam"},{"name":"Dr. Iman Parsa","aff":"Assistant Professor, Stockholm School of Economics"},{"name":"Prof. Luk Van Wassenhove","aff":"Professor, INSEAD"}],"order":4}]},{"id":"s13","title":"Excellence in Community-Oriented Operations and Supply Chains","track":"POM and Community","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"EMBASSY F","chairs":["Dr. Saif Mir"],"abstracts":[{"id":"136-0632","title":"Inclusive Workflow Optimization in Apparel Manufacturing","content":"In this study, we investigate workflow improvement in apparel manufacturing with a diverse workforce, including individuals with disabilities. We first characterize sewing machine operation tasks based on individual abilities and then formulate an optimal assignment model to maximize productivity.","presenter":"Ms. Sun Kim","authors":[{"name":"Ms. Sun Kim","aff":"Student, Michigan State University"},{"name":"Prof. Sriram Narayanan","aff":"Professor, Michigan State University"}],"order":1},{"id":"136-0900","title":"Towards an Operational Framework for Assessing Person-Job Fit","content":"Inclusion of people with disabilities in the workforce is crucial for addressing labor shortages in the US. Despite comprising nearly 12% of the population, people with disabilities face significant barriers, however, current frameworks for fitting people with disabilities into jobs are inadequate. This study proposes a novel framework for inclusion.","presenter":"Mr. Bhavjot Singh","authors":[{"name":"Mr. Bhavjot Singh","aff":"Student, Michigan State University"},{"name":"Prof. Sriram Narayanan","aff":"Professor, Michigan State University"},{"name":"Prof. Rajiv Ranganathan","aff":"Associate Professor, Michigan State University"},{"name":"Prof. Hung Kuo","aff":"Assistant Professor, Michigan State University"}],"order":2},{"id":"136-1543","title":"Tales from the Frontline: Exploring Interracial Service Improvisations","content":"Researchers argue most service encounters are interracial interactions. As the social landscape becomes more “anti-woke” and divisive, interracial service encounters become increasingly complex. Frontline black workers are tasked with navigating this challenging dynamic. This study explores the service improvisations used by frontline black workers utilize during interracial service encounters.","presenter":"Dr. LaDonna Thornton","authors":[{"name":"Dr. LaDonna Thornton","aff":"Assistant Professor, Auburn University Harbert College of Bus"}],"order":3}]},{"id":"s20","title":"Delivery of Essential Services","track":"POM and Community","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"EMBASSY E","chairs":["Mr. Iman Attari"],"abstracts":[{"id":"136-0237","title":"No Country for Young Refugees: Barriers and Opportunities for Inclusive Refugee Education Practices","content":"The recent refugee crises in Ukraine (2022) and Syria (2011) have created millions of refugees, 40% of whom are children. This study considers the following research question: How can a host country improve the inclusion of refugee children in the education system without overburdening its infrastructure?","presenter":"Ms. Sebnem Manolya Demir","authors":[{"name":"Ms. Sebnem Manolya Demir","aff":"Student, Marshall School of Business"},{"name":"Dr. Feyza G. Sahinyazan","aff":"Assistant Professor, Simon Fraser University"},{"name":"Prof. Bahar Y. Kara","aff":"Professor, Bilkent University"},{"name":"Ms. Elfe Buluc","aff":"Supply Associate, UNHCR"}],"order":1},{"id":"136-0263","title":"Failures of Health Equity: An Examination of Bias in Clinical Trials","content":"Failures of health equity are closely intertwined with biases in healthcare treatment, such as bias due to race, ethnicity, gender, and age. This paper studies how underrepresentation bias in clinical trials affects health outcomes and equity.","presenter":"Ms. Ling Li","authors":[{"name":"Ms. Ling Li","aff":"Student, Kelley School of Business"},{"name":"Dr. Xiaoshan Peng","aff":"Assistant Professor, Kelley School of Business"},{"name":"Prof. Kurt Bretthauer","aff":"Professor, Indiana University"}],"order":2},{"id":"136-0965","title":"Beyond the Pulse: Racial Disparities in Oximetry Readings and the Influence on Early Readmission Rates","content":"This study investigates the impact of racial bias in pulse oximetry on early hospital readmissions, focusing on sequential mediation by oxygen delivery and length-of-stay deviations. Our findings highlight significant disparities in oxygen therapy and discharge timing for Black patients leading to increased early readmissions, emphasizing healthcare operational inefficiencies.","presenter":"Dr. Gaurav Jetley","authors":[{"name":"Dr. Gaurav Jetley","aff":"Assistant Professor, Colorado State University Fort Collins"},{"name":"Dr. He Zhang","aff":"Assistant Professor, Cal Poly"}],"order":3}]},{"id":"s60","title":"Sustainable and Socially Responsible Operations","track":"Sustainable Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"GRAND HALL EAST C","chairs":["Prof. Yanchong Zheng","Ms. Yuan Shi"],"abstracts":[{"id":"136-0460","title":"Conditional Lending for Sustainable Farm Practices","content":"In 2022 $20bn of farm credit was extended to row crop farmers, whose practices accounted for \r\nnearly 1 bn. tons of annual scope 3 carbon emitted in the watershed. We present a financial theory framework to link nutrient-driven water risks to carbon markets with impacts for various stakeholders. \r\n","presenter":"Prof. Ravi Anupindi","authors":[{"name":"Ms. Lis Huang","aff":"Student, University of Michigan - Ann Arbor"},{"name":"Prof. Ravi Anupindi","aff":"Professor, University of Michigan Ann Arbor"},{"name":"Mr. Darren Wolfberg","aff":"CEO / Founder, Blockchain Triangle"},{"name":"Prof. Peter Adriaens","aff":"Professor, University of Michigan - Ann Arbor"},{"name":"Dr. Jon Allan","aff":"Senior Lecturer, University of Michigan Ann Arbor"}],"order":1},{"id":"136-0568","title":"Supply Chain Intermediation in Developing Economies","content":"This study examines the role of third-party service providers in the delivery of goods in developing economies. Using clean cooking solutions as a motivating example, it explores how intermediaries address logistical challenges and influence adoption. We aim to uncover conditions under which intermediation benefits businesses and reduces barriers for users.","presenter":"Ms. Banu Tiryaki","authors":[{"name":"Prof. Dan Iancu","aff":"Associate Professor, Stanford University"},{"name":"Mr. Omer Karaduman","aff":"Assistant Professor, Stanford University"},{"name":"Ms. Banu Tiryaki","aff":"Student, Stanford University"}],"order":2},{"id":"136-1017","title":"When Where Watt: Harnessing the Value of Time and Location for Renewable Electricity Generation","content":"Renewable energy investments are growing but face limited profitability due to mismatch in electricity generation time and high-price periods. We propose Quality Adjusted Power Value (QAPV), a site selection metric that accounts for time and location of generation. Applying QAPV to Texas wind plants increased revenues by up to 19%.","presenter":"Mr. Vishrut Rana","authors":[{"name":"Mr. Vishrut Rana","aff":"Student, The Wharton School"},{"name":"Prof. Christian Kaps","aff":"Assistant Professor, Harvard Business School"},{"name":"Prof. Serguei Netessine","aff":"Professor, The Wharton School"}],"order":3},{"id":"136-1746","title":"Shaping Perceptions: The Impact of Ratings Displays on Bias in Service Delivery Evaluations","content":"Prior ratings, often used as quality signals in service management, can unintentionally introduce bias in follow-up evaluations. This project experimentally examines how different ratings displays influence evaluation bias and explores the underlying mechanisms. Our findings aim to identify operational strategies to mitigate bias, enhancing fairness and transparency in service delivery.","presenter":"Ms. Tong Wang","authors":[{"name":"Dr. Monika Heller","aff":"Post Doc/Researcher, University College London"},{"name":"Prof. Kamalini Ramdas","aff":"Professor, London Business School"},{"name":"Ms. Tong Wang","aff":"Student, London Business School"}],"order":4}]},{"id":"s99","title":"Empirical Insights on Quality, Innovation, Networks, and Meme-Driven Decision-Making-2","track":"Product Innovation and Technology Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"COURTLAND","chairs":["Dr. Xiaojin Liu","Dr. Pankaj Kumar"],"abstracts":[{"id":"136-1533","title":"Spillover Effects in Multi-tier Supply Chains: Network Characteristics and Firm Financial Performance","content":"Firms receive resources and improve performance when embedding in supply chain networks. Utilizing financial panel data, we empirically investigate the spillover effects of network characteristics on firms’ financial performance in technology-driven multi-tier supply chains. Our study illustrates the employment of network analysis and facilitates firms’ decision-making in multi-tier supply chains.","presenter":"Dr. Kara Li Liu","authors":[{"name":"Dr. Kara Li Liu","aff":"Assistant Professor, Roger Williams University"},{"name":"Dr. Koray Özpolat","aff":"Professor, University of Rhode Island"},{"name":"Dr. Xuemei Su","aff":"Professor, California State University Long Beach"}],"order":1},{"id":"136-1613","title":"Effects of Technological Transition on Innovation: A Study of the Automotive Industry","content":"Automotive industry is undergoing a transition from Internal Combustion Engine vehicles towards the electric vehicles. Traditional automotive manufacturers are adapting, requiring firms to innovate. This transition also heavily relies on suppliers’ ability to innovate. In this study, we focus into the mechanisms and enablers that drive suppliers’ transition in innovation.","presenter":"Mr. Apurva Shrey","authors":[{"name":"Mr. Apurva Shrey","aff":"Student, Michigan State University"},{"name":"Dr. Adrian Choo","aff":"Associate Professor, Michigan State University"},{"name":"Prof. Sri Talluri","aff":"Professor, Michigan State University"}],"order":2},{"id":"136-1945","title":"Algorithmic Driven Decision Making in Healthcare : Role of non-clinical agents","content":"We investigate the role of non-clinical agents in using clinical decision support system using call level data from NHS 111 England. We identify the appropriate clinical-non-clinical mix to achieve operational efficiency","presenter":"Ms. Deepanshi Bhardwaj","authors":[{"name":"Ms. Deepanshi Bhardwaj","aff":"Student, University College London"},{"name":"Prof. Bilal Gokpinar","aff":"Professor, University College London"}],"order":3}]},{"id":"s100","title":"Managing Strategic Trade-offs in Supply Chains","track":"POM-Economics Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"VININGS","chairs":["Prof. Abhishek Roy"],"abstracts":[{"id":"136-0316","title":"Information Sharing and Manufacturer Rebate Competition","content":"We investigate the incentive for a retailer to share private demand information with two rebate-offering manufacturers who sell substitutable products through the retailer. We characterize how the information sharing equilibrium depends on key factors such as the proportion of rebate-sensitive consumers and competition intensity.","presenter":"Dr. Yunjie WANG","authors":[{"name":"Prof. Albert Ha","aff":"Professor, Hong Kong University of Science and Technology"},{"name":"Prof. Weixin Shang","aff":"Associate Professor, Lingnan Univ"},{"name":"Dr. Yunjie WANG","aff":"Associate Professor, Renmin University of China"}],"order":1},{"id":"136-0406","title":"Progressive referral fee on online retail platforms","content":"To boost product variety, online retailers have adopted agency selling model wherein the supplier determines prices and retailer charges a fraction of price as referral fee. This paper tackles the important question of how should a retail platform design progressive referral fees facing heterogenous suppliers differing in demand and cost.","presenter":"Prof. Aditya Jain","authors":[{"name":"Prof. Aditya Jain","aff":"Associate Professor, Baruch College"},{"name":"Prof. Aadhaar Chaturvedi","aff":"Associate Professor, Clemson University"}],"order":2},{"id":"136-0455","title":"Non-Profit Support in Education: Resource Allocation and Students’ Lifetime Outcomes","content":"We study operations in a not-for-profit organization (NPO) that provides access to valuable resource to a beneficiary. The NPO and the beneficiary benefit from the beneficiary accessing the valuable resource. Despite its availability in abundance, we show when and why the NPO benefits from throttling access to the resource.","presenter":"Dr. Harish Guda","authors":[{"name":"Dr. Harish Guda","aff":"Assistant Professor, Arizona State University"},{"name":"Dr. Goutham Takasi","aff":"Assistant Professor, University of Alabama Tuscaloosa"},{"name":"Prof. Milind Dawande","aff":"Professor, The University of Texas at Dallas"},{"name":"Prof. Ganesh Janakiraman","aff":"Professor, The University of Texas at Dallas"}],"order":3},{"id":"136-0466","title":"Collaborative New Product Development: Co-creating with a Shared Supplier in the Presence of a Competitor","content":"In many industries, suppliers are shared by competing manufacturers, who may benefit from forming alliances and co-creating new products jointly with their shared suppliers. We analyze the strategic interactions in such a collaborative alliance when competing buyers decide to co-create a common component with the supplier.","presenter":"Prof. Abhishek Roy","authors":[{"name":"Prof. Abhishek Roy","aff":"Assistant Professor, Temple University"}],"order":4}]},{"id":"s109","title":"Responsible Research in Operations Management","track":"Empirical Research in Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"EMBASSY B","chairs":["Ms. Yeonjoo Lee"],"abstracts":[{"id":"136-0061","title":"Sustainable and Affordable? Examining CSR Communications for Affordable Sustainable Apparel","content":"We use controlled experiments (non-incentivized and incentivized) in an online purchase context to examine how consumers' purchase intention is influenced by a retailer's disclosure of a manufacturer's CSR performance. We show that disclosing CSR performance is more challenging (and potentially riskier) with consumers who typically pay a higher price.","presenter":"Dr. Junhao Vincent Yu","authors":[{"name":"Dr. Junhao Vincent Yu","aff":"Assistant Professor, Miami University"},{"name":"Prof. Tim Kraft","aff":"Associate Professor, North Carolina State University"},{"name":"Dr. Robert Handfield","aff":"Professor, North Carolina State University"},{"name":"Dr. Rejaul Hasan","aff":"?, Amazon.com"},{"name":"Dr. Marguerite Moore","aff":"Professor, North Carolina State University"}],"order":1},{"id":"136-0542","title":"Quantifying and Ranking the Impact of Social Unsustainability in Public Firms and their Supply Chains","content":"We quantify the effects of six social sustainability issues on firm market value by classifying articles from 187 news outlets published between 1990 and 2019. While the market effects are short-lived, the severity of these issues varies depending on whether they occur within the firm or its supply chain.","presenter":"Ms. Soh Hyun Chu","authors":[{"name":"Ms. Soh Hyun Chu","aff":"Assistant Professor, Rotterdam School of Management"},{"name":"Prof. Christian Blanco","aff":"Assistant Professor, Ohio State University"},{"name":"Prof. James Hill","aff":"Professor, Ohio State University"}],"order":2},{"id":"136-0894","title":"Can Investing in Employees Drive Environmental Performance? Strategic HRM Practices and Sustainable Operations","content":"Investment-oriented HRM practices increase employees' willingness to make environmentally sustainable operational decisions. Using MSCI KLD ESG data (1995–2019) and a behavioral experiment, we find HRM investments motivate operations managers to prioritize environmental initiatives, regardless of company strategy. This highlights social sustainability as a key driver of environmental performance in operations.","presenter":"Dr. Emily Dickey","authors":[{"name":"Dr. Emily Dickey","aff":"Assistant Professor, University of Tennessee"},{"name":"Dr. Prisca Brosi","aff":"Associate Professor, Kuehne Logistics University"},{"name":"Prof. Jan Fransoo","aff":"Professor, Tilburg University"},{"name":"Dr. Brent Moritz","aff":"Associate Professor, Penn State University University Park"}],"order":3},{"id":"136-1085","title":"Improving Food Security with Scheduled Neighborhood Grocery Delivery","content":"Online grocery delivery offers potential to address food security issues, but the high cost of typical on-demand services raises questions about its sustainability. This study investigates how scheduled neighborhood grocery delivery may better support food security principles, using field data and experiments to explore both operational and customer benefits.","presenter":"Ms. Yeonjoo Lee","authors":[{"name":"Ms. Yeonjoo Lee","aff":"Student, University of Minnesota"},{"name":"Prof. Karen Donohue","aff":"Professor, Arizona State University"}],"order":4}]},{"id":"s117","title":"Data-Driven and Behavioral Perspectives on Platform Operations","track":"Behavioral Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"EMBASSY D","chairs":["Prof. Park Sinchaisri","Ms. Shunan Jiang"],"abstracts":[{"id":"136-1690","title":"Understanding Gig Worker Resistance and Cooperation under Algorithmic Management","content":"The emergence of algorithmic management practices on gig platforms has seen a rise in new types of worker resistive behaviors. Primarily focusing on task selectively, we develop a game theoretic framework and run a behavioral experiment which reveal implications for platforms regarding human and algorithmic management.","presenter":"Mr. Austin Zhu","authors":[{"name":"Mr. Austin Zhu","aff":"Student, University of California Berkeley"},{"name":"Prof. Park Sinchaisri","aff":"Assistant Professor, University of California Berkeley"}],"order":1},{"id":"136-1796","title":"Match Made with Matrix Completion: Efficient Offline and Online Learning in Matching Markets","content":"This paper tackles high-dimensional reward learning in online markets using low-rank matrix structures and nuclear norm regularization. It overcomes matching interference, ensures near-optimal accuracy, and extends to online settings with improved regret bounds. Practical value is demonstrated through applications in labor markets using synthetic and real-world data.","presenter":"Prof. Kan Xu","authors":[{"name":"Prof. Kan Xu","aff":"Assistant Professor, Arizona State University"}],"order":2},{"id":"136-1874","title":"Doubly High-Dimensional Contextual Bandits: An Interpretable Model of Customer Behavior with Applications to Assortment/Pricing","content":"We consider contextual bandits that are doubly high-dimensional in the sense that both covariates and actions are allowed to take values in high-dimensional spaces and model the interactions between covariates/actions via a (near) low-rank representation matrix to learn customer behaviors. We propose an efficient low-rank matrix estimator with provable bounds.","presenter":"Dr. Jeff Cai","authors":[{"name":"Dr. Jeff Cai","aff":"Assistant Professor, University of Notre Dame"},{"name":"Dr. Ran Chen","aff":"Assistant Professor, Washington University in St. Louis"},{"name":"Prof. Martin Wainwright","aff":"Professor, Massachusetts Institute of Technology"},{"name":"Prof. Linda Zhao","aff":"Professor, Wharton School"}],"order":3},{"id":"136-1654","title":"Optimal Information Provision and Competition Between Freelancer Platforms","content":"This paper develops a tractable framework to analyze freelancer platforms' equilibrium strategies for information provision and commission fees in competitive markets. By reducing infinite-dimensional optimization problems to convex formulations, it examines how platforms optimize freelancer quality and quantity. Findings reveal strategic responses to competitive dynamics and labor cost differences.","presenter":"Dr. Wenchang Zhang","authors":[{"name":"Prof. Kostas Bimpikis","aff":"Assistant Professor, Stanford University"},{"name":"Prof. Yiangos Papanastasiou","aff":"Associate Professor, Rice University"},{"name":"Dr. Wenchang Zhang","aff":"Assistant Professor, Kelley School of Business"}],"order":4}]},{"id":"s150","title":"Supply Chain Performance","track":"POM-Finance Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"Learning Center","chairs":["Prof. Nikolay Osadchiy","Mr. Deepak Agrawal"],"abstracts":[{"id":"136-0661","title":"Internal Credit and External Blame: Attribution Bias in Operations and Supply Chain Performance Discussions","content":"This study uses large language models (LLMs) to analyze conference call data, revealing that managers often attribute operational successes to internal factors like innovation and planning, while blaming failures on external partners or macroeconomic conditions. This opportunistic bias enhances sales and inventory efficiencies of firms.","presenter":"Prof. Jing Wu","authors":[{"name":"Prof. Jing Wu","aff":"Associate Professor, The Chinese University of Hong Kong"},{"name":"Ms. Yimeng Niu","aff":"Assistant Professor, Tilburg University"}],"order":1},{"id":"136-0864","title":"The Cash Conversion Cycle: An Empirical Analysis of its Impact on Supply Chain Performance","content":"We propose a Cash Conversion Distance metric that identifies the degree with which a firm practices aggressive (or lax) working capital management. \r\nWe show how a firm's profitability as well as that of its partners varies as a function of this measure and its importance in their supply network.","presenter":"Dr. Maximiliano Udenio","authors":[{"name":"Dr. Maximiliano Udenio","aff":"Associate Professor, KU Leuven"},{"name":"Dr. Shaunak Dabadghao","aff":"Assistant Professor, Technische Universiteit Eindhoven"}],"order":2},{"id":"136-1151","title":"Performance Implications of Supply Chain Turnover","content":"We examine the operational performance consequences of supply chain turnover. Analyzing a panel of buyer-supplier turnovers in the consumer products industries, increasing turnover increases the consumer complaints, signaling a decrease in product quality, offsetting the decreased costs associated with turnover. Further, we examine the impacts of turnover type and distance.","presenter":"Dr. Christopher Chen","authors":[{"name":"Dr. Kevin Mayo","aff":"Assistant Professor, Washington State University"},{"name":"Dr. Christopher Chen","aff":"Assistant Professor, Indiana University Bloomington"},{"name":"Prof. George Ball","aff":"Associate Professor, Kelley School of Business, Indiana Univ."},{"name":"Prof. Kurt Bretthauer","aff":"Professor, Indiana University"}],"order":3},{"id":"136-1829","title":"On the Benefits of Supplier vs Customer Diversification: a Geographical Analysis","content":"Diversification is traditionally thought to be a risk mitigation tool. However, in our paper, we show that diversification also have first order effect on inventory productivity. We find a nonlinear relationship between geographical diversification and inventory turnover. Further, we examine the varying effects of diversification by firm's upstreamness.","presenter":"Mr. Deepak Agrawal","authors":[{"name":"Mr. Deepak Agrawal","aff":"Student, Emory University"},{"name":"Prof. Nikolay Osadchiy","aff":"Associate Professor, Emory University"}],"order":4}]},{"id":"s160","title":"Healthcare IT in Information Systems","track":"Healthcare Analytics","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"GRAND HALL EAST D","chairs":["Mr. Jiayuan Tian"],"abstracts":[{"id":"136-0093","title":"The Effect of Electronic Medical Records on Hospital Utilization Costs","content":"This paper examines the impact of electronic medical record (EMR) adoption on\r\nhospital utilization costs. We proxy for utilization costs using hospital charges for Medicare\r\ndiagnosis-related groups (DRGs). Results confirm expectations of improved efficiency (reflected\r\nin lower charges) following EMR adoption.","presenter":"Dr. Xue Guo","authors":[{"name":"Dr. Xue Guo","aff":"Assistant Professor, Georgia State University"}],"order":1},{"id":"136-1055","title":"Technological Interventions to Combat Social Stigma in Mental Health Support","content":"This study explores how telehealth and conversational AI can reduce stigma and encourage individuals to seek mental health support by conducting a controlled online experiment and a field experiment. This study underscores the need to address the tension between social stigma and privacy concerns.","presenter":"Mr. Zhichen Chen","authors":[{"name":"Mr. Zhichen Chen","aff":"Student, Boston University"},{"name":"Prof. Gordon Burtch","aff":"Associate Professor, Boston University"},{"name":"Prof. Chrysanthos Dellarocas","aff":"Professor, Boston University"},{"name":"Prof. Bin Gu","aff":"Professor, Boston University"}],"order":2},{"id":"136-0837","title":"Doing Well while Doing Good: The Case of Medical Live Streaming","content":"This study examines the impact of medical live streaming on patient consultations and literacy using data from an online medical consultation platform. Results show that medical live streaming improves both consultations and literacy, with stronger effects for frequent, high-quality events. The study offers insights into optimizing medical live streaming operations.","presenter":"Ms. YIXUAN LIU","authors":[{"name":"Ms. YIXUAN LIU","aff":"Student, hongkong polytechnical university"},{"name":"Prof. xiaofei zhang","aff":"Associate Professor, Nankai Univeristy"},{"name":"Prof. Yixin Lu","aff":"Associate Professor, George Washington University"},{"name":"Prof. Liangfei Qiu","aff":"Professor, University of Florida"},{"name":"Prof. Kee-Hung Lai","aff":"Professor, The Hong Kong Polytechnic University"}],"order":3},{"id":"136-1590","title":"News Deserts and Disease Outbreaks","content":"The local newspaper closures create critical information gaps, leaving communities less equipped to respond to public health crises. Our research reveals that these closures significantly increase the severity of disease outbreaks, particularly in low Internet access communities. This study underscores the vital role of local journalism in safeguarding public health.","presenter":"Ms. Fangchen Song","authors":[{"name":"Ms. Fangchen Song","aff":"Student, The University of Texas at Austin"},{"name":"Dr. Jason Chan","aff":"Associate Professor, University of Minnesota"},{"name":"Dr. Avinash Collis","aff":"Assistant Professor, Carnegie Mellon University"}],"order":4}]},{"id":"s195","title":"Recent Empirical Work in Service Operations","track":"Service Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"EMBASSY C","chairs":["Prof. Dayton Steele"],"abstracts":[{"id":"136-0068","title":"Revitalizing the In-Store Experience: An Empirical Study on the Spillover Effects of Experiential Services","content":"Retailers are adopting experiential services to increase foot traffic to stores. However, it remains unclear whether introducing such a service leads to positive spillover effects on the main-store service, rather than cannibalizing existing sales. We provide the first empirical documentation of the spillover effects and mechanisms behind the observed effects.","presenter":"Dr. Bengu Ozdemir","authors":[{"name":"Dr. Bengu Ozdemir","aff":"Assistant Professor, University of Wisconsin-Whitewater"},{"name":"Prof. Stanley Lim","aff":"Assistant Professor, Michigan State University"}],"order":1},{"id":"136-0121","title":"Fast-food Stores With A Drive-through Recovered Post-pandemic; Stores Without Did Not","content":"We empirically document a profound, permanent change in the US fast-food consumer demand after the COVID-19 pandemic. After a big pandemic slump, visits to drive-through stores almost recovered to pre-pandemic levels, but visits to non-drive-through stores stayed permanently suppressed. Our findings are robust to matching, differences-in-differences regression and placebo tests.","presenter":"Mr. Partha Mishra","authors":[{"name":"Mr. Partha Mishra","aff":"Student, Northwestern University Kellogg School o"},{"name":"Prof. Sunil Chopra","aff":"Professor, Kellogg School of Management"},{"name":"Prof. Yannis Stamatopoulos","aff":"Associate Professor, The University of Texas at Austin"}],"order":2},{"id":"136-0219","title":"The Hidden Costs of Working Multiple Jobs","content":"Across three studies, combining survey data, and transaction-level analysis from 90,548 customers of a nationwide retail bank, and insights from the General Social Survey, we study whether people with multiple jobs spend their labor income differently than people who earn the same total income from a single job.","presenter":"Ms. Paige Tsai","authors":[{"name":"Ms. Paige Tsai","aff":"Student, Harvard Business School"},{"name":"Prof. Ryan Buell","aff":"Professor, Harvard Business School"}],"order":3},{"id":"136-1089","title":"Afraid of Niche, Tired of Mass: Atypical Idea Combination on Crowdfunding Platform","content":"A successful business idea usually balances familiarity and atypicality. Using a double machine learning model, we find that there exists an optimal pattern of idea combination that balances familiarity and atypicality.","presenter":"Prof. Yu Kan","authors":[{"name":"Prof. Yu Kan","aff":"Assistant Professor, Indiana University"}],"order":4},{"id":"136-1192","title":"Evaluating Crowdsourcing Problem Specifications: A Text Discourse Analysis using LLMs","content":"Problem specifications are pivotal in shaping crowdsourcing contest outcomes. However, how the problem specifications should be crafted to enhance contest performance remains underexplored. Leveraging Large Language Models (LLMs), this study empirically investigates how problem specification discourse impacts solver’s behavior, offering novel insights into the design of crowdsourcing contests. \r\n","presenter":"Mr. Andrew Shin","authors":[{"name":"Mr. Andrew Shin","aff":"Student, University of Minnesota"},{"name":"Prof. Anant Mishra","aff":"Professor, University of Minnesota"},{"name":"Prof. Dayton Steele","aff":"Assistant Professor, University of Minnesota"},{"name":"Prof. Brian Lee","aff":"Assistant Professor, Pennsylvania State University"}],"order":5}]},{"id":"s212","title":"Social Technologies in Supply Chains","track":"Supply Chain Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"GRAND HALL EAST A","chairs":["Dr. Lina Zhang"],"abstracts":[{"id":"136-1362","title":"Advancing Social Sustainability with Blockchain: A Strategic Framework for Global Supply Chains","content":"Stakeholders across industries continue to face ongoing challenges related to data integrity, supply chain transparency, and accountability in advancing social sustainability. Blockchain technology (BT) offers transformative potentials. This research explores successful cases in emerging economies, laying the groundwork for a framework leveraging BT features to address global sustainability standards.","presenter":"Ms. Emilia Manfredi","authors":[{"name":"Ms. Emilia Manfredi","aff":"Student, University of Bristol"},{"name":"Dr. Phuong Tran","aff":"Lecturer, University of Bristol"},{"name":"Dr. Chandrasekararao Seepana","aff":"Lecturer, University of Bristol"},{"name":"Prof. Gianluca Veronesi","aff":"Professor, University of Bristol"}],"order":1},{"id":"136-1345","title":"Channel Strategy in Live Streaming E-commerce","content":"Live-streaming channels, merging entertainment with instant purchasing, are key in digital marketing. This study analyzes sales, entertainment quality, and pricing strategies, emphasizing their synergy, along with market size and collaboration dynamics, to optimize benefits for manufacturers and live streamers.\r\n","presenter":"Dr. Yumeng Zhang","authors":[{"name":"Dr. Yumeng Zhang","aff":"Lecturer, University of Liverpool"},{"name":"Dr. Lina Zhang","aff":"Lecturer, University of Exeter"},{"name":"Prof. Suresh Sethi","aff":"Professor, University of Texas Dallas"}],"order":2},{"id":"136-0754","title":"Climate-Specific Investments in Supply Chains: A Dynamic Game Model Analysis","content":"Extreme weather conditions have been playing havoc on supply chains. Companies are investing in climate-specific assets to mitigate weather-related risks and ensure continuous supply chain activities. Through a game-theoretic model, we examine how supplier characteristics and weather disruption probabilities shape supplier-buyer interactions and strategic decision-making under uncertainty.","presenter":"Dr. Dewang Pagare","authors":[{"name":"Dr. Indranil Biswas","aff":"Associate Professor, NEOMA Business School"},{"name":"Dr. Dewang Pagare","aff":"Lecturer, Royal Holloway, University of London"},{"name":"Dr. Sunil Tiwari","aff":"Senior Lecturer, University of Bristol"},{"name":"Prof. Tsan-Ming Choi","aff":"Professor, University of Liverpool"}],"order":3}]},{"id":"s248","title":"Optimal Mechanisms for Platforms; Resilience and Sustainability in Supply Chains","track":"Digital Platforms, Innovations and Transformations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"GREENBRIAR","chairs":["Dr. Chandrasekhar Manchiraju"],"abstracts":[{"id":"136-0870","title":"Understanding Manufacturing Resilience Amid Material Shortages","content":"This study examines how manufacturing plants respond to raw material shortages, leveraging data from the QSPC, ASM, and Economic Census. Using a panel design with firm-level fixed effects, we analyze strategies like pricing and product mix adjustments, and their impacts on capacity utilization and costs, offering insights for managing disruptions.","presenter":"Dr. Anne Dohmen","authors":[{"name":"Dr. Anne Dohmen","aff":"Assistant Professor, Michigan State University"}],"order":1},{"id":"136-1149","title":"Prior-Free Optimality in Dynamic Two-Sided Markets","content":"We consider a two-sided platform where unit-demand buyers and unit-supply sellers arrive according to Poisson processes. Buyers and sellers have private valuations and costs, respectively. The platform incurs a waiting cost per unit time for each unmatched agent waiting in the market. For this setting, we provide an asymptotically-optimal mechanism","presenter":"Dr. Arun Kumar Rout","authors":[{"name":"Dr. Arun Kumar Rout","aff":"Assistant Professor, State University of New York"},{"name":"Prof. Ganesh Janakiraman","aff":"Professor, The University of Texas at Dallas"},{"name":"Prof. Milind Dawande","aff":"Professor, The University of Texas at Dallas"}],"order":2},{"id":"136-1595","title":"Dynamics of Environmental Management in Multi-tier Supply Chains","content":"This research examines how downstream firms affect the environmental efficiency of upstream partners in multi-tier supply chains, using network data envelopment analysis. Findings reveal that a firm's environmental efficiency positively influences that of its neighboring suppliers.","presenter":"Mr. Seongwon Park","authors":[{"name":"Mr. Seongwon Park","aff":"Student, Michigan State University"},{"name":"Prof. Srinivas Talluri","aff":"Professor, Michigan State University"},{"name":"Dr. Chandrasekhar Manchiraju","aff":"Assistant Professor, Michigan State University"},{"name":"Dr. Gyusuk Lee","aff":"Assistant Professor, IE BUSINESS SCHOOL"}],"order":3}]},{"id":"s249","title":"From Shelter to Supply Chains: Data-Driven Approaches to Social and Economic Resilience","track":"Operations and Society","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"LENOX","chairs":["Prof. Amir Karimi","Dr. Olumurejiwa Fatunde"],"abstracts":[{"id":"136-1976","title":"Opioid use disorder and homelessness: Modeling health and economic impacts of stable housing provision","content":"The leading cause of death among people experiencing homelessness (PEH) in the US is opioid overdose. Using a compartmental model, we assessed the cost-effectiveness of providing stable housing to PEH with opioid use disorder. Housing interventions improved health outcomes, reduced mortality, with cost-effectiveness at $26,200 per quality-adjusted life year gained.","presenter":"Prof. Isabelle Rao","authors":[{"name":"Prof. Isabelle Rao","aff":"Assistant Professor, University of Toronto"},{"name":"Prof. Margaret Brandeau","aff":"Professor, Stanford University"}],"order":1},{"id":"136-1186","title":"Tradable Equity Credits (TECs) Scheme for Public Transit: A Nonlinear Programming Model for Equitable Revenue","content":"This paper proposes a Tradable Equity Credits (TECs) scheme to support subsidy programs while simultaneously maximizing farebox revenue and enhancing \"transportation equity.\" A trading market is introduced, where \"equity debts\" occur if an agency fails to meet the equity baseline, and \"equity credits\" are earned by exceeding it.","presenter":"Dr. Xin Wu","authors":[{"name":"Dr. Xin Wu","aff":"Post Doc/Researcher, Villanova University"},{"name":"Dr. Kailun Liu","aff":"Post Doc/Researcher, Villanova University"},{"name":"Dr. Qingbin Cui","aff":"Associate Professor, University of Maryland - College Park"},{"name":"Mr. Ya Ji","aff":"Post Doc/Researcher, University of Maryland - College Park"},{"name":"Dr. Chenfeng Xiong","aff":"Post Doc/Researcher, Villanova University"}],"order":2},{"id":"136-0543","title":"Clustering, Regression, and Optimization Models for Increasing Access to Healthy Food Through Existing Infrastructure.","content":"This study expands the definition of food access by including diverse food outlets beyond supermarkets, addressing the limitations of traditional models focused solely on proximity and income. Using Chicago as a case study, we apply K-means clustering, regression, and network optimization models to measure food access in vulnerable urban populations.","presenter":"Prof. Sofia Perez-Guzman","authors":[{"name":"Mrs. Carla Tejada","aff":"Post Doc/Researcher, University of Illinois at Chicago"},{"name":"Prof. Sofia Perez-Guzman","aff":"Assistant Professor, Georgia Institute of Technology"},{"name":"Ms. Meen-Sung Kim","aff":"Student, Georgia Institute of Technology"},{"name":"Ms. Otgondulam Boldbaatar","aff":"Student, University of Illinois at Chicago"}],"order":3},{"id":"136-0778","title":"Retail Contracts to Combat Supplier Unreliability in Emerging Markets","content":"We use data from a Nigerian retailer to predict supplier reliability under severe macroeconomic volatility. Building on the literature on information asymmetry in supply chain contracting, we examine whether suppliers can be incentivized to share real-time information and test the effect of increased information-sharing on supplier reliability and retailer performance.","presenter":"Dr. Olumurejiwa Fatunde","authors":[{"name":"Dr. Olumurejiwa Fatunde","aff":"Post Doc/Researcher, University of Toronto"}],"order":4}]},{"id":"s261","title":"Interdisciplinary Research at the Interface of OM and Marketing","track":"POM-Marketing Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"DUNWOODY","chairs":["Dr. Natalie (Ximin) Huang"],"abstracts":[{"id":"136-1200","title":"Addictive Goods Market: Analysis &amp; Control","content":"Opioid market trade-off: establishing vs. enforcing quotas. Enforcing quotas gets harder in secondary markets. Furthermore, given the addictive character of modern opioids, it is unclear if imposing limits will be effective as restricting access to addictive products can cause extra demand to be sparked. What ought the planner to do?","presenter":"Prof. Abhishek Ray","authors":[{"name":"Prof. Abhishek Ray","aff":"Assistant Professor, George Mason University"},{"name":"Prof. Mehmet Altug","aff":"Associate Professor, George Mason University"}],"order":1},{"id":"136-1470","title":"Effects of Firm-Generated Content in Social Media on Sales and Returns","content":"This study analyzes firm-generated social media content's impact on sales and returns, revealing that posts on the product's standard-features boost both, while those on its customizable-features reduce them. Persuasive content moderates these effects, providing actionable insights for optimizing social media marketing.","presenter":"Dr. Paolo Letizia","authors":[{"name":"Dr. M. Serkan Akturk","aff":"Associate Professor, Clemson University"},{"name":"Dr. Haileab Hilafu","aff":"Associate Professor, University of Tennessee Knoxville"},{"name":"Dr. Paolo Letizia","aff":"Associate Professor, University of Tennessee"}],"order":2},{"id":"136-1476","title":"Rarity vs. Commonality: Optimal NFT Art Collection Design","content":"How should an artist optimize the distributions of rare and common features across different dimensions of an art collection? We will formulate the design problem as an integer program, solve a continuous counterpart of the program, and use the insights to construct near-optimal algorithms for large-scale design problems.","presenter":"Mr. Ali Daei Naby","authors":[{"name":"Prof. Ming Hu","aff":"Professor, University of Toronto"},{"name":"Mr. Ali Daei Naby","aff":"Student, University of Toronto"},{"name":"Dr. Zhoupeng (Jack) Zhang","aff":"Assistant Professor, University at Buffalo, SUNY"}],"order":3},{"id":"136-1753","title":"The Impact of Consumer Quality Target on Product Line Design","content":"We study a firm's product line design when customers' utility of consuming a product is affected by not only the product quality but also the difference between the actual product quality and customers' desired quality level. We characterize the optimal product line strategy.","presenter":"Prof. Lucy Chen","authors":[{"name":"Prof. Lucy Chen","aff":"Associate Professor, National University of Singapore"},{"name":"Prof. Qingshan Kong","aff":"Associate Professor, Shandong University"},{"name":"Dr. Shuguang Zhang","aff":"Post Doc/Researcher, National University of Singapore Research Institute in Chongqing"}],"order":4}]},{"id":"s271","title":"Marketing-OM Interface","track":"POM-Marketing Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"HARRIS","chairs":["Prof. Ernan Haruvy"],"abstracts":[{"id":"136-0211","title":"Executive Teams’ Political Alignment and Buyer-Supplier Relationship Outcomes","content":"The alignment between the focal firm’s executive team’s political values and those of a target firm’s executive team can increase the odds of the formation of a new relation and lengthen the duration of an existing one.","presenter":"Prof. Vivek Astvansh","authors":[{"name":"Prof. Vivek Astvansh","aff":"Associate Professor, McGill University"}],"order":1},{"id":"136-2045","title":"The Yin and Yang of Environmental Threat Appeals: Modeling Green Consumption as a Moral Dilemma","content":"This paper argues that environmental threat appeals affect green consumption through two counterbalancing mediators. How consumers respond to such appeal ultimately depends on the balance between these countervailing forces. This research also demonstrates that moderators tip the balance one way or the other.","presenter":"Prof. Paul Messinger","authors":[{"name":"Ms. Hui Jiang","aff":"Professor, ?"},{"name":"Prof. Paul Messinger","aff":"Associate Professor, University of Alberta"},{"name":"Mr. Kaichao Wang","aff":"Student, ?"},{"name":"Mr. Suli Wang","aff":"Student, ?"},{"name":"Mr. Shuiqing Yang","aff":"Student, ?"}],"order":2},{"id":"136-2047","title":"An Empirical Investigation of a Digital Platform’s Release Strategy for Serialized Content","content":"We investigate three release strategies of serialized digital content: simultaneous (releasing the entire content of a book at once), sequential (releasing the content of a book sequentially over time), and hybrid release. These release strategies impact the platform’s revenue through two opposing effects: binge consumption and product exploration.","presenter":"Ms. Clarice Zhao","authors":[{"name":"Ms. Clarice Zhao","aff":"Assistant Professor, McGill University"},{"name":"Mr. Nitin Mehta","aff":"Professor, University of Toronto"},{"name":"Prof. Mengze Shi","aff":"Professor, Hong Kong University of Science and Technology"}],"order":3},{"id":"136-1532","title":"Getting your foot in the door: Seller preferences for surcharges","content":"We develop a game and experimental design to study compulsory surcharges in service contracts. In an online experiment, we find surcharges are highest with exogenous pricing and lowest with ultimatum offers, indicating greater seller pricing autonomy increases moral responsibility. Competition lowers total prices but reduces pricing transparency.","presenter":"Prof. Timo Heinrich","authors":[{"name":"Prof. Ernan Haruvy","aff":"Professor, McGill University"},{"name":"Prof. Timo Heinrich","aff":"Professor, Hamburg University of Technology"},{"name":"Dr. Matthew Walker","aff":"Lecturer, Newcastle University Business School"}],"order":4}]},{"id":"s277","title":"Societal Implications of Drone Integration","track":"Aviation, Transportation, and Logistics Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"UNIVERSITY","chairs":["Prof. Amro El-Adle"],"abstracts":[{"id":"136-1924","title":"Consolidation in parcel delivery by vehicle and drone","content":"We examine a parcel consolidation problem in the context of last-mile delivery by vehicle and drone. The problem is viewed as a multi-period Traveling Salesman Problem with Drone for which an MIP is proposed. We contrast heuristic policies with optimized solutions over problem instances involving up to 100 customers.","presenter":"Prof. Ahmed Ghoniem","authors":[{"name":"Prof. Ahmed Ghoniem","aff":"Professor, University of Massachusetts Amherst"},{"name":"Prof. Amro El-Adle","aff":"Assistant Professor, Old Dominion University"},{"name":"Mr. Semih Boz","aff":"Student, University of Massachusetts Amherst"}],"order":1},{"id":"136-2017","title":"Decomposition approach for vehicle-drone parcel delivery","content":"We investigate a decomposition approach, based on column generation, that seeks to address multi-vehicle/drone operations in last-mile deliveries. Enhancements are proposed to improve the computational tractability of the problem and enable optimized solutions for problem instance sizes of industry relevance.","presenter":"Mr. Semih Boz","authors":[{"name":"Mr. Semih Boz","aff":"Student, University of Massachusetts Amherst"},{"name":"Prof. Ahmed Ghoniem","aff":"Professor, University of Massachusetts Amherst"},{"name":"Prof. Amro El-Adle","aff":"Assistant Professor, Old Dominion University"}],"order":2},{"id":"136-2016","title":"Development of a Probabilistic Approach to Noise Assessment for Drone Package Delivery Operations","content":"Near-future drone package delivery operations are expected to grow rapidly. Their noise emissions must be assessed to estimate the significance of their environmental impact. We develop an approach that addresses the limitations of current methods used for commercial aviation by accounting for the uncertain and large-scale aspects characterizing drone operations.","presenter":"Ms. Nada Himdi","authors":[{"name":"Ms. Nada Himdi","aff":"Student, Georgia Institute of Technology"},{"name":"Dr. Raphael Gautier","aff":"Professor, Georgia Institute of Technology"}],"order":3},{"id":"136-0757","title":"Weather permitting: Tactical Optimization of Drone Delivery Hubs","content":"Considering current regulations and drone technology, we analyze the impact of adverse weather\r\non drone delivery operations, focusing on its effects on profitability and investment decisions.\r\nUsing Dallas, Texas, as a case study, our findings underscore the importance of integrating\r\nweather considerations into service requirements to enhance platform reliability.","presenter":"Mr. Hyun June Kim","authors":[{"name":"Prof. Amro El-Adle","aff":"Assistant Professor, Old Dominion University"},{"name":"Mr. Hyun June Kim","aff":"Student, University of Michigan, Ann Arbor"},{"name":"Dr. Chen Yin-Hsuen","aff":"Post Doc/Researcher, Old Dominion University"},{"name":"Prof. Max Li","aff":"Assistant Professor, University of Michigan - Ann Arbor"}],"order":4},{"id":"136-1934","title":"Equitable Flight Paths for Drone Delivery","content":"We present a computational optimization model that integrates noise pollution metrics into drone flight path planning to both mitigate and equitably distribute the noise resulting from commercial drone flights. The proposed model balances metrics that assess community equity and logistical efficiency.","presenter":"Prof. Amro El-Adle","authors":[{"name":"Prof. Ahmed Ghoniem","aff":"Professor, University of Massachusetts Amherst"},{"name":"Prof. Amro El-Adle","aff":"Assistant Professor, Old Dominion University"},{"name":"Mr. Blake Steiner","aff":"Post Doc/Researcher, Old Dominion University"}],"order":5}]},{"id":"s293","title":"Assortment Planning and Emerging Technologies","track":"Retail Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"FAIRLIE","chairs":["Dr. Amin Aslani"],"abstracts":[{"id":"136-0285","title":"Basic Reusability and Beyond: Joint Inventory and Online Assortment Optimization with Reusable Resource","content":"In this work, we study the joint inventory and online assortment problem, wherein a decision maker (DM) must first select initial inventory levels for a collection of available reusable products, and then offer personalized assortments to customers who arrive over a finite selling horizon.","presenter":"Mr. Yukai Huang","authors":[{"name":"Mr. Yukai Huang","aff":"Student, Washington University in St Louis"},{"name":"Mr. Jacob Feldman","aff":"Associate Professor, Washington University St Louis"},{"name":"Prof. Heng Zhang","aff":"Assistant Professor, Arizona State University"}],"order":1},{"id":"136-0310","title":"Leveraging Augmented Reality and Assortment Planning in Omnichannel Retail Systems","content":"In omnichannel retail, the lack of physical interaction may deter online purchases. Augmented Reality (AR) tools can partially address this issue, while product assortments in physical stores also offer direct interaction. This research examines their interdependence to determine optimal AR investment and in-store assortments, enhancing customer experience and maximizing profitability.","presenter":"Dr. Amin Aslani","authors":[{"name":"Dr. Amin Aslani","aff":"Assistant Professor, University of Wisconsin-Whitewater"},{"name":"Dr. Borzou Rostami","aff":"Assistant Professor, University of Alberta"},{"name":"Mr. Mojtaba Araghi","aff":"Associate Professor, Wilfrid Laurier University"}],"order":3},{"id":"136-0700","title":"Assortments Optimization in Presence of Influencers","content":"We investigate three scenarios of a platform's assortment optimization problem with influencers when some products can promoted by influencers. We establish the structural properties of the optimal assortment and provide polynomial-time or efficient approximation algorithms to address the assortment challenges in each scenario.","presenter":"Dr. Guang Li","authors":[{"name":"Dr. Elaheh Fata","aff":"Assistant Professor, Queens University"},{"name":"Prof. Sumit Kunnumkal","aff":"Professor, Indian School of Business"},{"name":"Dr. Guang Li","aff":"Associate Professor, Queen's University"}],"order":4},{"id":"136-1084","title":"Online Assortment Optimization for Random Consideration Set Choice Model","content":"In this paper, we investigate the online assortment optimization problem for the random consideration set choice model and propose algorithms for both stationary and non-stationary environment.","presenter":"Dr. Wentao Lu","authors":[{"name":"Dr. Wentao Lu","aff":"Post Doc/Researcher, Carey Business School"}],"order":5}]},{"id":"s296","title":"Panel: Publishing Industry Studies and Policy Research","track":"Industry Studies and Public Policy","type":"Panel","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"KENNESAW","chairs":["Dr. Jeff Shockley"],"abstracts":[{"id":"136-2126","title":"Panel: Publishing Industry Studies and Policy Research","content":"Learn from a panel of top journal editors on how to position and publish Industry Studies and Public Policy research, along with best practices and trends.","presenter":"Dr. Jeff Shockley","authors":[{"name":"Dr. Jeff Shockley","aff":"Associate Professor, Virginia Commonwealth University"},{"name":"Dr. John Gray","aff":"Professor, Ohio State University"},{"name":"Prof. Nitin Joglekar","aff":"Associate Professor, Villanova University"},{"name":"Prof. Bradley Staats","aff":"Professor, University of North Carolina Chapel Hill"},{"name":"Prof. Tonya Boone","aff":"Professor, College of William and Mary"}],"order":1}]},{"id":"s307","title":"Risk Management and Financial Hedging Strategies in Supply Chains","track":"Supply Chain Risk Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"EMBASSY H","chairs":["Dr. Piyal Sarkar"],"abstracts":[{"id":"136-1853","title":"The Impact of Frequency and Duration on Supplier Disruption Risk Mitigation","content":"Supplier Disruption risk is a combination of Frequency and Duration of disruptions. We study the impact of each of the dimensions and see that strategies like are dependent on the two dimensions individually. We show how managers must tailor their mitigation strategies to the disruption risk profile they face.","presenter":"Mr. Vishwakant Malladi","authors":[{"name":"Mr. Vishwakant Malladi","aff":"Assistant Professor, Indian School of Business"}],"order":2},{"id":"136-0863","title":"Designing a downside risk diagnosis process for the supply chain","content":"This research investigates the relationship between the performance of supply chains and disruptions, aiming to proactively manage downside risks using concepts and models from medical diagnostics. The focus is on the relationships between various types of supply chain performance and the specific types of disruptions they may lead to.","presenter":"Mr. Zhong Guan","authors":[{"name":"Mr. Zhong Guan","aff":"Student, Cambridge University"},{"name":"Ms. Mariel Alem Fonseca","aff":"Student, Cambridge University"},{"name":"Dr. Yongjiang Shi","aff":"Lecturer, Cambridge University"},{"name":"Dr. Mukesh Kumar","aff":"Associate Professor, University of Cambridge"}],"order":3},{"id":"136-1394","title":"Supply Chain Disruption Risk and Government Credit Disbursement","content":"By constructing a multilayer network and measuring the node disruption risk and shocked intensity based on a dynamics approach, this paper provides a new algorithm to characterize the disruption risk of corporate supply chains and investigates the impact of corporate supply chain disruption risk on state credit disbursement.","presenter":"Dr. Jian Xiong","authors":[{"name":"Dr. Jian Xiong","aff":"Student, Southeast University"},{"name":"Prof. Wei Yin","aff":"Associate Professor, Southeast University"}],"order":4},{"id":"136-1597","title":"Trade credit under weather risk in supply chains","content":"Trade credit is one of the widely used financing schemes today. Trade credit acts as an incentive to encourage buyers to increase ordering quantities as it allows delayed payments. This paper explores the coordination mechanism of trade credits in a supply chain with weather-related uncertainties.","presenter":"Dr. Piyal Sarkar","authors":[{"name":"Dr. Piyal Sarkar","aff":"Assistant Professor, Pennsylvania State University Harrisburg"},{"name":"Dr. Wahab Ismail","aff":"Professor, Ryerson University"},{"name":"Dr. Liping Fang","aff":"Professor, Ryerson University"}],"order":5}]},{"id":"s315","title":"Information Policies in Revenue Management","track":"Revenue Management and Pricing","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"MARIETTA","chairs":["Dr. Yang Lu"],"abstracts":[{"id":"136-0711","title":"Value of One Data Point: Active Label Acquisition in Assortment Optimization","content":"This paper studies how to sequentially and actively collect informative data to construct a prediction model for predicting customers preferences and thereby determine best personalized assortment. We introduce a novel concept,`value of one data point,' which evaluates the marginal contribution of acquiring a specific customer's preference to the expected revenue.","presenter":"Prof. Mo Liu","authors":[{"name":"Prof. Mo Liu","aff":"Assistant Professor, University of North Carolina at Chapel Hill"},{"name":"Dr. Junyu Cao","aff":"Assistant Professor, University of Texas Austin"},{"name":"Prof. Max Shen","aff":"Professor, University of Hongkong"}],"order":1},{"id":"136-0696","title":"Product Information Display Optimization with Quality Uncertainty and Returns","content":"Display quality refers to product information such as the images and textual descriptions of product quality presented to consumers shopping online. We investigate the product display optimization problems on display quality, pricing, and assortment planning, in consideration of product quality uncertainty and consumers' returns.","presenter":"Dr. Yang Lu","authors":[{"name":"Dr. Yang Lu","aff":"Student, China University of Science and Technology"},{"name":"Dr. Ruxian Wang","aff":"Professor, Johns Hopkins University"},{"name":"Prof. Yan Xiaoming","aff":"Associate Professor, China University of Science and Technology"},{"name":"Prof. Yugang Yu","aff":"Professor, University of Science and Technology of China"}],"order":2},{"id":"136-0988","title":"On the interplay between pricing and information policies in monopoly selling","content":"This paper explores how firms maximize revenue in markets with social learning by integrating pricing strategies and information policies. It reveals that dynamic pricing enables firms to leverage the most informative signals, while under static pricing, additional informational signals offer mixed benefits due to complex purchasing responses from customers.","presenter":"Ms. Zi Ling","authors":[{"name":"Ms. Zi Ling","aff":"Student, University of Chicago"},{"name":"Dr. Chris Ryan","aff":"Associate Professor, University of British Columbia"},{"name":"Dr. Mengzhenyu Zhang","aff":"Assistant Professor, UCL School of Management"}],"order":3}]},{"id":"s321","title":"Market Design, Risk, and Financial Integration","track":"POM-Finance Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"EMBASSY A","chairs":["Prof. Anqi Wu","Mr. Shi Qiu"],"abstracts":[{"id":"136-0977","title":"Impact of AI on Electricity Market Auction","content":"With AI's rise in electricity market, we develop deep neural network agents to simulate electricity market auction without model-free assumptions. Experiments reveal negative price, a counterintuitive phenomenon unique to electricity markets. We analyze its causes and social welfare impacts, offering insights for policymakers and advancing AI-driven market design discussions.","presenter":"Mr. JUNQI LIU","authors":[{"name":"Mr. JUNQI LIU","aff":"Student, Bauer Human-Centered AI Institute, University of Houston"}],"order":2},{"id":"136-1515","title":"The Lost Decade for U.S. Manufacturing Jobs: A Story of Cost and Risk","content":"This paper identifies a risk management motive for outsourcing: post-China’s 2000 PNTR, U.S. firms outsourced to mitigate supply-demand mismatch risk under high systematic risk and volatility. Empirical results highlight this alongside pre-2000 cost arbitrage motives. Counterfactual analysis emphasizes the need to enhance domestic production flexibility to retain manufacturing jobs.","presenter":"Mr. Shi Qiu","authors":[{"name":"Mr. Shi Qiu","aff":"Student, University of Illinois at Urbana Champaign"}],"order":3},{"id":"136-1711","title":"Mergers and Acquisitions in the Inter-State Trade Network","content":"Using a network framework, we show that cross-state mergers propagate along trade links, with high merger activity in one state increasing mergers in its trading partners. This effect spans vertically connected industries but is weaker in non-tradable sectors, highlighting the role of economic integration in merger dynamics.","presenter":"Dr. Xinyan Yan","authors":[{"name":"Dr. Xinyan Yan","aff":"Assistant Professor, University of South Florida"},{"name":"Dr. Lei Kong","aff":"Associate Professor, University of Alabama"}],"order":4}]},{"id":"s322","title":"Workshop: Operational Efficiency Tools, Techniques and Approaches","track":"Operational Excellence","type":"Workshop","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"BAKER","chairs":["Prof. Adel Hatamimarbini"],"abstracts":[{"id":"136-2115","title":"Operational Efficiency Tools, Techniques and Approaches","content":"This workshop will explore tools, techniques and metrics designed to improve operational efficiency in manufacturing and service settings - including a discussion on the role and impact of emerging technologies.","presenter":"Prof. Adel Hatamimarbini","authors":[{"name":"Prof. Adel Hatamimarbini","aff":"Professor, University of Huddersfield"}],"order":1}]},{"id":"s334","title":"Operational Efficiency in Healthcare Delivery Systems","track":"Healthcare Analytics","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"INMAN","chairs":["Dr. Seokjun Youn"],"abstracts":[{"id":"136-1456","title":"Diagnostic Discrepancies and Their Operational Impact: The Influence of Physician Experience","content":"This study examines diagnostic discrepancies, or mismatches between admission and primary diagnoses, and their operational impact on hospital stays. Through retrospective medical record analysis, it identifies discrepancy patterns and investigates how the focused and varied experience of physicians affects these dynamics and influences the overall operational outcomes.","presenter":"Dr. Yingchao Lan","authors":[{"name":"Dr. Seokjun Youn","aff":"Assistant Professor, University of Arizona"},{"name":"Dr. Yingchao Lan","aff":"Associate Professor, University of Nebraska Lincoln"}],"order":1},{"id":"136-1764","title":"Measuring Consistency in Service Delivery: Examining the Effect of Process Standardization on Hospital Performance","content":"We examine process standardization in healthcare, developing a novel construct based on service consistency. Using detailed inpatient data, we analyze its impact on cost, quality, and variation across hospitals, operating units, and health conditions, while exploring factors influencing standardization, such as capacity utilization, disease complexity, focus, and adherence.","presenter":"Dr. Anand Bhatia","authors":[{"name":"Dr. Anand Bhatia","aff":"Assistant Professor, IE BUSINESS SCHOOL"},{"name":"Prof. Jayashankar Swaminathan","aff":"Professor, University of North Carolina Chapel Hill"}],"order":3},{"id":"136-1066","title":"Physician Workload and Incidence of Medical Malpractice Lawsuits: An Empirical Investigation","content":"The U.S. experiences medical malpractice payments totaling billions of dollars annually. This study utilizes an extensive national, longitudinal database to determine how physician workload intensity impacts malpractice case frequency. Our results have policy implications and can help physicians manage their liability risk better. Robustness checks are done using adverse action.","presenter":"Ms. Denise Bergdolt","authors":[{"name":"Ms. Denise Bergdolt","aff":"Student, University of Pittsburgh"},{"name":"Dr. PRAKASH MIRCHANDANI","aff":"Professor, University of Pittsburgh"}],"order":4},{"id":"136-1684","title":"Substance Use Disorder Treatment Hypothesis Generation with Machine Learning","content":"Substance Use Disorder (SUD) treatment is a context rich with opportunities for generating new hypotheses. However, rigorous hypothesis generation is non-trivial. We propose and apply a Machine Learning (ML) framework for hypothesis generation in the context of SUD treatment, generating hypotheses related to heterogeneity in SUD treatment completion.\r\n\r\n\r\n\r\n\r\n","presenter":"Mr. Mouayed Lajnef","authors":[{"name":"Mr. Mouayed Lajnef","aff":"Student, Georgia State University"},{"name":"Dr. Aaron Baird","aff":"Associate Professor, Georgia State University"},{"name":"Dr. Arun Rai","aff":"Professor, Georgia State University"},{"name":"Prof. Yusen Xia","aff":"Professor, Georgia State University"}],"order":5}]},{"id":"s386","title":"Storage Operations and Emerging Trends in Energy Management","track":"Energy and Natural Resource Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"TECHWOOD","chairs":["Dr. Majid Azadi"],"abstracts":[{"id":"136-1560","title":"Matching Supply with Demand for a Renewable Energy Generator Using a Battery Energy Storage System","content":"Battery energy storage system (BESS) helps renewable energy sources (RES) manage intermittent energy generation and capture higher revenues. We investigate the optimal BESS usage when RES participates in the electricity market and faces balancing penalties. We find that RES using BESS would exploit arbitrage and cause overall lower grid imbalance.","presenter":"Mr. Ashish Bhandari","authors":[{"name":"Mr. Ashish Bhandari","aff":"Student, Indian Institute of Management Bangalore"},{"name":"Prof. Amar Sapra","aff":"Professor, Indian Institute of Management Bangalore"}],"order":1},{"id":"136-0174","title":"Mitigating Investment Risks in Long Duration Energy Storage through Capacity Market Contracts","content":"This study explores how pre-signing capacity market contracts can mitigate investment risks in long duration energy storage (LDES) to enhance LDES deployment within a low-carbon energy system. To this end, the research examines investment costs, optimal capacity, and technology options, while identifying key risks from a risk-averse investor's perspective.","presenter":"Dr. Reza Gharoie Ahangar","authors":[{"name":"Ms. Yufeng Gao","aff":"Student, University of Hong Kong"},{"name":"Dr. Reza Gharoie Ahangar","aff":"Assistant Professor, Lewis University"}],"order":2},{"id":"136-1020","title":"Multi-criteria decision analysis for hydrogen hub location: Key factors in renewable energy value chains","content":"Ports play pivotal roles in green hydrogen value chains, serving as industrial, logistics, transport, and bunkering hubs. We develop a framework, identify stakeholders and criteria for site selection, and propose a multi-actor multi-criteria decision-making model to guide strategic decisions, supporting the transition to decarbonized energy systems through hydrogen adoption.","presenter":"Ms. Lara Pomaska","authors":[{"name":"Ms. Lara Pomaska","aff":"Student, Kuehne Logistics University"}],"order":3},{"id":"136-0072","title":"Multicomponent production technologies and the performance of green power plants","content":"Green energy production plays a key role in the world economy. By using multiple hybrid returns to scale technologies we propose a model to assess the performance of green power plants. We also show how the developed technology in this study can improve the performance in multicomponent production systems.","presenter":"Dr. Majid Azadi","authors":[{"name":"Dr. Majid Azadi","aff":"Assistant Professor, Aston University Birmingham"}],"order":4}]},{"id":"s409","title":"Emergency Services and Healthcare Access Optimization","track":"Healthcare Operations Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"PIEDMONT","chairs":["Dr. Isil Koyuncu"],"abstracts":[{"id":"136-1988","title":"A Geometrically Convergent Solution to Spatial Hypercube Queueing Models for Emergency Services","content":"We have extended the hypercube queueing model to accommodate heterogeneous service rates by devising an exact solution. We prove that our algorithm converges to the exact solution at a geometric rate. We developed a parallel computing algorithm with high efficiency. We also illustrate how our solution supports operational decision-making.","presenter":"Mr. Yixing Wen","authors":[{"name":"Dr. Cheng Hua","aff":"Associate Professor, Shanghai Jiao Tong University"},{"name":"Dr. Jun Luo","aff":"Professor, Shanghai Jiao Tong University"},{"name":"Prof. Arthur Swersey","aff":"Retired, Yale University"},{"name":"Mr. Yixing Wen","aff":"Student, Shanghai Jiao Tong Univesity"}],"order":1},{"id":"136-1701","title":"Modeling Treatment Center Location Selection and its Effects on Access to Gene Therapy in Brazil","content":"To improve access for patients with low-prevalence diseases, our approach to treatment center location facilitates decision-maker discussion with an interactive optimization model that explicitly includes patient travel costs. Based on application to an upcoming gene therapy launch in Brazil, we discuss how the approach enabled stakeholders to explore access options.","presenter":"Dr. Jarrod Goentzel","authors":[{"name":"Ms. Sarah Wertheimer","aff":"Student, Massachusetts Institute of Technology"},{"name":"Dr. Jarrod Goentzel","aff":"Post Doc/Researcher, Massachusetts Institute of Technology"}],"order":3},{"id":"136-1454","title":"Assessing the effect of centralization in the dispatch of emergency services","content":"Drawing on a multi-year, full panel of regional emergency response cases, we assess the effects of a policy change that centralizes the allocation of emergency cars. We provide evidence for an unresolved principal-agent problem in the selection of hospitals for treatment which remained decentralized","presenter":"Dr. Oliver von Dzengelevski","authors":[{"name":"Dr. Matteo Bernasconi","aff":"Student, Universitat St. Gallen"},{"name":"Dr. Oliver von Dzengelevski","aff":"Lecturer, ETH Zurich"},{"name":"Mrs. Jessica Helbling","aff":"Student, University of St.Gallen"},{"name":"Prof. Thomas Friedli","aff":"Professor, University of St. Gallen"},{"name":"Prof. Torbjørn Netland","aff":"Professor, ETH Zurich"}],"order":5}]},{"id":"s432","title":"New Product Development and Innovation in Supply Chains","track":"Supply Chain Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"EMBASSY G","chairs":["Mr. Faizul Haque"],"abstracts":[{"id":"136-0704","title":"Bridging the Gap: How Reducing Supply Chain Distance Boosts Enterprise Innovation","content":"We examine how supply chain distance aaffects enterprise innovation output, using panel data from Chinese A-share listed companies. Findings reveal a negative impact, especially in non-state-owned SMEs with concentrated supply chains. Risk-taking and information asymmetry partially mediate this relationship. Firms should mitigate these effects through best practices and improved communication.","presenter":"Prof. Mihalis Giannakis","authors":[{"name":"Prof. Mihalis Giannakis","aff":"Professor, Audencia Business School"},{"name":"Dr. Yao Liu","aff":"Post Doc/Researcher, Sichuan University"}],"order":1},{"id":"136-0122","title":"Chasing the Rivals : How does supply chain overlap with rivals affect firm innovation?","content":"We examine the innovation ecosystem created due to the overlap of suppliers and strategic partners in the supply network between a focal firm and its rivals, which influences the firm's innovation. We constructed a unique panel dataset from 2009 to 2019, consisting of 490 global manufacturing firms from different industries.","presenter":"Prof. Krishna Sundar Diatha","authors":[{"name":"Mr. Shubham Singh","aff":"Student, Indian Institute of Management Bangalore"},{"name":"Dr. Ravi Srinivasan","aff":"Professor, Loyola University Maryland"},{"name":"Dr. Anirban Adhikary","aff":"Associate Professor, IIM Udaipur"},{"name":"Prof. Krishna Sundar Diatha","aff":"Professor, Indian Institute of Management Bangalore"}],"order":2},{"id":"136-0060","title":"R&amp;D and Patent Data Usage in Supply Chain Research: A Review and Framework Forward","content":"There is widespread variation in how theories and measures are utilized to explore innovation in the extant SCM literature. Through a structured literature review we tabulate measures published in top SCM research journals and evaluate the consistency of various archival proxy variables for measuring “innovation” across this stream of research.","presenter":"Dr. Senali Amarasuriya","authors":[{"name":"Dr. Senali Amarasuriya","aff":"Assistant Professor, Middle Tennessee State University"},{"name":"Dr. Alan Mackelprang","aff":"Associate Professor, Georgia Southern University"},{"name":"Dr. Jerry Burke","aff":"Professor, Dept. of LSCM, Georgia Southern"}],"order":3},{"id":"136-0732","title":"Greening the Competition: Optimal Strategies for National and Store Brands","content":"Amid rising consumer environmental consciousness and the introduction of green products in the market, competition between National Brands and Store Brands has intensified. In this study, we address a contemporary problem by investigating how the decisions to develop green products by both brands and the preferences of green-conscious consumers interact.","presenter":"Mr. Faizul Haque","authors":[{"name":"Mr. Ranit Saha","aff":"Student, Indian Institute of Management Calcutta"},{"name":"Mr. Faizul Haque","aff":"Student, Indian Institute of Management Calcutta"},{"name":"Prof. Sumanta Basu","aff":"Professor, Indian Institute of Management Calcutta"}],"order":4}]},{"id":"s441","title":"AI and Analytics Impact on students, workers, and sports","track":"Data Science, Analytics and AI","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"ROSWELL","chairs":["Mr. Daniel Nielubowicz"],"abstracts":[{"id":"136-0414","title":"Algorithmic Screening under Competition","content":"The advent of AI and machine learning algorithms has demonstrated potential advantages in the recruitment process, with an increasing number of firms adopting algorithmic tools for candidate selection. To examine how firms balance the dual-layer trade-offs in AI recruiting, we consider competition for a certain pool of candidates.","presenter":"Dr. Xuefeng Peng","authors":[{"name":"Dr. Xuefeng Peng","aff":"Post Doc/Researcher, The University of Hong Kong"},{"name":"Prof. Stefanus Jasin","aff":"Associate Professor, University of Michigan"},{"name":"Prof. Feng Tian","aff":"Assistant Professor, the University of Hong Kong"}],"order":1},{"id":"136-1991","title":"AI Exposure on Workers’ Career Path: Evidence from U.S. Workforce","content":"We find a diverged impact of being exposed to AI on employees' career paths with different seniority levels. For employees whose seniority level is high when exposed to AI, their future salary and seniority will increase compared to those not being exposed, while for junior employees, these will decrease.","presenter":"Dr. Guohou Shan","authors":[{"name":"Mr. Xiaoning Wang","aff":"Assistant Professor, University of Texas at Dallas"},{"name":"Dr. Guohou Shan","aff":"Assistant Professor, Northeastern University"},{"name":"Prof. Amit Mehra","aff":"Professor, University of Texas Dallas"}],"order":2},{"id":"136-1955","title":"Soccer Player Position Analytics","content":"Soccer is widely regarded as one of the most popular sports in the world. This study aims to develop an efficient analytical technique to help managers, and general users of soccer data to extract actionable information from the wide range of metrics now routinely measured on players.","presenter":"Dr. Emmanuel Otubo","authors":[{"name":"Dr. Emmanuel Otubo","aff":"Assistant Professor, Coastal Carolina University"},{"name":"Dr. Olajumoke Awe","aff":"Associate Professor, Coastal Carolina University"}],"order":3},{"id":"136-2001","title":"Student AI usage in Higher Education","content":"We explore how students in higher education utilize AI tools for learning, focusing on usage trends, academic impact, and ethical considerations. The study highlights challenges such as digital literacy gaps and access disparities, offering insights for institutions to support responsible and effective AI adoption in academic environments.","presenter":"Mr. Daniel Nielubowicz","authors":[{"name":"Mr. Daniel Nielubowicz","aff":"Assistant Professor, University of Washington Bothell"}],"order":4}]},{"id":"s443","title":"Data Driven Strategies and AI Implementation in Healthcare","track":"Healthcare Analytics","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"SPRING","chairs":["Prof. Shujing Sun"],"abstracts":[{"id":"136-1237","title":"Regulating Adaptive Medical Artificial Intelligence: Can Less Oversight Lead to Greater Compliance?","content":"As of June 2024, the FDA approved 950 AI/ML devices, yet its regulatory framework hinders adaptive learning by freezing algorithms post-approval. Predetermined Change Control Plans (PCCP) allow pre-approved updates, but their compliance impact is uncertain. Modeling reveals that reduced oversight can boost compliance under moderate auditing and significant retraining benefits.","presenter":"Prof. Tinglong Dai","authors":[{"name":"Ms. Jiayi Lai","aff":"Student, Singapore Management University"},{"name":"Dr. Liang Xu","aff":"Assistant Professor, Singapore Management University"},{"name":"Dr. Xin Fang","aff":"Associate Professor, Singapore Management University"},{"name":"Prof. Tinglong Dai","aff":"Professor, Johns Hopkins University"}],"order":1},{"id":"136-1734","title":"How Does Insurance Coverage Affect Unclaimed Prescriptions and Physician’s Behavior?","content":"This study examines how insurance coverage affects unclaimed prescriptions and prescribing behaviors using outpatient data from a Liaoning hospital, revealing variations by charges, drug types, and demographics. Findings underscore the need for tailored policies to balance patient needs and healthcare budgets effectively.","presenter":"Ms. Zheng Zeng","authors":[{"name":"Ms. Zheng Zeng","aff":"Student, Rutgers Business School"},{"name":"Dr. Xiaowei Xu","aff":"Associate Professor, Rutgers Business School"},{"name":"Dr. Lian Qi","aff":"Professor, Rutgers University"}],"order":2},{"id":"136-0464","title":"The Dominance of Social Influence Over Algorithm Accuracy in Patient Decision","content":"This study explores the impact of technical and social information on human acceptance of algorithmic recommendations in a healthcare context. Our analysis shows that patient acceptance of AI recommendations are highly correlated with algorithm accuracy or peer acceptance when they are present.","presenter":"Prof. Shujing Sun","authors":[{"name":"Prof. Shujing Sun","aff":"Assistant Professor, University of Texas at Dallas"},{"name":"Prof. Lauren Lu","aff":"Professor, Dartmouth College"},{"name":"Prof. Feng (Susan) Lu","aff":"Professor, Purdue University"},{"name":"Dr. Wei Gu","aff":"Professor, University of Science and Technology Beijing"}],"order":4}]},{"id":"s450","title":"Impacts of Policy on Humanitarian Operations Practice","track":"Humanitarian Operations and Crisis Management","type":"Panel","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"11:30 AM","end":"1:00 PM","startMin":690,"room":"AUBURN","chairs":["Dr. Felipe Aros-Vera"],"abstracts":[{"id":"136-2144","title":"Impacts of Policy on Humanitarian Operations Practice ","content":"This panel serves as a follow-up from the fieldtrip (Mini-Conference).","presenter":"Dr. Felipe Aros-Vera","authors":[{"name":"Dr. Felipe Aros-Vera","aff":"Associate Professor, Ohio University"}],"order":1}]},{"id":"s9","title":"Empirical research on POM and Community topics","track":"POM and Community","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"EMBASSY F","chairs":["Dr. Li Ding"],"abstracts":[{"id":"136-0378","title":"Riding Through Rallies: Will You Tip More?","content":"We collect the ride-hailing data from the Chicago Data Portal and estimate a year-to-year difference-in-difference model to study the impact of antiracism protests on customers’ prosocial behaviours (i.e., tipping). We find that such social shocks encouraged passengers to tip more, yet the ultimate\r\nimpacts on workers’ incomes are more nuanced.","presenter":"Dr. Zhoupeng (Jack) Zhang","authors":[{"name":"Dr. Zhoupeng (Jack) Zhang","aff":"Assistant Professor, University at Buffalo, SUNY"},{"name":"Dr. Wanjiang Deng","aff":"Assistant Professor, Zhejiang University"},{"name":"Prof. Ming Hu","aff":"Professor, University of Toronto"}],"order":1},{"id":"136-0565","title":"Rumors, Worker Productivity, and Team Performance","content":"Rumors are ubiquitous in the workplace, particularly regarding organizational changes. These rumors significantly influence worker behavior by introducing uncertainty, and thus, affect productivity and team performance. However, no studies have provided empirical evidence for these impacts due to data limitations on rumors and workers’ behaviors in completing tasks.","presenter":"Mr. Zhanzhi Zheng","authors":[{"name":"Mr. Zhanzhi Zheng","aff":"Student, UNC Kenan-Flagler Business School"},{"name":"Prof. Bradley Staats","aff":"Professor, University of North Carolina Chapel Hill"},{"name":"Dr. Shenyang Jiang","aff":"Assistant Professor, Tongji University"}],"order":2},{"id":"136-0716","title":"Close Childcare Retains Talent: An Empirical Study of Childcare Availability and US Knowledge Workers","content":"The scarcity of quality childcare services has long obstructed the career progression of working parents in the US. Leveraging large-scale national job profile data from 1997 to 2019, we investigate how the career development of employees in a variety of industries is influenced by the availability and location of childcare.","presenter":"Mrs. Zhihan (Helen) Wang","authors":[{"name":"Mrs. Zhihan (Helen) Wang","aff":"Student, University of Michigan, Ann Arbor"},{"name":"Prof. Damian Beil","aff":"Professor, University of Michigan"},{"name":"Prof. Jun Li","aff":"Associate Professor, Ross School of Business"}],"order":3}]},{"id":"s28","title":"Practice-based decision-support modelling work in humanitarian OM","track":"Humanitarian Operations and Crisis Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"GRAND HALL EAST B","chairs":["Dr. Harwin De Vries"],"abstracts":[{"id":"136-0047","title":"Reconciling rigor vs. relevance: Lessons from humanitarian fleet management","content":"We reframe the relevance vs. rigor debate as a Kuhnian crisis, in which the dominant paradigm of quantitative modeling shows signs of exhaustion. Humanitarian fleet management is presented as an empirical case. Combining “hard” and “soft” OR, solutions can become more productive by surfacing the organizational context of decision-making.","presenter":"Dr. Sarah Schaumann","authors":[{"name":"Dr. Sarah Schaumann","aff":"Post Doc/Researcher, Massachusetts Institute of Technology"},{"name":"Ms. Bublu Thakur-Weigold","aff":"Senior Lecturer, Swiss Federal Institute of Technology Zurich"},{"name":"Prof. Luk Van Wassenhove","aff":"Professor, INSEAD"}],"order":1},{"id":"136-0301","title":"Data-driven optimization in humanitarian supply chains. An application to Madagascar","content":"In this talk, I reflect on conducting bottom-up research, which involves directly engaging with field organizations in humanitarian supply chains to identify challenges and propose solutions through modeling and solving complex decision-making problems. I also present an analytics-based solution framework developed with EPSUS for cyclone response prepositioning in Madagascar.","presenter":"Dr. Marie-Eve Rancourt","authors":[{"name":"Dr. Marie-Eve Rancourt","aff":"Associate Professor, HEC Montréal"},{"name":"Ms. Birce Adsanver","aff":"Student, HEC Montréal"},{"name":"Dr. Burcu Balcik","aff":"Professor, Ozyegin University"},{"name":"Dr. Valérie Bélanger","aff":"Associate Professor, HEC Montréal"}],"order":2},{"id":"136-0550","title":"Common Relief Network Design Assumptions that Fall Short: The Role of Staging Hubs in Ukraine","content":"Staging hubs are temporary, intermediate nodes in humanitarian aid supply chains. Many papers for optimizing networks of staging hubs exist. We distill common assumptions from these papers, and compare these with observations from our field exploration of staging hubs in Ukraine.","presenter":"Dr. Harwin De Vries","authors":[{"name":"Dr. Harwin De Vries","aff":"Associate Professor, Rotterdam School of Management"},{"name":"Mr. Matthieu Asselin","aff":"Student, Rotterdam School of Management"},{"name":"Mrs. Océane Fourmentraux","aff":"Student, Rotterdam School of Management"},{"name":"Mrs. Anna Nikulina","aff":"Lecturer, Erasmus University"}],"order":3},{"id":"136-1580","title":"From the Ivory Tower to the Field: The Impact of Humanitarian Operations Research on Practice","content":"This paper seeks to better understand the gap between research and practice in humanitarian operations. We draw on a review of abstracts, survey of authors, and interviews with humanitarian practitioners to identify the extent of and barriers to practice impact, and we develop a framework for describing it.","presenter":"Dr. Erica Gralla","authors":[{"name":"Dr. Erica Gralla","aff":"Associate Professor, George Washington University"},{"name":"Prof. Maria Besiou","aff":"Professor, Kuehne Logistics University"}],"order":4}]},{"id":"s29","title":"Workforce Management","track":"POM and Community","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"EMBASSY E","chairs":["Prof. Vincent Slaugh"],"abstracts":[{"id":"136-1425","title":"Can Workplace DEI enhance manufacturing environmental performance? Evidence from Employment Non-Discrimination Acts","content":"In this study, we explore how enhanced workplace DEI affects toxic releases in manufacturing operations. To investigate this idea, we utilize the staggered adoption of Employment Non-Discrimination Act and find that enhanced workplace DEI, facilitated by ENDA enactments, leads to reduced toxic chemical releases.","presenter":"Mr. Max Ji","authors":[{"name":"Mr. Max Ji","aff":"Student, Penn State"},{"name":"Prof. Suvrat Dhanorkar","aff":"Associate Professor, Penn State University State College"},{"name":"Dr. Kevin Linderman","aff":"Professor, Penn State University"},{"name":"Prof. Suresh Muthulingam","aff":"Professor, Penn State University University Park"}],"order":1},{"id":"136-1743","title":"Workforce Management in Tribal Enterprises: Career Trajectories, Turnovers, and Tribal Membership Status","content":"We utlilize a novel data set to investigate career trajectories and turnover rate at tribal enterprises/casinos over the span of several decades. We highlight rehiring patterns as they pertain to tribal membership status.","presenter":"Mr. Jacob Ornelas","authors":[{"name":"Mr. Jacob Ornelas","aff":"Student, Cornell University"},{"name":"Prof. Vincent Slaugh","aff":"Assistant Professor, Cornell University"},{"name":"Prof. Chris Anderson","aff":"Associate Professor, Cornell University"}],"order":2},{"id":"136-1790","title":"The Long Wait: A Theory of Youth Unemployment","content":"We study how esteem affects job search and as a result the levels of youth unemployment especially in developing countries in the context of applying for public sector/government jobs. We find multiple equilibria with one characterized by very high levels of youth unemployment when we incorporate esteem in job search.","presenter":"Ms. Saloni Vadeyar","authors":[{"name":"Ms. Saloni Vadeyar","aff":"Student, Cornell University"}],"order":3}]},{"id":"s36","title":"Algorithmic Decision-Making in Healthcare","track":"Healthcare Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"PIEDMONT","chairs":["Dr. Reza Skandari"],"abstracts":[{"id":"136-2043","title":"When Systemic Biases Taint Algorithms: A Path to More Equitable Access in Healthcare","content":"Algorithms using historical data can replicate and amplify existing flaws in social systems. For example, systemic disparities in access to healthcare can taint algorithmic predictions, leading to \"socio-algorithmic bias.\" We formulate a bias-aware algorithmic decision-making framework that factors the origins of socio-algorithmic bias in healthcare while considering fairness and efficiency.","presenter":"Ms. Ozgur Aksoy","authors":[{"name":"Ms. Ozgur Aksoy","aff":"Student, The University of Texas at Dallas"},{"name":"Prof. Mehmet Ayvaci","aff":"Associate Professor, The University of Texas at Dallas"},{"name":"Prof. Asunur Cezar","aff":"Professor, Bogazici University"},{"name":"Prof. Srinivasan Raghunathan","aff":"Professor, The University of Texas at Dallas"}],"order":1},{"id":"136-0141","title":"Machine Learning-Guided Cancer Screening: The Benefits of Proactive Care","content":"We study the real-world effects of a machine learning-guided colorectal cancer screening program deployed at a health system in Pennsylvania. Using a regression discontinuity design based on the predicted risk score for having cancer, we evaluate the causal effects of the program on screening uptake and patient mortality.","presenter":"Prof. Minje Park","authors":[{"name":"Prof. Minje Park","aff":"Assistant Professor, The University of Hong Kong"},{"name":"Prof. Carri Chan","aff":"Assistant Professor, Columbia University"},{"name":"Dr. Keith Boell","aff":"Chief Quality Officer / Geisinger, Geisinger"},{"name":"Dr. Elliot Mitchell","aff":"Senior Data Scientist, Geisinger"},{"name":"Dr. Abdul Tariq","aff":"Associate Vice President (Data Science), Children’s Hospital of Philadelphia"}],"order":2},{"id":"136-1837","title":"Synchronizing the Treatment of Multiple Chronic Conditions","content":"We design a dynamic programming approach to study the treatment synchronization of multiple chronic conditions. We provide a closed-form heuristic to solve this problem and bound its regret. A case study on age-related macular degeneration shows up to $582M in savings by efficiently synchronizing treatments in the US.\r\n","presenter":"Mr. Kuofu Liu","authors":[{"name":"Dr. Luke DeRoos","aff":"Post Doc/Researcher, University of Michigan, Ann Arbor"},{"name":"Mr. Kuofu Liu","aff":"Student, University of Michigan, Ann Arbor"},{"name":"Dr. Amirehossein Moosavi","aff":"Post Doc/Researcher, University of Michigan, Ann Arbor"},{"name":"Prof. Mariel Lavieri","aff":"Associate Professor, University of Michigan - Ann Arbor"},{"name":"Dr. Joshua Stein","aff":"Associate Professor, University of Michigan - Ann Arbor"},{"name":"Jason Miller","aff":""}],"order":4},{"id":"136-0322","title":"A Data-driven Optimization Approach to Designing Parsimonious Treatment Guidelines","content":"To balance between personalized medicine and clinical guidelines, we develop a framework to design optimal parsimonious treatment guidelines for a heterogeneous population of patients. We propose several exact and heuristic methods to solve the problem and apply our methods to a case study on hypertension treatment planning.","presenter":"Dr. Gian-Gabriel Garcia","authors":[{"name":"Dr. Gian-Gabriel Garcia","aff":"Assistant Professor, Georgia Institute of Technology"},{"name":"Ms. Sun Ju Lee","aff":"Student, Georgia Institute of Technology"}],"order":6},{"id":"136-1933","title":"Efficient Discovery of Cost-effective Policies in Sequential, Medical Decision-Making Problems","content":"Cost-effectiveness analysis guides healthcare policymakers in budget allocation by evaluating interventions across willingness-to-pay thresholds. We introduce a novel algorithm to identify the cost-effectiveness frontier in parametric linear programming models, including CMDPs and CPOMDPs, and demonstrate its application in designing hearing loss screening strategies for cystic fibrosis populations.","presenter":"Dr. Reza Skandari","authors":[{"name":"Ms. Narges Mohammadi","aff":"Student, Imperial College London"},{"name":"Dr. Reza Skandari","aff":"Assistant Professor, Imperial College London"}],"order":7}]},{"id":"s61","title":"Socially Responsible Operations","track":"Sustainable Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"GRAND HALL EAST C","chairs":["Dr. Gokce Esenduran","Dr. Burcu Tan Erciyes"],"abstracts":[{"id":"136-0138","title":"Empowering or Exploiting? The Implications of Direct Market Access for Improving Smallholder Farmers' Welfare","content":"Poor market access impedes poverty reduction in remote areas. We evaluate two major market access strategies for enhancing farmers' income: contract farming and rural livestreaming. We find that policymakers should consider the operational and market characteristics of local crops and existing poverty reduction policies when choosing between the two strategies.","presenter":"Mr. Xi (Henry) Lin","authors":[{"name":"Mr. Xi (Henry) Lin","aff":"Student, University of California Irvine"},{"name":"Prof. Luyi Gui","aff":"Associate Professor, University of California Irvine"},{"name":"Prof. Yixin Lu","aff":"Associate Professor, George Washington University"}],"order":1},{"id":"136-0207","title":"Building Alliances for Corporate Social Responsibility","content":"Companies successfully form an alliance for a shared social responsibility initiative despite the incentive to free ride. Our model finds that an invitation mechanism and status seeking together explain the success. Our lab experiment shows that the invitation mechanism is key and heterogeneous brand value affects whether an invitation succeeds.","presenter":"Dr. Han Zhang","authors":[{"name":"Dr. Han Zhang","aff":"Assistant Professor, Michigan State University"},{"name":"Dr. Ruth Beer","aff":"Associate Professor, Baruch College"},{"name":"Prof. Kyle Cattani","aff":"Professor, Indiana University Bloomington"}],"order":2},{"id":"136-0384","title":"Manufacturing as a Service: Bringing Job Opportunities to the Bottom of the Pyramid","content":"We study a Manufacturing as a Service environment motivated by an initiative that brings mobile manufacturing environments (i.e., Factories on Wheels -FOWs-) to low-income communities (i.e., labor firms) so these communities make/sell products and achieve economic growth. We model the interaction between a social planner, labor firms, and FOWs.","presenter":"Dr. Burcu Tan Erciyes","authors":[{"name":"Dr. Gokce Esenduran","aff":"Associate Professor, Purdue University"},{"name":"Dr. Burcu Tan Erciyes","aff":"Associate Professor, University of New Mexico"},{"name":"Prof. Alok Chaturvedi","aff":"Professor, Purdue University"},{"name":"Dr. Gaurav Nanda","aff":"Assistant Professor, Purdue University"}],"order":3},{"id":"136-1722","title":"Analytics and Operations to Improve Welfare in Distributed Artisanal Supply Chains","content":"Inspite of their significant contribution as a primary source of employment for women in the developing world, artisanal supply chains continue to face issues of low productivity. This research tackles that challenge by identifying innovative operational interventions to improve weavers' productivity.","presenter":"Prof. Somya Singhvi","authors":[{"name":"Mr. Josh Ong","aff":"Student, University of Southern California"},{"name":"Prof. Divya Singhvi","aff":"Assistant Professor, New York University"},{"name":"Prof. Somya Singhvi","aff":"Assistant Professor, University of Southern California"}],"order":4}]},{"id":"s102","title":"Decentralized Digital Economies","track":"Product Innovation and Technology Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"COURTLAND","chairs":["Prof. Rowena Gan","Mr. Leon Leng"],"abstracts":[{"id":"136-0631","title":"The Blockchain Newsvendor: Value of Freshness Transparency and Smart Contracts","content":"Motivated by blockchain applications in food supply chain, we consider a problem where a retailer can have more transparency over freshness by adopting blockchain. Despite substantial value for the retailer, blockchain adoption can hurt its supplier. Then, we design a family of smart contracts and examine their win-win propositions.","presenter":"Mr. Chenghuai Li","authors":[{"name":"Prof. N. Bora Keskin","aff":"Associate Professor, Duke University Durham"},{"name":"Mr. Chenghuai Li","aff":"Student, Duke University"},{"name":"Prof. Jing-Sheng (Jeannette) Song","aff":"Professor, Duke University Durham"}],"order":1},{"id":"136-0917","title":"Nonfungible tokens: how to match supply with demand in the metaverse","content":"NFT marketplaces can control the supply of digital collectibles through token sales, airdrops, and token burns. A study of virtual real estate market reveals that increasing supply via these policies and decreasing production costs impact transaction frequency and market prices, influencing platform revenues, the relationship is  non-linear.","presenter":"Dr. Dmitrii Sumkin","authors":[{"name":"Dr. Dmitrii Sumkin","aff":"Post Doc/Researcher, University of Illinois Urbana-Champaign"},{"name":"Mr. Pavel Kireyev","aff":"Assistant Professor, INSEAD"}],"order":2},{"id":"136-1238","title":"Decentralized Insurance","content":"Decentralized insurance, enabled by blockchain, mitigates bias in claims evaluation by using independent assessors. Assessors vote collectively, and their compensation aligns with the majority decision, promoting impartial judgments over company profit-driven biases. This model offers a transparent alternative to traditional insurance practices.","presenter":"Mr. Leon Leng","authors":[{"name":"Prof. Rowena Gan","aff":"Assistant Professor, Southern Methodist University"},{"name":"Mr. Leon Leng","aff":"Student, Michael G. Foster School of Business"}],"order":3}]},{"id":"s103","title":"Behavioral Topics: exploring self and others from agriculture to sustainability","track":"Behavioral Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"EMBASSY D","chairs":["Dr. NESLIHAN OZLU"],"abstracts":[{"id":"136-0771","title":"Economics of Fertilizer Pollution Mitigation","content":"Reactive nitrogen loss from US Midwest corn and soybean farms, covering 50% of cropland and a third of global production, poses environmental and health risks. Despite proven benefits, adoption of precision fertilizer practices remains low. We investigate fertilizer use practices using stylized economic models and extensive operational data.","presenter":"Dr. Canberk Ucel","authors":[{"name":"Dr. Canberk Ucel","aff":"Assistant Professor, ESSEC Business School"},{"name":"Prof. Enver Yucesan","aff":"Professor, INSEAD"}],"order":1},{"id":"136-1216","title":"Sustainable Supplier Selection Decisions: Choices and Tradeoffs of Practicing Managers","content":"We investigate how experienced practitioners value supplier sustainability. Using a discrete choice experiment, we explore willingness to pay for waste management, carbon efficiency, green product and process design, and organizational support for environmental sustainability. We find strong and non-linear results of managers’ personal environmental preferences on their decisions.","presenter":"Dr. Andrew Collins","authors":[{"name":"Dr. Andrew Collins","aff":"Senior Lecturer, The University of Sydney"},{"name":"Dr. Brent Moritz","aff":"Associate Professor, Penn State University University Park"},{"name":"Prof. Behnam Fahimnia","aff":"Professor, The University of Sydney"},{"name":"Ms. Mehrnoosh Enjelasi","aff":"Student, The University of Sydney"}],"order":2},{"id":"136-0777","title":"Relentless Retribution: Exploring the Impact of Time Delays on Self-Governance Mechanisms","content":"We develop a system dynamics model incorporating time delays, nonlinearities, and uncertainties to study self-governance mechanisms—internal communication and peer punishment—in common-pool resource dilemmas. Using Amazon Mechanical Turk data, findings reveal that communication and peer punishment fail to prevent overinvestment and resource overexploitation, especially with longer delays.","presenter":"Dr. Ali Akhavan","authors":[{"name":"Dr. Ali Akhavan","aff":"Post Doc/Researcher, Massachusetts General Hospital and MIT"},{"name":"Prof. Paulo Goncalves","aff":"Professor, Università della Svizzera italiana"}],"order":3},{"id":"136-1770","title":"Exploring the Relationship between ESG and Fair Cost sharing in Supplier-buyer Relationships","content":"We study a two-stage supply chain where a manufacturer proposes an ESG initiative to enhance sustainability, expecting cost-sharing with a retailer. Our research explores how supply chain visibility, power dynamics, and retailer social preferences influence cost-sharing decisions, offering insights into effective collaboration for sustainable supply chains.","presenter":"Dr. Ping Su","authors":[{"name":"Dr. Ping Su","aff":"Associate Professor, Hofstra University"},{"name":"Dr. Kaushik Sengupta","aff":"Professor, Hofstra University"},{"name":"Dr. Kevin Sun","aff":"Associate Professor, St. Johns University"}],"order":4}]},{"id":"s118","title":"Technology and Operations Management","track":"Empirical Research in Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"EMBASSY B","chairs":["Dr. Eunae Yoo","Prof. Seongkyoon Jeong"],"abstracts":[{"id":"136-0329","title":"Managing Digital Supply Chain Risk with Automation: Evidence from Dependabot","content":"Supply chain risk management is critical for digital products, particularly in addressing security vulnerabilities in software dependencies. We examine how adopting an automated tool, Dependabot, influences the resolution of 1,545,860 vulnerable dependencies. Our findings show that adoption increases resolution speed, but its effectiveness varies by dependency visibility, complexity, and severity.","presenter":"Dr. Eunae Yoo","authors":[{"name":"Prof. Seongkyoon Jeong","aff":"Assistant Professor, University of Tennessee Knoxville"},{"name":"Dr. Eunae Yoo","aff":"Assistant Professor, Indiana University Bloomington"}],"order":1},{"id":"136-0699","title":"Omnichannel ordering in the nanostore retail channel: A field experiment","content":"The ordering process of millions of nanostores is becoming increasingly digitized. Digital technologies offer opportunities for better information acquisition ahead of the ordering deadline (assortment discovery; cash and sales evolution). Moreover, digital technologies enable product ordering capabilities. We investigate shopkeepers' omnichannel ordering behavior through a field experiment in Latin America.","presenter":"Dr. Rafael Escamilla","authors":[{"name":"Mr. Fabio Castro","aff":"Student, Massachusetts Institute of Technology"},{"name":"Dr. Rafael Escamilla","aff":"Assistant Professor, Arizona State University"},{"name":"Dr. Sreedevi Rajagopalan","aff":"Post Doc/Researcher, Massachusetts Institute of Techno"},{"name":"Dr. Josue Velazquez-Martinez","aff":"Professor, Massachusetts Institute of Technology"}],"order":2},{"id":"136-1417","title":"Incentivizing Competition: How Utilization-Based Incentive Program Reshapes Driver Choices and Platform Rivalry","content":"Transportation network companies (TNCs) often classify drivers as contractors, limiting protections and prompting grievances. This study examines a utilization-based insurance policy by a Southeast Asian ride-sourcing platform. Using trip-level data and difference-in-differences analysis, findings reveal shifts in driver behavior, cross-platform spillovers, and implications for policy and competition.","presenter":"Dr. Sukrit Pal","authors":[{"name":"Dr. Sukrit Pal","aff":"Assistant Professor, Iowa State University"},{"name":"Ms. Thu Trang Hoang","aff":"Student, University of Nebraska At Omaha"}],"order":3},{"id":"136-1692","title":"Impact of National Defense Authorization Act on Supply Chains","content":"In this research, we examine the impact of National Defense Authorization act on Global Supply Chains.","presenter":"Dr. Rakesh Mallipeddi","authors":[{"name":"Dr. Rakesh Mallipeddi","aff":"Assistant Professor, The Ohio State University"},{"name":"Dr. M. Serkan Akturk","aff":"Associate Professor, Clemson University"},{"name":"Yao Chen","aff":""},{"name":"Dr. Arvind Mahajan","aff":"Professor, Texas A&amp;M University College Station"}],"order":4}]},{"id":"s138","title":"iFORM","track":"POM-Finance Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"Learning Center","chairs":["Prof. Fasheng Xu"],"abstracts":[{"id":"136-0256","title":"FinTech Lending, Open Banking, and Data Manipulation","content":"We examine the impact of Open Banking on FinTechs' ability to serve underserved populations. Our findings suggest that granting FinTechs access to banking data can influence borrowers’ manipulation of their alternative data, potentially reducing the informativeness of this data and ultimately weakening financial inclusion.","presenter":"Mr. Yangguang Wang","authors":[{"name":"Mr. Yangguang Wang","aff":"Student, Syracuse University"},{"name":"Prof. Fasheng Xu","aff":"Assistant Professor, University of Connecticut"},{"name":"Prof. Zhengping Wu","aff":"Associate Professor, Syracuse University"}],"order":1},{"id":"136-0663","title":"Decoding the Sales Impact of Persuasive Strategies in Livestream Selling","content":"We investigate the persuasive language in livestream e-commerce used by streamers. Analyzing a large TikTok dataset, we identify 7 persuasive strategies using LLMs. Our study reveals that semantic strategies impact sales, particularly in competitive markets. Streamers can enhance effectiveness by adopting less emotional and more concrete language.","presenter":"Prof. Jing Wu","authors":[{"name":"Mr. Jincheng Fang","aff":"Student, University of Chinese Academy of Science"},{"name":"Prof. Jia Liu","aff":"Assistant Professor, HKUST"},{"name":"Prof. Ying Liu","aff":"Professor, University of Chinese Academy of Science"},{"name":"Prof. Jing Wu","aff":"Associate Professor, The Chinese University of Hong Kong"}],"order":2},{"id":"136-0945","title":"Commodity Processing and Downward Substitution under Stochastic Prices","content":"We explore the value of downward substitution under stochastically evolving exogenous commodity\r\nprices using a multi-period stochastic inventory model. We provide a unique set of managerial insights through linking the decision of downward substitution with the evolution of the market prices, as well as the demand uncertainty.","presenter":"Dr. Feray Tunçalp","authors":[{"name":"Dr. Fehmi Tanrisever","aff":"Associate Professor, Faculty of Business Administration"},{"name":"Dr. Zumbul Atan","aff":"Associate Professor, Eindhoven University of Technology"},{"name":"Dr. Feray Tunçalp","aff":"Assistant Professor, Bilkent University"}],"order":3},{"id":"136-2038","title":"Platform Size and Price Effects: An Economic Analysis of Amazon’s Buy box","content":"We study the impact of Amazon's Featured Offer (Buy Box) on market competition and pricing. Using an economic model comparing third-party seller behavior across platforms, we find its effects vary with market size: it can either reduce or inflate prices. While benefiting consumers, it may create challenges for smaller marketplaces.","presenter":"Mr. Nipun Thakurele","authors":[{"name":"Prof. Lauren Lu","aff":"Professor, Dartmouth College"},{"name":"Mr. Nipun Thakurele","aff":"Student, New York University"},{"name":"Prof. Wenqiang Xiao","aff":"Professor, New York University"}],"order":4}]},{"id":"s161","title":"Resource Allocation in Healthcare","track":"Healthcare Analytics","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"GRAND HALL EAST D","chairs":["Prof. Yu Kan"],"abstracts":[{"id":"136-1116","title":"Improving National Kidney Allocation Policy Under Endogenous Patient Choice and Geographical Sharing","content":"We develop a data-driven framework for assessing the impact of changes to the deceased-donor kidney allocation policy that takes into account of the transplant candidates’ (endogenous) organ acceptance behavior and sharing among different locations under United Network of Organ Sharing (UNOS)’ geographically tiered allocation structure.","presenter":"Dr. Yuwei Zhou","authors":[{"name":"Prof. Baris Ata","aff":"Professor, University of Chicago"},{"name":"Dr. John Friedewald","aff":"Associate Professor, Northwestern University"},{"name":"Dr. Yue Hu","aff":"Assistant Professor, Stanford University"},{"name":"Dr. Cem Randa","aff":"Post Doc/Researcher, (CIF:ESG50985993)"},{"name":"Dr. Yuwei Zhou","aff":"Assistant Professor, Indiana University"}],"order":1},{"id":"136-1306","title":"COVID-19 Vaccine Supply: Access and Fairness","content":"Our paper seeks to understand how vaccine supply allocation by state agencies and the systemic structural barriers impacted vaccination coverage for BIPOC and under-represented communities in the United States. Our goal is to identify the relative importance of key factors that shape vaccination behaviors.","presenter":"Prof. Yu Kan","authors":[{"name":"Prof. Yu Kan","aff":"Assistant Professor, Indiana University"},{"name":"Prof. Leela Nageswaran","aff":"Assistant Professor, University of Washington"}],"order":2},{"id":"136-1793","title":"Reddit Flair","content":"In this paper, we investigate ways to help the online healthcare communities, specifically Reddit, better understand the utility of the flair and improve the design of the flair to enhance users benefits (health conditions). Additionally, we demonstrate that users are also learning through their engagement with flairs.","presenter":"Ms. Jun Tan","authors":[{"name":"Prof. Yu Kan","aff":"Assistant Professor, Indiana University"},{"name":"Ms. Jun Tan","aff":"Student, University of Washington"},{"name":"Prof. Lu (Lucy) Yan","aff":"Associate Professor, Indiana University Bloomington"}],"order":3},{"id":"136-1544","title":"Drop in the Ocean: Inventory Management for Large Public Cord Blood Banks","content":"Treating many blood-related diseases require umbilical cord blood (CB) cell transplantation. Public CB banks store the donated CB cells. With 10 million genetic variants in the US, limited inventory, random replenishment and demand, CB bank compositions change non-deterministically over time. We propose several inventory policies for increasing the CB-Bank’s efficiency.","presenter":"Prof. Sundara Natarajan Panchanatham","authors":[{"name":"Prof. Sundara Natarajan Panchanatham","aff":"Assistant Professor, Hong Kong University"},{"name":"Prof. Harry Groenevelt","aff":"Associate Professor, University of Rochester"},{"name":"Prof. Sameer Hasija","aff":"Professor, INSEAD"}],"order":4}]},{"id":"s193","title":"Service Design Framework","track":"Service Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"EMBASSY C","chairs":["Dr. Lu Kong"],"abstracts":[{"id":"136-1178","title":"Emotional Customer Journeys: A Service Design Framework","content":"Many service contexts comprise of customers experiencing emotional highs and lows during their journey such as financial services, healthcare, and non-profit organizations that offer support services to the community. This multi-disciplinary study aims to develop a conceptual framework for designing such emotionally charged service experiences.","presenter":"Prof. Liana Victorino","authors":[{"name":"Prof. Liana Victorino","aff":"Associate Professor, University of Victoria"},{"name":"Prof. Secil Bayraktar","aff":"Associate Professor, Toulouse Business School"},{"name":"Prof. Sara Soares Traquina Alves Elias","aff":"Associate Professor, University of Victoria"},{"name":"Prof. Sudhir Nair","aff":"Associate Professor, University of Victoria"},{"name":"Prof. Yan Shen","aff":"Associate Professor, University of Victoria"}],"order":1},{"id":"136-1215","title":"Flexible Workforce and Endogenous Behavior: Implications for Service System Design","content":"We study modern service systems with a flexible workforce where server reliability is endogenously determined by system parameters. Using a queueing-theoretic framework, we demonstrate how behavioral factors influence service systems and can disrupt economies of scale, impacting optimal capacity planning and system design.","presenter":"Ms. Himani Ananthula","authors":[{"name":"Ms. Himani Ananthula","aff":"Student, Kellogg School of Management"},{"name":"Dr. Milind Sohoni","aff":"Professor, The State University of New York at Buffalo"},{"name":"Prof. Achal Bassamboo","aff":"Professor, Northwestern University"}],"order":3},{"id":"136-1723","title":"The Efficiency in Supplying Accommodation Service Capacity in Urban Area","content":"This study analyzes the spatial distribution of accommodation facilities in a city to examine the efficiency in supplying accommodation service capacity for visitors. After descriptively examining the distribution of accommodation facilities in Osaka City, Japan, we attempt an econometric analysis to explain the emergence of new facility openings.","presenter":"Dr. Hiroki Sano","authors":[{"name":"Dr. Hiroki Sano","aff":"Associate Professor, Ritsumeikan University"},{"name":"Dr. Shuichi Nagata","aff":"Associate Professor, Kwansei Gakuin University"},{"name":"Dr. Kaede Sano","aff":"Associate Professor, Wakayama University"}],"order":4},{"id":"136-1260","title":"Service Analysis of Physician-led Health Clinic","content":"Physician entrepreneurs face several challenges in successful operation of health clinics, as their primary strength is medical practices, not business management. This study conducts an analysis of a physician-led health clinic in light of service strategies such as service vision, innovation, design, process matrix, SWOT analysis and patient value evaluation.","presenter":"Dr. Sanjeev Bordoloi","authors":[{"name":"Dr. Sanjeev Bordoloi","aff":"Associate Professor, University of St. Thomas"}],"order":5}]},{"id":"s224","title":"International Logistics and Trade","track":"Supply Chain Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"GRAND HALL EAST A","chairs":["Prof. Behzad Hezarkhani"],"abstracts":[{"id":"136-0281","title":"Using \"Mirror\" Trade Data for Global Supply Chain Management","content":"Mirror trade data for a commodity is the parallel time series of imports and exports reported by a destination and a source respectively. We exploit mirror trade date from United Nations Commodity Trade Statistics Database (UN Comtrade) to analyze global logistics and supply chains.","presenter":"Prof. Behzad Hezarkhani","authors":[{"name":"Prof. Behzad Hezarkhani","aff":"Associate Professor, University of Southampton"},{"name":"Dr. Guven Demirel","aff":"Reader, Queen Mary University of London"}],"order":1},{"id":"136-0545","title":"Reconstructing supply networks for foresight analysis","content":"We use network reconstruction methods to project existing partially observable supply network and trade data into the future under different scenarios, capturing critical uncertainties. We conduct foresight analysis by characterising the topological properties of the reconstructed networks and stress-testing these statistical ensembles for resilience to different types of shocks.","presenter":"Dr. Guven Demirel","authors":[{"name":"Dr. Guven Demirel","aff":"Reader, Queen Mary University of London"}],"order":2},{"id":"136-2044","title":"Coalition or Free Rider? Evidence from Corporate Lobbying Strategies through Supply Chains","content":"We investigate whether corporate lobbying strategies among supply chain partners exhibit coalition. Using a network analysis approach, we uncover a negative spillover of corporate lobbying strategies from customers to suppliers. This spillover is stronger when customers have more market power and located in central network position. ","presenter":"Dr. Jing Li","authors":[{"name":"Dr. Jing Li","aff":"Post Doc/Researcher, CGFR, PBCSF, Tsinghua U."},{"name":"Dr. Daoju Peng","aff":"Associate Professor, Capital University of Economics and Bus"}],"order":3}]},{"id":"s225","title":"Fairness and Equity in OM","track":"POM-Economics Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"VININGS","chairs":["Prof. Aydin Alptekinoglu","Dr. David Rea"],"abstracts":[{"id":"136-1169","title":"Improving the Equity and Efficiency of Cystic Fibrosis Screening","content":"Screening newborns for cystic fibrosis (CF) starts with an IRT test (CF elevates IRT levels); newborns with IRT levels above a threshold undergo an expensive large-panel genetic test that detects disease-causing mutations (from among the hundreds known). We study adding an inexpensive small-panel test before IRT, to customize IRT thresholds.","presenter":"Dr. Hussein El Hajj","authors":[{"name":"Dr. Hussein El Hajj","aff":"Assistant Professor, Santa Clara University"},{"name":"Dr. Douglas Bish","aff":"Professor, University of Alabama"},{"name":"Dr. Ebru Bish","aff":"Professor, The University of Alabama"}],"order":1},{"id":"136-1447","title":"Equity-Efficiency Symbiosis","content":"While previous research has focused on the potential tradeoff between equality-based fairness and efficiency, this research considers when equity-based fairness works in conjunction with efficiency.","presenter":"Dr. David Rea","authors":[{"name":"Dr. David Rea","aff":"Assistant Professor, Lehigh University"},{"name":"Dr. Violet (Xinying) Chen","aff":"Assistant Professor, Stevens Institute of Technology"}],"order":2},{"id":"136-1825","title":"Achieving Rawlsian Justice in Food Rescue","content":"We explore an idea to achieve more fair outcomes in food rescue platforms that operate on a first-come-first-serve basis: Give a head-start to a subset of recipients in claiming a donation. Our objective is to maximize the benefit gained by the worst-off recipient, a Rawlsian notion of fairness.","presenter":"Prof. Aydin Alptekinoglu","authors":[{"name":"Prof. Aydin Alptekinoglu","aff":"Professor, Penn State University University Park"},{"name":"Dr. Gerdus Benade","aff":"Assistant Professor, Boston University"}],"order":3},{"id":"136-1836","title":"Optimizing the Food Bank Fresh Produce Supply Chain","content":"Food banks face significant challenges in managing the quality and distribution of fresh produce, particularly in balancing donations and/or purchases while minimizing food waste and ensuring equitable access. This paper introduces a nonlinear optimization model that addresses these challenges by integrating quality deterioration, minimum quality standards, equity, and waste.","presenter":"Dr. Deniz Besik","authors":[{"name":"Dr. Deniz Besik","aff":"Assistant Professor, University of Richmond"},{"name":"Prof. Anna Nagurney","aff":"Professor, University of Massachusetts Amherst"},{"name":"Dr. Shital Thekdi","aff":"Assistant Professor, University of Richmond"}],"order":4},{"id":"136-0680","title":"Enhancing Volunteer Retention: The Role of Experienced Volunteers","content":"Nonprofit organizations rely on volunteers to alleviate some of the financial constraints around employing a large paid workforce. Low volunteer retention is costly and disruptive to operations. \r\nUsing data from a food bank, we study how the presence of experienced volunteers increases the retention rate of new volunteers.","presenter":"Mr. Vinit Tipnis","authors":[{"name":"Mr. Vinit Tipnis","aff":"Student, Indiana University Bloomington"},{"name":"Dr. Christopher Chen","aff":"Assistant Professor, Indiana University Bloomington"},{"name":"Dr. Fei Gao","aff":"Associate Professor, Indiana University Bloomington"}],"order":5}]},{"id":"s264","title":"Strategies for Managing Information","track":"POM-Marketing Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"DUNWOODY","chairs":["Prof. Guangwen Kong","Ms. Jingjing Weng"],"abstracts":[{"id":"136-0697","title":"Selling and Renting Mechatronics","content":"This study examines how mechatronic firms should market their products. Employing a Stackelberg game model, we investigate two strategies: selling both high- and low-end products or offering just just the low-end product with an option for consumers to rent the high-end functionality for a fee.","presenter":"Dr. Guang Li","authors":[{"name":"Mr. Xianfeng Meng","aff":"Student, Queen's University"},{"name":"Dr. Guang Li","aff":"Associate Professor, Queen's University"},{"name":"Prof. Anton Ovchinnikov","aff":"Professor, Queens University"}],"order":1},{"id":"136-1217","title":"Online-Offline Salesforce compensation: A Dynamic Double Moral Hazard Model","content":"We consider a principal-agent problem within a continuous-time framework, involving a principal and an agent. There is a joint effort process of the principal and agent, where they may exert effort to raise the arrival rate of customers, aiming to maximize their respective payoffs.","presenter":"Dr. Shuqi Liu","authors":[{"name":"Dr. Shuqi Liu","aff":"Student, China University of Science and Technology"},{"name":"Prof. Xiaobei Shen","aff":"Professor, China University of Science and Technology"},{"name":"Dr. Shouqiang Wang","aff":"Associate Professor, University of Texas Dallas"}],"order":2},{"id":"136-1249","title":"Advice Provision in the Pandemic: The Impact of Information Granularity on Social Protection","content":"This paper investigates the strategies for providing public health advice during a pandemic, focusing on the granularity of information given by a social planner. We compare two main information provision strategies: uniform and targeted information provision. We identify conditions where a uniform scheme is more effective than a targeted one.","presenter":"Ms. Jingjing Weng","authors":[{"name":"Prof. Guangwen Kong","aff":"Associate Professor, Temple University"},{"name":"Ms. Jingjing Weng","aff":"Student, Temple University"},{"name":"Dr. Yang Zhang","aff":"Associate Professor, University of Kent"}],"order":3}]},{"id":"s270","title":"Digital Frontiers: Addressing Inequality, Bias, and AI in Marketing and Consumer Behavior","track":"POM-Marketing Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"HARRIS","chairs":["Ms. Mengxia Zhang"],"abstracts":[{"id":"136-0245","title":"From Food Deserts to Fresh Food: Bridging the Gap with SNAP Online for Low-Income Households","content":"Online grocery delivery often fails to address food insecurity for low-income households due to financial barriers. SNAP Online helps remove these barriers, enabling benefit usage for online purchases. We show SNAP Online increases total and fresh food consumption, especially in food deserts, while access and habits moderate its effectiveness.","presenter":"Dr. Cheng He","authors":[{"name":"Dr. Cheng He","aff":"Assistant Professor, University of Wisconsin Madison"},{"name":"Mr. Allen Li","aff":"Associate Professor, University of Wisconsin Madison"}],"order":1},{"id":"136-0290","title":"Does Polarizing Content Pay Off?","content":"This study examines how politically polarizing content affects subscription and advertising revenue for a European news website. Using NLP-based polarization measures and user interaction data, we find polarized content boosts page views but reduces subscriptions, particularly among ideologically aligned users, challenging assumptions about confirmation bias in digital media consumption.","presenter":"Ms. Shunyao Yan","authors":[{"name":"Ms. Shunyao Yan","aff":"Assistant Professor, Santa Clara University"},{"name":"Prof. Klaus Miller","aff":"Assistant Professor, Hec Paris"}],"order":2},{"id":"136-0703","title":"Beyond the Hype: Unveiling the Marginal Benefits of 3D Virtual Tours in Real Estate","content":"Using data from 75,178 Los Angeles home sales (2019–2021), we find virtual tours (VTs) boost views and favorites but increase cross-outs and minimally impact tours, sale prices, or time on the market, highlighting limited benefits compared to other marketing efforts.","presenter":"Ms. Mengxia Zhang","authors":[{"name":"Ms. Mengxia Zhang","aff":"Assistant Professor, University of Western Ontario"},{"name":"Ms. Isamar Troncoso","aff":"Assistant Professor, Harvard Business School"}],"order":3}]},{"id":"s278","title":"Emerging Topics in Coordinated Operations","track":"Aviation, Transportation, and Logistics Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"UNIVERSITY","chairs":["Ms. Mengting Chao"],"abstracts":[{"id":"136-0561","title":"The bicycle problem: an MIP formulation and worst-case analysis","content":"The bicycle problem minimizes the arrival time of the last person in a team traveling a fixed distance from an origin to a destination using a single one-seat bicycle. We study a more realistic variant where each person can use the bicycle at most once by MIP.","presenter":"Mr. Jiaqi Wang","authors":[{"name":"Mr. Jiaqi Wang","aff":"Student, University of Maryland, College Park"},{"name":"Prof. Bruce Golden","aff":"Professor, University of Maryland"},{"name":"Mr. Adriano Masone","aff":"Student, University of Naples Federico II"}],"order":1},{"id":"136-1197","title":"The Driver-Aide Problem in Urban Areas","content":"Many logistics companies have resorted to using a “driver-aide” to assist with deliveries. Our goal is to optimize the coordination between a driver (with a truck) and an aide to minimize the total delivery time for last-mile deliveries in urban areas.","presenter":"Ms. Mengting Chao","authors":[{"name":"Ms. Mengting Chao","aff":"Student, University of Maryland - College Park"},{"name":"Prof. Bruce Golden","aff":"Professor, University of Maryland"},{"name":"Mr. Adriano Masone","aff":"Student, University of Naples Federico II"},{"name":"Prof. Rui Zhang","aff":"Associate Professor, University of Colorado Boulder"}],"order":2},{"id":"136-0656","title":"Meals on Autonomous Wheels: Delivery with Vehicle-Customer Coordination","content":"Considering meals delivered by autonomous vehicles, we study a new vehicle-customer coordination delivery problem. In this problem, customers and vehicles are regarding pickup locations to improve delivery efficiency. A case study based on UberEats indicates that vehicle-customer coordination results in more completed orders and higher revenue for the delivery platform.","presenter":"Mr. Decheng Li","authors":[{"name":"Mr. Decheng Li","aff":"Student, Wuhan University"},{"name":"Prof. kai Wang","aff":"Professor, Wuhan University"},{"name":"Prof. Rui Zhang","aff":"Associate Professor, University of Colorado Boulder"}],"order":3},{"id":"136-0558","title":"Last Mile Delivery Robots along with a Man and Van: A Metaheuristic Solution","content":"We address a last-mile delivery system with a truck and two delivery robots under partial charging and alternating usage constraints. Our model optimizes delivery efficiency by incorporating battery dynamics, non-concurrent operation, and flexible charging schedules. Using a metaheuristic approach, the solution minimizes costs while adhering to operational constraints.","presenter":"Dr. Anurag Tewari","authors":[{"name":"Dr. Anurag Tewari","aff":"Assistant Professor, University of Washington Bothell"},{"name":"Mr. Ritik Dubey","aff":"Senior software engineer, Larsen and toubro infotech mindtreee"}],"order":4}]},{"id":"s291","title":"General Information Systems","track":"Information Systems and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"SPRING","chairs":["Ms. Saeede eftekhari"],"abstracts":[{"id":"136-1195","title":"Bossware: An Agency Theoretic Perspective","content":"Who should determine monitoring levels in an organization using artificial intelligence -powered employee monitoring systems? We consider this question amid companies' growing usage of AI-powered 'bossware' technologies. AI-powered bossware technologies, popular with various employers, collect and process workers' efforts, compromising workplace privacy and mental health.","presenter":"Prof. Abhishek Ray","authors":[{"name":"Prof. Abhishek Ray","aff":"Assistant Professor, George Mason University"},{"name":"Prof. Aaron Baird","aff":""}],"order":1},{"id":"136-1450","title":"How Addressing Community Feedback Affects the Popularity and Code Reuse of Open-Source Software Projects","content":"Addressing community feedback is crucial for open-source software success. Analyzing GitHub data, we find addressing feedback boosts popularity and code reuse, especially in new, end-user-focused projects with less code contribution. Timely responses, particularly to bug reports and feature requests, significantly enhance project outcomes.","presenter":"Dr. Seokjun Youn","authors":[{"name":"Dr. Zisu Wang","aff":"Assistant Professor, University of Illinois at Chicago"},{"name":"Prof. Yong Ge","aff":"Associate Professor, University of Arizona"},{"name":"Dr. Seokjun Youn","aff":"Assistant Professor, University of Arizona"}],"order":2},{"id":"136-1480","title":"Merchants of Vulnerabilities: How Bug Bounty Programs Benefit Software Vendors","content":"This study examines how bug bounty programs (BBPs) counterintuitively encourage earlier software releases despite increased vulnerability risks. Our game-theoretic model shows BBPs transform uncontrolled vulnerability discovery into a managed process, enabling vendors to coordinate disclosure and patch deployment while balancing interactions between vendors and hackers.","presenter":"Dr. Muhammad Zia Hydari","authors":[{"name":"Dr. Muhammad Zia Hydari","aff":"Assistant Professor, University of Pittsburgh"},{"name":"Prof. Esther Gal-Or","aff":"Professor, University of Pittsburgh"},{"name":"Dr. Rahul Telang","aff":", Carnegie Mellon University"}],"order":3},{"id":"136-2064","title":"Prosocial Fundraising for Sociopolitical Crisis Response Evidence from the Arab Spring","content":"We examine how microlending responds to sociopolitical crises, introducing lender value alignment—the idea that lending increases when lenders’ cultural values align with a crisis’s ideology. Using Kiva data from the Arab Spring, we find that loans supporting crisis-related values attract more funding, offering insights for digital platforms and crisis fundraising.","presenter":"Dr. Amin Sabzehzar","authors":[{"name":"Dr. Amin Sabzehzar","aff":"Assistant Professor, Tulane University"},{"name":"Prof. Gordon Burtch","aff":"Associate Professor, Boston University"},{"name":"Dr. Yili Hong","aff":"Professor, University of Miami"},{"name":"Dr. Raghu Santanam","aff":"Professor, Arizona State University Tempe"}],"order":4},{"id":"136-1687","title":"Message framing and the mobilization of online social movement","content":"This study examines whether Collective Action Framing Theory explains participant mobilization in entirely online social movements. While the theory captures the framing decisions of social movement organizations, its role as the primary mobilizer is limited. Instead, the connectedness of online communities drives action, challenging traditional theories and revealing new implications.","presenter":"Ms. Saeede eftekhari","authors":[{"name":"Prof. Sudip Bhattacharjee","aff":"Professor, University of Connecticut"},{"name":"Dr. Ugochukwu Etudo","aff":"Assistant Professor, Virginia Commonwealth University"},{"name":"Ms. Saeede eftekhari","aff":"Assistant Professor, Tulane University"}],"order":5}]},{"id":"s292","title":"Finding the Right Balance: Efficiency, Fairness, and Impact in Social Systems","track":"Operations and Society","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"LENOX","chairs":["Prof. Wiljeana Glover","Dr. LaDonna Thornton","Dr. LaDonna Thornton"],"abstracts":[{"id":"136-1299","title":"Improving a housing share program through stakeholder engagement and decision modeling","content":"A nonprofit organization provides affordable housing by matching those with space available in their units with others seeking shelter. Using principles of community-engaged operations research, we evaluate the efficiency and efficacy of the current program, and propose decision modeling approaches to expand the program’s size and impact.","presenter":"Prof. Michael Johnson","authors":[{"name":"Prof. Michael Johnson","aff":"Professor, University of Massachusetts Boston"},{"name":"Mr. Mubarak Iddrisu","aff":"Student, University of Massachusetts Boston"},{"name":"Ms. Karla CorresLuna","aff":"Student, University of Massachusetts Boston"}],"order":1},{"id":"136-1576","title":"Physician Compensation &amp; Productivity: Navigating the Universal Healthcare System with Regional Authorities","content":"The Canadian universal healthcare system aims to ensure equitable access to care. Still, demand-supply mismatch creates tensions between cost-focused regional governments seeking improved productivity and welfare-driven frontline healthcare workers seeking enhanced job satisfaction. This study explores a balanced compromise to promote equity across stakeholders.","presenter":"Dr. Enayon Taiwo","authors":[{"name":"Dr. Enayon Taiwo","aff":"Assistant Professor, The University of Winnipeg"}],"order":2},{"id":"136-1733","title":"Enhancing Fairness in Emergency Food Assistance: A Data-Driven Framework for Equitable Resource Distribution","content":"This study proposes a framework to assess the fairness of emergency food assistance programs in addressing food insecurity in the U.S. Using stakeholder engagement, spatial analysis, and optimization, it ensures equitable resource distribution, focusing on vulnerable populations and transportation access while fostering collaboration between researchers and practitioners for community-focused solutions.","presenter":"Dr. Sadan Kulturel-Konak","authors":[{"name":"Dr. Abdullah Konak","aff":"Professor, Penn State Berks"},{"name":"Dr. Sadan Kulturel-Konak","aff":"Professor, Penn State Berks"}],"order":3},{"id":"136-1538","title":"Compassionate Practices for Innovation Under Pressure","content":"In times of crisis, organizations face a dilemma: How should they balance between surviving operationally and acting for the benefit of all stakeholders and of society at large? Using a mixed methods approach, we examine how compassion practices coupled with responses to operational and regulatory pressures advance innovation performance.","presenter":"Prof. Wiljeana Glover","authors":[{"name":"Prof. Wiljeana Glover","aff":"Associate Professor, Babson College"},{"name":"Dr. Zhike Lei","aff":"Professor, IMD"},{"name":"Prof. Eitan Naveh","aff":"Professor, Technion Israel Institute of Technology"}],"order":4}]},{"id":"s316","title":"Channel Strategies and Capacity Rationing","track":"Revenue Management and Pricing","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"MARIETTA","chairs":["Ms. Ke Sun"],"abstracts":[{"id":"136-2015","title":"Evaluating Capacity Rationing Strategies under Mixed Demand Conditions","content":"This study evaluates current dynamic allocation heuristics of scarce capacity in make-to-order environments, comparing them to the first-come-first-served policy. It explores diverse demand patterns across segments, assesses statistical performance, and examines heuristics’ desirability against optimal solution with full knowledge, providing broader insight into its practical effectiveness.","presenter":"Dr. Mehmet Barut","authors":[{"name":"Dr. Mehmet Barut","aff":"Professor, Wichita State University"}],"order":1},{"id":"136-1067","title":"Self-Service or Staffed Checkout? Service Channel Strategies in Supermarkets","content":"This paper investigates the impact of self-service technology on queueing systems with heterogeneous demand. A game-theoretic model shows that consumers with low or high demand use self-service or sales-agent service, respectively. We find optimal pricing depends on machine inconvenience, and larger demand volumes do not always increase profits.","presenter":"Ms. Ke Sun","authors":[{"name":"Ms. Ke Sun","aff":"Post Doc/Researcher, McGill University"},{"name":"Dr. Zhongbin Wang","aff":"Associate Professor, Tianjin University"},{"name":"Dr. Yunan Liu","aff":"Associate Professor, North Carolina State University"},{"name":"Dr. Jingchen Liu","aff":"Assistant Professor, Renmin University of China"}],"order":2},{"id":"136-1076","title":"Revenue Management with Predictions","content":"Online decision-makers often obtain predictions on future variables. These range from simple time-series models to state-of-the-art machine learning techniques. However, the prediction accuracy is unknown a priori, hence blindly following the predictions can be harmful. We address this problem by developing algorithms that is robust to the unknown prediction accuracy.","presenter":"Mr. Lin An","authors":[{"name":"Mr. Lin An","aff":"Student, Carnegie Mellon University"},{"name":"Prof. Andrew Li","aff":"Assistant Professor, Carnegie Mellon University"},{"name":"Prof. Ben Moseley","aff":"Associate Professor, Carnegie Mellon University"},{"name":"Mr. Gabriel Visotsky","aff":"Student, Carnegie Mellon University"}],"order":3}]},{"id":"s320","title":"Advanced Topics in Supply Chain","track":"Supply Chain Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"EMBASSY A","chairs":["Dr. Jiashuo Jiang","Prof. Linwei Xin"],"abstracts":[{"id":"136-0797","title":"Landscape of Finite-Horizon MDPs with General States and Actions","content":"We develop a framework ensuring the Kurdyka-Łojasiewicz condition for policy optimization in finite-horizon MDPs, enabling global convergence of policy gradient methods despite nonconvexity. Our results find applications in various operations models and establishe the first sample complexity bounds for multi-period inventory systems with Markov-modulated demands and cash balance problem.","presenter":"Mr. Minda Zhao","authors":[{"name":"Dr. Xin Chen","aff":"Professor, Georgia Institute of Technology"},{"name":"Mr. Yifan Hu","aff":"Post Doc/Researcher, EPFL"},{"name":"Mr. Minda Zhao","aff":"Student, Georgia Institute of Technology"}],"order":1},{"id":"136-0932","title":"The Multi-Secretary Problem with Replenishment","content":"This paper explores whether inventory replenishment policies or real-time fulfillment algorithms have a greater impact. This question naturally arises in e-commerce, where e-retailers must simultaneously determine both inventory replenishment policies and real-time fulfillment algorithms. We provide managerial insights into situations where inventory replenishment policies are more influential, and vice versa.","presenter":"Ms. Zi Ling","authors":[{"name":"Ms. Zi Ling","aff":"Student, Booth School of Business"},{"name":"Dr. Jiashuo Jiang","aff":"Assistant Professor, The University of Science and Technology of Hong Kong"},{"name":"Prof. Linwei Xin","aff":"Associate Professor, University of Chicago"}],"order":2},{"id":"136-1248","title":"Losing Sales to Gain: Mitigating Demand Spillover in Inventory Networks","content":"We explore demand spillover under fulfillment flexibility in online retail, challenging the square-root law's benefits of inventory pooling (Eppen, 1979) and the effectiveness of long-chain designs (Jordan and Graves, 1995). Our findings reveal a new phenomenon: a small increase in lost-sales can significantly reduce spillover.","presenter":"Ms. Jingyuan Yang","authors":[{"name":"Ms. Jingyuan Yang","aff":"Student, Booth School of Business"},{"name":"Prof. Linwei Xin","aff":"Associate Professor, Booth School of Business"},{"name":"Dr. Yuan Zhong","aff":"Associate Professor, Booth School of Business"}],"order":3}]},{"id":"s323","title":"Efficiency and Performance in Operations and Supply Chains","track":"Operational Excellence","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"BAKER","chairs":["Prof. Adel Hatamimarbini"],"abstracts":[{"id":"136-1520","title":"Measuring the Performance of Digital Technologies on Sustainability in UK Food and Beverage Supply Chain","content":"This research examines digital technologies in Industry 4.0 within the UK's food and beverage sector supply chains, focusing on sustainability impacts. Using Organizational Information Processing and Dynamic Capability theories, it employs input-output analysis and Network Data Envelopment Analysis to measure efficiency and enhance sustainability practices.","presenter":"Mr. Emmanuel Odumosu","authors":[{"name":"Mr. Emmanuel Odumosu","aff":"Student, De Montfort University"},{"name":"Prof. Adel Hatamimarbini","aff":"Professor, University of Huddersfield"},{"name":"Dr. Ayham Jaaron","aff":"Associate Professor, De Montfort University"}],"order":1},{"id":"136-1594","title":"The Petroleum Supply Chain Risk Management Framework: An Application of DEA","content":"The petroleum industry operates under a complex supply chain with numerous risk factors. This paper develops a framework to aid researchers and decision-makers in exploring innovative risk management strategies that complement the potential risk factors in the petroleum supply chain using Data Envelopment Analysis (DEA)","presenter":"Prof. Adel Hatamimarbini","authors":[{"name":"Dr. John Asu","aff":"Lecturer, De Montfort University"},{"name":"Prof. Adel Hatamimarbini","aff":"Professor, University of Huddersfield"}],"order":2},{"id":"136-1025","title":"The Role of Supplier Sustainability in improving Airline Efficiency and Financial Performance","content":"This study analyzes the impact of supplier sustainability on U.S. airlines' performance. Using ESG scores from 36 suppliers, findings show that higher environmental scores significantly reduce inefficiency, while Tobin's Q confirms financial benefits. The results emphasize the value of sustainable supply chains in improving both operational efficiency and market valuation.","presenter":"Dr. Sepideh Kaffash","authors":[{"name":"Dr. Sepideh Kaffash","aff":"Assistant Professor, The Business School"},{"name":"Dr. Fahimeh Chomachaei","aff":"Assistant Professor, University of Massachusetts Boston"}],"order":3},{"id":"136-1902","title":"Socially sustainable strategies in municipal waste collection: a worker-centred approach to job planning","content":"The management of waste collection should ensure respect for the environment and take into account current issues such as labour shortages and diversity. Thus, we develop a job planning strategy in order to obtain an age-sensitive sustainable workload distribution to achieve efficiency and social sustainability at once.","presenter":"Dr. Serena Finco","authors":[{"name":"Dr. Serena Finco","aff":"Assistant Professor, Padova University"},{"name":"Prof. Daria Battini","aff":"Professor, Padova University"},{"name":"Dr. Ajay Das","aff":"Professor, Baruch College"},{"name":"Prof. Patrick Neumann","aff":"Professor, Toronto Metropolitan University"}],"order":4},{"id":"136-0723","title":"Robust Performance Analysis of Time-Dependent Supply Chains using Dynamic Network Data Envelopment Analysis","content":"Supply chains operate as decentralised systems with both common goals and interests across multiple tiers. This paper presents a model for assessing supply chain performance, considering intertemporal dynamics, competitive-cooperative aspects, and uncertainty. Using robust optimisation, the model addresses data uncertainties, with applications demonstrated in the pulp and packaging industry.","presenter":"Prof. Adel Hatamimarbini","authors":[{"name":"Prof. Adel Hatamimarbini","aff":"Professor, University of Huddersfield"},{"name":"Dr. Aliasghar Arabmaldar","aff":"Lecturer, University of Hertfordshire"},{"name":"Dr. Pegah Khoshnevis","aff":"Lecturer, University of Sheffield"}],"order":5}]},{"id":"s345","title":"Leveraging Health Informatics in Healthcare Delivery","track":"Healthcare Analytics","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"INMAN","chairs":["Dr. Brandon Lee"],"abstracts":[{"id":"136-0249","title":"A Visual-Based Consumer Health Informatics Decision Support Methodology for Informed Patient Treatment Decisions","content":"A methodology is presented to support shared (clinicians and patients) decision making concerning medical treatments. Interactive visualizations represent the probabilities and impacts of benefits and risks (e.g. side effects). Individualized indifference curves are generated based on patients' choices when presented with these visualizations in an iterative manner.\r\n","presenter":"Ms. Fangzhou Xie","authors":[{"name":"Prof. John Maleyeff","aff":"Associate Professor, Boston University"},{"name":"Ms. Fangzhou Xie","aff":"Student, Boston University"},{"name":"Ms. Yangyuechen Zhao","aff":"Student, Boston University"}],"order":1},{"id":"136-0271","title":"Enhancing Precision Medicine by Identifying Patient Comorbidity Heterogeneity through a Novel Probabilistic Model","content":"We introduce a nonparametric Bayesian model for COPD, identifying patient subgroups based on binary comorbidities and characteristics like age and smoking history. The model estimates subgroup-specific associations, adapts subgroup numbers during inference, and uses scalable Bayesian variational inference for efficiency. Validated with simulated and real data, it supports precision medicine.","presenter":"Prof. Tingting Zhao","authors":[{"name":"Prof. Tingting Zhao","aff":"Assistant Professor, University of Rhode Island"},{"name":"Prof. Jennifer Dy","aff":"Professor, Northeastern University"},{"name":"Prof. James Ross","aff":"Assistant Professor, Harvard University"}],"order":2},{"id":"136-1694","title":"Data-Driven Care Decisions: Modeling Discharge Probabilities with AM-PAC Mobility Scores","content":"This study employs logistic regression to predict discharge destinations using AM-PAC mobility scores, focusing on age-related probabilities of home discharge by initial mobility scores. The model provides physical therapists and physicians with probabilistic insights, supporting informed, confident decisions about care transitions and optimizing resource allocation in healthcare settings.","presenter":"Prof. Rajesh Srivastava","authors":[{"name":"Prof. Rajesh Srivastava","aff":"Professor, Florida Gulf Coast University"},{"name":"Prof. Elias Kirche","aff":"Associate Professor, Florida Gulf Coast University"},{"name":"Dr. Yong-Taek Min","aff":"Assistant Professor, Florida Gulf Coast University"}],"order":4},{"id":"136-1159","title":"A Data-Driven, Interpretable, Risk-Aware Framework for Clinical Decision-Making under Limited Resources","content":"We propose a framework that involves learning an interpretable, concise Markov Decision Process (MDP) model from observed data, finding optimal treatment policies for this MDP using context-specific risk-aware algorithms, and finally assigning treatments under limited resources. We illustrate the utility of the framework on a real sepsis treatment dataset.","presenter":"Ms. Angela Lin","authors":[{"name":"Dr. Lien Le","aff":"VP of Hospital Medicine, Associate Chief Medical Officer, Tampa General Hospital"},{"name":"Ms. Angela Lin","aff":"Student, Massachusetts Institute of Technology"},{"name":"Prof. Dessislava Pachamanova","aff":"Professor, Babson College"},{"name":"Prof. Georgia Perakis","aff":"Professor, Massachusetts Institute of Technology"},{"name":"Mr. Omar Skali Lami","aff":"Student, Massachusetts Institute of Technology"}],"order":5},{"id":"136-2035","title":"The Role of Family Engagement in Influencing Patient Satisfaction and Readmission","content":"Family engagement (FE) is an ongoing partnership between health professionals and patients’ families to enhance healthcare quality, safety, and delivery. This study looks at the impact of family engagement on care delivery outcomes for inpatient settings. ","presenter":"Dr. Luv Sharma","authors":[{"name":"Dr. Joonhyuk Bok","aff":"Assistant Professor, Dongbei University of Finance and Economics"},{"name":"Dr. Luv Sharma","aff":"Associate Professor, University of South Carolina"},{"name":"Prof. Christopher McDermott","aff":"Professor, Rensselaer Polytechnic Institute"}],"order":6}]},{"id":"s348","title":"Industry Policy, Energy, and Sustainability","track":"Industry Studies and Public Policy","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"KENNESAW","chairs":["Prof. Manmohan Sodhi"],"abstracts":[{"id":"136-1997","title":"The impact of non-local vehicle restriction policy on new vehicle registrations and air pollution","content":"To close the loophole of vehicle ownership restriction (VOR) policy, Beijing introduced a non-local vehicle restriction (NLVR) policy with an announcement period prior to the official enforcement of NLVR. This paper quantifies the effectiveness of NLVR in patching VOR and explores citizens’ adaptive behavioral response during the announcement period.","presenter":"Dr. Yifan Fu","authors":[{"name":"Dr. Yifan Fu","aff":"Student, Tianjin university COME"},{"name":"Mr. Zhong shiquan","aff":"Professor, Tianjin university COME"},{"name":"Prof. Shuai Ling","aff":"Professor, Tianjin Uinversity"},{"name":"Prof. Zhengbing He","aff":"Professor, Massachusetts Institute of Technology"}],"order":1},{"id":"136-0766","title":"From Policy to Power Savings: Role of Smart Technology Installations in Reducing Household Electricity Bills","content":"This study investigates the factors influencing smart thermostat adoption, with a specific focus on the different policy measures that encourage such adoption. Moreover, it explores how these policies potentially narrow the adoption gap between urban and rural regions.","presenter":"Ms. Chunjie Zhao","authors":[{"name":"Ms. Chunjie Zhao","aff":"Student, Clark University"}],"order":2},{"id":"136-2070","title":"Labor Market Power in Food Retailing","content":"Understanding labor market power, or wage-productivity gaps, is crucial for sustainable supply chains. I estimate these gaps for workers in U.S. food retailing. I find the gaps are significant in concentrated markets but fall over time, 2004-2019. These findings inform antitrust policies and strategies to optimize workforce management in retailing.","presenter":"Mr. Ujjwol Paudel","authors":[{"name":"Mr. Ujjwol Paudel","aff":"Student, Arizona State University"}],"order":3},{"id":"136-1381","title":"How might sustainability emerge in low-earth orbit satellite operations","content":"The rapidly growing use of satellites, mostly in near-earth orbit, threaten sustainability in space and on earth. We report findings from interviews with respondents and publicly available documents from different companies focused on various stages in the satellite lifecycle: design, build, launch, operate, and serve.","presenter":"Prof. Manmohan Sodhi","authors":[{"name":"Prof. Manmohan Sodhi","aff":"Professor, Bayes Business School"},{"name":"Dr. Atanu Chaudhuri","aff":"Professor, Durham University Business School"},{"name":"Dr. Ujjal Mukherjee","aff":"Associate Professor, University of Illinois Urbana-Champaign"}],"order":4}]},{"id":"s373","title":"Fulfillment and Distribution","track":"Retail Operations","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"FAIRLIE","chairs":["Mr. Thomas Kretschmar"],"abstracts":[{"id":"136-0833","title":"A branch-price-and-cut algorithm for instant order fulfillment problem with cooperative riders and drones","content":"We propose a branch-price-and-cut algorithm to address an emerging instant order fulfillment problem in the O2O environment. In this context, an online retail platform (e.g., Meituan) employs cooperative riders and drones to deliver orders to consumers within the promised delivery time, typically ranging from 15 to 30 minutes.","presenter":"Mr. Ruiguang Yang","authors":[{"name":"Mr. Ruiguang Yang","aff":"Student, Tongji University"},{"name":"Prof. Xiangyong Li","aff":"Professor, Tongji University"}],"order":1},{"id":"136-1355","title":"Forecasting for Order Fulfillment Planning","content":"Forecast accuracy is crucial for order fulfillment planning. Limited information sharing between a retailer and its vertically integrated supplier exacerbates the problem. We analyze the impact on forecast accuracy of leading indicators (e.g. weather) combined with different levels of aggregation (hierarchical, temporal) using data from an FMCG manufacturer.","presenter":"Mr. Thomas Kretschmar","authors":[{"name":"Mr. Thomas Kretschmar","aff":"Student, WHU - Otto Beisheim School of Management"},{"name":"Prof. Arnd Huchzermeier","aff":"Professor, WHU - Otto Beisheim School of Management"}],"order":2},{"id":"136-0340","title":"Last-mile retail logistics distribution. A case study in three Latin American cities","content":"This research analyses retail last-mile distribution in three Latin American cities. It uses a mixed-methodology approach and identifies distribution patterns based on product types. Finally, the research proposes a freight trip public policy for decision-makers.","presenter":"Ms. Agatha Da Silva Ovando","authors":[{"name":"Mr. Juan Sebastian Garcia Pajoy","aff":"Student, Universidad Icesi"},{"name":"Mrs. Sofia Villavisencio","aff":"Student, Universidad del Pacifico"},{"name":"Mrs. Fernanda Serrano","aff":"Student, Universidad del Pacifico"},{"name":"Ms. Agatha Da Silva Ovando","aff":"Student, Universidad Privada Boliviana"},{"name":"Dr. Mario Chong","aff":"Professor, Universidad del Pacifico"}],"order":3},{"id":"136-1510","title":"Hybrid Fulfilment Strategies for Buy Online Pickup in-store (BOPS) Orders Considering Returns in Omnichannel Retailing","content":"Inventory management at physical stores catering to BOPS and offline orders becomes increasingly complex with the consideration of uncertain returns and demands across multiple channels. This study optimizes integrated inventory decisions by leveraging hybrid fulfillment strategies for BOPS orders, employing Markov Decision Process to address demand and returns uncertainties effectively.","presenter":"Mr. Anukesh Valase","authors":[{"name":"Mr. Anukesh Valase","aff":"Student, Indian Institute of Technology Madras"},{"name":"Prof. Arshinder Kaur","aff":"Professor, Indian Institute of Technology Madras"},{"name":"Prof. Alexander Hübner","aff":"Professor, Technical University of Munich"}],"order":4}]},{"id":"s387","title":"Advances in Electricity Markets","track":"Energy and Natural Resource Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"TECHWOOD","chairs":["Prof. Cheng Guo"],"abstracts":[{"id":"136-1284","title":"Modeling, equilibrium and market power for electricity capacity markets","content":"The capacity market is a marketplace for electricity generation capacity, and its efficiency is a subject of ongoing debate. Based on real-life practices, we model and analyze the capacity market. We find that it incentivizes investment of certain generators, and facilitates reliability by preventing physical withholding at higher demand levels.\r\n","presenter":"Prof. Cheng Guo","authors":[{"name":"Prof. Cheng Guo","aff":"Assistant Professor, Clemson University"},{"name":"Prof. Christian Kroer","aff":"Assistant Professor, Columbia University"},{"name":"Prof. Yury Dvorkin","aff":"Associate Professor, Johns Hopkins University"},{"name":"Prof. Daniel Bienstock","aff":"Professor, Columbia University"}],"order":1},{"id":"136-1291","title":"Bitcoin Mining, Energy Prices, and Sustainability: Exploring the role of Clean Energy and Green Bonds","content":"This study employs the CAViaR-TVP-VAR model to examine the interconnectedness and tail risk spillovers between Bitcoin, energy prices, and sustainability indices during the COVID-19 pandemic and Russia-Ukraine war. Findings reveal that Bitcoin and energy prices act as transmitters, while sustainability indices function as receivers of risk, especially during crises.","presenter":"Mr. Sagheer Muhammad","authors":[{"name":"Mr. Sagheer Muhammad","aff":"Student, University of Science and Technology Beijing"},{"name":"Prof. Xiaoxia Huang","aff":"Professor, University of Science and Technology, Beijing China"}],"order":2},{"id":"136-0410","title":"A Dynamic Strategic Plan for Transition to a Clean Campus using Multistage Stochastic Programming","content":"We propose a multistage stochastic program to optimize strategic plans for clean campus transition, considering the uncertainty scenarios in cost and efficiency. Our optimization model minimizes the total expected cost subject to emission targets and budget restrictions. As a case study, we focus on the Middle Eastern Technical University campus.","presenter":"Dr. Burak Kocuk","authors":[{"name":"Mr. Ahmet Emir Sener","aff":"Student, Bogazici University"},{"name":"Dr. Burak Kocuk","aff":"Associate Professor, Sabanci University Tuzla Vd 7360078450"},{"name":"Dr. Tugce Yuksel","aff":"Assistant Professor, Sabanci University"}],"order":3},{"id":"136-1271","title":"Risk-Aware Security-Constrained Unit Commitment: Taming the Curse of Real-Time Volatility and Consumer Exposure","content":"We propose an enhancement to wholesale electricity markets to contain consumers’ exposure to volatile real-time net loads, i.e., loads minus renewable outputs. Our model features data-driven uncertainty sets based on principal component analysis. We develop a decomposition algorithm that handles nonconvex subproblems and conduct extensive experiments on NYISO datasets.","presenter":"Prof. Cheng Guo","authors":[{"name":"Prof. Daniel Bienstock","aff":"Professor, Columbia University"},{"name":"Prof. Yury Dvorkin","aff":"Associate Professor, Johns Hopkins University"},{"name":"Prof. Cheng Guo","aff":"Assistant Professor, Clemson University"},{"name":"Prof. Robert Mieth","aff":"Assistant Professor, Rutgers University"},{"name":"Ms. Jiayi Wang","aff":"Student, Stanford University"}],"order":4}]},{"id":"s416","title":"Optimization and Decision-Making in Healthcare Operations","track":"Healthcare Operations Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"EMBASSY H","chairs":["Dr. Noura El Hassan"],"abstracts":[{"id":"136-1897","title":"An Analysis of the Sterile Processing Department Using Buffer Theory","content":"The Sterile Processing Department of a hospital is integral to providing safe, efficient surgical procedures in a hospital. This paper uses buffer theory (Hopp and Spearman, 2004) to analyze the decontamination, sterilization and delivery of reusable instrument trays from one SPD to the operating rooms of a hospital.","presenter":"Dr. Lawrence Fredendall","authors":[{"name":"Dr. Lawrence Fredendall","aff":"Professor, Clemson University"},{"name":"Mr. Sayed Islam","aff":"Student, Clemson University"},{"name":"Dr. Kevin Taaffe","aff":"Associate Professor, Clemson University"},{"name":"Dr. Ken Catchpole","aff":"Professor, Medical University of South Carolina"},{"name":"Dr. Michael Rayo","aff":"Professor, Ohio State University"}],"order":1},{"id":"136-1802","title":"Trade-off analysis in multi-objective home health care optimization","content":"This study evaluates home healthcare efficiency from the perspectives of patients, caregivers, and managers, and compares service designs by integrating or isolating their expectations. Different approaches, including ε-constraint metaheuristics, heuristics, and a MILP model, analyze the trade-offs of these actors through various experiments based on literature benchmarks.","presenter":"Mr. Andrés Torres Ramos","authors":[{"name":"Mr. Andrés Torres Ramos","aff":"Student, Universidad De Los Andes"},{"name":"Dr. Fabián Castaño","aff":"Applied Intelligence Specialist, Mercado Libre"},{"name":"Prof. Nubia Velasco","aff":"Emeritus Professor, Universidad De Los Andes"}],"order":2},{"id":"136-0727","title":"Laparoscope And Robot-Assisted Surgeries: Experience, Technology Choice And Performance","content":"The study explores the effects of surgeons' experience on surgical method choice and duration. The findings are: (i) surgeon own and peers experience affect the method choice, (ii) laparoscopic duration decreases (increases) with robot method (different procedure) experience. (iii) Robot duration increases (decreases) with laparoscopic method (different procedure) experience.","presenter":"Dr. Pradeep K. Pendem","authors":[{"name":"Dr. Pradeep K. Pendem","aff":"Assistant Professor, University of Oregon"},{"name":"Prof. Sriram Narayanan","aff":"Professor, Michigan State University"},{"name":"Prof. Vikram Tiwari","aff":"Professor, Vanderbilt University Medical Center"}],"order":3},{"id":"136-1018","title":"Outpatient Appointment Systems: A Review of Overbooking and No-Shows","content":"Overbooking mitigates the negative effects of patient no-shows, uncertain service times, patient wait time, physician idle time, and overtime in outpatient clinics. This review categorizes Operations Research models and solution methods for managing overbooking and no-shows. It highlights open problems and offers guidelines for future research and practice.","presenter":"Mr. Mubarak Iddrisu","authors":[{"name":"Mr. Mubarak Iddrisu","aff":"Student, University of Massachusetts Boston"},{"name":"Prof. Davood Golmohammadi","aff":"Associate Professor, University of Massachusetts Boston"},{"name":"Prof. Ken Klassen","aff":"Professor, Brock University"},{"name":"Prof. Emel Aktas","aff":"Professor, Cranfield University"}],"order":4},{"id":"136-1904","title":"Optimal Lockdown Timing During an Epidemic","content":"We use an MDP to determine the optimal time to impose a lockdown. Based on a well-known SIS epidemic model, we derive an optimal policy based on threshold values on the number of infections. Accordingly, we propose an efficient search and storage method that allows handling large real-world problems.","presenter":"Dr. Noura El Hassan","authors":[{"name":"Dr. Noura El Hassan","aff":"Assistant Professor, American University of Beirut"},{"name":"Dr. Bacel Maddah","aff":"Professor, American University of Beirut"},{"name":"Dr. Fouad Ben Abdelaziz","aff":"Professor, NEOMA Business School"}],"order":5}]},{"id":"s417","title":"Digital Transformation and Innovation","track":"Digital Platforms, Innovations and Transformations","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"GREENBRIAR","chairs":["Dr. Marco Formentini"],"abstracts":[{"id":"136-0975","title":"Synchronizing Artificial Intelligence within the Digital Platform Ecosystem to Drive Circular Business Model Innovation","content":"This study presents the design and validation of a novel digital platform intended to connect various industrial ecosystem stakeholders and in turn develop innovative circular economy business models. The proposed platform incorporates Artificial Intelligence-based functionalities to improve platform governance and decision-making. The study adopts a design science approach.","presenter":"Dr. Marco Formentini","authors":[{"name":"Dr. Janpriy Sharma","aff":"Post Doc/Researcher, University of Trento"},{"name":"Dr. Marco Formentini","aff":"Associate Professor, University of Trento"},{"name":"Dr. Nicola Mezzetti","aff":"CEO, Techneos"},{"name":"Mr. Alfredo Apicella","aff":"Post Doc/Researcher, University of Trento"}],"order":1},{"id":"136-0800","title":"Mechanisms for Digital Innovation in SMEs Enabled by Low-Code Technology Affordance","content":"Low-code technology activates the creativity of business personnel at a low cost., addressing the financial disadvantages in SMEs' digital transformation. Using case studies and the technology affordance theory, we explore how SMEs leverage low-code technology for point-specific digital innovation, leading to collective-level digital innovation.","presenter":"Ms. Jingrong Li","authors":[{"name":"Ms. Jingrong Li","aff":"Student, Renmin University of China"}],"order":2},{"id":"136-1375","title":"Digital Transformation in Universities' Societal Engagement: Leveraging Social Networks to Drive Institutional Change","content":"Digital transformation is reshaping knowledge transfer in universities engagement with the society. By influencing academics’ social networks and their perceptions of institutional logics, analyzing the role of networks in shaping these logics can uncover opportunities to optimize collaboration, resource allocation, and operational efficiency, ultimately enhancing academic contributions to societal development.","presenter":"Ms. Xuqi Chen","authors":[{"name":"Ms. Xuqi Chen","aff":"Student, Tongji University"}],"order":3},{"id":"136-1422","title":"Dynamics of Urban Innovation Ecosystems under Digital Transformation - A Spatial Production Theory Perspective","content":"Digital disruption has accelerated the shift to the knowledge economy era, and many cities have recognised the importance of innovation ecosystems. Based on the spatial production theory, this paper expands the dynamic factors of innovation ecosystems and constructs a system dynamics model of the dynamic mechanism of innovation ecosystems.","presenter":"Ms. ke Shi","authors":[{"name":"Ms. ke Shi","aff":"Student, Tongji University"}],"order":4}]},{"id":"s430","title":"Ethics, Copy-rights, Copy-cats, and Counterfeits","track":"Supply Chain Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"EMBASSY G","chairs":["Dr. Dara Schniederjans"],"abstracts":[{"id":"136-0382","title":"The Optimal Content Provision Model Based on IP and Video Platform's Anti-Piracy Monitoring","content":"This study explores optimal IP strategies in digital media under piracy. Model P suits low-cost content, Model H benefits high-cost content. Revenue-sharing works with low mismatch costs, buyouts suit higher ones. Targeted content, anti-piracy measures, and accessible pricing help maximize economic gains and expand legitimate markets.","presenter":"Ms. Meixian Xu","authors":[{"name":"Mr. Sijie Li","aff":"Professor, Southeast University"},{"name":"Ms. Meixian Xu","aff":"Student, Southeast University, Nanjing, China"}],"order":1},{"id":"136-0368","title":"Creating Transparency in Markets with Quality Differentiation: on the Role of Pricing and Smart Packaging","content":"The trade of counterfeit goods is recently growing. We consider counterfeit products, as low-quality products that are imported to a new market and traded as high-quality products. We investigate two approaches, based on pricing and smart packaging, for detecting counterfeits and creating transparency.","presenter":"Dr. Iman Nosoohi","authors":[{"name":"Dr. Iman Nosoohi","aff":"Assistant Professor, Memorial University of Newfoundland"},{"name":"Prof. Jing Chen","aff":"Professor, Dalhousie University"}],"order":2},{"id":"136-0935","title":"The Influence of Copycat Entry Period on the Platform Supply Chain","content":"This paper models platform-supplier dynamics, analyzing the impact of contract preferences and copycat entry timing. Findings suggest that strategic inventory under the dynamic contract can alleviate double marginalization; however, its effectiveness depends on copycat timing, thereby significantly influencing platform-supplier cooperation and overall profitability.","presenter":"Ms. Jie Miao","authors":[{"name":"Ms. Jie Miao","aff":"Student, Tianjin University"},{"name":"Prof. Zhaofang Mao","aff":"Professor, Tianjin University"},{"name":"Mr. Zhe Yang","aff":"Student, Tianjin University"},{"name":"Prof. Yunchuan Liu","aff":"Associate Professor, University of Illinois Urbana-Champaign"}],"order":3},{"id":"136-0454","title":"Necessary Conditions for Moral Disengagement in Buyer-Supplier E-Communications","content":"This study explores the necessary conditions for moral disengagement in buyer-supplier e-communications. With a focus on individual-level and team-level factors, this study enhances an understanding of ethical challenges and strategies for fostering ethical climates in buyer-supplier relationships.","presenter":"Dr. Dara Schniederjans","authors":[{"name":"Ms. Soode Vaezinejad","aff":"Student, University of Rhode Island"},{"name":"Dr. Chris Starkey","aff":"Assistant Professor, Rhode Island College"},{"name":"Dr. Dara Schniederjans","aff":"Professor, University of Rhode Island"}],"order":4}]},{"id":"s442","title":"AI and Analytics Impact on Illicit trade: Threats and Solutions","track":"Data Science, Analytics and AI","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"3:00 PM","end":"4:30 PM","startMin":900,"room":"ROSWELL","chairs":["Dr. Violet (Xinying) Chen"],"abstracts":[{"id":"136-1334","title":"Heterogeneous Graph and LLM-enabled Illicit Trade Detection in the Retail Stage of Supply Chain","content":"Illicit trade in the retail stage of the supply chain poses significant threats and is difficult to detect due to the highly dynamic market. This research leverages heterogeneous graphs to capture the spatio-temporal dependencies of retailer ordering behaviors and utilizes large language models (LLMs) as predictors for fraud detection.","presenter":"Ms. Lin ZHENG","authors":[{"name":"Ms. Lin ZHENG","aff":"Student, City Univerisity of Hong Kong"},{"name":"Ms. Zhuzhi SHI","aff":"Student, City Univerisity of Hong Kong"},{"name":"Ms. Zhen Liu","aff":"Manager, Monopoly Supervision and Management Section Henan Tobacco Company Zhengzhou"},{"name":"Prof. Jian MA","aff":"Professor, City Univerisity of Hong Kong"},{"name":"Mr. Jintao Hao","aff":"Director, Monopoly Supervision and Management Section Henan Tobacco Company Zhengzhou"}],"order":1},{"id":"136-2058","title":"Identifying the Digital Fingerprints of Illicit Massage Businesses in Mobility Data","content":"Illicit massage businesses (IMBs) operate as regular businesses that also provide illicit services performed by human trafficking victims. We leverage cell phone mobility data and machine learning techniques to train a classifier for identifying IMBs. We use the classifier to provide insights regarding the potential scale of this illicit industry.","presenter":"Ms. roya shomali","authors":[{"name":"Ms. roya shomali","aff":"Student, The University of Alabama"},{"name":"Dr. Nickolas Freeman","aff":"Associate Professor, University of Alabama Tuscaloosa"},{"name":"Dr. Gregory Bott","aff":"Assistant Professor, University of Alabama Tuscaloosa"},{"name":"Dr. Iman Dayarian","aff":"Assistant Professor, University of Alabama"}],"order":2},{"id":"136-1682","title":"Modeling and Learning Dynamic Moral Judgments towards Allocations in High-stakes Domains","content":"We propose a framework for modeling dynamic moral judgments in sequential resource allocation. Our approach learns stakeholders’ evolving preferences through Bayesian inference and active feedback. Simulations and a human subject study validate the model’s effectiveness in capturing moral priorities during high-stakes scenarios like medical resource allocation.","presenter":"Dr. Violet (Xinying) Chen","authors":[{"name":"Dr. Violet (Xinying) Chen","aff":"Assistant Professor, Stevens Institute of Technology"},{"name":"Mr. Joshua Williams","aff":"Student, Carnegie Mellon University"},{"name":"Dr. Derek Leben","aff":"Associate Professor, Carnegie Mellon University"},{"name":"Dr. Hoda Heidari","aff":"Assistant Professor, Carnegie Mellon University"}],"order":3}]},{"id":"s15","title":"Performance Implications of POM and Community","track":"POM and Community","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"EMBASSY F","chairs":["Dr. Kevin Mayo"],"abstracts":[{"id":"136-1022","title":"The Impact of ESG Challenges on Megaproject Performance","content":"This study investigates the performance implications of ESG challenges in the context of megaprojects (i.e., large-scale construction projects). We first operationalize ESG by utilizing text mining with multiple sources of text data. Then, we examine how ESG challenges impact cost and schedule performance.","presenter":"Ms. Sun Kim","authors":[{"name":"Ms. Sun Kim","aff":"Student, Michigan State University"},{"name":"Prof. Budi Harsanto","aff":"Associate Professor, Padjadjaran University"},{"name":"Prof. Sriram Narayanan","aff":"Professor, Michigan State University"}],"order":1},{"id":"136-1023","title":"Board-Workforce Gender Identification and Corporate Environmental Innovation","content":"Focusing on the oft-examined BFR-EI relationship, our panel analysis identifies board-workforce gender identification—the combination of three female directors and a gender-balanced workforce—as a necessary organizational condition for BFR to boost EI. We also find empirical support that BFR enhances EI via both workforce corporate value alignment and greater FWAs implementation.","presenter":"Mr. Nuo Yuan","authors":[{"name":"Mr. Nuo Yuan","aff":"Student, Boston University"},{"name":"Dr. Marcus Bellamy","aff":"Associate Professor, Boston University"}],"order":2},{"id":"136-1783","title":"Female FDA Inspectors and Medical Device Plant Inspections","content":"The impact of gender on decision-making and outcomes in the operations is a growing area of concern in academic literature and practical settings. We use 20 years of FDA inspection data to explore the relationship between the inspectors’ gender and inspection outcomes and investigate the subsequent impact of those outcomes.","presenter":"Ms. Shirin Shahsavand","authors":[{"name":"Ms. Shirin Shahsavand","aff":"Student, Washington State University"},{"name":"Dr. Kevin Mayo","aff":"Assistant Professor, Washington State University"},{"name":"Prof. George Ball","aff":"Associate Professor, Kelley School of Business, Indiana Univ."},{"name":"Dr. Kaitlin Wowak","aff":"Associate Professor, University of Notre Dame"}],"order":3}]},{"id":"s37","title":"Behavioral Insights in Humanitarian Operations","track":"Humanitarian Operations and Crisis Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"GRAND HALL EAST B","chairs":["Dr. Hasti Rahemi"],"abstracts":[{"id":"136-0305","title":"Examining the researcher-practitioner gap on developing and adopting tools for Disaster and Humanitarian Operations","content":"This study investigates the divergence between researchers and practitioners regarding developing tools for disaster and humanitarian operations. We applied Survey and Design Science Research with Brazilian stakeholders. Results revealed the need for risk mapping and training by practitioners and scientific discussion in stakeholder coordination by researchers. We propose conciliatory strategies.","presenter":"Prof. Tharcisio Fontainha","authors":[{"name":"Mrs. Híngred Resende","aff":"Student, Federal University of Rio De Janeiro"},{"name":"Mrs. Ana Nascimento","aff":"Student, Federal University of Rio De Janeiro"},{"name":"Prof. Tharcisio Fontainha","aff":"Professor, Federal University of Rio De Janeiro"}],"order":1},{"id":"136-1847","title":"Behavioral Responses to Nonprofit Operational Performance Metrics","content":"Nonprofit organizations often disclose financial performance metrics to donors. However, current literature and practitioners call for disclosure of supplementing operational performance metrics. Nevertheless, the effects of these metrics on donations are understudied. In a behavioral experiment, we operationalize and study the effects of operational metrics on donations to nonprofits.","presenter":"Dr. Hasti Rahemi","authors":[{"name":"Dr. Hasti Rahemi","aff":"Assistant Professor, University of Wisconsin-Whitewater"},{"name":"Dr. Gloria Urrea","aff":"Assistant Professor, University of Colorado Boulder"},{"name":"Prof. Leon Valdes","aff":"Associate Professor, University of Pittsburgh"}],"order":2},{"id":"136-0276","title":"Impact of Climate Risk Perception on Stockpiling Behavior: Evidence from Chinese E-Commerce Data","content":"This study analyzes the impact of climate risk perception on stockpiling behavior using e-commerce tissue sales data from 250 Chinese cities (2019-2024). A climate risk perception index was constructed using keyword search data. Findings reveal spatiotemporal spillover effects of stockpiling, highlighting e-commerce’s role in consumer responses to extreme climate events.","presenter":"Dr. Tong Niu","authors":[{"name":"Dr. Tong Niu","aff":"Student, Tongji University"},{"name":"Prof. Yong Li","aff":"Associate Professor, Tongji University"}],"order":3},{"id":"136-0689","title":"Stress, trauma, and decision making in humanitarian aid logistics","content":"Experience and trauma may influence humanitarian aid logistics workers' decision-making in inventory management. Through a behavioral experiment, we compare decisions across different levels of trauma and experience to identify when decision makers are most vulnerable to new information and potential trauma triggers.","presenter":"Prof. Julie Niederhoff","authors":[{"name":"Prof. Julie Niederhoff","aff":"Associate Professor, Syracuse University"},{"name":"Dr. Llord Brooks","aff":"Assistant Professor, University of South Florida"}],"order":4}]},{"id":"s49","title":"From Product Design to Returns: Economic Perspectives on New Business Practices","track":"POM-Economics Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"VININGS","chairs":["Dr. Gokce Esenduran","Dr. Paolo Letizia"],"abstracts":[{"id":"136-0076","title":"Optimal Product Return Insurance","content":"In response to the high cost of returns, some firms have discontinued their free returns policy, instead offering customers the option to purchase return insurance. This insurance allows customers to return items and receive a refund. We examine how to optimally design the return policy and insurance structure.","presenter":"Dr. Gokce Esenduran","authors":[{"name":"Dr. Gokce Esenduran","aff":"Associate Professor, Purdue University"},{"name":"Dr. Paolo Letizia","aff":"Associate Professor, University of Tennessee"},{"name":"Prof. Anton Ovchinnikov","aff":"Professor, Queens University"}],"order":1},{"id":"136-0448","title":"Sell the Virtual Before the Physical Product? Managing the Dual Channels for an Apparel Brand","content":"Apparel retailers have been using multiple strategies to address the uncertainty of demand. By observing apparel firms extend the traditional lines with virtual items, we consider this new channel of distribution and model the firm decisions of price and quantity in traditional and virtual channel.","presenter":"Prof. Mehmet Altug","authors":[{"name":"Ms. Mariia Petryk","aff":"Assistant Professor, George Mason University"},{"name":"Prof. Mehmet Altug","aff":"Associate Professor, George Mason University"}],"order":2},{"id":"136-1241","title":"Inventory Disclosure with Uncertain Consumer Valuations and Returns","content":"We study optimal inventory disclosure when uncertain consumer valuations trigger product returns. Contrasting the optimality of consistent disclosure of low availability with known customer valuations and no product returns, we find that retailers may optimally display \"in stock\" messages. Therefore, online retailers should rethink inventory availability disclosure with product returns.","presenter":"Ms. Ceren Gultekin","authors":[{"name":"Ms. Ceren Gultekin","aff":"Student, Baruch College, Graduate Center, CUNY"},{"name":"Prof. Tolga Aydinliyim","aff":"Associate Professor, Baruch College"}],"order":3},{"id":"136-1621","title":"Combining a Smart Pricing Policy with a Simple Replenishment Policy: Taming Uncertainties of Product Return","content":"Product returns have cost retailers hundreds of billions of dollars and has significantly increased landfills via its impact on supply chain. Motivated by this reality, in this paper, we aim to design an implementable joint pricing and inventory policy that achieves cost reduction and sustainability objectives simultaneously.","presenter":"Ms. Alys Liang","authors":[{"name":"Ms. Alys Liang","aff":"Assistant Professor, McGill University"},{"name":"Prof. Stefanus Jasin","aff":"Professor, University of Michigan"},{"name":"Prof. Joline Uichanco","aff":"Associate Professor, University of Michigan"}],"order":4},{"id":"136-1956","title":"Scaling Prosocial Innovations: Balancing Product Localization and Pricing","content":"Social enterprises can scale uptake and therefore social value of their products by price reduction; meanwhile, product design localization can be another effective lever. We study how these levers can be strategically employed to form the optimal product offering strategy, and how the organization's prosocial orientation plays a role.","presenter":"Dr. Natalie (Ximin) Huang","authors":[{"name":"Dr. Natalie (Ximin) Huang","aff":"Assistant Professor, University of Minnesota"},{"name":"Prof. Karthik V. Natarajan","aff":"Associate Professor, University of Minnesota"},{"name":"Dr. Karthik Ramachandran","aff":"Professor, Georgia Institute of Technology"}],"order":5}]},{"id":"s73","title":"Corporate Carbon Reduction Strategies","track":"Sustainable Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"GRAND HALL EAST C","chairs":["Dr. Ravi Subramanian","Mr. Donghyun (Daniel) Choi"],"abstracts":[{"id":"136-0040","title":"The Effectiveness of Science-Based Carbon Targets","content":"Although goal-setting theory predicts that a challenging and specific goal can improve performance, the evidence regarding the effectiveness of an environmental goal in organizations is mixed. We apply a Difference-in-Differences (DiD) strategy and empirically analyze the effect of having science-based carbon emissions targets (SBTs) on firms’ performance.","presenter":"Prof. Xichen Sun","authors":[{"name":"Prof. Xichen Sun","aff":"Assistant Professor, Tilburg University"},{"name":"Dr. Xingzhi Jia","aff":"Assistant Professor, Renmin University of China"},{"name":"Dr. Rogelio Oliva","aff":"Professor, Texas A&amp;M University College Station"}],"order":1},{"id":"136-0184","title":"Pooling carbon targets","content":"Many corporations now set voluntary direct (Scope 1) and indirect (Scope 2) carbon emissions reduction targets. Does pooling Scope 1and 2 targets increase the likelihood of success? We use ten years of data collected by CDP to explore our research question.","presenter":"Prof. Christian Blanco","authors":[{"name":"Prof. Christian Blanco","aff":"Assistant Professor, Ohio State University"},{"name":"Dr. Oznur Ozdemir","aff":"Assistant Professor, University of Bradford"},{"name":"Dr. Erdinc Akyildirim","aff":"Associate Professor, University of Bradford"}],"order":3},{"id":"136-0866","title":"Effect of Slack Resources and Emissions Controllability on Science-Based Target Adoption","content":"Science-based targets are standardized, verifiable targets, disallowing firms from adjusting the target parameters. We focus on the SBTs and using a sample of over 9,000 global firms investigate the role of slack resources, internal carbon pricing, and proportion of scope 3 emissions on firm commitment to SBTi.","presenter":"Mr. Donghyun (Daniel) Choi","authors":[{"name":"Mr. Donghyun (Daniel) Choi","aff":"Student, Georgia Institute of Technology"},{"name":"Mr. Abhinav Shubham","aff":"Student, Georgia Institute of Technology"},{"name":"Prof. Manpreet Hora","aff":"Professor, Georgia Institute of Technology"}],"order":4}]},{"id":"s120","title":"Human-AI Interaction","track":"Empirical Research in Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"EMBASSY B","chairs":["Prof. Brian Han"],"abstracts":[{"id":"136-0489","title":"Spatial Decision Bias and Algorithm Interface Design","content":"This study investigates behavioral biases in spatial decisions with experimental evidence on process flexibility. We test our hypotheses in controlled laboratory experiments with financially incentivized human subjects. The empirical result reveals two spatial biases dependent on the interface design: spatial mental accounting, spatial regret and their interplay.","presenter":"Mr. Feiteng Huang","authors":[{"name":"Mr. Feiteng Huang","aff":"Student, University of Houston"},{"name":"Dr. Meng Li","aff":"Professor, University of Houston"},{"name":"Dr. Yang Zhang","aff":"Associate Professor, University of Kent"}],"order":1},{"id":"136-0492","title":"The Impact of Unmanned System Adoption on Store Performance: Evidence from a Field Experiment","content":"This study explores the effects of unmanned systems on retail performance through a field experiment. Results show that extending operational hours with unmanned systems significantly boosts performance, particularly during low-traffic periods and in less favorable locations. We also find that adopting in-store technology could impact consumer loyalty and shopping habits.","presenter":"Ms. Shasha Cao","authors":[{"name":"Ms. Shasha Cao","aff":"Student, Arizona State University"},{"name":"Prof. Pei-yu Chen","aff":"Professor, Arizona State University"},{"name":"Dr. Raghu Santanam","aff":"Professor, Arizona State University Tempe"},{"name":"Prof. Xin Tian","aff":"Associate Professor, University of Chinese Academy of Sciences"}],"order":2},{"id":"136-0203","title":"Less is more: monologue vs. dialogue in AI-enabled telemarketing","content":"Artificial intelligence has advanced telemarketing from traditional robocalls to AI-enabled dialogue telemarketing systems, yet its effectiveness remains uncertain. A field experiment with 90,000 participants reveals that traditional monologue telemarketing outperforms AI-enabled dialogue, achieving an 18.43% higher response rate, challenging assumptions about AI’s advantage in telemarketing.","presenter":"Prof. Brian Han","authors":[{"name":"Mr. Xincheng Ma","aff":"Student, HKUST Business School"},{"name":"Prof. Brian Han","aff":"Assistant Professor, University of Illinois at Urbana Champaign"},{"name":"Mr. Dongwon Lee","aff":"Assistant Professor, HKUST"},{"name":"Junbum Kwon","aff":""}],"order":3},{"id":"136-0502","title":"A Simple Solution to Improving Human Supervision of Algorithms: Evidence from Smart Vending","content":"Humans nowadays inevitably collaborate with algorithms. We propose a novel framework for human-algorithm collaboration to improve performance. We find strong evidence supporting our framework through a field experiment in the case of inventory replenishment of smart vending machines with over $500$ workers managing more than 50,000 shelves.","presenter":"Mr. Minda Zhao","authors":[{"name":"Mr. Minda Zhao","aff":"Student, Georgia Institute of Technology"},{"name":"Prof. Brian Han","aff":"Assistant Professor, University of Illinois at Urbana Champaign"},{"name":"Dr. Xin Chen","aff":"Professor, Georgia Institute of Technology"},{"name":"Dr. Tao Zhu","aff":"Chief Information Officer, Shenzhen Fengyi Technology Co., Ltd."}],"order":4}]},{"id":"s162","title":"Navigating Healthcare Challenges: Disparities, Partnerships, and Innovations","track":"Healthcare Analytics","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"GRAND HALL EAST D","chairs":["Mrs. Jane Iversen"],"abstracts":[{"id":"136-0073","title":"Busyness, Task Complexity and Access to Surgery: An Empirical Study of Racial Disparity in Hospitals","content":"Hospital managers evaluate and decide how resources should be allocated to patients based on clinical needs. This decision-making process can introduce bias, potentially affecting patient outcomes negatively.","presenter":"Dr. Temidayo Adepoju","authors":[{"name":"Dr. Xin Ding","aff":"Associate Professor, Rutgers Business School"},{"name":"Dr. Temidayo Adepoju","aff":"Assistant Professor, Rutgers Business School"}],"order":1},{"id":"136-1536","title":"The Role of Familiarity in Improving the Effectiveness of Medicaid Managed Care","content":"Under Medicaid Managed Care (MMC) models, private insurers receive capitated payments to maintain provider networks that meet the needs of the patients they serve. This paper examines the impact of MMC on the quality and the efficiency of the care delivered to Medicaid patients and the moderating role of familiarity.","presenter":"Prof. Jong Myeong Lim","authors":[{"name":"Dr. Min Chen","aff":"Associate Professor, Florida International University"},{"name":"Prof. Jong Youl Lee","aff":"Assistant Professor, Florida International University"},{"name":"Prof. Jong Myeong Lim","aff":"Assistant Professor, Miami Herbert Busienss School"}],"order":4},{"id":"136-1577","title":"Factors Influencing Big-Big Pharma Companies’ Successful R&amp;D Partnerships","content":"The COVID-19 pandemic triggered unusual partnerships between big pharma companies — they started seeking R&amp;D collaboration with their traditional rivals. Motivated by the patent data distribution patterns we discover, we propose boundary conditions influencing their partnership decisions.","presenter":"Prof. Fuminori Toyasaki","authors":[{"name":"Prof. Fuminori Toyasaki","aff":"Professor, York University"},{"name":"Dr. Can Baris Cetin","aff":"Post Doc/Researcher, York University"},{"name":"Dr. Abigail Richard","aff":"Assistant Professor, University of Indianapolis"},{"name":"Prof. Johnny Rungtusanatham","aff":"Professor, University of Cincinnati"}],"order":5},{"id":"136-1878","title":"Optimizing Wearable Devices in Personalized Opioid Use Disorder Treatments Under Budget Constraint","content":"We explore the potential of wearable devices to enhance treatments for opioid use disorder (OUD) through frequent status updates and personalized care. We develop a partially observable Markov decision process (POMDP) with two types of budget constraints—one at the population level and one at the individual level—to evaluate the cost-effectiveness.","presenter":"Prof. Savannah Tang","authors":[{"name":"Dr. Kyra Gan","aff":"Assistant Professor, Cornell University"},{"name":"Prof. Savannah Tang","aff":"Assistant Professor, SMU Cox School of Business"},{"name":"Prof. Alan Scheller-Wolf","aff":"Professor, Tepper School of Business"},{"name":"Prof. Sridhar Tayur","aff":"Professor, Carnegie Mellon University"}],"order":6}]},{"id":"s168","title":"AI and Human Decision-Making","track":"Product Innovation and Technology Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"COURTLAND","chairs":["Mr. Mohamed Megahed"],"abstracts":[{"id":"136-0679","title":"Generative AI in Clinical Documentation: Impact on Healthcare Efficiency and Provider Well-being","content":"This study empirically examines the effects of ambient documentation tools that automatically generate clinical notes from patient-provider conversations. Using panel data from a large hospital, we identify positive impacts on provider productivity and well-being. Results show these effects are moderated by contextual factors and provider characteristics.","presenter":"Mr. Ragip Gurlek","authors":[{"name":"Mr. Ragip Gurlek","aff":"Student, Emory University"},{"name":"Prof. Diwas KC","aff":"Professor, Emory University"}],"order":1},{"id":"136-1474","title":"Mapping the Effects of Operational Misconduct on Service Quality","content":"Operational misconduct—illegal or improper behavior committed by the management board or employees within a corporation that pertains to its operational system—can impact service quality. Our study uses a word-embedding approach to detect unobservable misconduct and a causal DAG to reveal the influence pathways from operational misconduct to service quality.","presenter":"Mr. Ziwei Zhu","authors":[{"name":"Prof. Bradley Staats","aff":"Professor, University of North Carolina Chapel Hill"},{"name":"Mr. Yushan Zhou","aff":"Student, Dalian University of Technology"},{"name":"Mr. Ziwei Zhu","aff":"Student, Cornell University"}],"order":2},{"id":"136-1609","title":"Evaluation of Generative Artificial Intelligence on the Problem Formulation Process in the Context of Crowdsourcing","content":"Despite the rising use of GenAI in the problem formulation process to define problem scopes, boundaries, and solution pathways, its impact on innovation seekers and problem solvers on crowdsourcing platforms remains underexplored. Our field experiment reveals that it enhances innovation seekers’ efficiency and amplifies problem solvers’ participation intention.","presenter":"Ms. Keyou Feng","authors":[{"name":"Ms. Keyou Feng","aff":"Student, University of Bristol"},{"name":"Dr. Minhao Zhang","aff":"Associate Professor, University of Bristol"},{"name":"Dr. Jens Roehrich","aff":"Professor, University of Bath"},{"name":"Prof. Anant Mishra","aff":"Professor, University of Minnesota"}],"order":3}]},{"id":"s196","title":"Innovations in Service Capacity Management","track":"Service Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"EMBASSY C","chairs":["Prof. Vincent Slaugh"],"abstracts":[{"id":"136-0388","title":"Breaking Barriers: Improving Patient Adherence to Appointments through Telehealth","content":"Using data from a large medical system, we examine the impact of telehealth on patient appointment adherence. We find that telehealth reduces no-show rates and improves punctuality, particularly for follow-up appointments and among patients with historically higher rates of non-adherence to in-person visits, i.e., women, minorities, and younger patients.","presenter":"Mr. Masoud Kamalahmadi","authors":[{"name":"Mr. Masoud Kamalahmadi","aff":"Assistant Professor, Miami Herbert Busienss School"},{"name":"Prof. Christos Zacharias","aff":"Assistant Professor, University of Miami"},{"name":"Mr. Howard Gitlow","aff":"Professor, University of Miami"}],"order":1},{"id":"136-0585","title":"The Granularity of Wait Time Information: A Large-Scale Field Experiment on a Major Ride-Sharing Platform","content":"Collaborating with a ride-sharing platform, we study whether and how the granularity of wait time information, WTI, impacts customers abandonment behavior through a randomized field experiment. To uncover the fundamental mechanism, we propose a structural model to explore the impacts of granularity of WTI. Additionally, we discuss the managerial implications.","presenter":"Dr. Yiming ZHANG","authors":[{"name":"Dr. Yiming ZHANG","aff":"Assistant Professor, The Chinese Univ of Hong Kong, Shenzhen"},{"name":"Prof. Qiuping Yu","aff":"Associate Professor, Georgetown University"},{"name":"Prof. Yong-Pin Zhou","aff":"Professor, University of Washington"}],"order":2},{"id":"136-1039","title":"Flock Management for Solar Grazing","content":"We present a novel model to optimize flock management for solar grazing, a service operation addressing vegetation maintenance on solar farms. We provide structural results for the initial flock procurement problem. Our findings reveal strategies for balancing sheep procurement, flock growth, and culling decisions.","presenter":"Prof. Vincent Slaugh","authors":[{"name":"Prof. Vincent Slaugh","aff":"Assistant Professor, Cornell University"},{"name":"Prof. Linwei Xin","aff":"Associate Professor, University of Chicago"},{"name":"Mr. Shane Henderson","aff":"Professor, Cornell University"}],"order":3},{"id":"136-1503","title":"Key Influences on Foster Care Outcomes","content":"We analyze key factors that influence outcomes for children in foster care, specifically placement stability and adoption. These factors include the child's demographics, number of placement settings, duration in foster care, and racial matching of foster parent(s) and child.","presenter":"Ms. Wani Zhang","authors":[{"name":"Ms. Wani Zhang","aff":"Student, London Business School"},{"name":"Prof. Kamalini Ramdas","aff":"Professor, London Business School"}],"order":4}]},{"id":"s265","title":"Market Dynamics and Strategic Decision-Making","track":"POM-Marketing Interface","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"DUNWOODY","chairs":["Dr. Yi Liu"],"abstracts":[{"id":"136-1931","title":"Blessing or Curse? Strategic Quality Communication in the Presence of Social Learning","content":"This study examines a firm's strategic quality communication choice---voluntary disclosure versus price signaling---in the presence of social learning. Our findings indicate that social learning can either enhance or diminish information transparency. Interestingly, when social learning improves information transparency, it adversely affects market-level firm profit, consumer surplus, and social welfare.","presenter":"Ms. Feiyang Shen","authors":[{"name":"Ms. Feiyang Shen","aff":"Student, Southeast University"},{"name":"Prof. Weili Xue","aff":"Professor, Southeast University"},{"name":"Dr. Yimin Yu","aff":"Associate Professor, City University of Hong Kong"},{"name":"Prof. Han Zhu","aff":"Professor, Dongbei University of Finance and Economics"}],"order":1},{"id":"136-2050","title":"Product Reviews, Prices, and Profits in Markets Driven by Randomness: The Null Model","content":"Myriad examples illustrate how randomness evokes wrong causal explanations and misguided implications. Judging the contribution of explanatory variables requires naïve null benchmark models. We provide a novel null model where consumers lack preferences, biases, and acquisition strategies. Moreover, we provide optimal managerial strategies for markets resembling our null model.","presenter":"Ms. Man Xie","authors":[{"name":"Dr. Steve Shugan","aff":"Professor, University of Florida"},{"name":"Ms. Man Xie","aff":"Assistant Professor, Arizona State University"}],"order":2},{"id":"136-2048","title":"Does Platform Fragmentation Harm Innovation?","content":"Platform fragmentation, i.e., coexistence of multiple versions of a platform technology, is conventionally considered to harm innovation. In this paper, we show the opposite may be true. Platform fragmentation causes market segmentation and reduces the winner-take-all propensity, which induces more frequent innovations from small developers and greater diversity of innovations.","presenter":"Dr. Yi Liu","authors":[{"name":"Dr. Zhuoxin (Allen) Li","aff":"Associate Professor, University of Wisconsin-Madison"},{"name":"Dr. Yi Liu","aff":"Assistant Professor, University of Wisconsin-Madison"}],"order":3}]},{"id":"s273","title":"Dynamic Fairness","track":"Operations and Society","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"LENOX","chairs":["Dr. David Rea","Dr. Violet (Xinying) Chen"],"abstracts":[{"id":"136-1227","title":"Delivering Mobile Public Services: A Data-Driven Optimization Approach","content":"This study addresses scheduling visits for mobile public service facilities delivering government services like identification and registration to rural areas. Using a data-driven approach with over 1 million observed service requests, it empirically models captured demand and optimizes schedules through mixed-integer linear programming. Computational experiments highlight efficiency improvements.","presenter":"Mr. Kerim U. Kizil","authors":[{"name":"Mr. Kerim U. Kizil","aff":"Student, Texas A&amp;M University"},{"name":"Dr. Huseyn Abdulla","aff":"Assistant Professor, University of Tennessee Knoxville"},{"name":"Prof. Chelliah Sriskandarajah","aff":"Professor, Texas A&amp;M University College Station"},{"name":"Prof. Jon Stauffer","aff":"Associate Professor, Mays Business School, Texas A&amp;M University"}],"order":1},{"id":"136-1451","title":"Fair Lending in the Fintech Era: A Profit-Based Test of Discrimination","content":"Adverse impact ratios and model calibration have been widely used to assess the fairness of algorithmic lending decisions, however these measures have limitations as regulatory mechanisms. Using loan data from a fintech lender, we propose and empirically test an alternative approach that examines risk-adjusted differences in profits across groups.","presenter":"Ms. Madison Coots","authors":[{"name":"Ms. Madison Coots","aff":"Student, Harvard University"},{"name":"Prof. Robert Bartlett","aff":"Professor, Stanford University"},{"name":"Prof. Julian Nyarko","aff":"Professor, Stanford University"},{"name":"Prof. Sharad Goel","aff":"Professor, Harvard University"}],"order":2},{"id":"136-0336","title":"Design of Optimal Bus Transportation for Charter School Students in South Carolina","content":"In this paper, I describe details of an application project for designing optimal bus transportation for &gt; 10,000 charter school students in South Carolina. SC Dept of Education is planning to use the approach to design optimal routes for facilitating charter school education.","presenter":"Prof. Sanjay Ahire","authors":[{"name":"Prof. Sanjay Ahire","aff":"Professor, University of South Carolina"}],"order":3},{"id":"136-1677","title":"Dynamic Fairness in Shared Electric Micromobility Systems","content":"Shared electric micromobility systems (SEMSs), including docked and dockless (e)-bike and e-scooter sharing systems, play increasingly important roles in urban transportation. Based on a systematic framework for assessing fairness in SEMSs, we explore time-based dynamics in the fairness of availability and accessibility.","presenter":"Dr. Violet (Xinying) Chen","authors":[{"name":"Dr. Violet (Xinying) Chen","aff":"Assistant Professor, Stevens Institute of Technology"}],"order":4}]},{"id":"s279","title":"Transportation Issues","track":"Aviation, Transportation, and Logistics Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"UNIVERSITY","chairs":["Dr. Teng Huang"],"abstracts":[{"id":"136-1165","title":"Cross-border e-commerce bonded imports assignment under uncertain demand and travel time","content":"Bonded warehouses can exempt imported goods from time-consuming first-leg overseas transportation in direct-mail logistics channels. To handle the high uncertainty in customer demand and travel time under this scenario, we develop a distributionally robust model for addressing warehouse rental schemes and inventory assignment problems in designing a bonded import network.","presenter":"Mr. Xuhui Chen","authors":[{"name":"Prof. Yong He","aff":"Professor, Southeast University"},{"name":"Mr. Xuhui Chen","aff":"Student, Southeast University, Nanjing, China"}],"order":1},{"id":"136-1214","title":"Balancing Speed and Precision: Estimating Knapsack Problem Optimal Solutions Through Regression and Machine Learning","content":"We develop approaches to obtain near-optimal, efficiently computable solution values for the NP-Hard Knapsack Problem. Using a randomized greedy heuristic, we use a linear regression model including heuristic predictors. We improve accuracy while maintaining reasonable computation times with random forest and neural network methods. Results are encouraging with difficult datasets.","presenter":"Mr. Hugo Mainguy","authors":[{"name":"Mr. Hugo Mainguy","aff":"Student, Smith School of Business, University of Maryland"},{"name":"Prof. Bruce Golden","aff":"Professor, University of Maryland"},{"name":"Prof. Luca Bertazzi","aff":"Associate Professor, Università degli Studi di Brescia"}],"order":4},{"id":"136-1393","title":"Walrasian Pricing for Combinatorial Markets with Compact-Bidding Languages: An Application to Truckload Transportation","content":"Motivated by truckload transportation markets, we explore new mechanisms for finding Walrasian equilibrium prices in combinatorial auctions and exchanges where bidders can use a compact-bidding language to express their complex preferences. We highlight significant potential gains by leveraging an integrated allocation and price determination based on an industry-specific bidding language.","presenter":"Dr. Mohsen Emadikhiav","authors":[{"name":"Dr. Mohsen Emadikhiav","aff":"Assistant Professor, Florida Atlantic University"},{"name":"Dr. Robert Day","aff":"Associate Professor, University of Connecticut"}],"order":5},{"id":"136-1407","title":"Post-Disaster Emergency Supply Chain Optimization: Multi-Period and Multi-Variety Supplies Distribution Amid Demand Uncertainty","content":"The disruptions caused by disasters often lead to explosive and unpredictable demand for emergency supplies in affected areas. To address this, we develop an evaluation model and employ a deep reinforcement learning algorithm to find optimal solutions for the Multi-period Dynamic Vehicle Routing Problem with Stochastic Requests (MDVRPSR).","presenter":"Mr. Shimin Gao","authors":[{"name":"Mr. Shimin Gao","aff":"Student, Central University of Finance And Economics"},{"name":"Dr. Hui Li","aff":"Lecturer, Central University of Finance And Economics"},{"name":"Dr. Xi Wang","aff":"Associate Professor, Central University of Finance And Economics"},{"name":"Dr. Jian Wang","aff":"Associate Professor, Central University of Finance And Economics"}],"order":6}]},{"id":"s286","title":"Generative AI/ML: Economic Modeling and Implications","track":"Generative AI and Societal Sustainable Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"HARRIS","chairs":["Prof. Icheng Chiang"],"abstracts":[{"id":"136-0905","title":"The Impact of Mandatory AIGC Disclosure in Online Communities on Creative Activities","content":"This study explores the impact of mandatory AI-generated content disclosure policies on community activities. Specifically, we investigate the impact on the creative behaviors of different creators and the content quantity and features of the community overall. This research sheds light on how innovative technologies impact traditional creative practices.","presenter":"Ms. Shu He","authors":[{"name":"Prof. Jianqing Chen","aff":"Professor, UT Dallas"},{"name":"Ms. Shu He","aff":"Assistant Professor, University of Florida"},{"name":"Ms. Hehe Pan","aff":"Student, Nanjing University"},{"name":"Dr. Xue Yang","aff":"Professor, Nanjing University"}],"order":1},{"id":"136-0961","title":"Labeling AI-Generated Content: Implications for Platforms, Creators, and Consumers","content":"With the rapid evolution of AI, the line between human-generated content and AI-generated content has become increasingly blurred. To ensure transparency and trust, some social-media platforms (e.g., Facebook) have started labeling AI-generated content. This study examines the impact of such initiatives on platform profitability, content creation, and consumers.","presenter":"Ms. Yan Zhu","authors":[{"name":"Ms. Yan Zhu","aff":"Student, University of Texas at Dallas"},{"name":"Prof. Jianqing Chen","aff":"Professor, University of Texas at Dallas"},{"name":"Prof. Srinivasan Raghunathan","aff":"Professor, The University of Texas at Dallas"}],"order":2},{"id":"136-1517","title":"To Cooperate or Not? The Impacts of Generative AI on Content Creation across Platforms","content":"A platform hosting original content may or may not cooperate with a platform of derivative contents. Generative AI is significantly impacting the industry and we characterize AI through its differential impacts on orginal and derivative content creations. Then, we study how Generative AI affects the two platforms' cooperation incentives.","presenter":"Dr. Chenglong Zhang","authors":[{"name":"Mr. Weilin Ye","aff":"Student, Chinese Univ of Hong Kong (Shenzhen)"},{"name":"Dr. Chenglong Zhang","aff":"Assistant Professor, Chinese Univ of Hong Kong (Shenzhen)"},{"name":"Dr. Zhou Zhou","aff":"Assistant Professor, City University of Hong Kong"}],"order":3},{"id":"136-1668","title":"Data, Algorithm, Computation: An Economic Analysis of Machine Learning Model as a Service","content":"In this paper, we develop a game-theoretical model to analyze the pricing of machine learning model as a service based on three key elements of machine learning: data, algorithms, and computation.","presenter":"Prof. Lin Hao","authors":[{"name":"Prof. Icheng Chiang","aff":"Professor, Fordham University Gabelli School of Bus"},{"name":"Prof. Lin Hao","aff":"Associate Professor, Fordham University Gabelli School of Bus"}],"order":4},{"id":"136-0823","title":"Adopting generative AI for value co-creation in a healthcare context: An intervention-based randomized field experiment","content":"There is a productivity paradox related to AI interventions and trust issue with the new technology。 Adopting a value co-creation view and actor network theory (ANT), we investigated how generative artificial intelligence (GenAI) can improve post-discharge care for patients with chronic diseases (e.g., cardiovascular disease) in a resource-limited setting.","presenter":"Prof. Lujie Chen","authors":[{"name":"Mr. Yanwu Song","aff":"Student, University of Science and Technology of China"},{"name":"Dr. Tingting Yan","aff":"Professor, Texas Tech University"},{"name":"Prof. Fu Jia","aff":"Professor, University of York, UK"},{"name":"Prof. Lujie Chen","aff":"Reader, Xi'an JiaoTong-Liverpool University"},{"name":"Dr. Hao Li","aff":"Professor, Nanjing University of Aeronautics and Astronautics"}],"order":6}]},{"id":"s294","title":"GenAI and Human-AI collaboration","track":"Disruptive Technologies and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"KENNESAW","chairs":["Dr. Xinyu Fu"],"abstracts":[{"id":"136-0255","title":"Enhancing Clinical Trial Patient Matching through Knowledge Augmentation with Multi-Agents","content":"Matching patients effectively and efficiently for clinical trials is a significant challenge due to the complexity and variability of patient profiles and trial criteria. This paper presents a novel framework, Multi-Agents for Knowledge Augmentation (MAKA), designed to enhance patient-trial matching by dynamically supplementing matching prompts with external, domain-specific knowledge.","presenter":"Mr. Hanwen Shi","authors":[{"name":"Mr. Hanwen Shi","aff":"Student, University of Maryland - College Park"},{"name":"Prof. Kunpeng Zhang","aff":"Associate Professor, University of Maryland"}],"order":1},{"id":"136-0709","title":"The Role of AI Adoption in Game Design–An Empirical Study in Video Game Industry","content":"This study explores the impact of AI adoption in game design on developers and player experiences. By uncovering causal pathways through which the integration of AI enhances user engagement, we offer managerial insights for stakeholders, including game developers, publishers, and platforms.","presenter":"Ms. Linghui Feng","authors":[{"name":"Ms. Linghui Feng","aff":"Student, Boston University"},{"name":"Dr. Qi Wang","aff":"Post Doc/Researcher, Boston University"}],"order":2},{"id":"136-1901","title":"Service Robot, Automated Interaction, and Customers’ Responses","content":"Effective deployment of automated robots in service operations is crucial for service firms. This study examines how automated robots interact with customers and shift the customers’ online discourse. We contribute to the human-robot interaction literature by identifying boundary conditions and mechanisms shaping customers’ interactions and evaluations of automated agents.","presenter":"Ms. Anqi Zhang","authors":[{"name":"Ms. Anqi Zhang","aff":"Student, Georgia State University"},{"name":"Dr. Xinyu Fu","aff":"Assistant Professor, Georgia State University"}],"order":4}]},{"id":"s298","title":"Sustainable Strategies and Market Dynamics: Innovations in Supply Chains, Pricing, and Advertising","track":"Information Systems and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"SPRING","chairs":["Ms. Jiayu Fan"],"abstracts":[{"id":"136-0272","title":"Circular Supply Chain Safety Management through Blockchain Technology","content":"This thesis examines circular supply chains (CSCs) with a focus on safety risks, often affecting vulnerable populations. Using blockchain (BC) for transparency and efficiency, it evaluates BC’s role in enhancing CSC sustainability from social, economic, and environmental perspectives. Insights aim to improve responsible, sustainable supply chain management and circularity integration.","presenter":"Ms. Zhuowen Chen","authors":[{"name":"Ms. Zhuowen Chen","aff":"Student, Worcester Polytechnic Institute"},{"name":"Prof. Joseph Sarkis","aff":"Professor, Worcester Polytechnic Institute"}],"order":1},{"id":"136-0515","title":"Need a quick ride or lower fee? Price and Waiting-time Differentiation in Ride-Hailing Platforms","content":"Some ride-hailing platforms allow consumers to choose between two prices associated with different levels of waiting time. In this paper, we concentrate on the impacts of this pricing strategy on the platform’s profit and performance in a duopoly model.","presenter":"Ms. Masoumeh Shahsavari","authors":[{"name":"Ms. Masoumeh Shahsavari","aff":"Student, Temple University"},{"name":"Dr. Emre Demirezen","aff":"Assistant Professor, University of Florida"},{"name":"Dr. Subodha Kumar","aff":"Professor, Temple University"}],"order":2},{"id":"136-0770","title":"Strategic Competition in Refund Policies: Regular Refund vs. Returnless Refund","content":"This study examines how two competing firms strategically choose between Regular Refund and Returnless Refund. The analysis incorporates a game-theoretic framework where firms compete on pricing and refund policies in a market with consumers sensitive to price, convenience, and utility derived from refund mechanisms.","presenter":"Ms. Lei Song","authors":[{"name":"Ms. Lei Song","aff":"Student, Temple University"}],"order":3},{"id":"136-1259","title":"A Comparative Analysis of Display and Shopping Ads on Social Media Platforms","content":"Social media platforms increasingly integrate e-commerce with shopping ads, generating ad and commission revenue. This study compares profits, pricing, and ad amounts for shopping and display ads, finding shopping ads can be more profitable even if disliked. Key insights guide platforms in optimizing advertising and commission strategies for revenue growth.","presenter":"Ms. Jiayu Fan","authors":[{"name":"Ms. Jiayu Fan","aff":"Student, Temple University"},{"name":"Dr. Subodha Kumar","aff":"Professor, Temple University"}],"order":4}]},{"id":"s305","title":"Pharmaceutical Research, Development, and Regulation","track":"Healthcare Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"PIEDMONT","chairs":["Dr. Xueze Song"],"abstracts":[{"id":"136-1471","title":"Empowering Frontline Health Workers to Manage Stock-outs: Evidence from Indonesia","content":"Through a collaboration with JSI Research &amp; Training Institute, Inc., we gain access to fine-grained, proprietary data from approximately 17,000 health facilities across Indonesia. Leveraging these data, we evaluate the impact of a training program for frontline health workers aimed at reducing the shortages of reproductive health commodities.","presenter":"Prof. Amir Karimi","authors":[{"name":"Prof. Amir Karimi","aff":"Assistant Professor, University of Texas at San Antonio"},{"name":"Prof. Anant Mishra","aff":"Professor, University of Minnesota"},{"name":"Prof. Karthik V. Natarajan","aff":"Associate Professor, University of Minnesota"},{"name":"Prof. Kingshuk Sinha","aff":"Professor, University of Minnesota"}],"order":1},{"id":"136-1990","title":"Experimentation Levels and Social Welfare under FDA's Flexible Approval Standards","content":"The FDA sets a uniform hypothesis test's approval standard for new drugs at the end of Phase III clinical trials. We study the impact of flexible approval standards on experimentation and social welfare when pharmaceutical companies (firms) are strategic, especially regarding the experimentation levels for the new drug.","presenter":"Dr. Amin Khademi","authors":[{"name":"Dr. Amin Khademi","aff":"Associate Professor, Clemson University"},{"name":"Dr. Hamed Rahimian","aff":"Assistant Professor, Clemson"},{"name":"Dr. Saeid Delshad","aff":"Post Doc/Researcher, University of California Davis"}],"order":2},{"id":"136-1229","title":"Turning a Blind Eye: Buyer-Supplier Relationships and Drug Diversion in the Prescription Opioid Supply Chain","content":"The opioid crisis is driven by the oversupply of prescription opioids. While the DEA has blamed large national suppliers for their role in the oversupply of drugs, we show that other distribution channels, such as small suppliers and self-distribution through vertically integrated supply structures also contribute significantly to the crisis.","presenter":"Mr. Iman Attari","authors":[{"name":"Mr. Iman Attari","aff":"Student, Indiana University Bloomington"},{"name":"Dr. Robert Wiedmer","aff":"Assistant Professor, Arizona State University Tempe"},{"name":"Prof. Jonathan Helm","aff":"Professor, Kelley School of Business"},{"name":"Prof. Jorge Mejia","aff":"Associate Professor, Indiana University"}],"order":3},{"id":"136-1737","title":"To Abandon or Not? Understanding the Impact of Participant Retention on Clinical Trial Outcomes","content":"The process of drug development is replete with significant risks and uncertainties, with as many as 12% of clinical trials terminated early. In this work, we study the impact of strategies to improve participant retention on clinical trial sponsor’s decision to terminate the clinical trial.","presenter":"Dr. Xueze Song","authors":[{"name":"Dr. Xueze Song","aff":"Assistant Professor, The University of Alabama"},{"name":"Dr. Mili Mehrotra","aff":"Associate Professor, University of Illinois"},{"name":"Dr. Ujjal Mukherjee","aff":"Associate Professor, University of Illinois Urbana-Champaign"},{"name":"Dr. Tharanga Rajapakshe","aff":"Associate Professor, University of Florida"}],"order":4}]},{"id":"s318","title":"Experimentation and Causal Inference in Operations","track":"Revenue Management and Pricing","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"MARIETTA","chairs":["Dr. Tu Ni"],"abstracts":[{"id":"136-0314","title":"Deep Learning for Policy Targeting with Continuous Treatment","content":"Experimentation is vital for decision making. We propose a double machine learning framework to optimize continuous treatment policies using discrete experimentation data, with theoretical guarantees for asymptotic unbiasedness and regret bounds. Tested on a leading short-video platform, our method outperforms benchmarks in policy value estimation and personalized policy targeting.","presenter":"Ms. Zhiqi Zhang","authors":[{"name":"Ms. Zhiqi Zhang","aff":"Student, Washington University in St. Louis"},{"name":"Ms. Zhiyu Zeng","aff":"Post Doc/Researcher, Washington University in St. Louis"},{"name":"Prof. Ruohan Zhan","aff":"Assistant Professor, Hong Kong University of Science and Technology"},{"name":"Prof. Dennis Zhang","aff":"Associate Professor, Washington University in St. Louis"}],"order":1},{"id":"136-1187","title":"Pricing Experiments in Matching Marketplaces under Interference: Designs and Estimators","content":"We consider pricing interventions, in which a platform adjusts base pricing levels in order to increase demand. Our model sheds light on two sources of interference: diminishing returns due to scarce supply and competition between discounted and undiscounted units. We propose a shadow price technique to reduce bias.","presenter":"Dr. Arthur Delarue","authors":[{"name":"Dr. Arthur Delarue","aff":"Assistant Professor, Georgia Institute of Technology"},{"name":"Mr. Kleanthis Karakolios","aff":"Student, Georgia Institute of Technology"}],"order":2},{"id":"136-1109","title":"Estimating Ship Arrival Rates and Charterer Taste Coefficients with Unobservable Balking","content":"We jointly estimate ship arrival and service rates, and charterer taste coefficients at a port terminal using an M/M/1 queue and a multinomial logit model. We formulate the estimation problem as a maximum likelihood estimation model, characterize the identification conditions, and develop algorithms evaluated against benchmarks.","presenter":"Ms. Weikun Xu","authors":[{"name":"Ms. Weikun Xu","aff":"Student, Washington State University"},{"name":"Dr. Xinchang Wang","aff":"Assistant Professor, Washington State University"}],"order":3},{"id":"136-1003","title":"Data Sharing in Inventory Experiments: a Comparative Study of Design-based and Sampling-based Inference","content":"This paper studies the benefit of data sharing for estimating the causal effect in inventory experiments, with a focus on the basic newsvendor setting to uncover the key properties underneath the problem structure of inventory management.","presenter":"Dr. Tu Ni","authors":[{"name":"Dr. Tu Ni","aff":"Post Doc/Researcher, Harvard Business School"}],"order":4}]},{"id":"s335","title":"Empirical and Behavioral perspectives with lab experiments","track":"Behavioral Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"EMBASSY D","chairs":["Dr. NESLIHAN OZLU"],"abstracts":[{"id":"136-0718","title":"Behavioral Interventions Encouraging Telemedicine Adoption in Epidemic Contexts","content":"We focus on telemedicine’s role in mitigating infection risks during epidemics and its convenience in eliminating transportation-related efforts, making it easier to integrate into patients’ schedules. We conduct behavioral experiments and show the effectiveness of informational interventions (nudges) for demand management in a multichannel healthcare setting.","presenter":"Ms. Elif Karul","authors":[{"name":"Ms. Elif Karul","aff":"Student, Koç University"},{"name":"Prof. Zeynep Aksin","aff":"Professor, Koc University"},{"name":"Dr. Erhun Özkan","aff":"Assistant Professor, Koç University"}],"order":1},{"id":"136-0379","title":"Creative Task Constraints and Knowledge Worker Productivity","content":"Knowledge workers must often create original output that meets a usefulness constraint. Our paper experimentally shows that increasing usefulness constraints can surprisingly result in poor participant performance that lacks in originality and/or usefulness. In such cases, task performance can improve by “artificially” lowering the constraint or altering the task goal.","presenter":"Prof. Samer Charbaji","authors":[{"name":"Prof. Samer Charbaji","aff":"Assistant Professor, New York Institute of Technology"},{"name":"Prof. Roman Kapuscinski","aff":"Professor, University of Michigan Ann Arbor"},{"name":"Prof. Stephen Leider","aff":"Professor, University of Michigan Ann Arbor"}],"order":2},{"id":"136-1619","title":"Waiting Games: Consumer Response to Shrouded Wait Times on Ride-Hailing Platforms","content":"We examine consumer responses to wait time transparency on ride-hailing platforms. We develop a theoretical model to evaluate adoption and firm performance under truthful, \"dripped\", and \"batched\" communication strategies for increased wait times. An experiment reveals “worse-before-better” outcomes for transparency, emphasizing its nuanced impacts on user behavior and firm performance.","presenter":"Dr. Jose Lopez","authors":[{"name":"Dr. Jose Lopez","aff":"Assistant Professor, Texas A&amp;M University"},{"name":"Prof. Edward Anderson","aff":"Professor, University of Texas Austin"}],"order":3}]},{"id":"s341","title":"Productivity Improvement: Novel Methods and Ideas","track":"Manufacturing Operations","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"ROSWELL","chairs":["Dr. Qazi Kabir"],"abstracts":[{"id":"136-0916","title":"Flow Shops With Reentry: The Total Weighted Completion Time Objective","content":"We consider a flow shop environment in which each job must loop through all machines in the shop multiple times before completion. This environment has industrial applications, e.g., in semiconductor manufacturing. The objective we consider is minimizing the total weighted completion time. We analyze priority rules and show performance guarantees.","presenter":"Mr. Nicklas Klein","authors":[{"name":"Mr. Maximilian von Aspern","aff":"Student, Technical University of Munich"},{"name":"Mr. Felix Buld","aff":"Student, Technical University of Munich"},{"name":"Mr. Nicklas Klein","aff":"Student, University of Bern"},{"name":"Prof. Michael Pinedo","aff":"Professor, New York University"}],"order":1},{"id":"136-1459","title":"Increasing Productivity of a Manufacturing Facility by Using Modular Battery for Automated Guided Vehicles","content":"Modular batteries, where one can swap a depleted module of the battery instead of swapping the whole battery, have the potential to improve the productivity of a manufacturing facility that uses battery-driven automated guided vehicles for materials management. This research will explore such potential of modular batteries through simulation experiment.","presenter":"Dr. Qazi Kabir","authors":[{"name":"Dr. Qazi Kabir","aff":"Assistant Professor, Rowan University"},{"name":"Dr. Bo Lan","aff":"Assistant Professor, Indiana State University"},{"name":"Dr. Yoshinori Suzuki","aff":"Professor, Iowa State University"}],"order":2},{"id":"136-0423","title":"Assessing the robustness of order release mechanisms in the semiconductor manufacturing industry","content":"Electronic chips are crucial in a digital economy, but manufacturers face challenges meeting demand. We evaluate the robustness of various order release mechanisms in semiconductor manufacturing regarding cost and on-time delivery performance. We simulate large-scale facilities with varying demand to compare against prior findings for a smaller model favoring LUMS-COR.","presenter":"Prof. Nico Schmid","authors":[{"name":"Prof. Nico Schmid","aff":"Assistant Professor, IESEG School of Management"},{"name":"Prof. Lars Mönch","aff":"Professor, Hagen"}],"order":3}]},{"id":"s344","title":"Additive Manufacturing","track":"Supply Chain Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"EMBASSY A","chairs":["Dr. MOHAMMAD ARBABIAN","Prof. Mirco Peron"],"abstracts":[{"id":"136-2008","title":"Predictive Spare Parts Printing Using Sensor Information","content":"We investigate predictive spare parts printing using sensor data to benefit from additive manufacturing for faster supply. Our Bayesian approach assesses component failure, guiding decisions between printing and supplier replenishment. Through a Markov decision process and numerical analysis, we analyze the trade-offs of additive manufacturing in spare parts provisioning.","presenter":"Dr. Rob Basten","authors":[{"name":"Prof. Ipek Tanil","aff":"Professor, Eindhoven University of Technology"},{"name":"Dr. Collin Drent","aff":"Assistant Professor, Eindhoven University of Technology"},{"name":"Dr. Rob Basten","aff":"Associate Professor, Eindhoven University of Technology"}],"order":1},{"id":"136-2011","title":"2Virgin or recycled powder for producing Additive Manufacturing spare parts? An economic analysis","content":"This paper examines the integration of Additive Manufacturing (AM) into decentralized supply chains using a Stackelberg game framework. It derives equilibria under capacity constraints for single- and multi-product scenarios, revealing critical cost thresholds for AM adoption. Study highlights AM's viability despite higher costs, emphasizing capacity's role in strategic decisions.","presenter":"Dr. MOHAMMAD ARBABIAN","authors":[{"name":"Dr. MOHAMMAD ARBABIAN","aff":"Assistant Professor, University of Portland"}],"order":2},{"id":"136-2010","title":"Virgin or recycled powder for producing Additive Manufacturing spare parts? An economic analysis","content":"Additive Manufacturing for spare parts faces high costs due to machines and raw materials. Using recycled powders reduces costs but compromises part quality and reliability. This study explores when using recycled powders is economically viable, emphasizing quality preservation over cost reduction, with future scenarios suggesting increasing viability.","presenter":"Prof. Mirco Peron","authors":[{"name":"Prof. Mirco Peron","aff":"Assistant Professor, NEOMA Business School"},{"name":"Prof. Luigi Panza","aff":"Professor, Politecnico of Torino"}],"order":3}]},{"id":"s346","title":"Machine Learning and Predictive Analytics in Driving Healthcare Outcomes","track":"Healthcare Analytics","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"INMAN","chairs":["Mr. Junjie Luo"],"abstracts":[{"id":"136-1124","title":"Explaining the Heterogeneous Impact of Teaching Hospitals on Pneumonia and Influenza Readmissions","content":"This work proposes a framework for identifying differences in health outcome variation that integrates stratification strategies and sources of outcome variation (patient and hospital). Teaching hospitals are well-resourced. We leverage our framework and causal ML to identify patient subgroups admitted to teaching hospitals more and less likely to be readmitted.","presenter":"Ms. Xuan Gao","authors":[{"name":"Ms. Xuan Gao","aff":"Student, Georgia State University"},{"name":"Dr. Aaron Baird","aff":"Associate Professor, Georgia State University"},{"name":"Prof. Yusen Xia","aff":"Professor, Georgia State University"}],"order":1},{"id":"136-1845","title":"Exploring Opioid Prescription Patterns and Overdose Rates in South Carolina (2017–2021)","content":"With opioid overdose rates on the rise, we aimed to develop a county-level risk stratification that specifically focused on access to medications for opioid use disorder (MOUDs) and high overdose rates. We examined over 15 million records from the South Carolina Prescription Tracking System (SCRIPTS) across 46 counties.","presenter":"Mr. Amir Sadeghi","authors":[{"name":"Mr. Amirreza Sahebi Fakhrabad","aff":"Student, North Carolina State University"},{"name":"Mr. Amir Sadeghi","aff":"Student, North Carolina State University"},{"name":"Dr. Robert Handfield","aff":"Professor, North Carolina State University"}],"order":2},{"id":"136-1185","title":"A fluid-mediated agent-based model for infection transmission in airplane cabin","content":"We present a fluid-mediated agent-based model to simulate infection transmission in an outbreak of COVID-19 in an airplane cabin. By integrating airflow dynamics, the agent-based model predicts the spread of airborne diseases, providing insights into improving the disease control measurement and enhancing public health strategies in the indoor environments.","presenter":"Dr. Shuyi Wang","authors":[{"name":"Dr. Han Yu","aff":"Post Doc/Researcher, Tianjin University"},{"name":"Dr. Shuyi Wang","aff":"Lecturer, University of Science and Technology Beijing"}],"order":3},{"id":"136-1495","title":"Fairness Evaluations on Continuous Glucose Monitor Large Sensor Models","content":"Foundation models are essential for Generative AI and are important in healthcare practice. Besides LLM, large sensor models (LSMs) pretrained on humans' continuous monitoring data, like CGM, achieve exceptional performance in health prediction. However, no fairness evaluation of these models has been conducted. We reveal fairness issues in the CGM-LSMs.","presenter":"Mr. Junjie Luo","authors":[{"name":"Mr. Junjie Luo","aff":"Student, School of Medicine"},{"name":"Prof. Ritu Agarwal","aff":"Professor, Carey Business School"},{"name":"Prof. Guodong \"Gordon\" Gao","aff":"Professor, Carey Business School"}],"order":4}]},{"id":"s356","title":"Tutorial: Using AI/ML for Causal Inference","track":"Information Systems and Operations Management","type":"Tutorial","invited":"Invited","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"EMBASSY E","chairs":["Prof. Amit Mehra","Prof. Guihua Wang"],"abstracts":[{"id":"136-2114","title":"Tutorial: Using AI/ML for Causal Inference Schedule on May 11 afternoon","content":"Machine learning approaches are well-placed to address existing challenges in causal inference. In this tutorial session, we discuss some recent approaches like Double Machine Learning which corrects for bias due to functional misspecifications and Causal Machine Learning which incorporates empirical econometrics into machine learning for heterogeneous treatment effect analysis.","presenter":"Prof. Amit Mehra","authors":[{"name":"Prof. Amit Mehra","aff":"Professor, University of Texas Dallas"},{"name":"Prof. Guihua Wang","aff":"Associate Professor, University of Texas Dallas"}],"order":1}]},{"id":"s374","title":"Order Selection and Delivery Considerations","track":"Retail Operations","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"FAIRLIE","chairs":["Dr. Annibal Sodero"],"abstracts":[{"id":"136-0435","title":"Robot routing and order selection strategies for omni-channel warehouses","content":"To manage demand fluctuations and reduce picker fatigue, Autonomous Mobile Robots are increasingly being used in omni-channel warehouses. Pickers and robots collaborate to improve warehouse productivity. For such systems, we develop a dynamic program to obtain optimal robot routing and order selection policies and thereby minimize long-term operational costs.","presenter":"Prof. Debjit Roy","authors":[{"name":"Prof. Debjit Roy","aff":"Professor, Indian Institute of Management Ahmedabad"},{"name":"Ms. Rashika Gupta","aff":"Student, IIMA"}],"order":1},{"id":"136-0610","title":"Examining retail store strategies in the era of quick commerce","content":"We investigate the optimal partnership strategy for small retailers in a developing economy: managing own deliveries, or partnering with Quick Commerce (QCom) platforms for delivery. We use a dynamic game of asymmetric information, where the platform lacks knowledge of a retailer’s type. We validate the results through an empirical investigation.","presenter":"Mr. Pranesh Saisridhar","authors":[{"name":"Mr. Pranesh Saisridhar","aff":"Student, Indian Institute of Management Calcutta"},{"name":"Dr. Indranil Biswas","aff":"Associate Professor, NEOMA Business School"},{"name":"Prof. Sumanta Basu","aff":"Professor, Indian Institute of Management Calcutta"},{"name":"Prof. Balram Avittathur","aff":"Professor, Indian Institute of Management Calcutta"}],"order":2},{"id":"136-0691","title":"Blame attribution when crowdsourced delivery fails: consumer perceptions in tetradic arrangements in online grocery shopping","content":"Crowdsourced delivery of online grocery purchases takes place in a tetradic arrangement involving a consumer, a retailer, a platform, and a crowdsourced worker. This study investigates who the consumer blames when there is a failure in the delivery.","presenter":"Dr. Annibal Sodero","authors":[{"name":"Dr. Annibal Sodero","aff":"Assistant Professor, Ohio State University"},{"name":"Dr. Vince Castillo","aff":"Assistant Professor, Ohio State University"}],"order":3},{"id":"136-0741","title":"Effort Competition in Online Food Delivery Platforms: A Game-Theoretic Analysis","content":"This study presents a game-theoretic model analyzing effort competition in online food delivery. It explores the impact of platform-induced quality enhancements, cloud kitchens, and revenue-sharing contracts on customer differentiation and demand. The model examines the dynamics between platforms and restaurants to optimize operational outcomes.","presenter":"Dr. Bhavinkumar Jaswantlal Shah","authors":[{"name":"Dr. Bhavinkumar Jaswantlal Shah","aff":"Professor, Indian Institute of Management Indore"},{"name":"Dr. Arvind Shroff","aff":"Assistant Professor, Indian Institute of Management Lucknow"}],"order":4}]},{"id":"s388","title":"Solar Panels and Energy Markets","track":"Energy and Natural Resource Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"TECHWOOD","chairs":["Prof. Cheng Guo"],"abstracts":[{"id":"136-0952","title":"Counterfactual Insights into Bridging Poverty Gaps with Sustainable Solar PV Systems for the Future","content":"This study investigates the role of solar PV systems in poverty alleviation, aiming to uncover gaps in the existing literature through a counterfactual thematic review. It explores the co-benefits of solar energy in advancing SDGs and proposes future research directions to further understand its potential impact on sustainable development.","presenter":"Ms. Yagmur Arioz","authors":[{"name":"Ms. Yagmur Arioz","aff":"Student, Ankara Yildirim Beyazit University"},{"name":"Prof. Joseph Sarkis","aff":"Professor, Worcester Polytechnic Institute"},{"name":"Prof. Yildizbasi Abdullah","aff":"Post Doc/Researcher, Worcester Polytechnic Institute"}],"order":1},{"id":"136-0963","title":"Benefit Evaluation in the Circular Solar PV Supply Chain: A Model-Based Approach","content":"This paper presents a model-based approach to evaluate the benefits of a circular solar PV supply chain, focusing on environmental, economic, and social impacts. It aims to provide a framework for assessing the sustainability and resilience of solar PV systems within a circular economy context.","presenter":"Ms. Yagmur Arioz","authors":[{"name":"Ms. Yagmur Arioz","aff":"Student, Ankara Yildirim Beyazit University"},{"name":"Dr. Ibrahim Yilmaz","aff":"Associate Professor, Ankara Yildirim Beyazit University"}],"order":2},{"id":"136-1280","title":"Copositive Duality for Discrete Energy Markets","content":"Nonconvex mixed-binary quadratic programs can be equivalently written as copositive programs (COPs), which are convex. We apply this perspective by writing nonconvex energy market problems as COPs, which are used to design new and revenue-adequate pricing mechanisms. We also design a novel cutting-plane algorithm for solving copositive programs exactly.\r\n","presenter":"Prof. Cheng Guo","authors":[{"name":"Prof. Cheng Guo","aff":"Assistant Professor, Clemson University"},{"name":"Prof. Merve Bodur","aff":"Associate Professor, University of Edinburgh"},{"name":"Prof. Joshua Taylor","aff":"Associate Professor, New Jersey Institute of Technology"}],"order":3}]},{"id":"s398","title":"New Models in Closed-loop Supply Chains","track":"Sustainable Operations Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"EMBASSY H","chairs":["Mr. Hongzhen Li"],"abstracts":[{"id":"136-1168","title":"Closed-loop supply chain network with interaction of forward and reverse logistics including design for remanufactureability","content":"The proposed closed-loop supply chain network model consists of two supply chain networks, namely the forward supply chain and the reverse supply chain. Manufacturers in the forward supply chain produce products that have different sustainability/remanufacturing levels. The network model captures product design and the interaction between the two heterogeneous products.","presenter":"Dr. Min Yu","authors":[{"name":"Prof. Qiang Qiang","aff":"Associate Professor, Penn State University Great Valley"},{"name":"Dr. Min Yu","aff":"Associate Professor, University of Portland"},{"name":"Dr. Ke Ke","aff":"Professor, Central Washington University"}],"order":1},{"id":"136-2036","title":"Consumer Acceptance and Preferences Based on Environment Knowledge to Inform Remanufacturing End-of-Life Approach","content":"Drawing on data from over 3,000 respondents, we examine the economic costs of electric vehicle battery remanufacturing from a systems perspective and advance a theoretical framework from a case study focused on the customer perspective, incorporating variables such as customer perceptions influenced by environmental awareness, technological advancements, and pollution taxation.","presenter":"Dr. Okechukwu Okorie","authors":[{"name":"Dr. Okechukwu Okorie","aff":"Senior Lecturer, The University of Manchester"},{"name":"Dr. Franklin Madubuko","aff":"Associate Professor, Ulster University"},{"name":"Mr. Yogendra Singh","aff":"Student, University of Exeter"},{"name":"Prof. Nnaemeka Emodi","aff":"Professor, University of Queensland"},{"name":"Prof. Martha Omolo","aff":"Professor, Exeter Business School"}],"order":2},{"id":"136-0790","title":"Contextual Uncertainties to Predict: Data-Driven Stochastic Optimization in Reverse Logistics Network Design","content":"This paper presents an integrated approach to optimize Municipal Solid Waste recycling networks. It introduces an Empirical Residuals Sample Average Approximation (ER-SAA) method to predict recycling supply and optimize logistics, while incorporating a continuous approximation for waste collection routing. The study demonstrates actionable policy recommendations through a Massachusetts case study.","presenter":"Mr. Austin Saragih","authors":[{"name":"Mr. Austin Saragih","aff":"Student, Massachusetts Institute of Technology"},{"name":"Dr. Milena Janjevic","aff":"Post Doc/Researcher, Massachusetts Institute of Technology"},{"name":"Prof. Yossi Sheffi","aff":"Professor, Massachusetts Institute of Technology"}],"order":3},{"id":"136-0526","title":"Product Acquisition for Remanufacturing","content":"We develop models to analyze the process of acquiring used products for remanufacturing. We perform numerical analyses to show the applicability of our models.\r\n","presenter":"Dr. Akshay Mutha","authors":[{"name":"Dr. Akshay Mutha","aff":"Associate Professor, University of Vermont"},{"name":"Dr. Daewon Sun","aff":"Professor, University of Notre Dame"},{"name":"Prof. Jennifer Ryan","aff":"Professor, University of Nebraska Lincoln"},{"name":"Dr. Zhaolin Li","aff":"Senior Lecturer, ."}],"order":4}]},{"id":"s404","title":"Operational Excellence Through Digital Transformation","track":"Operational Excellence","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"BAKER","chairs":["Dr. Bart Lameijer"],"abstracts":[{"id":"136-0204","title":"Direct Digital, On-site, and Mobile Manufacturing: The Value of Mobile Digital Factories","content":"Mobile digital factories are production units equipped with direct digital manufacturing technology that can be set-up at any location. Our qualitative case data, including 32 semi-structured interviews and secondary data, allow us to build theory on how mobile digital factories provide value in realizing efficient and flexible supply chains.","presenter":"Ms. Jasmina Holst","authors":[{"name":"Ms. Jasmina Holst","aff":"Post Doc/Researcher, ETH Zürich"},{"name":"Prof. Kai Hoberg","aff":"Professor, Kühne Logistics University"},{"name":"Prof. Jan Holmström","aff":"Professor, Aalto University"}],"order":1},{"id":"136-0155","title":"Data analytics and firm performance: applying an operations management perspective","content":"Despite the high expectations around data analytics (DA), understanding of the mechanisms that drive value creation from adopting DA is inadequate. This research studies intermediate mechanisms that can explain the value created by DA, focusing on the use of DA in operations management.","presenter":"Dr. Bart Lameijer","authors":[{"name":"Dr. Bart Lameijer","aff":"Assistant Professor, University of Amsterdam"},{"name":"Prof. Jeroen de Mast","aff":"Professor, University of Amsterdam"},{"name":"Dr. Leopoldo Gutierrez","aff":"Professor, University of Granada"},{"name":"Dr. Gopesh Anand","aff":"Professor, University of Illinois Urbana-Champaign"}],"order":2},{"id":"136-2012","title":"Lean Manufacturing Principles and Institutional Pressures on Adoption of Digital Transformation in SMEs","content":"This paper investigates the intersection of Lean Manufacturing (LM) principles and Digital Transformation (DT) technologies through the lens of institutional theory. By analyzing their combined impact on operational performance, it offers theoretical expansion by exploring how implementation of LM practices supports DT technologies in SMEs.","presenter":"Ms. Aysegul Yilmaz","authors":[{"name":"Ms. Aysegul Yilmaz","aff":"Student, Brunel University"},{"name":"Prof. Manoj Dora","aff":"Professor, Anglia Ruskin University"}],"order":3}]},{"id":"s418","title":"Platform Economics and Market Dynamics","track":"Digital Platforms, Innovations and Transformations","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"GREENBRIAR","chairs":["Mr. Emin Ozyoruk"],"abstracts":[{"id":"136-1759","title":"The Competition and Cooperation Game of Platform Services between e-CNY and Third-party Payment Platform","content":"China's digital currency has its own platform and can also be mediated by third-party payment platforms. We establish competition and coopetition models considering service rate, consumer payment preference and platform scenario richness. Novel conclusions about fee structures, agency channel, and subsidy strategies address the theoretical gaps and practical voids.","presenter":"Ms. yuhang Liu","authors":[{"name":"Ms. yuhang Liu","aff":"Student, Tianjin Universsity"},{"name":"Mr. Qingqi Long","aff":"Professor, Zhejiang University of Finance &amp; Economics"},{"name":"Dr. Haiyang Feng","aff":"Professor, Tianjin University"}],"order":1},{"id":"136-0617","title":"Slippage in AMM Markets","content":"In this paper, we 1) explain the key differences between Automated Market Making (AMM) used in crypto trading and traditional limit-order book-based market making, 2) show crypto price formation step-by-step, and 3) derive a closed-form solution for ex-ante crypto slippage estimation to extract better profits from crypto trading.","presenter":"Ms. Irene Aldridge","authors":[{"name":"Ms. Irene Aldridge","aff":"Student, Cornell University"}],"order":2},{"id":"136-0910","title":"Effect of Serial Crowdfunders’ Prior Project Outcome Disclosure on the Funding Performance of Subsequent Projects","content":"This paper applies signaling theory to analyze 68,875 Kickstarter projects, exploring how prior project outcome disclosure influences subsequent project funding performance in serial crowdfunding. It finds positive effects, particularly when prior and subsequent projects are less similar. These insights significantly contribute to the operational management and practices of crowdfunding projects.","presenter":"Ms. Jiayue Wang","authors":[{"name":"Ms. Jiayue Wang","aff":"Student, Renmin University of China"},{"name":"Mr. Changqing Zhuo","aff":"Student, Renmin University of China"},{"name":"Dr. Shouwang Lu","aff":"Assistant Professor, Beijing Jiaotong University"},{"name":"Prof. Kanliang Wang","aff":"Professor, Renmin University of China"}],"order":3},{"id":"136-1093","title":"Pricing and Capacity Decisions in Platform Competition with Network Externalities","content":"We study platform competition in ride-hailing. Riders are sensitive to price and delay, drivers prefer high wages and utilization, and platforms gain efficiency from density. Platforms choose full prices and benefit from economies of scale. We show the existence and uniqueness of equilibrium and analyze oligopoly and entry limits.","presenter":"Mr. Emin Ozyoruk","authors":[{"name":"Prof. John Birge","aff":"Professor, University of Chicago"},{"name":"Mr. Emin Ozyoruk","aff":"Student, University of Chicago"}],"order":4}]},{"id":"s425","title":"Disruptive Technologies and Supply Chain Operations","track":"Supply Chain Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"GRAND HALL EAST A","chairs":["Dr. Kiarash Sadeghi R"],"abstracts":[{"id":"136-1277","title":"AI-driven Contract Design for Professional Services","content":"Professional service contracts often face expertise asymmetry. We develop a performance-based contract framework with AI-driven monitoring systems, which improves alignment between client and provider incentives and enhances contract efficiency. This study advances our understanding of contract theory and practice.","presenter":"Ms. Jiayu Tian","authors":[{"name":"Ms. Jiayu Tian","aff":"Student, Hong Kong University of Science and Technology"},{"name":"Prof. Ting Luo","aff":"Associate Professor, California State University Fullerton"}],"order":1},{"id":"136-0286","title":"Factors influencing delivery workers' willingness to use of Autonomous Delivery Robots: Motivators and inhibitors","content":"AI and Self-driving technology are advancing rapidly, including Autonomous Delivery Robots (ADRs). ADRs have attracted considerable interest from both academia and industry. This study explores factors influencing delivery workers' acceptance of ADRs in the workplace, addressing a key research gap on employee perspectives in new technology adoption.","presenter":"Dr. Jason Shin","authors":[{"name":"Dr. Jason Shin","aff":"Assistant Professor, Mississippi State University"},{"name":"Dr. Jutong Wen","aff":"Assistant Professor, Farmingdale State College"},{"name":"Mr. Zhao Liu","aff":"Student, Mississippi State University"},{"name":"Ms. Xinwei Liu","aff":"Student, Mississippi State University"},{"name":"Dr. Lu He","aff":"Lecturer, Mississippi State University"}],"order":2},{"id":"136-0970","title":"Technology-Driven Strategies to Overcome Digitalization Barriers for Resilient Road Freight Transportation Evolution","content":"Digitalization in road freight transportation faces challenges like lack of vision, skilled employees, and infrastructure. This study uses Fuzzy-DEMATEL to identify barriers, calculates their impacts, and employs a mathematical model to optimize resilience strategies under budget constraints. Blockchain technology emerges as crucial for addressing infrastructure and reliability issues, guiding managerial","presenter":"Mr. Rohit Yadav","authors":[{"name":"Mr. Rohit Yadav","aff":"Student, IIM Ranchi"},{"name":"Dr. Krishna Dadsena","aff":"Assistant Professor, Indian Institute of Management Ranchi"}],"order":3},{"id":"136-1696","title":"The Effects of Blockchain-Based Information Systems on Cyber-Resilience and Sustainability in Supply Chains","content":"Blockchain can help in automatic and real-time response to disruptions and finding more sustainable solutions. This paper follows the precise rule of blockchain in a cyber-resilient and sustainable supply chain by answering this question: How can blockchain-based information systems impact sustainability and cyber-resilience in supply chains?","presenter":"Dr. Kiarash Sadeghi R","authors":[{"name":"Ms. Saba Rezaeinejad","aff":"Student, University of North Texas"},{"name":"Dr. Kiarash Sadeghi R","aff":"Assistant Professor, North Carolina A&amp;T State University"},{"name":"Prof. Brian Sauser","aff":"Professor, University of North Texas"}],"order":4}]},{"id":"s434","title":"Contemporary Issues in Supply Chain Management","track":"Supply Chain Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-11","dow":"Sunday","day":11,"mon":"May"},"start":"4:45 PM","end":"6:15 PM","startMin":1005,"room":"EMBASSY G","chairs":["Prof. Julia Hartmann"],"abstracts":[{"id":"136-0496","title":"Supply Chain Learning in the era of Generalised Artificial Intelligence: Α systematic literature review","content":"This systematic literature review examines supply chain learning (SCL), highlighting its conceptual foundations, methodologies, and key themes. Utilizing articles from Web of Science and Scopus, it identifies five key themes, including technological enablers and performance outcomes, and proposes a research agenda emphasizing sustainability and advanced technologies including Generalised AI.","presenter":"Prof. Ilias Vlachos","authors":[{"name":"Prof. Ilias Vlachos","aff":"Professor, Excelia Business School"}],"order":1},{"id":"136-1841","title":"The effectiveness of Discrete Event Simulation Games in Teaching Supply Chain Management","content":"This study examines the effectiveness of a discrete event simulation game in teaching supply chain management to college students. We use an experimental approach to compare learning outcomes between simulation participants and those taught through traditional lectures using an experimental approach. We also examine participants' team work development.","presenter":"Dr. Ehsan Elahi","authors":[{"name":"Dr. Ehsan Elahi","aff":"Associate Professor, University of Massachusetts Boston"},{"name":"Dr. Babak Rezaee","aff":"Assistant Professor, Ferdowsi University of Mashhad"}],"order":2},{"id":"136-0582","title":"The Strategic Impact of Disruption Information Sharing on Injectable Drug Supply","content":"In the US, there are frequent shortages of sterile injectable drugs. We study the role of cross-supply chain visibility of disruption status that the FDA imposes on firms. We show that information sharing is a strategic substitute for proactive production, which may adversely lead to lower drug supply.","presenter":"Prof. Parshuram Hotkar","authors":[{"name":"Prof. Parshuram Hotkar","aff":"Assistant Professor, Indian School of Business"},{"name":"Prof. Diwakar Gupta","aff":"Professor, University of Texas Austin"}],"order":3},{"id":"136-1926","title":"Benefits of Extreme Political Stability and Instability of Suppliers Countries for Firms: The U-Shaped Relationship","content":"We examine how suppliers' political instability affects buyer firms' performance and find a U-shaped relationship. This effect varies by industry, with high productivity industries showing a stronger U-shape and durable goods industries showing the opposite.","presenter":"Dr. Jafar Namdar","authors":[{"name":"Dr. Jafar Namdar","aff":"Assistant Professor, Michigan State University"},{"name":"Dr. Sachin Modi","aff":"Professor, University of Cincinnati"},{"name":"Prof. Arash Azadegan","aff":"Professor, Rutgers University"},{"name":"Dr. Milad Baghersad","aff":"Assistant Professor, Florida Atlantic University"}],"order":4},{"id":"136-0596","title":"Harnessing Influence or Shifting Burdens? MNCs and Governance of Supplier Emissions in Chains","content":"This study explores how multinational corporations (MNCs) improve suppliers' environmental performance, focusing on Scope 1 GHG emissions. Using sustainable relational governance (SRG) as a strategic capability, we demonstrate its role in reducing supplier emissions across global supply chains, even amid regulatory disparities, contributing to global SCM literature.","presenter":"Prof. Julia Hartmann","authors":[{"name":"Prof. Julia Hartmann","aff":"Professor, European Business School"},{"name":"Dr. Karoline Bax","aff":"Post Doc/Researcher, Tum School of Management"},{"name":"Prof. Sandra Paterlini","aff":"Professor, University of Trento"}],"order":5}]},{"id":"s16","title":"Bridging the Gaps: Policies and Practices for Social and Environmental Sustainability","track":"POM and Community","type":"Regular","invited":"Invited","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY F","chairs":["Prof. Chengcheng Zhai"],"abstracts":[{"id":"136-0050","title":"Subsidizing Social Welfare Programs: Contracted Slots Or Vouchers?","content":"We study operational decision-making by profit-oriented service providers under two popular service-focused subsidy welfare programs—namely, vouchers and contracted slots. We analyze how provider- and market-related factors impact providers' participation decisions and identify conditions under which it is beneficial for the government to rely on vouchers versus contracted slots.","presenter":"Dr. Wei Wei","authors":[{"name":"Dr. Wei Wei","aff":"Assistant Professor, University of New Hampshire"},{"name":"Dr. Priyank Arora","aff":"Associate Professor, University of South Carolina"},{"name":"Dr. Senay Solak","aff":"Professor, University of Massachusetts Amherst"}],"order":1},{"id":"136-0059","title":"Going the Distance: The Impact of Commute on Gender Diversity in Public Service","content":"We analyze the extent to which longer commute distances deter female political participation and whether this effect varies according to the degree of flexibility and commensurate compensation provided by the position. Furthermore, we investigate policies that can lower the barrier to entry for women in politics.","presenter":"Prof. Vanitha Virudachalam","authors":[{"name":"Prof. Dawson Kaaua","aff":"Assistant Professor, Georgetown University"},{"name":"Prof. Vanitha Virudachalam","aff":"Assistant Professor, University of Illinois Urbana-Champaign"}],"order":2},{"id":"136-0634","title":"Equity in Health and Humanitarian Logistics: A People-Centered Perspective","content":"Tensions and even conflicts can arise if affected communities perceive the distribution of aid as inequitable. These perceptions are driven by people’s so-called distributional preferences. Using current examples, we conceptualize inclusive and people-centered approaches that account for distributional preferences.","presenter":"Dr. Thomas Breugem","authors":[{"name":"Dr. Thomas Breugem","aff":"Associate Professor, Tilburg University"},{"name":"Mr. Yu Fan","aff":"Post Doc/Researcher, University of Science and Technology of China"},{"name":"Prof. Andreas Gernert","aff":"Assistant Professor, Kuehne Logistics University"},{"name":"Prof. Luk Van Wassenhove","aff":"Professor, INSEAD"}],"order":3}]},{"id":"s140","title":"Empirical Research in Healthcare","track":"Empirical Research in Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY B","chairs":["Dr. Maria Ibanez"],"abstracts":[{"id":"136-0443","title":"Racial Disparity in Maternal Care and Operational Factors: Role of Specialization, Exposure, and Ownership","content":"Demographic disparities in the quality of obstetric care and outcomes persist over time. For instance, Black women continue to experience higher rates of labor complications. In this paper, we examine the role of hospital operational factors in moderating and accentuating the racial disparity for Black mothers.","presenter":"Mr. Max Yakovlev","authors":[{"name":"Mr. Max Yakovlev","aff":"Student, Owen School of Management"},{"name":"Dr. Maria Ibanez","aff":"Assistant Professor, Kellogg School of Management"}],"order":1},{"id":"136-0456","title":"On state- and time-dependent service processes in healthcare","content":"The empirical operations literature highlights state-dependency in service processes, focusing on patient length-of-stay (LOS) and workload. However, service processes are also time-dependent due to dynamic physician workloads. By analyzing instantaneous service rates instead of LOS, we reconcile conflicting findings, revealing intuitive relationships and demonstrating improved staffing performance in emergency departments.","presenter":"Prof. Hao Ding","authors":[{"name":"Prof. Hao Ding","aff":"Assistant Professor, Auburn University"},{"name":"Prof. Sokol Tushe","aff":"Assistant Professor, University of South Florida"},{"name":"Prof. Ruomeng Cui","aff":"Professor, Emory University"},{"name":"Prof. Donald Lee","aff":"Associate Professor, Emory University"}],"order":2},{"id":"136-0483","title":"First, Do No Harm: Do Staffing Shortages Drive Abuse and Malfeasance in U.S. Nursing Homes?","content":"Although it is known that understaffing can reduce the quality of nursing home services and care, we examine the under-recognized possibility that understaffing may harm patients by incentivizing unethical behavior. We empirically study the causal relationship between nursing home staffing and the use of antipsychotic medications.","presenter":"Prof. Minje Park","authors":[{"name":"Prof. Jong Myeong Lim","aff":"Assistant Professor, Miami Herbert Busienss School"},{"name":"Prof. Ken Moon","aff":"Assistant Professor, The Wharton School"},{"name":"Prof. Minje Park","aff":"Assistant Professor, The University of Hong Kong"}],"order":3},{"id":"136-1673","title":"Does Real Options Reasoning Benefit Firm Survival?","content":"This study examines whether real options reasoning (ROR), an appealing logic of decision-making, enhances operational performance. Analyzing five-year survival data from 259 Iranian small and medium-sized businesses, we identify firm imitation propensity, as opposed to innovation, as a key boundary condition influencing ROR's role in facilitating or constraining firm survival.","presenter":"Dr. Stephen Zhang","authors":[{"name":"Dr. Stephen Zhang","aff":"Professor, Baylor University"},{"name":"Dr. Daniel Chen","aff":"Professor, Baylor University"}],"order":4}]},{"id":"s180","title":"Analytics to Improve Welfare in Agricultural Supply Chains","track":"Agriculture and Food Supply Chains","type":"Regular","invited":"Invited","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"VININGS","chairs":["Prof. Somya Singhvi"],"abstracts":[{"id":"136-0537","title":"Cooperation among Small-Medium Enterprises in the Food Sector","content":"SMEs play a vital role in societal well-being and sustainability. However, their lack of resources and market power often hinders their impact and success. This study aims to assess how inter-organizational systems, designed to engender cooperative ecosystems, influence SME cooperation, competitiveness, and the well-being of their communities.","presenter":"Dr. Llord Brooks","authors":[{"name":"Dr. Llord Brooks","aff":"Assistant Professor, University of South Florida"},{"name":"Dr. Seckin Ozkul","aff":"Assistant Professor, University of South Florida"},{"name":"Dr. Sofía Pérez-Guzmán","aff":"Assistant Professor, Georgia Institute of Technology"},{"name":"Mrs. Valentina Castañeda Torres","aff":"Student, Georgia Institute of Technology"}],"order":1},{"id":"136-0769","title":"Fertilizer Pollution Mitigation is a Newsvendor Problem","content":"Reactive nitrogen loss from US Midwest corn and soybean farms, covering 50% of cropland and a third of global production, poses environmental and health risks. Despite proven benefits, adoption of precision fertilizer practices remains low. We analyze farmer-level returns using granular data from hundreds of acre-years of production (2000–2019).","presenter":"Dr. Canberk Ucel","authors":[{"name":"Dr. Canberk Ucel","aff":"Assistant Professor, ESSEC Business School"},{"name":"Prof. Enver Yucesan","aff":"Professor, INSEAD"}],"order":2},{"id":"136-1054","title":"Incentivizing Sustainable Agriculture under Bounded Rationality: Lab in the Field","content":"We study the design of incentive schemes for adoption of sustainable practices by farmers through a lab experiment with smallholder palm oil farmers in Indonesia. We show proper incentive design increases adoption under the same cost and propose a new behavioral contract design approach based on our findings.","presenter":"Ms. Yuan Shi","authors":[{"name":"Ms. Yuan Shi","aff":"Student, Massachusetts Institute of Technology"},{"name":"Dr. Iskandar Siregar","aff":"Professor, IPB University"},{"name":"Prof. Yanchong Zheng","aff":"Professor, Massachusetts Institute of Technology"}],"order":3},{"id":"136-1900","title":"Index-based yield protection for smallholder farmers","content":"Government subsidies are common in the agricultural sector to protect farmers from unexpected losses. This paper studies the design of an index-based yield protection policy that triggers subsidy payments to farmers when a pre-determined index (e.g., rainfall) predicts a low yield. Our analysis reveals several insights with policy implications.","presenter":"Prof. Can Zhang","authors":[{"name":"Mr. Kehan Lu","aff":"Student, Duke University Durham"},{"name":"Prof. Jing-Sheng (Jeannette) Song","aff":"Professor, Duke University Durham"},{"name":"Prof. Can Zhang","aff":"Associate Professor, Duke University"}],"order":5}]},{"id":"s216","title":"Advances in Collaborative NPD","track":"Product Innovation and Technology Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"COURTLAND","chairs":["Hossein Nikpayam"],"abstracts":[{"id":"136-0431","title":"An Experimental Analysis of Participation Restriction and Visibility in Parallel Innovation Contests","content":"We study parallel innovation contests that seek solutions from independent solvers. We analyze whether solvers should be restricted to participating in a single contest and, when restricted, whether they should observe which contests other solvers join.","presenter":"Mr. RAMAZAN KIZILYILDIRIM","authors":[{"name":"Mr. RAMAZAN KIZILYILDIRIM","aff":"Student, University College London"},{"name":"Dr. C. Gizem Korpeoglu","aff":"Assistant Professor, Eindhoven University of Technology"},{"name":"Dr. Ersin Korpeoglu","aff":"Associate Professor, University College London"},{"name":"Dr. Mirko Kremer","aff":"Professor, Frankfurt School of Finance &amp; Management"}],"order":1},{"id":"136-0467","title":"Designing Data Science Contests: The Role of Training vs Test Splits","content":"We present a theory of data science contests that focuses on how contest data split influences the participant behavior. Previous research suggests a balanced data split to enhance model consistency. We show that this middle-ground approach can invite sub-optimal submissions, preventing the host from accurately identifying the best model.","presenter":"Ms. Ping-Chieh Huang","authors":[{"name":"Ms. Ping-Chieh Huang","aff":"Student, University of California, San Diego"},{"name":"Prof. Zhe Zhang","aff":"Assistant Professor, Rady School of Management"},{"name":"Prof. Sanjiv Erat","aff":"Associate Professor, Rady School of Management"}],"order":2},{"id":"136-0796","title":"Small and Medium Enterprises in Open Innovation","content":"We develop a game-theoretic model exploring SMEs' innovation strategies, focusing on risk aversion and capital costs that hinder innovation. Collaborating with institutes or suppliers impacts effort and launch inefficiencies differently. We determine whether SMEs choose to engage in open innovation with institutes or suppliers based on the innovation characteristics.","presenter":"Ms. Gaoyu Xie","authors":[{"name":"Ms. Gaoyu Xie","aff":"Student, George Washington University"},{"name":"Prof. Pascale Crama","aff":"Professor, Singapore Management University"},{"name":"Prof. Janne Kettunen","aff":"Associate Professor, George Washington University"}],"order":3}]},{"id":"s251","title":"Addressing Scheduling Issues in Logistics","track":"Aviation, Transportation, and Logistics Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"FAIRLIE","chairs":["Dr. Yunxia Zhu","Mr. Kerim U. Kizil"],"abstracts":[{"id":"136-0885","title":"Designing Scheduled Service Networks for Expeditionary Logistics Operations","content":"We address a scheduled service network design problem for expeditionary logistics. We model it as a multi-commodity capacitated VRP with time windows and propose a branch-and-cut-and-price approach with cuts generated by solving second-stage separable single-commodity maximum-flow problems. We solve on actual expeditionary training scenarios for the US marine corps.","presenter":"Prof. Mathieu Dahan","authors":[{"name":"Mr. Joseph Boone","aff":"Student, Georgia Institute of Technology"},{"name":"Prof. Mathieu Dahan","aff":"Assistant Professor, Georgia Institute of Technology"}],"order":1},{"id":"136-1835","title":"Repatriation scheduling problem applied in a sudden-onset disaster scenario","content":"The study proposes a generic mathematical model, tested through a Brazilian case to validate its effectiveness in repatriation scheduling problems. Focused on sudden-onset disasters, it considers extreme weather events and social polarization as aggravating factors for involuntary migration. The tool aims to optimize logistical decision-making, integrating humanitarian and operational constraints.","presenter":"Prof. Adriana Leiras","authors":[{"name":"Mr. Thiago Rodrigues de Almeida","aff":"Student, University of Sao Paulo"},{"name":"Prof. Irineu de Brito Junior","aff":"Associate Professor, Sao Paulo State University - UNESP"},{"name":"Prof. Adriana Leiras","aff":"Associate Professor, Pontifícia Universidade Católica do Rio de Janeiro - PUC-Rio"}],"order":2},{"id":"136-1219","title":"Robotic Mobile Fulfillment Systems: Strategies for Pod Selection and Scheduling","content":"Robotic mobile fulfillment systems automate storage and transport tasks in a fulfillment center but rely on human pickers. This study focuses on minimizing overall completion time and the number of robots required to support picker schedules. It investigates the pod selection and scheduling problems and offers managerial insights.","presenter":"Mr. Kerim U. Kizil","authors":[{"name":"Mr. Kerim U. Kizil","aff":"Student, Texas A&amp;M University"},{"name":"Prof. Chelliah Sriskandarajah","aff":"Professor, Texas A&amp;M University College Station"},{"name":"Prof. Jon Stauffer","aff":"Associate Professor, Mays Business School, Texas A&amp;M University"}],"order":3},{"id":"136-1413","title":"Modeling Single-Donor Organ Chain Exchange: Optimization Framework for Analyzing Transplant Success","content":"An optimal matching problem to maximize transplant success rate is investigated in the context of single donor organ exchange, where one living\r\ndonor’s organ is transplanted to a single patient. In such exchanges, multiple medical compatibility criteria pose a serious challenge for matching a\r\npatient with compatible donor.","presenter":"Dr. Yunxia Zhu","authors":[{"name":"Dr. Rakesh Mallipeddi","aff":"Assistant Professor, The Ohio State University"},{"name":"Prof. Chelliah Sriskandarajah","aff":"Professor, Texas A&amp;M University College Station"},{"name":"Prof. Jon Stauffer","aff":"Associate Professor, Mays Business School, Texas A&amp;M University"},{"name":"Dr. Yunxia Zhu","aff":"Associate Professor, University of Nebraska Lincoln"}],"order":4}]},{"id":"s290","title":"Optimizing Markets, Supply Chains, and Well-Being Through Data-Driven Strategies","track":"Disruptive Technologies and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"KENNESAW","chairs":["Dr. Xue Guo"],"abstracts":[{"id":"136-0223","title":"Dynamic Pricing and Ordering Policy in Omnichannel Retailing","content":"We investigate the dynamic pricing and ordering policy for in-store inventories of a firm that owns an online store and operates multiple retail stores in omnichannel retailing. The solutions obtained by mean-field approach demonstrate how a group of retail stores cooperatively manage in-store inventories in a cost-effective manner.\r\n\r\n","presenter":"Dr. Joohyun Kim","authors":[{"name":"Dr. Joohyun Kim","aff":"Assistant Professor, University of North Carolina Charlotte"},{"name":"Dr. Sila Cetinkaya","aff":"Professor, Southern Methodist University"}],"order":1},{"id":"136-0758","title":"Strategic improvement of supplier reliability","content":"A buyer procures a product from a supplier to sell to the\r\ndownstream market. A disruption at supplier may occur after buyer reserves\r\ncapacity with supplier. The buyer may improve the reliability of supplier to\r\nlower the probability of a disruption. What is the optimal level of supplier improvement?","presenter":"Dr. Chandrasekhar Manchiraju","authors":[{"name":"Dr. Han Zhang","aff":"Assistant Professor, Michigan State University"},{"name":"Prof. Lusheng Shao","aff":"Associate Professor, University of Melbourne"},{"name":"Prof. Sri Talluri","aff":"Professor, Michigan State University"},{"name":"Dr. Chandrasekhar Manchiraju","aff":"Assistant Professor, Michigan State University"}],"order":2},{"id":"136-1131","title":"Uncovering Average and Heterogeneous Treatment Effects of Digital and Social Capital on Community Mental Health","content":"Mental health issues are rising due to inequalities and health crises. Using difference-in-differences and causal forests, we investigate show telehealth can reduces mentally unhealthy days, with the greatest benefits in counties with moderate digital but high social and economic capital.","presenter":"Ms. Yi Yang","authors":[{"name":"Ms. Yi Yang","aff":"Student, Georgia State University"},{"name":"Prof. Arun Rai","aff":"Professor, Georgia State University"},{"name":"Prof. Aaron Baird","aff":"Associate Professor, Georgia State University"}],"order":3},{"id":"136-1204","title":"Pay Model Intuitiveness and Transparency on On-Demand Service Platforms","content":"Motivated by platforms’ move towards less-intuitive and opaque models that determine workers’ compensation, we conduct incentivized experiments to examine how a pay model’s intuitiveness, transparency, and a change that reduces the model’s intuitiveness affect worker participation. We derive insights on how platforms can better manage their pay models.","presenter":"Mr. Swanand Kulkarni","authors":[{"name":"Mr. Swanand Kulkarni","aff":"Post Doc/Researcher, Tuck School of Business"},{"name":"Prof. Basak Kalkanci","aff":"Associate Professor, Georgia Institute of Technology"},{"name":"Dr. Chris Parker","aff":"Associate Professor, Darden School of Business"}],"order":4},{"id":"136-1975","title":"Innovation and pricing competition with absorptive capacity","content":"We develop a game theoretical model of sequential entrance in which an entrant with absorptive capacity tries to enter a market where the incumbent exists. The incumbent decides on innovation and pricing strategies to prevent or allow market entry of the entrant with absorptive capacity.","presenter":"Prof. Xiuli He","authors":[{"name":"Prof. Xiuli He","aff":"Professor, University of North Carolina Charlotte"},{"name":"Dr. Xianjin Du","aff":"Associate Professor, Hefei University of Technology"}],"order":5}]},{"id":"s314","title":"Personalized Pricing and Assortment Optimization","track":"Revenue Management and Pricing","type":"Regular","invited":"Invited","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"MARIETTA","chairs":["Prof. Andrew Li","Mr. Lin An"],"abstracts":[{"id":"136-1699","title":"Revenue Management in Stochastic Systems with Abandonments","content":"We investigate optimal dynamic pricing for a stochastic service system with impatient customers. After revealing the structural properties of the optimal pricing policy, we develop an efficient solution algorithm and implementable heuristics that achieve near-optimal performance.","presenter":"Jieqi Di","authors":[{"name":"Jieqi Di","aff":"Student, Georgia Institute of Technology"},{"name":"Prof. Sigrun Andradottir","aff":"Professor, Georgia Institute of Technology"},{"name":"Prof. Hayriye Ayhan","aff":"Professor, Georgia Institute of Technology"}],"order":5}]},{"id":"s336","title":"AI in Supply Chain and Retail","track":"Information Systems and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY E","chairs":["Prof. Lin Hao"],"abstracts":[{"id":"136-1980","title":"Cascading Effects of Conference Calls in Supply Chain Networks","content":"This study examines post-conference-call stock volatility through supply chain linkages derived from the FactSet Supply Chain dataset. By using state-of-the-art GNN models, our analysis will reveal how the conference-call disclosures trigger cascading effects among supply chain networks, affecting not only the focal firm but also its suppliers, customers, and competitors.","presenter":"Mr. Zhibo Ye","authors":[{"name":"Mr. Zhibo Ye","aff":"Student, New Jersey Institute of Technology"},{"name":"Mr. Muntasir Shohrab","aff":"Student, New Jersey Institute of Technology"},{"name":"Prof. Alice Liu","aff":"Assistant Professor, New Jersey Institute of Technology"},{"name":"Dr. Dantong Yu","aff":"Professor, New Jersey Institute of Technology"}],"order":2},{"id":"136-1982","title":"SupplyChainAlpha: A Novel Measure of Firm-Level Supply Chain Resilience Using Alpha Centrality","content":"SupplyChainAlpha is an alpha centrality-based measure capturing firm-level supply chain resilience. It quantifies network risk propagation, correlates with realized and implied volatility, and distinguishes supply chain-specific exposure. It predicts strategic inventory buffers, liquidity adjustments, and limited trade credit, and forecasts worse firm performance during unforeseen disruptions, further guiding empirical research.","presenter":"Mr. Muntasir Shohrab","authors":[{"name":"Mr. Muntasir Shohrab","aff":"Student, New Jersey Institute of Technology"},{"name":"Mr. Zhibo Ye","aff":"Student, New Jersey Institute of Technology"},{"name":"Prof. Alice Liu","aff":"Assistant Professor, New Jersey Institute of Technology"},{"name":"Dr. Dantong Yu","aff":"Professor, New Jersey Institute of Technology"}],"order":3},{"id":"136-1105","title":"Is additional supply information always beneficial: a simulation study?","content":"This study simulates a scenario in which one retailer gains access to advanced supplier information from a supplier that also serves an identical competitor. The analysis explores various conditions to determine when the retailer benefits from the advanced supply information and when such advantages are not applicable.","presenter":"Dr. Quan Yuan","authors":[{"name":"Dr. Quan Yuan","aff":"Assistant Professor, Ball State University"},{"name":"Dr. Qiannong Gu","aff":"Associate Professor, Ball State University"}],"order":4},{"id":"136-1984","title":"Assessing Risk Propagation in Supply Chains Using Alpha Centrality","content":"This study constructs a supply chain network to analyze risk propagation. Using alpha centrality, it identifies direct and indirect dependencies among entities, enabling a comprehensive assessment of how disruptions, such as adverse weather, spread through the network. Based on this risk assessment, effective mitigation strategies for supply chains are developed.","presenter":"Mr. Muntasir Shohrab","authors":[{"name":"Mr. Muntasir Shohrab","aff":"Student, New Jersey Institute of Technology"},{"name":"Mr. Zhibo Ye","aff":"Student, New Jersey Institute of Technology"},{"name":"Prof. Alice Liu","aff":"Assistant Professor, New Jersey Institute of Technology"},{"name":"Dr. Dantong Yu","aff":"Professor, New Jersey Institute of Technology"}],"order":6}]},{"id":"s347","title":"Healthcare Delivery: An Operational Effiiency Perspective","track":"Healthcare Analytics","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"GRAND HALL EAST D","chairs":["Dr. Seonjun Kang"],"abstracts":[{"id":"136-1374","title":"Scheduling Surgical Procedures Under Uncertainty for NHS England","content":"In UK hospitals, subsets of patients waiting for a surgeon are scheduled into, say four-hour, slots called lists using the ex ante uncertain procedure times. Using data from two hospitals, we seek to (1) reduce procedure uncertainty and (2) find a way to schedule procedures to reduce list over/under-utilization.","presenter":"Prof. Manmohan Sodhi","authors":[{"name":"Prof. Manmohan Sodhi","aff":"Professor, Bayes Business School"}],"order":1},{"id":"136-1781","title":"Who is Next? Guiding Physicians with Time-dependent Patient Selection Policies under Shift Work","content":"Patient selection by physicians in Emergency Departments can significantly impact operational and clinical outcomes. We propose a time-dependent policy to guide physicians in this decision, where we consider patients waiting for initial assessments and re-assessments as well as patients being handed over at the end of a physician's shift.","presenter":"Dr. Marco Bijvank","authors":[{"name":"Mr. Mahdi Shakeri","aff":"Student, University of Calgary"},{"name":"Dr. Marco Bijvank","aff":"Associate Professor, University of Calgary"},{"name":"Prof. Soroush Saghafian","aff":"Associate Professor, Harvard University"}],"order":2},{"id":"136-1788","title":"Impact of Patient-Provider Relationships on Telehealth Responses: Empathy, Turnaround Time, and Predictive Insights","content":"Asynchronous communication in telehealth is crucial for non-urgent care. This study explores whether patient-provider relationships influence provider behaviors. Using LLM-extracted empathy sentiments, EHR audit logs, predictive modeling, and response turnaround time, it assesses the impact of these relationships on provider responses, aiming to address challenges in equitable telehealth care delivery.","presenter":"Ms. Jahnavi Galla","authors":[{"name":"Ms. Jahnavi Galla","aff":"Student, University of Cincinnati"},{"name":"Mr. Jeffrey Shaffer","aff":"Assistant Professor, University of Cincinnati"},{"name":"Dr. Dong-Gil Ko","aff":"Associate Professor, University of Cincinnati"}],"order":3},{"id":"136-1851","title":"Beyond the Screen: Hidden Costs of Telehealth","content":"Although concerns have been raised about the potential for telehealth to compromise the quality of care, much of the existing research predominantly emphasizes its benefits, particularly in enhancing access and convenience for managing chronic conditions like diabetes. We investigate the potential risks of, focusing on its impact on HbA1c levels.","presenter":"Dr. Seonjun Kang","authors":[{"name":"Dr. Seonjun Kang","aff":"Assistant Professor, Missouri University of Science And Technology"},{"name":"Dr. Elizabeth Baker","aff":"Associate Professor, Virginia Commonwealth University"},{"name":"Dr. Ugochukwu Etudo","aff":"Assistant Professor, Virginia Commonwealth University"},{"name":"Prof. Yeongin Kim","aff":"Assistant Professor, Wake Forest University"}],"order":4}]},{"id":"s353","title":"Service System Modeling","track":"Service Operations","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY C","chairs":["Dr. Eojin Han"],"abstracts":[{"id":"136-0517","title":"Analyses of Business Models Pertaining to the Electric Vehicle Industry","content":"Electric vehicle (EV) manufacturers have introduced non-ownership business plans like battery leasing and subscription. We analyse the effect of non-ownership and ownership plans on pricing and adoption decision. Applying game theoretic modelling, we find that integrating non-ownership business plans alongside ownership has a positive impact on overall electric vehicle adoption.","presenter":"Mr. Tridib Guha","authors":[{"name":"Mr. Tridib Guha","aff":"Student, IIM Udaipur"},{"name":"Dr. Avijit Raychaudhuri","aff":"Assistant Professor, Indian Institute of Management Udaipur"}],"order":1},{"id":"136-1880","title":"A Unified Fluid Model for Large Service Systems with Patience- or Delay-Dependent Service Times","content":"We consider many-server queueing systems where service times of customers depend on patience times and delay experienced in queue. We propose a deterministic approximation for the queueing dynamics, called Unified Fluid Model. We show that systems with patience-dependent services have unique stationary points. However, delay-dependent services may cause multiple equilibria.","presenter":"Ms. Deniz Simsek","authors":[{"name":"Ms. Deniz Simsek","aff":"Student, Kellogg School of Management"},{"name":"Prof. Achal Bassamboo","aff":"Professor, Northwestern University"},{"name":"Dr. Ohad Perry","aff":"Associate Professor, Southern Methodist University"},{"name":"Dr. Chenguang (Allen) Wu","aff":"Assistant Professor, Hong Kong University of Science and Technology"}],"order":2},{"id":"136-0469","title":"Distribution-Free Policies for Stochastic Clearing Systems","content":"We propose a class of distribution-free policies for stochastic clearing operations which have numerous applications such as last-mile delivery. By only utilizing limited information of stochastic input processes, our framework efficiently computes optimal policies with closed-form solutions in specific cases, and allows several extensions to incorporate multiple practical considerations.","presenter":"Dr. Eojin Han","authors":[{"name":"Dr. Eojin Han","aff":"Assistant Professor, University of Notre Dame"},{"name":"Dr. Sila Cetinkaya","aff":"Professor, Southern Methodist University"}],"order":3},{"id":"136-2029","title":"Optimizing Services with Appointment Exchangeability","content":"Appointment-driven queuing systems are prevalent in various services, characterized by non-punctual arrivals, multi-stage multi-server processes, and stochastic durations. This study introduces a framework leveraging service time exchangeability across stages to mitigate uncertainties. The integration of clustering with stochastic optimization demonstrated significant improvements in computational and operational performance in real-world applications.","presenter":"Dr. Majed Hadid","authors":[{"name":"Dr. Majed Hadid","aff":"Post Doc/Researcher, Hamad Bin Khalifa University"},{"name":"Dr. Adel Elomri","aff":"Associate Professor, Hamad Bin Khalifa University"},{"name":"Dr. Regina Padmanabhan","aff":"Post Doc/Researcher, Hamad Bin Khalifa University"},{"name":"Prof. Laoucine Kerbache","aff":"Professor, Hamad Bin Khalifa University"},{"name":"Dr. Abdelfatteh El Omri","aff":"Dept of Surgery, Hamad Medical Corporation"}],"order":4},{"id":"136-0231","title":"Super Distribution in the News Media Supply Chain","content":"This study advances news media service supply chain literature by examining consumer \"super-distribution,\" where digitalization empowers consumers to distribute news. A 2X2 experiment reveals how source venue and outrage rhetoric shape perceptions of credibility and news-sharing intentions, contributing insights into social identity and legitimacy theories within digital information flows.","presenter":"Mr. Derek Dubois","authors":[{"name":"Mr. Derek Dubois","aff":"Student, University of Rhode Island"},{"name":"Dr. Anis Triki","aff":"Associate Professor, University of Rhode Island"},{"name":"Dr. Muhammad Hasan Ashraf","aff":"Assistant Professor, California State University Long Beach"},{"name":"Dr. Mehmet Yalcin","aff":"Assistant Professor, University of Rhode Island"}],"order":5}]},{"id":"s364","title":"Tech-Driven Solutions for Disaster Management","track":"Humanitarian Operations and Crisis Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY G","chairs":["Prof. Frederick Benaben"],"abstracts":[{"id":"136-0304","title":"Digitalization in Disaster and Humanitarian Operations: lessons from the development of technological platforms in Brazil","content":"Several factors have boosted the digitalization of disaster and humanitarian operations (DHO). This work presents the adoption of the Design Science Research for developing three web technological platforms for DHO. The findings reveal challenges in engaging stakeholders and promoting long-term commitment in the ecosystem to run and improve the platforms.","presenter":"Prof. Tharcisio Fontainha","authors":[{"name":"Prof. Tharcisio Fontainha","aff":"Professor, Federal University of Rio De Janeiro"},{"name":"Mr. Estevão Leite","aff":"Student, Federal University of Rio De Janeiro"},{"name":"Mr. Renan Correia","aff":"Student, Federal University of Rio De Janeiro"},{"name":"Mrs. Ana Nascimento","aff":"Student, Federal University of Rio De Janeiro"}],"order":1},{"id":"136-1910","title":"Toward an improvement of the humanitarian logistics and supply chains practices through VR trainings","content":"Humanitarian operations practices can be enhanced through dedicated trainings. This research work develops an Immersive Teaching Campus based on VR technologies which could be used for this purpose. This proposal not only helps to develop skills derived from current knowledge, but also facilitates the transfer of research results to practitioners.","presenter":"Prof. Frederick Benaben","authors":[{"name":"Prof. Matthieu Lauras","aff":"Professor, IMT Mines Albi / Georgia Tech"},{"name":"Prof. Frederick Benaben","aff":"Professor, IMT Mines Albi / Georgia Tech"},{"name":"Dr. Victor Romero","aff":"Assistant Professor, IMT Mines Albi"}],"order":2},{"id":"136-0590","title":"An ensemble-based forecasting model for the relief demand in flooded areas","content":"Flooding is a common occurrence among all natural disasters. This study presents an ensemble- based approach to anticipate relief demands for inundated regions, incorporating various machine learning algorithms to improve forecasting precision and robustness. This study further helps resource allocation and optimizes disaster response via demand forecasting.","presenter":"Ms. Sima Kundu","authors":[{"name":"Ms. Sima Kundu","aff":"Student, IIT Kharagpur"},{"name":"Dr. M. Rani","aff":"Assistant Professor, IIT Kharagpur"}],"order":3},{"id":"136-0307","title":"Methodology for assessing contingency plans: design, development, and applications in Brazil","content":"The research developed a methodology to evaluate contingency plans for disasters. Based on Systematic Review, Design Science Research, and Case Study, we proposed and tested the methodology co-created with Brazilian stakeholders. The methodology incorporated a diverse number of elements, and its application in Brazil reveals a lack of stakeholders' engagement.","presenter":"Prof. Tharcisio Fontainha","authors":[{"name":"Mr. Fabio Moraes","aff":"Student, Federal University of Rio De Janeiro"},{"name":"Prof. Tharcisio Fontainha","aff":"Professor, Federal University of Rio De Janeiro"}],"order":4}]},{"id":"s366","title":"Disaster Preparedness and Community Resilience","track":"Humanitarian Operations and Crisis Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"GRAND HALL EAST B","chairs":["Dr. Diana Ramirez-Rios"],"abstracts":[{"id":"136-0933","title":"Post-Disaster Resident Relocation Problem Considering Shelter Site Selection and Logistics Support","content":"This study addresses post-disaster challenges in rural areas with limited infrastructure and resources, focusing on shelter site selection and resident relocation. It emphasizes scheduling relocation and supply vehicles separately, balancing operational costs, relocation times, and resource constraints, the framework ensures timely resettlement and optimal resource use for affected residents.","presenter":"Mr. Qiao Pan","authors":[{"name":"Prof. Zhaofang Mao","aff":"Professor, Tianjin University"},{"name":"Mr. Qiao Pan","aff":"Student, Tianjin University"},{"name":"Mr. Yiting Sun","aff":"Student, Tianjin Uinversity"}],"order":1},{"id":"136-1606","title":"Exploring the Factors Influencing Hurricane Damages from Hurricanes Maria and Fiona in Puerto Rico","content":"This work considers characteristics beyond sociodemographic factors, like infrastructure and health access, to understand the impacts of hurricanes by predicting damage estimates through the analysis of county-level data in Puerto Rico. Model training is performed on 2017 Hurricane Maria and extrapolations of results are used to understand 2022 Fiona damages.","presenter":"Ms. Judith Brennan","authors":[{"name":"Ms. Judith Brennan","aff":"Student, University at Buffalo, SUNY"},{"name":"Dr. Diana Ramirez-Rios","aff":"Assistant Professor, The State University of New York at Buffalo"}],"order":2},{"id":"136-1712","title":"Social Impacts from Disaster-Induced Critical Infrastructure Disruptions","content":"We designed a community-centric rapid-response framework that analyzes the social impact of critical infrastructure disruptions on the affected population after a disaster. We present the case electric grid and transportation infrastructures after 2022 Hurricane Fiona in Puerto Rico. The analysis informed better recovery efforts to the most socially vulnerable communities.","presenter":"Dr. Diana Ramirez-Rios","authors":[{"name":"Dr. Diana Ramirez-Rios","aff":"Assistant Professor, The State University of New York at Buffalo"},{"name":"Dr. Sayanti Mukherjee","aff":"Assistant Professor, University at Buffalo, SUNY"},{"name":"Mr. Angelo Soto Vergel","aff":"Student, University at Buffalo, SUNY"},{"name":"Ms. Judith Brennan","aff":"Student, University at Buffalo, SUNY"},{"name":"Ms. Poulomee Roy","aff":"Student, University at Buffalo"}],"order":4}]},{"id":"s370","title":"Pricing and Retail Business Models","track":"POM-Marketing Interface","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"DUNWOODY","chairs":["Prof. Yu Xia"],"abstracts":[{"id":"136-1304","title":"Promote More or Less? Optimal Promotional Effort in the Presence of Platform Private Labels","content":"We determine a platform's optimal promotional effort to sell its private label in the presence of its spillover effect on a competing national brand it also sells. We show that, contrary to intuition, the platform exerts effort only when the cost of promotion is high.","presenter":"Mr. Madduri Murthy","authors":[{"name":"Mr. Madduri Murthy","aff":"Student, Indian Institute of Management Ahmedabad"},{"name":"Prof. Sachin Jayaswal","aff":"Professor, Indian Institute of Management Ahmedabad"},{"name":"Prof. Benny Mantin","aff":"Professor, University of Luxembourg"}],"order":1},{"id":"136-1549","title":"FACTORS INFLUENCING SMALL FARMERS' CHOICE OF DISTRIBUTION AND MARKETING CHANNELS","content":"This study develops a framework to identify the factors influencing small and medium farmers' marketing and distribution decisions in India. Through qualitative interviews, it explores the behavioural and environmental factors affecting decision-making at various stages of the farmers' value chain.","presenter":"Prof. Aditya Billore","authors":[{"name":"Prof. Aditya Billore","aff":"Professor, Indian Institute of Management Indore"},{"name":"Prof. Piyush Singh","aff":"Assistant Professor, Indian Institute of Technology Kharagpur"},{"name":"Mr. Kripamay Baishnab","aff":"Post Doc/Researcher, Indian Institute of Technology Kharagpur"}],"order":2},{"id":"136-0400","title":"Physical Product Subscription Supply Chain: Pricing Strategies and Coordination","content":"This paper examines the physical product subscription supply chain, focusing on pay-per-unit and fixed pricing strategies. It highlights production costs, recycling value, and service operation costs. Both decentralized and centralized supply chains are analyzed, with coordination and equilibrium decisions explored for the decentralized model.","presenter":"Prof. Yu Xia","authors":[{"name":"Mr. Jiangchao Li","aff":"Student, Southwestern University of Finance and Economics"},{"name":"Prof. Shilei Yang","aff":", Southwestern University of Finance &amp; Economics"},{"name":"Prof. Yu Xia","aff":"Professor, College of William and Mary"}],"order":3}]},{"id":"s381","title":"Consumers and Behavioral Operations","track":"Behavioral Operations Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY D","chairs":["Ms. Anqi Zhang"],"abstracts":[{"id":"136-0795","title":"Consumers' Privacy Awareness and Trust: Impacts on Regional Courier Services","content":"This study investigates the impact of consumers’ privacy awareness on regional courier services, with consumer trust as a mediating variable. By providing empirical evidence on the mediating role of consumer trust, this study enriches the theoretical understanding of consumer behavior in privacy-sensitive contexts and offers actionable insights.","presenter":"Dr. CHEN MENGTING","authors":[{"name":"Dr. CHEN MENGTING","aff":"Student, Korea University"},{"name":"Prof. Kwangtae Park","aff":"Professor, KUBS(Korea University Business School)"}],"order":1},{"id":"136-0731","title":"Eye on Logistics and Engagement: How Shopping Goals Influence Livestream E-commerce","content":"Livestream e-commerce platforms leverage engagement cues to influence consumer purchasing behavior. In recent years, logistics integration has emerged as a key factor alongside engagement. Using multi-methods with cases, eye-tracking, and an analytical model, our study investigates how these factors affect consumer purchasing behavior on a livestream e-commerce platform.","presenter":"Mr. Faizul Haque","authors":[{"name":"Mr. Faizul Haque","aff":"Student, Indian Institute of Management Calcutta"},{"name":"Prof. Sumanta Basu","aff":"Professor, Indian Institute of Management Calcutta"}],"order":2},{"id":"136-0416","title":"Left-digit bias, shrinkflation, and channel effects","content":"Left-digit bias to prices has been documented across many domains. This paper investigates how this bias shapes the firm's strategic quality and pricing decisions. We find that the bias drives shrinkflation. In channels, we show that the the bias can either exacerbate the double marginalization problem or improve channel coordination.","presenter":"Dr. Xuefeng Peng","authors":[{"name":"Dr. Xuefeng Peng","aff":"Post Doc/Researcher, The University of Hong Kong"},{"name":"Prof. Zemin (Zachary) Zhong","aff":"Assistant Professor, University of Toronto"}],"order":3},{"id":"136-0273","title":"Automated Service Encounter: How Robotic Agents Impact Customer Online Reviews","content":"This study examines how interactions with robotic service agents affect customer’s online complaints and disclosure behaviors through experimental studies. We also explore how brand positioning (luxury vs. economy) moderates these effects, providing insights into customer responses in automated service encounter and implications for managers deploying robotic customer service agents.","presenter":"Ms. Anqi Zhang","authors":[{"name":"Ms. Anqi Zhang","aff":"Student, Georgia State University"},{"name":"Dr. Xinyu Fu","aff":"Assistant Professor, Georgia State University"}],"order":4}]},{"id":"s390","title":"New Advances in Transportation and Logistics","track":"Aviation, Transportation, and Logistics Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"UNIVERSITY","chairs":["Dr. Xiaotang Yang"],"abstracts":[{"id":"136-0412","title":"Contextual difference of Willingness-to-pay for airline ancillary services using Latent Class Choice Modelling","content":"Airlines face financial challenges despite growing air-travel demand. Ancillary revenues are becoming vital for sustainability. Using latent class choice modelling on HPC, we quantify air-travellers preference heterogeneity for ancillaries across travel time, destinations, and carriers. Our study estimates relative-importance and willingness-to-pay, emphasising choice behaviour variations across classes for enhanced profitability.","presenter":"Mr. Sourav Mandal","authors":[{"name":"Mr. Sourav Mandal","aff":"Student, Indian Institute of Technology Kharagpur"},{"name":"Dr. Swagato Chatterjee","aff":"Senior Lecturer, Queen Mary University of London"}],"order":1},{"id":"136-0576","title":"Coordination Behavior in Travel Mode Choice: An Experiment on Autonomous Vehicle Services","content":"This study examines mode choice between autonomous vehicles (AVs) and human-driven vehicles (HVs) using MNL and MMNL models. It finds that feedback type (partial/full), payoff fairness, experience-based learning, and heterogeneous preferences influence choices, offering insights for promoting AV adoption and smoother transitions.","presenter":"Ms. Xin Zhang","authors":[{"name":"Ms. Xin Zhang","aff":"Student, Tianjin Univercity"},{"name":"Prof. Ning Jia","aff":"Professor, Tianjin university"}],"order":2},{"id":"136-0819","title":"Modelling Electric Bus Routing Problems for Urban Public Bus Transport Systems","content":"The Mixed Fleet Public Bus Routing Problem (MFPBRP) integrates diesel and electric buses to optimize public transit. A cost-effective method to solve battery limitations, recharging requirements, and emission reduction is proposed in this study. It emphasizes sustainable mobility and operational efficiency in India’s metropolitan areas via green transportation systems.","presenter":"Ms. Soumita Rakshit","authors":[{"name":"Ms. Soumita Rakshit","aff":"Student, IIT Kharagpur"},{"name":"Dr. Sushil Punia","aff":"Assistant Professor, Indian Institute of Technology, Kharagpur"}],"order":3}]},{"id":"s400","title":"Innovative Strategies in Sustainable Operations","track":"Sustainable Operations Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"GRAND HALL EAST C","chairs":["Mr. Gökhan Cenk"],"abstracts":[{"id":"136-0670","title":"The spillover effects of co-opetition on environmental innovation","content":"Existing literature alludes to co-opetition to complement coopetitor’s sustainability efforts. Our study builds on this body of work by examining the spillover effect of coopetitors’ environmental transparency on focal firms’ environmental innovation. In doing so, our study considers the role of focal firm’s resource slack, coopetition experience, and aligned focus","presenter":"Mr. Ebenezer Afum","authors":[{"name":"Mr. Ebenezer Afum","aff":"Student, University of Bristol Business School"},{"name":"Dr. Chandrasekararao Seepana","aff":"Lecturer, University of Bristol"},{"name":"Prof. Palie Smart","aff":"Professor, University of Bristol"}],"order":2},{"id":"136-1048","title":"Supply Network Configuration for Resource Constrained Environment: Multi-Industry Study","content":"The aim of the study is to propose a framework for supply chain configuration that is designed within the context of water scarcity. It is further tested utilising a case study method. The results demonstrate three configurational archetypes that can be developed for natural resource scarcity mitigation.","presenter":"Dr. Katya Yatskovskaya","authors":[{"name":"Dr. Katya Yatskovskaya","aff":"Assistant Professor, IESEG School of Management"}],"order":3},{"id":"136-0186","title":"Co-opetition in Sustainability Initiative","content":"We explore the dynamics of co-opetition, that is, cooperation among competitors, in sustainability initiatives. We study the strategic interaction of two competing brands’ participation in the initiative by considering their market shares, consumer segments, and loyalties, and the change in profit margin and investment costs when participating.","presenter":"Prof. Jen-Yi Chen","authors":[{"name":"Prof. Jen-Yi Chen","aff":"Associate Professor, Cleveland State University"},{"name":"Mr. Moonwon Chung","aff":"Assistant Professor, Cleveland State University"},{"name":"Prof. Chien-Hui Wang","aff":"Assistant Professor, Feng Chia University"}],"order":5},{"id":"136-0102","title":"Using A Digital Supply Chain Twin To Ensure The Tripple Bottom Line","content":"The digital supply chain twin uses immersive technologies to guarantee calculated operational supply chain costs by mitigating risks, visualizing material flows, and achieving sustainable goals. Its technology stack allows firms to connect their IT systems enriched with various open data sources, such as weather, environmental, or public social data.","presenter":"Mr. Gökhan Cenk","authors":[{"name":"Mr. Gökhan Cenk","aff":"Lecturer, University of Applied Sciences Neu-Ulm"},{"name":"Mr. Jonas Andersson","aff":"Lecturer, University of Applied Sciences Neu-Ulm"},{"name":"Prof. Tobias Engel","aff":"Professor, University of Applied Sciences Neu-Ulm"}],"order":6}]},{"id":"s405","title":"Emerging Topics in Technology and Analytics","track":"Operational Excellence","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"BAKER","chairs":["Mr. Jiannan Xu"],"abstracts":[{"id":"136-0420","title":"Picking the Best Bot. Analysis of Human-Robot Collaborative Policies in Order Pick Systems","content":"Collaborative robots (cobots) enhance order-picking efficiency in omnichannel warehouses by reducing human travel times. This study compares two collaboration policies: swarm and system-directed. Using queuing networks and simulations, we find the swarm policy improves throughput by up to 40%. However, system-directed approaches may excel under specific conditions, offering operational insights.","presenter":"Mr. Mahdi Ghorashi Khalilabadi","authors":[{"name":"Mr. Mahdi Ghorashi Khalilabadi","aff":"Student, Rotterdam School of Management"},{"name":"Prof. Debjit Roy","aff":"Professor, Indian Institute of Management Ahmedabad"},{"name":"Prof. René De Koster","aff":"Professor, Erasmus University Rotterdam"}],"order":1},{"id":"136-1314","title":"Developing a modernised total cost of quality (TCoQ) model","content":"This study proposes a modernized Total Cost of Quality (TCoQ) model aligned with Industry 4.0 and Quality 4.0, integrating advanced technologies and intangible costs like opportunity costs. Using a mixed-methods approach, it addresses gaps in theory and practice, optimizing costs and decision-making, with a focus on emerging markets.","presenter":"Mr. Robert Mupazviriwo","authors":[{"name":"Mr. Robert Mupazviriwo","aff":"Student, University of Pretoria"}],"order":2},{"id":"136-1685","title":"Words Matter! Dynamic Forecasting of Freelance Job Success Using Conversational Analytics","content":"This study leverages conversational analytics and machine learning to analyze millions of freelancer-client messages, uncovering linguistic and behavioral patterns that impact job success. Grounded in Grice’s Maxims (1975), we evelop AI-driven predictive models, advancing NLP applications in labor markets and offering actionable insights to help freelancers improve communication strategies.","presenter":"Mr. Jiannan Xu","authors":[{"name":"Mr. Jiannan Xu","aff":"Student, University of Maryland"},{"name":"Prof. Ashish Kabra","aff":"Assistant Professor, University of Maryland"},{"name":"Prof. Kunpeng Zhang","aff":"Associate Professor, University of Maryland"},{"name":"Prof. Wedad Elmaghraby","aff":"Professor, University of Maryland"}],"order":3}]},{"id":"s410","title":"Hospital Capacity Management and Scheduling","track":"Healthcare Operations Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"PIEDMONT","chairs":["Prof. Hung Do"],"abstracts":[{"id":"136-1102","title":"Managing Routine and Same-day Appointments for Outpatient Clinics","content":"The paper presents the mixed appointment scheduling (MAS) policy, allowing shared slots for routine and same-day patients to overcome inefficiencies in carve-out scheduling (COS). We propose an optimization framework to demonstrate that MAS enhances utilization, reduces delays, and lowers costs, especially under moderate same-day demand.","presenter":"Dr. Enayon Taiwo","authors":[{"name":"Dr. Enayon Taiwo","aff":"Assistant Professor, The University of Winnipeg"},{"name":"Prof. Sergei Savin","aff":"Professor, University of Pennsylvania"},{"name":"Prof. Frank Chen","aff":"Professor, City University of Hong Kong"}],"order":1},{"id":"136-1008","title":"Remaining length of stay for real-time decision-making: a predictive process monitoring approach","content":"This study explores real-time decision-making in healthcare, developing a predictive model to estimate the remaining length of stay (RLoS). By estimating RLoS at anywhere of patients’ journey, providers can make more informed real-time decision. The predictive model has been developed based on two years data of an Italian hospital. \r\n","presenter":"Mrs. Rosalinda Iachetta","authors":[{"name":"Mrs. Rosalinda Iachetta","aff":"Student, Universita Degli Studi Di Palermo"},{"name":"Prof. Erica Mazzola","aff":"Associate Professor, Universita Degli Studi Di Palermo"},{"name":"Prof. Manfredi Bruccoleri","aff":"Professor, Universita Degli Studi Di Palermo"}],"order":3},{"id":"136-1747","title":"A Pareto Improvement Bumping-Rescheduling Policy for Operating Room Scheduling","content":"For hospitals using shared operating rooms for scheduled and emergent cases, a bumping policy is needed to accommodate emergent cases as they arrive, but it often operates with competing objectives. The current bumping policies do not offer efficient access to capacity (i.e., Operating Rooms) as well as any mechanism for","presenter":"Prof. Hung Do","authors":[{"name":"Prof. Hung Do","aff":"Associate Professor, University of Vermont"},{"name":"Dr. David Novak","aff":"Professor, University of Vermont"},{"name":"Prof. Mitchell Tsai","aff":"Associate Professor, University of Vermont"},{"name":"Prof. Andrey Ukhov","aff":"Associate Professor, The University of Vermont"}],"order":6}]},{"id":"s414","title":"Healthcare Access and Service Delivery","track":"Healthcare Operations Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY H","chairs":["Prof. Sundara Natarajan Panchanatham"],"abstracts":[{"id":"136-2022","title":"Vaccine Distribution in India: Overcoming Cold Chain Barriers","content":"Efficient vaccine distribution is critical to India's healthcare system, particularly in underserved regions. This study analyzes challenges in the healthcare cold chain, focusing on temperature compliance and storage reliability. Using statistical models, it identifies factors causing product spoilage and delays, offering insights to enhance cold chain efficiency and vaccine accessibility.","presenter":"Prof. Karuna Jain","authors":[{"name":"Prof. Karuna Jain","aff":"Professor, Indian Institute of Technology Bombay"},{"name":"Prof. Shashank Kumar","aff":"Assistant Professor, IIM Bodhgaya"},{"name":"Mr. Balkrishna Narkhede","aff":"Associate Professor, National Institute of Industrial Engineering"}],"order":1},{"id":"136-1762","title":"Service Line Analysis: Services Offered, Services Rendered, and the Impact on Hospital Performance","content":"As healthcare markets demand comprehensive coverage across disease states, broadening service lines presents significant performance implications for hospitals. This study explores service line management through breadth, concentration, and in-house versus partnered services, examining their impact on service delivery and operational outcomes from both service offerings and service utilization perspectives.","presenter":"Dr. Anand Bhatia","authors":[{"name":"Dr. Anand Bhatia","aff":"Assistant Professor, IE BUSINESS SCHOOL"},{"name":"Prof. Jayashankar Swaminathan","aff":"Professor, University of North Carolina Chapel Hill"}],"order":2},{"id":"136-1604","title":"Care Access in a Constrained Capacity System across Behavioral Health Units at CentraCare","content":"Access barriers to mental and behavioral healthcare are widespread in the U.S., particularly in rural areas. We use a systems dynamic approach to explore the effects of new patient access across scope of care levels within a constrained capacity environment. We suggest tools and policy guidelines to increase system capacity.","presenter":"Dr. Sarah Sengupta","authors":[{"name":"Dr. Sarah Sengupta","aff":"Associate Professor, St.Cloud State University"},{"name":"Dr. Sudipendra Nath Roy","aff":"Lecturer, University of Saskatchewan"}],"order":5},{"id":"136-1518","title":"Sharing In Caring: Analyzing Shared Medical Appointments Through an Operations Lens","content":"Shared medical appointments (SMA) are visits where groups of patients are seen by healthcare professionals in a concurrent session. This is especially useful in resource-constrained environments. However, operational decisions like the optimal group size and capacity allocation are challenging. Here, we mathematically analyze key operational trade-offs involved and provide prescriptions.","presenter":"Dr. Sundara Natarajan Panchanatham","authors":[{"name":"Dr. Sundara Natarajan Panchanatham","aff":"Assistant Professor, Hong Kong University"},{"name":"Prof. Enver Yucesan","aff":"Professor, INSEAD"}],"order":7}]},{"id":"s422","title":"Platform Strategies and Digital Ecosystem Development","track":"Digital Platforms, Innovations and Transformations","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"GREENBRIAR","chairs":["Dr. Prasenjit Mandal"],"abstracts":[{"id":"136-1390","title":"Manufacturer’s Contract Preference in the Presence of Retail and Rental Platforms","content":"Manufacturers often adopt a dual-distribution strategy, offering products through both retail and rental platforms. While retail platforms provide consumers with exclusive ownership, rental platforms enable temporary access to products. Our study examines the manufacturer's preference of contract: agency or wholesale, with both types of platforms.","presenter":"Dr. Prasenjit Mandal","authors":[{"name":"Dr. Prasenjit Mandal","aff":"Associate Professor, NEOMA Business School"},{"name":"Dr. Tania Saha","aff":"Assistant Professor, SPJIMR"}],"order":1},{"id":"136-0879","title":"UGC Platform Ad Model Selection under Creator Heterogeneity","content":"In the UGC media market with heterogeneous content creators, this study comparatively analyzes the revenues of the platform and content creators under two advertising models, namely the programmatic advertising model and the mutual selection advertising model, and explores the platform's preference for these two advertising models under different conditions.","presenter":"Ms. Wenhui LU","authors":[{"name":"Ms. Wenhui LU","aff":"Student, Southeast University, Nanjing, China"},{"name":"Prof. Weili Xue","aff":"Professor, Southeast University"},{"name":"Prof. Jing Chen","aff":"Professor, Southeast University, Nanjing, China"}],"order":2},{"id":"136-1473","title":"Digital Twin Smart Campus: basic framework - current state, trends and challenges","content":"Digital Twin Smart Campus Framework is a bibliometric research, it investigates the evolution and applications of Digital Twin integrating Industry 4.0 concepts such as Automation, Internet of Things, Real-time data analytics and Predictions in academic settings. The result contributes to guide implementation, demanded by Society 5.0 trends.","presenter":"Mr. ENIDO Ramos","authors":[{"name":"Mr. ENIDO Ramos","aff":"Student, UNICAMP"},{"name":"Dr. Ieda Makiya","aff":"Professor, Unicamp"},{"name":"Dr. Francisco Cesar","aff":"Professor, Instituto Federal de São Paulo - IFSP"}],"order":3},{"id":"136-0355","title":"Philanthropic Giving and Financial Inclusion Among Women in Ghana","content":"This study examines the impact of demographic factors on financial inclusion and philanthropic giving among women in Ghana, using a quantitative approach with logistic regression. The research explores how these factors influence women's charitable behaviours, applying the Ubuntu perspective to address existing gaps in the literature.","presenter":"Mr. Shaibu Salifu","authors":[{"name":"Mr. Shaibu Salifu","aff":"Student, University of the Witwatersrand"}],"order":4}]},{"id":"s426","title":"Supply Chain Planning and Control","track":"Supply Chain Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"GRAND HALL EAST A","chairs":["Mr. Christian Kalla"],"abstracts":[{"id":"136-0930","title":"Leveraging DDMRP and Postponement in Assembly-to-Order Supply Chains","content":"This study aims to minimize inventory management costs of assembly-to-order supply chains by combining DDMRP with postponement. By shifting the decoupling point, adjusting buffer zones dynamically, and optimizing order quantities, the methodology offers a practical approach to achieving cost reductions and improving resilience in supply chains with high product variability.","presenter":"Mr. Oskari Huttunen","authors":[{"name":"Mr. Oskari Huttunen","aff":"Student, University of Vaasa"},{"name":"Prof. Petri Helo","aff":"Professor, University of Vaasa"}],"order":1},{"id":"136-1365","title":"Integrating transfer pricing into short-term scheduling: A case study of a phosphate chemical company","content":"This study examines how transfer pricing impacts supply chain performance at a phosphate chemical company. It analyzes short-term scheduling scenarios with and without internal transfers. The findings demonstrate how appropriate transfer pricing systems, informed by organizational architecture, enhance scheduling efficiency, overall supply chain performance, and decision-making within responsibility centers.","presenter":"Ms. Salma EL ATCHI","authors":[{"name":"Ms. Salma EL ATCHI","aff":"Student, Panthéon-Sorbonne University"},{"name":"Prof. Ahlam AZZAMOURI","aff":"Professor, EMINES – School of Industrial Management, Mohammed VI Polytechnic University"},{"name":"Prof. Frederic Gautier","aff":"Professor, IAE Paris – Sorbonne, Paris 1 Pantheon-Sorbonne University"}],"order":2},{"id":"136-0070","title":"Overcoming Path-Dependent Lock-Ins: Enabling the Adaption of Sales and Operations Planning (S&amp;OP) to New Contexts","content":"Path-dependent lock-ins can prevent incumbent firms from adapting their Sales and Operations Planning (S&amp;OP) to new contexts, reducing its efficiency and effectiveness. This empirical case study of a global automotive manufacturer offers a solution by exploring how firms can overcome these lock-ins to regain a contextual fit of S&amp;OP.","presenter":"Mr. Fabian Tschirch","authors":[{"name":"Mr. Fabian Tschirch","aff":"Student, Ruhr-Universität Bochum"},{"name":"Prof. Jens Poeppelbuss","aff":"Professor, Ruhr-Universität Bochum"}],"order":3},{"id":"136-1335","title":"Adapting sales and operations planning to uncertain business environments","content":"This study examines adapting sales and operations planning (S&amp;OP) to uncertain business environments by integrating supply chain risk management activities. Using contingency theory and multiple case studies, it identifies promising S&amp;OP adaptations through a holistic and integrated people-process-IT perspective, offering valuable insights for academics and practitioners.","presenter":"Mr. Christian Kalla","authors":[{"name":"Mr. Christian Kalla","aff":"Post Doc/Researcher, University of Muenster"},{"name":"Prof. Luiz Felipe Scavarda","aff":"Professor, Pontifícia Universidade Católica do Rio de Janeiro - PUC-Rio"},{"name":"Prof. Bernd Hellingrath","aff":"Professor, University of Muenster"}],"order":4}]},{"id":"s428","title":"Dynamics of Platforms and Contract Manufacturing","track":"Supply Chain Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"8:00 AM","end":"9:30 AM","startMin":480,"room":"EMBASSY A","chairs":["Ms. Xiaochen Yan"],"abstracts":[{"id":"136-1312","title":"Quality Positioning of Platform's Private Labels: Impact of Sourcing Strategies and Agency Selling","content":"We study the optimal positioning of private labels(PL) sold by platforms under various sourcing strategies. Contrary to existing literature, higher consumer willingness to pay may reduce optimal PL quality. We further show that platforms should position PL as higher quality when sourcing from national brands, despite lower in-house sourcing costs","presenter":"Prof. Sriram Sankaranarayanan","authors":[{"name":"Mr. Madduri Murthy","aff":"Student, Indian Institute of Management Ahmedabad"},{"name":"Prof. Sachin Jayaswal","aff":"Professor, Indian Institute of Management Ahmedabad"},{"name":"Prof. Sriram Sankaranarayanan","aff":"Assistant Professor, Indian Institute of Management Ahmedabad"}],"order":1},{"id":"136-0376","title":"Market Expansion Strategy Considering Relevance and Brand Spillover","content":"Using a model with one contract manufacturer and two firms of differing brand appeal, the well-known brand operates in both core and expanded markets. Results show that brand spillover effect doesn’t always harm the dominant brand and may benefit both as the competitor’s appeal grows.","presenter":"Mr. Hailong Wang","authors":[{"name":"Mr. Sijie Li","aff":"Professor, Southeast University"},{"name":"Mr. Hailong Wang","aff":"Student, Southeast University"}],"order":2},{"id":"136-1457","title":"The Impact of Private Label Producers' Disclosure on Retailers and National Brand Manufacturers","content":"In this paper I analyze how disclosing private label producers affects operations of retailers who carry these products in the assortment and manufacturers who produce either the private labels themselves or national brands within the same category.","presenter":"Dr. Alexander Maslov","authors":[{"name":"Dr. Alexander Maslov","aff":"Lecturer, Gatton College of Business and Economics"}],"order":3},{"id":"136-1352","title":"Commission Payments vs. Data Monetization: Choices of Sellers on Online Retail Platforms","content":"Platforms can gather significant amounts of data and obtain valuable insights. This study establishes two modes about “commission mode + full information sharing” and “information sale + partial information sharing”. We will examine the equilibrium information-sharing outcome by considering their interactions on information-sharing agreements.","presenter":"Dr. Xiaochen Yan","authors":[{"name":"Dr. Xiaochen Yan","aff":"Student, Southeast University"},{"name":"Ms. Yajun Cai","aff":"Senior Lecturer, Southeast University"},{"name":"Prof. Weili Xue","aff":"Professor, Southeast University"}],"order":4}]},{"id":"s17","title":"Empirical Research with Social Impacts","track":"POM and Community","type":"Regular","invited":"Invited","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY F","chairs":["Mr. Masoud Kamalahmadi"],"abstracts":[{"id":"136-0091","title":"Bias Through the Screen: Systematic Inequity in Online Student Evaluations of Teaching","content":"This study examines how online education intensifies racial and gender biases in student evaluations of teaching (SETs). Data from RateMyProfessor.com show non-white male instructors received lower ratings post-pandemic, underscoring the need for inclusive evaluation practices to reduce biases in online learning.","presenter":"Dr. Lu Kong","authors":[{"name":"Dr. Lu Kong","aff":"Assistant Professor, University of South Florida"},{"name":"Prof. Kejia Hu","aff":"Associate Professor, University of Oxford"},{"name":"Dr. Lanfei Shi","aff":"Assistant Professor, University of Virginia"},{"name":"Prof. Timothy Vogus","aff":"Professor, Vanderbilt University"}],"order":1},{"id":"136-0574","title":"Explain Worker Schedule Quality Disparities: Evidence from an American Restaurant Chain","content":"Using real-world shift data from a restaurant chain, we investigate the gender and racial disparities in workers' schedule quality in terms of sufficiency and predictability. We decompose the impact of various human capital factors and rule out workers' preference and availability as the driving factor, hinting potential managerial bias.","presenter":"Ms. Xiaoxuan Hou","authors":[{"name":"Ms. Xiaoxuan Hou","aff":"Student, University of Washington"},{"name":"Prof. Qiuping Yu","aff":"Associate Professor, Georgetown University"}],"order":2},{"id":"136-1478","title":"Political Leadership and Contraceptive Uptake: Evidence from India","content":"Utilizing close elections in India as the identification strategy, we estimate a fixed effects instrumental variable specification to evaluate the effect of political leadership on contraceptive uptake.","presenter":"Prof. Dwaipayan Roy","authors":[{"name":"Prof. Amir Karimi","aff":"Assistant Professor, University of Texas at San Antonio"},{"name":"Prof. Dwaipayan Roy","aff":"Assistant Professor, University of Virginia"}],"order":3}]},{"id":"s171","title":"Navigating Retail and Supply Chain Challenges in the Digital Age","track":"Information Systems and Operations Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY E","chairs":["Dr. Shubham Gupta"],"abstracts":[{"id":"136-0500","title":"BM Retailer’s Exclusive Brand Introduction and Consumer Showrooming: A Dual-channel Perspective","content":"Consumers often engage in showrooming behaviour by visiting brick-and-mortar (BM) retail stores to gather product information before making purchases through the manufacturer's online store. We explore how BM retailers comabt showrooming by offering exclusive store-brand products unavailable in the manufacturer’s online channel.","presenter":"Dr. Prasenjit Mandal","authors":[{"name":"Dr. Prasenjit Mandal","aff":"Associate Professor, NEOMA Business School"},{"name":"Prof. Abhishek Roy","aff":"Assistant Professor, Temple University"}],"order":1},{"id":"136-1601","title":"Survivability in the era of Industry 4.0","content":"This research explores the pivotal role of Big Data Analytics in fostering supply chain survivability within the context of Industry 4.0. Supply chain survivability improves the ability to be more flexible (adaptive, agile, and responsible) and withstand long-term disruptions. The research proposes a novel framework to develop supply chain survivability.","presenter":"Dr. Piyal Sarkar","authors":[{"name":"Dr. Piyal Sarkar","aff":"Assistant Professor, Pennsylvania State University Harrisburg"},{"name":"Angappa Gunasekaran","aff":"Professor, University Of Massachusetts Dartmouth"},{"name":"Harshwinder Kiran Patil","aff":""}],"order":2},{"id":"136-1891","title":"Multi-Agent Reinforcement Learning Framework for Closed-Loop Supply Chain Management","content":"The research presents the development and implementation of a multi-agent reinforcement learning (MARL) system applied to a supply chain network consisting of four key agents: Retailer, Distributor, Manufacturer, and Remanufacturer. Each agent within the system operates with specific goals and actions, leveraging deep Q-learning to optimize decision-making.","presenter":"Mr. Pankaj Sharma","authors":[{"name":"Mr. Pankaj Sharma","aff":"Student, University of Massachusetts Lowell"},{"name":"Dr. Nichalin Summerfield","aff":"Assistant Professor, University of Massachusetts Lowell"}],"order":3},{"id":"136-2132","title":"The Role of Gen AI in World Class Manufacturing","content":"Gen AI systems capable of producing new content by analyzing existing data which has profound implications for Industry 4.0. This paper examines the transformative role of Gen AI in world-class manufacturing and its potential to redefine the future of industrial excellence.","presenter":"Prof. Gunasekaran Angappa","authors":[{"name":"Prof. Gunasekaran Angappa","aff":"Professor, Penn State"}],"order":4}]},{"id":"s280","title":"Strategic Decision-Making in Transportation and Logistics","track":"Aviation, Transportation, and Logistics Management","type":"Regular","invited":"Invited","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"UNIVERSITY","chairs":["Rang Gong"],"abstracts":[{"id":"136-1101","title":"Unlocking sales growth: The dynamic interplay between post- and pre-sales fit uncertainty mitigation practices","content":"A lenient return policy boosts sales, but what if a retailer can't provide such a lenient policy? Using the furniture industry as a case study, we find that offering design services, whether technology- or human-based, effectively compensates for the potential sales loss.","presenter":"Dr. Brett Wang","authors":[{"name":"Dr. Brett Wang","aff":"Student, University of Maryland - College Park"}],"order":1},{"id":"136-1561","title":"Relative Performance Feedback And Fuel Efficiency In The Trucking Industry","content":"We investigate how relative performance feedback (RPF) influences truck drivers' fuel efficiency, finding that truck drivers enhance/reduce their subsequent fuel efficiency performance after receiving RPF indicating a higher/lower rank. Additionally, deteriorations in drivers’ rankings over time can negate the positive impacts of RPF on fuel efficiency.","presenter":"Ms. Ha Lam","authors":[{"name":"Ms. Ha Lam","aff":"Student, University of Arkansas"},{"name":"Dr. Saif Mir","aff":"Assistant Professor, Lehigh University"},{"name":"Dr. Christian Hofer","aff":"Professor, University of Arkansas"}],"order":2},{"id":"136-1600","title":"Influence of Loyalty Program Dynamics on Airline Service Complaints","content":"This study explores how airline loyalty program features, specifically points redeemability and accessibility, affect customer complaints. We examine the moderating role of airfares, timing, and airline category on the relationship between program benefits and complaint rates, incorporating various control variables to isolate these effects.","presenter":"Dr. Zenan Zhou","authors":[{"name":"Dr. Jing Wang","aff":"Professor, Beijing Technology and Business University"},{"name":"Ms. Sining Li","aff":"Student, Beijing Technology and Business University"},{"name":"Dr. Zenan Zhou","aff":"Assistant Professor, Arizona State University"},{"name":"Dr. Kevin Park","aff":"Assistant Professor, University of Dayton"}],"order":3}]},{"id":"s303","title":"Platform Operations in the New Technology Age","track":"Service Operations","type":"Regular","invited":"Invited","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY C","chairs":["Ms. Qiaowen Guo","Dr. Fuqiang Zhang"],"abstracts":[{"id":"136-0323","title":"Supplier Encroachment through Online Marketplaces","content":"We study whether a supplier should encroach on an online retail marketplace where both reselling and agency channels are available and its impact on stakeholders in e-commerce. We show that agency encroachment could lead to different results and managerial insights, comparing with traditional supplier encroachment through a direct channel.","presenter":"Prof. Hongseok Jang","authors":[{"name":"Prof. Hongseok Jang","aff":"Assistant Professor, Tulane University"},{"name":"Prof. Quan Zheng","aff":"Professor, University of Science and Technology of China"},{"name":"Dr. Xiajun Pan","aff":"Associate Professor, University of Florida"}],"order":1},{"id":"136-0604","title":"Is Algorithm-Controlled Gig Better Than Human-Controlled Traditional Customer Service?","content":"A field experiment comparing gig and traditional service workers reveals gig agents excel in algorithmic metrics like efficiency but generate negative customer emotions and fewer purchases due to frequent case transfers. This highlights limitations of metric-based algorithmic control versus human supervision.","presenter":"Ms. Qiaowen Guo","authors":[{"name":"Ms. Qiaowen Guo","aff":"Student, Washington University in St. Louis"},{"name":"Dr. Fuqiang Zhang","aff":"Professor, Washington University St Louis"},{"name":"Prof. Xiang Hui","aff":"Assistant Professor, Washington University in St. Louis"},{"name":"Prof. Tianjun Feng","aff":"Professor, Fudan University"}],"order":2},{"id":"136-1172","title":"Optimal dynamic contracting for teams","content":"We consider a continuous-time setting of a principal contracting with a team of agents to undertake a project. The success rate of the project depends on the agents' hidden efforts. We study different information environments, derive the corresponding optimal contract and obtain some implications for optimal contract design.","presenter":"Ms. Yangge xiao","authors":[{"name":"Prof. Ping Cao","aff":"Associate Professor, School of Management"},{"name":"Prof. Peng Sun","aff":"Professor, Duke University Durham"},{"name":"Prof. Feng Tian","aff":"Assistant Professor, the University of Hong Kong"},{"name":"Ms. Yangge xiao","aff":"Post Doc/Researcher, Duke"}],"order":3},{"id":"136-1430","title":"Voice Chatbot Design: Leveraging the Preemptive Prediction Algorithm","content":"This study examines the impact of preemptive prediction algorithms on voice chatbot design in customer service, leveraging data from a leading platform.","presenter":"Prof. Yuqian Xu","authors":[{"name":"Mr. Shuai Hao","aff":"Student, University of Illinois Urbana-Champaign"},{"name":"Prof. Yuqian Xu","aff":"Associate Professor, UNC Chapel Hill"}],"order":4}]},{"id":"s350","title":"Impact of Technology Adoption in Agricultural Supply Chains","track":"Agriculture and Food Supply Chains","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"VININGS","chairs":["Dr. Victor Pimentel"],"abstracts":[{"id":"136-1351","title":"Digitalisation of the Agriculture Certifications: From Compliance to Due Diligent Operations","content":"Agriculture supply chains aim to enhance traceability for compliance in global trade. Digitalization of phytosanitary certificates by blockchain integration is one such effort, in which mapping complex process interactions among supply chain partners is key. We report on how supply chain complexity informs the effectiveness of blockchain-enabled visibility tools.","presenter":"Dr. Janpriy Sharma","authors":[{"name":"Dr. Janpriy Sharma","aff":"Post Doc/Researcher, Rotterdam School of Management"},{"name":"Dr. Katie Kenny","aff":"Post Doc/Researcher, Rotterdam School of Management"},{"name":"Prof. Rob Zuidwijk","aff":"Professor, Rotterdam School of Management"}],"order":1},{"id":"136-1328","title":"Building Trust, Fairness, and Equity in Contract Farming Using Blockchain Technology","content":"Contract farming in developing economies faces power imbalances, information asymmetry, distrust in private companies, and land insecurity. This study uses game-theoretic approach to develop equitable strategies and integrates blockchain technology to ensure secure, transparent, and authentic contracts, empowering farmers and fostering trust among stakeholders for sustainable agricultural development.","presenter":"Mr. Abhinay Mishra","authors":[{"name":"Mr. Abhinay Mishra","aff":"Student, Indian Institute of Management Indore"},{"name":"Prof. Tanmoy Kundu","aff":"Assistant Professor, Indian Institute of Management Indore"},{"name":"Prof. Rohit Kapoor","aff":"Professor, Indian Institute of Management Indore"}],"order":2},{"id":"136-0503","title":"Pandemic-Driven Shifts in Coffee Production Efficiency: A Study of Peruvian Producers","content":"This study explores the impact of COVID-19 on Peruvian coffee producers, analyzing export data (2017–2023) and managerial interviews. Producers adopting technology and adapting processes improved efficiency post-pandemic. Findings highlight innovation's role in resilience, offering insights for academics, policymakers, and agribusiness practitioners on sustainable recovery and operational efficiency in agriculture.","presenter":"Dr. Jonathan Jackson","authors":[{"name":"Dr. Faruk Arslan","aff":"Assistant Professor, New Mexico State University"},{"name":"Dr. Jimoh Fatoki","aff":"Assistant Professor, Roger Williams University"},{"name":"Dr. Donovan Fuqua","aff":"Assistant Professor, New Mexico State University"},{"name":"Dr. Jonathan Jackson","aff":"Associate Professor, Providence College"},{"name":"Dr. Victor Pimentel","aff":"Assistant Professor, New Mexico State University"}],"order":3},{"id":"136-1489","title":"Optimizing Harvest Scheduling in Banana Production","content":"We analyze the decision-making process of a banana producer in scheduling harvests from multiple growers during peak seasons. By accounting for banana maturity, weather conditions, and growers' market price expectations, the producer aims to optimize harvest timing within the available windows to maximize yield.","presenter":"Dr. Harun Avci","authors":[{"name":"Dr. Harun Avci","aff":"Assistant Professor, Kennesaw State University"}],"order":4},{"id":"136-0781","title":"Impacts of Drone Technology and Other High-Tech Solutions on Small-Scale Farmers’ Operations and Well-Being","content":"Drone technology and high-tech agricultural solutions, such as precision tools and automated machinery, could benefit small-scale farmers by increasing income, reducing costs, and promoting sustainability. This study examines their impacts on livelihoods, their role in enhancing well-being, and the barriers to adopting high-tech solutions in small-scale farming operations.","presenter":"Ms. Kehinde Ibosiola","authors":[{"name":"Ms. Kehinde Ibosiola","aff":"Student, Graves School of Business- 4100 Hillen R"},{"name":"Dr. Ziping Wang","aff":"Professor, Morgan State University"},{"name":"Dr. Xingxing Zu","aff":"Associate Professor, Morgan State University"}],"order":5}]},{"id":"s365","title":"Optimizing Humanitarian Supply Chains","track":"Humanitarian Operations and Crisis Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY G","chairs":["Ms. Agatha Da Silva Ovando"],"abstracts":[{"id":"136-1371","title":"Supply chain management for bridging diagnosis and health outcomes","content":"We examine the implementation of a digital health diagnosis tool in a developing country. While adoption is promising, limited medicine availability in community health centers impedes improvements in health outcomes. We identify the root causes of this problem and propose supply chain interventions to address it.","presenter":"Dr. Maximilian Löffel","authors":[{"name":"Dr. Maximilian Löffel","aff":"Post Doc/Researcher, ETH Zurich"},{"name":"Dr. Nathan Kunz","aff":"Professor, University of Applied Sciences"}],"order":1},{"id":"136-0729","title":"Perishable Emergency Inventory Management for Typhoons: A Chance Constrained Program Approach","content":"We explore how to plan the daily purchasing quantities of perishable emergency supplies for stores spanning days around a typhoon's arrival. Considering the randomness of the demands, we build a chance constrained program (CCP) model to guide the daily inventory decision. We study how to solve the CCP efficiently.","presenter":"Ms. Xintong Zhang","authors":[{"name":"Ms. Xintong Zhang","aff":"Student, Tongji University"},{"name":"Prof. Zhaolin Hu","aff":"Professor, Tongji University"}],"order":3}]},{"id":"s367","title":"Coordination and Resource Management in Humanitarian Operations","track":"Humanitarian Operations and Crisis Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"GRAND HALL EAST B","chairs":["Dr. Mario Chong"],"abstracts":[{"id":"136-0129","title":"Coordination Under Constraints in a Pro-social Supply Chain – The Case of India’s Deceased-donation Program","content":"Prosocial supply chains often lack effective coordination, leading to sub-optimal social welfare. We study the case of India’s cadaveric organ donation program and offer evidence-based recommendations on how to manage input and process constraints through idiosyncratic resource environment and social capital utilization while enforcing output constraints for accountability.","presenter":"Mr. Satyajit Roy","authors":[{"name":"Mr. Satyajit Roy","aff":"Student, Indian Institute of Management Bangalore"},{"name":"Prof. Haritha Saranga","aff":"Professor, Indian Institute of Management Bangalore"}],"order":1},{"id":"136-1527","title":"Analysis of brazilian emergency operations centers in disasters response management","content":"This study presents a typology of Emergency Operations Centers (EOCs) for disaster response, based on an analysis of operations in public institutions in Brazil. The analysis was conducted through interviews and technical visits to EOCs in the southern and southeastern regions of the country.\r\n","presenter":"Dr. Mario Chong","authors":[{"name":"Dr. Tábata Bertazzo","aff":"Assistant Professor, Faculdade de Tecnologia de São Paulo - FATEC / AMAZUL"},{"name":"Prof. Irineu de Brito Junior","aff":"Associate Professor, Sao Paulo State University - UNESP"},{"name":"Dr. Mario Chong","aff":"Professor, Universidad del Pacifico"},{"name":"Dr. Davi Nakano","aff":"Assistant Professor, Universidade De Sao Paulo"},{"name":"Prof. Hugo Yoshizaki","aff":"Retired, Universidade de São Paulo"}],"order":2},{"id":"136-1406","title":"Dynamic-Priced Contracts for Uncertain Episodic Service Demand","content":"Following disasters, the uncertain, episodic, and time-sensitive service demand makes it difficult for relief actors to compete with private-sector customers for commercial capacity leading to high costs. We analyze a case of transportation service procurement using dynamic-priced contracts to improve service-level while reducing costs in order to satisfy emergency demand.","presenter":"Dr. Shraddha Rana","authors":[{"name":"Dr. Shraddha Rana","aff":"Post Doc/Researcher, INSEAD"},{"name":"Dr. Jarrod Goentzel","aff":"Post Doc/Researcher, Massachusetts Institute of Technology"},{"name":"Dr. Chris Caplice","aff":"Post Doc/Researcher, Massachusetts Institute of Technology"},{"name":"Prof. Luk Van Wassenhove","aff":"Professor, INSEAD"}],"order":3}]},{"id":"s369","title":"Livestreaming Strategies","track":"POM-Marketing Interface","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"DUNWOODY","chairs":["Prof. Hui Xiong"],"abstracts":[{"id":"136-1046","title":"“Live” May Backfire: A Comparative Eye-Tracking Study of How Video Synchronization Influences Consumers’ Online Shopping","content":"In a live-streaming shopping context, we investigate how video synchronization impacts consumer engagement, particularly attention and interest. Using eye-tracking and an object detection algorithm, we identify instances where promotional features divert customer attention, leading to reduced interest in the product being sold.","presenter":"Dr. Keran Zhao","authors":[{"name":"Dr. Keran Zhao","aff":"Assistant Professor, Penn State University"},{"name":"Dr. Wael Jabr","aff":"Assistant Professor, Penn State University"},{"name":"Dr. Shi (Sherry) Wang","aff":"Assistant Professor, Ohio State University"},{"name":"Dr. Mi Hyun Lee","aff":"Assistant Professor, Northwestern University"},{"name":"Dr. Ming Chen","aff":"Assistant Professor, University of North Carolina Charlotte"}],"order":1},{"id":"136-0578","title":"Evaluating the Interaction Effects on the Adoption of Virtual Livestream Strategies","content":"Manufacturers choose between hiring KOL virtual streamers (Model L) or self-building virtual streamers (Model M), balancing commission costs with livestream revenue to optimize distribution channels. We examine interactivity models within each approach, specifically focusing on consumer-streamer (CSI) and consumer-consumer interaction (CCI) dynamics in different channel structures.","presenter":"Ms. Liu Zixuan","authors":[{"name":"Ms. Liu Zixuan","aff":"Student, Tianjin university COME"},{"name":"Mr. Zhong shiquan","aff":"Professor, Tianjin university COME"},{"name":"Prof. Ning Jia","aff":"Professor, Tianjin university"}],"order":2},{"id":"136-0150","title":"Live streaming selling under consumers’ limited attention","content":"In recent years, many sellers sell products through third-party live streamers and share revenue with these streamers. In this paper, we consider consumers’ limited attention to informative and noninformative content, and characterize the bargaining process between the seller and the streamer in game-theoretic models.","presenter":"Prof. Hui Xiong","authors":[{"name":"Prof. Hui Xiong","aff":"Professor, Donghua University"},{"name":"Dr. Jie Liu","aff":"Assistant Professor, Soochow University"},{"name":"Prof. Ying-Ju Chen","aff":"Professor, Hong Kong University of Science and Technology"}],"order":3}]},{"id":"s379","title":"Managers, Workers, and Behavioral Operations","track":"Behavioral Operations Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY D","chairs":["Dr. Jose Benedicto Duhaylongsod"],"abstracts":[{"id":"136-0589","title":"Problem Prevention Behavior among Operations Managers: Interaction of Proactive Personality and Developmental Job Experience","content":"We examine how individual and motivational factors influence operations managers to engage in proactive, problem prevention behaviors. We also contend that this relationship is conditional on these managers’ level of developmental job experience. We test our model using survey data over three waves and contextualize it using semi-structured interviews.","presenter":"Dr. Jose Benedicto Duhaylongsod","authors":[{"name":"Dr. Jose Benedicto Duhaylongsod","aff":"Assistant Professor, IESEG School of Management"},{"name":"Dr. Seamus Dufurrena","aff":"Assistant Professor, Toulouse Business School"},{"name":"Dr. Sheldon Carvalho","aff":"Assistant Professor, Middlesex University"},{"name":"Dr. Irene De Pater","aff":"Professor, Edith Cowan University"}],"order":1},{"id":"136-1442","title":"The Impact of Safety And Productivity Reminders on Warehouse Driver Behavior: A VR Experiment","content":"Balancing productivity and safety is a key challenge in warehouses. This study uses a VR simulator to explore the impact of safety audio reminders, varying in specificity and exposure time, on warehouse vehicle drivers' performance. It also examines drivers' individual differences, including Regulatory Focus and Big Five Personality Traits.","presenter":"Mrs. Mahsa Alirezaei","authors":[{"name":"Mrs. Mahsa Alirezaei","aff":"Student, Erasmus University Rotterdam"},{"name":"Dr. Jelle de Vries","aff":"Assistant Professor, Rotterdam School of Management"},{"name":"Prof. René De Koster","aff":"Professor, Erasmus University Rotterdam"}],"order":2},{"id":"136-0831","title":"When you get what you want, but not what you need: Digital versus traditional resources","content":"Firms adopt digital tools like Augmented Reality to assist workers but may discontinue them if benefits fall short. Using controlled lab experiments with objective and subjective stress measures, we examine whether removing such tools increases worker stress during tasks.","presenter":"Mr. Mrunal Mohadikar","authors":[{"name":"Prof. Michela Carraro","aff":"Assistant Professor, NEOMA Business School"},{"name":"Prof. David Wuttke","aff":"Assistant Professor, TUM School of Management, HN Campus"},{"name":"Mr. Mrunal Mohadikar","aff":"Student, TUM School of Management, HN Campus"},{"name":"Mr. Ankit Upadhyay","aff":"Student, TUM School of Management, HN Campus"},{"name":"Dr. Enno Siemsen","aff":"Professor, University of Wisconsin"}],"order":3},{"id":"136-0969","title":"\"Do you hear my performance?\" Empirical investigations on the operations impact of occupational noise","content":"Analyses regarding occupational noise have looked into generalized regulations and worker damage control, neglecting impacts on individual workers.  We conducted controlled lab experiments recording digital traces in the MADE Center in Milan and provide novelty situated explanations into the triangulated nexus between occupational noise, human manufacturing performance and cognitive processes.","presenter":"Mr. Sajjad Shooshtari","authors":[{"name":"Mr. Sajjad Shooshtari","aff":"Student, Politecnico Di Milano"},{"name":"Dr. Dominic Loske","aff":"Post Doc/Researcher, Tu Darmstadt"},{"name":"Prof. Matthias Klumpp","aff":"Associate Professor, Politecnico Di Milano"}],"order":4},{"id":"136-1140","title":"Do managers change the way they think when in backlog?","content":"We hypothesize that managers will transition from System 2(slow, analytical) thinking to System 1(fast, intuitive) when in backlog. We test our hypothesis on neurophysiological data gathered from an experiment where practitioners play the computerized version of the Beer Distribution Game while wearing electroencephalography(EEG) headsets.\r\n","presenter":"Mr. Myung Jin Lee","authors":[{"name":"Mr. Myung Jin Lee","aff":"Student, Texas A&amp;M University"},{"name":"Dr. Rogelio Oliva","aff":"Professor, Texas A&amp;M University College Station"},{"name":"Dr. Juan Pablo Torres","aff":"Associate Professor, Universidad Adolfo Ibáñez"}],"order":5}]},{"id":"s399","title":"Public Sector Operations &amp; Sustainability","track":"Sustainable Operations Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"GRAND HALL EAST C","chairs":["Prof. John Maleyeff"],"abstracts":[{"id":"136-1438","title":"Disentangling the impact of Green Public Procurement policies on suppliers: a multiple-case study","content":"Green Public Procurement (GPP) policies require public sector organizations to adopt environmental criteria in supplier selection. Previous research has primarily focused on GPP’s impact on public bodies. We investigate its influence on the operations of public sector suppliers through 12 exploratory case studies, providing preliminary empirical insights and policy recommendations.","presenter":"Dr. Antonio Cavallin Toscani","authors":[{"name":"Dr. Antonio Cavallin Toscani","aff":"Assistant Professor, Padova University"},{"name":"Mr. Stefano Roana","aff":"Student, Padova University"},{"name":"Prof. Andrea Vinelli","aff":"Professor, Padova University"}],"order":1},{"id":"136-0893","title":"Government-Business Interplay in Digital Twin-Enabled Reverse Supply Chains: Subsidizing Recycler, Manufacturer, or Customer?","content":"Inspired by the 2024 launch of China Resources Recycling Group (CRRG), this research examines how national initiatives can drive sustainable economic growth by integrating digital technologies like Digital Twins in the recycling industry. It explores optimal subsidy strategies in digital transformation for consumers, manufacturers, recyclers, some, or all three.","presenter":"Ms. Shuyi Wang","authors":[{"name":"Ms. Shuyi Wang","aff":"Lecturer, University of Science and Technology Beijing"}],"order":2},{"id":"136-1061","title":"Integrating Sustainability and Inventory Practices for University Chemical Materials","content":"Sustainability is integrated into a chemical inventory model for a University. The model considers decentralized and aggregation options based on traditional inventory costs with quantified impacts of expiration, energy, and transportation, while accounting for greener substitutions. The approach is applied at Boston University, sponsored by their Institute for Global Sustainability.","presenter":"Ms. Chenxi Feng","authors":[{"name":"Prof. John Maleyeff","aff":"Associate Professor, Boston University"},{"name":"Ms. Chenxi Feng","aff":"Student, Boston University"},{"name":"Mr. Ron Morales","aff":"Director, Research Safety, Environmental Health &amp; Safety"}],"order":3},{"id":"136-0248","title":"Choosing a Climate Risk Response for a University Facility Considering Ripple Effects","content":"A decision support methodology is presented for mitigating risk of severe weather events on a university facility that considers direct and ripple effects to university operations. Users determine indifference probabilities that equate mitigation responses using pairwise comparisons. The options are ranked using AHP and an R-Shiny application is demonstrated.","presenter":"Prof. John Maleyeff","authors":[{"name":"Prof. John Maleyeff","aff":"Associate Professor, Boston University"},{"name":"Ms. Kunsinee Srivichaiin","aff":"Student, Metropolitan College"},{"name":"Ms. Kaumudi Dande","aff":"Student, Metropolitan College"}],"order":4}]},{"id":"s406","title":"Improving Team Performance and Production Efficiency","track":"Operational Excellence","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"BAKER","chairs":["Dr. Xianghui (Richard) Peng"],"abstracts":[{"id":"136-0600","title":"Mastering Variance in Individualized Mixed-Model Assemblies: Why the Variable Takt Outperforms the Fixed Takt","content":"Demands on assembly lines have increased; hence, the fixed takt approach is being challenged. We develop an efficient method for the general assembly line balancing problem and prove how the variable takt can master unlimited product customization, thus strictly outperforming the fixed takt regarding utilization and profitability.","presenter":"Mr. Philipp Pithan","authors":[{"name":"Mr. Philipp Pithan","aff":"Student, WHU - Otto Beisheim School of Management"},{"name":"Prof. Arnd Huchzermeier","aff":"Professor, WHU - Otto Beisheim School of Management"}],"order":1},{"id":"136-0984","title":"Development and Validation of an Agile Project Management Framework","content":"This study examines the prevailing practice-oriented agile project management methods. We develop and test an agile project management framework. It contributes to the area by investigating its effectiveness as an organizational initiative. The two-stage test of PLS-SEM validates the measurements of constructs and their roles within the framework.","presenter":"Dr. Xianghui (Richard) Peng","authors":[{"name":"Dr. Ying Cao","aff":"Assistant Professor, Penn State Erie"},{"name":"Dr. Xinyu Wei","aff":"Assistant Professor, California State University, Chico"},{"name":"Dr. Xianghui (Richard) Peng","aff":"Associate Professor, Penn State University Erie"}],"order":2},{"id":"136-2014","title":"From individual proactivity to team proactive performance in operational excellence transformations","content":"Team proactive performance (TPP) is central for continuous improvement and operational excellence initiatives. We develop an agent-based model (ABM) to simulate how TPP emerges from interactions among individuals. We argue that due to the complex nature of within-team interactions, TPP emerges following a compilative emergence process.","presenter":"Mr. Davide Bonfio","authors":[{"name":"Prof. Andrea Furlan","aff":"Professor, Padova University"},{"name":"Mr. Davide Bonfio","aff":"Student, University of Padova"}],"order":3}]},{"id":"s412","title":"Workforce and Resource Optimization in Healthcare","track":"Healthcare Operations Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"PIEDMONT","chairs":["Prof. Karuna Jain"],"abstracts":[{"id":"136-0783","title":"Infection Aware Nurse Staffing","content":"During outbreaks of infectious diseases, hospitals encounter significant challenges making well-informed nurse staffing decisions. Nurses experience significant higher infection rates than the public, which greatly disrupts hospital operations. We use a random graph model to model the interaction between disease transmission and nurse staffing to recommend mitigation policies for hospitals.","presenter":"Mr. Buyun Li","authors":[{"name":"Mr. Buyun Li","aff":"Student, Indiana University"},{"name":"Prof. Jonathan Helm","aff":"Professor, Kelley School of Business"},{"name":"Prof. Pengyi Shi","aff":"Associate Professor, Purdue University"},{"name":"Prof. Kurt Bretthauer","aff":"Professor, Indiana University"}],"order":1},{"id":"136-1064","title":"Addressing Healthcare Provider Burnout: Fair Online Hospital Diagnostic Service Scheduling","content":"This work proposes an online allocation framework for quantifying and mitigating healthcare provider burnout risks related to workload fairness, variability, and complexity. For echocardiograms at our partner hospital, our method improves technician load fairness by 28% and reduces variability compared to current policy, without compromising patient throughput and wait times.","presenter":"Ms. Joyce Luo","authors":[{"name":"Ms. Joyce Luo","aff":"Student, Massachusetts Institute of Technology"},{"name":"Dr. Maureen Canellas","aff":"Assistant Professor, UMass-Chan Medical School"},{"name":"Prof. Dessislava Pachamanova","aff":"Professor, Babson College"},{"name":"Prof. Georgia Perakis","aff":"Professor, Massachusetts Institute of Technology"}],"order":2},{"id":"136-1073","title":"Multi-Class Advance Patient Scheduling","content":"This paper presents a framework for advance scheduling across multiple patient classes with varying service needs and waiting costs. By strategically delaying certain scheduling decisions to gather more demand information, the proposed policy effectively balances resource utilization and waiting times, as demonstrated through empirical validation using data from four hospitals.","presenter":"Mr. Sadegh Shirani","authors":[{"name":"Mr. Sadegh Shirani","aff":"Student, Stanford University"},{"name":"Prof. Hossein Abouee Mehrizi","aff":"Professor, University of Waterloo"},{"name":"Prof. Mohammad Kazem Shirani Faradonbeh","aff":"Assistant Professor, Southern Methodist University"}],"order":3},{"id":"136-2021","title":"Optimizing Blood Supply Chains: Enhancing Healthcare Outcomes in India","content":"Efficient blood supply chains are vital for addressing India’s healthcare needs. This study develops a mathematical model to optimize the perishable blood supply chain by minimizing costs, ensuring timely delivery, and preserving quality. Tackling demand variability and perishability, the model enhances operational efficiency, real-time decision-making, and healthcare outcomes across India.","presenter":"Prof. Karuna Jain","authors":[{"name":"Prof. Karuna Jain","aff":"Professor, Indian Institute of Technology Bombay"},{"name":"Prof. Vijaya Patil","aff":"Assistant Professor, Welingkar Institute of Management Development and Research"}],"order":7}]},{"id":"s415","title":"Decision-Making and Technology in Patient Care","track":"Healthcare Operations Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY H","chairs":["Mrs. Rosalinda Iachetta"],"abstracts":[{"id":"136-0957","title":"Designing Doctor-Patient Shared Decision-Making Processes under Bounded Rationality","content":"Shared decision-making processes, in which doctors and patients work together to choose among treatment options, have gained increasing support from clinicians and governments. We develop a stylized analytical model to derive a set of results characterizing when and how to design the shared decision-making processes between doctors and patients.","presenter":"Dr. Feray Tunçalp","authors":[{"name":"Dr. Feray Tunçalp","aff":"Assistant Professor, Bilkent University"},{"name":"Dr. Rouba Ibrahim","aff":"Professor, University College London"},{"name":"Dr. Song-Hee Kim","aff":"Associate Professor, Seoul National University"},{"name":"Prof. Jordan Tong","aff":"Professor, University of Wisconsin-Madison"}],"order":1},{"id":"136-1488","title":"Telemedicine and Anticoagulant Prescription Patterns for Atrial Fibrillation Patients","content":"In this healthcare operations study, analysis of 16,603 patients shows telemedicine visits result in 5.2% lower guideline adherence for anticoagulant prescriptions in atrial fibrillation compared to in-person care, revealing operational needs for quality interventions across care delivery modes.","presenter":"Dr. Muhammad Zia Hydari","authors":[{"name":"Dr. Muhammad Zia Hydari","aff":"Assistant Professor, University of Pittsburgh"},{"name":"Dr. Rahul Telang","aff":"Professor, Carnegie Mellon University"},{"name":"Dr. Eric Dueweke","aff":"Lecturer, UPMC"},{"name":"Dr. Shalini Allam","aff":"Cardiology Fellow, UMPC"}],"order":3}]},{"id":"s419","title":"Supply Chain and Sustainability","track":"Digital Platforms, Innovations and Transformations","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"GREENBRIAR","chairs":["Dr. Goutham Takasi"],"abstracts":[{"id":"136-1911","title":"Revolutionizing Supply Chain Training: An Immersive VR-Based Approach","content":"This research introduces an innovative, immersive VR-based approach to enhance training in supply chain and logistics management. By mimicking or escaping reality, VR combines familiar sensory contexts with abstract concept visualization, revolutionizing education in these fields. A live demo will be provided during the presentation.","presenter":"Dr. Victor Romero","authors":[{"name":"Prof. Frederick Benaben","aff":"Professor, IMT Mines Albi / Georgia Tech"},{"name":"Prof. Matthieu Lauras","aff":"Professor, IMT Mines Albi / Georgia Tech"},{"name":"Dr. Victor Romero","aff":"Assistant Professor, IMT Mines Albi"}],"order":1},{"id":"136-1208","title":"Investigating the Impact of Digital Technologies on Resilient and Sustainable Agri-Food Supply Chains","content":"Motivated by agri-food supply chain vulnerabilities and global food insecurity persistence, we find that digital technologies are crucial to supply chain resilience following disruptive events and to firm performance. Practical implications result from our grouping of digital technologies into three categories: technologies for data-driven insights, transactional efficiency, and farm-level productivity.","presenter":"Dr. Misty Blessley","authors":[{"name":"Mr. Luong Dao","aff":"Student, Temple University"},{"name":"Dr. Misty Blessley","aff":"Associate Professor, Temple University"}],"order":2},{"id":"136-1446","title":"Platform Economics and Piracy Control: When Supply-side Enforcement Backfires","content":"The rise of digital platforms has fundamentally changed content distribution in the digital economy. In contrast to previous findings favoring supply-side measures, we discover that supply-side enforcement unintentionally reduces discovery system investment and weakens network externalities, diminishing product quality. Our results suggest a reconsideration of anti-piracy strategies in platform-dominated markets.","presenter":"Ms. Guangjun Huang","authors":[{"name":"Ms. Guangjun Huang","aff":"Student, Central South University"},{"name":"Prof. Fuqiang Wang","aff":"Associate Professor, Central South University"},{"name":"Prof. Yunchuan Liu","aff":"Associate Professor, University of Illinois Urbana-Champaign"}],"order":3},{"id":"136-0088","title":"Optimal Design of Income Sharing Loan (ISL) Programs in Education Sector: A Non-Profit Organization Perspective","content":"Motivated by the growing concern over rising student debt in the U.S. and inspired by the recent implementation of Income-Sharing Loans (ISLs) at Stanford Law School through Flywheel Fund (a non-profit), we investigate the optimal design of ISLs to address this financial challenge from the non-profit (student welfare) perspective.","presenter":"Dr. Goutham Takasi","authors":[{"name":"Dr. Goutham Takasi","aff":"Assistant Professor, University of Alabama Tuscaloosa"}],"order":4}]},{"id":"s423","title":"Technology-Driven Sustainability and Workforce Optimization","track":"Disruptive Technologies and Operations Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"KENNESAW","chairs":["Dr. Jim Shi"],"abstracts":[{"id":"136-0845","title":"Internet of Things for supply chain management: A systematic literature review and research agenda","content":"This study conducts a systematic literature review of Internet of Things in supply chains regarding applications, barriers, and outcomes. Key applications include real-time monitoring, inventory optimization, and logistics tracking. Barriers such as high costs, security concerns, and lack of standardization. Outcomes include improved efficiency, cost reductions, and Sustainability.","presenter":"Prof. Ilias Vlachos","authors":[{"name":"Prof. Ilias Vlachos","aff":"Professor, Excelia Business School"}],"order":1},{"id":"136-1519","title":"Digital technologies as resources or demands? Transforming technostress into improved worker performance","content":"We experimented at a lab with 56 participants on technostress. Machine vision with real-time feedback improved capabilities but slowed tasks, while monitoring cameras eased task performance. Detailed tech instructions reduced errors, improving worker performance. We discuss that technology acts as a resource and a demand, with detailed information inhibiting technostress.","presenter":"Mrs. Jessica Dornelles","authors":[{"name":"Mrs. Jessica Dornelles","aff":"Student, Federal University of Rio Grande do Sul"},{"name":"Prof. Alejandro Frank","aff":"Professor, Federal University of Rio Grande do Sul"}],"order":2},{"id":"136-1075","title":"The impact of Technology Adoption on Sustainability:","content":"This study explores i4.0 technology investment impact on sustainability through secondary data from 1,000 Italian firms, highlighting the interplay between technological adoption and sustainability via structural equation","presenter":"Mrs. Maria Alice Moreira Trindade","authors":[{"name":"Mrs. Maria Alice Moreira Trindade","aff":"Assistant Professor, Texas A&amp;M University College Station"}],"order":3},{"id":"136-1869","title":"Plastic Recycling Driven by Blockchain: ESG Optimization and Implications","content":"The plastic waste crisis has been exacerbating nowadays. To address the burgeoning challenge, one innovative solution is to incentivize recycling via leveraging tokenization thanks to Blockchain technology (BCT). In this study, we devise an optimization model considering the tokenization to examine the environmental and social governance (ESG) performance.","presenter":"Dr. Jim Shi","authors":[{"name":"Prof. Aichih Chang","aff":"Assistant Professor, New Jersey Institute of Technology"},{"name":"Dr. Nesreen El-Rayes","aff":"Assistant Professor, Georgia State University"},{"name":"Dr. Jim Shi","aff":"Professor, New Jersey Inst of Technology"},{"name":"Ms. Fuqin Zhou","aff":"Student, New Jersey Institute of Technology"}],"order":4}]},{"id":"s427","title":"Supply Chain Game Theory","track":"Supply Chain Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"GRAND HALL EAST A","chairs":["Dr. Erfan Asgari"],"abstracts":[{"id":"136-0882","title":"The role of commitment in supply chain competition under uncertainty","content":"We model supply chains facing demand uncertainty consisting of two types of producers - producers that can credibly commit to a production schedule and the ones that cannot. Under a variety of settings, we identify the equilibrium production quantities, prices, profits and other metrics of interest.","presenter":"Prof. Sriram Sankaranarayanan","authors":[{"name":"Prof. Sriram Sankaranarayanan","aff":"Assistant Professor, Indian Institute of Management Ahmedabad"},{"name":"Prof. Sanjith Gopalakrishnan","aff":"Assistant Professor, McGill University"}],"order":1},{"id":"136-0016","title":"Pricing and Production Coordination with Complementary Products in Decentralized Supply Chains","content":"We analyze a supply chain comprising a set of suppliers producing complementary components for a common manufacturer. We characterize pure strategy subgame perfect Nash Equilibrium constituting pricing, and production decisions. We study the horizontal inefficiency due to the decentralized suppliers’ coalition, and analyze the stability of the coalition structure.","presenter":"Dr. Peeyush Mehta","authors":[{"name":"Dr. Peeyush Mehta","aff":"Professor, Indian Institute of Management Calcutta"},{"name":"Prof. Conan Mukherjee","aff":"Associate Professor, Indian Institute of Management Calcutta"}],"order":2},{"id":"136-0470","title":"Newsvendor Competition of Distributionally Robust Retailers","content":"We study retailers' strategic decisions when they rely on limited distributional information to make pessimistic decisions against distributional ambiguity in the context of competitive newsvendor games. We analytically characterize the unique Nash equilibrium in closed-form, offering valuable insights that extend the current literature and providing practical implications.","presenter":"Dr. Eojin Han","authors":[{"name":"Dr. Eojin Han","aff":"Assistant Professor, University of Notre Dame"},{"name":"Dr. Milad Armaghan","aff":"Post Doc/Researcher, Southern Methodist University"},{"name":"Dr. Sila Cetinkaya","aff":"Professor, Southern Methodist University"}],"order":3},{"id":"136-0280","title":"Green Profits and Fast Fulfillment: Coordinating Dual-Channal Supply Chains in an Eco-Conscious Market","content":"This study analyzes a two-stage supply chain with a retailer using Make-to-Stock and a manufacturer adopting Make-to-Order strategies. Demand depends on price, delivery time, and carbon intensity. Using Stackelberg game, the research optimizes wholesale pricing, emissions, lead times, retail price, and order size to balance economic, environmental, and market factors.","presenter":"Dr. Erfan Asgari","authors":[{"name":"Dr. Erfan Asgari","aff":"Assistant Professor, Excelia Business School"},{"name":"Dr. Nazanin Foroozesh","aff":"Post Doc/Researcher, IMT Atlantique"},{"name":"Dr. Reza Babajanivalashedi","aff":"R&amp;D engineer, OMIA"}],"order":4}]},{"id":"s429","title":"Sustainability, Circularity, and Resilience","track":"Supply Chain Management","type":"Regular","invited":"Contributed","date":{"iso":"2025-05-12","dow":"Monday","day":12,"mon":"May"},"start":"9:45 AM","end":"11:15 AM","startMin":585,"room":"EMBASSY A","chairs":["Mr. Tiloux Soundja"],"abstracts":[{"id":"136-1634","title":"Circular economy practices and institutional pressures: understanding the role of digitalization, information alignment and coordination.","content":"Drawing on institutional and stakeholder theories, we explore integration of circular economy and industry 4.0 principles, to improve sustainable collaborative supply chains in developing country. Based on data from manufacturing firms, and using statistical techniques, we examine the interplay between circular economy practices, institutional pressures, digitalization, information alignment and coordination","presenter":"Mr. Amine Hamdaoui","authors":[{"name":"Mr. Amine Hamdaoui","aff":"Student, ibn Zohr University"},{"name":"Dr. Elhoussaine Erraoui","aff":"Professor, ibn Zohr University"},{"name":"Dr. Issam Laguir","aff":"Associate Professor, Montpellier Business School"}],"order":1},{"id":"136-0177","title":"Circular economy practices, financial performance, and environmental performance: understanding the mediating role of firm reputation.","content":"Drawing on stakeholder theory, we examine the role of firm reputation in translating circular economy practices into financial and environmental performances. Based on data from 135 manufacturing firms, and using hierarchical-regressions analysis, results reveal that circular economy practices improve financial and environmental performances through the mediating role of firm reputation.","presenter":"Mr. Amine Hamdaoui","authors":[{"name":"Mr. Amine Hamdaoui","aff":"Student, ibn Zohr University"},{"name":"Dr. Elhoussaine Erraoui","aff":"Professor, ibn Zohr University"},{"name":"Dr. Issam Laguir","aff":"Associate Professor, Montpellier Business School"}],"order":2},{"id":"136-1615","title":"The Optimal Controller: Applying PID Control in Supply Chain Theory Development and Policy Design","content":"Scholarly conceptualization of the supply chain has long made fruitful use of control engineering principles. In a case study conceptualizing supply chain sustainability and circularity across time scales, the principle of optimal control was used to design and test a Proportional Integral Derivative (PID) controller. Value and contributions are discussed.","presenter":"Prof. Samuel Allen","authors":[{"name":"Prof. Samuel Allen","aff":"Technical Analyst, Professor, RAND"},{"name":"Prof. Joseph Sarkis","aff":"Professor, Worcester Polytechnic Institute"},{"name":"Dr. Xun Wang","aff":"Lecturer, Cardiff University"},{"name":"Dr. Khalid Saeed","aff":"Professor, Worcester Polytechnic Institute"}],"order":3},{"id":"136-1191","title":"Dynamic capacity-based supply chain resilience: Case of Quebec's Food Banks","content":"Under the lens of dynamic capabilities theory, this study examines how resilience develops within organizations and through supply chain interactions. It builds a comprehensive framework that combines intra- and inter-organizational resilience perspectives, often treated separately. This study offers valuable insights, especially for supply chains led by nonprofit actors.","presenter":"Mr. Tiloux Soundja","authors":[{"name":"Mr. Tiloux Soundja","aff":"Student, Universite Laval"},{"name":"Dr. Karima Afif","aff":"Professor, Universite Laval"}],"order":4}]}]};
